insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】近距離攻撃\\n巨大なハサミと硬い殻が自慢の\\nカニの魔物。砂に潜んで気長に獲物\\nを待つ姿はどこか愛らしい。', 204502, 0, 1, 204502, 270, 0, 0, 0, 0, 2.0, 80, 'スパイククラブ');
