insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】近接攻撃\\n固い葉っぱを鎧のように纏い、\\n痛烈な体当たりをする大イノシシ。\\nだが所詮葉っぱ。魔法は防げない。', 204700, 0, 1, 204700, 270, 0, 0, 0, 0, 4.0, 200, 'リーフボア');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】近接攻撃\\n砂を固めて鎧のように纏うのは、\\n捨て身を恐れない一族の戦士の証。\\nだが所詮は砂。魔法は防げない。', 204701, 0, 1, 204701, 270, 0, 0, 0, 0, 4.0, 200, 'サンドボア');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】近接攻撃\\n熱地に生きる、原始の大イノシシ。\\n数多のマグマ岩を突き続けた先に、\\n鎧をも砕く牙の一撃を体得した。', 204702, 0, 1, 204702, 270, 0, 0, 0, 0, 4.0, 170, 'ワイルドボア');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】近接攻撃\\n固い葉っぱを鎧のように纏い、\\n痛烈な体当たりをする大イノシシ。\\nだが所詮葉っぱ。魔法は防げない。', 204703, 0, 1, 204703, 270, 0, 0, 0, 0, 4.0, 200, 'リーフボア');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】近接攻撃\\nイクト・ガラディオンに付き従う古代の自動人形。\\n意思を持たず、自身が瓦解するまで戦い続ける。', 204800, 0, 1, 204800, 270, 0, 0, 0, 0, 1.8, 150, 'ルインドール');
