insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】中距離攻撃\\nイカリ頭のイカ魔物。金属質の錨は\\n高硬度のかわりに重く、バランスを\\n崩しよくひっくり返る。', 205900, 0, 0, 205900, 270, 0, 0, 0, 0, 2.5, 200, 'イカリイカ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】近接攻撃\\n身体も態度も巨漢な北海のドン。\\n纏う厚い脂肪が敵からの物理攻撃\\nを押止める。', 206000, 0, 1, 206000, 270, 0, 0, 1, 0, 4.0, 100, 'トドドン');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【魔法】遠距離攻撃\\n浴びれば凍える冷気の魔法で、\\n戦意を奪うオウムガイ型の魔物。', 206100, 0, 2, 206100, 270, 0, 0, 7, 0, 4.5, 1080, 'ワイズワンド');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】中距離攻撃\\n貝殻をぶつけて不意をつく、\\n意地悪な北海のチンピラっこ。', 206200, 0, 1, 206200, 270, 0, 0, 1, 0, 3.5, 650, 'ギャングオッター');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】中距離攻撃\\n片っ端から木を削り倒すビーバー。\\n削った木片は家作りだけでなく、\\n家を守るための飛び道具となる。', 206201, 0, 1, 206201, 270, 0, 0, 1, 0, 0.5, 650, 'ノーティビーバー');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【回復】単体ＴＰ回復\\nルナの塔建造と共に造られた、エネルギー増幅器。\\n漂う魔力を濃縮し、供給することで守護者を強化する。', 206300, 0, 0, 206300, 270, 0, 0, 0, 0, 10.0, 1110, 'ルナポッド');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【回復】単体ＴＰ回復\\nルナの塔建造と共に造られた、エネルギー増幅器。\\n漂う魔力を濃縮し、供給することで守護者を強化する。', 206301, 0, 0, 206300, 270, 0, 0, 0, 0, 10.0, 1800, 'ルナポッド');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】近接攻撃\\n一ツ目族の王に仕える、小さな召使い。\\n王様がくれた金ピカ装備が、大のお気に入り。', 206400, 0, 1, 206400, 270, 0, 0, 0, 0, 2.5, 100, 'リトルアイ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】近接攻撃\\nウキキーがより成長した姿。幼少より大岩を投げ\\n続けたその太腕は、絶大な打撃を繰り出す。', 206500, 0, 1, 206500, 300, 0, 0, 0, 0, 2.5, 100, 'コマンド・ウキキー');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('ヒヨリの姿をした特殊な魔物\\n\\n・目の前の敵１キャラに物理大ダメージを与え、\\n\u3000その周りの狭い範囲の敵すべてにも\\n\u3000物理中ダメージを与える。\\n・目の前の敵１キャラに物理中ダメージを\\n\u3000与える。\\n・目の前の敵１キャラに物理小ダメージを与え、\\n\u3000さらに自分の物理攻撃力を中アップさせる。', 206700, 0, 1, 206700, 270, 0, 0, 1, 0, 2.295, 200, 'ヒヨリのシャドウ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('レイ（ニューイヤー）の姿をした特殊な魔物\\n\\n・敵全体に物理中ダメージを与え、\\n\u3000さらにスタンさせる。\\n・【挑発】敵全体を挑発する。\\n\u3000挑発後のモーション中に攻撃を受けた場合、\\n\u3000範囲内の敵すべてに物理中ダメージを与え、\\n\u3000さらに物理防御力を小ダウンさせる。\\n・自分の周囲の味方すべてに\\n\u3000魔法無効バリアを展開し、さらに\\n\u3000自身の魔法防御力を中アップさせる。', 206701, 0, 1, 206701, 270, 0, 0, 4, 0, 1.965, 400, 'レイ（ニューイヤー）のシャドウ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('ユイ（ニューイヤー）の姿をした特殊な魔物\\n\\n・味方全体に物理/魔法無効バリアと\\n\u3000継続ＨＰ回復状態を付与するが、\\n\u3000自身の魔法攻撃力を大ダウンさせる。\\n・前から２番目の敵１キャラの\\n\u3000物理攻撃力と魔法攻撃力を大ダウンさせる。\\n・魔法攻撃を行う全ての味方キャラの\\n\u3000魔法攻撃力を大アップさせる。', 206702, 0, 2, 206702, 270, 0, 0, 7, 0, 2.27, 600, 'ユイ（ニューイヤー）のシャドウ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('仮', 206800, 0, 0, 206800, 20, 0, 0, 0, 0, 999.0, 0, '煩悩バリア1');
