insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('ノゾミの姿をした特殊な魔物\\n\\n・【挑発】味方全体の物理攻撃力を小アップさせ、\\n\u3000自分の物理防御力と魔法防御力を大アップさせ\\n\u3000る。さらに敵全体を挑発する。\\n・前方範囲内の敵すべてに物理小ダメージを与え、\\n\u3000さらにスタンさせる。\\n・自分の周囲の味方すべてのＨＰを中回復させる。', 214801, 0, 1, 214801, 450, 0, 0, 4, 0, 1.965, 160, 'ノゾミのシャドウ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('ムイミの姿をした特殊な魔物\\n\\n・目の前の敵１キャラに物理特大ダメージを与え\\n\u3000る。さらにＴＰが無くなるまでの間天楼覇断剣\\n\u3000を装備する。\\n・前方範囲内の敵すべてに物理小ダメージを与え、\\n\u3000さらにスタンさせて小さく吹き飛ばす。\\n・前方範囲内の敵すべての物理防御力を小ダウン\\n\u3000させる。', 214901, 0, 1, 214901, 450, 0, 0, 2, 0, 1.8, 240, 'ムイミのシャドウ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('カヤの姿をした特殊な魔物\\n\\n・目の前の敵１キャラに物理特大ダメージを与え\\n\u3000る。バトル開始後、初弾のユニオンバーストは\\n\u3000ダメージ量が大幅アップ。\\n・目の前の敵１キャラに物理中ダメージを与える。\\n・自分の物理攻撃力と物理クリティカルを大アッ\\n\u3000プさせる。', 215001, 0, 1, 215001, 450, 0, 0, 1, 0, 2.17, 320, 'カヤのシャドウ');
