insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('プレシア（フォールン）の姿をした特殊な魔物', 216400, 0, 2, 216400, 450, 0, 0, 44, 0, 2.09, 540, 'プレシア（フォールン）のシャドウ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('リリ（フォールン）の姿をした特殊な魔物\\n\\n・【召喚】目の前の敵１キャラに物理大ダメージ\\n\u3000を与える。このスキルのダメージは自分のシャ\\n\u3000ドウの数に応じて増加する。さらにユニオン\\n\u3000バーストを使用しない、自分のシャドウを２体\\n\u3000生成する。\\n\u3000生成されたシャドウは自分を飛行状態にする。\\n・自分を中心とした範囲内の味方すべての物理攻\\n\u3000撃力を特大アップさせる。\\n・目の前の敵１キャラに物理大ダメージを与え、\\n\u3000物理防御力を小ダウンさせる。', 216501, 0, 1, 216501, 450, 0, 0, 3, 0, 2.09, 464, 'リリ（フォールン）のシャドウ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('クリア（フォールン）の姿をした特殊な魔物\\n\\n・目の前の敵１キャラに物理中ダメージを与え、\\n\u3000自分のＨＰを中回復させる。自分を除く味方の\\n\u3000残りＨＰに応じて、このスキルのダメージが\\n\u3000アップする。\\n・目の前の敵１キャラに物理中ダメージを与え、\\n\u3000物理防御力を中ダウンさせる。自分を除く味方\\n\u3000の残りＨＰに応じて、このスキルのダメージが\\n\u3000アップする。\\n・自分以外の最もＨＰの低い味方１キャラに継続\\n\u3000ＨＰ回復状態と【堕天使の加護】を付与する。\\n\u3000【堕天使の加護】が付与されている間、その\\n\u3000キャラへの敵の攻撃をすべて代わりに受け、自\\n\u3000分への物理ダメージと魔法ダメージをカットし、\\n\u3000自分が敵から受ける行動不能を無効化する。', 216601, 0, 1, 216601, 450, 0, 0, 0, 0, 2.09, 406, 'クリア（フォールン）のシャドウ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】ダメージカット\\nシャドウと共に聖域を守護する、記憶の番人。\\n真なる力を欲するものに、相応の試練を与える。\\n\\n・味方全体に物理魔法ダメージカット効果を付与\\n\u3000する。さらに、自身以外のダメージを受けてい\\n\u3000る味方に無敵状態を付与し、物理攻撃力と魔法\\n\u3000攻撃力をアップさせる。', 216700, 0, 1, 216700, 270, 0, 0, 0, 0, 1.9, 400, 'シールド・レリック');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【魔法】遠距離攻撃\\nシャドウと共に聖域を守護する、記憶の番人。\\n真なる力を欲するものに、相応の試練を与える。\\n\\n・敵の挑発を無視して、最も遠い敵１キャラに\\n\u3000５万の魔法固定ダメージを与える。このスキ\\n\u3000ルを使用するたび、次のスキルを使用するま\\n\u3000での時間が短くなる。', 216800, 0, 2, 216800, 270, 0, 0, 0, 0, 0.9, 1200, 'アタック・レリック');
