insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】【物理防御】\\n幼くも、勇猛な見習いゴブリン。\\n非力を補う動きで、前線を駆ける。\\n\\n・近接攻撃\\n・与えるダメージによるＴＰ回復量80％ダウン', 250300, 0, 1, 250300, 270, 0, 0, 0, 0, 0.5, 95, 'ゴブリンリトル');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】【防御】\\n身体も態度も巨漢な北海のドン。\\n纏う厚い脂肪が敵からの攻撃を押止める。\\n\\n・近接攻撃\\n・与えるダメージによるＴＰ回復量80％ダウン', 250400, 0, 1, 250400, 270, 0, 0, 1, 0, 4.0, 55, 'トドドン');
