insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】【妨害】\\n魔力の流れに敏感なキツツキ。\\n鋭い嘴の攻撃で気力を減衰させる。\\n\\n・魔攻高いキャラ攻撃、ＴＰダウン\\n・与えるダメージによるＴＰ回復量80％ダウン', 253400, 0, 1, 253400, 270, 0, 0, 0, 0, 0.9, 400, 'ツキツキ');
