insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【魔法】【中距離】\\n覚えたての魔法で手当り次第に\\n攻撃する赤ちゃん悪魔。\\n\\n・後ろから３番目攻撃\\n・与えるダメージによるＴＰ回復量80％ダウン', 257300, 0, 2, 257300, 270, 0, 0, 0, 0, 3.5, 760, 'プチデビル');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【回復】【補助】\\n拾った潜水服に水を溜め、\\n陸でも戦えるクラゲの魔物。\\n\\n・全体回復\\n・全体魔攻アップ', 257400, 0, 2, 257400, 270, 0, 0, 0, 0, 3.0, 775, 'モグリクラゲ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】【遠距離】\\n大きな岩を投げて、遠くから\\n攻撃してくるサルの魔物。\\n\\n・一番後ろ攻撃\\n・与えるダメージによるＴＰ回復量80％ダウン', 257500, 0, 1, 257500, 270, 0, 0, 0, 0, 3.5, 900, 'ウキキー');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【回復】\\nぷっくりお腹に溜めた魔力を、\\n癒しの波動に変えるトリの魔物。\\n\\n・全体回復', 257600, 0, 1, 257600, 270, 0, 0, 0, 0, 3.0, 905, 'バルーンバード');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】【中距離】【範囲】\\n小石を弾丸のように飛ばして攻撃する、\\n岩でできた動く花。\\n\\n・後ろから３番目中心範囲攻撃\\n・与えるダメージによるＴＰ回復量80％ダウン', 257700, 0, 1, 257700, 270, 0, 0, 15, 0, 3.5, 910, 'ロックフラワー');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】【遠距離】【範囲】\\n尾の花はひどい臭いを放つが、\\n慣れると案外癖になるらしい。\\n\\n・後ろから２番目中心範囲攻撃、毒\\n・与えるダメージによるＴＰ回復量80％ダウン\\n・毒ダメージによるＴＰ回復なし', 257800, 0, 1, 257800, 270, 0, 0, 15, 0, 3.5, 915, 'マッドフラワー');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】【遠距離】【範囲】【妨害】\\n触ると痺れる針山を無限に\\n飛ばしてくる、動くサボテン。\\n\\n・後ろから２番目中心範囲攻撃、麻痺\\n\u3000（ダメージ無効化時も付与）\\n・与えるダメージによるＴＰ回復量80％ダウン', 257900, 0, 1, 257900, 270, 0, 0, 15, 0, 3.5, 920, 'カクタスフラワー');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【魔法】【召喚】\\n大地の魔力でキノコの魔物\\nを自在に生やす、森の精霊。\\n\\n・近接攻撃\\n・ヒカリタケを召喚\\n・与えるダメージによるＴＰ回復量80％ダウン', 258000, 0, 2, 258000, 270, 0, 0, 15, 0, 2.5, 930, 'ドリアード');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【魔法】【中距離】【妨害】\\n遊び相手を見つけては、見境なしに\\nイタズラをする、森の精霊。\\n\\n・前から２番目攻撃、行動速度ダウン\\n\u3000（ダメージ無効化時も付与）\\n・与えるダメージによるＴＰ回復量80％ダウン', 258100, 0, 2, 258100, 270, 0, 0, 15, 0, 2.5, 935, 'ニンフ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【魔法】\\n小さくても強力な炎を吐く、こどものオオトカゲ。\\n\\n・近接攻撃\\n・与えるダメージによるＴＰ回復量80％ダウン', 258200, 0, 2, 258200, 270, 0, 0, 17, 0, 3.5, 925, 'コドモオオトカゲ');
