insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】【遠距離】\\n岩を食べられるほど頑丈な歯をもつ山の精霊。\\n\\n・一番後ろ攻撃\\n・与えるダメージによるＴＰ回復量80％ダウン', 258700, 0, 1, 258700, 270, 0, 0, 15, 0, 3.5, 1035, 'ビッグル');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】【遠距離】\\n氷の塊を武器にも食料にもする雪山の精霊。\\n\\n・一番後ろ攻撃\\n・与えるダメージによるＴＰ回復量80％ダウン', 258800, 0, 1, 258800, 270, 0, 0, 15, 0, 3.5, 1040, 'ムックル');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【魔法】【中距離】\\n地獄の炎をまとい、\\n生者に襲い掛かる怨念の集合体。\\n\\n・後ろから３番目攻撃\\n・与えるダメージによるＴＰ回復量80％ダウン', 258900, 0, 2, 258900, 270, 0, 0, 17, 0, 3.0, 1045, 'スカルフレイム');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【魔法】【中距離】【範囲】【補助】\\n気象を自在に操り、雷を落とす雲の魔物。\\n\\n・前から２、３番目攻撃\\n・全体魔攻アップ\\n・与えるダメージによるＴＰ回復量80％ダウン', 259000, 0, 2, 259000, 270, 0, 0, 0, 0, 3.0, 1050, 'エルダークラウド');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】【中距離】【妨害】\\nヘドロの沼に棲み、\\n口から強力な毒を吐く山椒魚の魔物。\\n\\n・前から２番目攻撃、毒\\n・与えるダメージによるＴＰ回復量80％ダウン\\n・毒ダメージによるＴＰ回復なし', 259100, 0, 1, 259100, 270, 0, 0, 0, 0, 3.0, 1060, 'ウパルパ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】【中距離】【妨害】\\n熔岩の海に潜み、近づくものには\\n灼熱の体液を吐く、山椒魚の魔物。\\n\\n・前から２番目攻撃、火傷\\n・与えるダメージによるＴＰ回復量80％ダウン\\n・火傷ダメージによるＴＰ回復なし', 259200, 0, 1, 259200, 270, 0, 0, 0, 0, 3.0, 1065, 'マグマウパルパ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【魔法】【遠距離】\\n地獄から呼び寄せた炎で魔法を飛ばす上級悪魔。\\n\\n・後ろから２番目攻撃\\n・与えるダメージによるＴＰ回復量80％ダウン', 259300, 0, 2, 259300, 270, 0, 0, 17, 0, 3.5, 1075, 'ファイヤーメイジ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】\\n長年使われるうちに\\n悪魔の魂が宿った、命ある砲台。\\n\\n・近接攻撃\\n・与えるダメージによるＴＰ回復量80％ダウン', 259400, 0, 1, 259400, 270, 0, 0, 16, 0, 4.0, 1055, 'イビルキャノン');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【魔法】【範囲】\\n頭部の石から発する超音波で\\n巧みに狩りをするエイの魔物。\\n\\n・近接２体攻撃\\n・与えるダメージによるＴＰ回復量80％ダウン', 259500, 0, 2, 259500, 270, 0, 0, 0, 0, 3.5, 1070, 'マジックレイ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【魔法】【妨害】\\n浴びれば凍える冷気の魔法で、\\n戦意を奪うオウムガイ型の魔物。\\n\\n・ＨＰの高いキャラを攻撃、攻撃力ダウン\\n・与えるダメージによるＴＰ回復量80％ダウン', 259600, 0, 2, 259600, 270, 0, 0, 7, 0, 4.5, 1080, 'ワイズワンド');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('', 290100, 0, 0, 290100, 0, 0, 0, 0, 0, 0.0, 0, 'モンスター一般');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】さらなる力を得た牡牛座の魔星獣。\\n力の限界を超えた戦斧の一撃が全てを破砕する。\\n\\n・物理攻撃力ダウン効果の影響を受けやすい。\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・ミノタウロスから受けるすべてのダメージで発\\n\u3000生する、パーティキャラのＴＰ回復量を中ダウ\\n\u3000ンさせる。\\n・ユニオンバーストは、敵全体にミノタウロスの\\n\u3000物理攻撃力に応じた物理割合ダメージを与え、\\n\u3000火傷状態を付与する。さらに自身の物理攻撃力\\n\u3000をバトル終了まで小アップさせる。このスキル\\n\u3000によるダメージでは、ＴＰが回復しない。この\\n\u3000スキルの状態異常はダメージを無効化しても付\\n\u3000与される。\\n・最も近い敵１キャラに物理特大ダメージを与え、\\n\u3000スタン状態を付与すると同時にノックバックさ\\n\u3000せる。その後キャラのＨＰが60％未満の場合、\\n\u3000自身の物理攻撃力を中アップさせる。このスキ\\n\u3000ルの状態異常はダメージを無効化しても付与さ\\n\u3000れる。\\n・飛行状態のキャラを含む敵全体に魔法大ダメー\\n\u3000ジを与え、物理クリティカルダメージと魔法ク\\n\u3000リティカルダメージを小ダウンさせる。', 300100, 0, 1, 300100, 270, 0, 0, 3, 0, 1.9, 3000, 'ミノタウロス');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】さらなる力を得た牡牛座の魔星獣。\\n力の限界を超えた戦斧の一撃が全てを破砕する。\\n\\n・物理攻撃力ダウン効果の影響を受けやすい。\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・ミノタウロスから受けるすべてのダメージで発\\n\u3000生する、パーティキャラのＴＰ回復量を中ダウ\\n\u3000ンさせる。\\n・ユニオンバーストは、敵全体にミノタウロスの\\n\u3000物理攻撃力に応じた物理割合ダメージを与え、\\n\u3000火傷状態を付与する。さらに自身の物理攻撃力\\n\u3000をバトル終了まで小アップさせる。このスキル\\n\u3000によるダメージでは、ＴＰが回復しない。この\\n\u3000スキルの状態異常はダメージを無効化しても付\\n\u3000与される。\\n・最も近い敵１キャラに物理特大ダメージを与え、\\n\u3000スタン状態を付与すると同時にノックバックさ\\n\u3000せる。その後キャラのＨＰが60％未満の場合、\\n\u3000自身の物理攻撃力を中アップさせる。このスキ\\n\u3000ルの状態異常はダメージを無効化しても付与さ\\n\u3000れる。\\n・飛行状態のキャラを含む敵全体に魔法大ダメー\\n\u3000ジを与え、物理クリティカルダメージと魔法ク\\n\u3000リティカルダメージを小ダウンさせる。\\n・最も近い敵２キャラに物理特大ダメージを与え、\\n\u3000スタン状態を付与する。その後、その２キャラ\\n\u3000のＨＰがともに60％未満の場合、自身の物理\\n\u3000攻撃力を中アップさせる。このスキルの状態異\\n\u3000常はダメージを無効化しても付与される。', 300101, 0, 1, 300101, 270, 0, 0, 3, 0, 1.9, 3000, 'ミノタウロス');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】さらなる力を得た牡牛座の魔星獣。\\n力の限界を超えた戦斧の一撃が全てを破砕する。\\n\\n・物理攻撃力ダウン効果の影響を受けやすい。\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を中アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・バトル開始時、敵全体のＨＰ吸収を特大ダウン\\n\u3000させる。 \\n・バトル開始時、敵全体のＴＰ上昇を中ダウンさ\\n\u3000せるフィールドを展開する。\\n・バトル開始時、自身にＴＰダウン100％カッ\\n\u3000ト効果を付与する。\\n・ミノタウロスから受けるすべてのダメージで発\\n\u3000生する、パーティキャラのＴＰ回復量を中ダウ\\n\u3000ンさせる。\\n・ユニオンバーストは、敵全体にミノタウロスの\\n\u3000物理攻撃力に応じた物理割合ダメージを与え、\\n\u3000火傷状態を付与する。さらに自身の物理攻撃力\\n\u3000をバトル終了まで小アップさせる。このスキル\\n\u3000によるダメージでは、ＴＰが回復しない。この\\n\u3000スキルの状態異常はダメージを無効化しても付\\n\u3000与される。\\n・最も近い敵１キャラに物理特大ダメージを与え、\\n\u3000スタン状態を付与すると同時にノックバックさ\\n\u3000せる。その後キャラのＨＰが70％未満の場合、\\n\u3000自身の物理攻撃力を中アップさせる。このスキ\\n\u3000ルの状態異常はダメージを無効化しても付与さ\\n\u3000れる。\\n・飛行状態のキャラを含む敵全体に魔法大ダメー\\n\u3000ジを与え、物理クリティカルダメージと魔法ク\\n\u3000リティカルダメージを特大ダウンさせ、麻痺状\\n\u3000態を付与する。このスキルによるダメージでは、\\n\u3000ＴＰが回復しない。このスキルの状態異常はダ\\n\u3000メージを無効化しても付与される。\\n・最も近い敵２キャラに物理特大ダメージを与え、\\n\u3000スタン状態を付与する。その後、その２キャラ\\n\u3000のＨＰがともに70％未満の場合、自身の物理\\n\u3000攻撃力を中アップさせる。このスキルの状態異\\n\u3000常はダメージを無効化しても付与される。\\n・自身と敵全体の物理攻撃力、魔法攻撃力、行動\\n\u3000速度を中アップさせ、物理防御力と魔法防御力\\n\u3000を中ダウンさせる。さらに自身にＴＰ継続回復\\n\u3000状態を付与する。', 300102, 0, 1, 300102, 270, 0, 0, 3, 0, 1.9, 3000, 'ミノタウロス');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('猛毒の尾棘で災厄を振りまく、蠍座の魔星獣。\\n砂漠を護る神蟲が、信仰を失い邪神と化した。\\n\\n・敵全体に物理大ダメージを与える。\\n\u3000ボスがユニオンバーストを使用する毎に、\\n\u3000敵に与えるダメージがアップ。\\n\u3000この効果は、最大３回まで累積する。\\n・前方範囲内の敵に物理中ダメージを与え、\\n\u3000毒状態にする。\\n・自身にかかっているステータスダウン効果を\\n\u3000解除し、さらに自身の物理防御力をアップ。', 300200, 0, 1, 300200, 270, 0, 0, 6, 0, 1.5, 1000, 'レサトパルト');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】信仰を失った神殿に遺る、蠍座の魔星獣。\\n過去に受けた敬虔な祈りも忘れ、破滅をもたらす。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・レサトパルトから受けるすべてのダメージで発\\n\u3000生する、パーティキャラのＴＰ回復量を中ダウ\\n\u3000ンさせる。\\n・ユニオンバーストは、敵全体に物理大ダメージ\\n\u3000を与える。このスキルを使用した後、敵を攻撃\\n\u3000するたび、以降その敵にレサトパルトが与える\\n\u3000ダメージがアップする。この効果は最大３回ま\\n\u3000で累積する。このスキルによるダメージでは、\\n\u3000ＴＰが回復しない。\\n・最も近い敵１キャラを中心にした小範囲に物理\\n\u3000中ダメージを与え、毒状態を付与する。このス\\n\u3000キルにより付与された毒のダメージでは、ＴＰ\\n\u3000が回復しない。\\n・自身の物理攻撃力、物理防御力、魔法防御力を\\n\u3000中アップさせる。', 300201, 0, 1, 300201, 270, 0, 0, 6, 0, 1.5, 1000, 'レサトパルト');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】信仰を失った神殿に遺る、蠍座の魔星獣。\\n過去に受けた敬虔な祈りも忘れ、破滅をもたらす。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・レサトパルトから受けるすべてのダメージで発\\n\u3000生する、パーティキャラのＴＰ回復量を中ダウ\\n\u3000ンさせる。\\n・ユニオンバーストは、敵全体に物理大ダメージ\\n\u3000を与える。このスキルを使用した後、敵を攻撃\\n\u3000するたび、以降その敵にレサトパルトが与える\\n\u3000ダメージがアップする。この効果は最大３回ま\\n\u3000で累積する。このスキルによるダメージでは、\\n\u3000ＴＰが回復しない。\\n・最も近い敵１キャラを中心にした小範囲に物理\\n\u3000中ダメージを与え、毒状態を付与する。このス\\n\u3000キルにより付与された毒のダメージでは、ＴＰ\\n\u3000が回復しない。\\n・自身の物理防御力、魔法防御力を中アップさせ\\n\u3000る。レサトガードが存在する場合、さらに自身\\n\u3000の物理攻撃力を大アップさせる。存在するレサ\\n\u3000トガードの数に応じて、物理防御力、魔法防御\\n\u3000力、物理攻撃力の上昇量がアップする。\\n・レサトガードを１体召喚する。召喚時、すでに\\n\u3000召喚されているレサトガードを１秒間無敵状態\\n\u3000にする。\\n・３体目のレサトガードが召喚された時、敵全体\\n\u3000のバリアを解除し、敵全体にキャラの最大ＨＰ\\n\u3000に応じた魔法割合ダメージを与え、さらにスタ\\n\u3000ン状態を付与する。このスキルの状態異常はダ\\n\u3000メージを無効化しても付与される。\\n・レサトガードのＨＰが一定値以下になった時、\\n\u3000レサトパルトに魔法固定ダメージを与え、さら\\n\u3000に物理攻撃力を中ダウンさせ、消滅する。', 300202, 0, 1, 300202, 270, 0, 0, 6, 0, 1.5, 1000, 'レサトパルト');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】信仰を失った神殿に遺る、蠍座の魔星獣。\\n過去に受けた敬虔な祈りも忘れ、破滅をもたらす。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・レサトパルトから受けるすべてのダメージで発\\n\u3000生する、パーティキャラのＴＰ回復量を中ダウ\\n\u3000ンさせる。\\n・ユニオンバーストは、敵全体に物理大ダメージ\\n\u3000を与える。このスキルを使用した後、敵を攻撃\\n\u3000するたび、以降その敵にレサトパルトが与える\\n\u3000ダメージがアップする。この効果は最大３回ま\\n\u3000で累積する。このスキルによるダメージでは、\\n\u3000ＴＰが回復しない。\\n・最も近い敵１キャラを中心にした小範囲に物理\\n\u3000中ダメージを与え、毒状態を付与する。このス\\n\u3000キルにより付与された毒のダメージでは、ＴＰ\\n\u3000が回復しない。\\n・自身の物理攻撃力、物理防御力、魔法防御力を\\n\u3000中アップさせる。', 300203, 0, 1, 300203, 270, 0, 0, 6, 0, 1.5, 1000, 'レサトパルト');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】信仰を失った神殿に遺る、蠍座の魔星獣。\\n過去に受けた敬虔な祈りも忘れ、破滅をもたらす。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・レサトパルトから受けるすべてのダメージで発\\n\u3000生する、パーティキャラのＴＰ回復量を中ダウ\\n\u3000ンさせる。\\n・ユニオンバーストは、敵全体に物理大ダメージ\\n\u3000を与える。このスキルを使用した後、敵を攻撃\\n\u3000するたび、以降その敵にレサトパルトが与える\\n\u3000ダメージがアップする。この効果は最大３回ま\\n\u3000で累積する。このスキルによるダメージでは、\\n\u3000ＴＰが回復しない。\\n・最も近い敵１キャラを中心にした小範囲に物理\\n\u3000中ダメージを与え、毒状態を付与する。このス\\n\u3000キルにより付与された毒のダメージでは、ＴＰ\\n\u3000が回復しない。\\n・自身の物理防御力、魔法防御力を中アップさせ\\n\u3000る。レサトガードが存在する場合、さらに自身\\n\u3000の物理攻撃力を大アップさせる。存在するレサ\\n\u3000トガードの数に応じて、物理防御力、魔法防御\\n\u3000力、物理攻撃力の上昇量がアップする。\\n・レサトガードを１体召喚する。召喚時、すでに\\n\u3000召喚されているレサトガードを１秒間無敵状態\\n\u3000にする。\\n・３体目のレサトガードが召喚された時、敵全体\\n\u3000のバリアを解除し、敵全体にキャラの最大ＨＰ\\n\u3000に応じた魔法割合ダメージを与え、さらにスタ\\n\u3000ン状態を付与する。このスキルの状態異常はダ\\n\u3000メージを無効化しても付与される。\\n・レサトガードのＨＰが一定値以下になった時、\\n\u3000レサトパルトに魔法固定ダメージを与え、さら\\n\u3000に物理攻撃力を中ダウンさせ、消滅する。', 300204, 0, 1, 300204, 270, 0, 0, 6, 0, 1.5, 1000, 'レサトパルト');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】信仰を失った神殿に遺る、蠍座の魔星獣。\\n過去に受けた敬虔な祈りも忘れ、破滅をもたらす。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を中アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・バトル開始時、敵全体のＴＰ上昇を中ダウンさ\\n\u3000せるフィールドを展開する。\\n・バトル開始時、自身にＴＰダウン50％カット\\n\u3000効果を付与する。\\n・レサトパルトから受けるすべてのダメージで発\\n\u3000生する、パーティキャラのＴＰ回復量を中ダウ\\n\u3000ンさせる。\\n・敵から受けるすべてのダメージで発生する、レ\\n\u3000サトパルトのＴＰ回復量が大ダウンする。\\n・ユニオンバーストは、敵全体に物理大ダメージ\\n\u3000を与える。このスキルを使用した後、敵を攻撃\\n\u3000するたび、以降その敵にレサトパルトが与える\\n\u3000ダメージがアップする。この効果は最大３回ま\\n\u3000で累積する。このスキルによるダメージでは、\\n\u3000ＴＰが回復しない。\\n・最も近い敵１キャラを中心にした小範囲に物理\\n\u3000中ダメージを与え、毒状態を付与する。このス\\n\u3000キルによるダメージと付与された毒のダメージ\\n\u3000では、ＴＰが回復しない。\\n・自身の物理防御力、魔法防御力を中アップさせ\\n\u3000る。レサトガードが存在する場合、さらに自身\\n\u3000の物理攻撃力を大アップさせる。存在するレサ\\n\u3000トガードの数に応じて、物理防御力、魔法防御\\n\u3000力、物理攻撃力の上昇量がアップする。\\n・レサトガードを１体召喚する。召喚時、すでに\\n\u3000召喚されているレサトガードを１秒間無敵状態\\n\u3000にする。\\n・３体目のレサトガードが召喚された時、敵全体\\n\u3000のバリアを解除し、敵全体にキャラの最大ＨＰ\\n\u3000に応じた魔法割合ダメージを与え、さらにスタ\\n\u3000ン状態を付与する。このスキルの状態異常はダ\\n\u3000メージを無効化しても付与される。\\n・レサトガードは、敵全体にキャラの最大ＨＰに\\n\u3000応じた魔法割合ダメージを与え、さらにＴＰを\\n\u3000小ダウンさせる。このスキルはダメージを無効\\n\u3000化してもＴＰをダウンさせる。このスキルによ\\n\u3000るダメージでは、ＴＰが回復しない。\\n・レサトガードは、レサトパルトの物理防御力と\\n\u3000魔法防御力を中アップさせる。\\n・レサトガードのＨＰが一定値以下になった時、\\n\u3000レサトパルトに魔法固定ダメージを与え、さら\\n\u3000に物理攻撃力を中ダウンさせ、消滅する。', 300205, 0, 1, 300205, 270, 0, 0, 6, 0, 1.5, 1000, 'レサトパルト');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】信仰を失った神殿に遺る、蠍座の魔星獣。\\n過去に受けた敬虔な祈りも忘れ、破滅をもたらす。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。\\n\u3000この防御力アップ効果で上昇した防御力は、バ\\n\u3000トル中に受ける防御力ダウンスキルの影響を受\\n\u3000けない。\\n・バトル開始時、敵全体のＴＰ上昇を小ダウンさ\\n\u3000せるフィールドを展開する。\\n・レサトパルトから受けるすべてのダメージで発\\n\u3000生する、パーティキャラのＴＰ回復量を小ダウ\\n\u3000ンさせる。\\n・ユニオンバーストは、敵全体に物理中ダメージ\\n\u3000を与える。\\n\u3000このスキルを使用した後、敵を攻撃するたび、\\n\u3000以降その敵にレサトパルトが与えるダメージが\\n\u3000アップする。\\n\u3000この効果は最大３回まで累積する。\\n\u3000このスキルによるダメージでは、敵のＴＰが回\\n\u3000復しない。\\n・最も近い１キャラを中心にした小範囲に物理中\\n\u3000ダメージを与え、毒状態にする。\\n\u3000このスキルにより付与された毒のダメージでは、\\n\u3000ＴＰが回復しない。\\n・自身の物理攻撃力、物理防御力、魔法防御力を\\n\u3000中アップ。\\n・レサトガードを１体召喚する。\\n\u3000召喚時、すでに召喚されているレサトガードを\\n\u3000１秒間無敵状態にする。\\n・３体目のレサトガードが召喚された時、敵全体\\n\u3000のバリアを解除し、敵全体にキャラの最大ＨＰ\\n\u3000に応じた魔法割合ダメージを与え、さらにスタ\\n\u3000ンさせる。\\n\u3000このスキルの状態異常はダメージを無効化して\\n\u3000も付与される。\\n・レサトガードは、敵全体にキャラの最大ＨＰに\\n\u3000応じた魔法割合ダメージを与え、さらにスタン\\n\u3000させる。\\n\u3000このスキルによるダメージでは、ＴＰ回復量は\\n\u3000減少する。\\n・レサトガードは、レサトパルトの物理防御力と\\n\u3000魔法防御力を中アップさせる。\\n・レサトガードのＨＰが一定値以下になった時、\\n\u3000レサトパルトに魔法固定ダメージを与え、さら\\n\u3000に物理攻撃力を中ダウンし、消滅する。', 300206, 0, 1, 300206, 270, 0, 0, 6, 0, 1.5, 1000, 'レサトパルト');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【魔法】さらなる力を得た牡羊座の魔星獣。\\n鬱々たる眠りの牢獄で冒険者の魂を貪り尽くす。\\n\\n・飛行状態の敵を攻撃対象にできる。\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・メサルティムから受けるすべてのダメージで発\\n\u3000生する、パーティキャラのＴＰ回復量を中ダウ\\n\u3000ンさせる。\\n・ユニオンバーストは、敵全体のバリアを解除し、\\n\u3000敵全体にキャラの最大ＨＰに応じた魔法割合ダ\\n\u3000メージを与える。行動不能状態のキャラには追\\n\u3000加の魔法大ダメージを与え、さらにＴＰを中ダ\\n\u3000ウンさせる。このスキルによる追加ダメージで\\n\u3000は、ＴＰが回復しない。\\n・前方範囲内の敵にキャラの最大ＨＰに応じた魔\\n\u3000法割合ダメージを与える。\\n・敵の挑発を無視して、残りＨＰ割合が最も低い\\n\u3000敵１キャラに束縛状態を付与する。敵キャラの\\n\u3000ＨＰが60％未満の場合、そのキャラを中心に\\n\u3000した小範囲に束縛状態を付与する。', 300300, 0, 2, 300300, 270, 0, 0, 7, 0, 2.5, 3000, 'メサルティム');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【魔法】さらなる力を得た牡羊座の魔星獣。\\n鬱々たる眠りの牢獄で冒険者の魂を貪り尽くす。\\n\\n・飛行状態の敵を攻撃対象にできる。\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・メサルティムから受けるすべてのダメージで発\\n\u3000生する、パーティキャラのＴＰ回復量を中ダウ\\n\u3000ンさせる。\\n・ユニオンバーストは、敵全体のバリアを解除し、\\n\u3000敵全体にキャラの最大ＨＰに応じた魔法割合ダ\\n\u3000メージを与える。行動不能状態のキャラには追\\n\u3000加の魔法大ダメージを与え、さらにＴＰを中ダ\\n\u3000ウンさせる。このスキルによる追加ダメージで\\n\u3000は、ＴＰが回復しない。\\n・前方範囲内の敵にキャラの最大ＨＰに応じた魔\\n\u3000法割合ダメージを与える。\\n・敵の挑発を無視して、残りＨＰ割合が最も低い\\n\u3000敵１キャラに束縛状態を付与する。敵キャラの\\n\u3000ＨＰが60％未満の場合、そのキャラを中心に\\n\u3000した小範囲に束縛状態を付与する。\\n・敵全体のバリアを解除し、敵全体にキャラの最\\n\u3000大ＨＰに応じた魔法割合ダメージを与え、短時\\n\u3000間束縛状態を付与する。敵キャラのＨＰが60％\\n\u3000未満の場合、長時間束縛状態を付与する。', 300301, 0, 2, 300301, 270, 0, 0, 7, 0, 2.5, 3000, 'メサルティム');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【魔法】さらなる力を得た牡羊座の魔星獣。\\n鬱々たる眠りの牢獄で冒険者の魂を貪り尽くす。\\n\\n・飛行状態の敵を攻撃対象にできる。\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を中アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・バトル開始時、敵全体のＨＰ吸収を特大ダウン\\n\u3000させる。\\n・バトル開始時、敵全体のＴＰ上昇を中ダウンさ\\n\u3000せるフィールドを展開する。\\n・バトル開始時、自身にＴＰダウン50％カット\\n\u3000効果を付与する。\\n・メサルティムから受けるすべてのダメージで発\\n\u3000生する、パーティキャラのＴＰ回復量を中ダウ\\n\u3000ンさせる。\\n・ユニオンバーストは、敵全体のバリアを解除し、\\n\u3000敵全体にキャラの最大ＨＰに応じた魔法割合ダ\\n\u3000メージを与える。行動不能状態のキャラには追\\n\u3000加の魔法大ダメージを与え、さらにＴＰを中ダ\\n\u3000ウンさせる。このスキルによるダメージでは、\\n\u3000ＴＰが回復しない。\\n・前方範囲内の敵にキャラの最大ＨＰに応じた魔\\n\u3000法割合ダメージを与える。\\n・敵の挑発を無視して、残りＨＰ割合が最も低い\\n\u3000敵１キャラに束縛状態を付与する。敵キャラの\\n\u3000ＨＰが70％未満の場合、そのキャラを中心に\\n\u3000した小範囲に束縛状態を付与する。\\n・敵全体のバリアを解除し、敵全体にキャラの最\\n\u3000大ＨＰに応じた魔法割合ダメージを与え、短時\\n\u3000間束縛状態を付与する。敵キャラのＨＰが70％\\n\u3000未満の場合、長時間束縛状態を付与する。この\\n\u3000スキルによるダメージでは、ＴＰが回復しない。\\n・敵全体のバリアを解除し、敵全体にキャラの最\\n\u3000大ＨＰに応じた魔法割合ダメージを与える。さ\\n\u3000らに物理攻撃力を中ダウン、魔法攻撃力を大ダ\\n\u3000ウンさせ、ＨＰ吸収とＨＰ回復量を特大ダウン\\n\u3000させる。このスキルによるダメージでは、ＴＰ\\n\u3000が回復しない。このスキルの状態異常はダメー\\n\u3000ジを無効化しても付与される。', 300302, 0, 2, 300302, 270, 0, 0, 7, 0, 2.5, 3000, 'メサルティム');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('妖しき邪教で世界支配を謀る、山羊座の魔星獣。\\n沙漠に迷う人間を誘い、悪魔の儀式で虜とする。\\n\\n・ユニオンバーストは敵全体に魔法大ダメ―ジ\\n\u3000さらに物理攻撃キャラは物理攻撃力をダウン\\n\u3000魔法攻撃キャラは魔法防御力をダウン。\\n・最も物理攻撃力の高い1キャラに魔法特大ダ\\n\u3000メージを与え、さらにＴＰダウン。\\n・前方の2キャラに魔法小ダメージを与え沈黙\\n\u3000状態を付与する。\\n\u3000さらに敵全体に魔法中ダメージ。', 300400, 0, 2, 300400, 270, 0, 0, 7, 0, 1.8, 1000, 'アルゲティ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【魔法】邪教の秘術を極めし、山羊座の魔星獣。\\n膨大な魔力を自在に操り、全ての自由を剥奪する。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・アルゲティから受けるすべてのダメージで発生\\n\u3000する、パーティキャラのＴＰ回復量を中ダウン\\n\u3000させる。\\n・ユニオンバーストは、物理攻撃をする敵全体の\\n\u3000物理攻撃力を大ダウンさせ、魔法攻撃をする敵\\n\u3000全体の魔法攻撃力を大ダウンさせる。このスキ\\n\u3000ルの状態異常は物理攻撃もしくは魔法攻撃をす\\n\u3000るキャラが飛行状態のキャラのみの場合、飛行\\n\u3000状態のキャラにも付与される。\\n・最も近い敵１キャラに魔法特大ダメージを与え、\\n\u3000沈黙状態を付与する。その後、敵全体に魔法大\\n\u3000ダメージを与える。このスキルによる全体ダ\\n\u3000メージでは、ＴＰが回復しない。このスキルの\\n\u3000状態異常はダメージを無効化しても付与される。\\n・最も近い敵１キャラに魔法特大ダメージを与え、\\n\u3000ＴＰを中ダウンさせる。このスキルはダメージ\\n\u3000を無効化してもＴＰをダウンさせる。', 300401, 0, 2, 300401, 270, 0, 0, 7, 0, 1.8, 1000, 'アルゲティ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【魔法】邪教の秘術を極めし、山羊座の魔星獣。\\n膨大な魔力を自在に操り、全ての自由を剥奪する。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・アルゲティから受けるすべてのダメージで発生\\n\u3000する、パーティキャラのＴＰ回復量を中ダウン\\n\u3000させる。\\n・ユニオンバーストは、物理攻撃をする敵全体の\\n\u3000物理攻撃力を大ダウンさせ、魔法攻撃をする敵\\n\u3000全体の魔法攻撃力を大ダウンさせる。このスキ\\n\u3000ルの状態異常は物理攻撃もしくは魔法攻撃をす\\n\u3000るキャラが飛行状態のキャラのみの場合、飛行\\n\u3000状態のキャラにも付与される。\\n・最も近い敵１キャラに魔法特大ダメージを与え、\\n\u3000沈黙状態を付与する。その後、敵全体に魔法大\\n\u3000ダメージを与える。このスキルによる全体ダ\\n\u3000メージでは、ＴＰが回復しない。このスキルの\\n\u3000状態異常はダメージを無効化しても付与される。\\n・最も近い敵１キャラに魔法特大ダメージを与え、\\n\u3000ＴＰを中ダウンさせる。このスキルはダメージ\\n\u3000を無効化してもＴＰをダウンさせる。\\n・敵全体に魔法大ダメージを与え、沈黙状態を付\\n\u3000与する。このスキルによるダメージでは、ＴＰ\\n\u3000が回復しない。', 300402, 0, 2, 300402, 270, 0, 0, 7, 0, 1.8, 1000, 'アルゲティ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【魔法】邪教の秘術を極めし、山羊座の魔星獣。\\n膨大な魔力を自在に操り、全ての自由を剥奪する。\\n\\n・ユニオンバーストは敵全体に魔法大ダメージ\\n\u3000さらに物理攻撃キャラは物理攻撃力をダウン\\n\u3000魔法攻撃キャラは魔法攻撃力をダウン。\\n・前から１キャラに魔法特大ダメージを与え沈黙\\n\u3000状態を付与する。\\n\u3000さらに敵全体に魔法中ダメージ。\\n・最も物理攻撃力の高い１キャラに\\n\u3000魔法大ダメージを与え、さらにＴＰダウン。\\n・アルゲティが毒、猛毒、呪い、火傷の\\n\u3000効果を受けていると、自身に沈黙状態を\\n\u3000付与し、さらに魔法大ダメージを与える。\\n\u3000効果を受けていない場合、敵全体に\\n\u3000沈黙状態を付与し、\\n\u3000さらに魔法大ダメージを与える。', 300403, 0, 2, 300403, 270, 0, 0, 7, 0, 1.8, 1000, 'アルゲティ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【魔法】邪教の秘術を極めし、山羊座の魔星獣。\\n膨大な魔力を自在に操り、全ての自由を剥奪する。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を中アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・バトル開始時、敵全体のＴＰ上昇を中ダウンさ\\n\u3000せるフィールドを展開する。\\n・バトル開始時、自身にＴＰダウン100％カッ\\n\u3000ト効果を付与する。\\n・アルゲティから受けるすべてのダメージで発生\\n\u3000する、パーティキャラのＴＰ回復量を中ダウン\\n\u3000させる。\\n・敵から受けるすべてのダメージで発生する、ア\\n\u3000ルゲティのＴＰ回復量が大ダウンする。\\n・ユニオンバーストは、物理攻撃をする敵全体の\\n\u3000物理攻撃力を特大ダウンさせ、魔法攻撃をする\\n\u3000敵全体の魔法攻撃力を特大ダウンさせる。さら\\n\u3000に、敵全体のＴＰ上昇を特大ダウンさせる。こ\\n\u3000のスキルの攻撃力ダウン効果は物理攻撃もしく\\n\u3000は魔法攻撃をするキャラが飛行状態のキャラの\\n\u3000みの場合、飛行状態のキャラにも付与される。\\n・最も近い敵１キャラに魔法特大ダメージを与え、\\n\u3000ＵＢ封印状態を付与する。その後、敵全体に魔\\n\u3000法中ダメージを与える。最も近い敵１キャラの\\n\u3000ＨＰが70％以下の場合、敵全体に魔法特大ダ\\n\u3000メージを与え、ＵＢ封印状態を付与する。この\\n\u3000スキルによる全体ダメージでは、ＴＰが回復し\\n\u3000ない。このスキルの状態異常はダメージを無効\\n\u3000化しても付与される。\\n・最も近い敵１キャラに魔法特大ダメージを与え、\\n\u3000ＴＰを中ダウンさせる。その後、最も近い敵１\\n\u3000キャラのＨＰが70％以下の場合、敵全体の\\n\u3000ＴＰを中ダウンさせ、自身のＴＰを大回復させ\\n\u3000る。このスキルはダメージを無効化してもＴＰ\\n\u3000をダウンさせる。\\n・敵全体に魔法中ダメージを与え、沈黙状態を付\\n\u3000与する。このスキルによるダメージでは、ＴＰ\\n\u3000が回復しない。', 300404, 0, 2, 300404, 270, 0, 0, 7, 0, 1.8, 1000, 'アルゲティ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】二刀を自在に操り、\\n煙幕弾で相手の目を\\nくらませる\\nオオトカゲの戦士。\\n\\n・ランダムな1キャラに物理\\n\u3000中ダメージを与える。\\n\\n・ランダムな敵を中心にした小範囲\\n\u3000に、物理小ダメージを与え、\\n\u3000暗闇状態にする。', 300500, 0, 1, 300500, 270, 0, 0, 4, 0, 1.8, 1000, 'リザードマン');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】頭から放つ毒攻撃と\\nツタによる範囲物理攻撃で\\n近づく冒険者の体力を一気に奪う\\n悪魔の花。\\n\\n・前方2キャラに物理中ダメージ\\n\u3000を与える。\\n\\n・前方3キャラの物理防御力を\\n\u3000下げ、毒状態にする。', 300600, 0, 1, 300600, 270, 0, 0, 2, 0, 1.8, 1000, 'クリーパー');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】特異な力で変質したクリーパー。\\n無数のトゲを持つ蔓を巻き付け、動きを奪う。\\n\\n・前方範囲内の敵に物理中ダメージを与え、\\n\u3000拘束状態にする。\\n・前方範囲内の敵の物理防御力を下げ、毒\\n\u3000状態にする。', 300601, 0, 1, 300601, 270, 0, 0, 2, 0, 1.8, 1000, 'ニードルクリーパー');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】特異な力で変質したクリーパー。\\n無数のトゲを持つ蔓を巻き付け、動きを奪う。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。\\n\u3000この防御力アップ効果で上昇した防御力は、バ\\n\u3000トル中に受ける防御力ダウンスキルの影響を受\\n\u3000けない。\\n・ニードルクリーパーから受けるすべてのダメー\\n\u3000ジで発生する、パーティキャラのＴＰ回復量を\\n\u3000中ダウンさせる。\\n・ユニオンバーストは、最も近い２キャラに物理\\n\u3000中ダメージを与え、拘束状態を付与する。\\n\u3000このスキルの状態異常はダメージを無効化して\\n\u3000も付与される。\\n・最も近い３キャラの物理防御力を中ダウンし、\\n\u3000毒状態を付与する。\\n\u3000このスキルにより付与された毒のダメージでは、\\n\u3000ＴＰが回復しない。', 300602, 0, 1, 300602, 270, 0, 0, 2, 0, 1.8, 1000, 'ニードルクリーパー');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】特異な力で変質したクリーパー。\\n無数のトゲを持つ蔓を巻き付け、動きを奪う。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を中アップさせる。\\n\u3000この防御力アップ効果で上昇した防御力は、バ\\n\u3000トル中に受ける防御力ダウンスキルの影響を受\\n\u3000けない。\\n・ニードルクリーパーから受けるすべてのダメー\\n\u3000ジで発生する、パーティキャラのＴＰ回復量を\\n\u3000中ダウンさせる。\\n・ユニオンバーストは、最も近い２キャラに物理\\n\u3000中ダメージを与える。\\n\u3000さらに拘束状態を付与し、ＴＰを大ダウン。\\n\u3000このスキルの状態異常はダメージを無効化して\\n\u3000も付与される。\\n・最も近い３キャラの物理防御力を中ダウンし、\\n\u3000毒状態を付与する。\\n\u3000このスキルにより付与された毒のダメージでは、\\n\u3000ＴＰが回復しない。', 300603, 0, 1, 300603, 270, 0, 0, 2, 0, 1.8, 1000, 'ニードルクリーパー');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】広大な砂海に棲む巨大な\\n食人植物の魔物。凶悪なトゲの蔓\\nで動きを封じ、冒険者を捕食する。\\n\\n・ユニオンバーストは、前から２\\n\u3000キャラに物理中ダメージを与え、\\n\u3000拘束状態にする。\\n\\n・前から３キャラの敵の物理防御\\n\u3000力を下げ、毒状態にする。', 300604, 0, 1, 300604, 270, 0, 0, 2, 0, 1.8, 1000, 'サンドクリーパー');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】特異な力で変質したクリーパー。\\n無数のトゲを持つ蔓を巻き付け、動きを奪う。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。\\n\u3000この防御力アップ効果で上昇した防御力は、バ\\n\u3000トル中に受ける防御力ダウンスキルの影響を受\\n\u3000けない。\\n・ニードルクリーパーから受けるすべてのダメー\\n\u3000ジで発生する、パーティキャラのＴＰ回復量を\\n\u3000中ダウンさせる。\\n・ユニオンバーストは、最も近い２キャラに物理\\n\u3000中ダメージを与える。\\n\u3000さらに拘束状態を付与し、ＴＰを大ダウン。\\n\u3000このスキルの状態異常はダメージを無効化して\\n\u3000も付与される。\\n・最も近い３キャラの物理防御力を中ダウンし、\\n\u3000毒状態を付与する。\\n\u3000このスキルにより付与された毒のダメージでは、\\n\u3000ＴＰが回復しない。', 300605, 0, 1, 300605, 270, 0, 0, 2, 0, 1.8, 3000, 'ニードルクリーパー');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】特異な力で変質したクリーパー。\\n無数のトゲを持つ蔓を巻き付け、動きを奪う。\\n\\n・ニードルクリーパーから受けるすべてのダメー\\n\u3000ジで発生する、パーティキャラのＴＰ回復量を\\n\u3000中ダウンさせる。\\n・ユニオンバーストは、最も近い敵２キャラに物\\n\u3000理大ダメージを与え、拘束状態を付与し、ＴＰ\\n\u3000を大ダウンさせる。このスキルの状態異常はダ\\n\u3000メージを無効化しても付与される。\\n・最も近い敵３キャラの物理防御力を大ダウンさ\\n\u3000せ、毒状態を付与する。このスキルにより付与\\n\u3000された毒のダメージでは、ＴＰが回復しない。', 300606, 0, 1, 300606, 270, 0, 0, 2, 0, 1.8, 3000, 'ニードルクリーパー');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】特異な力で変質したクリーパー。\\n無数のトゲを持つ蔓を巻き付け、動きを奪う。\\n\\n・環境効果【炎天烈日】を発動する。このスキル\\n\u3000の効果は敵、味方すべてに適用される。一定時\\n\u3000間が経過するごとに、敵、味方全体に最大ＨＰ\\n\u3000に応じた最大20万の割合ダメージを与える。\\n\u3000さらに、付与される継続ダメージが上昇する。\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を中アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・バトル開始時、自身にＴＰダウン50％カット\\n\u3000効果を付与する。\\n・バトル開始時、敵全体のＨＰ吸収を特大ダウン\\n\u3000させる。\\n・自身が一度の行動で受けるダメージ値を減衰さ\\n\u3000せる。ダメージ値が上昇するほど減衰率も上昇\\n\u3000する。\\n・バトル開始時、敵全体にＴＰ上昇上限効果を付\\n\u3000与する。\\n・ニードルクリーパーから受けるすべてのダメー\\n\u3000ジで発生する、パーティキャラのＴＰ回復量を\\n\u3000中ダウンさせる。\\n・ユニオンバーストは、最も近い敵２キャラに物\\n\u3000理大ダメージを与え、拘束状態を付与し、ＴＰ\\n\u3000を大ダウンさせる。このスキルの状態異常はダ\\n\u3000メージを無効化しても付与される。\\n・最も近い敵３キャラの物理防御力を大ダウンさ\\n\u3000せ、毒状態を付与する。このスキルにより付与\\n\u3000された毒のダメージでは、ＴＰが回復しない。', 300607, 0, 1, 300607, 270, 0, 0, 2, 0, 1.8, 3000, 'ニードルクリーパー');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】族長として群れを鼓舞し\\n大地を砕くほどの連撃で\\n敵に大ダメージを与える\\nオーク中のオーク。\\n\\n・ランダムな3キャラに\\n\u3000物理中ダメージを与える。\\n\\n・味方全体の物理攻撃力を上げる。', 300700, 0, 1, 300700, 270, 0, 0, 13, 0, 1.5, 1000, 'オークリーダー');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】特異な力で変質したオークリーダー。\\n巨大な盾で、攻防一体の一撃を繰り出す。\\n\\n・物理攻撃力ダウン効果の影響を受けやすい。\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・オークチーフから受けるすべてのダメージで発\\n\u3000生する、パーティキャラのＴＰ回復量を中ダウ\\n\u3000ンさせる。\\n・ユニオンバーストは、最も近い敵３キャラに\\n\u3000オークチーフの物理攻撃力に応じた物理固定ダ\\n\u3000メージを与え、スタン状態を付与する。このス\\n\u3000キルの状態異常はダメージを無効化しても付与\\n\u3000される。\\n・最も近い敵２キャラのＴＰを小ダウンさせ、\\n\u3000ＨＰ吸収を特大ダウンさせる。さらに自身の\\n\u3000ＴＰを小回復し、行動速度を中アップさせる。', 300701, 0, 1, 300701, 270, 0, 0, 13, 0, 1.5, 1000, 'オークチーフ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】特異な力で変質したオークリーダー。\\n巨大な盾で、攻防一体の一撃を繰り出す。\\n\\n・物理攻撃力ダウン効果の影響を受けやすい。\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を中アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・バトル開始時、自身にＴＰダウン100％カッ\\n\u3000ト効果を付与する。\\n・バトル開始時、敵全体のＨＰ吸収を特大ダウン\\n\u3000させ、ＴＰ上昇を小ダウンさせる。\\n・オークチーフから受けるすべてのダメージで発\\n\u3000生する、パーティキャラのＴＰ回復量を中ダウ\\n\u3000ンさせる。\\n・ユニオンバーストは、召喚体、分身を除いた最\\n\u3000も近い敵３キャラにオークチーフの物理攻撃力\\n\u3000に応じた物理固定ダメージを与え、スタン状態\\n\u3000を付与する。このスキルの状態異常はダメージ\\n\u3000を無効化しても付与される。\\n・召喚体、分身を除いた最も近い敵２キャラの\\n\u3000ＴＰを小ダウンさせ、ＨＰ吸収を特大ダウンさ\\n\u3000せる。さらに自身のＴＰを小回復し、物理防御\\n\u3000力を小アップさせ、行動速度を中アップさせる。', 300702, 0, 1, 300702, 270, 0, 0, 13, 0, 1.5, 1000, 'オークチーフ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】特異な力で変質したオーク\\nリーダー。巨大な盾で、攻防一体の\\n一撃を繰り出す。\\n\\n・ユニオンバーストは、前方\\n\u3000３キャラに物理大ダメージを\\n\u3000与え、さらにスタンさせる。\\n\\n・前方２キャラの物理防御力を\\n\u3000大ダウン。', 300703, 0, 1, 300703, 270, 0, 0, 13, 0, 1.5, 1000, 'オークチーフ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】特異な力で変質したオークリーダー。\\n巨大な盾で、攻防一体の一撃を繰り出す。\\n\\n・物理攻撃力ダウン効果の影響を受けやすい。\\n・オークチーフから受けるすべてのダメージで発\\n\u3000生する、パーティキャラのＴＰ回復量を中ダウ\\n\u3000ンさせる。\\n・ユニオンバーストは、召喚体、分身を除いた最\\n\u3000も近い敵３キャラにオークチーフの物理攻撃力\\n\u3000に応じた物理固定ダメージを与え、スタン状態\\n\u3000を付与する。このスキルの状態異常はダメージ\\n\u3000を無効化しても付与される。\\n・召喚体、分身を除いた最も近い敵２キャラの\\n\u3000ＴＰを小ダウンさせ、ＨＰ吸収を特大ダウンさ\\n\u3000せる。さらに自身のＴＰを小回復し、物理防御\\n\u3000力を小アップさせ、行動速度を中アップさせる。', 300704, 0, 1, 300704, 270, 0, 0, 13, 0, 1.5, 3000, 'オークチーフ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】ひとたび暴れ出せば\\n手が付けられず、その嘶きは\\n天まで届くと言われる\\n伝説のワイルドホーン。\\n\\n・敵全体に物理中ダメージを与え、\\n\u3000小さく引き寄せる。\\n\\n・前方3キャラに物理中ダメージを\\n\u3000与え、物理防御力を下げる。', 300800, 0, 1, 300800, 270, 0, 0, 1, 0, 1.8, 1000, 'エルダーホーン');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】特異な力で変質したエルダーホーン。\\n角に魔力を込め、打撃より強力な一撃を放つ。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・スピリットホーンから受けるすべてのダメージ\\n\u3000で発生する、パーティキャラのＴＰ回復量を小\\n\u3000ダウンさせる。\\n・ユニオンバーストは、敵の挑発を無視して、物\\n\u3000理攻撃力もしくは魔法攻撃力が最も高い敵１\\n\u3000キャラに魔法大ダメージを与え、麻痺状態を付\\n\u3000与する。さらに物理攻撃力を特大ダウンさせ、\\n\u3000魔法攻撃力を中ダウンさせ、ＴＰを毎秒小ダウ\\n\u3000ンさせる。このスキルの状態異常はダメージを\\n\u3000無効化しても付与される。\\n・敵全体に魔法小ダメージを与え、物理攻撃力を\\n\u3000大ダウンさせ、魔法攻撃力を小ダウンさせ、さ\\n\u3000らに自身のＴＰを小アップする。このスキルに\\n\u3000よるダメージでは、敵のＴＰが回復しない。こ\\n\u3000のスキルの状態異常はダメージを無効化しても\\n\u3000付与される。', 300801, 0, 1, 300801, 270, 0, 0, 1, 0, 1.8, 3000, 'スピリットホーン');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】特異な力で変質したエルダーホーン。\\n角に魔力を込め、打撃より強力な一撃を放つ。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を中アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・バトル開始時、敵全体のＴＰ上昇を小ダウンさ\\n\u3000せるフィールドを展開する。\\n・バトル開始時、自身にＴＰダウン50％カット\\n\u3000効果を付与する。\\n・スピリットホーンから受けるすべてのダメージ\\n\u3000で発生する、パーティキャラのＴＰ回復量を小\\n\u3000ダウンさせる。\\n・敵から受けるすべてのダメージで発生する、ス\\n\u3000ピリットホーンのＴＰ回復量が大ダウンする。\\n・ユニオンバーストは、敵の挑発を無視して、物\\n\u3000理攻撃力もしくは魔法攻撃力が最も高い敵１\\n\u3000キャラに魔法大ダメージを与え、麻痺状態を付\\n\u3000与する。さらに物理攻撃力を特大ダウンさせ、\\n\u3000魔法攻撃力を中ダウンさせ、ＴＰを毎秒小ダウ\\n\u3000ンさせる。このスキルの状態異常はダメージを\\n\u3000無効化しても付与される。\\n・敵全体に魔法小ダメージを与え、物理攻撃力を\\n\u3000大ダウンさせ、魔法攻撃力を小ダウンさせ、さ\\n\u3000らに自身のＴＰを中アップする。このスキルに\\n\u3000よるダメージでは、敵のＴＰが回復しない。こ\\n\u3000のスキルの状態異常はダメージを無効化しても\\n\u3000付与される。', 300802, 0, 1, 300802, 270, 0, 0, 1, 0, 1.8, 3000, 'スピリットホーン');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】特異な力で変質したエルダーホーン。\\n角に魔力を込め、打撃より強力な一撃を放つ。\\n\\n・スピリットホーンから受けるすべてのダメージ\\n\u3000で発生する、パーティキャラのＴＰ回復量を中\\n\u3000ダウンさせる。\\n・ユニオンバーストは、敵の挑発を無視して、物\\n\u3000理攻撃力もしくは魔法攻撃力が最も高い敵１\\n\u3000キャラに魔法大ダメージを与え、麻痺状態を付\\n\u3000与する。さらに物理攻撃力と魔法攻撃力を特大\\n\u3000ダウンさせ、ＴＰを毎秒小ダウンさせる。この\\n\u3000スキルの状態異常はダメージを無効化しても付\\n\u3000与される。このスキルはダメージを無効化して\\n\u3000もＴＰをダウンさせる。\\n・敵全体に魔法小ダメージを与え、物理攻撃力と\\n\u3000魔法攻撃力を大ダウンさせ、さらに自身のＴＰ\\n\u3000を中回復する。このスキルによるダメージでは、\\n\u3000敵のＴＰが回復しない。このスキルの状態異常\\n\u3000はダメージを無効化しても付与される。', 300803, 0, 1, 300803, 270, 0, 0, 1, 0, 1.8, 3000, 'スピリットホーン');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】岩山の如く進化した、大いなる老亀。\\n強力無比な頭突きは、大地を容易く砕き割る。\\n\\n・ユニオンバーストは前から４キャラに物理\\n\u3000ダメージを与え、さらに麻痺状態にする。\\n・前方3キャラに物理防御力ダウン。', 300900, 0, 1, 300900, 270, 0, 0, 13, 0, 1.8, 1000, 'エルダータイラント');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】強力な氷のブレスで\\n前衛を一瞬で氷漬けにし、\\n咬みついて身体を砕く\\n獰猛な深海竜。\\n\\n・前方3キャラに物理中ダメージを\\n\u3000与える。\\n\\n・前方2キャラに物理中ダメージを\\n\u3000与え、凍結状態にする。', 301000, 0, 1, 301000, 270, 0, 0, 14, 0, 1.8, 1000, 'シードレイク');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】強力な氷のブレスで前衛を一瞬で\\n氷漬けにし、咬みついて身体を砕く獰猛な深海竜。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・シードレイクから受けるすべてのダメージで発\\n\u3000生する、パーティキャラのＴＰ回復量を中ダウ\\n\u3000ンさせる。\\n・ユニオンバーストは、召喚体、分身を除いた最\\n\u3000も近い敵３キャラに物理特大ダメージを与え、\\n\u3000さらに物理防御力と魔法防御力を特大ダウンさ\\n\u3000せる。このスキルの状態異常はダメージを無効\\n\u3000化しても付与される。\\n・召喚体、分身を除いた最も近い敵２キャラに魔\\n\u3000法大ダメージを与え、短時間凍結状態を付与す\\n\u3000る。敵キャラのＨＰが80％未満の場合、長時\\n\u3000間凍結状態を付与する。このスキルの状態異常\\n\u3000はダメージを無効化しても付与される。', 301001, 0, 1, 301001, 270, 0, 0, 14, 0, 1.8, 1000, 'シードレイク');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】強力な氷のブレスで前衛を一瞬で\\n氷漬けにし、咬みついて身体を砕く獰猛な深海竜。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を中アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・バトル開始時、敵全体のＨＰ吸収を特大ダウン\\n\u3000させる。 \\n・バトル開始時、敵全体のＴＰ上昇を小ダウンさ\\n\u3000せるフィールドを展開する。\\n・バトル開始時、自身にＴＰダウン100％カッ\\n\u3000ト効果を付与する。\\n・シードレイクから受けるすべてのダメージで発\\n\u3000生する、パーティキャラのＴＰ回復量を中ダウ\\n\u3000ンさせる。\\n・ユニオンバーストは、召喚体、分身を除いた最\\n\u3000も近い敵３キャラに物理特大ダメージを与え、\\n\u3000さらに物理防御力と魔法防御力を特大ダウンさ\\n\u3000せる。このスキルの状態異常はダメージを無効\\n\u3000化しても付与される。\\n・召喚体、分身を除いた最も近い敵２キャラに魔\\n\u3000法大ダメージを与え、短時間凍結状態を付与す\\n\u3000る。敵キャラのＨＰが80％未満の場合、長時\\n\u3000間凍結状態を付与する。このスキルの状態異常\\n\u3000はダメージを無効化しても付与される。', 301002, 0, 1, 301002, 270, 0, 0, 14, 0, 1.8, 1000, 'シードレイク');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】強力な氷のブレスで前衛を一瞬で\\n氷漬けにし、咬みついて身体を砕く獰猛な深海竜。\\n\\n・シードレイクから受けるすべてのダメージで発\\n\u3000生する、パーティキャラのＴＰ回復量を中ダウ\\n\u3000ンさせる。\\n・ユニオンバーストは、召喚体、分身を除いた最\\n\u3000も近い敵３キャラに物理特大ダメージを与え、\\n\u3000さらに物理防御力と魔法防御力を特大ダウンさ\\n\u3000せる。このスキルの状態異常はダメージを無効\\n\u3000化しても付与される。\\n・召喚体、分身を除いた最も近い敵２キャラに魔\\n\u3000法大ダメージを与え、短時間凍結状態を付与す\\n\u3000る。敵キャラのＨＰが70％未満の場合、長時\\n\u3000間凍結状態を付与する。このスキルの状態異常\\n\u3000はダメージを無効化しても付与される。', 301003, 0, 1, 301003, 270, 0, 0, 14, 0, 1.8, 1000, 'シードレイク');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】体格にそぐわぬ俊敏さと\\n咬みつき攻撃で体力を奪い、\\n巨大なツメで敵を引き裂く\\n残虐非道な森の支配者。\\n\\n・前方4キャラに物理大ダメージを\\n\u3000与える。\\n\\n・前方1キャラに物理小ダメージを\\n\u3000与え、物理攻撃力を下げる。', 301100, 0, 1, 301100, 270, 0, 0, 13, 0, 1.7, 1000, 'サベージベア');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】特異な力で変質したサベージベア。\\n怒りを込めた剛腕は、敵ごと地面を引き裂く。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・マッドベアから受けるすべてのダメージで発生\\n\u3000する、パーティキャラのＴＰ回復量を中ダウン\\n\u3000させる。\\n・ユニオンバーストは、最も近い敵１キャラを中\\n\u3000心にした小範囲に物理特大ダメージを与え、さ\\n\u3000らにスタン状態を付与する。このスキルの状態\\n\u3000異常はダメージを無効化しても付与される。\\n・最も近い敵１キャラを中心にした小範囲に物理\\n\u3000小ダメージを与え、物理防御力を特大ダウンさ\\n\u3000せる。このスキルの状態異常はダメージを無効\\n\u3000化しても付与される。', 301101, 0, 1, 301101, 270, 0, 0, 13, 0, 2.0, 1000, 'マッドベア');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】特異な力で変質したサベージベア。\\n怒りを込めた剛腕は、敵ごと地面を引き裂く。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を中アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・バトル開始時、敵全体のＴＰ上昇を小ダウンさ\\n\u3000せるフィールドを展開する。\\n・バトル開始時、自身にＴＰダウン100％カッ\\n\u3000ト効果を付与する。\\n・マッドベアから受けるすべてのダメージで発生\\n\u3000する、パーティキャラのＴＰ回復量を中ダウン\\n\u3000させる。\\n・敵から受けるすべてのダメージで発生する、\\n\u3000マッドベアのＴＰ回復量が大ダウンする。\\n・ユニオンバーストは、最も近い敵１キャラを中\\n\u3000心にした小範囲に物理特大ダメージを与え、さ\\n\u3000らにノックバックさせ、スタン状態を付与する。\\n\u3000このスキルの状態異常はダメージを無効化して\\n\u3000も付与される。\\n・最も近い敵１キャラを中心にした小範囲に物理\\n\u3000小ダメージを与え、物理防御力を特大ダウンさ\\n\u3000せる。このスキルの状態異常はダメージを無効\\n\u3000化しても付与される。', 301102, 0, 1, 301102, 270, 0, 0, 13, 0, 2.0, 1000, 'マッドベア');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】特異な力で変質したサベージベア。\\n怒りを込めた剛腕は、敵ごと地面を引き裂く。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。\\n\u3000この防御力アップ効果で上昇した防御力は、バ\\n\u3000トル中に受ける防御力ダウンスキルの影響を受\\n\u3000けない。\\n・マッドベアから受けるすべてのダメージで発生\\n\u3000する、パーティキャラのＴＰ回復量を大ダウン\\n\u3000させる。\\n・ユニオンバーストは、最も近い敵１キャラを中\\n\u3000心にした小範囲に物理特大ダメージを与え、さ\\n\u3000らにスタンさせる。\\n\u3000このスキルの状態異常はダメージを無効化して\\n\u3000も付与される。\\n・最も近い敵１キャラを中心にした小範囲に物理\\n\u3000大ダメージを与え、物理防御力を大ダウンさせ\\n\u3000る。\\n\u3000このスキルの状態異常はダメージを無効化して\\n\u3000も付与される。', 301103, 0, 1, 301103, 270, 0, 0, 13, 0, 2.0, 1000, 'マッドベア');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】塔の魔力で狂暴化した森の支配者。\\n狂気に飲まれ放つ斬撃は、周囲の全てを粉砕する。\\n\\n・バトル開始時、自身にダメージ上限スキルを使\\n\u3000用し、一度の行動で受けるダメージの値が一定\\n\u3000を超えた場合、ダメージ量を減少させる。\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・バトル開始時、自身にＴＰダウン50%カット\\n\u3000効果を付与する。\\n・ルナティックベアから受けるすべてのダメージ\\n\u3000で発生する、パーティキャラのＴＰ回復量を小\\n\u3000ダウンさせる。\\n・ユニオンバーストは、最も近い敵１キャラを中\\n\u3000心にした小範囲に物理特大ダメージを与え、さ\\n\u3000らにスタンさせる。このスキルの状態異常はダ\\n\u3000メージを無効化しても付与される。\\n・最も近い敵１キャラを中心にした小範囲に物理\\n\u3000大ダメージを与え、物理防御力を特大ダウンさ\\n\u3000せる。このスキルの状態異常はダメージを無効\\n\u3000化しても付与される。', 301104, 0, 1, 301104, 270, 0, 0, 13, 0, 2.0, 1000, 'ルナティックベア');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】特異な力で変質した\\nサベージベア。怒りを込めた\\n剛腕は、敵ごと地面を引き裂\\nく。\\n\\n・ユニオンバーストは、最も\\n\u3000近い敵１キャラを中心にし\\n\u3000た小範囲に物理特大ダメー\\n\u3000ジを与え、さらにスタンさ\\n\u3000せる。\\n\\n・最も近い敵１キャラを中心\\n\u3000にした小範囲に物理大ダ\\n\u3000メージを与え、物理防御力\\n\u3000を大ダウンさせる。', 301105, 0, 1, 301105, 270, 0, 0, 13, 0, 2.0, 1000, 'マッドベア');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】際限なくゴーレムを召喚し\\n岩の針で体力と精神を同時に削る。\\n無数のゴーレムの残骸を\\n魔力で再構築した巨大なゴーレム。\\n\\n・前方4キャラに物理中ダメージを\\n\u3000与え、ＴＰを下げる。\\n\\n・ゴーレムを召喚する。', 301200, 0, 1, 301200, 270, 0, 0, 13, 0, 1.6, 1000, 'グレーターゴーレム');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】ルナの魔力の結晶でその身を覆う巨大\\nゴーレム。身に纏う結晶は堅牢な盾であり、全\\nてを穿つ矛となる。\\n\\n・クリスタルゴーレムが毒、猛毒、呪い、火傷の\\n\u3000効果を受けると、行動速度が大ダウンする。\\n・ユニオンバーストは、自身のデバフ効果をすべ\\n\u3000て解除し、物理防御力と魔法防御力を大アップ\\n\u3000させる。さらに、自分以外の味方の物理防御力\\n\u3000と魔法防御力を中アップさせる。\\n・敵全体に物理中ダメージを与え、スタンさせる。\\n・前方範囲内の敵に物理大ダメージを与え、味方\\n\u3000全体の物理攻撃力と魔法攻撃力を小アップさせ\\n\u3000る。さらに、自身のＴＰを中回復する。\\n・自身のＨＰが40％を切ると、さらに攻撃が激\\n\u3000しく凶暴になる。', 301201, 0, 1, 301201, 270, 0, 0, 13, 0, 1.3, 1000, 'クリスタルゴーレム');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】凍てつく大地の洞窟に\\n潜む巨大ゴーレム。身に纏う\\n結晶は堅牢な盾にも矛にもなる。\\n\\n・アイスゴーレムが毒、猛毒、呪\\n\u3000い、火傷の効果を受けると、行\\n\u3000動速度が大ダウンする。\\n\\n・自身のデバフ効果をすべて解除\\n\u3000し、物理防御力と魔法防御力を\\n\u3000中アップする。\\n\\n・敵全体に物理中ダメージを与え\\n\u3000る。\\n\\n・前方範囲内の敵に物理大ダメー\\n\u3000ジを与える。', 301202, 0, 1, 301202, 270, 0, 0, 13, 0, 1.3, 1000, 'アイスゴーレム');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】凍てつく大地の洞窟に\\n潜む巨大ゴーレム。身に纏う\\n結晶は堅牢な盾にも矛にもなる。\\n\\n・アイスゴーレムが毒、猛毒、呪\\n\u3000い、火傷の効果を受けると、行\\n\u3000動速度が大ダウンする。\\n\\n・自身のデバフ効果をすべて解除\\n\u3000し、物理防御力と魔法防御力を\\n\u3000中アップする。\\n\\n・敵全体に物理中ダメージを与え\\n\u3000る。\\n\\n・前方範囲内の敵に物理大ダメー\\n\u3000ジを与える。', 301203, 0, 1, 301202, 270, 0, 0, 13, 0, 1.3, 1000, 'アイスゴーレム');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('暴食の凶獣として悪名轟く、天秤座の魔星獣。\\n奪った魂の善悪をはかり、味の違いを愉しむ。\\n\\n・敵からの攻撃による麻痺、スタン、束縛、\\n\u3000行動速度低下効果への耐性を持たない。\\n・敵全体に魔法大ダメージを与え、さらに自\\n\u3000身の物理攻撃力と魔法攻撃力を特大アップ。\\n・後方範囲内の敵に魔法中ダメージ。\\n・前方範囲内の敵に魔法中ダメージを与え、Ｔ\\n\u3000Ｐを小ダウン。さらに自身のＴＰを中アップ\\n\u3000させる。', 301300, 0, 1, 301300, 270, 0, 0, 4, 0, 3.0, 1000, 'グラットン');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】あらゆる魂を貪る、天秤座の魔星獣。\\nその天秤は、厳正とは程遠く暴食獣の食欲に傾く。\\n\\n・物理攻撃力ダウンと魔法攻撃力ダウン効果の影\\n\u3000響を受けやすい。\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・グラットンから受けるすべてのダメージで発生\\n\u3000する、パーティキャラのＴＰ回復量を中ダウン\\n\u3000させる。\\n・ユニオンバーストは、敵全体に自身の物理攻撃\\n\u3000力に応じた物理割合ダメージを与え、自身の魔\\n\u3000法攻撃力に応じて物理攻撃力と魔法攻撃力をダ\\n\u3000ウンさせる。さらに、自身の物理攻撃力と魔法\\n\u3000攻撃力を特大アップさせる。このスキルによる\\n\u3000ダメージでは、敵のＴＰが回復しない。このス\\n\u3000キルの状態異常はダメージを無効化しても付与\\n\u3000される。\\n・最も遠い敵２キャラに物理特大ダメージ。\\n・敵全体に魔法小ダメージを与え、自身の魔法攻\\n\u3000撃力に応じてＴＰをダウンさせる。さらに、自\\n\u3000身のＴＰを中アップさせる。このスキルはダ\\n\u3000メージを無効化してもＴＰをダウンさせる。\\n・向かって左側のターゲットのブレイク時、自身\\n\u3000の物理攻撃力が特大ダウン。\\n・中央のターゲットのブレイク時、自身の物理防\\n\u3000御力と魔法防御力が大ダウン。\\n・向かって右側のターゲットのブレイク時、自身\\n\u3000の魔法攻撃力が特大ダウン。', 301301, 0, 1, 301301, 270, 0, 0, 4, 0, 3.0, 1000, 'グラットン');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】あらゆる魂を貪る、天秤座の魔星獣。\\nその天秤は、厳正とは程遠く暴食獣の食欲に傾く。\\n\\n・物理攻撃力ダウンと魔法攻撃力ダウン効果の影\\n\u3000響を受けやすい。\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・グラットンから受けるすべてのダメージで発生\\n\u3000する、パーティキャラのＴＰ回復量を中ダウン\\n\u3000させる。\\n・ユニオンバーストは、敵全体に自身の物理攻撃\\n\u3000力に応じた物理割合ダメージを与え、自身の魔\\n\u3000法攻撃力に応じて物理攻撃力と魔法攻撃力をダ\\n\u3000ウンさせる。さらに、自身の物理攻撃力と魔法\\n\u3000攻撃力を特大アップさせる。このスキルによる\\n\u3000ダメージでは、敵のＴＰが回復しない。このス\\n\u3000キルの状態異常はダメージを無効化しても付与\\n\u3000される。\\n・最も遠い敵２キャラに物理特大ダメージ。\\n・敵全体に魔法小ダメージを与え、自身の魔法攻\\n\u3000撃力に応じてＴＰをダウンさせる。さらに、自\\n\u3000身のＴＰを中アップさせる。このスキルはダ\\n\u3000メージを無効化してもＴＰをダウンさせる。\\n・最もＴＰの高い敵３キャラに束縛状態を付与し、\\n\u3000自身の魔法攻撃力に応じて行動速度をダウンさ\\n\u3000せる。ＴＰが最大値に達しているキャラを除く。\\n・向かって左側のターゲットのブレイク時、自身\\n\u3000の物理攻撃力が特大ダウン。\\n・中央のターゲットのブレイク時、自身の物理防\\n\u3000御力と魔法防御力が大ダウン。\\n・向かって右側のターゲットのブレイク時、自身\\n\u3000の魔法攻撃力が特大ダウン。', 301302, 0, 1, 301302, 270, 0, 0, 4, 0, 3.0, 1000, 'グラットン');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】あらゆる魂を貪る、天秤座の魔星獣。\\nその天秤は、厳正とは程遠く暴食獣の食欲に傾く。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。\\n\u3000この防御力アップ効果で上昇した防御力は、バ\\n\u3000トル中に受ける防御力ダウンスキルの影響を受\\n\u3000けない。\\n・グラットンから受けるすべてのダメージで発生\\n\u3000する、パーティキャラのＴＰ回復量を小ダウン\\n\u3000させる。\\n・ユニオンバーストは、敵全体に魔法大ダメージ\\n\u3000を与え、さらに自身の物理攻撃力と魔法攻撃力\\n\u3000を大アップ。\\n\u3000このスキルによるダメージでは、敵のＴＰが回\\n\u3000復しない。\\n・最も遠い２キャラに魔法中ダメージ。\\n・最も近い３キャラに魔法小ダメージを与え、Ｔ\\n\u3000Ｐを小ダウン。\\n\u3000さらに自身のＴＰを中アップさせる。\\n\u3000このスキルはダメージを無効化してもＴＰをダ\\n\u3000ウンさせる。\\n・向かって左側のターゲットのブレイク時、自身\\n\u3000の物理防御力と魔法防御力が大ダウン。\\n・中央のターゲットのブレイク時、自身の魔法攻\\n\u3000撃力が特大ダウン。\\n・向かって右側のターゲットのブレイク時、自身\\n\u3000の物理防御力と魔法防御力が大ダウン。', 301303, 0, 1, 301303, 270, 0, 0, 4, 0, 3.0, 1000, 'グラットン');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】あらゆる魂を貪る、天秤座の魔星獣。\\nその天秤は、厳正とは程遠く暴食獣の食欲に傾く。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。\\n\u3000この防御力アップ効果で上昇した防御力は、バ\\n\u3000トル中に受ける防御力ダウンスキルの影響を受\\n\u3000けない。\\n・グラットンから受けるすべてのダメージで発生\\n\u3000する、パーティキャラのＴＰ回復量を小ダウン\\n\u3000させる。\\n・ユニオンバーストは、敵全体に魔法大ダメージ\\n\u3000を与え、さらに自身の物理攻撃力と魔法攻撃力\\n\u3000を大アップ。\\n\u3000このスキルによるダメージでは、敵のＴＰが回\\n\u3000復しない。\\n・最も遠い２キャラに魔法中ダメージ。\\n・最も近い３キャラに魔法小ダメージを与え、Ｔ\\n\u3000Ｐを中ダウン。\\n\u3000さらに自身のＴＰを中アップさせる。\\n\u3000このスキルはダメージを無効化してもＴＰをダ\\n\u3000ウンさせる。\\n・最も近い３キャラを束縛状態にし、魔法大ダ\\n\u3000メージを与える。\\n\u3000自身のターゲットがブレイクしている場合、自\\n\u3000身の魔法攻撃力を特大アップ。\\n\u3000このスキルの状態異常はダメージを無効化して\\n\u3000も付与される。\\n・向かって左側のターゲットのブレイク時、自身\\n\u3000の物理防御力と魔法防御力が大ダウン。\\n・中央のターゲットのブレイク時、自身の魔法攻\\n\u3000撃力が特大ダウン。\\n・向かって右側のターゲットのブレイク時、自身\\n\u3000の物理防御力と魔法防御力が大ダウン。', 301304, 0, 1, 301304, 270, 0, 0, 4, 0, 3.0, 1000, 'グラットン');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】あらゆる魂を貪る、天秤座の魔星獣。\\nその天秤は、厳正とは程遠く暴食獣の食欲に傾く。\\n\\n・物理攻撃力ダウンと魔法攻撃力ダウン効果の影\\n\u3000響を受けやすい。\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を中アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・バトル開始時、敵全体のＴＰ上昇を中ダウンさ\\n\u3000せるフィールドを展開する。\\n・バトル開始時、自身にＴＰダウン80％カット\\n\u3000効果を付与する。\\n・グラットンから受けるすべてのダメージで発生\\n\u3000する、パーティキャラのＴＰ回復量を中ダウン\\n\u3000させる。\\n・敵から受けるすべてのダメージで発生する、グ\\n\u3000ラットンのＴＰ回復量が大ダウンする。\\n・ユニオンバーストは、敵全体に自身の物理攻撃\\n\u3000力に応じた物理割合ダメージを与え、自身の魔\\n\u3000法攻撃力に応じて物理攻撃力と魔法攻撃力をダ\\n\u3000ウンさせる。さらに、自身の物理攻撃力と魔法\\n\u3000攻撃力を特大アップさせる。このスキルによる\\n\u3000ダメージでは、敵のＴＰが回復しない。このス\\n\u3000キルの状態異常はダメージを無効化しても付与\\n\u3000される。\\n・最も遠い敵２キャラに物理特大ダメージ。この\\n\u3000スキルによるダメージでは、敵のＴＰが回復し\\n\u3000ない。\\n・敵全体に魔法小ダメージを与え、自身の魔法攻\\n\u3000撃力に応じてＴＰをダウンさせる。さらに、自\\n\u3000身のＴＰを中アップさせる。このスキルによる\\n\u3000ダメージでは、敵のＴＰが回復しない。このス\\n\u3000キルはダメージを無効化してもＴＰをダウンさ\\n\u3000せる。\\n・最もＴＰの高い敵３キャラに束縛状態を付与し、\\n\u3000自身の魔法攻撃力に応じて行動速度をダウンさ\\n\u3000せる。ＴＰが最大値に達しているキャラを除く。\\n・敵全体に自身の物理攻撃力に応じた物理割合ダ\\n\u3000メージを毎秒与え、自身の魔法攻撃力に応じて\\n\u3000ＴＰを毎秒ダウンさせる。このスキルによるダ\\n\u3000メージでは、敵のＴＰが回復しない。このスキ\\n\u3000ルはダメージを無効化してもＴＰをダウンさせ\\n\u3000る。\\n・向かって左側のターゲットのブレイク時、自身\\n\u3000の物理攻撃力が特大ダウン。\\n・中央のターゲットのブレイク時、自身の物理防\\n\u3000御力と魔法防御力が大ダウン。\\n・向かって右側のターゲットのブレイク時、自身\\n\u3000の魔法攻撃力が特大ダウン。', 301305, 0, 1, 301305, 270, 0, 0, 4, 0, 3.0, 1000, 'グラットン');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('無数の毒蛇から成る頭髪の、乙女座の魔星獣。\\n悲恋の苦しみは、全てを拒み石に変える。\\n\\n・敵全体に魔法大ダメージを与え、前方範囲内\\n\u3000の敵はさらに石化状態にする。\\n・前方範囲内の敵に物理ダメージを与え、石化\\n\u3000状態の敵はさらにＴＰを大ダウン。\\n・物理攻撃力が最も高い敵1キャラに魔法大ダ\\n\u3000メージを与え、毒状態にする。', 301400, 0, 1, 301400, 270, 0, 0, 3, 0, 2.5, 1000, 'メデューサ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】果てのない愛憎に狂う乙女座の魔星獣。\\n凄まじい嫉妬と拒絶が見るもの全てを石化させる。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・メデューサから受けるすべてのダメージで発生\\n\u3000する、パーティキャラのＴＰ回復量を小ダウン\\n\u3000させる。\\n・ユニオンバーストは、敵全体に魔法大ダメージ\\n\u3000を与え、短時間石化状態にする。猛毒状態の場\\n\u3000合、長時間石化状態にする。このスキルによる\\n\u3000ダメージでは、キャラのＴＰが回復しない。こ\\n\u3000のスキルの状態異常はダメージを無効化しても\\n\u3000付与される。\\n・敵全体に物理中ダメージを与え、ＨＰ回復量を\\n\u3000中ダウンさせ、ＨＰ吸収を大ダウンさせる。猛\\n\u3000毒状態の場合、さらにＴＰを中ダウンさせる。\\n\u3000このスキルの状態異常はダメージを無効化して\\n\u3000も付与される。\\n・後ろから２番目の敵を中心にした小範囲に魔法\\n\u3000小ダメージを与え、毒状態を付与する。キャラ\\n\u3000のＨＰが60％未満の場合、猛毒状態を付与す\\n\u3000る。このスキルにより付与された毒と猛毒のダ\\n\u3000メージでは、ＴＰが回復しない。このスキルの\\n\u3000状態異常はダメージを無効化しても付与される。', 301401, 0, 1, 301401, 270, 0, 0, 3, 0, 2.5, 1000, 'メデューサ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】果てのない愛憎に狂う乙女座の魔星獣。\\n凄まじい嫉妬と拒絶が見るもの全てを石化させる。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・メデューサから受けるすべてのダメージで発生\\n\u3000する、パーティキャラのＴＰ回復量を小ダウン\\n\u3000させる。\\n・ユニオンバーストは、敵全体に魔法大ダメージ\\n\u3000を与え、短時間石化状態にする。猛毒状態の場\\n\u3000合、長時間石化状態にする。このスキルによる\\n\u3000ダメージでは、キャラのＴＰが回復しない。こ\\n\u3000のスキルの状態異常はダメージを無効化しても\\n\u3000付与される。\\n・敵全体に物理中ダメージを与え、ＨＰ回復量を\\n\u3000大ダウンさせ、ＨＰ吸収を特大ダウンさせる。\\n\u3000猛毒状態の場合、さらにＴＰを中ダウンさせる。\\n\u3000このスキルの状態異常はダメージを無効化して\\n\u3000も付与される。\\n・後ろから２番目の敵を中心にした小範囲に魔法\\n\u3000小ダメージを与え、毒状態を付与する。キャラ\\n\u3000のＨＰが60％未満の場合、猛毒状態を付与す\\n\u3000る。このスキルにより付与された毒と猛毒のダ\\n\u3000メージでは、ＴＰが回復しない。このスキルの\\n\u3000状態異常はダメージを無効化しても付与される。\\n・後ろから２番目の敵を中心にした小範囲に魔法\\n\u3000小ダメージを与える。キャラが猛毒状態の場合、\\n\u3000石化状態を付与する。このスキルの状態異常は\\n\u3000ダメージを無効化しても付与される。', 301402, 0, 1, 301402, 270, 0, 0, 3, 0, 2.5, 1000, 'メデューサ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】果てのない愛憎に狂う乙女座の魔星獣。\\n凄まじい嫉妬と拒絶が見るもの全てを石化させる。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を中アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・バトル開始時、敵全体のＴＰ上昇を中ダウンさ\\n\u3000せるフィールドを展開する。\\n・バトル開始時、自身にＴＰダウン50％カット\\n\u3000効果を付与する。\\n・メデューサから受けるすべてのダメージで発生\\n\u3000する、パーティキャラのＴＰ回復量を中ダウン\\n\u3000させる。\\n・敵から受けるすべてのダメージで発生する、メ\\n\u3000デューサのＴＰ回復量が大ダウンする。\\n・ユニオンバーストは、敵全体に魔法大ダメージ\\n\u3000を与え、短時間石化状態にする。猛毒状態の場\\n\u3000合、長時間石化状態にする。このスキルによる\\n\u3000ダメージでは、キャラのＴＰが回復しない。こ\\n\u3000のスキルの状態異常はダメージを無効化しても\\n\u3000付与される。\\n・敵全体に物理中ダメージを与え、ＨＰ回復量を\\n\u3000大ダウンさせ、ＨＰ吸収を特大ダウンさせる。\\n\u3000猛毒状態の場合、さらにＴＰを中ダウンさせる。\\n\u3000このスキルの状態異常はダメージを無効化して\\n\u3000も付与される。\\n・後ろから２番目の敵を中心にした小範囲に魔法\\n\u3000小ダメージを与え、毒状態を付与する。キャラ\\n\u3000のＨＰが60％未満の場合、猛毒状態を付与す\\n\u3000る。このスキルにより付与された毒と猛毒のダ\\n\u3000メージでは、ＴＰが回復しない。このスキルの\\n\u3000状態異常はダメージを無効化しても付与される。\\n・後ろから２番目の敵を中心にした小範囲に魔法\\n\u3000小ダメージを与える。キャラが猛毒状態の場合、\\n\u3000石化状態を付与する。このスキルの状態異常は\\n\u3000ダメージを無効化しても付与される。\\n・しもべを２体召喚し、自身の物理防御力と魔法\\n\u3000防御力を大ダウンさせる。\\n・しもべは、最も近い１キャラに物理中ダメージ\\n\u3000を与え、毒状態を付与する。キャラのＨＰが\\n\u300070％未満の場合、猛毒状態を付与する。この\\n\u3000スキルによるダメージでは、ＴＰ回復量は減少\\n\u3000する。このスキルにより付与された毒と猛毒の\\n\u3000ダメージではＴＰが回復しない。このスキルの\\n\u3000状態異常はダメージを無効化しても付与される。\\n・しもべのＨＰが一定値以下になった時、\\n\u3000メデューサに物理固定ダメージを与える。', 301403, 0, 1, 301403, 270, 0, 0, 3, 0, 2.5, 1000, 'メデューサ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】果てのない愛憎に狂う乙女座の魔星獣。\\n凄まじい嫉妬と拒絶が見るもの全てを石化させる。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。\\n\u3000この防御力アップ効果で上昇した防御力は、バ\\n\u3000トル中に受ける防御力ダウンスキルの影響を受\\n\u3000けない。\\n・バトル開始時、敵全体のＴＰ上昇を小ダウンさ\\n\u3000せるフィールドを展開する。\\n・メデューサから受けるすべてのダメージで発生\\n\u3000する、パーティキャラのＴＰ回復量を小ダウン\\n\u3000させる。\\n・ユニオンバーストは、敵全体に魔法大ダメージ\\n\u3000を与え、短時間石化状態にする。\\n\u3000キャラのＨＰが70%未満の場合、長時間石化\\n\u3000状態にする。\\n\u3000このスキルによるダメージでは、キャラのＴＰ\\n\u3000が回復しない。\\n\u3000このスキルの状態異常はダメージを無効化して\\n\u3000も付与される。\\n・前方範囲内の敵に物理大ダメージを与え、行動\\n\u3000不能状態の敵はさらにＴＰを中ダウン。\\n\u3000このスキルはダメージを無効化してもＴＰをダ\\n\u3000ウンさせる。\\n・後ろから２番目の敵を中心にした小範囲に魔法\\n\u3000小ダメージを与え、毒状態を付与する。\\n\u3000このスキルにより付与された毒のダメージでは、\\n\u3000ＴＰが回復しない。\\n\u3000このスキルの状態異常はダメージを無効化して\\n\u3000も付与される。\\n・後ろから２番目の敵を中心にした小範囲に魔法\\n\u3000小ダメージを与える。\\n\u3000キャラのＨＰが60％未満の場合、石化状態を\\n\u3000付与する。\\n\u3000このスキルの状態異常はダメージを無効化して\\n\u3000も付与される。\\n・しもべを２体召喚し、自身の物理防御力と魔法\\n\u3000防御力を大ダウン。\\n・しもべは、最も近い１キャラに物理中ダメージ。\\n\u3000このスキルによるダメージでは、ＴＰ回復量は\\n\u3000減少する。\\n・しもべのＨＰが一定値以下になった時、メデュ\\n\u3000ーサに物理固定ダメージを与える。', 301404, 0, 1, 301404, 270, 0, 0, 3, 0, 2.5, 1000, 'メデューサ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】遠吠えで獲物を麻痺させ\\nひるんだ所をツメで引き裂く。\\n数々の冒険者の行く手を阻んできた\\n残虐を極める魔界の狼。\\n\\n・ランダムな2キャラに物理\\n\u3000大ダメージを与える。\\n\\n・前方3キャラに魔法小ダメージを\\n\u3000与え、麻痺状態にする。', 301500, 0, 1, 301500, 270, 0, 0, 12, 0, 1.8, 1000, 'ウールヴヘジン');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】遠吠えで獲物をひるませツメで引き裂く。\\n自身の欲望のまま、残虐の限りを尽くす魔狼。\\n\\n・挑発効果の影響を受けやすい。 \\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・ウールヴヘジンから受けるすべてのダメージで\\n\u3000発生する、パーティキャラのＴＰ回復量を中ダ\\n\u3000ウンさせる。\\n・ユニオンバーストは、ランダムな敵最大３キャ\\n\u3000ラのステータスアップ効果を解除した後、物理\\n\u3000特大ダメージを与える。\\n・敵全体の物理攻撃力と魔法攻撃力を大ダウンさ\\n\u3000せ、自身の行動速度を特大アップさせる。', 301501, 0, 1, 301501, 270, 0, 0, 12, 0, 1.8, 3000, 'ウールヴヘジン');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】遠吠えで獲物をひるませツメで引き裂く。\\n自身の欲望のまま、残虐の限りを尽くす魔狼。\\n\\n・挑発効果の影響を受けやすい。 \\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を中アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・バトル開始時、敵全体のＨＰ吸収を特大ダウン\\n\u3000させる。 \\n・バトル開始時、敵全体のＴＰ上昇を小ダウンさ\\n\u3000せるフィールドを展開する。\\n・バトル開始時、自身にＴＰダウン100％カッ\\n\u3000ト効果を付与する。\\n・ウールヴヘジンから受けるすべてのダメージで\\n\u3000発生する、パーティキャラのＴＰ回復量を中ダ\\n\u3000ウンさせる。\\n・ユニオンバーストは、ランダムな敵最大３キャ\\n\u3000ラのステータスアップ効果を解除した後、物理\\n\u3000特大ダメージを与える。\\n・敵全体の物理攻撃力と魔法攻撃力を大ダウンさ\\n\u3000せ、自身の行動速度を特大アップさせる。', 301502, 0, 1, 301502, 270, 0, 0, 12, 0, 1.8, 3000, 'ウールヴヘジン');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】猛り狂う暴風を纏いし大怪鳥。\\n魔物図鑑を抜け出し、破壊の限りを尽くす。\\n\\n・敵全体にキャラの最大ＨＰに応じた\\n\u3000大ダメージを与える。\\n・前方範囲内の敵に物理中ダメージを与え、\\n\u3000さらにスタンさせる。', 301600, 0, 1, 301600, 270, 0, 0, 3, 0, 1.8, 1000, 'ジズ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】猛り狂う暴風を纏いし大怪鳥。\\n魔物図鑑を抜け出し、破壊の限りを尽くす。\\n\\n・敵全体にキャラの最大ＨＰに応じた\\n\u3000大ダメージを与える。\\n・前方範囲内の敵に物理中ダメージを与え、\\n\u3000さらにスタンさせる。\\n・前方範囲内の敵にキャラの最大ＨＰに応じた\\n\u3000中ダメージを与え、物理防御力を下げる。\\n・ジズ自身のＨＰが50％を切ると、さらに\\n\u3000攻撃が激しく凶暴になる。', 301601, 0, 1, 301600, 270, 0, 0, 3, 0, 1.8, 1000, 'ジズ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】砂島にのさばる獰猛な大\\n怪鳥。紫電を纏い嵐を巻き起こす\\nさまは、天災と恐れられる。\\n\\n・ユニオンバーストは、敵全体に\\n\u3000最大ＨＰに応じた物理割合\\n\u3000ダメージを与える。\\n\\n・前から１番目の敵を中心にした\\n\u3000小範囲の最大２キャラに物理中\\n\u3000ダメージを与え、さらにスタン\\n\u3000させる。', 301602, 0, 1, 301602, 270, 0, 0, 3, 0, 1.8, 1000, 'ストーム・ジズ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】毒瘴の闇稜の頂に棲まう、醜悪なる狂獣。\\n猛毒の瘴気で生を奪い、屍を食み力の糧にする。\\n\\n・ユニオンバーストは敵全体に魔法大ダメージと\\n\u3000毒状態を与え、さらにノックバックさせる。\\n・前方2キャラに物理ダメージを与え、さらに物\\n\u3000理攻撃力とTPをダウンさせる。\\n・ジャバウォック自身の残りHPが40%を切る\\n\u3000とさらに攻撃が激しく強暴になり、さらに3体\\n\u3000のモンスターを呼び寄せる。\\n・残り時間が20秒を切ると、敵全体に強力な毒\\n\u3000状態を付与し、自身のTPを特大ダウン。', 301700, 0, 1, 301700, 270, 0, 0, 3, 0, 2.6, 1000, 'ジャバウォック');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('天を駆け数多の標的を射止める射手座の魔星獣。\\n雷光纏いし矢は、刹那にすべてを穿つ至高の技。\\n\\n・ユニオンバーストは敵全体に最大ＨＰに応じ\\n\u3000て魔法ダメージを与える。\\n\u3000暗闇状態の敵はダメージが3倍になる。\\n・敵全体に魔法中ダメージを与え、さらに残り\\n\u3000ＨＰ割合が最も少ない敵1キャラに強力な暗\\n\u3000闇状態を付与。\\n・前方の敵3キャラに物理ダメージを与える。', 301800, 0, 1, 301800, 270, 0, 0, 3, 0, 2.0, 1000, 'サジタリウス');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】星穹の神殿を守護する射手座の魔星獣。\\n万象を射抜く一閃は、紫電煌めく神域の絶技。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・サジタリウスから受けるすべてのダメージで発\\n\u3000生する、パーティキャラのＴＰ回復量を中ダウ\\n\u3000ンさせる。\\n・ユニオンバーストは、敵全体に魔法中ダメージ\\n\u3000を与え、さらに【黒星】の数に応じて、追加の\\n\u3000魔法ダメージを与える。\\n・敵全体に魔法小ダメージを与え、自身の矢に\\n\u3000【黒星】を１追加する。さらに前方広範囲内の\\n\u3000敵に魔法大ダメージを与え、範囲内に敵が存在\\n\u3000する場合、自身の矢に【黒星】を１追加する。\\n・最も近い敵２キャラに物理中ダメージを与え、\\n\u3000物理防御力を中ダウンさせる。このスキルの状\\n\u3000態異常はダメージを無効化しても付与される。', 301801, 0, 1, 301801, 270, 0, 0, 3, 0, 2.0, 1000, 'サジタリウス');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】星穹の神殿を守護する射手座の魔星獣。\\n万象を射抜く一閃は、紫電煌めく神域の絶技。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・サジタリウスから受けるすべてのダメージで発\\n\u3000生する、パーティキャラのＴＰ回復量を中ダウ\\n\u3000ンさせる。\\n・ユニオンバーストは、敵全体に魔法中ダメージ\\n\u3000を与え、さらに【黒星】の数に応じて、追加の\\n\u3000魔法ダメージを与える。このスキルによるダ\\n\u3000メージでは、ＴＰ回復量が大ダウンする。\\n・敵全体に魔法小ダメージを与え、自身の矢に\\n\u3000【黒星】を１追加する。さらに前方広範囲内の\\n\u3000敵に魔法大ダメージを与え、範囲内に敵が存在\\n\u3000する場合、自身の矢に【黒星】を２追加する。\\n\u3000このスキルによるダメージでは、ＴＰ回復量が\\n\u3000大ダウンする。\\n・最も近い敵２キャラに物理中ダメージを与え、\\n\u3000物理防御力を中ダウンさせる。このスキルの状\\n\u3000態異常はダメージを無効化しても付与される。\\n・敵全体のバリアを解除し、魔法小ダメージを与\\n\u3000え、前方広範囲内の敵に魔法大ダメージを与え\\n\u3000る。このスキルによるダメージでは、ＴＰ回復\\n\u3000量が大ダウンする。', 301802, 0, 1, 301802, 270, 0, 0, 3, 0, 2.0, 1000, 'サジタリウス');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】星穹の神殿を守護する射手座の魔星獣。\\n万象を射抜く一閃は、紫電煌めく神域の絶技。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を中アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・バトル開始時、敵全体のＴＰ上昇を中ダウンさ\\n\u3000せるフィールドを展開する。\\n・バトル開始時、自身にＴＰダウン100％カッ\\n\u3000ト効果を付与する。\\n・サジタリウスから受けるすべてのダメージで発\\n\u3000生する、パーティキャラのＴＰ回復量を中ダウ\\n\u3000ンさせる。\\n・敵から受けるすべてのダメージで発生する、サ\\n\u3000ジタリウスのＴＰ回復量が大ダウンする。\\n・ユニオンバーストは、敵全体に魔法中ダメージ\\n\u3000を与え、さらに【黒星】の数に応じて、追加の\\n\u3000魔法割合ダメージを与える。このスキルによる\\n\u3000ダメージでは、ＴＰが回復しない。\\n・敵全体に魔法小ダメージを与え、自身の矢に\\n\u3000【黒星】を１追加する。さらに前方広範囲内の\\n\u3000敵に魔法大ダメージを与え、範囲内に敵が存在\\n\u3000する場合、自身の矢に【黒星】を２追加する。\\n\u3000このスキルによるダメージでは、ＴＰが回復し\\n\u3000ない。\\n・最も近い敵２キャラに物理中ダメージを与え、\\n\u3000物理防御力を大ダウンさせる。このスキルの状\\n\u3000態異常はダメージを無効化しても付与される。\\n・敵全体のバリアを解除し、魔法小ダメージを与\\n\u3000え、前方広範囲内の敵に魔法大ダメージを与え\\n\u3000る。さらに【黒星】の数に応じて、自身のＴＰ\\n\u3000を回復する。このスキルによるダメージでは、\\n\u3000ＴＰが回復しない。', 301803, 0, 1, 301803, 270, 0, 0, 3, 0, 2.0, 1000, 'サジタリウス');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】鋭い眼つきで、獲物\\nと波を探し求める海のハンター。\\n魔力で無限に生み出す潮水は\\n敵の刃と気力を鈍らせる。\\n\\n・前方4キャラに物理中ダメージを\\n\u3000与え、物理攻撃力を下げる。\\n\\n・前方2キャラに魔法小ダメージを\\n\u3000与え、ＴＰを下げる。', 301900, 0, 1, 301900, 270, 0, 0, 11, 0, 1.7, 1000, 'ウェアオルカ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】ルナの魔力により凶悪化した大海の狩人。\\n鍛え抜いた躰で、刃と化した水流の一撃を放つ。\\n\\n・前方４キャラに物理大ダメージを与え、\\n\u3000物理攻撃力を中ダウンさせる。さらに、\\n\u3000味方全員のＴＰ上昇を小アップする。\\n・前方小範囲に魔法中ダメージを与え、\\n\u3000ＴＰを大ダウン。\\n・後ろから２番目のキャラを中心にした\\n\u3000小範囲に物理中ダメージを与え、\\n\u3000魔法攻撃力を大ダウンさせる。', 301901, 0, 1, 301901, 270, 0, 0, 11, 0, 1.5, 1000, 'キリングオルカ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】過酷な環境で進化したプチグリフォン。\\n竜巻で獲物を巻き上げ、空で狩りをする。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・ワイルドグリフォンから受けるすべてのダメー\\n\u3000ジで発生する、パーティキャラのＴＰ回復量を\\n\u3000中ダウンさせる。\\n・ユニオンバーストは、召喚体、分身を除いた最\\n\u3000も近い敵３キャラに魔法大ダメージを与える。', 302000, 0, 1, 302000, 270, 0, 0, 11, 0, 1.6, 1000, 'ワイルドグリフォン');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('過酷な環境で進化したプチグリフォン。\\n竜巻で獲物を巻き上げ、空で狩りをする。\\n\\n・前方範囲内の敵に魔法中ダメージ。', 302001, 0, 1, 302001, 270, 0, 0, 11, 0, 1.6, 1000, 'ワイルドグリフォン');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】過酷な環境で進化したプチグリフォン。\\n竜巻で獲物を巻き上げ、空で狩りをする。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を中アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・バトル開始時、敵全体のＨＰ吸収を特大ダウン\\n\u3000させ、ＴＰ上昇を小ダウンさせる。\\n・バトル開始時、自身にＴＰダウン50％カット\\n\u3000効果を付与する。\\n・ワイルドグリフォンから受けるすべてのダメー\\n\u3000ジで発生する、パーティキャラのＴＰ回復量を\\n\u3000中ダウンさせる。\\n・ユニオンバーストは、召喚体、分身を除いた最\\n\u3000も近い敵３キャラに魔法大ダメージを与え、\\n\u3000ノックバックさせる。さらに、キャラのＨＰが\\n\u300070％未満の場合、スタン状態を付与する。こ\\n\u3000のスキルの状態異常はダメージを無効化しても\\n\u3000付与される。\\n・召喚体、分身を除いた最も近い敵３キャラに魔\\n\u3000法中ダメージを与え、魔法防御力を中ダウンさ\\n\u3000せる。このスキルの状態異常はダメージを無効\\n\u3000化しても付与される。', 302002, 0, 1, 302002, 270, 0, 0, 11, 0, 1.6, 1000, 'ワイルドグリフォン');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】苛烈な環境で生き抜いた、\\n獰猛な鷲獅子。剛翼から放つ強風\\nは、冒険者を容易に吹き飛ばす。\\n\\n・ユニオンバーストは、前から\\n\u3000３キャラに魔法中ダメージを\\n\u3000与え、さらにノックバック\\n\u3000させる。キャラのＨＰが70％\\n\u3000未満の場合、スタン状態を\\n\u3000付与する。\\n\u3000このスキルの状態異常は\\n\u3000ダメージを無効化しても\\n\u3000付与される。\\n\\n・前から３キャラに魔法中ダメージ\\n\u3000を与え、魔法防御力を小ダウン\\n\u3000させる。このスキルの状態異常は\\n\u3000ダメージを無効化しても\\n\u3000付与される。', 302003, 0, 1, 302003, 270, 0, 0, 11, 0, 1.6, 1000, '暴風の鷲獅子');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】過酷な環境で進化したプチグリフォン。\\n竜巻で獲物を巻き上げ、空で狩りをする。\\n\\n・ワイルドグリフォンから受けるすべてのダメー\\n\u3000ジで発生する、パーティキャラのＴＰ回復量を\\n\u3000中ダウンさせる。\\n・ユニオンバーストは、召喚体、分身を除いた最\\n\u3000も近い敵３キャラに魔法中ダメージを与え、\\n\u3000ノックバックさせる。さらに、キャラのＨＰが\\n\u300070％未満の場合、スタン状態を付与する。こ\\n\u3000のスキルの状態異常はダメージを無効化しても\\n\u3000付与される。\\n・召喚体、分身を除いた最も近い敵３キャラに魔\\n\u3000法中ダメージを与え、魔法防御力を中ダウンさ\\n\u3000せる。このスキルの状態異常はダメージを無効\\n\u3000化しても付与される。', 302004, 0, 1, 302004, 270, 0, 0, 11, 0, 1.6, 1000, 'ワイルドグリフォン');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】大きな皮翼を使い、空を駆ける翼竜。\\n巨大な火球を吐き、侵入者の行く手を阻む。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・ワイバーンから受けるすべてのダメージで発生\\n\u3000する、パーティキャラのＴＰ回復量を中ダウン\\n\u3000させる。\\n・ユニオンバーストは、最も近い敵１キャラを中\\n\u3000心にした広範囲内の敵最大３キャラに物理大ダ\\n\u3000メージを与える。', 302100, 0, 1, 302100, 270, 0, 0, 11, 0, 1.6, 3000, 'ワイバーン');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】大きな皮翼を使い、空を駆ける翼竜。\\n巨大な火球を吐き、侵入者の行く手を阻む。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を中アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・バトル開始時、敵全体のＨＰ吸収を特大ダウン\\n\u3000させ、ＴＰ上昇を小ダウンさせる。\\n・バトル開始時、自身にＴＰダウン50％カット\\n\u3000効果を付与する。\\n・ワイバーンから受けるすべてのダメージで発生\\n\u3000する、パーティキャラのＴＰ回復量を特大ダウ\\n\u3000ンさせる。\\n・ユニオンバーストは、最も近い敵１キャラを中\\n\u3000心にした広範囲内の敵最大３キャラに物理大ダ\\n\u3000メージを与え、物理防御力を中ダウンさせる。\\n\u3000さらに自身の物理防御力をバトル終了まで小\\n\u3000アップさせる。このスキルの状態異常はダメー\\n\u3000ジを無効化しても付与される。\\n・最も近い敵３キャラをノックバックさせ、行動\\n\u3000速度を中ダウンさせる。', 302101, 0, 1, 302101, 270, 0, 0, 11, 0, 1.6, 3000, 'ワイバーン');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】大きな皮翼を使い、空を駆ける翼竜。\\n巨大な火球を吐き、侵入者の行く手を阻む。\\n\\n・前から１番目の敵を中心にした小範囲の\\n\u3000最大３キャラに物理中ダメージ。', 302102, 0, 1, 302102, 270, 0, 0, 11, 0, 1.6, 1000, 'ワイバーン');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】砂塵舞う空を縄張りにする\\n翼竜。厳しい環境でも獲物を逃さず\\n荒野の空を支配する。\\n\\n・前から１番目の敵を中心にした小\\n\u3000範囲の最大３キャラに魔法中ダメ\\n\u3000ージ。', 302103, 0, 1, 302103, 270, 0, 0, 11, 0, 1.6, 1000, 'サンドワイバーン');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】砂塵舞う空を縄張りにする\\n翼竜。厳しい環境でも獲物を逃さず\\n荒野の空を支配する。\\n\\n・前から１番目の敵を中心にした小\\n\u3000範囲の最大３キャラに魔法中ダメ\\n\u3000ージ。', 302104, 0, 1, 302103, 270, 0, 0, 11, 0, 1.6, 1000, 'サンドワイバーン');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】大きな皮翼を使い、空を駆ける翼竜。\\n巨大な火球を吐き、侵入者の行く手を阻む。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・ワイバーンから受けるすべてのダメージで発生\\n\u3000する、パーティキャラのＴＰ回復量を中ダウン\\n\u3000させる。\\n・ユニオンバーストは、前から３キャラに物理中\\n\u3000ダメージを与え、物理防御力を特大ダウンさせ\\n\u3000る。\\n\u3000さらに自身の物理防御力を小アップさせる。\\n\u3000このスキルの状態異常はダメージを無効化して\\n\u3000も付与される。\\n・前から１キャラをノックバックさせ、行動速度\\n\u3000を中ダウンさせる。', 302105, 0, 1, 302105, 270, 0, 0, 11, 0, 1.6, 3000, 'ワイバーン');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】大きな皮翼を使い、空を駆ける翼竜。\\n巨大な火球を吐き、侵入者の行く手を阻む。\\n\\n・ワイバーンから受けるすべてのダメージで発生\\n\u3000する、パーティキャラのＴＰ回復量を中ダウン\\n\u3000させる。\\n・ユニオンバーストは、最も近い敵を中心にした\\n\u3000広範囲の最大３キャラに物理大ダメージを与え、\\n\u3000物理防御力を中ダウンさせる。さらに自身の物\\n\u3000理防御力をバトル終了まで小アップさせる。こ\\n\u3000のスキルの状態異常はダメージを無効化しても\\n\u3000付与される。\\n・最も近い敵３キャラをノックバックさせ、行動\\n\u3000速度を中ダウンさせる。', 302106, 0, 1, 302106, 270, 0, 0, 11, 0, 1.6, 3000, 'ワイバーン');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【魔法】ルナの魔力で目覚めた、古代の機械兵器。\\n無慈悲に放たれる魔力が、侵入者を阻む。\\n\\n・敵全体に魔法特大ダメージを与え、魔法防御力\\n\u3000を大ダウン。\\n・前から３キャラに物理大ダメージを与える。\\n・前から２キャラに魔法大ダメージを\\n\u3000与え、麻痺状態にする。', 302200, 0, 2, 302200, 270, 0, 0, 16, 0, 1.6, 1000, 'イクト・ガラディオン');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【魔法】大樹の頂に棲まう、聡明なる大梟。\\n森に生ける者の英知を束ね、巧みに魔術を操る。\\n\\n・ユニオンバーストは敵全体に魔法ダメージを\\n\u3000与える。\\n・ランダムな1キャラに物理ダメージを与え\\n\u3000さらに麻痺状態にする。', 302300, 0, 2, 302300, 270, 0, 0, 16, 0, 1.8, 1000, 'ワイズオウル');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】太古より遺跡を護り続ける人工生命体。\\n創造主の秘術で、無限に動力を得て動き続ける。\\n\\n・ユニオンバーストは敵全体に魔法大ダメージを\\n\u3000与える。\\n・前方範囲内に物理ダメージを与える。\\n・敵全体に魔法ダメージを与え、さらに沈黙させ\\n\u3000る。', 302400, 0, 1, 302400, 270, 0, 0, 16, 0, 1.6, 1000, 'アークガーディアン');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】孤塔の頂に座する、暴虐なる混成魔獣。\\n千変万化の猛攻は、挑む者数多を屠ってきた。\\n\\n・ユニオンバーストは前方範囲内に物理大\\n\u3000ダメージを与え、さらにノックバックさせる。\\n・前方3キャラに物理ダメージを与え、さらに\\n\u3000火傷状態にする。\\n・敵全体に魔法ダメージを与え、さらに行動速度\\n\u3000物理防御力、魔法防御力をダウン。\\n・残り時間が10秒を切ると、敵全体に魔法極大\\n\u3000ダメージを与え、自身のTPを特大ダウン。', 302500, 0, 1, 302500, 270, 0, 0, 16, 0, 1.4, 1000, 'キマイラ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】さらなる力を得た双子座の魔星獣。\\n前衛で防御しつつ、熟達した技で攻撃を行う。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・ツインピッグスから受けるすべてのダメージで\\n\u3000発生する、パーティキャラのＴＰ回復量を中ダ\\n\u3000ウンさせる。\\n・ユニオンバーストは、敵全体にキャラの最大\\n\u3000ＨＰに応じた物理割合ダメージを与え、物理攻\\n\u3000撃力と魔法攻撃力を大ダウンさせる。このスキ\\n\u3000ルによるダメージでは、ＴＰが回復しない。こ\\n\u3000のスキルの状態異常はダメージを無効化しても\\n\u3000付与される。\\n・後方小範囲内の敵最大３キャラに物理中ダメー\\n\u3000ジを与え、スタン状態を付与する。このスキル\\n\u3000の状態異常はダメージを無効化しても付与され\\n\u3000る。\\n・後方小範囲内の敵最大３キャラに物理中ダメー\\n\u3000ジを与え、ＴＰを中ダウンさせる。その後、前\\n\u3000にいるツインピッグスは前方へ移動する。この\\n\u3000スキルによるダメージでは、ＴＰが回復しない。\\n\u3000このスキルはダメージを無効化してもＴＰをダ\\n\u3000ウンさせる。', 302600, 0, 1, 302600, 270, 0, 0, 16, 0, 1.6, 1000, 'ツインピッグス');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】さらなる力を得た双子座の魔星獣。\\n前衛で防御しつつ、熟達した技で攻撃を行う。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・ツインピッグスから受けるすべてのダメージで\\n\u3000発生する、パーティキャラのＴＰ回復量を中ダ\\n\u3000ウンさせる。\\n・ユニオンバーストは、敵全体にキャラの最大\\n\u3000ＨＰに応じた物理割合ダメージを与え、物理攻\\n\u3000撃力と魔法攻撃力を大ダウンさせる。このスキ\\n\u3000ルによるダメージでは、ＴＰが回復しない。こ\\n\u3000のスキルの状態異常はダメージを無効化しても\\n\u3000付与される。\\n・後方小範囲内の敵最大３キャラに物理中ダメー\\n\u3000ジを与え、スタン状態を付与する。このスキル\\n\u3000の状態異常はダメージを無効化しても付与され\\n\u3000る。\\n・後方小範囲内の敵最大３キャラに物理中ダメー\\n\u3000ジを与え、ＴＰを中ダウンさせる。その後、前\\n\u3000にいるツインピッグスは前方へ移動する。この\\n\u3000スキルによるダメージでは、ＴＰが回復しない。\\n\u3000このスキルはダメージを無効化してもＴＰをダ\\n\u3000ウンさせる。\\n・敵全体に物理小ダメージを与え、自身のＴＰを\\n\u3000小回復し、行動速度を中アップさせる。', 302601, 0, 1, 302601, 270, 0, 0, 16, 0, 1.6, 1000, 'ツインピッグス');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】さらなる力を得た双子座の魔星獣。\\n前衛で防御しつつ、熟達した技で攻撃を行う。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を中アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・バトル開始時、自身にＴＰダウン50％カット\\n\u3000効果を付与する。\\n・バトル開始時、敵全体のＨＰ吸収を特大ダウン\\n\u3000させ、ＴＰ上昇を小ダウンさせる。\\n・ツインピッグスから受けるすべてのダメージで\\n\u3000発生する、パーティキャラのＴＰ回復量を特大\\n\u3000ダウンさせる。\\n・ユニオンバーストは、敵全体にキャラの最大\\n\u3000ＨＰに応じた物理割合ダメージを与え、物理攻\\n\u3000撃力と魔法攻撃力を大ダウンさせる。このスキ\\n\u3000ルによるダメージでは、ＴＰが回復しない。こ\\n\u3000のスキルの状態異常はダメージを無効化しても\\n\u3000付与される。\\n・後方小範囲内の敵最大３キャラに物理中ダメー\\n\u3000ジを与え、スタン状態を付与する。このスキル\\n\u3000の状態異常はダメージを無効化しても付与され\\n\u3000る。\\n・後方小範囲内の敵最大３キャラに物理中ダメー\\n\u3000ジを与え、ＴＰを中ダウンさせる。その後、前\\n\u3000にいるツインピッグスは前方へ移動する。この\\n\u3000スキルによるダメージでは、ＴＰが回復しない。\\n\u3000このスキルはダメージを無効化してもＴＰをダ\\n\u3000ウンさせる。\\n・敵全体に物理小ダメージを与え、自身のＴＰを\\n\u3000中回復し、行動速度を中アップさせる。\\n・敵全体の物理攻撃のダメージと魔法攻撃のダ\\n\u3000メージと行動速度を中ダウンさせる。このスキ\\n\u3000ルの行動速度ダウン効果は他の行動速度変化ス\\n\u3000キルと重複する。\\n・通常攻撃は、最も近い敵１キャラに物理中ダ\\n\u3000メージを与える。このスキルによるダメージで\\n\u3000は、ＴＰが回復しない。', 302602, 0, 1, 302602, 270, 0, 0, 16, 0, 1.6, 1000, 'ツインピッグス');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】船墓の入江に巣食う、蟹座の魔星獣。\\n巨大なハサミの一撃で、無数の船を沈める。\\n\\n・敵全体に魔法大ダメージを与え、物理防御力\\n\u3000をダウン。\\n・前方範囲内の敵すべてに物理中ダメージを与\\n\u3000え、さらにスタン状態にする。\\n・敵全体に物理中ダメージ。', 302700, 0, 1, 302700, 270, 0, 0, 16, 0, 1.8, 1000, 'カルキノス');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】幾多の船を沈めた蟹座の魔星獣。\\n大海の覇者は万物を断裁し、圧潰し、殲滅する。\\n\\n・物理攻撃力ダウンと魔法攻撃力ダウン効果の影\\n\u3000響を受けやすい。\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・カルキノスから受けるすべてのダメージで発生\\n\u3000する、パーティキャラのＴＰ回復量を中ダウン\\n\u3000させる。\\n・ユニオンバーストは、敵全体に自身の魔法攻撃\\n\u3000力に応じた魔法固定ダメージを与える。その後、\\n\u3000自身の魔法攻撃力をバトル終了まで中アップさ\\n\u3000せる。このスキルによるダメージでは、敵の\\n\u3000ＴＰが回復しない。\\n・最も近い敵１キャラを中心とした小範囲内の敵\\n\u3000すべてに物理特大ダメージを与える。\\n・敵全体に物理小ダメージを与え、行動速度を中\\n\u3000ダウンさせる。このスキルの状態異常はダメー\\n\u3000ジを無効化しても付与される。', 302701, 0, 1, 302701, 270, 0, 0, 16, 0, 1.8, 1000, 'カルキノス');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】幾多の船を沈めた蟹座の魔星獣。\\n大海の覇者は万物を断裁し、圧潰し、殲滅する。\\n\\n・物理攻撃力ダウンと魔法攻撃力ダウン効果の影\\n\u3000響を受けやすい。\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・カルキノスから受けるすべてのダメージで発生\\n\u3000する、パーティキャラのＴＰ回復量を中ダウン\\n\u3000させる。\\n・ユニオンバーストは、敵全体に自身の魔法攻撃\\n\u3000力に応じた魔法固定ダメージを与える。その後、\\n\u3000自身の魔法攻撃力をバトル終了まで中アップさ\\n\u3000せる。このスキルによるダメージでは、敵の\\n\u3000ＴＰが回復しない。\\n・最も近い敵１キャラを中心とした小範囲内の敵\\n\u3000すべてに物理特大ダメージを与える。\\n・敵全体に物理小ダメージを与え、行動速度を中\\n\u3000ダウンさせる。このスキルの状態異常はダメー\\n\u3000ジを無効化しても付与される。\\n・バトル終了まで姿を変える。姿を変える際、自\\n\u3000身の魔法攻撃力と行動速度を特大アップさせ、\\n\u3000すべてのスキルを魔法攻撃に変化させる。', 302702, 0, 1, 302702, 270, 0, 0, 16, 0, 1.8, 1000, 'カルキノス');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】幾多の船を沈めた蟹座の魔星獣。\\n大海の覇者は万物を断裁し、圧潰し、殲滅する。\\n\\n・物理攻撃力ダウンと魔法攻撃力ダウン効果の影\\n\u3000響を受けやすい。\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を中アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・バトル開始時、敵全体のＨＰ吸収を特大ダウン\\n\u3000させ、ＴＰ上昇を小ダウンさせる。\\n・バトル開始時、自身にＴＰダウン100％カッ\\n\u3000ト効果を付与する。\\n・カルキノスから受けるすべてのダメージで発生\\n\u3000する、パーティキャラのＴＰ回復量を特大ダウ\\n\u3000ンさせる。\\n・ユニオンバーストは、敵全体のバリア効果を解\\n\u3000除し、自身の魔法攻撃力に応じた魔法固定ダ\\n\u3000メージを与える。その後、自身の魔法攻撃力を\\n\u3000バトル終了まで中アップさせる。このスキルに\\n\u3000よるダメージでは、ＴＰが回復しない。\\n・最も近い敵１キャラを中心とした小範囲内の敵\\n\u3000すべてに物理特大ダメージを与える。\\n・敵全体に物理小ダメージを与え、行動速度を中\\n\u3000ダウンさせる。このスキルの効果は他の行動速\\n\u3000度変化スキルと重複する。このスキルの状態異\\n\u3000常はダメージを無効化しても付与される。\\n・バトル終了まで姿を変える。姿を変える際、自\\n\u3000身の魔法攻撃力と行動速度を特大アップさせ、\\n\u3000すべてのスキルを魔法攻撃に変化させる。', 302703, 0, 1, 302703, 270, 0, 0, 16, 0, 1.8, 1000, 'カルキノス');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('サバンナの覇者と名高い、獅子座の魔星獣。\\n刃向かう者は、灼熱の咆哮で焼き尽くす。\\n\\n・敵全体に、最大ＨＰに応じた防御力無視の\\n\u3000物理大ダメージを与え、残りＨＰの少ない\\n\u3000敵はさらに火傷状態にする。\\n・敵1キャラに物理大ダメージを与え、火傷\\n\u3000状態の場合はさらに追加ダメージ。\\n・前方範囲内の敵に物理中ダメージを与え、\\n\u3000火傷状態の場合はさらに追加ダメージ。', 302800, 0, 1, 302800, 270, 0, 0, 16, 0, 1.8, 1000, 'オルレオン');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】荒涼たる原野に君臨する獅子座の魔星獣。\\n鋭爪で大気を切裂き、業火の咆哮が大地を焦がす。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・オルレオンから受けるすべてのダメージで発生\\n\u3000する、パーティキャラのＴＰ回復量を中ダウン\\n\u3000させる。\\n・ユニオンバーストは、敵全体に物理中ダメージ\\n\u3000を与え、短時間火傷状態を付与する。キャラの\\n\u3000ＨＰが60％未満の場合、長時間火傷状態を付\\n\u3000与する。このスキルによるダメージと付与され\\n\u3000た火傷状態のダメージでは、ＴＰが回復しない。\\n\u3000このスキルの状態異常はダメージを無効化して\\n\u3000も付与される。\\n・最も近い敵１キャラに物理特大ダメージを与え、\\n\u3000火傷状態の場合はさらに追加の物理固定ダメー\\n\u3000ジを与える。このスキルによる追加ダメージで\\n\u3000は、ＴＰが回復しない。\\n・前方広範囲内の敵すべてに物理大ダメージを与\\n\u3000え、火傷状態の場合はさらに追加の物理固定ダ\\n\u3000メージを与える。このスキルによる追加ダメー\\n\u3000ジでは、ＴＰが回復しない。', 302801, 0, 1, 302801, 270, 0, 0, 16, 0, 3.0, 1000, 'オルレオン');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】荒涼たる原野に君臨する獅子座の魔星獣。\\n鋭爪で大気を切裂き、業火の咆哮が大地を焦がす。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・オルレオンから受けるすべてのダメージで発生\\n\u3000する、パーティキャラのＴＰ回復量を中ダウン\\n\u3000させる。\\n・ユニオンバーストは、敵全体に物理中ダメージ\\n\u3000を与え、短時間火傷状態を付与する。キャラの\\n\u3000ＨＰが60％未満の場合、長時間火傷状態を付\\n\u3000与する。このスキルによるダメージと付与され\\n\u3000た火傷状態のダメージでは、ＴＰが回復しない。\\n\u3000このスキルの状態異常はダメージを無効化して\\n\u3000も付与される。\\n・最も近い敵１キャラに物理特大ダメージを与え、\\n\u3000火傷状態の場合はさらに追加の物理固定ダメー\\n\u3000ジを与える。このスキルによる追加ダメージで\\n\u3000は、ＴＰが回復しない。\\n・前方広範囲内の敵すべてに物理大ダメージを与\\n\u3000え、火傷状態の場合はさらに追加の物理固定ダ\\n\u3000メージを与える。このスキルによる追加ダメー\\n\u3000ジでは、ＴＰが回復しない。\\n・敵全体にキャラの最大ＨＰに応じた魔法割合ダ\\n\u3000メージを与え、短時間スタン状態を付与する。\\n\u3000キャラのＨＰが60％未満の場合、長時間スタ\\n\u3000ン状態を付与する。このスキルによるダメージ\\n\u3000では、ＴＰが回復しない。このスキルの状態異\\n\u3000常はダメージを無効化しても付与される。', 302802, 0, 1, 302802, 270, 0, 0, 16, 0, 3.0, 1000, 'オルレオン');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】荒涼たる原野に君臨する獅子座の魔星獣。\\n鋭爪で大気を切裂き、業火の咆哮が大地を焦がす。\\n\\n・水属性のキャラが４体以上編成されているとき、\\n\u3000キャラの属性ボーナスが強化される。\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を大アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・バトル開始時、敵全体のＨＰ吸収を特大ダウン\\n\u3000させ、ＴＰ上昇を中ダウンさせる。\\n・バトル開始時、自身にＴＰダウン100％カッ\\n\u3000ト効果を付与する。\\n・オルレオンから受けるすべてのダメージで発生\\n\u3000する、パーティキャラのＴＰ回復量を中ダウン\\n\u3000させる。\\n・ユニオンバーストは、敵全体に物理中ダメージ\\n\u3000を与え、短時間火傷状態を付与する。キャラの\\n\u3000ＨＰが60％未満の場合、長時間火傷状態を付\\n\u3000与する。このスキルによるダメージと付与され\\n\u3000た火傷状態のダメージでは、ＴＰが回復しない。\\n\u3000このスキルの状態異常はダメージを無効化して\\n\u3000も付与される。\\n・最も近い敵１キャラに物理特大ダメージを与え、\\n\u3000火傷状態の場合はさらに追加の物理固定ダメー\\n\u3000ジを与える。このスキルによる追加ダメージで\\n\u3000は、ＴＰが回復しない。\\n・前方広範囲内の敵すべてに物理大ダメージを与\\n\u3000え、火傷状態の場合はさらに追加の物理固定ダ\\n\u3000メージを与える。このスキルによるダメージで\\n\u3000は、ＴＰが回復しない。\\n・敵全体にキャラの最大ＨＰに応じた魔法割合ダ\\n\u3000メージを与え、短時間スタン状態を付与する。\\n\u3000キャラのＨＰが60％未満の場合、長時間スタ\\n\u3000ン状態を付与する。このスキルによるダメージ\\n\u3000では、ＴＰが回復しない。このスキルの状態異\\n\u3000常はダメージを無効化しても付与される。\\n・敵の挑発を無視して、前から３番目のキャラを\\n\u3000中心にした中範囲内の敵すべてに継続魔法ダ\\n\u3000メージを与えるフィールドを展開する。このス\\n\u3000キルによるダメージでは、ＴＰが回復しない。', 302803, 0, 1, 302803, 270, 0, 0, 16, 0, 3.0, 1000, 'オルレオン');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('神瓶に宿る魔力に取込まれた、水瓶座の魔星獣。\\n強大な力に溺れ、大海を支配せんと暴れまわる。\\n\\n・ユニオンバーストは、敵全体に魔法小ダメー\\n\u3000ジを計６回与える。\\n\u3000キャラのＨＰが８０％を切るとノックバック\\n\u3000させ、４０％を切るとさらに追加でノックバ\\n\u3000ックとスタン状態を付与。\\n・目の前の敵３キャラに物理中ダメージ。\\n・自身のステータスダウン効果と、敵全体のス\\n\u3000テータスアップ効果を打消し、自身のＴＰを\\n\u3000アップ。', 302900, 0, 1, 302900, 270, 0, 0, 16, 0, 1.8, 1000, 'アクアリオス');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】神瓶に宿る魔力を操る水瓶座の魔星獣。\\n激流は全てを飲込み蒼海の支配者として君臨する。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・アクアリオスから受けるすべてのダメージで発\\n\u3000生する、パーティキャラのＴＰ回復量を中ダウ\\n\u3000ンさせる。\\n・ユニオンバーストは、敵全体に魔法大ダメージ\\n\u3000を与え、ノックバックさせる。さらに召喚体、\\n\u3000分身を除いた最も近い敵２キャラのＨＰが80％\\n\u3000未満の場合、大きくノックバックさせる。この\\n\u3000スキルによるダメージでは、ＴＰが回復しない。\\n・敵全体の物理防御力と魔法防御力を大ダウンさ\\n\u3000せる。さらに自身の物理防御力と魔法防御力を\\n\u3000小アップさせ、ＴＰを小回復する。\\n・最も近い敵３キャラに物理大ダメージを与える。', 302901, 0, 1, 302901, 270, 0, 0, 16, 0, 1.8, 1000, 'アクアリオス');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】神瓶に宿る魔力を操る水瓶座の魔星獣。\\n激流は全てを飲込み蒼海の支配者として君臨する。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・アクアリオスから受けるすべてのダメージで発\\n\u3000生する、パーティキャラのＴＰ回復量を中ダウ\\n\u3000ンさせる。\\n・ユニオンバーストは、敵全体に魔法大ダメージ\\n\u3000を与え、ノックバックさせる。さらに召喚体、\\n\u3000分身を除いた最も近い敵２キャラのＨＰが80％\\n\u3000未満の場合、大きくノックバックさせる。この\\n\u3000スキルによるダメージでは、ＴＰが回復しない。\\n・敵全体の物理防御力と魔法防御力を大ダウンさ\\n\u3000せる。さらに自身の物理防御力と魔法防御力を\\n\u3000小アップさせ、ＴＰを小回復する。\\n・最も近い敵３キャラに物理大ダメージを与える。\\n\\n【バトルフィールド効果】\\n一定時間が経過するごとに、激流が発生する。\\n・敵全体に魔法大ダメージを与え、移動速度を大\\n\u3000ダウンさせ、ＨＰ回復量を中ダウンさせる。こ\\n\u3000のスキルによるダメージでは、ＴＰが回復しな\\n\u3000い。このスキルの状態異常はダメージを無効化\\n\u3000しても付与される。', 302902, 0, 1, 302902, 270, 0, 0, 16, 0, 1.8, 1000, 'アクアリオス');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】神瓶に宿る魔力を操る水瓶座の魔星獣。\\n激流は全てを飲込み蒼海の支配者として君臨する。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・アクアリオスから受けるすべてのダメージで発\\n\u3000生する、パーティキャラのＴＰ回復量を中ダウ\\n\u3000ンさせる。\\n・ユニオンバーストは、敵全体に魔法大ダメージ\\n\u3000を与え、ノックバックさせる。さらに召喚体、\\n\u3000分身を除いた最も近い敵２キャラのＨＰが80％\\n\u3000未満の場合、大きくノックバックさせる。この\\n\u3000スキルによるダメージでは、ＴＰが回復しない。\\n・敵全体の物理防御力と魔法防御力を大ダウンさ\\n\u3000せる。さらに自身の物理防御力と魔法防御力を\\n\u3000小アップさせ、ＴＰを小回復する。\\n・最も近い敵３キャラに物理大ダメージを与える。\\n\\n【バトルフィールド効果】\\n一定時間が経過するごとに、激流が発生する。\\n・敵全体に魔法大ダメージを与え、移動速度を大\\n\u3000ダウンさせ、ＨＰ回復量を中ダウンさせる。こ\\n\u3000のスキルによるダメージでは、ＴＰが回復しな\\n\u3000い。このスキルの状態異常はダメージを無効化\\n\u3000しても付与される。', 302903, 0, 1, 302903, 270, 0, 0, 16, 0, 1.8, 1000, 'アクアリオス');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】神瓶に宿る魔力を操る水瓶座の魔星獣。\\n激流は全てを飲込み蒼海の支配者として君臨する。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を中アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・バトル開始時、敵全体のＴＰ上昇を中ダウンさ\\n\u3000せるフィールドを展開する。\\n・バトル開始時、自身にＴＰダウン50％カット\\n\u3000効果を付与する。\\n・アクアリオスから受けるすべてのダメージで発\\n\u3000生する、パーティキャラのＴＰ回復量を中ダウ\\n\u3000ンさせる。\\n・敵から受けるすべてのダメージで発生する、ア\\n\u3000クアリオスのＴＰ回復量が大ダウンする。\\n・ユニオンバーストは、敵全体に魔法大ダメージ\\n\u3000を与え、ノックバックさせる。さらに召喚体、\\n\u3000分身を除いた最も近い敵２キャラのＨＰが80％\\n\u3000未満の場合、大きくノックバックさせる。この\\n\u3000スキルによるダメージでは、ＴＰが回復しない。\\n・敵全体のバリアを解除し、物理防御力と魔法防\\n\u3000御力を大ダウンさせる。さらに自身の物理防御\\n\u3000力と魔法防御力を小アップさせ、ＴＰを小回復\\n\u3000する。\\n・最も近い敵３キャラに物理大ダメージを与える。\\n\\n【バトルフィールド効果】\\n一定時間が経過するごとに、激流が発生する。\\n・敵全体に魔法大ダメージを与え、移動速度を大\\n\u3000ダウンさせ、ＨＰ回復量を中ダウンさせる。こ\\n\u3000のスキルによるダメージでは、ＴＰが回復しな\\n\u3000い。このスキルの状態異常はダメージを無効化\\n\u3000しても付与される。', 302904, 0, 1, 302904, 270, 0, 0, 16, 0, 1.8, 1000, 'アクアリオス');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('大海原を爆走し、鬼シケ呼び込む魚座の魔星獣。\\n取巻く手下の赤ビレはカチコミ上等ヘッドの証。\\n\\n・物理攻撃力アップ・ダウン効果の影響を受け\\n\u3000やすい。\\n・ユニオンバーストは、敵全体に物理大ダメー\\n\u3000ジを与え、自分の行動速度と物理攻撃力をア\\n\u3000ップ。\\n・敵全体に物理小ダメージ。\\n・前方２キャラに物理中ダメージを与え、物理\\n\u3000防御力を小ダウン。', 303000, 0, 1, 303000, 270, 0, 0, 16, 0, 1.8, 1000, 'トルペドン');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】大海を背負って立つ、爆走魚座の魔星獣。\\n舎弟に魅せるその背中。共に往くのは覇道の極み。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・トルペドンから受けるすべてのダメージで発生\\n\u3000する、パーティキャラのＴＰ回復量を中ダウン\\n\u3000させる。\\n・ユニオンバーストは、敵全体のバリアを解除し、\\n\u3000物理大ダメージを与え、さらに自身の行動速度\\n\u3000と物理攻撃力を特大アップさせる。このスキル\\n\u3000によるダメージでは、敵のＴＰが回復しない。\\n・敵全体に物理小ダメージを与える。このスキル\\n\u3000によるダメージでは、敵のＴＰが回復しない。\\n・最も近い敵２キャラに物理中ダメージを与え、\\n\u3000物理防御力を大ダウンさせる。このスキルの状\\n\u3000態異常はダメージを無効化しても付与される。', 303001, 0, 1, 303001, 270, 0, 0, 16, 0, 1.8, 1000, 'トルペドン');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】大海を背負って立つ、爆走魚座の魔星獣。\\n舎弟に魅せるその背中。共に往くのは覇道の極み。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・トルペドンから受けるすべてのダメージで発生\\n\u3000する、パーティキャラのＴＰ回復量を中ダウン\\n\u3000させる。\\n・ユニオンバーストは、敵全体のバリアを解除し、\\n\u3000物理大ダメージを与え、さらに自身の行動速度\\n\u3000と物理攻撃力を特大アップさせる。このスキル\\n\u3000によるダメージでは、敵のＴＰが回復しない。\\n・敵全体に物理小ダメージを与える。旗持ち子分\\n\u3000が存在する場合、さらに追加物理ダメージを与\\n\u3000える。このスキルの追加ダメージは、旗持ち子\\n\u3000分の数に応じて、与えられるダメージ量が大き\\n\u3000く上昇する。このスキルによるダメージでは、\\n\u3000敵のＴＰが回復しない。\\n・最も近い敵２キャラに物理中ダメージを与え、\\n\u3000物理防御力を大ダウンさせる。このスキルの状\\n\u3000態異常はダメージを無効化しても付与される。\\n・旗持ち子分を２体召喚し、自身の物理防御力と\\n\u3000魔法防御力を中ダウンさせる。\\n・旗持ち子分はトルペドンのＴＰを小回復させる。\\n・旗持ち子分のＨＰが一定値以下になった時、敵\\n\u3000全体の物理攻撃力と魔法攻撃力を中アップさせ、\\n\u3000消滅する。', 303002, 0, 1, 303002, 270, 0, 0, 16, 0, 1.8, 1000, 'トルペドン');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】大海を背負って立つ、爆走魚座の魔星獣。\\n舎弟に魅せるその背中。共に往くのは覇道の極み。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を中アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・バトル開始時、敵全体のＨＰ吸収を特大ダウン\\n\u3000させる。 \\n・バトル開始時、敵全体のＴＰ上昇を中ダウンさ\\n\u3000せるフィールドを展開する。\\n・バトル開始時、自身にＴＰダウン50％カット\\n\u3000効果を付与する。\\n・トルペドンから受けるすべてのダメージで発生\\n\u3000する、パーティキャラのＴＰ回復量を中ダウン\\n\u3000させる。\\n・ユニオンバーストは、敵全体のバリアを解除し、\\n\u3000物理大ダメージを与え、さらに自身の行動速度\\n\u3000と物理攻撃力を特大アップさせる。このスキル\\n\u3000によるダメージでは、敵のＴＰが回復しない。\\n・敵全体に物理小ダメージを与える。旗持ち子分\\n\u3000が存在する場合、さらに追加物理ダメージを与\\n\u3000える。このスキルの追加ダメージは、旗持ち子\\n\u3000分の数に応じて、与えられるダメージ量が大き\\n\u3000く上昇する。このスキルによるダメージでは、\\n\u3000敵のＴＰが回復しない。\\n・最も近い敵２キャラに物理中ダメージを与え、\\n\u3000物理防御力を大ダウンさせる。このスキルの状\\n\u3000態異常はダメージを無効化しても付与される。\\n・旗持ち子分を３体召喚し、自身の物理防御力と\\n\u3000魔法防御力を中ダウンさせる。\\n・旗持ち子分はトルペドンのＴＰを小回復させる。\\n・旗持ち子分のＨＰが一定値以下になった時、敵\\n\u3000全体の物理攻撃力と魔法攻撃力を中アップさせ、\\n\u3000消滅する。', 303003, 0, 1, 303003, 270, 0, 0, 16, 0, 1.8, 1000, 'トルペドン');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】大海を背負って立つ、爆走魚座の魔星獣。\\n舎弟に魅せるその背中。共に往くのは覇道の極み。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・トルペドンから受けるすべてのダメージで発生\\n\u3000する、パーティキャラのＴＰ回復量を中ダウン\\n\u3000させる。\\n・ユニオンバーストは、敵全体のバリアを解除し、\\n\u3000物理大ダメージを与え、さらに自身の行動速度\\n\u3000と物理攻撃力を特大アップさせる。このスキル\\n\u3000によるダメージでは、敵のＴＰが回復しない。\\n・敵全体に物理小ダメージを与える。旗持ち子分\\n\u3000が存在する場合、さらに追加物理ダメージを与\\n\u3000える。このスキルの追加ダメージは、旗持ち子\\n\u3000分の数に応じて、与えられるダメージ量が大き\\n\u3000く上昇する。このスキルによるダメージでは、\\n\u3000敵のＴＰが回復しない。\\n・最も近い敵２キャラに物理中ダメージを与え、\\n\u3000物理防御力を大ダウンさせる。このスキルの状\\n\u3000態異常はダメージを無効化しても付与される。\\n・旗持ち子分を２体召喚し、自身の物理防御力と\\n\u3000魔法防御力を中ダウンさせる。\\n・旗持ち子分はトルペドンのＴＰを小回復させる。\\n・旗持ち子分のＨＰが一定値以下になった時、敵\\n\u3000全体の物理攻撃力と魔法攻撃力を中アップさせ、\\n\u3000消滅する。', 303004, 0, 1, 303002, 270, 0, 0, 16, 0, 1.8, 1000, 'トルペドン');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】氷穴最奥に引き篭り\\n生涯冬眠すると決めた巨大熊。\\n長い歳月を夢うつつの中で過ごし\\n獲物を狩るその一瞬、覚醒する。\\n\\n・敵全体に魔法大ダメージを与え、\\n\u3000物理攻撃力を下げる。\\n\\n・前方3キャラに物理小ダメージを\\n\u3000与える。さらに、前方1キャラを\\n\u3000大きく吹き飛ばし、氷結状態\\n\u3000にして移動速度を下げる。', 303100, 0, 1, 303100, 270, 0, 0, 13, 0, 3.5, 1000, 'トウミングマ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】生涯冬眠すると決め、氷穴に篭る巨大熊。\\n日々を夢の中で暮し、獲物を狩る一瞬、覚醒する。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・バトル開始時、自身に魔法ダメージ20%\\n\u3000カット効果を付与する。\\n・ユニオンバーストは、敵全体に魔法大ダメージ\\n\u3000を与え、物理攻撃力と魔法攻撃力を大ダウンさ\\n\u3000せる。このスキルの状態異常はダメージを無効\\n\u3000化しても付与される。このスキルによるダメー\\n\u3000ジでは、敵のＴＰが回復しない。\\n・前方３キャラに物理小ダメージを与える。さら\\n\u3000に、前方１キャラを吹き飛ばし、凍結状態にし\\n\u3000て移動速度を下げる。\\n・前方１キャラに物理特大ダメージ。このスキル\\n\u3000によるダメージでは、ＴＰ回復量は減少する。', 303101, 0, 1, 303101, 270, 0, 0, 13, 0, 3.5, 1000, 'トウミングマ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】生涯冬眠すると決め、氷穴に篭る巨大熊。\\n日々を夢の中で暮し、獲物を狩る一瞬、覚醒する。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・バトル開始時、自身に魔法ダメージ50%\\n\u3000カット効果を付与する。\\n・ユニオンバーストは、敵全体に魔法大ダメージ\\n\u3000を与え、物理攻撃力と魔法攻撃力を大ダウンさ\\n\u3000せる。このスキルの状態異常はダメージを無効\\n\u3000化しても付与される。このスキルによるダメー\\n\u3000ジでは、敵のＴＰが回復しない。\\n・前方３キャラに物理小ダメージを与える。さら\\n\u3000に、前方１キャラを吹き飛ばし、凍結状態にし\\n\u3000て移動速度を下げる。\\n・前方１キャラに物理特大ダメージ。このスキル\\n\u3000によるダメージでは、ＴＰ回復量は減少する。', 303102, 0, 1, 303102, 270, 0, 0, 13, 0, 3.5, 1000, 'トウミングマ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】生涯冬眠すると決め、氷穴に篭る巨大熊。\\n日々を夢の中で暮し、獲物を狩る一瞬、覚醒する。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・バトル開始時、自身に魔法ダメージ50%\\n\u3000カット効果を付与する。\\n・バトル開始時、味方全体のＴＰを中アップ。\\n・ユニオンバーストは、敵全体に魔法大ダメージ\\n\u3000を与え、物理攻撃力と魔法攻撃力を大ダウンさ\\n\u3000せる。このスキルの状態異常はダメージを無効\\n\u3000化しても付与される。このスキルによるダメー\\n\u3000ジでは、敵のＴＰが回復しない。\\n・前方３キャラに物理小ダメージを与える。さら\\n\u3000に、前方１キャラを吹き飛ばし、凍結状態にし\\n\u3000て移動速度を下げる。\\n・前方１キャラに物理特大ダメージ。このスキル\\n\u3000によるダメージでは、ＴＰ回復量は減少する。', 303103, 0, 1, 303103, 270, 0, 0, 13, 0, 3.5, 1000, 'トウミングマ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】生涯冬眠すると決め、氷穴に篭る巨大熊。\\n日々を夢の中で暮し、獲物を狩る一瞬、覚醒する。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・バトル開始時、自身に魔法ダメージ70%\\n\u3000カット効果を付与する。\\n・バトル開始時、味方全体のＴＰを中アップ。\\n・ユニオンバーストは、敵全体に魔法大ダメージ\\n\u3000を与え、物理攻撃力と魔法攻撃力を大ダウンさ\\n\u3000せる。さらに、敵全体をスタンさせる。このス\\n\u3000キルの状態異常はダメージを無効化しても付与\\n\u3000される。このスキルによるダメージでは、敵の\\n\u3000ＴＰが回復しない。\\n・前方３キャラに物理小ダメージを与える。さら\\n\u3000に、前方１キャラを吹き飛ばし、凍結状態にし\\n\u3000て移動速度を下げる。\\n・前方１キャラに物理特大ダメージ。このスキル\\n\u3000によるダメージでは、ＴＰ回復量は減少する。', 303104, 0, 1, 303104, 270, 0, 0, 13, 0, 3.5, 1000, 'トウミングマ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】生涯冬眠すると決め、氷穴に篭る巨大熊。\\n日々を夢の中で暮し、獲物を狩る一瞬、覚醒する。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・バトル開始時、自身に魔法ダメージ100%\\n\u3000カット効果を付与する。\\n・バトル開始時、味方全体のＴＰを中アップ。\\n・ユニオンバーストは、敵全体に魔法大ダメージ\\n\u3000を与え、物理攻撃力と魔法攻撃力を大ダウンさ\\n\u3000せる。さらに、敵全体をスタンさせる。このス\\n\u3000キルの状態異常はダメージを無効化しても付与\\n\u3000される。このスキルによるダメージでは、敵の\\n\u3000ＴＰが回復しない。\\n・前方３キャラに物理小ダメージを与える。さら\\n\u3000に、前方１キャラを吹き飛ばし、凍結状態にし\\n\u3000て移動速度を下げる。\\n・前方１キャラに物理特大ダメージ。このスキル\\n\u3000によるダメージでは、ＴＰ回復量は減少する。', 303105, 0, 1, 303105, 270, 0, 0, 13, 0, 3.5, 1000, 'トウミングマ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】生涯冬眠すると決め、氷穴に篭る巨大熊。\\n日々を夢の中で暮し、獲物を狩る一瞬、覚醒する。\\n\\n・環境効果【寒気凛冽】を発動する。このスキル\\n\u3000の効果は敵、味方すべてに適用される。敵、味\\n\u3000方全体の行動速度を小ダウンさせる。このスキ\\n\u3000ルの効果は他の行動速度変化スキルと重複する。\\n\u3000さらに一定時間が経過するごとに、初期値より\\n\u3000行動速度が低い状態のキャラに凍結状態を付与\\n\u3000する。\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を中アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・バトル開始時、自身にＴＰダウン50％カット\\n\u3000効果を付与する。\\n・バトル開始時、敵全体のＨＰ吸収を特大ダウン\\n\u3000させる。\\n・自身が一度の行動で受けるダメージ値を減衰さ\\n\u3000せる。ダメージ値が上昇するほど減衰率も上昇\\n\u3000する。\\n・バトル開始時、敵全体にＴＰ上昇上限効果を付\\n\u3000与する。\\n・トウミングマから受けるすべてのダメージで発\\n\u3000生する、パーティキャラのＴＰ回復量を中ダウ\\n\u3000ンさせる。\\n・ユニオンバーストは、敵全体に魔法大ダメージ\\n\u3000を与える。さらに、敵全体の物理攻撃力、魔法\\n\u3000攻撃力、行動速度を大ダウンさせる。このスキ\\n\u3000ルによるダメージでは、敵のＴＰが回復しない。\\n\u3000このスキルの状態異常はダメージを無効化して\\n\u3000も付与される。\\n・前方３キャラに物理小ダメージを与える。さら\\n\u3000に、前方１キャラをノックバックし、凍結状態\\n\u3000にして移動速度を下げる。このスキルの状態異\\n\u3000常はダメージを無効化しても付与される。', 303106, 0, 1, 303106, 270, 0, 0, 13, 0, 3.5, 1000, 'トウミングマ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】吹雪と共に現れ、\\n縄張りを荒らす者には\\n大群を呼び寄せ襲い掛かる\\n雪国イチのゴージャスマダム。\\n\\n・前方4キャラに魔法中ダメージを\\n\u3000与える。\\n\\n・ランダムな2キャラに魔法\\n\u3000小ダメージを与え、\\n\u3000凍結状態にする。', 303200, 0, 1, 303200, 270, 0, 0, 6, 0, 1.6, 1000, 'マダムピック');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】朽ちた遺跡に残り\\n主亡き地を護る、謎の鳥像。\\n街も命令も、全て砂と消えた今は\\n誰彼構わず炎を吐き襲い掛かる。\\n\\n・前方5キャラに魔法中ダメージを\\n\u3000与え、火傷状態にする。さらに、\\n\u3000魔法防御力を下げる。\\n\\n・ランダムな3キャラに\\n\u3000魔法小ダメージを与え、\\n\u3000敵全体を暗闇状態にする。', 303300, 0, 1, 303300, 270, 0, 0, 13, 0, 2.1, 1000, 'ガーゴイル');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】暴食の君主に仕える、近衛の黒鉄像。\\n冥府を彷徨いし魂を巧みに操り、主に捧げる。\\n\\n・物理防御力ダウンと魔法防御力ダウン効果の影\\n\u3000響を受けやすい。\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・ダークガーゴイルから受けるすべてのダメージ\\n\u3000で発生する、パーティキャラのＴＰ回復量を中\\n\u3000ダウンさせる。\\n・ユニオンバーストは、物理攻撃をする敵全体に\\n\u3000自身の物理防御力に応じたダメージを与える火\\n\u3000傷状態を付与し、魔法攻撃をする敵全体に自身\\n\u3000の魔法防御力に応じたダメージを与える火傷状\\n\u3000態を付与する。さらに、敵全体のＨＰ吸収を大\\n\u3000ダウンさせる。このスキルにより付与された火\\n\u3000傷のダメージでは、ＴＰが回復しない。\\n・敵全体に物理小ダメージを与え、ノックバック\\n\u3000させる。このスキルによるダメージでは、敵の\\n\u3000ＴＰが回復しない。', 303301, 0, 1, 303301, 270, 0, 0, 13, 0, 2.1, 1000, 'ダークガーゴイル');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】暴食の君主に仕える、近衛の黒鉄像。\\n冥府を彷徨いし魂を巧みに操り、主に捧げる。\\n\\n・物理防御力ダウンと魔法防御力ダウン効果の影\\n\u3000響を受けやすい。\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・バトル開始時、敵全体のＴＰ上昇を小ダウンさ\\n\u3000せるフィールドを展開する。\\n・バトル開始時、自身にＴＰダウン100％カッ\\n\u3000ト効果を付与する。\\n・ダークガーゴイルから受けるすべてのダメージ\\n\u3000で発生する、パーティキャラのＴＰ回復量を中\\n\u3000ダウンさせる。\\n・敵から受けるすべてのダメージで発生する、\\n\u3000ダークガーゴイルのＴＰ回復量が大ダウンする。\\n・ユニオンバーストは、物理攻撃をする敵全体に\\n\u3000自身の物理防御力に応じたダメージを与える火\\n\u3000傷状態を付与し、魔法攻撃をする敵全体に自身\\n\u3000の魔法防御力に応じたダメージを与える火傷状\\n\u3000態を付与する。さらに、敵全体のＨＰ吸収を特\\n\u3000大ダウンさせる。このスキルにより付与された\\n\u3000火傷のダメージでは、ＴＰが回復しない。\\n・敵全体に物理小ダメージを与え、ノックバック\\n\u3000させる。さらに、最も近い敵１キャラに追加の\\n\u3000魔法固定ダメージを与える。このスキルによる\\n\u3000ダメージでは、敵のＴＰが回復しない。', 303302, 0, 1, 303302, 270, 0, 0, 13, 0, 2.1, 1000, 'ダークガーゴイル');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】塔の魔力を帯び命を宿した砂岩像の魔物。\\n砂塵舞う地で敵を待ち、灼炎を吐いて襲い掛かる。\\n\\n・前方範囲内に魔法大ダメージを与え、火傷状態\\n\u3000にする。さらに、魔法防御力を中ダウンさせる。\\n・前方３キャラに魔法中ダメージを与え、敵全体\\n\u3000を暗闇状態にする。\\n・目の前の敵１キャラに物理大ダメージを与える。\\n\u3000さらに、敵全体のうち火傷状態の敵には魔法\\n\u3000大ダメージを与える。', 303303, 0, 1, 303303, 270, 0, 0, 13, 0, 2.1, 1000, 'サンドガーゴイル');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】砂の大地を守護する漆黒\\nの悪魔像。広大な砂漠一面を焼き\\n尽くすブレスを吐き、灼熱の地を\\n進む冒険者の行手を阻む。\\n\\n・ユニオンバーストは、敵全体に\\n\u3000魔法中ダメージを与え、火傷状\\n\u3000態にし、さらに魔法防御力を小\\n\u3000ダウンさせる。\\n\u3000このスキルによるダメージ\\n\u3000では、敵のＴＰが回復しない。\\n\\n・前方の敵１キャラに魔法中\\n\u3000ダメージを与える。\\n\u3000さらに敵全体に魔法中ダメージ\\n\u3000を与え、物理攻撃力と魔法攻撃\\n\u3000力を中ダウンさせる。', 303304, 0, 1, 303304, 270, 0, 0, 13, 0, 2.1, 1000, 'アウスグス');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】暴食の君主に仕える、近衛の黒鉄像。\\n冥府を彷徨いし魂を巧みに操り、主に捧げる。\\n\\n・ダークガーゴイルから受けるすべてのダメージ\\n\u3000で発生する、パーティキャラのＴＰ回復量を中\\n\u3000ダウンさせる。\\n・ユニオンバーストは、物理攻撃をする敵全体に\\n\u3000自身の物理防御力に応じたダメージを与える火\\n\u3000傷状態を付与し、魔法攻撃をする敵全体に自身\\n\u3000の魔法防御力に応じたダメージを与える火傷状\\n\u3000態を付与する。さらに、敵全体のＨＰ吸収を特\\n\u3000大ダウンさせる。このスキルにより付与された\\n\u3000火傷のダメージでは、ＴＰが回復しない。\\n・敵全体に物理小ダメージを与え、ノックバック\\n\u3000させる。さらに、最も近い敵１キャラに追加の\\n\u3000魔法固定ダメージを与える。このスキルによる\\n\u3000ダメージでは、敵のＴＰが回復しない。', 303305, 0, 1, 303305, 270, 0, 0, 13, 0, 2.1, 3000, 'ダークガーゴイル');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】生存競争激しい砂漠の\\n頂点に君臨する、巨大トカゲ。\\n毒を使い、砂を活かす戦法は、\\n過酷な環境で得たサバイバル術。\\n\\n・敵全体に物理中ダメージを与え、\\n\u3000行動速度を下げる。\\n\u3000さらに、味方全体の物理攻撃力を\\n\u3000上げる。\\n\\n・前方1キャラを中心にした小範囲\\n\u3000に物理小ダメージを与え、毒状態\\n\u3000にする。さらに、物理防御力を\\n\u3000下げる。', 303400, 0, 1, 303400, 270, 0, 0, 13, 0, 1.9, 1000, 'スナノヅチ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】ルナの魔力を帯び変異した巨大トカゲ。\\n硬い棘状のうろこが、敵の体力と鎧を削り落とす。\\n\\n・敵全体に物理大ダメージを与え、さらにＴＰを\\n\u3000下げる。\\n・前方2キャラに物理中ダメージを与え、毒状態\\n\u3000にする。\\n・前方3キャラに物理中ダメージを与える。\\n\u3000さらに前方1キャラに物理大ダメージを与え、\\n\u3000物理防御力と魔法防御力を中ダウンさせる。', 303401, 0, 1, 303401, 270, 0, 0, 13, 0, 1.9, 1000, 'イワノヅチ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】ルナの魔力を帯び変異した巨大トカゲ。\\n硬い棘状のうろこが、敵の体力と鎧を削り落とす。\\n\\n・敵全体に物理大ダメージを与え、さらにＴＰを\\n\u3000下げる。\\n・前方2キャラに物理中ダメージを与え、毒状態\\n\u3000にする。\\n・前方3キャラに物理中ダメージを与える。\\n\u3000さらに前方1キャラに物理大ダメージを与え、\\n\u3000物理防御力と魔法防御力を中ダウンさせる。', 303402, 0, 1, 303402, 270, 0, 0, 13, 0, 1.9, 1000, 'イワノヅチ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】吸い続けた他者の\\n魔力で、妖術を体得した魔物。\\n敵に付けた傷から魔力を奪い、\\nさらなる力を得ようとする。\\n\\n・敵全体に魔法中ダメージを与え、\\n\u3000魔法攻撃をする敵すべての\\n\u3000ＴＰを下げる。\\n\\n・前方1キャラを中心にした小範囲\\n\u3000に魔法小ダメージを与え、\\n\u3000魔法防御力を下げる。', 303500, 0, 1, 303500, 270, 0, 0, 13, 0, 1.8, 1000, 'ムシュフシュ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】吸い続けた他者の魔力で妖術を得た魔物。\\n敵に付けた傷から魔力を奪いさらなる力を求める。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・ムシュフシュから受けるすべてのダメージで発\\n\u3000生する、パーティキャラのＴＰ回復量を小ダウ\\n\u3000ンさせる。\\n・ユニオンバーストは、最も近い敵１キャラを中\\n\u3000心にした小範囲に毒状態を付与する。さらに敵\\n\u3000全体に物理攻撃力中ダウンと魔法攻撃力大ダウ\\n\u3000ンを付与する。このスキルにより付与された毒\\n\u3000のダメージでは、ＴＰが回復しない。\\n・最も近い敵１キャラを中心にした小範囲に物理\\n\u3000大ダメージを与える。', 303501, 0, 1, 303501, 270, 0, 0, 13, 0, 1.8, 1000, 'ムシュフシュ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】吸い続けた他者の魔力で妖術を得た魔物。\\n敵に付けた傷から魔力を奪いさらなる力を求める。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を中アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・バトル開始時、自身にＴＰダウン100%カッ\\n\u3000ト効果を付与する。\\n・ムシュフシュから受けるすべてのダメージで発\\n\u3000生する、パーティキャラのＴＰ回復量を小ダウ\\n\u3000ンさせる。\\n・ユニオンバーストは、最も近い敵１キャラを中\\n\u3000心にした小範囲に毒状態を付与する。さらに敵\\n\u3000全体に物理攻撃力中ダウンと魔法攻撃力大ダウ\\n\u3000ン、ＨＰ吸収特大ダウンを付与する。このスキ\\n\u3000ルにより付与された毒のダメージでは、ＴＰが\\n\u3000回復しない。\\n・最も近い敵１キャラを中心にした小範囲に物理\\n\u3000大ダメージを与える。', 303502, 0, 1, 303502, 270, 0, 0, 13, 0, 1.8, 1000, 'ムシュフシュ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】吸い続けた他者の魔力で妖術を得た魔物。\\n敵に付けた傷から魔力を奪いさらなる力を求める。\\n\\n・ムシュフシュから受けるすべてのダメージで発\\n\u3000生する、パーティキャラのＴＰ回復量を小ダウ\\n\u3000ンさせる。\\n・ユニオンバーストは、最も近い敵１キャラを中\\n\u3000心にした小範囲に毒状態を付与する。さらに敵\\n\u3000全体に物理攻撃力中ダウンと魔法攻撃力大ダウ\\n\u3000ンを付与する。このスキルにより付与された毒\\n\u3000のダメージでは、ＴＰが回復しない。\\n・最も近い敵１キャラを中心にした小範囲に物理\\n\u3000大ダメージを与える。', 303503, 0, 1, 303503, 270, 0, 0, 13, 0, 1.8, 1000, 'ムシュフシュ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【魔法】吸い続けた他者の魔力で妖術を得た魔物。\\n敵に付けた傷から魔力を奪いさらなる力を求める。\\n\\n・ムシュフシュから受けるすべてのダメージで発\\n\u3000生する、パーティキャラのＴＰ回復量を中ダウ\\n\u3000ンさせる。\\n・ユニオンバーストは、最も近い敵１キャラを中\\n\u3000心にした小範囲に毒状態を付与し、さらに敵全\\n\u3000体の物理攻撃力と魔法攻撃力とＨＰ吸収を特大\\n\u3000ダウンさせる。このスキルにより付与された毒\\n\u3000のダメージでは、ＴＰが回復しない。このスキ\\n\u3000ルの状態異常はダメージを無効化しても付与さ\\n\u3000れる。\\n・最も近い敵１キャラを中心にした小範囲に物理\\n\u3000大ダメージを与える。', 303504, 0, 1, 303504, 270, 0, 0, 13, 0, 1.8, 1000, 'ムシュフシュ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】強靭な脚と鋭利なツメで\\n獲物を一瞬で狩る、獰猛な恐竜。\\n滅びた大地でマグマを喰らい、\\n生存の道を見つけた孤高の存在。\\n\\n・敵全体に物理中ダメージを与え、\\n\u3000自分の行動速度を上げる。\\n\\n・前方3キャラに物理中ダメージ\\n\u3000を与え、行動速度を下げる。', 303600, 0, 1, 303600, 270, 0, 0, 13, 0, 1.7, 1000, 'バーンサウルス');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】強靭な脚と鋭利なツメを操る獰猛な恐竜。\\n滅びた大地でマグマを喰らい生きる孤高の存在。\\n\\n・バトル開始時、自身にダメージ上限スキルを使\\n\u3000用し、一度の行動で受けるダメージの値が一定\\n\u3000を超えた場合、ダメージ量を減少させる。\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・ユニオンバーストは、敵全体に物理中ダメージ\\n\u3000を与え、自身の行動速度を大アップさせる。こ\\n\u3000のスキルによるダメージでは、敵のＴＰが回復\\n\u3000しない。\\n・前方３キャラに物理中ダメージを与え、行動速\\n\u3000度を中ダウン。\\n・前方１キャラに物理特大ダメージ。\\n\u3000このスキルによるダメージでは、ＴＰ回復量は\\n\u3000減少する。', 303601, 0, 1, 303601, 270, 0, 0, 13, 0, 1.7, 1000, 'バーンサウルス');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】強靭な脚と鋭利なツメを操る獰猛な恐竜。\\n滅びた大地でマグマを喰らい生きる孤高の存在。\\n\\n・バトル開始時、自身にダメージ上限スキルを使\\n\u3000用し、一度の行動で受けるダメージの値が一定\\n\u3000を超えた場合、ダメージ量を減少させる。\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・バトル開始時、自身の物理攻撃力を大アップ。\\n・ユニオンバーストは、敵全体に物理中ダメージ\\n\u3000を与え、自身の行動速度を大アップさせる。こ\\n\u3000のスキルによるダメージでは、敵のＴＰが回復\\n\u3000しない。\\n・前方３キャラに物理中ダメージを与え、行動速\\n\u3000度を中ダウン。\\n・前方１キャラに物理特大ダメージ。\\n\u3000このスキルによるダメージでは、ＴＰ回復量は\\n\u3000減少する。', 303602, 0, 1, 303602, 270, 0, 0, 13, 0, 1.7, 1000, 'バーンサウルス');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】強靭な脚と鋭利なツメを操る獰猛な恐竜。\\n滅びた大地でマグマを喰らい生きる孤高の存在。\\n\\n・バトル開始時、自身にダメージ上限スキルを使\\n\u3000用し、一度の行動で受けるダメージの値が一定\\n\u3000を超えた場合、ダメージ量を減少させる。\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・バトル開始時、自身の物理攻撃力を大アップ。\\n・ユニオンバーストは、敵全体に物理中ダメージ\\n\u3000を与え、自身の行動速度を大アップさせる。こ\\n\u3000のスキルによるダメージでは、敵のＴＰが回復\\n\u3000しない。\\n・前方３キャラに物理中ダメージを与え、行動速\\n\u3000度を中ダウン。\\n・前方１キャラに物理特大ダメージ。\\n\u3000このスキルによるダメージでは、ＴＰ回復量は\\n\u3000減少する。', 303603, 0, 1, 303603, 270, 0, 0, 13, 0, 1.7, 1000, 'バーンサウルス');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】強靭な脚と鋭利なツメを操る獰猛な恐竜。\\n滅びた大地でマグマを喰らい生きる孤高の存在。\\n\\n・バトル開始時、自身にダメージ上限スキルを使\\n\u3000用し、一度の行動で受けるダメージの値が一定\\n\u3000を超えた場合、ダメージ量を減少させる。\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・バトル開始時、自身の物理攻撃力を大アップ。\\n・ユニオンバーストは、敵全体に物理中ダメージ\\n\u3000を与え、自身の行動速度と物理攻撃力を大アッ\\n\u3000プさせる。このスキルによるダメージでは、敵\\n\u3000のＴＰが回復しない。\\n・前方３キャラに物理中ダメージを与え、行動速\\n\u3000度を中ダウン。\\n・前方１キャラに物理特大ダメージ。\\n\u3000このスキルによるダメージでは、ＴＰ回復量は\\n\u3000減少する。', 303604, 0, 1, 303604, 270, 0, 0, 13, 0, 1.7, 1000, 'バーンサウルス');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】強靭な脚と鋭利なツメを操る獰猛な恐竜。\\n滅びた大地でマグマを喰らい生きる孤高の存在。\\n\\n・バトル開始時、自身にダメージ上限スキルを使\\n\u3000用し、一度の行動で受けるダメージの値が一定\\n\u3000を超えた場合、ダメージ量を減少させる。\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・バトル開始時、敵全体の最大ＨＰを20％減少\\n\u3000させる。\\n・バトル開始時、自身の物理攻撃力を大アップ。\\n・ユニオンバーストは、敵全体に物理中ダメージ\\n\u3000を与え、自身の行動速度と物理攻撃力を大アッ\\n\u3000プさせる。このスキルによるダメージでは、敵\\n\u3000のＴＰが回復しない。\\n・前方３キャラに物理中ダメージを与え、行動速\\n\u3000度を中ダウン。\\n・前方１キャラに物理特大ダメージ。\\n\u3000このスキルによるダメージでは、ＴＰ回復量は\\n\u3000減少する。', 303605, 0, 1, 303605, 270, 0, 0, 13, 0, 1.7, 1000, 'バーンサウルス');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】強靭な脚と鋭利なツメを操る獰猛な恐竜。\\n滅びた大地でマグマを喰らい生きる孤高の存在。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・バーンサウルスから受けるすべてのダメージで\\n\u3000発生する、パーティキャラのＴＰ回復量を中ダ\\n\u3000ウンさせる。\\n・ユニオンバーストは、最も近い敵１キャラを中\\n\u3000心にした中範囲内の敵すべてに物理中ダメージ\\n\u3000を与え、敵全体の行動速度を中ダウンさせ、さ\\n\u3000らに自身の行動速度を大アップさせる。範囲内\\n\u3000の敵の数に応じて、このスキルのダメージがダ\\n\u3000ウンする。このスキルによるダメージではＴＰ\\n\u3000が回復しない。このスキルの効果はダメージを\\n\u3000無効化しても付与される。\\n・最も近い敵１キャラを中心にした中範囲内の敵\\n\u3000すべてに物理小ダメージを与え、物理防御力を\\n\u3000特大ダウンさせる。範囲内の敵の数に応じて、\\n\u3000防御力の減少量がダウンする。このスキルの効\\n\u3000果はダメージを無効化しても付与される。', 303606, 0, 1, 303606, 270, 0, 0, 13, 0, 1.7, 1000, 'バーンサウルス');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】強靭な脚と鋭利なツメを操る獰猛な恐竜。\\n滅びた大地でマグマを喰らい生きる孤高の存在。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を中アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・バトル開始時、敵全体のＨＰ吸収を特大ダウン\\n\u3000させ、ＴＰ上昇を小ダウンさせる。\\n・バトル開始時、自身にＴＰダウン100％カッ\\n\u3000ト効果を付与する。\\n・バーンサウルスから受けるすべてのダメージで\\n\u3000は、パーティキャラのＴＰが回復しない。\\n・ユニオンバーストは、最も近い敵１キャラを中\\n\u3000心にした中範囲内の敵すべてに物理中ダメージ\\n\u3000を与え、敵全体の行動速度を大ダウンさせ、さ\\n\u3000らに自身の行動速度を大アップさせる。範囲内\\n\u3000の敵の数に応じて、このスキルのダメージがダ\\n\u3000ウンする。このスキルによるダメージではＴＰ\\n\u3000が回復しない。このスキルの効果はダメージを\\n\u3000無効化しても付与される。\\n・最も近い敵１キャラを中心にした中範囲内の敵\\n\u3000すべてに物理小ダメージを与え、物理防御力を\\n\u3000特大ダウンさせる。範囲内の敵の数に応じて、\\n\u3000防御力の減少量がダウンする。このスキルの効\\n\u3000果はダメージを無効化しても付与される。', 303607, 0, 1, 303607, 270, 0, 0, 13, 0, 1.7, 1000, 'バーンサウルス');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】強靭な脚と鋭利なツメを操る獰猛な恐竜。\\n滅びた大地でマグマを喰らい生きる孤高の存在。\\n\\n・バーンサウルスから受けるすべてのダメージで\\n\u3000発生する、パーティキャラのＴＰ回復量を大ダ\\n\u3000ウンさせる。\\n・ユニオンバーストは、最も近い敵１キャラを中\\n\u3000心とした範囲に物理特大ダメージを与え、敵全\\n\u3000体の行動速度を大ダウンさせ、さらに自身の行\\n\u3000動速度を特大アップさせる。範囲内の敵の数に\\n\u3000応じて、このスキルのダメージがダウンする。\\n\u3000このスキルによるダメージでは、敵のＴＰが回\\n\u3000復しない。このスキルの状態異常はダメージを\\n\u3000無効化しても付与される。\\n・最も近い敵１キャラを中心にした範囲に物理中\\n\u3000ダメージを与え、さらに物理防御力を大ダウン\\n\u3000させる。範囲内の敵の数に応じて、防御力の減\\n\u3000少量がダウンする。このスキルの状態異常はダ\\n\u3000メージを無効化しても付与される。', 303608, 0, 1, 303608, 270, 0, 0, 13, 0, 1.7, 1000, 'バーンサウルス');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】火山に身を落としてなお\\n地獄の炎を纏い蘇った双頭の魔犬。\\n愛犬ボニーと共に縄張りを駆け、\\n侵入者には灼熱の洗礼を浴びせる。\\n\\n・敵全体に物理中ダメージを与え、\\n\u3000火傷状態にする。さらに、召喚\\n\u3000モンスターのＨＰを回復する。\\n\\n・ボニーを召喚する。', 303700, 0, 1, 303700, 270, 0, 0, 14, 0, 0.7, 1000, 'ヘルハウンド');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】塔の魔力で、魔界の炎を顕現させる魔狼。\\n灼熱の地で、相棒のボニーとともに待ち受ける。\\n\\n・敵全体に物理大ダメージを与え火傷状態にする。\\n\u3000さらに、ボニーのHPを回復する。\\n・ボニーを召喚する。\\n・敵全体に物理中ダメージを与え、行動速度をダ\\n\u3000ウンさせる。さらに、味方全体の物理攻撃力を\\n\u3000大アップさせる。', 303701, 0, 1, 303701, 270, 0, 0, 14, 0, 0.7, 1000, 'バーンウルフ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】はるか古より迷宮を守護する防衛兵器。すべての罠を超えた最奥で侵入者を静かに待つ。\\n・敵全体にキャラの最大ＨＰに応じた\\n\u3000魔法中ダメージを与える。\\n・前方範囲内の敵に物理中ダメージを与える。', 303800, 0, 1, 303800, 270, 0, 0, 16, 0, 2.0, 1000, 'アルマ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】はるか古より迷宮を守護する防衛兵器。すべての罠を超えた最奥で侵入者を静かに待つ。\\n・敵全体にキャラの最大ＨＰに応じた\\n\u3000魔法特大ダメージを与える。\\n・前方範囲内の敵に物理中ダメージを与える。\\n・残りＨＰの高い敵に対して最大ＨＰに応じた\\n\u3000魔法中ダメージを与えさらにスタンさせる。\\n・アルマ自身のＨＰが50％を切ると、さらに\\n\u3000攻撃が激しく凶暴になる。', 303801, 0, 1, 303800, 270, 0, 0, 16, 0, 2.0, 1000, 'アルマ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】怪力が自慢の、凶暴な一つ目巨人。\\n瞳に魔力をみなぎらせ、強力な怪光線を放つ。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・サイクロプスから受けるすべてのダメージで発\\n\u3000生する、パーティキャラのＴＰ回復量を中ダウ\\n\u3000ンさせる。\\n・ユニオンバーストは、飛行状態のキャラを含む\\n\u3000敵全体にキャラの最大ＨＰに応じた魔法割合ダ\\n\u3000メージを与え、ＴＰを小ダウンさせ、ステータ\\n\u3000スアップ効果を解除する。さらに、バトル終了\\n\u3000まで物理攻撃力を大ダウン、魔法攻撃力を中ダ\\n\u3000ウンさせる。このスキルの状態異常はダメージ\\n\u3000を無効化しても付与される。このスキルはダ\\n\u3000メージを無効化してもＴＰをダウンさせる。\\n・物理攻撃力もしくは魔法攻撃力が最も高い敵１\\n\u3000キャラを中心にした小範囲に物理特大ダメージ\\n\u3000を与え、スタン状態を付与する。このスキルに\\n\u3000よるダメージでは、ＴＰが回復しない。このス\\n\u3000キルの状態異常はダメージを無効化しても付与\\n\u3000される。', 303900, 0, 1, 303900, 270, 0, 0, 13, 0, 2.0, 1000, 'サイクロプス');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】怪力が自慢の、凶暴な一つ目巨人。\\n瞳に魔力をみなぎらせ、強力な怪光線を放つ。\\n\\n・敵全体に魔法大ダメージ。\\n\u3000残りＨＰが１００％のキャラにはダメージが\\n\u3000アップし、さらに行動速度をダウンさせる。\\n・最も物理攻撃力が高い１キャラに、最大ＨＰ\\n\u3000に応じた物理中ダメージを与え、ＴＰダウン。', 303901, 0, 1, 303901, 270, 0, 0, 13, 0, 2.0, 1000, 'サイクロプス');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】怪力が自慢の、凶暴な一つ目巨人。\\n瞳に魔力をみなぎらせ、強力な怪光線を放つ。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を中アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・バトル開始時、敵全体のＨＰ吸収を特大ダウン\\n\u3000させる。 \\n・バトル開始時、敵全体のＴＰ上昇を小ダウンさ\\n\u3000せるフィールドを展開する。\\n・バトル開始時、自身にＴＰダウン25％カット\\n\u3000効果を付与する。\\n・サイクロプスから受けるすべてのダメージで発\\n\u3000生する、パーティキャラのＴＰ回復量を中ダウ\\n\u3000ンさせる。\\n・ユニオンバーストは、飛行状態のキャラを含む\\n\u3000敵全体にキャラの最大ＨＰに応じた魔法割合ダ\\n\u3000メージを与え、ＴＰを中ダウンさせ、ステータ\\n\u3000スアップ効果を解除する。さらに、バトル終了\\n\u3000まで物理攻撃力を大ダウン、魔法攻撃力を中ダ\\n\u3000ウンさせる。このスキルの状態異常はダメージ\\n\u3000を無効化しても付与される。このスキルはダ\\n\u3000メージを無効化してもＴＰをダウンさせる。\\n・物理攻撃力もしくは魔法攻撃力が最も高い敵１\\n\u3000キャラを中心にした小範囲に物理特大ダメージ\\n\u3000を与え、スタン状態を付与する。このスキルに\\n\u3000よるダメージでは、ＴＰが回復しない。このス\\n\u3000キルの状態異常はダメージを無効化しても付与\\n\u3000される。\\n・通常攻撃によるダメージでは、ＴＰ回復量が特\\n\u3000大ダウンする。', 303902, 0, 1, 303902, 270, 0, 0, 13, 0, 2.0, 1000, 'サイクロプス');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】砂塵の中、山のように佇\\nむ一つ目の巨人。単眼から超強力\\nな光線を発し冒険者を薙ぎ払う。\\n\\n・ユニオンバーストは、敵全体に\\n\u3000魔法大ダメージを与え、さらに\\n\u3000行動速度を中ダウンさせる。\\n\u3000残りＨＰが100％のキャラ\\n\u3000には、ダメージがアップする。\\n\\n・最も物理攻撃力が高い１キャラ\\n\u3000に、最大ＨＰに応じた物理割合\\n\u3000ダメージを与え、さらにＴＰを\\n\u3000大ダウンさせる。', 303903, 0, 1, 303903, 270, 0, 0, 13, 0, 2.0, 1000, 'ヒトツメ巨人');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】怪力が自慢の、凶暴な一つ目巨人。\\n瞳に魔力をみなぎらせ、強力な怪光線を放つ。\\n\\n・サイクロプスから受けるすべてのダメージで発\\n\u3000生する、パーティキャラのＴＰ回復量を中ダウ\\n\u3000ンさせる。\\n・ユニオンバーストは、敵全体にキャラの最大Ｈ\\n\u3000Ｐに応じた魔法割合ダメージを与え、物理攻撃\\n\u3000力を大ダウン、魔法攻撃力を中ダウン、ＴＰを\\n\u3000大ダウンさせ、ステータスアップ効果を解除す\\n\u3000る。このスキルの状態異常はダメージを無効化\\n\u3000しても付与される。\\n・挑発を無視して、物理攻撃力もしくは魔法攻撃\\n\u3000力が最も高い敵１キャラを中心とした小範囲に\\n\u3000物理大ダメージを与え、スタン状態を付与し、\\n\u3000行動速度を中ダウンさせる。このスキルによる\\n\u3000ダメージでは、キャラのＴＰが回復しない。こ\\n\u3000のスキルの状態異常はダメージを無効化しても\\n\u3000付与される。', 303904, 0, 1, 303904, 270, 0, 0, 13, 0, 2.0, 3000, 'サイクロプス');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】夢幻より生まれ、闇を彷徨う魔獣。\\n悪夢の牢に獲物を縛り、旨そうに生気を喰う。\\n\\n・挑発効果の影響を受けやすい。\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・ムーバから受けるすべてのダメージで発生する、\\n\u3000パーティキャラのＴＰ回復量を中ダウンさせる。\\n・ユニオンバーストは、物理攻撃力もしくは魔法\\n\u3000攻撃力が最も高い敵１キャラに魔法特大ダメー\\n\u3000ジを与え、ＴＰを特大ダウンさせる。このスキ\\n\u3000ルはダメージを無効化してもＴＰをダウンさせ\\n\u3000る。\\n・敵の挑発を無視して、最も遠い敵１キャラを中\\n\u3000心にした小範囲内の敵すべてに呪い状態を付与\\n\u3000する。このスキルにより付与された呪いのダ\\n\u3000メージでは、ＴＰが回復しない。', 304000, 0, 1, 304000, 270, 0, 0, 13, 0, 2.0, 1000, 'ムーバ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】夢幻より生まれ、闇を彷徨う魔獣。\\n悪夢の牢に獲物を縛り、旨そうに生気を喰う。\\n\\n・挑発効果の影響を受けやすい。\\n・バトル開始時、自身の物理防御力を大アップさ\\n\u3000せ、魔法防御力を中アップさせる。この防御力\\n\u3000アップ効果で上昇した防御力は、バトル中に受\\n\u3000ける防御力ダウンスキルの影響を受けない。\\n・バトル開始時、敵全体のＨＰ吸収を特大ダウン\\n\u3000させる。\\n・バトル開始時、敵全体のＴＰ上昇を小ダウンさ\\n\u3000せるフィールドを展開する。\\n・バトル開始時、自身にＴＰダウン100％カッ\\n\u3000ト効果を付与する。\\n・ムーバから受けるすべてのダメージで発生する、\\n\u3000パーティキャラのＴＰ回復量を中ダウンさせる。\\n・ユニオンバーストは、物理攻撃力もしくは魔法\\n\u3000攻撃力が最も高い敵１キャラのステータスアッ\\n\u3000プ効果を解除した後、魔法特大ダメージを与え、\\n\u3000ＴＰを特大ダウンさせる。このスキルはダメー\\n\u3000ジを無効化してもＴＰをダウンさせる。\\n・敵の挑発を無視して、最も遠い敵１キャラを中\\n\u3000心にした小範囲内の敵すべてのＴＰを小ダウン\\n\u3000させ、呪い状態を付与する。このスキルにより\\n\u3000付与された呪いのダメージでは、ＴＰが回復し\\n\u3000ない。', 304001, 0, 1, 304001, 270, 0, 0, 13, 0, 2.0, 1000, 'ムーバ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】夢幻より生まれ、闇を彷徨う魔獣。\\n悪夢の牢に獲物を縛り、旨そうに生気を喰う。\\n\\n・ムーバから受けるすべてのダメージで発生する、\\n\u3000パーティキャラのＴＰ回復量を中ダウンさせる。\\n・ユニオンバーストは、物理攻撃力もしくは魔法\\n\u3000攻撃力が最も高い敵１キャラのステータスアッ\\n\u3000プ効果を解除した後、魔法特大ダメージを与え、\\n\u3000ＴＰを特大ダウンさせる。\\n・敵の挑発を無視して、最も遠い敵１キャラを中\\n\u3000心にした小範囲内の敵すべてのＴＰを小ダウン\\n\u3000させ、呪い状態を付与する。このスキルにより\\n\u3000付与された呪いのダメージでは、ＴＰが回復し\\n\u3000ない。\\n・通常攻撃は、物理攻撃力もしくは魔法攻撃力が\\n\u3000最も高い敵１キャラに物理大ダメージを与える。\\n', 304002, 0, 1, 304002, 270, 0, 0, 13, 0, 2.0, 1000, 'ムーバ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('甲羅に大樹が根ざすほどの、老大な陸ガメ。\\n敵の攻撃を耐え続け、憤怒の反撃を見舞う。\\n\\n・敵全体に物理大ダメージを与える。\\n・甲羅にこもっている間に受けたダメージ量に\\n\u3000応じた物理ダメージを与える。', 304100, 0, 1, 304100, 270, 0, 0, 13, 0, 2.5, 1000, 'ティタノタートル');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】甲羅に大樹が根ざすほどの老大な陸ガメ。\\n敵の攻撃を耐え続け、憤怒の反撃を見舞う。\\n\\n・物理攻撃力ダウン効果の影響を受けやすい。\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・ティタノタートルから受けるすべてのダメージ\\n\u3000で発生する、パーティキャラのＴＰ回復量を中\\n\u3000ダウンさせる。\\n・ユニオンバーストは、敵全体に物理大ダメージ\\n\u3000を与える。このスキルによるダメージでは、\\n\u3000ＴＰが回復しない。\\n・甲羅にこもっている間に自身の物理防御力と魔\\n\u3000法防御力を特大アップする。その後、敵全体に\\n\u3000自身の物理攻撃力に応じた物理ダメージを与え\\n\u3000る。このスキルによるダメージでは、ＴＰが回\\n\u3000復しない。\\n・全ターゲットがブレイクされると、一定時間行\\n\u3000動不能になる。行動不能の間、自身の物理防御\\n\u3000力と魔法防御力を中ダウンさせ、ブレイクされ\\n\u3000なくなる。', 304101, 0, 1, 304101, 270, 0, 0, 13, 0, 0.1, 1000, 'ティタノタートル');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】甲羅に大樹が根ざすほどの老大な陸ガメ。\\n敵の攻撃を耐え続け、憤怒の反撃を見舞う。\\n\\n・物理攻撃力ダウン効果の影響を受けやすい。\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を中アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・バトル開始時、敵全体のＨＰ吸収を特大ダウン\\n\u3000させ、ＴＰ上昇を小ダウンさせる。\\n・バトル開始時、自身にＴＰダウン100％カッ\\n\u3000ト効果を付与する。\\n・ティタノタートルから受けるすべてのダメージ\\n\u3000では、パーティキャラのＴＰが回復しない。\\n・ユニオンバーストは、敵全体に物理大ダメージ\\n\u3000を与え、物理攻撃力と魔法攻撃力を大ダウンさ\\n\u3000せる。このスキルの状態異常はダメージを無効\\n\u3000化しても付与される。\\n・甲羅にこもっている間に自身の物理防御力と魔\\n\u3000法防御力を特大アップする。その後、飛行状態\\n\u3000のキャラを含む敵全体に自身の物理攻撃力に応\\n\u3000じた物理固定ダメージを与える。\\n・全ターゲットがブレイクされると、一定時間行\\n\u3000動不能になる。行動不能の間、自身のクリティ\\n\u3000カルを受けた際のダメージを特大アップさせ、\\n\u3000ブレイクされなくなる。', 304102, 0, 1, 304102, 270, 0, 0, 13, 0, 0.1, 1000, 'ティタノタートル');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】甲羅に大樹が根ざすほどの老大な陸ガメ。\\n敵の攻撃を耐え続け、憤怒の反撃を見舞う。\\n\\n・ティタノタートルから受けるすべてのダメージ\\n\u3000では、パーティキャラのＴＰが回復しない。\\n・ユニオンバーストは、敵全体に物理中ダメージ\\n\u3000を与え、行動速度を大ダウンさせる。このスキ\\n\u3000ルの状態異常はダメージを無効化しても付与さ\\n\u3000れる。\\n・甲羅にこもっている間に自身の物理防御力と魔\\n\u3000法防御力を特大アップする。その後、飛行状態\\n\u3000のキャラを含む敵全体に物理特大ダメージを与\\n\u3000える。\\n・全ターゲットがブレイクされると、一定時間行\\n\u3000動不能になる。行動不能の間、自身の物理防御\\n\u3000力と魔法防御力を大ダウンさせ、ブレイクされ\\n\u3000なくなる。', 304103, 0, 1, 304103, 270, 0, 0, 13, 0, 0.1, 1000, 'ティタノタートル');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】屍肉を喰らう凶暴な大型魔獣。\\n強固な棘を全身に纏い獲物を執念深くつけ狙う。\\n・敵全体にキャラの最大ＨＰに応じた\\n\u3000物理中ダメージを与える。\\n・後方範囲内に物理中ダメージを与えさらに\\n\u3000スタンさせる。', 304200, 0, 1, 304200, 270, 0, 0, 16, 0, 1.8, 1000, 'ガルグ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】屍肉を喰らう凶暴な大型魔獣。\\n強固な棘を全身に纏い獲物を執念深くつけ狙う。\\n・敵全体にキャラの最大ＨＰに応じた\\n\u3000物理中ダメージを与える。\\n・後方範囲内に物理中ダメージを与えさらに\\n\u3000スタンさせる。\\n・前方２番目の敵に物理中ダメージを与える。\\n・ガルグ自身のＨＰが50％を切ると、さらに\\n\u3000攻撃が激しく凶暴になる。', 304201, 0, 1, 304200, 270, 0, 0, 16, 0, 1.8, 1000, 'ガルグ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】海辺に君臨する巨大な軟体魔獣。\\n強靭な触手と鋼鉄の大銛で全てを破壊しつくす。\\n・敵全体にキャラの最大ＨＰに応じた\\n\u3000物理大ダメージを与える。\\n・後方範囲内に魔法中ダメージを与え、\\n\u3000麻痺状態を付与、さらに物理攻撃力、\\n\u3000魔法攻撃力を特大ダウン。\\n・一定時間経過すると敵単体に\\n\u3000物理超特大ダメージを与える。\\n・テンタパス自身のＨＰが40％を切ると、\\n\u3000さらに攻撃が激しく凶暴になる。', 304300, 0, 1, 304300, 270, 0, 0, 16, 0, 1.8, 1000, 'テンタパス');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】海辺に君臨する巨大な軟体魔獣。\\n強靭な触手と鋼鉄の大銛で全てを破壊しつくす。\\n・敵全体にキャラの最大ＨＰに応じた\\n\u3000物理大ダメージを与える。\\n・後方範囲内に魔法中ダメージを与え、\\n\u3000麻痺状態を付与、さらに物理攻撃力、\\n\u3000魔法攻撃力を特大ダウン。', 304301, 0, 1, 304300, 270, 0, 0, 16, 0, 1.8, 1000, 'テンタパス');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】海辺に君臨する巨大な軟体魔獣。\\n強靭な触手と鋼鉄の大銛で全てを破壊しつくす。\\n・敵全体にキャラの最大ＨＰに応じた\\n\u3000物理大ダメージを与える。\\n・後方範囲内に魔法中ダメージを与え、\\n\u3000麻痺状態を付与、さらに物理攻撃力、\\n\u3000魔法攻撃力を特大ダウン。\\n・テンタパス自身のＨＰが40％を切ると、\\n\u3000さらに攻撃が激しく凶暴になる。', 304302, 0, 1, 304300, 270, 0, 0, 16, 0, 1.8, 1000, 'テンタパス');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】海辺に君臨する巨大な軟体魔獣。\\n強靭な触手と鋼鉄の大銛で全てを破壊しつくす。\\n・敵全体にキャラの最大ＨＰに応じた\\n\u3000物理大ダメージを与える。\\n・後方範囲内に魔法中ダメージを与え、\\n\u3000麻痺状態を付与、さらに物理攻撃力、\\n\u3000魔法攻撃力を特大ダウン。\\n・一定時間経過すると敵単体に\\n\u3000物理超特大ダメージを与える。\\n・テンタパス自身のＨＰが40％を切ると、\\n\u3000さらに攻撃が激しく凶暴になる。', 304303, 0, 1, 304300, 270, 0, 0, 16, 0, 1.8, 1000, 'テンタパス');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】塔の力で人間に復讐を目論む、軟体魔獣。\\n若かりし頃に刺された銛の恨みは、海よりも深い。\\n\\n・敵全体に物理大ダメージを与える。\\n・前から３番目以降の敵に魔法中ダメージを与え、\\n\u3000物理防御力と行動速度を中ダウン。\\n\u3000さらに、ステータスアップ効果を解除する。\\n・残りＨＰの最も高い敵に、残りＨＰに応じた\\n\u3000物理大ダメージを与え、ＴＰを中ダウン。', 304304, 0, 1, 304304, 270, 0, 0, 16, 0, 1.6, 1000, 'オクタスキッド');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】数多の探検家を飲み込んだ幻島の巨鯨。欲望、幻想に憑りつかれた愚者を無慈悲に葬る。\\n\\n・敵全体にキャラの最大ＨＰに応じた\\n\u3000物理大ダメージを与える。\\n・敵全体に魔法中ダメージを与え、\\n\u3000さらに島クジラ自身の物理防御力、\\n\u3000魔法防御力を極大アップ。\\n・前から３キャラに魔法大ダメージを与え、\\n\u3000さらに大きく吹き飛ばす。\\n・島クジラ自身のＨＰが40％を切ると、\\n\u3000さらに攻撃が激しく凶暴になる。', 304400, 0, 1, 304400, 270, 0, 0, 16, 0, 1.8, 1000, '島クジラ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】数多の探検家を飲み込んだ幻島の巨鯨。欲望、幻想に憑りつかれた愚者を無慈悲に葬る。\\n\\n・敵全体にキャラの最大ＨＰに応じた\\n\u3000物理大ダメージを与える。\\n・敵全体に魔法中ダメージを与え、\\n\u3000さらに島クジラ自身の物理防御力、\\n\u3000魔法防御力を極大アップ。', 304401, 0, 1, 304400, 270, 0, 0, 16, 0, 1.8, 1000, '島クジラ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】数多の探検家を飲み込んだ幻島の巨鯨。欲望、幻想に憑りつかれた愚者を無慈悲に葬る。\\n\\n・敵全体にキャラの最大ＨＰに応じた\\n\u3000物理大ダメージを与える。\\n・敵全体に魔法中ダメージを与え、\\n\u3000さらに島クジラ自身の物理防御力、\\n\u3000魔法防御力を極大アップ。\\n・前から３キャラに魔法大ダメージを与え、\\n\u3000さらに大きく吹き飛ばす。\\n・島クジラ自身のＨＰが40％を切ると、\\n\u3000さらに攻撃が激しく凶暴になる。', 304402, 0, 1, 304400, 270, 0, 0, 16, 0, 1.8, 1000, '島クジラ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】数多の探検家を飲み込んだ幻島の巨鯨。欲望、幻想に憑りつかれた愚者を無慈悲に葬る。\\n\\n・敵全体にキャラの最大ＨＰに応じた\\n\u3000物理大ダメージを与える。\\n・敵全体に魔法中ダメージを与え、\\n\u3000さらに島クジラ自身の物理防御力、\\n\u3000魔法防御力を極大アップ。\\n・前から３キャラに魔法大ダメージを与え、\\n\u3000さらに大きく吹き飛ばす。\\n・島クジラ自身のＨＰが40％を切ると、\\n\u3000さらに攻撃が激しく凶暴になる。', 304403, 0, 1, 304400, 270, 0, 0, 16, 0, 1.8, 1000, '島クジラ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】熟練の戦闘術で翻弄するクワガタの魔物。\\n豪雷を纏う技のキレに、シビれる者が続出。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・ライデンから受けるすべてのダメージで発生す\\n\u3000る、パーティキャラのＴＰ回復量を中ダウンさ\\n\u3000せる。\\n・ユニオンバーストは、最も近い敵１キャラに物\\n\u3000理特大ダメージを与える。さらに敵全体に麻痺\\n\u3000状態を付与し、物理攻撃力と魔法攻撃力を中ダ\\n\u3000ウンさせる。このスキルの状態異常はダメージ\\n\u3000を無効化しても付与される。\\n・丸太状態になっている間、自身の物理防御力と\\n\u3000魔法防御力を特大アップさせる。さらに丸太状\\n\u3000態が解除された後、自身の物理防御力と魔法防\\n\u3000御力を短時間大ダウンさせる。', 304500, 0, 1, 304500, 270, 0, 0, 16, 0, 1.8, 3000, 'ライデン');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】熟練の戦闘術で翻弄するクワガタの魔物。\\n豪雷を纏う技のキレに、シビれる者が続出。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を中アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・バトル開始時、敵全体のＴＰ上昇を小ダウンさ\\n\u3000せるフィールドを展開する。\\n・バトル開始時、自身にＴＰダウン50％カット\\n\u3000効果を付与する。\\n・ライデンから受けるすべてのダメージで発生す\\n\u3000る、パーティキャラのＴＰ回復量を中ダウンさ\\n\u3000せる。\\n・敵から受けるすべてのダメージで発生する、ラ\\n\u3000イデンのＴＰ回復量が大ダウンする。\\n・ユニオンバーストは、最も近い敵１キャラに物\\n\u3000理特大ダメージを与える。さらに敵全体に麻痺\\n\u3000状態を付与し、物理攻撃力と魔法攻撃力を中ダ\\n\u3000ウンさせる。このスキルの状態異常はダメージ\\n\u3000を無効化しても付与される。\\n・丸太状態になっている間、自身の物理防御力と\\n\u3000魔法防御力を特大アップさせる。さらに丸太状\\n\u3000態が解除された後、自身の物理防御力と魔法防\\n\u3000御力を短時間特大ダウンさせる。', 304501, 0, 1, 304501, 270, 0, 0, 16, 0, 1.8, 3000, 'ライデン');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】熟練の戦闘術で翻弄するクワガタの魔物。\\n豪雷を纏う技のキレに、シビれる者が続出。\\n\\n・ライデンから受けるすべてのダメージで発生す\\n\u3000る、パーティキャラのＴＰ回復量を中ダウンさ\\n\u3000せる。\\n・ユニオンバーストは、最も近い敵１キャラに物\\n\u3000理特大ダメージを与える。さらに敵全体に麻痺\\n\u3000状態を付与し、物理攻撃力と魔法攻撃力を中ダ\\n\u3000ウンさせる。このスキルの状態異常はダメージ\\n\u3000を無効化しても付与される。\\n・丸太状態になっている間、自身の物理防御力と\\n\u3000魔法防御力を特大アップさせる。さらに丸太状\\n\u3000態が解除された後、自身の物理防御力と魔法防\\n\u3000御力を短時間特大ダウンさせる。', 304502, 0, 1, 304502, 270, 0, 0, 16, 0, 1.8, 3000, 'ライデン');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【魔法】雷雲を従え、無邪気に暴れるカミナリ娘。\\n油断すると、加減知らずの雷撃を見舞われる。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・ライライから受けるすべてのダメージで発生す\\n\u3000る、パーティキャラのＴＰ回復量を中ダウンさ\\n\u3000せる。\\n・ユニオンバーストは、敵全体に魔法大ダメージ\\n\u3000を与える。\\n・最も遠い敵２キャラに魔法中ダメージを与える。', 304600, 0, 2, 304600, 270, 0, 0, 16, 0, 1.8, 3000, 'ライライ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【魔法】雷雲を従え、無邪気に暴れるカミナリ娘。\\n油断すると、加減知らずの雷撃を見舞われる。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を中アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・バトル開始時、敵全体のＨＰ吸収を特大ダウン\\n\u3000させ、ＴＰ上昇を小ダウンさせる。\\n・バトル開始時、自身にＴＰダウン25％カット\\n\u3000効果を付与する。\\n・ライライから受けるすべてのダメージで発生す\\n\u3000る、パーティキャラのＴＰ回復量を中ダウンさ\\n\u3000せる。\\n・ユニオンバーストは、敵全体に魔法大ダメージ\\n\u3000を与え、さらにスタン状態を付与する。このス\\n\u3000キルの状態異常はダメージを無効化しても付与\\n\u3000される。\\n・最も遠い敵２キャラに魔法中ダメージを与え、\\n\u3000ＴＰ上昇を大ダウンさせ、ＴＰを小ダウンさせ\\n\u3000る。このスキルの状態異常はダメージを無効化\\n\u3000しても付与される。このスキルはダメージを無\\n\u3000効化してもＴＰをダウンさせる。\\n・最も遠い敵２キャラに魔法中ダメージを与え、\\n\u3000さらに物理攻撃力と魔法攻撃力を特大ダウンさ\\n\u3000せる。このスキルの効果はダメージを無効化し\\n\u3000ても付与される。', 304601, 0, 2, 304601, 270, 0, 0, 16, 0, 1.8, 3000, 'ライライ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【魔法】雷雲を従え、無邪気に暴れるカミナリ娘。\\n油断すると、加減知らずの雷撃を見舞われる。\\n\\n・敵全体に魔法中ダメージ。\\n・後方２キャラの敵に魔法小ダメージ。', 304602, 0, 2, 304602, 270, 0, 0, 16, 0, 1.8, 1000, 'ライライ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【魔法】雷雲を従え、無邪気に暴れるカミナリ娘。\\n油断すると、加減知らずの雷撃を見舞われる。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・ライライから受けるすべてのダメージで発生す\\n\u3000る、パーティキャラのＴＰ回復量を小ダウンさ\\n\u3000せる。\\n・ユニオンバーストは、敵全体に魔法中ダメージ\\n\u3000を与え、さらにスタンさせる。このスキルの状\\n\u3000態異常はダメージを無効化しても付与される。\\n・後方２キャラに魔法中ダメージを与え、さらに\\n\u3000ＴＰを小ダウン。このスキルはダメージを無効\\n\u3000化してもＴＰをダウンさせる。\\n・後方２キャラに魔法中ダメージを与え、さらに\\n\u3000物理攻撃力と魔法攻撃力を中ダウン。このスキ\\n\u3000ルの状態異常はダメージを無効化しても付与さ\\n\u3000れる。', 304603, 0, 2, 304603, 270, 0, 0, 16, 0, 1.8, 3000, 'ライライ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【魔法】雷雲を従え、無邪気に暴れるカミナリ娘。\\n油断すると、加減知らずの雷撃を見舞われる。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・バトル開始時、味方全体の物理防御力と魔法防\\n\u3000御力を特大アップ。\\n・ライライから受けるすべてのダメージで発生す\\n\u3000る、パーティキャラのＴＰ回復量を小ダウンさ\\n\u3000せる。\\n・ユニオンバーストは、敵全体に魔法中ダメージ\\n\u3000を与え、さらにスタンさせる。このスキルの状\\n\u3000態異常はダメージを無効化しても付与される。\\n・後方２キャラに魔法中ダメージを与え、さらに\\n\u3000ＴＰを小ダウン。このスキルはダメージを無効\\n\u3000化してもＴＰをダウンさせる。\\n・後方２キャラに魔法中ダメージを与え、さらに\\n\u3000物理攻撃力と魔法攻撃力を中ダウン。このスキ\\n\u3000ルの状態異常はダメージを無効化しても付与さ\\n\u3000れる。', 304604, 0, 2, 304604, 270, 0, 0, 16, 0, 1.8, 3000, 'ライライ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【魔法】雷雲を従え、無邪気に暴れるカミナリ娘。\\n油断すると、加減知らずの雷撃を見舞われる。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を中アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・ライライから受けるすべてのダメージで発生す\\n\u3000る、パーティキャラのＴＰ回復量を小ダウンさ\\n\u3000せる。\\n・ユニオンバーストは、敵全体に魔法中ダメージ\\n\u3000を与え、さらにスタン状態を付与する。このス\\n\u3000キルの状態異常はダメージを無効化しても付与\\n\u3000される。\\n・後方２キャラに魔法中ダメージを与え、さらに\\n\u3000ＴＰを小ダウンさせる。このスキルはダメージ\\n\u3000を無効化してもＴＰをダウンさせる。\\n・後方２キャラに魔法中ダメージを与え、さらに\\n\u3000物理攻撃力と魔法攻撃力を大ダウンさせる。こ\\n\u3000のスキルの状態異常はダメージを無効化しても\\n\u3000付与される。', 304605, 0, 2, 304605, 270, 0, 0, 16, 0, 1.8, 3000, 'ライライ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【魔法】雷雲を従え、無邪気に暴れるカミナリ娘。\\n油断すると、加減知らずの雷撃を見舞われる。\\n\\n・ライライから受けるすべてのダメージで発生す\\n\u3000る、パーティキャラのＴＰ回復量を中ダウンさ\\n\u3000せる。\\n・ユニオンバーストは、敵全体に魔法大ダメージ\\n\u3000を与え、さらにスタン状態を付与する。このス\\n\u3000キルの状態異常はダメージを無効化しても付与\\n\u3000される。\\n・最も遠い敵２キャラに魔法中ダメージを与え、\\n\u3000ＴＰを小ダウンさせる。このスキルはダメージ\\n\u3000を無効化してもＴＰをダウンさせる。\\n・最も遠い敵２キャラに魔法中ダメージを与え、\\n\u3000さらに物理攻撃力と魔法攻撃力を特大ダウンさ\\n\u3000せる。このスキルの状態異常はダメージを無効\\n\u3000化しても付与される。', 304606, 0, 2, 304606, 270, 0, 0, 16, 0, 1.8, 3000, 'ライライ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】金属を喰らい、武具を操る謎の魔物。\\n増殖融合し超大な怪物となり、平和を脅かす。\\n・敵全体にキャラの最大ＨＰに応じた\\n\u3000物理大ダメージを与え、物理攻撃力と。\\n\u3000物理防御力を大ダウン。\\n・前方範囲内に物理大ダメージを与える。\\n・ＴＰの高い敵3キャラのＴＰを減少させ、\\n\u3000自身の物理攻撃力を大アップ。\\n・リビングメイル自身のＨＰが40％を切ると、\u3000さらに攻撃が激しく凶暴になる。', 304700, 0, 1, 304700, 270, 0, 0, 16, 0, 0.8, 1000, 'リビングメイル');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】金属を喰らい、武具を操る謎の魔物。\\n増殖融合し超大な怪物となり、平和を脅かす。\\n・敵全体にキャラの最大ＨＰに応じた\\n\u3000物理大ダメージを与え、物理攻撃力と\\n\u3000物理防御力を大ダウン。\\n・前方範囲内に物理大ダメージを与える。', 304701, 0, 1, 304700, 270, 0, 0, 16, 0, 0.8, 1000, 'リビングメイル');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】金属を喰らい、武具を操る謎の魔物。\\n増殖融合し超大な怪物となり、平和を脅かす。\\n・敵全体にキャラの最大ＨＰに応じた\\n\u3000物理大ダメージを与え、物理攻撃力と\\n\u3000物理防御力を大ダウン。\\n・前方範囲内に物理大ダメージを与える。\\n・残りＨＰの割合が多い敵3キャラのＴＰを\\n\u3000減少させ、自身の物理攻撃力を大アップ。\\n・リビングメイル自身のＨＰが40％を切ると、\u3000さらに攻撃が激しく凶暴になる。', 304702, 0, 1, 304700, 270, 0, 0, 16, 0, 0.8, 1000, 'リビングメイル');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】金属を喰らい、武具を操る謎の魔物。\\n増殖融合し超大な怪物となり、平和を脅かす。\\n・敵全体にキャラの最大ＨＰに応じた\\n\u3000物理大ダメージを与え、物理攻撃力と\\n\u3000物理防御力を大ダウン。\\n・前方範囲内に物理大ダメージを与える。\\n・残りＨＰの割合が多い敵3キャラのＴＰを\\n\u3000減少させ、自身の物理攻撃力を大アップ。\\n・リビングメイル自身のＨＰが40％を切ると、\u3000さらに攻撃が激しく凶暴になる。', 304703, 0, 1, 304700, 270, 0, 0, 16, 0, 0.8, 1000, 'リビングメイル');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】ルナの塔の魔力を喰らい、増殖融合を\\n続ける謎の魔物。すべてを無差別に圧し潰す。\\n\\n・敵全体に物理大ダメージを与え、\\n\u3000さらに物理防御力を中ダウン。\\n・前方範囲内の敵に物理ダメージを与え、\\n\u3000そのうち物理攻撃力の高い2キャラの\\n\u3000物理攻撃力を特大ダウンさせ、さらに\\n\u3000ＴＰを特大ダウン。\\n\u3000自分の物理防御力を大ダウン。\\n・前から3キャラに物理中ダメージを与え、\\n\u3000自分の物理攻撃力を中アップ。', 304704, 0, 1, 304704, 270, 0, 0, 16, 0, 1.8, 1000, '壊乱の黒鎧騎士');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】金属を喰らい、武具を操る謎の魔物。\\n増殖融合し超大な怪物となり、平和を脅かす。\\n\\n・ユニオンバーストは、敵全体にキャラの\\n\u3000最大ＨＰに応じた物理大ダメージを与え、\\n\u3000物理攻撃力と物理防御力を大ダウン。\\n・前から３キャラに物理大ダメージを与える。\\n・ＴＰの高い敵３キャラのＴＰを減少させ、\\n\u3000自身の物理攻撃力を大アップ。\\n・リビングメイル自身のＨＰが40％を切ると、\u3000さらに攻撃が激しく凶暴になる。', 304705, 0, 1, 304705, 270, 0, 0, 16, 0, 0.8, 1000, 'リビングメイル');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】金属を喰らい、武具を操る謎の魔物。\\n増殖融合し超大な怪物となり、平和を脅かす。\\n\\n・ユニオンバーストは、敵全体にキャラの\\n\u3000最大ＨＰに応じた物理大ダメージを与え、\\n\u3000物理攻撃力と物理防御力を大ダウン。\\n・前から３キャラに物理大ダメージを与える。', 304706, 0, 1, 304705, 270, 0, 0, 16, 0, 0.8, 1000, 'リビングメイル');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】金属を喰らい、武具を操る謎の魔物。\\n増殖融合し超大な怪物となり、平和を脅かす。\\n\\n・ユニオンバーストは、敵全体にキャラの\\n\u3000最大ＨＰに応じた物理大ダメージを与え、\\n\u3000物理攻撃力と物理防御力を大ダウン。\\n・残りＨＰの割合が多い敵３キャラのＴＰを\\n\u3000減少し、さらにノックバックさせる。\\n\u3000その際、自身の物理攻撃力を大アップ。\\n・前から３キャラに物理大ダメージを与える。\\n・リビングメイル自身のＨＰが40％を切ると、\u3000さらに攻撃が激しく凶暴になる。', 304707, 0, 1, 304705, 270, 0, 0, 16, 0, 0.8, 1000, 'リビングメイル');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】金属を喰らい、武具を操る謎の魔物。\\n増殖融合し超大な怪物となり、平和を脅かす。\\n\\n・ユニオンバーストは、敵全体にキャラの\\n\u3000最大ＨＰに応じた物理大ダメージを与え、\\n\u3000物理攻撃力と物理防御力を大ダウン。\\n・残りＨＰの割合が多い敵３キャラのＴＰを\\n\u3000減少し、さらにノックバックさせる。\\n\u3000その際、自身の物理攻撃力を大アップ。\\n・前から３キャラに物理大ダメージを与える。\\n・リビングメイル自身のＨＰが40％を切ると、\u3000さらに攻撃が激しく凶暴になる。', 304708, 0, 1, 304705, 270, 0, 0, 16, 0, 0.8, 1000, 'リビングメイル');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【魔法】強者の魂を幽鬼とし従える、冥府の高官。\\n亡者の念が刃に絡みつき、動きを鈍らせる。\\n\\n・魔法攻撃力ダウン効果の影響を受けやすい。\\n・飛行状態の敵を攻撃対象にできる。\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・レイスロードから受けるすべてのダメージで発\\n\u3000生する、パーティキャラのＴＰ回復量を中ダウ\\n\u3000ンさせる。\\n・ユニオンバーストは、最も近い敵１キャラを中\\n\u3000心にした中範囲にレイスロードの魔法攻撃力に\\n\u3000応じた魔法割合ダメージを与える。その後、与\\n\u3000えた総ダメージに応じて最大ＨＰをダウンさせ\\n\u3000る。このスキルの状態異常はダメージを無効化\\n\u3000しても付与される。\\n・最も近い敵１キャラを中心にした中範囲にレイ\\n\u3000スロードの魔法攻撃力に応じてダメージを与え\\n\u3000る呪い状態を付与し、ＨＰ回復量とＨＰ吸収を\\n\u3000特大ダウンさせる。このスキルにより付与され\\n\u3000た呪いのダメージでは、ＴＰが回復しない。\\n・通常攻撃は、最も近い敵１キャラにレイスロー\\n\u3000ドの魔法攻撃力に応じた魔法割合ダメージを与\\n\u3000える。', 304800, 0, 2, 304800, 270, 0, 0, 16, 0, 1.8, 3000, 'レイスロード');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【魔法】強者の魂を幽鬼とし従える、冥府の高官。\\n亡者の念が刃に絡みつき、動きを鈍らせる。\\n\\n・魔法攻撃力ダウン効果の影響を受けやすい。\\n・飛行状態の敵を攻撃対象にできる。\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を中アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・バトル開始時、敵全体のＴＰ上昇を小ダウンさ\\n\u3000せるフィールドを展開する。\\n・バトル開始時、自身にＴＰダウン50％カット\\n\u3000効果を付与する。\\n・レイスロードから受けるすべてのダメージで発\\n\u3000生する、パーティキャラのＴＰ回復量を中ダウ\\n\u3000ンさせる。\\n・敵から受けるすべてのダメージで発生する、レ\\n\u3000イスロードのＴＰ回復量が大ダウンする。\\n・ユニオンバーストは、最も近い敵１キャラを中\\n\u3000心にした中範囲にレイスロードの魔法攻撃力に\\n\u3000応じた魔法割合ダメージを与える。その後、与\\n\u3000えた総ダメージに応じて最大ＨＰをダウンさせ\\n\u3000る。このスキルの状態異常はダメージを無効化\\n\u3000しても付与される。\\n・最も近い敵１キャラを中心にした中範囲にレイ\\n\u3000スロードの魔法攻撃力に応じてダメージを与え\\n\u3000る呪い状態を付与し、ＨＰ回復量とＨＰ吸収を\\n\u3000特大ダウンさせる。このスキルにより付与され\\n\u3000た呪いのダメージでは、ＴＰが回復しない。\\n・通常攻撃は、最も近い敵１キャラにレイスロー\\n\u3000ドの魔法攻撃力に応じた魔法割合ダメージを与\\n\u3000える。', 304801, 0, 2, 304801, 270, 0, 0, 16, 0, 1.8, 3000, 'レイスロード');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】塔の魔力で蘇り、生命のマナを求め彷徨\\nう悪霊。幽鬼の念を纏う大鎌を振るい、無差別に\\n生者の魂を刈る。\\n\\n・前方範囲内に魔法大ダメージを与え、物理\\n\u3000攻撃力を特大ダウンさせる。\\n・前方範囲内に魔法中ダメージを与える。\\n\u3000物理攻撃をする敵には追加の魔法ダメージを\\n\u3000与え、さらに行動速度をダウンさせる。\\n・前方範囲内に物理中ダメージを与え、\\n\u3000ステータスアップ効果を解除させる。', 304802, 0, 1, 304802, 270, 0, 0, 16, 0, 1.8, 1000, 'ソウルイーター');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】強者の魂を幽鬼とし従える、冥府の高官。\\n亡者の念が刃に絡みつき、動きを鈍らせる。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・バトル開始時、自身に物理ダメージ20%\\n\u3000カット効果を付与する。\\n・ユニオンバーストは、敵の挑発を無視して、最\\n\u3000も物理攻撃力が高い敵１キャラと最も魔法攻撃\\n\u3000力が高い敵１キャラに魔法大ダメージ。このス\\n\u3000キルによるダメージでは、敵のＴＰが回復しな\\n\u3000い。\\n・前方３キャラに魔法中ダメージを与え、物理攻\\n\u3000撃力、魔法攻撃力、行動速度を大ダウン。\\n・前方１キャラに物理特大ダメージ。このスキル\\n\u3000によるダメージでは、ＴＰ回復量は減少する。', 304803, 0, 1, 304803, 270, 0, 0, 16, 0, 1.8, 1000, 'レイスロード');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】強者の魂を幽鬼とし従える、冥府の高官。\\n亡者の念が刃に絡みつき、動きを鈍らせる。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・バトル開始時、自身に物理ダメージ50%\\n\u3000カット効果を付与する。\\n・ユニオンバーストは、敵の挑発を無視して、最\\n\u3000も物理攻撃力が高い敵１キャラと最も魔法攻撃\\n\u3000力が高い敵１キャラに魔法大ダメージ。このス\\n\u3000キルによるダメージでは、敵のＴＰが回復しな\\n\u3000い。\\n・前方３キャラに魔法中ダメージを与え、物理攻\\n\u3000撃力、魔法攻撃力、行動速度を大ダウン。\\n・前方１キャラに物理特大ダメージ。このスキル\\n\u3000によるダメージでは、ＴＰ回復量は減少する。', 304804, 0, 1, 304804, 270, 0, 0, 16, 0, 1.8, 1000, 'レイスロード');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】強者の魂を幽鬼とし従える、冥府の高官。\\n亡者の念が刃に絡みつき、動きを鈍らせる。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・バトル開始時、自身に物理ダメージ50%\\n\u3000カット効果を付与する。\\n・バトル開始時、味方全体のＴＰを中アップ。\\n・ユニオンバーストは、敵の挑発を無視して、最\\n\u3000も物理攻撃力が高い敵１キャラと最も魔法攻撃\\n\u3000力が高い敵１キャラに魔法大ダメージ。このス\\n\u3000キルによるダメージでは、敵のＴＰが回復しな\\n\u3000い。\\n・前方３キャラに魔法中ダメージを与え、物理攻\\n\u3000撃力、魔法攻撃力、行動速度を大ダウン。\\n・前方１キャラに物理特大ダメージ。このスキル\\n\u3000によるダメージでは、ＴＰ回復量は減少する。', 304805, 0, 1, 304805, 270, 0, 0, 16, 0, 1.8, 1000, 'レイスロード');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】強者の魂を幽鬼とし従える、冥府の高官。\\n亡者の念が刃に絡みつき、動きを鈍らせる。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・バトル開始時、自身に物理ダメージ70%\\n\u3000カット効果を付与する。\\n・バトル開始時、味方全体のＴＰを中アップ。\\n・ユニオンバーストは、敵の挑発を無視して、最\\n\u3000も物理攻撃力が高い敵１キャラと最も魔法攻撃\\n\u3000力が高い敵１キャラに魔法大ダメージ。さらに、\\n\u3000敵全体をスタンさせる。このスキルによるダ\\n\u3000メージでは、敵のＴＰが回復しない。\\n・前方３キャラに魔法中ダメージを与え、物理攻\\n\u3000撃力、魔法攻撃力、行動速度を大ダウン。\\n・前方１キャラに物理特大ダメージ。このスキル\\n\u3000によるダメージでは、ＴＰ回復量は減少する。', 304806, 0, 1, 304806, 270, 0, 0, 16, 0, 1.8, 1000, 'レイスロード');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】強者の魂を幽鬼とし従える、冥府の高官。\\n亡者の念が刃に絡みつき、動きを鈍らせる。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・バトル開始時、自身に物理ダメージ100%\\n\u3000カット効果を付与する。\\n・バトル開始時、味方全体のＴＰを中アップ。\\n・ユニオンバーストは、敵の挑発を無視して、最\\n\u3000も物理攻撃力が高い敵１キャラと最も魔法攻撃\\n\u3000力が高い敵１キャラに魔法大ダメージ。さらに、\\n\u3000敵全体をスタンさせる。このスキルによるダ\\n\u3000メージでは、敵のＴＰが回復しない。\\n・前方３キャラに魔法中ダメージを与え、物理攻\\n\u3000撃力、魔法攻撃力、行動速度を大ダウン。\\n・前方１キャラに物理特大ダメージ。このスキル\\n\u3000によるダメージでは、ＴＰ回復量は減少する。', 304807, 0, 1, 304807, 270, 0, 0, 16, 0, 1.8, 1000, 'レイスロード');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【魔法】強者の魂を幽鬼とし従える、冥府の高官。\\n亡者の念が刃に絡みつき、動きを鈍らせる。\\n\\n・魔法攻撃力ダウン効果の影響を受けやすい。\\n・レイスロードから受けるすべてのダメージで発\\n\u3000生する、パーティキャラのＴＰ回復量を中ダウ\\n\u3000ンさせる。\\n・ユニオンバーストは、最も近い敵１キャラを中\\n\u3000心にした中範囲にレイスロードの魔法攻撃力に\\n\u3000応じた魔法割合ダメージを与える。その後、与\\n\u3000えた総ダメージに応じて最大ＨＰをダウンさせ\\n\u3000る。このスキルの状態異常はダメージを無効化\\n\u3000しても付与される。\\n・最も近い敵１キャラを中心にした中範囲にレイ\\n\u3000スロードの魔法攻撃力に応じてダメージを与え\\n\u3000る呪い状態を付与し、ＨＰ回復量とＨＰ吸収を\\n\u3000特大ダウンさせる。このスキルにより付与され\\n\u3000た呪いのダメージでは、ＴＰが回復しない。\\n・通常攻撃は、最も近い敵１キャラにレイスロー\\n\u3000ドの魔法攻撃力に応じた魔法割合ダメージを与\\n\u3000える。', 304808, 0, 1, 304808, 270, 0, 0, 16, 0, 1.8, 1000, 'レイスロード');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】ルナの魔力で目覚めた、巨腕の改造人間。\\n小型リアクターの最大出力は自身が感電するほど。\\n\\n・ユニオンバーストは、前から敵３キャラに物理\\n\u3000大ダメージを与え、前から敵２キャラに麻痺状\\n\u3000態を付与する。さらに自身のステータスアップ\\n\u3000効果を解除し、物理防御力と魔法防御力を中ダ\\n\u3000ウンさせる。このスキルの状態異常はダメージ\\n\u3000を無効化しても付与される。\\n・敵全体に魔法大ダメージを与え、自身の物理攻\\n\u3000撃力を長時間大アップさせる。\\n・味方全体の行動速度を大アップさせる。\\n・自身のＨＰが40％を切ると、さらに攻撃が激\\n\u3000しく凶暴になる。', 304900, 0, 1, 304900, 270, 0, 0, 16, 0, 1.8, 1000, 'エレクトロ・ギガス');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】人間への復讐を企む、霊界の住人。\\n「オイラはジャック！ジャック・オー・プリン！\\n\u3000遊んでくれなきゃ、イタズラしちゃうぞ～」\\n\\n・敵全体に物理大ダメージを与え、\\n\u3000キャラのＨＰが40%を切っている場合、\\n\u3000誘惑状態にする。\\n・敵全体に魔法小ダメージを与え、\\n\u3000キャラのステータスアップ効果を解除。\\n・最も近い敵に物理中ダメージを与え、\\n\u3000さらに、前から3キャラに、物理中\\n\u3000ダメージ＆スタン。\\n・ジャック・オー・プリン自身のＨＰが\\n\u300040％を切ると、さらに攻撃が激しく\\n\u3000凶暴になる。\\n', 305000, 0, 1, 305000, 270, 0, 0, 16, 0, 0.8, 1000, 'ジャック・オー・プリン');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】人間への復讐を企む、霊界の住人。\\n「オイラはジャック！ジャック・オー・プリン！\\n\u3000遊んでくれなきゃ、イタズラしちゃうぞ～」\\n\\n・敵全体に物理大ダメージを与え、\\n\u3000キャラのＨＰが40%を切っている場合、\\n\u3000誘惑状態にする。\\n・最も近い敵に物理中ダメージを与え、\\n\u3000さらに、前から3キャラに、物理中\\n\u3000ダメージ＆スタン。\\n', 305001, 0, 1, 305000, 270, 0, 0, 16, 0, 0.8, 1000, 'ジャック・オー・プリン');
