insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】巨体を駆使して暴れ回る大ウサギの魔物。\\n繰り出す一撃は消耗が大きく、持てあまし気味。\\n\\n・ユニオンバーストは敵全体に物理大ダメージ\\n\u3000を与え、さらにノックバックさせる。\\n\u3000その後、目を回している間、自身の物理防御\\n\u3000力と魔法防御力が大幅にダウン。\\n・敵全体に物理中ダメージを与え、さらに前方\\n\u3000範囲内の敵をスタンさせる。\\n\u3000このスキルの状態異常はダメージを無効化し\\n\u3000ても付与される。', 305100, 0, 1, 305100, 270, 0, 0, 16, 0, 1.8, 1000, 'メガラパーン');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】巨体を駆使して暴れまわる\\n大ウサギの魔物。繰り出す一撃は\\n消耗が大きく、持てあまし気味。\\n\\n・敵全体に物理大ダメージを与え、\\n\u3000さらにノックバックさせる。\\n\u3000その後、目を回している間、\\n\u3000自身の物理防御力と魔法防御力が\\n\u3000大幅にダウン。\\n\\n・敵全体に物理中ダメージを与え、\\n\u3000さらに前方範囲内の敵をスタン\\n\u3000させる。', 305101, 0, 1, 305100, 270, 0, 0, 16, 0, 1.8, 1000, 'メガラパーン');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】巨体を駆使して暴れ回る大ウサギの魔物。\\n繰り出す一撃は消耗が大きく、持てあまし気味。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・メガラパーンから受けるすべてのダメージで発\\n\u3000生する、パーティキャラのＴＰ回復量を中ダウ\\n\u3000ンさせる。\\n・ユニオンバーストは、敵全体に物理中ダメージ\\n\u3000を与え、ノックバックさせる。さらにキャラの\\n\u3000ＨＰが80％未満の場合、スタン状態を付与す\\n\u3000る。このスキルの状態異常はダメージを無効化\\n\u3000しても付与される。このスキルによるダメージ\\n\u3000では、ＴＰが回復しない。\\n・敵全体に物理小ダメージを与えて吹き飛ばす。\\n\u3000その後、自身のＴＰを小回復。\\n・通常攻撃は最も近い敵１キャラに物理大ダメー\\n\u3000ジを与え、さらにノックバックさせる。', 305102, 0, 1, 305102, 270, 0, 0, 16, 0, 1.8, 1000, 'メガラパーン');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】巨体を駆使して暴れ回る大ウサギの魔物。\\n繰り出す一撃は消耗が大きく、持てあまし気味。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を中アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・バトル開始時、敵全体のＴＰ上昇を小ダウンさ\\n\u3000せるフィールドを展開する。\\n・バトル開始時、自身にＴＰダウン100％カッ\\n\u3000ト効果を付与する。\\n・メガラパーンから受けるすべてのダメージで発\\n\u3000生する、パーティキャラのＴＰ回復量を中ダウ\\n\u3000ンさせる。\\n・敵から受けるすべてのダメージで発生する、メ\\n\u3000ガラパーンのＴＰ回復量が大ダウンする。\\n・ユニオンバーストは、敵全体に物理中ダメージ\\n\u3000を与え、ノックバックさせる。さらにキャラの\\n\u3000ＨＰが95％未満の場合、スタン状態を付与す\\n\u3000る。このスキルの状態異常はダメージを無効化\\n\u3000しても付与される。このスキルによるダメージ\\n\u3000では、ＴＰが回復しない。\\n・敵全体に物理小ダメージを与えて吹き飛ばす。\\n\u3000その後、自身のＴＰを中回復。このスキルによ\\n\u3000るダメージでは、ＴＰが回復しない。\\n・通常攻撃は最も近い敵１キャラに物理大ダメー\\n\u3000ジを与え、さらにノックバックさせる。', 305103, 0, 1, 305103, 270, 0, 0, 16, 0, 1.8, 1000, 'メガラパーン');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】巨体を駆使して暴れ回る大ウサギの魔物。\\n繰り出す一撃は消耗が大きく、持てあまし気味。\\n\\n・ユニオンバーストは、敵全体に物理中ダメージ\\n\u3000を与え、ノックバックさせる。さらにキャラの\\n\u3000ＨＰが80％未満の場合、スタン状態を付与す\\n\u3000る。このスキルの状態異常はダメージを無効化\\n\u3000しても付与される。このスキルによるダメージ\\n\u3000では、ＴＰが回復しない。\\n・敵全体に物理小ダメージを与えて吹き飛ばす。\\n\u3000その後、自身のＴＰを中回復する。このスキル\\n\u3000によるダメージでは、ＴＰが回復しない。\\n・通常攻撃は最も近い敵１キャラに物理大ダメー\\n\u3000ジを与え、ノックバックさせる。このスキルに\\n\u3000よるダメージでは、ＴＰ回復量が中ダウンする。', 305104, 0, 1, 305104, 270, 0, 0, 16, 0, 1.8, 3000, 'メガラパーン');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】はるか古に生み出された、防衛兵器。\\n悪党の謀により悠久の眠りに終焉を告げる。\\n\\n・敵全体にキャラの最大ＨＰに応じた\\n\u3000物理大ダメージを与えたのち、\\n\u3000自身の物理攻撃力を大ダウン。\\n・前方中範囲内の敵に物理中ダメージを与え、\\n\u3000物理攻撃力を大ダウン。\\n・前方広範囲内の敵に物理中ダメージを与え、\\n\u3000麻痺状態にする。\\n\u3000キャラのＨＰが70％以下の場合、\\n\u3000麻痺の効果時間が長くなる。\\n・オラム自身のＨＰが40％を切ると、\u3000\\n\u3000さらに攻撃が激しく凶暴になる。', 305200, 0, 1, 305200, 270, 0, 0, 16, 0, 1.8, 1000, 'オラム');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】はるか古に生み出された、防衛兵器。\\n悪党の謀により悠久の眠りに終焉を告げる。\\n\\n・敵全体にキャラの最大ＨＰに応じた\\n\u3000物理大ダメージを与えたのち、\\n\u3000自身の物理攻撃力を大ダウン。\\n・前方中範囲内の敵に物理中ダメージを与え、\\n\u3000物理攻撃力を大ダウン。', 305201, 0, 1, 305200, 270, 0, 0, 16, 0, 1.8, 1000, 'オラム');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】はるか古に生み出された、防衛兵器。\\n悪党の謀により悠久の眠りに終焉を告げる。\\n\\n・敵全体にキャラの最大ＨＰに応じた\\n\u3000物理大ダメージを与えたのち、\\n\u3000自身の物理攻撃力を大ダウン。\\n・前方中範囲内の敵に物理中ダメージを与え、\\n\u3000物理攻撃力を大ダウン。\\n・前方広範囲内の敵に物理中ダメージを与え、\\n\u3000麻痺状態にする。\\n\u3000キャラのＨＰが70％以下の場合、\\n\u3000麻痺の効果時間が長くなる。\\n・オラム自身のＨＰが40％を切ると、\u3000\\n\u3000さらに攻撃が激しく凶暴になる。', 305202, 0, 1, 305200, 270, 0, 0, 16, 0, 1.8, 1000, 'オラム');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】はるか古に生み出された、防衛兵器。\\n悪党の謀により悠久の眠りに終焉を告げる。\\n\\n・敵全体にキャラの最大ＨＰに応じた\\n\u3000物理大ダメージを与えたのち、\\n\u3000自身の物理攻撃力を大ダウン。\\n・前方中範囲内の敵に物理中ダメージを与え、\\n\u3000物理攻撃力を大ダウン。\\n・前方広範囲内の敵に物理中ダメージを与え、\\n\u3000麻痺状態にする。\\n\u3000キャラのＨＰが70％以下の場合、\\n\u3000麻痺の効果時間が長くなる。\\n・オラム自身のＨＰが40％を切ると、\u3000\\n\u3000さらに攻撃が激しく凶暴になる。', 305203, 0, 1, 305200, 270, 0, 0, 16, 0, 1.8, 1000, 'オラム');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】ルナの塔の魔力で暴走する、古代兵器。\\n古き守護の力は、呪いを振りまく大禍と化した。\\n\\n・敵全体に物理大ダメージを与え、自身の\\n\u3000物理防御力と魔法防御力を大ダウンさせる。\\n・前方１キャラを中心にした範囲内の敵すべてに\\n\u3000物理中ダメージを与え、物理防御力を中ダウン\\n\u3000させる。さらにスタンを与える。\\n・敵全体に物理中ダメージを与え、呪い状態\\n\u3000にする。キャラのＨＰが40％以下の場合、\\n\u3000呪いのダメージが２倍になる。', 305204, 0, 1, 305204, 270, 0, 0, 16, 0, 1.8, 1000, 'カース・オラム');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】はるか古に生み出された、防衛兵器。\\n悪党の謀により悠久の眠りに終焉を告げる。\\n\\n・ユニオンバーストは、敵全体にキャラの\\n最大ＨＰに応じた物理大ダメージを与えた\\nのち、自身の物理攻撃力を大ダウン。\\n・前方中範囲内の敵に物理中ダメージを与え、\\n\u3000物理攻撃力を大ダウン。\\n・前方広範囲内の敵に物理中ダメージを与え、\\n\u3000麻痺状態にする。\\n\u3000キャラのＨＰが70％以下の場合、\\n\u3000麻痺の効果時間が長くなる。\\n・オラム自身のＨＰが40％を切ると、\u3000\\n\u3000さらに攻撃が激しく凶暴になる。', 305205, 0, 1, 305205, 270, 0, 0, 16, 0, 1.8, 1000, 'オラム');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】はるか古に生み出された、防衛兵器。\\n悪党の謀により悠久の眠りに終焉を告げる。\\n\\n・ユニオンバーストは、自身の物理攻撃力を\\n\u3000大ダウンしたのち、敵全体にキャラの最大\\n\u3000ＨＰに応じた物理大ダメージを与える。\\n・前方中範囲内の敵に物理大ダメージを与え、\\n\u3000物理攻撃力を大ダウン。', 305206, 0, 1, 305205, 270, 0, 0, 16, 0, 1.8, 1000, 'オラム');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】はるか古に生み出された、防衛兵器。\\n悪党の謀により悠久の眠りに終焉を告げる。\\n\\n・ユニオンバーストは、自身の物理攻撃力を\\n\u3000大ダウンしたのち、敵全体にキャラの最大\\n\u3000ＨＰに応じた物理大ダメージを与える。\\n・前方中範囲内の敵に物理大ダメージを与え、\\n\u3000物理攻撃力を大ダウン。\\n・前方広範囲内の敵に物理大ダメージを与え、\\n\u3000麻痺状態にする。\\n\u3000キャラのＨＰが70％以下の場合、\\n\u3000麻痺の効果時間が長くなる。\\n・オラム自身のＨＰが40％を切ると、\u3000\\n\u3000さらに攻撃が激しく凶暴になる。', 305207, 0, 1, 305205, 270, 0, 0, 16, 0, 1.8, 1000, 'オラム');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】はるか古に生み出された、防衛兵器。\\n悪党の謀により悠久の眠りに終焉を告げる。\\n\\n・ユニオンバーストは、自身の物理攻撃力を\\n\u3000大ダウンしたのち、敵全体にキャラの最大\\n\u3000ＨＰに応じた物理大ダメージを与える。\\n・前方中範囲内の敵に物理大ダメージを与え、\\n\u3000物理攻撃力を大ダウン。\\n・前方広範囲内の敵に物理大ダメージを与え、\\n\u3000麻痺状態にする。\\n\u3000キャラのＨＰが70％以下の場合、\\n\u3000麻痺の効果時間が長くなる。\\n・オラム自身のＨＰが40％を切ると、\u3000\\n\u3000さらに攻撃が激しく凶暴になる。', 305208, 0, 1, 305205, 270, 0, 0, 16, 0, 1.8, 1000, 'オラム');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】ルナの魔力を帯び変異した獰猛な魔獣。\\n強靭な歯牙は歴戦の冒険者さえ容易く切り裂く。\\n\\n・ユニオンバーストは敵全体に物理大ダメージを\\n\u3000与え、さらに自分のＨＰを回復する。\\n・後方範囲内の敵に物理ダメージを与え、スタン\\n\u3000させる。\\n\u3000さらに敵全体の物理防御力を中ダウンさせる。\\n・前から３キャラに物理ダメージを与え、\\n\u3000毒状態にする。', 305300, 0, 1, 305300, 270, 0, 0, 16, 0, 1.8, 1000, 'ハイ・ガルグ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】雪山に棲む獰猛な魔狼。\\n強靭な歯牙は歴戦の冒険者さえ\\n容易く氷塊の墓標へ変える。\\n\\n・ユニオンバーストは敵全体に物\\n\u3000理大ダメージを与える。\\n\\n・一番後ろの敵キャラを中心とし\\n\u3000て、範囲内の敵すべてに物理小\\n\u3000ダメージを与え、スタンさせる。\\n\u3000さらに敵全体の物理防御力を中\\n\u3000ダウンさせる。\\n\\n・前方範囲内の敵すべてに物理小\\n\u3000ダメージを与え、毒状態にする。', 305301, 0, 1, 305301, 270, 0, 0, 16, 0, 1.8, 1000, 'アイスガルグ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】雪山に棲む獰猛な魔狼。\\n強靭な歯牙は歴戦の冒険者さえ\\n容易く氷塊の墓標へ変える。\\n\\n・ユニオンバーストは敵全体に物\\n\u3000理大ダメージを与える。\\n\\n・一番後ろの敵キャラを中心とし\\n\u3000て、範囲内の敵すべてに物理小\\n\u3000ダメージを与え、スタンさせる。\\n\u3000さらに敵全体の物理防御力を中\\n\u3000ダウンさせる。\\n\\n・前方範囲内の敵すべてに物理小\\n\u3000ダメージを与え、毒状態にする。', 305302, 0, 1, 305301, 270, 0, 0, 16, 0, 1.8, 1000, 'アイスガルグ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】強力な氷の頭突きで\\n堅牢な盾も貫き穿つ一角獣。\\n氷丘押し寄せる北の果てで、\\n冒険者を氷獄へ突き落す。\\n\\n・敵全体に魔法大ダメージを与え、\\n\u3000魔法防御力を下げる。\\n\u3000さらに、味方全体のＴＰ上昇率を\\n\u3000上げる。\\n\\n・前方小範囲内に魔法小ダメージを\\n\u3000与え、氷結状態にする。さらに、\\n\u3000全体に魔法小ダメージを与え、\\n\u3000前方3キャラを小さく\\n\u3000吹き飛ばす。', 305400, 0, 1, 305400, 270, 0, 0, 16, 0, 1.8, 1000, 'アイスホーン');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【魔法】幾多の伝承に名を残す、記憶の大精霊。\\n霧の如く実態を持たず、全て覆い隠してしまう。\\n\\n・ユニオンバーストは敵全体に\\n\u3000魔法大ダメージを与え、\\n\u3000さらに敵が呪い状態の場合、\\n\u3000ダメージがアップする。\\n・敵全体に魔法中ダメージを与える。\\n\u3000さらに呪い状態にする。\\n・分身体（紫）（赤）（青）のうち、\\n\u3000いずれか1体を召喚する。\\n\u3000召喚する際は敵全体をノックバックさせる。\\n・【物理】分身体（紫）は、自身に物理/魔法\\n\u3000吸収バリアを展開する。\\n・【物理】分身体（赤）は、敵全体に\\n\u3000魔法中ダメージを与える。\\n・【物理】分身体（青）は、敵全体に\\n\u3000魔法中ダメージ。\\n\u3000さらに、呪い状態にする。\\n\u3000分身体（青）のＨＰが30％以下になった時、\\n\u3000フォギーのＴＰを300回復させる。\\n・フォギー自身のＨＰが\\n\u300050％を切ると、さらに攻撃が激しく\\n\u3000凶暴になる。', 305500, 0, 2, 305500, 270, 0, 0, 16, 0, 3.0, 2160, 'フォギー');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【魔法】幾多の伝承に名を残す、記憶の大精霊。\\n霧の如く実態を持たず、全て覆い隠してしまう。\\n\\n・ユニオンバーストは敵全体に\\n\u3000魔法大ダメージを与え、\\n\u3000さらに敵が呪い状態の場合、\\n\u3000ダメージがアップする。\\n・敵全体に魔法中ダメージを与え、\\n\u3000さらに呪い状態にする。\\n・分身体（紫）（赤）のうち、どちらか1体を\\n\u3000召喚する。\\n\u3000召喚する際は敵全体をノックバックさせる。\\n・【物理】分身体（紫）は、自身に物理/魔法\\n\u3000吸収バリアを展開する。\\n・【物理】分身体（赤）は、敵全体に\\n\u3000魔法中ダメージを与える。', 305501, 0, 2, 305500, 270, 0, 0, 16, 0, 3.0, 2160, 'フォギー');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【魔法】幾多の伝承に名を残す、記憶の大精霊。\\n霧の如く実態を持たず、全て覆い隠してしまう。\\n\\n・ユニオンバーストは敵全体に\\n\u3000魔法大ダメージを与え、\\n\u3000さらに敵が呪い状態の場合、\\n\u3000ダメージがアップする。\\n・敵全体に魔法中ダメージを与え、\\n\u3000さらに呪い状態にする。\\n・分身体（紫）（赤）のうち、どちらか1体を\\n\u3000召喚する。\\n\u3000召喚する際は敵全体をノックバックさせる。\\n・【物理】分身体（紫）は、自身に物理/魔法\\n\u3000吸収バリアを展開する。\\n・【物理】分身体（赤）は、敵全体に\\n\u3000魔法中ダメージを与える。\\n・フォギー自身のＨＰが\\n\u300050％を切ると、さらに攻撃が激しく\\n\u3000凶暴になる。', 305502, 0, 2, 305500, 270, 0, 0, 16, 0, 3.0, 2160, 'フォギー');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【魔法】幾多の伝承に名を残す、記憶の大精霊。\\n霧の如く実態を持たず、全て覆い隠してしまう。\\n\\n・ユニオンバーストは敵全体に\\n\u3000魔法大ダメージを与え、\\n\u3000さらに敵が呪い状態の場合、\\n\u3000ダメージがアップする。\\n・敵全体に魔法中ダメージを与える。\\n\u3000さらに呪い状態にする。\\n・分身体（紫）（赤）（青）のうち、\\n\u3000いずれか1体を召喚する。\\n\u3000召喚する際は敵全体をノックバックさせる。\\n・【物理】分身体（紫）は、自身に物理/魔法\\n\u3000吸収バリアを展開する。\\n・【物理】分身体（赤）は、敵全体に\\n\u3000魔法中ダメージを与える。\\n・【物理】分身体（青）は、敵全体に\\n\u3000魔法中ダメージ。\\n\u3000さらに、呪い状態にする。\\n\u3000分身体（青）のＨＰが30％以下になった時、\\n\u3000フォギーのＴＰを300回復させる。\\n・フォギー自身のＨＰが\\n\u300050％を切ると、さらに攻撃が激しく\\n\u3000凶暴になる。', 305503, 0, 2, 305500, 270, 0, 0, 16, 0, 3.0, 2160, 'フォギー');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【魔法】幾多の伝承に名を残す、記憶の大精霊。\\n霧の如く実体を持たず、全て覆い隠してしまう。\\n\\n・ユニオンバーストは敵全体に\\n\u3000魔法大ダメージを与え、\\n\u3000さらに敵が呪い状態の場合、\\n\u3000ダメージがアップする。\\n・敵全体に魔法大ダメージを与える。\\n\u3000さらに呪い状態にする。\\n・分身体（紫）（赤）（青）のうち、\\n\u3000いずれか1体を召喚する。\\n\u3000召喚する際は敵全体をノックバックさせる。\\n・【物理】分身体（紫）は、自身に物理/魔法\\n\u3000吸収バリアを展開する。\\n・【物理】分身体（赤）は、敵全体に\\n\u3000魔法中ダメージを与える。\\n・【物理】分身体（青）は、敵全体に\\n\u3000魔法中ダメージ。\\n\u3000さらに、呪い状態にする。\\n\u3000分身体（青）のＨＰが30％以下になった時、\\n\u3000フォギーのＴＰを300回復させる。\\n・フォギー自身のＨＰが\\n\u300050％を切ると、さらに攻撃が激しく\\n\u3000凶暴になる。', 305504, 0, 2, 305500, 270, 0, 0, 16, 0, 3.0, 2160, 'フォギー');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【魔法】幾多の伝承に名を残す、記憶の大精霊。\\n霧の如く実体を持たず、全て覆い隠してしまう。\\n\\n・ユニオンバーストは敵全体に\\n\u3000魔法中ダメージを与え、\\n\u3000さらに敵が呪い状態の場合、\\n\u3000ダメージがアップする。\\n・敵全体に魔法小ダメージを与え、\\n\u3000さらに呪い状態にする。\\n・分身体（紫）（赤）のうち、どちらか1体を\\n\u3000召喚する。\\n\u3000召喚する際は敵全体をノックバックさせる。\\n・【物理】分身体（紫）は、自身に物理/魔法\\n\u3000吸収バリアを展開する。\\n・【物理】分身体（赤）は、敵全体に\\n\u3000魔法大ダメージを与える。', 305505, 0, 2, 305500, 270, 0, 0, 16, 0, 3.0, 2160, 'フォギー');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【魔法】幾多の伝承に名を残す、記憶の大精霊。\\n霧の如く実体を持たず、全て覆い隠してしまう。\\n\\n・ユニオンバーストは敵全体に\\n\u3000魔法中ダメージを与え、\\n\u3000さらに敵が呪い状態の場合、\\n\u3000ダメージがアップする。\\n・敵全体に魔法小ダメージを与え、\\n\u3000さらに呪い状態にする。\\n・分身体（紫）（赤）のうち、どちらか1体を\\n\u3000召喚する。\\n\u3000召喚する際は敵全体をノックバックさせる。\\n・【物理】分身体（紫）は、自身に物理/魔法\\n\u3000吸収バリアを展開する。\\n・【物理】分身体（赤）は、敵全体に\\n\u3000魔法大ダメージを与える。\\n・フォギー自身のＨＰが\\n\u300050％を切ると、さらに攻撃が激しく\\n\u3000凶暴になる。', 305506, 0, 2, 305500, 270, 0, 0, 16, 0, 3.0, 2160, 'フォギー');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【魔法】幾多の伝承に名を残す、記憶の大精霊。\\n霧の如く実体を持たず、全て覆い隠してしまう。\\n\\n・ユニオンバーストは敵全体に\\n\u3000魔法大ダメージを与え、\\n\u3000さらに敵が呪い状態の場合、\\n\u3000ダメージがアップする。\\n・敵全体に魔法大ダメージを与える。\\n\u3000さらに呪い状態にする。\\n・分身体（紫）（赤）（青）のうち、\\n\u3000いずれか1体を召喚する。\\n\u3000召喚する際は敵全体をノックバックさせる。\\n・【物理】分身体（紫）は、自身に物理/魔法\\n\u3000吸収バリアを展開する。\\n・【物理】分身体（赤）は、敵全体に\\n\u3000魔法大ダメージを与える。\\n・【物理】分身体（青）は、敵全体に\\n\u3000物理小ダメージ。\\n\u3000さらに、呪い状態にする。\\n\u3000分身体（青）のＨＰが30％以下になった時、\\n\u3000フォギーのＴＰを300回復させる。\\n・フォギー自身のＨＰが\\n\u300050％を切ると、さらに攻撃が激しく\\n\u3000凶暴になる。', 305507, 0, 2, 305500, 270, 0, 0, 16, 0, 3.0, 2160, 'フォギー');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【魔法】塔の魔力を帯びた霧が実体化した魔物。\\n怨嗟を振りまき、分身とともに冒険者を付け狙う。\\n\\n・敵全体に魔法大ダメージを与える。\\n\u3000敵が呪い状態の場合、ダメージがアップし、呪\\n\u3000詛状態の場合、さらにダメージがアップする。\\n・敵全体に魔法中ダメージを与える。\\n\u3000敵が呪い状態の場合、呪詛状態にする。さらに、\\n\u3000ミストシーカー自身のＨＰが80％未満の場合、\\n\u3000物理攻撃力と魔法攻撃力を短時間大ダウンさせ\\n\u3000る。\\n・分身体を召喚する。\\n\u3000召喚する際は敵全体をノックバックさせる。\\n・分身体は、敵全体に物理中ダメージを\\n\u3000与え、さらに呪い状態にする。\\n・分身体のＨＰが30％以下になった時、最も魔\\n\u3000法攻撃力が高い味方１キャラのＴＰを1000\\n\u3000回復させる。\\n・ミストシーカー自身のＨＰが80％を切ると、\\n\u3000さらに攻撃が激しく狂暴になる。', 305508, 0, 2, 305508, 270, 0, 0, 16, 0, 3.0, 1000, 'ミストシーカー');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】ルナの魔力欲しさに現れた異界の魔物。\\n魔眼と従えた兵で、ルナの塔の征服を目論む。\\n\\n・敵全体に魔法大ダメージを与え、\\n\u3000さらに敵全体の魔法防御力を中ダウンさせる。\\n・6回、ランダムで1キャラに魔法小ダメージ\\n\u3000を与える。\\n・後ろから3番目のキャラに魔法中ダメージと、\\n\u3000長時間の拘束を与える。\\n\u3000さらに全体に魔法小ダメージを与える。', 305600, 0, 1, 305600, 270, 0, 0, 16, 0, 1.8, 1000, 'ロード・イビリィ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】豪快に戦斧を振るう熟練のゴブリン戦士。\\n幼き戦士を脇に抱え、魂の技を見せ付ける。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・ゴブリングレートから受けるすべてのダメージ\\n\u3000で発生する、パーティキャラのＴＰ回復量を中\\n\u3000ダウンさせる。\\n・ユニオンバーストは、最も近い敵１キャラに物\\n\u3000理特大ダメージを与え、自身の物理攻撃力と物\\n\u3000理防御力をバトル終了まで小アップさせる。', 305700, 0, 1, 305700, 270, 0, 0, 16, 0, 1.8, 1000, 'ゴブリングレート');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('豪快に戦斧を振り回す、熟練のゴブリン戦士。\\n幼き戦士を脇に抱え、魂の技を見せ付ける。\\n\\n・ユニオンバーストは、自身の物理攻撃力を中\\n\u3000アップ、物理防御力を小アップさせ、さらに\\n\u3000目の前の１キャラに物理特大ダメージ。', 305701, 0, 1, 305701, 270, 0, 0, 16, 0, 1.8, 1000, 'ゴブリングレート');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】豪快に戦斧を振るう熟練のゴブリン戦士。\\n幼き戦士を脇に抱え、魂の技を見せ付ける。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を中アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・バトル開始時、敵全体のＨＰ吸収を特大ダウン\\n\u3000させ、ＴＰ上昇を小ダウンさせる。\\n・バトル開始時、自身にＴＰダウン100％カッ\\n\u3000ト効果を付与する。\\n・ゴブリングレートから受けるすべてのダメージ\\n\u3000で発生する、パーティキャラのＴＰ回復量を中\\n\u3000ダウンさせる。\\n・ユニオンバーストは、最も近い敵１キャラに物\\n\u3000理特大ダメージを与え、スタン状態を付与し、\\n\u3000さらに自身の物理攻撃力と物理防御力をバトル\\n\u3000終了まで小アップさせる。このスキルの状態異\\n\u3000常はダメージを無効化しても付与される。\\n・最も近い敵１キャラに物理大ダメージを与え、\\n\u3000スタン状態を付与する。このスキルの状態異常\\n\u3000はダメージを無効化しても付与される。', 305702, 0, 1, 305702, 270, 0, 0, 16, 0, 1.8, 1000, 'ゴブリングレート');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】屈強な体と心で砂漠を\\n生き抜く蛮族の戦士。我が幼子を\\n守るため、戦斧を振るい続ける。\\n\\n・ユニオンバーストは、自身の物理\\n\u3000攻撃力を中アップ、物理防御力を\\n\u3000小アップさせる。\\n\u3000さらに目の前の１キャラに物理特\\n\u3000大ダメージを与える。', 305703, 0, 1, 305703, 270, 0, 0, 16, 0, 1.8, 1000, '蛮族のリーダー');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】豪快に戦斧を振るう熟練のゴブリン戦士。\\n幼き戦士を脇に抱え、魂の技を見せ付ける。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を中アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・バトル開始時、自身にＴＰダウン50％カット\\n\u3000効果を付与する。\\n・ゴブリングレートから受けるすべてのダメージ\\n\u3000で発生する、パーティキャラのＴＰ回復量を中\\n\u3000ダウンさせる。\\n・ユニオンバーストは、自身の物理攻撃力と物理\\n\u3000防御力を小アップさせ、最も近い敵１キャラに\\n\u3000物理特大ダメージを与え、さらにスタン状態を\\n\u3000付与する。このスキルの状態異常はダメージを\\n\u3000無効化しても付与される。\\n・最も近い敵１キャラに物理大ダメージを与え、\\n\u3000スタン状態を付与する。このスキルの状態異常\\n\u3000はダメージを無効化しても付与される。', 305704, 0, 1, 305704, 270, 0, 0, 16, 0, 1.8, 1000, 'ゴブリングレート');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】豪快に戦斧を振るう熟練のゴブリン戦士。\\n幼き戦士を脇に抱え、魂の技を見せ付ける。\\n\\n・ゴブリングレートから受けるすべてのダメージ\\n\u3000で発生する、パーティキャラのＴＰ回復量を中\\n\u3000ダウンさせる。\\n・ユニオンバーストは、最も近い敵１キャラに物\\n\u3000理特大ダメージを与え、さらにスタン状態を付\\n\u3000与する。その後自身の物理攻撃力と物理防御力\\n\u3000をバトル終了まで小アップさせる。このスキル\\n\u3000の状態異常はダメージを無効化しても付与され\\n\u3000る。\\n・最も近い敵１キャラに物理大ダメージを与え、\\n\u3000スタン状態を付与する。このスキルの状態異常\\n\u3000はダメージを無効化しても付与される。', 305705, 0, 1, 305705, 270, 0, 0, 16, 0, 1.8, 1000, 'ゴブリングレート');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】ロードの左腕にしてゴブリンの大戦士。\\n巨大な戦斧を豪快に振るい、眼前の敵を打ち砕く。\\n\\n・バトル開始時、自身の物理防御力と魔法防御\\n\u3000力を小アップさせる。この防御力アップ効果\\n\u3000で上昇した防御力は、バトル中に受ける防御\\n\u3000力ダウンスキルの影響を受けない。\\n・バトル開始時、ダメージ上限スキルを使用し\\n\u3000て、一度の行動で与えるダメージの値が一定\\n\u3000を超えた場合、与えるダメージの値に応じて\\n\u3000ダメージ量を減少させる。\\n・ゴブリングレートから受けるすべてのダメー\\n\u3000ジで発生する、パーティキャラのＴＰ回復量\\n\u3000を中ダウンさせる。\\n・ユニオンバーストは、前方１キャラに物理特\\n\u3000大ダメージを与え、自身の物理攻撃力と物理\\n\u3000防御力を小アップさせる。\\n・前方１キャラにキャラの最大ＨＰに応じた\\n\u3000物理割合ダメージを与える。', 305707, 0, 1, 305707, 270, 0, 0, 16, 0, 1.8, 1000, 'ゴブリングレート');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【魔法】海神の使者で、不思議な軟体の魔物。\\n身体のほとんどは魔力を帯びた海水だとか。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・ネプテリオンから受けるすべてのダメージで発\\n\u3000生する、パーティキャラのＴＰ回復量を小ダウ\\n\u3000ンさせる。\\n・ユニオンバーストは、敵全体に魔法大ダメージ\\n\u3000を与え、さらに物理攻撃力と魔法攻撃力を大ダ\\n\u3000ウンさせる。このスキルの状態異常はダメージ\\n\u3000を無効化しても付与される。このスキルによる\\n\u3000ダメージでは、敵のＴＰが回復しない。\\n・敵の挑発を無視して、前から４番目のキャラを\\n\u3000中心とした小範囲に継続魔法小ダメージを与え\\n\u3000る。このスキルによるダメージでは、敵のＴＰ\\n\u3000が回復しない。\\n・通常攻撃は敵の挑発を無視して、前から４番目\\n\u3000のキャラに魔法特大ダメージを与え、そのキャ\\n\u3000ラを中心とした小範囲に行動速度を大ダウンさ\\n\u3000せる。このスキルの状態異常はダメージを無効\\n\u3000化しても付与される。', 305800, 0, 2, 305800, 270, 0, 0, 16, 0, 1.8, 1000, 'ネプテリオン');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【魔法】ルナの塔で暴れ回る海獣。太古の海神に\\n仕えるが、今や大義なき破壊者となり果てる。\\n\\n・敵全体に魔法ダメージを与える。\\n・一定範囲に、物理攻撃力と魔法防御力を\\n\u3000ダウンさせ、継続魔法ダメージを与える\\n\u3000フィールドを展開する。\\n・前から２番目と３番目のキャラに\\n\u3000魔法大ダメージを与える。', 305801, 0, 2, 305801, 270, 0, 0, 16, 0, 2.6, 1000, 'カムツカイ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【魔法】海神に仕える奇体な魔物。\\n水域の平穏を脅かす侵入者を見るや\\n神使いの力を行使し、一掃する。\\n\\n・敵全体に魔法大ダメージ。\\n\\n・前から２番目のキャラに魔法特大\\n\u3000ダメージ、前から３番目のキャラ\\n\u3000に魔法中ダメージ。\\n\\n・一定範囲に、魔法防御力をダウン\\n\u3000させ、継続魔法ダメージを与える\\n\u3000フィールドを展開。', 305802, 0, 2, 305802, 270, 0, 0, 16, 0, 1.8, 1000, 'ネプテリオン');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【魔法】海神の使者で、不思議な軟体の魔物。\\n身体のほとんどは魔力を帯びた海水だとか。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を中アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・ネプテリオンから受けるすべてのダメージで発\\n\u3000生する、パーティキャラのＴＰ回復量を小ダウ\\n\u3000ンさせる。\\n・ユニオンバーストは、敵全体に魔法大ダメージ\\n\u3000を与え、さらに物理攻撃力と魔法攻撃力を大ダ\\n\u3000ウンさせる。このスキルの状態異常はダメージ\\n\u3000を無効化しても付与される。このスキルによる\\n\u3000ダメージでは、敵のＴＰが回復しない。\\n・敵の挑発を無視して、前から４番目のキャラを\\n\u3000中心とした小範囲に継続魔法小ダメージを与え\\n\u3000る。このスキルによるダメージでは、敵のＴＰ\\n\u3000が回復しない。\\n・通常攻撃は敵の挑発を無視して、前から４番目\\n\u3000のキャラに魔法特大ダメージを与え、そのキャ\\n\u3000ラを中心とした小範囲に行動速度を特大ダウン\\n\u3000させる。このスキルの状態異常はダメージを無\\n\u3000効化しても付与される。', 305803, 0, 2, 305803, 270, 0, 0, 16, 0, 1.8, 1000, 'ネプテリオン');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【魔法】海神の使者で、不思議な軟体の魔物。\\n身体のほとんどは魔力を帯びた海水だとか。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・ネプテリオンから受けるすべてのダメージで発\\n\u3000生する、パーティキャラのＴＰ回復量を小ダウ\\n\u3000ンさせる。\\n・ユニオンバーストは、敵全体に魔法大ダメージ\\n\u3000を与え、さらに物理攻撃力と魔法攻撃力を大ダ\\n\u3000ウンさせる。このスキルの状態異常はダメージ\\n\u3000を無効化しても付与される。このスキルによる\\n\u3000ダメージでは、敵のＴＰが回復しない。\\n・敵の挑発を無視して、前から４番目のキャラを\\n\u3000中心とした小範囲に継続魔法小ダメージを与え\\n\u3000る。このスキルによるダメージでは、敵のＴＰ\\n\u3000が回復しない。\\n・通常攻撃は敵の挑発を無視して、前から４番目\\n\u3000のキャラに魔法特大ダメージを与え、そのキャ\\n\u3000ラを中心とした小範囲に行動速度を大ダウンさ\\n\u3000せる。このスキルの状態異常はダメージを無効\\n\u3000化しても付与される。', 305804, 0, 2, 305804, 270, 0, 0, 16, 0, 1.8, 3000, 'ネプテリオン');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【魔法】海神の使者で、不思議な軟体の魔物。\\n身体のほとんどは魔力を帯びた海水だとか。\\n\\n・ネプテリオンから受けるすべてのダメージで発\\n\u3000生する、パーティキャラのＴＰ回復量を中ダウ\\n\u3000ンさせる。\\n・ユニオンバーストは、敵全体に魔法大ダメージ\\n\u3000を与え、さらに物理攻撃力と魔法攻撃力を大ダ\\n\u3000ウンさせる。このスキルの状態異常はダメージ\\n\u3000を無効化しても付与される。このスキルによる\\n\u3000ダメージでは、敵のＴＰが回復しない。\\n・最も遠い敵１キャラを中心にした小範囲に継続\\n\u3000魔法小ダメージを与える。このスキルによるダ\\n\u3000メージでは、敵のＴＰが回復しない。\\n・通常攻撃は、最も遠い敵１キャラに魔法大ダ\\n\u3000メージを与え、そのキャラを中心にした小範囲\\n\u3000に行動速度を特大ダウンさせる。このスキルの\\n\u3000状態異常はダメージを無効化しても付与される。', 305805, 0, 2, 305805, 270, 0, 0, 16, 0, 1.8, 3000, 'ネプテリオン');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【魔法】圧倒的な魅力を放つ麗しき極彩色の艶鳥。\\nその色香に囚われれば、味方を襲う下僕となる。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。\\n\u3000この防御力アップ効果で上昇した防御力は、バ\\n\u3000トル中に受ける防御力ダウンスキルの影響を受\\n\u3000けない。\\n・ユニオンバーストは、敵全体のバリアを解除し、\\n\u3000敵全体にキャラの最大ＨＰに応じた魔法割合ダ\\n\u3000メージを与える。\\n\u3000さらに、物理攻撃力と魔法攻撃力を大ダウンさ\\n\u3000せる。\\n\u3000キャラのＨＰが70％未満の場合、誘惑状態を\\n\u3000付与する。\\n\u3000このスキルによるダメージでは、敵のＴＰが回\\n\u3000復しない。\\n・前から２キャラに魔法中ダメージを与え、誘惑\\n\u3000状態を付与する。\\n\u3000さらに、物理攻撃力と魔法攻撃力を大ダウンさ\\n\u3000せる。\\n\u3000このスキルによる物理攻撃力と魔法攻撃力ダウ\\n\u3000ン効果はダメージを無効化しても付与される。', 305900, 0, 2, 305900, 270, 0, 0, 16, 0, 2.2, 1000, 'マダムプリズム');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【魔法】圧倒的な魅力を放つ麗しき極彩色の艶鳥。\\nその色香に囚われれば、味方を襲う下僕となる。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。\\n\u3000この防御力アップ効果で上昇した防御力は、バ\\n\u3000トル中に受ける防御力ダウンスキルの影響を受\\n\u3000けない。\\n・ユニオンバーストは、敵全体のバリアを解除し、\\n\u3000敵全体にキャラの最大ＨＰに応じた魔法割合ダ\\n\u3000メージを与える。\\n\u3000さらに、物理攻撃力と魔法攻撃力を大ダウンさ\\n\u3000せる。\\n\u3000キャラのＨＰが70％未満の場合、誘惑状態を\\n\u3000付与する。\\n\u3000このスキルによるダメージでは、敵のＴＰが回\\n\u3000復しない。\\n・前から２キャラに魔法中ダメージを与え、誘惑\\n\u3000状態を付与する。\\n\u3000さらに、物理攻撃力と魔法攻撃力を大ダウンさ\\n\u3000せる。\\n\u3000このスキルによる物理攻撃力と魔法攻撃力ダウ\\n\u3000ン効果はダメージを無効化しても付与される。', 305901, 0, 2, 305901, 270, 0, 0, 16, 0, 2.2, 1000, 'マダムプリズム');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【魔法】圧倒的な魅力を放つ麗しき極彩色の艶鳥。\\nその色香に囚われれば、味方を襲う下僕となる。\\n\\n・マダムプリズムから受けるすべてのダメージで\\n\u3000発生する、パーティキャラのＴＰ回復量を中ダ\\n\u3000ウンさせる。\\n・ユニオンバーストは、敵全体にキャラの最大Ｈ\\n\u3000Ｐに応じた魔法割合ダメージを与える。敵にバ\\n\u3000リアが展開されていない場合、誘惑状態を付与\\n\u3000する。さらに、敵全体の物理攻撃力と魔法攻撃\\n\u3000力を大アップさせる。このスキルによるダメー\\n\u3000ジでは、敵のＴＰが回復しない。\\n・前方範囲内の敵すべてに魔法大ダメージを与え、\\n\u3000誘惑状態を付与する。さらに、物理攻撃のダ\\n\u3000メージ、魔法攻撃のダメージを中ダウンさせる。\\n\u3000このスキルの状態異常はダメージを無効化して\\n\u3000も付与される。', 305902, 0, 2, 305902, 270, 0, 0, 16, 0, 2.2, 1000, 'マダムプリズム');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】邪念の残滓が群集し邪神と化した。\\n顕現した煩悩を全て浄化し、新年を迎えよう！\\n\\n・ユニオンバーストは敵全体に\\n\u3000物理大ダメージを与える。\\n・前方3キャラに魔法中ダメージを与え、\\n\u3000物理攻撃力を下げる。\\n・時限式の爆弾モチを前方中距離に召喚する。\\n・爆弾モチは、召喚されてから\\n\u30008秒後に大爆発し、範囲内の敵全体に\\n\u3000物理中ダメージを与える。\\n\u3000ただし、爆発するまでに爆弾モチ自身の\\n\u3000ＨＰが50％を切ると、\\n\u3000敵全体のＨＰを小回復し、消滅する。\\n・邪餅神ガミィ自身のＨＰが\\n\u300050％を切ると、さらに攻撃が激しく\\n\u3000凶暴になる。', 306000, 0, 1, 306000, 270, 0, 0, 16, 0, 1.6, 2160, '邪餅神ガミィ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】邪念の残滓が群集し邪神と化した。\\n顕現した煩悩を全て浄化し、新年を迎えよう！\\n\\n・ユニオンバーストは敵全体に\\n\u3000物理大ダメージを与える。\\n・前方3キャラに魔法中ダメージを与え、\\n\u3000物理攻撃力を下げる。', 306001, 0, 1, 306000, 270, 0, 0, 16, 0, 1.6, 2160, '邪餅神ガミィ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】邪念の残滓が群集し邪神と化した。\\n顕現した煩悩を全て浄化し、新年を迎えよう！\\n\\n・ユニオンバーストは敵全体に\\n\u3000物理大ダメージを与える。\\n・前方3キャラに魔法中ダメージを与え、\\n\u3000物理攻撃力を下げる。\\n・時限式の爆弾モチを前方中距離に召喚する。\\n・爆弾モチは、召喚されてから\\n\u30008秒後に大爆発し、範囲内の敵全体に\\n\u3000物理中ダメージを与える。\\n\u3000ただし、爆発するまでに爆弾モチ自身の\\n\u3000ＨＰが50％を切ると、\\n\u3000敵全体のＨＰを小回復し、消滅する。\\n・邪餅神ガミィ自身のＨＰが\\n\u300050％を切ると、さらに攻撃が激しく\\n\u3000凶暴になる。', 306002, 0, 1, 306000, 270, 0, 0, 16, 0, 1.6, 2160, '邪餅神ガミィ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】邪念の残滓が群集し邪神と化した。\\n顕現した煩悩を全て浄化し、新年を迎えよう！\\n\\n・ユニオンバーストは敵全体に\\n\u3000物理大ダメージを与える。\\n・前方3キャラに魔法中ダメージを与え、\\n\u3000物理攻撃力を下げる。\\n・時限式の爆弾モチを前方中距離に召喚する。\\n・爆弾モチは、召喚されてから\\n\u30008秒後に大爆発し、範囲内の敵全体に\\n\u3000物理中ダメージを与える。\\n\u3000ただし、爆発するまでに爆弾モチ自身の\\n\u3000ＨＰが50％を切ると、\\n\u3000敵全体のＨＰを小回復し、消滅する。\\n・邪餅神ガミィ自身のＨＰが\\n\u300050％を切ると、さらに攻撃が激しく\\n\u3000凶暴になる。', 306003, 0, 1, 306000, 270, 0, 0, 16, 0, 1.6, 2160, '邪餅神ガミィ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【MODE1】邪念の残滓が群集し邪神と化した。\\n顕現した煩悩を全て浄化し、新年を迎えよう！\\n\\n・邪餅神ガミィ自身が攻撃を受けると、\\n\u3000味方全体のＨＰを小回復し、\\n\u3000邪餅神ガミィ自身のＨＰを全回復する。', 306004, 0, 1, 306004, 270, 0, 0, 16, 0, 0.0, 3000, '邪餅神ガミィ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【MODE2】邪念の残滓が群集し邪神と化した。\\n顕現した煩悩を全て浄化し、新年を迎えよう！\\n\\n・前方1キャラに物理ダメージを与える。\\n・前方範囲内に魔法中ダメージを与え、\\n\u3000大きく吹き飛ばす。\\n・6個の邪念を込めてボンノウ（赤）を召喚する。\\n・3個の邪念を込めてボンノウ（紫）を召喚する。\\n・1個の邪念を込めてボンノウ（青）を召喚する。', 306005, 0, 1, 306005, 270, 0, 0, 16, 0, 1.6, 3000, '邪餅神ガミィ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【MODE3】邪念の残滓が群集し邪神と化した。\\n顕現した煩悩を全て浄化し、新年を迎えよう！\\n\\n・前方1キャラに物理ダメージを与える。\\n・ユニオンバーストは敵全体に\\n\u3000物理大ダメージを与える。\\n・前方3キャラに魔法中ダメージを与え、\\n\u3000物理攻撃力を下げる。\\n・時限式の爆弾モチを前方中距離に召喚する。\\n・爆弾モチは、召喚されてから\\n\u30008秒後に大爆発し、範囲内の敵全体に\\n\u3000物理中ダメージを与える。\\n\u3000ただし、爆発するまでに爆弾モチ自身の\\n\u3000ＨＰが50％を切ると、\\n\u3000敵全体のＨＰを小回復し、消滅する。', 306006, 0, 1, 306006, 270, 0, 0, 16, 0, 1.6, 2160, '邪餅神ガミィ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】邪念の残滓が群集し邪神と化した。\\n顕現した煩悩を全て浄化し、新年を迎えよう！\\n\\n・ユニオンバーストは敵全体に\\n\u3000キャラの最大ＨＰに応じた\\n\u3000物理大ダメージを与える。\\n・前方３キャラに魔法中ダメージを与え、\\n\u3000物理攻撃力を小ダウンさせる。\\n・時限式の爆弾モチを前方中距離に召喚する。\\n・爆弾モチは、召喚されてから\\n\u3000８秒後に大爆発し、範囲内の敵すべてに\\n\u3000物理中ダメージを与える。\\n\u3000ただし、爆発するまでに爆弾モチ自身の\\n\u3000ＨＰが50％を切ると、\\n\u3000敵全体のＨＰを小回復し、消滅する。', 306007, 0, 1, 306000, 270, 0, 0, 16, 0, 1.6, 2160, '邪餅神ガミィ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】邪念の残滓が群集し邪神と化した。\\n顕現した煩悩を全て浄化し、新年を迎えよう！\\n\\n・ユニオンバーストは敵全体に\\n\u3000キャラの最大ＨＰに応じた\\n\u3000物理大ダメージを与える。\\n・前方３キャラに魔法中ダメージを与え、\\n\u3000物理攻撃力を小ダウンさせる。\\n・時限式の爆弾モチを前方中距離に召喚する。\\n・爆弾モチは、召喚されてから\\n\u3000８秒後に大爆発し、範囲内の敵すべてに\\n\u3000物理中ダメージを与える。\\n\u3000ただし、爆発するまでに爆弾モチ自身の\\n\u3000ＨＰが50％を切ると、\\n\u3000敵全体のＨＰを小回復し、消滅する。\\n・邪餅神ガミィ自身のＨＰが\\n\u300050％を切ると、さらに攻撃が激しく\\n\u3000凶暴になる。', 306008, 0, 1, 306000, 270, 0, 0, 16, 0, 1.6, 2160, '邪餅神ガミィ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】邪念の残滓が群集し邪神と化した。\\n顕現した煩悩を全て浄化し、新年を迎えよう！\\n\\n・ユニオンバーストは敵全体に\\n\u3000キャラの最大ＨＰに応じた\\n\u3000物理大ダメージを与える。\\n・前方３キャラに魔法中ダメージを与え、\\n\u3000物理攻撃力を小ダウンさせる。\\n・時限式の爆弾モチを前方中距離に召喚する。\\n・爆弾モチは、召喚されてから\\n\u3000８秒後に大爆発し、範囲内の敵すべてに\\n\u3000物理大ダメージを与える。\\n\u3000ただし、爆発するまでに爆弾モチ自身の\\n\u3000ＨＰが50％を切ると、\\n\u3000敵全体のＨＰを小回復し、消滅する。\\n・邪餅神ガミィ自身のＨＰが\\n\u300050％を切ると、さらに攻撃が激しく\\n\u3000凶暴になる。', 306009, 0, 1, 306000, 270, 0, 0, 16, 0, 1.6, 2160, '邪餅神ガミィ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】邪念の残滓が群集し邪神と化した。\\n顕現した煩悩を全て浄化し、新年を迎えよう！\\n\\n・ユニオンバーストは敵全体に\\n\u3000キャラの最大ＨＰに応じた\\n\u3000物理大ダメージを与える。\\n・前方３キャラに魔法中ダメージを与え、\\n\u3000物理攻撃力を下げる。\\n・時限式の爆弾モチを前方中距離に召喚する。\\n・爆弾モチは、召喚されてから\\n\u3000８秒後に大爆発し、範囲内の敵全体に\\n\u3000物理中ダメージを与える。\\n\u3000ただし、爆発するまでに爆弾モチ自身の\\n\u3000ＨＰが50％を切ると、\\n\u3000敵全体のＨＰを小回復し、消滅する。\\n・邪餅神ガミィ自身のＨＰが\\n\u300060％を切ると、さらに攻撃が激しく\\n\u3000凶暴になる。', 306010, 0, 1, 306000, 270, 0, 0, 16, 0, 1.6, 2160, '邪餅神ガミィ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】闇に紛れ、人里で盗みを\\nはたらく魔物の頭目。\\nくすねたエモノを容赦なく投げつけ\\n開拓の邪魔をするならず者。\\n\\n・前方３キャラに物理中ダメージを\\n\u3000与え、麻痺させる。\\n\\n・敵全体に物理小ダメージを与え、\\n\u3000行動速度を下げる。\\n\u3000さらに、前方小範囲を毒状態\\n\u3000にする。', 306100, 0, 1, 306100, 270, 0, 0, 16, 0, 1.8, 1000, 'ジャッカルシーフ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】闇に紛れ、人里で盗みを働く魔物の頭目。\\nくすねたエモノを器用に使って戦う、ならず者。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・ジャッカルシーフから受けるすべてのダメージ\\n\u3000で発生する、パーティキャラのＴＰ回復量を中\\n\u3000ダウンさせる。\\n・ユニオンバーストは、敵全体に物理大ダメージ\\n\u3000を与え、短時間麻痺状態を付与する。敵キャラ\\n\u3000が毒状態の場合、長時間麻痺状態を付与する。\\n\u3000このスキルによるダメージでは、ＴＰが回復し\\n\u3000ない。このスキルの状態異常はダメージを無効\\n\u3000化しても付与される。\\n・敵全体に物理中ダメージを与え、毒状態を付与\\n\u3000する。このスキルにより付与された毒のダメー\\n\u3000ジでは、ＴＰが回復しない。', 306101, 0, 1, 306101, 270, 0, 0, 16, 0, 1.8, 1000, 'ジャッカルシーフ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】闇に紛れ、人里で盗みを働く魔物の頭目。\\nくすねたエモノを器用に使って戦う、ならず者。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を中アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・バトル開始時、敵全体のＨＰ吸収を特大ダウン\\n\u3000させる。\\n・バトル開始時、敵全体のＴＰ上昇を小ダウンさ\\n\u3000せるフィールドを展開する。\\n・バトル開始時、自身にＴＰダウン50％カット\\n\u3000効果を付与する。\\n・ジャッカルシーフから受けるすべてのダメージ\\n\u3000で発生する、パーティキャラのＴＰ回復量を中\\n\u3000ダウンさせる。\\n・ユニオンバーストは、敵全体に物理大ダメージ\\n\u3000を与え、短時間麻痺状態を付与する。敵キャラ\\n\u3000が毒状態の場合、長時間麻痺状態を付与する。\\n\u3000このスキルによるダメージでは、ＴＰが回復し\\n\u3000ない。このスキルの状態異常はダメージを無効\\n\u3000化しても付与される。\\n・敵全体に物理中ダメージを与え、ＨＰ吸収を特\\n\u3000大ダウンさせ、毒状態を付与する。このスキル\\n\u3000によるダメージでは、ＴＰが回復しない。\\n・通常攻撃は最も近い敵１キャラに物理中ダメー\\n\u3000ジを与え、毒状態を付与し、行動速度を小ダウ\\n\u3000ンさせる。このスキルの状態異常はダメージを\\n\u3000無効化しても付与される。バトル開始後、初弾\\n\u3000の通常攻撃はダメージ量が大幅アップする。\\n・ジャッカルシーフの付与する毒のダメージでは、\\n\u3000キャラのＴＰが回復しない。', 306102, 0, 1, 306102, 270, 0, 0, 16, 0, 1.8, 1000, 'ジャッカルシーフ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】闇に紛れ、人里で盗みを働く魔物の頭目。\\nくすねたエモノを器用に使って戦う、ならず者。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。\\n\u3000この防御力アップ効果で上昇した防御力は、バ\\n\u3000トル中に受ける防御力ダウンスキルの影響を受\\n\u3000けない。\\n・ジャッカルシーフから受けるすべてのダメージ\\n\u3000で発生する、パーティキャラのＴＰ回復量を中\\n\u3000ダウンさせる。\\n・ユニオンバーストは、敵全体に物理大ダメージ\\n\u3000を与え、短時間麻痺状態にする。\\n\u3000毒状態の場合は長時間麻痺状態にする。\\n\u3000このスキルの状態異常はダメージを無効化して\\n\u3000も付与される。\\n\u3000このスキルによるダメージでは、敵のＴＰが回\\n\u3000復しない。\\n・敵全体に物理中ダメージを与え、行動速度を中\\n\u3000ダウンさせる。\\n\u3000さらに、敵全体のＨＰ吸収を特大ダウンさせる。\\n\u3000キャラのＨＰが90％未満の場合、毒状態を付\\n\u3000与する。\\n\u3000このスキルの状態異常はダメージを無効化して\\n\u3000も付与される。\\n\u3000このスキルにより付与された毒のダメージでは、\\n\u3000ＴＰが回復しない。\\n・通常攻撃は最も近い敵１キャラに物理大ダメー\\n\u3000ジを与え、毒状態を付与する。\\n\u3000このスキルにより付与された毒のダメージでは、\\n\u3000ＴＰが回復しない。', 306103, 0, 1, 306103, 270, 0, 0, 16, 0, 1.8, 3000, 'ジャッカルシーフ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】森奥に座し、周辺一帯を\\n手下と共に支配する老獪な大狸。\\nありもしない幻を見せ、精神を蝕む\\n幻影攻撃を巧みに操る。\\n\\n・敵全体に魔法中ダメージを与え、\\n\u3000ワッパダヌキ２体を召喚する。\\n\\n・敵全体に魔法小ダメージを与え、\\n\u3000無敵状態でない召喚モンスターを\\n\u3000消滅させる。\\n\u3000さらに敵のＨＰが40％以下の\\n\u3000場合、麻痺状態にする。', 306200, 0, 1, 306200, 270, 0, 0, 16, 0, 1.8, 1000, 'マスター・センリ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】森奥に座し、一帯を支配する老獪な大狸。\\n口寄せした子狸との多彩な連携で敵を惑わせる。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。\\n\u3000この防御力アップ効果で上昇した防御力は、バ\\n\u3000トル中に受ける防御力ダウンスキルの影響を受\\n\u3000けない。\\n・ユニオンバーストは、敵全体に魔法中ダメージ\\n\u3000を与え、ワッパダヌキ２体を召喚する。\\n\u3000このスキルによるダメージでは、敵のＴＰが回\\n\u3000復しない。\\n・敵全体に魔法小ダメージを与え、ノックバック\\n\u3000し、無敵状態でないワッパダヌキを消滅させる。\\n\u3000さらに敵のＨＰが50％未満の場合、麻痺状態\\n\u3000を付与する。', 306201, 0, 1, 306201, 270, 0, 0, 16, 0, 1.8, 1000, 'マスター・センリ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】森奥に座し、一帯を支配する老獪な大狸。\\n口寄せした子狸との多彩な連携で敵を惑わせる。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。\\n\u3000この防御力アップ効果で上昇した防御力は、バ\\n\u3000トル中に受ける防御力ダウンスキルの影響を受\\n\u3000けない。\\n・ユニオンバーストは、敵全体に魔法中ダメージ\\n\u3000を与え、ワッパダヌキ２体を召喚する。\\n\u3000このスキルによるダメージでは、敵のＴＰが回\\n\u3000復しない。\\n・敵全体に魔法小ダメージを与え、ノックバック\\n\u3000し、無敵状態でないワッパダヌキを消滅させる。\\n\u3000さらに敵のＨＰが50％未満の場合、麻痺状態\\n\u3000を付与する。', 306202, 0, 1, 306202, 270, 0, 0, 16, 0, 1.8, 1000, 'マスター・センリ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】森奥に座し、一帯を支配する老獪な大狸。\\n口寄せした子狸との多彩な連携で敵を惑わせる。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。\\n\u3000この防御力アップ効果で上昇した防御力は、バ\\n\u3000トル中に受ける防御力ダウンスキルの影響を受\\n\u3000けない。\\n・ユニオンバーストは、敵全体に魔法中ダメージ\\n\u3000を与え、ワッパダヌキ２体を召喚する。\\n\u3000このスキルによるダメージでは、敵のＴＰが回\\n\u3000復しない。\\n・敵全体に魔法小ダメージを与え、ノックバック\\n\u3000し、無敵状態でないワッパダヌキを消滅させる。\\n\u3000さらに敵のＨＰが50％未満の場合、麻痺状態\\n\u3000を付与する。', 306203, 0, 1, 306203, 270, 0, 0, 16, 0, 1.8, 1000, 'マスター・センリ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】森奥に座し、一帯を支配する老獪な大狸。\\n口寄せした子狸との多彩な連携で敵を惑わせる。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。\\n\u3000この防御力アップ効果で上昇した防御力は、バ\\n\u3000トル中に受ける防御力ダウンスキルの影響を受\\n\u3000けない。\\n・ユニオンバーストは、敵全体に魔法中ダメージ\\n\u3000を与え、ワッパダヌキ２体を召喚する。\\n\u3000このスキルによるダメージでは、敵のＴＰが回\\n\u3000復しない。\\n・敵全体に魔法小ダメージを与え、ノックバック\\n\u3000し、無敵状態でないワッパダヌキを消滅させる。\\n\u3000さらに敵のＨＰが50％未満の場合、麻痺状態\\n\u3000を付与する。', 306204, 0, 1, 306204, 270, 0, 0, 16, 0, 1.8, 1000, 'マスター・センリ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】ルナの魔力を使いウキキーを統べる仙猿。\\n宝武具の棍を自在に操り、すべての敵をなぎ払う。\\n\\n・敵全体に物理大ダメージを与える。\\n\u3000この攻撃は火傷状態の敵に対して、\\n\u3000ダメージが1.8倍になる。\\n・前方中範囲の敵に物理中ダメージを与える。\\n・前方小範囲の敵に魔法中ダメージを与え、\\n\u3000火傷状態にする。', 306300, 0, 1, 306300, 270, 0, 0, 16, 0, 1.8, 1000, 'マスター・ウキキー');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】ルナの魔力を使いウキキーを統べる仙猿。\\n宝武具の棍を自在に操り、すべての敵をなぎ払う。\\n\\n・敵全体に物理大ダメージを与え、\\n\u3000さらに物理攻撃キャラの物理攻撃力を下げる。\\n\u3000この攻撃は火傷状態の敵に対して、\\n\u3000ダメージが1.8倍になる。\\n・前方中範囲の敵に物理中ダメージを与える。\\n・前方小範囲の敵に魔法中ダメージを与え、\\n\u3000火傷状態にする。', 306301, 0, 1, 306301, 270, 0, 0, 16, 0, 1.8, 1000, 'マスター・ウキキー');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】ルナの魔力を使いウキキーを統べる仙猿。\\n宝武具の棍を自在に操り、すべての敵をなぎ払う。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・マスター・ウキキーから受けるすべてのダメー\\n\u3000ジで発生する、パーティキャラのＴＰ回復量を\\n\u3000中ダウンさせる。\\n・ユニオンバーストは、敵全体にキャラの最大Ｈ\\n\u3000Ｐに応じた物理大ダメージを与え、スタンさせ\\n\u3000る。この攻撃は火傷状態の敵に対して、ダメー\\n\u3000ジが1.5倍になる。このスキルによるダメー\\n\u3000ジでは、敵のＴＰが回復しない。\\n・前方３キャラに物理中ダメージを与える。\\n・前方２キャラに魔法中ダメージを与え、火傷状\\n\u3000態にする。このスキルにより付与された火傷の\\n\u3000ダメージでは、ＴＰが回復しない。\\n・前方１キャラに物理大ダメージを与える。', 306302, 0, 1, 306302, 270, 0, 0, 16, 0, 1.8, 3000, 'マスター・ウキキー');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】ルナの魔力を使いウキキーを統べる仙猿。\\n宝武具の棍を自在に操り、すべての敵をなぎ払う。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・バトル開始時、味方全体の物理防御力と魔法防\\n\u3000御力を特大アップ。\\n・マスター・ウキキーから受けるすべてのダメー\\n\u3000ジで発生する、パーティキャラのＴＰ回復量を\\n\u3000中ダウンさせる。\\n・ユニオンバーストは、敵全体にキャラの最大Ｈ\\n\u3000Ｐに応じた物理大ダメージを与え、スタンさせ\\n\u3000る。この攻撃は火傷状態の敵に対して、ダメー\\n\u3000ジが1.5倍になる。このスキルによるダメー\\n\u3000ジでは、敵のＴＰが回復しない。\\n・前方３キャラに物理中ダメージを与える。\\n・前方２キャラに魔法中ダメージを与え、火傷状\\n\u3000態にする。このスキルにより付与された火傷の\\n\u3000ダメージでは、ＴＰが回復しない。\\n・前方１キャラに物理大ダメージを与える。', 306303, 0, 1, 306303, 270, 0, 0, 16, 0, 1.8, 3000, 'マスター・ウキキー');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】魔力を用いてウキキーを統べる仙猿。\\n宝武具の棍を自在に操り、すべての敵をなぎ払う。\\n\\n・マスター・ウキキーから受けるすべてのダメー\\n\u3000ジで発生する、パーティキャラのＴＰ回復量を\\n\u3000中ダウンさせる。\\n・ユニオンバーストは、敵全体にキャラの最大Ｈ\\n\u3000Ｐに応じた物理割合ダメージを与え、スタン状\\n\u3000態を付与する。このスキルは火傷状態の敵に対\\n\u3000して、ダメージが1.5倍になる。このスキル\\n\u3000によるダメージでは、敵のＴＰが回復しない。\\n・最も近い敵３キャラに物理中ダメージを与える。\\n・最も近い敵２キャラに魔法中ダメージを与え、\\n\u3000火傷状態を付与する。このスキルにより付与さ\\n\u3000れた火傷のダメージでは、ＴＰが回復しない。', 306304, 0, 1, 306304, 270, 0, 0, 16, 0, 1.8, 3000, 'マスター・ウキキー');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】荒れ山の捕食者として君臨\\nする、凶悪な怪鳥獣。\\n狩りを続けることでつくりあげた\\n膂力と剛爪が、侵入者をつけ狙う。\\n\\n・敵全体に物理大ダメージを与え、\\n\u3000ＴＰ上昇をダウンさせる。\\n\u3000発動するたびにダメージがアップ\\n\u3000する。この効果は最大３回まで\\n\u3000累積する。\\n\\n・後ろから２番目の敵を中心にした\\n\u3000小範囲に物理小ダメージを与え、\\n\u3000麻痺状態にする。', 306400, 0, 1, 306400, 270, 0, 0, 16, 0, 3.5, 1000, 'ワイルドクロウ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】荒れ山の捕食者として君臨する、凶悪な\\n怪鳥獣。狩りを続けることでつくりあげた膂力と\\n剛爪が、侵入者をつけ狙う。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。\\n\u3000この防御力アップ効果で上昇した防御力は、バ\\n\u3000トル中に受ける防御力ダウンスキルの影響を受\\n\u3000けない。\\n・ワイルドクロウから受けるすべてのダメージで\\n\u3000発生する、パーティキャラのＴＰ回復量を中ダ\\n\u3000ウンさせる。\\n・ユニオンバーストは、敵全体に物理中ダメージ\\n\u3000を与え、ＴＰ上昇を大ダウンさせる。\\n\u3000このスキルの状態異常はダメージを無効化して\\n\u3000も付与される。\\n・後ろから２番目の敵を中心にした小範囲に物理\\n\u3000大ダメージを与え、麻痺状態にする。', 306401, 0, 1, 306401, 270, 0, 0, 16, 0, 3.5, 1000, 'ワイルドクロウ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】塔の魔力で強化された凶悪な怪鳥獣。\\n捕食者の爪先は一度狙った獲物を決して逃さない。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を中アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・バトル開始時、自身にＴＰダウン50％カット\\n\u3000効果を付与する。\\n・バトル開始時、敵全体のＨＰ吸収を特大ダウン\\n\u3000させる。\\n・自身が一度の行動で受けるダメージ値を減衰さ\\n\u3000せる。ダメージ値が上昇するほど減衰率も上昇\\n\u3000する。\\n・レイザークロウから受けるすべてのダメージで\\n\u3000発生する、パーティキャラのＴＰ回復量を中ダ\\n\u3000ウンさせる。\\n・ユニオンバーストは、敵全体に自身の物理防御\\n\u3000力に応じた物理ダメージを与える。このスキル\\n\u3000によるダメージでは、ＴＰが回復しない。\\n・最も近い敵１キャラを中心にした小範囲に物理\\n\u3000大ダメージを与え、麻痺状態を付与する。さら\\n\u3000に自身の物理防御力をバトル終了まで小アップ\\n\u3000させる。このスキルの状態異常はダメージを無\\n\u3000効化しても付与される。', 306402, 0, 1, 306402, 270, 0, 0, 16, 0, 3.5, 3000, 'レイザークロウ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】荒れ山の捕食者として君臨する、凶悪な\\n怪鳥獣。狩りを続けることでつくりあげた膂力と\\n剛爪が、侵入者をつけ狙う。\\n\\n・ワイルドクロウから受けるすべてのダメージで\\n\u3000発生する、パーティキャラのＴＰ回復量を中ダ\\n\u3000ウンさせる。\\n・ユニオンバーストは、最も近い敵１キャラを中\\n\u3000心にした小範囲に自身の物理防御力に応じた物\\n\u3000理ダメージを与える。このスキルによるダメー\\n\u3000ジでは、ＴＰが回復しない。\\n・最も近い敵１キャラを中心にした小範囲に物理\\n\u3000大ダメージを与え、麻痺状態を付与する。さら\\n\u3000に自身の物理防御力をバトル終了まで小アップ\\n\u3000させる。このスキルの状態異常はダメージを無\\n\u3000効化しても付与される。', 306403, 0, 1, 306403, 270, 0, 0, 16, 0, 3.5, 3000, 'ワイルドクロウ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】辺境の森のオークたちの\\n首魁。独自の民族性の奇怪な\\nリズムを撒き散らす。その怪音は、\\n敵対者を混迷の渦に突き落とす。\\n\\n・敵全体に物理大ダメージを与え、\\n\u3000物理防御力と魔法防御力をダウン\\n\u3000さらに自身の物理攻撃力と\\n\u3000魔法攻撃力をアップする。\\n\\n・前方４キャラに魔法小ダメージを\\n\u3000与え、敵のＨＰが70％以下の\\n\u3000場合、混乱状態にする。', 306500, 0, 1, 306500, 270, 0, 0, 16, 0, 0.9, 1000, 'トライバルオーク');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】ルナの塔の力に魅せられたオークの首魁。\\n奇怪なリズムの太鼓で、戦場に騒乱を引き起こす。\\n\\n・敵全体に物理大ダメージを与え、物理防御力と\\n\u3000魔法防御力をダウンさせる。さらに、自分の\\n\u3000物理攻撃力と魔法攻撃力をアップさせる。\\n・前方３キャラに魔法小ダメージを与え、\\n\u3000小さく吹き飛ばす。敵のＨＰが70％未満の\\n\u3000場合、混乱状態にする。\\n・敵全体に残りＨＰに応じた魔法大ダメージを\\n\u3000与え、行動速度をダウンさせる。\\n\u3000さらに、敵全体のステータスアップ効果を\\n\u3000解除する。', 306501, 0, 1, 306501, 270, 0, 0, 16, 0, 0.9, 1000, 'ノイジーオーク');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】獲物を求め水辺を猛毒\\nで満たす、サンショウウオの魔物。\\n漏れるほどに溜め込んだ猛毒は、\\n近づくだけで意識を奪う危険物。\\n\\n・敵全体に魔法中ダメージを与え、\\n\u3000毒状態にする。\\n\u3000さらに猛毒状態にする。\\n\\n・最も近い敵を中心とした\\n\u3000範囲内の敵すべてに魔法\\n\u3000小ダメージを与え、\\n\u3000猛毒状態にする。', 306600, 0, 1, 306600, 270, 0, 0, 16, 0, 1.8, 1000, 'ベノムサラマンドラ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】悪罵で暴走した、巨大なチョコの魔物。\\nささやく愛も誤れば、人を傷つける刃と化す。\\n\\n・ユニオンバーストは、敵全体にキャラの\\n\u3000最大ＨＰに応じた物理大ダメージを与え、\\n\u3000火傷状態の場合は、さらに追加ダメージ。\\n・前方3キャラに物理中ダメージを与え、スタン\\n\u3000させる。\\n\u3000さらにキャラのＨＰが50％以下の場合、\\n\u3000火傷状態にする。\\n・アグリーラブリー自身のＨＰが\\n\u300050％を切ると、さらに攻撃が激しく\\n\u3000凶暴になる。', 306700, 0, 1, 306700, 270, 0, 0, 16, 0, 1.8, 2160, 'アグリーラブリー');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】悪罵で暴走した、巨大なチョコの魔物。\\nささやく愛も誤れば、人を傷つける刃と化す。\\n\\n・ユニオンバーストは、敵全体にキャラの\\n\u3000最大ＨＰに応じた物理大ダメージを与え、\\n\u3000火傷状態の場合は、さらに追加ダメージ。\\n・前方3キャラに物理中ダメージを与え、スタン\\n\u3000させる。\\n\u3000さらにキャラのＨＰが50％以下の場合、\\n\u3000火傷状態にする。', 306701, 0, 1, 306700, 270, 0, 0, 16, 0, 1.8, 2160, 'アグリーラブリー');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】悪罵で暴走した、巨大なチョコの魔物。\\nささやく愛も誤れば、人を傷つける刃と化す。\\n\\n・ユニオンバーストは、敵全体にキャラの\\n\u3000最大ＨＰに応じた物理大ダメージを与え、\\n\u3000火傷状態の場合は、さらに追加ダメージ。\\n・前方3キャラに物理中ダメージを与え、スタン\\n\u3000させる。\\n\u3000さらにキャラのＨＰが50％以下の場合、\\n\u3000火傷状態にする。\\n・アグリーラブリー自身のＨＰが\\n\u300050％を切ると、さらに攻撃が激しく\\n\u3000凶暴になる。', 306702, 0, 1, 306700, 270, 0, 0, 16, 0, 1.8, 2160, 'アグリーラブリー');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】悪罵で暴走した、巨大なチョコの魔物。\\nささやく愛も誤れば、人を傷つける刃と化す。\\n\\n・ユニオンバーストは、敵全体にキャラの\\n\u3000最大ＨＰに応じた物理大ダメージを与え、\\n\u3000火傷状態の場合は、さらに追加ダメージ。\\n・前方3キャラに物理中ダメージを与え、スタン\\n\u3000させる。\\n\u3000さらにキャラのＨＰが50％以下の場合、\\n\u3000火傷状態にする。\\n・アグリーラブリー自身のＨＰが\\n\u300050％を切ると、さらに攻撃が激しく\\n\u3000凶暴になる。', 306703, 0, 1, 306700, 270, 0, 0, 16, 0, 1.8, 2160, 'アグリーラブリー');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【MODE1】チョコを大噴射し、身を覆い隠す。\\n敵の攻撃を受け続け、憤怒の一撃を炸裂する。\\n\\n・敵全体に物理小ダメージを与え、バトル中の間\\n\u3000火傷状態にする。\\n・チョコドームにこもっている間は、アグリー\\n\u3000ラブリー自身の物理防御力を中アップする。\\n\u3000チョコドーム状態を解除したのち、この状態の\\n\u3000間に受けたダメージ量に応じた\\n\u3000物理ダメージを与える。\\n\u3000さらにアグリーラブリー自身の物理防御力を\\n\u3000大ダウンする。', 306704, 0, 1, 306700, 270, 0, 0, 16, 0, 1.8, 3000, 'アグリーラブリー');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【MODE2】カカオウラは奮起し、\\n 死地に飛び込む。\\n 激化する魔物の攻撃から、\\n 大切な者たちを守るため。\\n\\n・ユニオンバーストは、敵全体にキャラの\\n\u3000最大ＨＰに応じた物理大ダメージを与え、\\n・カカオウラがキャラの味方として出現する。\\n\u3000カカオウラ出現中は、キャラ全体の物理\\n\u3000攻撃力と魔法攻撃力と行動速度が中アップする。\\n・敵全体に魔法小ダメージを与え、\\n\u3000行動速度を大ダウンさせる。\\n', 306705, 0, 1, 306700, 270, 0, 0, 16, 0, 1.8, 3000, 'アグリーラブリー');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【MODE3】轟々たる咆哮が、会場を包み込む。\\n愛憎渦巻くバレンタイン事変もいよいよ終局。\\n\\n・ユニオンバーストは、敵全体にキャラの\\n\u3000最大ＨＰに応じた物理大ダメージを与え、\\n\u3000火傷状態の場合は、さらに追加ダメージ。\\n・前方3キャラに物理中ダメージを与え、スタン\\n\u3000させる。\\n\u3000キャラのＨＰが50％以下の場合、\\n\u3000火傷状態にする。', 306706, 0, 1, 306700, 270, 0, 0, 16, 0, 1.8, 2160, 'アグリーラブリー');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】悪罵で暴走した、巨大なチョコの魔物。\\nささやく愛も誤れば、人を傷つける刃と化す。\\n\\n・ユニオンバーストは、敵全体にキャラの\\n\u3000最大ＨＰに応じた物理大ダメージを与え、\\n\u3000火傷状態の場合は、さらに追加ダメージ。\\n・前方３キャラにキャラの最大ＨＰに応じた\\n\u3000物理中ダメージを与え、さらに火傷状態に\\n\u3000する。', 306708, 0, 1, 306700, 270, 0, 0, 16, 0, 1.8, 2160, 'アグリーラブリー');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】悪罵で暴走した、巨大なチョコの魔物。\\nささやく愛も誤れば、人を傷つける刃と化す。\\n\\n・ユニオンバーストは、敵全体にキャラの\\n\u3000最大ＨＰに応じた物理大ダメージを与え、\\n\u3000火傷状態の場合は、さらに追加ダメージ。\\n・前方３キャラにキャラの最大ＨＰに応じた\\n\u3000物理中ダメージを与え、さらに火傷状態に\\n\u3000する。\\n・アグリーラブリー自身のＨＰが\\n\u300045％を切ると、さらに攻撃が激しく\\n\u3000凶暴になる。', 306709, 0, 1, 306700, 270, 0, 0, 16, 0, 1.8, 2160, 'アグリーラブリー');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】悪罵で暴走した、巨大なチョコの魔物。\\nささやく愛も誤れば、人を傷つける刃と化す。\\n\\n・ユニオンバーストは、敵全体にキャラの\\n\u3000最大ＨＰに応じた物理大ダメージを与え、\\n\u3000火傷状態の場合は、さらに追加ダメージ。\\n・前方３キャラにキャラの最大ＨＰに応じた\\n\u3000物理中ダメージを与え、さらに火傷状態に\\n\u3000する。\\n・アグリーラブリー自身のＨＰが\\n\u300045％を切ると、さらに攻撃が激しく\\n\u3000凶暴になる。', 306710, 0, 1, 306700, 270, 0, 0, 16, 0, 1.8, 2160, 'アグリーラブリー');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【MODE1】チョコを大噴射し、身を覆い隠す。\\n敵の攻撃を受け続け、憤怒の一撃を炸裂する。\\n\\n・敵全体に物理小ダメージを与え、バトル中の間\\n\u3000火傷状態にする。\\n・チョコドームにこもっている間は、アグリー\\n\u3000ラブリー自身の物理防御力を中アップする。\\n\u3000チョコドーム状態を解除したのち、この状態の\\n\u3000間に受けたダメージ量に応じた\\n\u3000物理ダメージを与える。\\n\u3000さらにアグリーラブリー自身の物理防御力を\\n\u3000大ダウンする。', 306711, 0, 1, 306700, 270, 0, 0, 16, 0, 1.8, 3000, 'アグリーラブリー');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【MODE2】カカオウラは奮起し、\\n 死地に飛び込む。\\n 激化する魔物の攻撃から、\\n 大切な者たちを守るため。\\n\\n・ユニオンバーストは、敵全体にキャラの\\n\u3000最大ＨＰに応じた物理大ダメージを与える。\\n・カカオウラがキャラの味方として出現する。\\n\u3000カカオウラ出現中は、キャラ全体の物理\\n\u3000攻撃力と魔法攻撃力と行動速度が中アップする。\\n・敵全体に魔法小ダメージを与え、\\n\u3000行動速度を大ダウンさせる。\\n', 306712, 0, 1, 306700, 270, 0, 0, 16, 0, 1.8, 3000, 'アグリーラブリー');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【MODE3】轟々たる咆哮が、会場を包み込む。\\n愛憎渦巻くバレンタイン事変もいよいよ終局。\\n\\n・ユニオンバーストは、敵全体にキャラの\\n\u3000最大ＨＰに応じた物理大ダメージを与え、\\n\u3000火傷状態の場合は、さらに追加ダメージ。\\n・前方3キャラに物理中ダメージを与え、スタン\\n\u3000させる。\\n\u3000キャラのＨＰが50％以下の場合、\\n\u3000火傷状態にする。\\n・バトル開始直後に、自身の物理攻撃力と\\n\u3000行動速度をアップさせる。', 306713, 0, 1, 306700, 270, 0, 0, 16, 0, 1.8, 2160, 'アグリーラブリー');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【魔法】失意と絶望で、魔に堕ちた悲哀の王女。\\n慟哭を求め、恐怖と呪詛ですべてを満たす。\\n\\n・ユニオンバーストは、敵全体にキャラの\\n\u3000最大ＨＰに応じた魔法大ダメージを与え、\\n\u3000魔法防御力を下げる。\\n・前方２番目、３番目のキャラに魔法\\n\u3000中ダメージを与え、スタンさせる。\\n・前方２キャラに魔法小ダメージを与え、\\n\u3000物理攻撃力を下げ、ＴＰを減少させる。\\n\u3000さらに呪い状態にする。\\n・嘆きの女神自身のＨＰが\\n\u300040％を切ると、さらに攻撃が激しく\\n\u3000凶暴になる。', 306800, 0, 2, 306800, 270, 0, 0, 16, 0, 1.6, 3000, '嘆きの女神');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【魔法】失意と絶望で、魔に堕ちた悲哀の王女。\\n慟哭を求め、恐怖と呪詛ですべてを満たす。\\n\\n・ユニオンバーストは、敵全体にキャラの\\n\u3000最大ＨＰに応じた魔法大ダメージを与え、\\n\u3000魔法防御力を下げる。\\n・前方２番目、３番目のキャラに魔法\\n\u3000中ダメージを与え、スタンさせる。', 306801, 0, 2, 306800, 270, 0, 0, 16, 0, 1.6, 3000, '嘆きの女神');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【魔法】失意と絶望で、魔に堕ちた悲哀の王女。\\n慟哭を求め、恐怖と呪詛ですべてを満たす。\\n\\n・ユニオンバーストは、敵全体にキャラの\\n\u3000最大ＨＰに応じた魔法大ダメージを与え、\\n\u3000魔法防御力を下げる。\\n・前方２番目、３番目のキャラに魔法\\n\u3000中ダメージを与え、スタンさせる。\\n・前方２キャラに魔法小ダメージを与え、\\n\u3000物理攻撃力を下げ、ＴＰを減少させる。\\n\u3000さらに呪い状態にする。\\n\u3000このスキルの状態異常はダメージを\\n\u3000無効化しても付与される。\\n・嘆きの女神自身のＨＰが\\n\u300040％を切ると、さらに攻撃が激しく\\n\u3000凶暴になる。', 306802, 0, 2, 306800, 270, 0, 0, 16, 0, 1.6, 3000, '嘆きの女神');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【魔法】失意と絶望で、魔に堕ちた悲哀の王女。\\n慟哭を求め、恐怖と呪詛ですべてを満たす。\\n\\n・ユニオンバーストは、敵全体にキャラの\\n\u3000最大ＨＰに応じた魔法大ダメージを与え、\\n\u3000魔法防御力を下げる。\\n・前方２番目、３番目のキャラに魔法\\n\u3000中ダメージを与え、スタンさせる。\\n・前方２キャラに魔法小ダメージを与え、\\n\u3000物理攻撃力を下げ、ＴＰを減少させる。\\n\u3000さらに呪い状態にする。\\n\u3000このスキルの状態異常はダメージを\\n\u3000無効化しても付与される。\\n・嘆きの女神自身のＨＰが\\n\u300040％を切ると、さらに攻撃が激しく\\n\u3000凶暴になる。', 306803, 0, 2, 306800, 270, 0, 0, 16, 0, 1.6, 3000, '嘆きの女神');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【MODE1】【自警団（カォン）】メンバーをシャドウとして召喚。\\n絆の断絶を目論み、挑みし者の心の弱さを突く。\\n\\n・シャドウを出現させる\\n・嘆きの女神自身は攻撃行動をとらない。', 306804, 0, 2, 306800, 270, 0, 0, 16, 0, 1.6, 3000, '嘆きの女神');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【MODE2】永久の闇で周囲を満たすべく、\\n\u3000持ちうる呪詛呪言で、冒険者のすべてを\\n\u3000阻み続ける。\\n\\n・ユニオンバーストは、敵全体にキャラの\\n\u3000最大ＨＰに応じた魔法大ダメージを与え、\\n\u3000魔法防御力を下げる。\\n・前方３キャラに魔法小ダメージを与え、\\n\u3000物理防御力を下げ、ＴＰを減少させ\\n\u3000取得率も下げる。\\n\u3000さらに呪い、混乱状態にさせ行動速度を下げる。\\n\u3000このスキルの状態異常はダメージを\\n\u3000無効化しても付与される。\\n・嘆きの女神自身の物理防御力を下げる。\\n\u3000さらに呪い状態になり、ＴＰが減少する。', 306805, 0, 2, 306800, 270, 0, 0, 16, 0, 1.6, 3000, '嘆きの女神');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【MODE3】狂気に満ちた悲哀は、女王の真の\u3000姿を解き放つ。呪われし願いは、一縷の希望も\u3000赦さない。\\n\\n・ユニオンバーストは、敵全体にキャラの\\n\u3000最大ＨＰに応じた魔法大ダメージを与え、\\n\u3000魔法防御力を下げる。\\n・前方２番目、３番目のキャラに魔法\\n\u3000中ダメージを与え、スタンさせる。\\n・前方２キャラに魔法小ダメージを与え、\\n\u3000物理攻撃力を下げ、ＴＰを減少させる。\\n\u3000さらに呪い状態にする。\\n\u3000このスキルの状態異常はダメージを\\n\u3000無効化しても付与される。', 306806, 0, 2, 306800, 270, 0, 0, 16, 0, 1.6, 3000, '嘆きの女神');
