insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【魔法】失意と絶望で、魔に堕ちた悲哀の王女。\\n慟哭を求め、恐怖と呪詛ですべてを満たす。\\n\\n・ユニオンバーストは、敵全体にキャラの\\n\u3000最大ＨＰに応じた魔法大ダメージを与え、\\n\u3000魔法防御力を下げる。\\n・前方２番目、３番目のキャラにキャラの\\n\u3000最大ＨＰに応じた魔法中ダメージを与え、\\n\u3000スタンさせる。', 306808, 0, 2, 306807, 270, 0, 0, 16, 0, 1.6, 3000, '嘆きの女神');
