insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【MODE3】狂気に満ちた悲哀は、女王の真の\u3000姿を解き放つ。呪われし願いは、一縷の希望も\u3000赦さない。\\n\\n・ユニオンバーストは、敵全体にキャラの\\n\u3000最大ＨＰに応じた魔法大ダメージを与え、\\n\u3000魔法防御力を下げる。\\n・前方２番目、３番目のキャラに魔法\\n\u3000中ダメージを与え、スタンさせる。\\n・前方２キャラに魔法小ダメージを与え、\\n\u3000物理攻撃力を下げ、ＴＰを減少させる。\\n\u3000さらに呪い状態にする。\\n\u3000このスキルの状態異常はダメージを\\n\u3000無効化しても付与される。\\n・バトル開始直後に、自身の魔法攻撃力と\\n\u3000行動速度をアップさせる。', 306813, 0, 2, 306800, 270, 0, 0, 16, 0, 1.6, 3000, '嘆きの女神');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【魔法】かつて人々に祀られていた三戦士の石像。\\nそれぞれが能力を高め合い、必殺の一撃を放つ。\\n\\n・物理攻撃力ダウンと魔法攻撃力ダウン効果の\\n影響を受けやすい。\\n・自身の物理攻撃力と魔法攻撃力を\\n\u3000極大アップさせ、敵全体に物理中ダメージと\\n\u3000魔法中ダメージを与える。\\n・前方範囲内の敵に魔法小ダメージ。\\n・敵全体に物理中ダメージ。', 306900, 0, 2, 306900, 270, 0, 0, 16, 0, 1.8, 1000, 'トライロッカー');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【魔法】かつて人々に祀られていた三戦士の石像。\\nそれぞれが能力を高め合い、必殺の一撃を放つ。\\n\\n・物理攻撃力ダウンと魔法攻撃力ダウン効果の影\\n\u3000響を受けやすい。\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・トライロッカーから受けるすべてのダメージで\\n\u3000発生する、パーティキャラのＴＰ回復量を中ダ\\n\u3000ウンさせる。\\n・ユニオンバーストは、敵全体に自身の物理攻撃\\n\u3000力に応じた物理割合ダメージと自身の魔法攻撃\\n\u3000力に応じた魔法割合ダメージを与え、自身の物\\n\u3000理攻撃力と魔法攻撃力を大アップさせる。この\\n\u3000スキルによるダメージでは、ＴＰが回復しない。\\n・敵全体に物理大ダメージを与え、さらに自身の\\n\u3000物理攻撃力に応じて物理攻撃をする敵全体の物\\n\u3000理攻撃力をダウンさせ、自身の魔法攻撃力に応\\n\u3000じて魔法攻撃をする敵全体の魔法攻撃力をダウ\\n\u3000ンさせる。このスキルの状態異常はダメージを\\n\u3000無効化しても付与される。\\n・通常攻撃は、最も近い敵１キャラに自身の物理\\n\u3000攻撃力に応じた物理固定ダメージと自身の魔法\\n\u3000攻撃力に応じた魔法固定ダメージを与える。', 306901, 0, 2, 306901, 270, 0, 0, 16, 0, 1.8, 3000, 'トライロッカー');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【魔法】かつて人々に祀られていた三戦士の石像。\\nそれぞれが能力を高め合い、必殺の一撃を放つ。\\n\\n・物理攻撃力ダウンと魔法攻撃力ダウン効果の影\\n\u3000響を受けやすい。\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を中アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・バトル開始時、敵全体のＴＰ上昇を小ダウンさ\\n\u3000せるフィールドを展開する。\\n・バトル開始時、自身にＴＰダウン50％カット\\n\u3000効果を付与する。\\n・トライロッカーから受けるすべてのダメージで\\n\u3000発生する、パーティキャラのＴＰ回復量を中ダ\\n\u3000ウンさせる。\\n・敵から受けるすべてのダメージで発生する、ト\\n\u3000ライロッカーのＴＰ回復量が大ダウンする。\\n・ユニオンバーストは、敵全体に自身の物理攻撃\\n\u3000力に応じた物理割合ダメージと自身の魔法攻撃\\n\u3000力に応じた魔法割合ダメージを与え、自身の物\\n\u3000理攻撃力と魔法攻撃力を大アップさせる。この\\n\u3000スキルによるダメージでは、ＴＰが回復しない。\\n・敵全体に物理大ダメージを与え、さらに自身の\\n\u3000物理攻撃力に応じて物理攻撃をする敵全体の物\\n\u3000理攻撃力をダウンさせ、自身の魔法攻撃力に応\\n\u3000じて魔法攻撃をする敵全体の魔法攻撃力をダウ\\n\u3000ンさせる。このスキルによるダメージでは、\\n\u3000ＴＰが回復しない。このスキルの状態異常はダ\\n\u3000メージを無効化しても付与される。\\n・通常攻撃は、最も近い敵１キャラに自身の物理\\n\u3000攻撃力に応じた物理固定ダメージと自身の魔法\\n\u3000攻撃力に応じた魔法固定ダメージを与える。', 306902, 0, 2, 306902, 270, 0, 0, 16, 0, 1.8, 3000, 'トライロッカー');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【魔法】かつて人々に祀られていた三戦士の石像。\\nそれぞれが能力を高め合い、必殺の一撃を放つ。\\n\\n・物理攻撃力ダウンと魔法攻撃力ダウン効果の影\\n\u3000響を受けやすい。\\n・ユニオンバーストは、敵全体に自身の物理攻撃\\n\u3000力に応じた物理割合ダメージと自身の魔法攻撃\\n\u3000力に応じた魔法割合ダメージを与え、自身の物\\n\u3000理攻撃力と魔法攻撃力を大アップさせる。この\\n\u3000スキルによるダメージでは、ＴＰが回復しない。\\n・敵全体に物理大ダメージを与え、さらに自身の\\n\u3000物理攻撃力に応じて物理攻撃をする敵全体の物\\n\u3000理攻撃力をダウンさせ、自身の魔法攻撃力に応\\n\u3000じて魔法攻撃をする敵全体の魔法攻撃力をダウ\\n\u3000ンさせる。このスキルによるダメージでは、\\n\u3000ＴＰが回復しない。このスキルの状態異常はダ\\n\u3000メージを無効化しても付与される。\\n・通常攻撃は、最も近い敵１キャラに自身の物理\\n\u3000攻撃力に応じた物理固定ダメージと自身の魔法\\n\u3000攻撃力に応じた魔法固定ダメージを与える。こ\\n\u3000のスキルによるダメージでは、ＴＰ回復量が中\\n\u3000ダウンする。', 306903, 0, 2, 306903, 270, 0, 0, 16, 0, 1.8, 3000, 'トライロッカー');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【魔法】かつて人々に祀られていた三戦士の石像。\\nそれぞれが能力を高め合い、必殺の一撃を放つ。\\n\\n・トライロッカーから受けるすべてのダメージで\\n\u3000発生する、パーティキャラのＴＰ回復量を中ダ\\n\u3000ウンさせる。\\n・物理攻撃力ダウンと魔法攻撃力ダウン効果の影\\n\u3000響を受けやすい。\\n・ユニオンバーストは、敵全体に自身の物理攻撃\\n\u3000力に応じた物理割合ダメージと自身の魔法攻撃\\n\u3000力に応じた魔法割合ダメージを与え、自身の物\\n\u3000理攻撃力と魔法攻撃力を特大アップさせる。こ\\n\u3000のスキルによるダメージではＴＰが回復しない。\\n・最も近い敵１キャラに自身の物理攻撃力に応じ\\n\u3000た物理固定ダメージと自身の魔法攻撃力に応じ\\n\u3000た魔法固定ダメージを与える。\\n・通常攻撃は、敵全体に物理大ダメージを与え、\\n\u3000さらに自身の物理攻撃力に応じて物理攻撃をす\\n\u3000る敵全体の物理攻撃力をダウンさせ、自身の魔\\n\u3000法攻撃力に応じて魔法攻撃をする敵全体の魔法\\n\u3000攻撃力をダウンさせる。このスキルによるダ\\n\u3000メージでは、ＴＰが回復しない。このスキルの\\n\u3000効果はダメージを無効化しても付与される。', 306904, 0, 2, 306904, 270, 0, 0, 16, 0, 1.8, 3000, 'トライロッカー');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('', 307000, 0, 1, 307000, 270, 0, 0, 16, 0, 1.8, 3000, 'コア・ギガース');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】異界の魔石から生まれた、弩級の巨人。\\n強靭な肉体を武器に、苛烈な猛攻を繰り出す。\\n\\n・物理攻撃力アップ・ダウン効果の影響を受け\\n\u3000やすい。\\n・ユニオンバーストは、敵全体に物理大ダメージ。\\n・前方３キャラに物理中ダメージ。\\n・敵全体に物理ダメージを与え、大きくノック\\n\u3000バックさせる。', 307001, 0, 1, 307000, 270, 0, 0, 16, 0, 1.8, 3000, 'コア・ギガース');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('', 307002, 0, 1, 307002, 270, 0, 0, 16, 0, 1.8, 3000, 'コア・ギガース');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】異界の魔石から生まれた、弩級の巨人。\\n強靭な肉体を武器に、苛烈な猛攻を繰り出す。\\n\\n・物理攻撃力アップ・ダウン効果の影響を受け\\n\u3000やすい。\\n・ユニオンバーストは、敵全体に物理大ダメージ。\\n・前方３キャラに物理中ダメージ。\\n・一定時間防御の構えをとったあと、その間に受\\n\u3000けたダメージ量に応じた物理ダメージを敵全体\\n\u3000に与え、前方２キャラを麻痺させる。\\n\u3000さらに、自身の物理攻撃力をアップ。\\n・敵全体に物理ダメージを与え、大きくノック\\n\u3000バックさせる。\\n・コア・ギガース自身のＨＰが40％を切ると\\n\u3000さらに攻撃が激しく凶暴になる。', 307003, 0, 1, 307002, 270, 0, 0, 16, 0, 1.8, 3000, 'コア・ギガース');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】異界の魔石から生まれた、弩級の巨人。\\n強靭な肉体を武器に、苛烈な猛攻を繰り出す。\\n\\n・物理攻撃力アップ・ダウン効果の影響を受け\\n\u3000やすい。\\n・ユニオンバーストは、敵全体に物理大ダメージ。\\n・前方３キャラに物理中ダメージ。\\n・一定時間防御の構えをとったあと、その間に受\\n\u3000けたダメージ量に応じた物理ダメージを敵全体\\n\u3000に与え、前方２キャラを麻痺させる。\\n\u3000さらに、自身の物理攻撃力をアップ。\\n・敵全体に物理ダメージを与え、大きくノック\\n\u3000バックさせる。\\n・コア・ギガース自身のＨＰが40％を切ると\\n\u3000さらに攻撃が激しく凶暴になる。', 307004, 0, 1, 307002, 270, 0, 0, 16, 0, 1.8, 3000, 'コア・ギガース');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【MODE1】【美食殿】メンバーをシャドウ\\nとして召喚。旅の思い出を盾に、３人の心の\\n弱さを試す。\\n\\n・シャドウを出現させる\\n・前方３キャラに物理中ダメージ。\\n・敵全体に物理ダメージを与え、大きくノック\\n\u3000バックさせる。', 307005, 0, 1, 307002, 270, 0, 0, 16, 0, 5.0, 3000, 'コア・ギガース');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【MODE2】強靭な肉体であらゆる攻撃を\\n耐え凌ぐ。その怒りを糧に、巨人は\\n怒涛の大反撃を見舞う。\\n\\n・物理攻撃力アップ・ダウン効果の影響を受け\\n\u3000やすい。\\n・ユニオンバーストは、敵全体に物理大ダメージ。\\n・前方３キャラに物理中ダメージ。\\n・一定時間防御の構えをとったあと、その間に受\\n\u3000けたダメージ量に応じた物理ダメージを敵全体\\n\u3000に与え、前方２キャラを麻痺させる。\\n\u3000さらに、自身の物理攻撃力をアップ。', 307006, 0, 1, 307002, 270, 0, 0, 16, 0, 5.0, 3000, 'コア・ギガース');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【MODE3】弩級の巨人は、全身全霊の力を\\n解放する。強大無比な破壊力を前に\\n小手先の攻撃は通じない。\\n\\n・物理攻撃力アップ・ダウン効果の影響を受け\\n\u3000やすい。\\n・ユニオンバーストは、敵全体に物理大ダメージ。\\n・前方３キャラに物理中ダメージ。\\n・一定時間防御の構えをとったあと、その間に受\\n\u3000けたダメージ量に応じた物理ダメージを敵全体\\n\u3000に与え、前方２キャラを麻痺させる。\\n\u3000さらに、自身の物理攻撃力をアップ。\\n・敵全体に物理ダメージを与え、大きくノック\\n\u3000バックさせる。', 307007, 0, 1, 307002, 270, 0, 0, 16, 0, 3.0, 3000, 'コア・ギガース');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('', 307008, 0, 1, 307000, 270, 0, 0, 16, 0, 1.8, 3000, 'コア・ギガース');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】異界の魔石から生まれた、弩級の巨人。\\n強靭な肉体を武器に、苛烈な猛攻を繰り出す。\\n\\n・物理攻撃力アップ・ダウン効果の影響を受け\\n\u3000やすい。\\n・ユニオンバーストは、敵全体にキャラの\\n\u3000最大ＨＰに応じた物理大ダメージ。\\n・前方３キャラに物理中ダメージ。\\n・敵全体に物理中ダメージを与え、大きくノック\\n\u3000バックさせる。', 307009, 0, 1, 307000, 270, 0, 0, 16, 0, 1.8, 3000, 'コア・ギガース');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】異界の魔石から生まれた、弩級の巨人。\\n強靭な肉体を武器に、苛烈な猛攻を繰り出す。\\n\\n・物理攻撃力アップ・ダウン効果の影響を受け\\n\u3000やすい。\\n・ユニオンバーストは、敵全体にキャラの\\n\u3000最大ＨＰに応じた物理大ダメージ。\\n・前方３キャラに物理中ダメージ。\\n・敵全体に物理中ダメージを与え、大きくノック\\n\u3000バックさせる。\\n・一定時間防御の構えをとったあと、その間に受\\n\u3000けたダメージ量に応じた物理ダメージを\\n\u3000飛行状態のキャラを含む敵全体に与える。\\n\u3000さらに敵全体に物理ダメージを与え、\\n\u3000行動速度をダウンさせる。\\n\u3000さらに、前方２キャラを麻痺させ、自身の\\n\u3000物理攻撃力をアップ。\\n・コア・ギガース自身のＨＰが35％を切ると\\n\u3000さらに攻撃が激しく凶暴になる。', 307010, 0, 1, 307008, 270, 0, 0, 16, 0, 1.8, 3000, 'コア・ギガース');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】異界の魔石から生まれた、弩級の巨人。\\n強靭な肉体を武器に、苛烈な猛攻を繰り出す。\\n\\n・物理攻撃力アップ・ダウン効果の影響を受け\\n\u3000やすい。\\n・ユニオンバーストは、敵全体にキャラの\\n\u3000最大ＨＰに応じた物理大ダメージ。\\n・前方３キャラに物理中ダメージ。\\n・敵全体に物理中ダメージを与え、大きくノック\\n\u3000バックさせる。\\n・一定時間防御の構えをとったあと、その間に受\\n\u3000けたダメージ量に応じた物理ダメージを\\n\u3000飛行状態のキャラを含む敵全体に与える。\\n\u3000さらに敵全体に物理ダメージを与え、\\n\u3000行動速度をダウンさせる。\\n\u3000さらに、前方２キャラを麻痺させ、自身の\\n\u3000物理攻撃力をアップ。\\n・コア・ギガース自身のＨＰが35％を切ると\\n\u3000さらに攻撃が激しく凶暴になる。', 307011, 0, 1, 307008, 270, 0, 0, 16, 0, 1.8, 3000, 'コア・ギガース');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】異界の魔石から生まれた、弩級の巨人。\\n強靭な肉体を武器に、苛烈な猛攻を繰り出す。\\n\\n・物理攻撃力アップ・ダウン効果の影響を受け\\n\u3000やすい。\\n・ユニオンバーストは、敵全体にキャラの\\n\u3000最大ＨＰに応じた物理大ダメージ。\\n・前方３キャラに物理中ダメージ。\\n・一定時間防御の構えをとったあと、その間に受\\n\u3000けたダメージ量に応じた物理ダメージを敵全体\\n\u3000に与え、行動速度をダウンさせる。\\n\u3000さらに、前方２キャラを麻痺させ、自身の\\n\u3000物理攻撃力をアップ。\\n・敵全体に物理中ダメージを与え、大きくノック\\n\u3000バックさせる。\\n・コア・ギガース自身のＨＰが35％を切ると\\n\u3000さらに攻撃が激しく凶暴になる。', 307012, 0, 1, 307008, 270, 0, 0, 16, 0, 1.8, 3000, 'コア・ギガース');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【MODE1】【美食殿】メンバーをシャドウ\\nとして召喚。旅の思い出を盾に、３人の心の\\n弱さを試す。\\n\\n・前方３キャラに物理中ダメージ。\\n・敵全体に物理中ダメージを与え、大きくノック\\n\u3000バックさせる。', 307013, 0, 1, 307002, 270, 0, 0, 16, 0, 5.0, 3000, 'コア・ギガース');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【MODE2】強靭な肉体であらゆる攻撃を\\n耐え凌ぐ。その怒りを糧に、巨人は\\n怒涛の大反撃を見舞う。\\n\\n・物理攻撃力アップ・ダウン効果の影響を受け\\n\u3000やすい。\\n・ユニオンバーストは、敵全体に物理中ダメージ。\\n・前方３キャラに物理大ダメージ。\\n・一定時間防御の構えをとったあと、その間に受\\n\u3000けたダメージ量に応じた物理ダメージを敵全体\\n\u3000に与え、前方２キャラを麻痺させる。\\n\u3000さらに、自身の物理攻撃力をアップ。', 307014, 0, 1, 307002, 270, 0, 0, 16, 0, 5.0, 3000, 'コア・ギガース');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【MODE3】弩級の巨人は、全身全霊の力を\\n解放する。強大無比な破壊力を前に\\n小手先の攻撃は通じない。\\n\\n・物理攻撃力アップ・ダウン効果の影響を受け\\n\u3000やすい。\\n・ユニオンバーストは、敵全体に物理中ダメージ。\\n・前方３キャラに物理大ダメージ。\\n・一定時間防御の構えをとったあと、その間に受\\n\u3000けたダメージ量に応じた物理ダメージを敵全体\\n\u3000に与え、前方２キャラを麻痺させる。\\n\u3000さらに、自身の物理攻撃力をアップ。\\n・敵全体に物理大ダメージを与え、大きくノック\\n\u3000バックさせる。\\n・バトル開始直後に、自身の物理攻撃力と\\n\u3000行動速度をアップさせる。', 307015, 0, 1, 307002, 270, 0, 0, 16, 0, 3.0, 3000, 'コア・ギガース');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('堅牢で多彩な技を持つ謎の巨大兵器の第１形態。\\nリンゴ型補給機で未知のエネルギーを充填し、\\n広範囲を焦土と化す連続攻撃に注意せよ！\\n\\n・ユニオンバーストは、敵全体に物理大ダメージ。\\n・前方１キャラに物理小ダメージ。\\n・一定範囲に、物理攻撃力と回避をダウンさせ\\n\u3000物理ダメージを与えるフィールドを展開。\\n\u3000同時に前方範囲内のキャラの\\n\u3000ステータスアップ効果を解除。\\n・前方範囲内に物理中ダメージを与え、\\n\u3000自身のＴＰ上昇をアップ。', 307100, 0, 1, 307100, 270, 0, 0, 16, 0, 2.8, 3000, 'ロボリマ（MODE1）');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('全てを攻めへと切替えた謎の巨大兵器の第２形態。\\nコアリマクターの放つ熱線が、全土を焼き尽くす。\\n無防備な巨大兵器に大ダメージを叩き込め！\\n\\n・ユニオンバーストは、前方小範囲に物理\\n\u3000特大ダメージ、中範囲に物理大ダメージ、\\n\u3000広範囲に物理中ダメージを与え、\\n\u3000大きく吹き飛ばす。\\n・前方１キャラに物理小ダメージ。\\n・ランダムな１キャラに物理小ダメージ。\\n・一定範囲に、物理攻撃力と魔法攻撃力を\\n\u3000大ダウンさせ、魔法ダメージを与える\\n\u3000フィールドを展開。\\n\u3000同時に、魔法攻撃力の高い２キャラを\\n\u3000沈黙させる。', 307101, 0, 1, 307101, 270, 0, 0, 16, 0, 1.2, 3000, 'ロボリマ（MODE2）');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('損耗を自己修復する謎の巨大兵器の第３形態。\\n隙だらけな本体への攻撃を、防衛ドローンが阻む。\\n範囲攻撃でドローンを蹴散らし、好機を狙え！\\n\\n・敵全体を大きく吹き飛ばし、\\n\u3000ミニロボリマを３体召喚する。\\n・ミニロボリマが、前方１キャラに\\n\u3000物理小ダメージ。\\n・ミニロボリマが、ランダムな１キャラに\\n\u3000魔法中ダメージ。\\n・敵全体に残りＨＰに応じた割合物理\\n\u3000特大ダメージ。', 307102, 0, 1, 307102, 270, 0, 0, 16, 0, 5.5, 3000, 'ロボリマ（MODE3）');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【魔法】ルナの魔力を求め飛来した大怪鳥。\\n雛鳥を従え、石化の呪剣を振り下ろす。\\n\\n・石化状態でないキャラ全員に魔法大ダメージ\\n\u3000を与え、短時間石化する。\\n\u3000石化状態のキャラ全員に最大ＨＰの80％の\\n\u3000ダメージを与える。\\n・前から３キャラに魔法小ダメージを与える。\\n\u3000さらにこのスキルでダメージが発生した\\n\u3000毒状態のキャラを長時間石化する。\\n・前方範囲内のキャラに魔法中ダメージを与え、\\n\u3000さらに毒状態にする。\\n\u3000自身のＨＰが50％以下の場合、さらに敵全体\\n\u3000をノックバックし、コッコーを召喚する。\\n・コッコーは、前方範囲内で物理攻撃力が\\n\u3000一番高い１キャラに物理小ダメージを与え、\\n\u3000さらに毒状態にする。\\n\u3000また自身のＨＰが最大ＨＰの35％以下にな\\n\u3000ると、物理攻撃力が最も高い味方のＴＰを\\n\u3000中アップし、自身は戦闘不能になる。', 307200, 0, 2, 307200, 270, 0, 0, 16, 0, 1.8, 3000, 'バジリスク');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【魔法】石化の呪剣を携えた怪鳥。尾蛇の毒牙で\\n獲物を蝕み、呪剣の石化で冒険者の歩みを止める。\\n\\n・飛行状態の敵を攻撃対象にできる。\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・バジリスクから受けるすべてのダメージで発生\\n\u3000する、パーティキャラのＴＰ回復量を中ダウン\\n\u3000させる。\\n・ユニオンバーストは、行動不能状態でない敵全\\n\u3000体に魔法特大ダメージを与え、石化状態を付与\\n\u3000する。行動不能状態の敵全体に最大ＨＰの\\n\u3000100％の魔法割合ダメージを与える。この\\n\u3000スキルによるダメージでは、ＴＰが回復しない。\\n\u3000このスキルの状態異常はダメージを無効化して\\n\u3000も付与される。\\n・前方広範囲に魔法特大ダメージを与える。さら\\n\u3000にキャラが毒状態の場合、石化状態を付与する。\\n\u3000このスキルの状態異常はダメージを無効化して\\n\u3000も付与される。\\n・敵全体に魔法特大ダメージを与え、毒状態を付\\n\u3000与する。このスキルにより付与された毒のダ\\n\u3000メージでは、ＴＰが回復しない。', 307201, 0, 2, 307201, 270, 0, 0, 16, 0, 1.8, 3000, 'バジリスク');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【魔法】森を抜ける冒険者を阻む\\n石化の怪鳥。毒の瘴気で蝕み、石\\n化で確実にとどめを刺す。\\n\\n・ユニオンバーストは、敵全体に\\n\u3000魔法中ダメージを与え、石化\\n\u3000状態にする。\\n\u3000さらに、敵全体のステータス\\n\u3000アップ効果を解除。\\n\u3000このスキルの状態異常はダメー\\n\u3000ジを無効化しても付与される。\\n\\n・敵全体に魔法中ダメージを与え\\n\u3000さらに毒状態にする。\\n\u3000このスキルの状態異常はダメー\\n\u3000ジを無効化しても付与される。', 307202, 0, 2, 307202, 270, 0, 0, 16, 0, 1.8, 3000, 'バシレウス');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【魔法】石化の呪剣を携えた怪鳥。尾蛇の毒牙で\\n獲物を蝕み、呪剣の石化で冒険者の歩みを止める。\\n\\n・飛行状態の敵を攻撃対象にできる。\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を大アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・バトル開始時、敵全体のＨＰ吸収を特大ダウン\\n\u3000させる。 \\n・バトル開始時、敵全体のＴＰ上昇を小ダウンさ\\n\u3000せるフィールドを展開する。\\n・バトル開始時、自身にＴＰダウン100％カッ\\n\u3000ト効果を付与する。\\n・バジリスクから受けるすべてのダメージで発生\\n\u3000する、パーティキャラのＴＰ回復量を特大ダウ\\n\u3000ンさせる。\\n・ユニオンバーストは、行動不能状態でない敵全\\n\u3000体に魔法特大ダメージを与え、石化状態を付与\\n\u3000する。行動不能状態の敵全体に最大ＨＰの\\n\u30001000％の魔法割合ダメージを与える。この\\n\u3000スキルによるダメージでは、ＴＰが回復しない。\\n\u3000このスキルの状態異常はダメージを無効化して\\n\u3000も付与される。\\n・前方広範囲に魔法特大ダメージを与え、短時間\\n\u3000石化状態を付与する。キャラが毒状態の場合、\\n\u3000長時間石化状態を付与する。このスキルの状態\\n\u3000異常はダメージを無効化しても付与される。\\n・敵全体に魔法特大ダメージを与え、毒状態を付\\n\u3000与する。このスキルによるダメージでは、ＴＰ\\n\u3000が回復しない。', 307203, 0, 2, 307203, 270, 0, 0, 16, 0, 1.8, 3000, 'バジリスク');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】強欲にまみれたカラクリ人形。\\nオーエド町の圧政者として君臨し、\\n横暴の限りを尽くす。\\n\\n・敵全体にキャラの最大ＨＰに応じた\\n\u3000物理大ダメージを与え、自分の物理\\n\u3000攻撃力を中アップさせる。', 307300, 0, 1, 307300, 270, 0, 0, 16, 0, 1.6, 3000, 'アクダイカン');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】強欲にまみれたカラクリ人形。\\nオーエド町の圧政者として君臨し、\\n横暴の限りを尽くす。\\n\\n・敵全体にキャラの最大ＨＰに応じた\\n\u3000物理大ダメージを与え、自分の物理\\n\u3000攻撃力を中アップさせる。', 307301, 0, 1, 307300, 270, 0, 0, 16, 0, 1.6, 3000, 'アクダイカン');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】強欲にまみれたカラクリ人形。\\nオーエド町の圧政者として君臨し、\\n横暴の限りを尽くす。\\n\\n・敵全体にキャラの最大ＨＰに応じた\\n\u3000物理大ダメージを与え、自分の物理\\n\u3000攻撃力を中アップさせる。', 307302, 0, 1, 307300, 270, 0, 0, 16, 0, 1.6, 3000, 'アクダイカン');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】強欲にまみれたカラクリ人形。\\nオーエド町の圧政者として君臨し、\\n横暴の限りを尽くす。\\n\\n・敵全体にキャラの最大ＨＰに応じた\\n\u3000物理大ダメージを与え、自分の物理\\n\u3000攻撃力を中アップさせる。さらに、\\n\u3000召喚されているすべてのケライのＨＰ\\n\u3000を0にする。\\n・目の前の敵１キャラへの物理攻撃を\\n\u3000行うケライを召喚する。\\n\u3000ケライは、自分のＨＰが0になると\\n\u3000大爆発し、範囲内の敵すべてに物理中\\n\u3000ダメージを与える。\\n・アクダイカン自身のＨＰが\\n\u300040％を切ると、さらに攻撃が激しく\\n\u3000凶暴になる。', 307303, 0, 1, 307300, 270, 0, 0, 16, 0, 1.6, 3000, 'アクダイカン');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【MODE1】【ヴァイスフリューゲル\\nランドソル支部】メンバーをシャドウ\\nとして召喚。３人の固い絆をあざ笑う\\n欲望の影が強襲する。\\n\\n・シャドウを出現させる\\n・目の前の敵１キャラへの物理攻撃\\n', 307304, 0, 1, 307300, 270, 0, 0, 16, 0, 1.6, 3000, 'アクダイカン');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【MODE2】物欲で周囲を従えるべく、\\nあらゆる虚構で欲望の渦へ引きずり込む。\\n\\n・目の前の敵１キャラへの物理攻撃\\n・敵全体に物理小ダメージを与え、\\n\u3000誘惑状態にする。\\n', 307305, 0, 1, 307300, 270, 0, 0, 16, 0, 1.6, 3000, 'アクダイカン');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【MODE3】虚栄に満ちた欲心は、すべて\\nを支配せんと真の力を解放する。\\n\\n・敵全体にキャラの最大ＨＰに応じた\\n\u3000物理大ダメージを与え、自分の物理\\n\u3000攻撃力を中アップさせる。さらに、\\n\u3000召喚されているすべてのケライのＨＰ\\n\u3000を0にする。\\n・目の前の敵１キャラへの物理攻撃を\\n\u3000行うケライを召喚する。\\n\u3000ケライは、自分のＨＰが0になると\\n\u3000大爆発し、範囲内の敵すべてに物理中\\n\u3000ダメージを与える。\\n', 307306, 0, 1, 307300, 270, 0, 0, 16, 0, 1.6, 3000, 'アクダイカン');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】強欲にまみれたカラクリ人形。\\nオーエド町の圧政者として君臨し、\\n横暴の限りを尽くす。\\n\\n・敵全体にキャラの最大ＨＰに応じた\\n\u3000物理割合ダメージを与え、自分の物理\\n\u3000攻撃力を中アップさせる。', 307307, 0, 1, 307307, 270, 0, 0, 16, 0, 1.6, 3000, 'アクダイカン');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】強欲にまみれたカラクリ人形。\\nオーエド町の圧政者として君臨し、\\n横暴の限りを尽くす。\\n\\n・敵全体にキャラの最大ＨＰに応じた\\n\u3000物理割合ダメージを与え、自分の物理\\n\u3000攻撃力を中アップさせる。', 307308, 0, 1, 307307, 270, 0, 0, 16, 0, 1.6, 3000, 'アクダイカン');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】強欲にまみれたカラクリ人形。\\nオーエド町の圧政者として君臨し、\\n横暴の限りを尽くす。\\n\\n・敵全体にキャラの最大ＨＰに応じた\\n\u3000物理割合ダメージを与え、自分の物理\\n\u3000攻撃力を中アップさせる。さらに、\\n\u3000召喚されているすべてのケライのＨＰ\\n\u3000を０にする。\\n・目の前の敵１キャラへの物理攻撃を\\n\u3000行うケライを召喚する。\\n\u3000ケライは、自分のＨＰが０になると\\n\u3000大爆発し、敵全体にキャラの最大ＨＰに\\n\u3000応じた物理割合ダメージを与える。\\n・アクダイカン自身のＨＰが\\n\u300040％を切ると、さらに攻撃が激しく\\n\u3000凶暴になる。', 307309, 0, 1, 307307, 270, 0, 0, 16, 0, 1.6, 3000, 'アクダイカン');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】強欲にまみれたカラクリ人形。\\nオーエド町の圧政者として君臨し、\\n横暴の限りを尽くす。\\n\\n・敵全体にキャラの最大ＨＰに応じた\\n\u3000物理割合ダメージを与え、自分の物理\\n\u3000攻撃力を中アップさせる。さらに、\\n\u3000召喚されているすべてのケライのＨＰ\\n\u3000を０にする。\\n・目の前の敵１キャラへの物理攻撃を\\n\u3000行うケライを召喚する。\\n\u3000ケライは、自分のＨＰが０になると\\n\u3000大爆発し、敵全体にキャラの最大ＨＰに\\n\u3000応じた物理割合ダメージを与える。\\n・アクダイカン自身のＨＰが\\n\u300040％を切ると、さらに攻撃が激しく\\n\u3000凶暴になる。', 307310, 0, 1, 307307, 270, 0, 0, 16, 0, 1.6, 3000, 'アクダイカン');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【MODE１】【ヴァイスフリューゲル\\nランドソル支部】メンバーをシャドウ\\nとして召喚。３人の固い絆をあざ笑う\\n欲望の影が強襲する。\\n\\n・前方１キャラに物理ダメージ。', 307311, 0, 1, 307307, 270, 0, 0, 16, 0, 1.6, 3000, 'アクダイカン');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【MODE２】物欲で周囲を従えるべく、\\nあらゆる虚構で欲望の渦へ引きずり込む。\\n\\n・前方１キャラに物理ダメージ。\\n・敵全体に物理小ダメージを与え、\\n\u3000誘惑状態にする。', 307312, 0, 1, 307307, 270, 0, 0, 16, 0, 1.6, 3000, 'アクダイカン');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【MODE３】虚栄に満ちた欲心は、すべて\\nを支配せんと真の力を解放する。\\n\\n・敵全体にキャラの最大ＨＰに応じた\\n\u3000物理割合ダメージを与え、自分の物理\\n\u3000攻撃力を中アップさせる。さらに、\\n\u3000召喚されているすべてのケライのＨＰ\\n\u3000を０にする。\\n・目の前の敵１キャラへの物理攻撃を\\n\u3000行うケライを召喚する。\\n\u3000ケライは、自分のＨＰが０になると\\n\u3000大爆発し、敵全体にキャラの最大ＨＰに\\n\u3000応じた物理割合ダメージを与える。\\n・バトル開始直後に、自身の物理攻撃力と\\n\u3000行動速度をアップさせる。', 307313, 0, 1, 307307, 270, 0, 0, 16, 0, 1.6, 3000, 'アクダイカン');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('', 307400, 0, 1, 307400, 270, 0, 0, 16, 0, 1.6, 3000, 'ペテルギウス');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】ルグニカに悪名高き魔女教の幹部。\\n異世界に行き着いてもなお自身の信念に従い、\\n強力な権能『見えざる手』の力で暗躍する。\\n\\n・ユニオンバーストは、敵全体にキャラの\\n\u3000最大ＨＰに応じた魔法割合ダメージを与える。\\n・前方範囲内のキャラ全員に魔法中ダメージと\\n\u3000ＴＰダウン。\\n\u3000さらに敵全体に魔法中ダメージ。\\n・後方２キャラに、キャラの最大ＨＰに応じた\\n\u3000物理割合ダメージを与える。\\n・向かって左側のターゲットのブレイク時、物理\\n\u3000防御力と魔法防御力が小ダウン、物理攻撃力が\\n\u3000小ダウン、魔法攻撃力が中ダウン。\\n・中央のターゲットのブレイク時、物理防御力と\\n\u3000魔法防御力が大ダウン、物理攻撃力が\\n\u3000小ダウン、魔法攻撃力が特大ダウン。\\n・向かって右側のターゲットのブレイク時、物理\\n\u3000防御力と魔法防御力が大ダウン、物理攻撃力が\\n\u3000小ダウン、魔法攻撃力が大ダウン。', 307401, 0, 1, 307400, 270, 0, 0, 16, 0, 1.6, 3000, 'ペテルギウス');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】ルグニカに悪名高き魔女教の幹部。\\n異世界に行き着いてもなお自身の信念に従い、\\n強力な権能『見えざる手』の力で暗躍する。\\n\\n・ユニオンバーストは、敵全体にキャラの\\n\u3000最大ＨＰに応じた魔法割合ダメージを与える。\\n・前方範囲内のキャラ全員に魔法中ダメージと\\n\u3000ＴＰダウン。\\n\u3000さらに敵全体に魔法中ダメージ。\\n・後方２キャラに、キャラの最大ＨＰに応じた\\n\u3000物理割合ダメージを与える。\\n・向かって左側のターゲットのブレイク時、物理\\n\u3000防御力と魔法防御力が小ダウン、物理攻撃力が\\n\u3000小ダウン、魔法攻撃力が中ダウン。\\n・中央のターゲットのブレイク時、物理防御力と\\n\u3000魔法防御力が大ダウン、物理攻撃力が\\n\u3000小ダウン、魔法攻撃力が特大ダウン。\\n・向かって右側のターゲットのブレイク時、物理\\n\u3000防御力と魔法防御力が大ダウン、物理攻撃力が\\n\u3000小ダウン、魔法攻撃力が大ダウン。\\n・残り時間が40秒を切ると、さらに攻撃が\\n\u3000激しく凶暴になる。', 307402, 0, 1, 307400, 270, 0, 0, 16, 0, 1.6, 3000, 'ペテルギウス');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】ルグニカに悪名高き魔女教の幹部。\\n異世界に行き着いてもなお自身の信念に従い、\\n強力な権能『見えざる手』の力で暗躍する。\\n\\n・ユニオンバーストは、敵全体にキャラの\\n\u3000最大ＨＰに応じた魔法割合ダメージを与える。\\n・前方範囲内のキャラ全員に魔法中ダメージと\\n\u3000ＴＰダウン。\\n\u3000さらに敵全体に魔法中ダメージ。\\n・後方２キャラに、キャラの最大ＨＰに応じた\\n\u3000物理割合ダメージを与える。\\n・向かって左側のターゲットのブレイク時、物理\\n\u3000防御力と魔法防御力が小ダウン、物理攻撃力が\\n\u3000小ダウン、魔法攻撃力が中ダウン。\\n・中央のターゲットのブレイク時、物理防御力と\\n\u3000魔法防御力が大ダウン、物理攻撃力が\\n\u3000小ダウン、魔法攻撃力が特大ダウン。\\n・向かって右側のターゲットのブレイク時、物理\\n\u3000防御力と魔法防御力が大ダウン、物理攻撃力が\\n\u3000小ダウン、魔法攻撃力が大ダウン。\\n・残り時間が40秒を切ると、さらに攻撃が\\n\u3000激しく凶暴になる。', 307403, 0, 1, 307400, 270, 0, 0, 16, 0, 1.6, 3000, 'ペテルギウス');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ１】レムとラムのシャドウを召喚。\\n大罪司教の狂気に呑まれた双子の影は、\\n魔女教の手となり、仲間の前に立ち塞がる。\\n\\n・目の前の敵１キャラに物理ダメージを与える。', 307404, 0, 1, 307400, 270, 0, 0, 16, 0, 1.6, 3000, 'ペテルギウス');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ２】威力を増した強力無比なる\\n権能は怠惰なる怨敵に無慈悲な終焉をもたらす。\\n\\n・ユニオンバーストは、敵全体にキャラの\\n\u3000最大ＨＰに応じた魔法割合ダメージを与える。\\n・後方２キャラに、キャラの最大ＨＰに応じた\\n\u3000物理割合ダメージを与える。\\n・残りＨＰ割合が少ない敵１キャラに\\n\u3000魔法大ダメージを与え、さらに\\n\u3000カウントダウンを付与する。\\n\u3000カウントが０になると、キャラの最大ＨＰに\\n\u3000応じた魔法割合ダメージを与える。\\n・向かって左側のターゲットのブレイク時、物理\\n\u3000防御力と魔法防御力が小ダウン、物理攻撃力が\\n\u3000小ダウン、魔法攻撃力が中ダウン。\\n・中央のターゲットのブレイク時、物理防御力が\\n\u3000中ダウン、魔法防御力が大ダウン、物理攻撃力\\n\u3000が小ダウン、魔法攻撃力が特大ダウン。\\n・向かって右側のターゲットのブレイク時、物理\\n\u3000防御力が中ダウン、魔法防御力が大ダウン、\\n\u3000物理攻撃力が小ダウン、魔法攻撃力が大ダウン。', 307405, 0, 1, 307400, 270, 0, 0, 16, 0, 1.6, 3000, 'ペテルギウス');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ３】理性も人の姿も失った狂信者は、\\nただ執念のみに動かされ、忠愛に死力を尽くす。\\n\\n・ユニオンバーストは、敵全体にキャラの\\n\u3000最大ＨＰに応じた魔法割合ダメージを与える。\\n・前方範囲内のキャラ全員に魔法中ダメージと\\n\u3000ＴＰダウン。\\n\u3000さらに敵全体に魔法中ダメージ。\\n・後方２キャラに、キャラの最大ＨＰに応じた\\n\u3000物理割合ダメージを与える。\\n・向かって左側のターゲットのブレイク時、物理\\n\u3000防御力と魔法防御力が小ダウン、物理攻撃力が\\n\u3000小ダウン、魔法攻撃力が中ダウン。\\n・中央のターゲットのブレイク時、物理防御力が\\n\u3000中ダウン、魔法防御力が大ダウン、物理攻撃力\\n\u3000が小ダウン、魔法攻撃力が特大ダウン。\\n・向かって右側のターゲットのブレイク時、物理\\n\u3000防御力が中ダウン、魔法防御力が大ダウン、\\n\u3000物理攻撃力が小ダウン、魔法攻撃力が大ダウン。\\n・残り時間が40秒を切ると、さらに攻撃が\\n\u3000激しく凶暴になる。', 307406, 0, 1, 307400, 270, 0, 0, 16, 0, 1.6, 3000, 'ペテルギウス');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】猛り狂う暴風を纏いし大怪鳥。\\n魔物図鑑を抜け出し、破壊の限りを尽くす。\\n\\n・敵全体にキャラの最大ＨＰに応じた\\n\u3000物理大ダメージを与える。\\n・最も近い敵を中心とした範囲内の\\n\u3000敵２体に物理中ダメージを与え、\\n\u3000さらにスタンさせる。', 307500, 0, 1, 307500, 270, 0, 0, 3, 0, 1.8, 1000, 'ジズ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】猛り狂う暴風を纏いし大怪鳥。\\n魔物図鑑を抜け出し、破壊の限りを尽くす。\\n\\n・敵全体にキャラの最大ＨＰに応じた\\n\u3000物理大ダメージを与える。\\n・最も近い敵を中心とした範囲内の\\n\u3000敵２キャラに物理中ダメージを与え、\\n\u3000さらにスタンさせる。', 307501, 0, 1, 307500, 270, 0, 0, 3, 0, 1.8, 1000, 'ジズ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】猛り狂う暴風を纏いし大怪鳥。\\n魔物図鑑を抜け出し、破壊の限りを尽くす。\\n\\n・敵全体にキャラの最大ＨＰに応じた\\n\u3000物理大ダメージを与える。\\n・最も近い敵を中心とした範囲内の\\n\u3000敵２キャラに物理中ダメージを与え、\\n\u3000さらにスタンさせる。\\n・前方範囲内の敵にキャラの最大ＨＰに応じた\\n\u3000物理中ダメージを与える。\\n・ジズ自身のＨＰが５０％を切ると、さらに\\n\u3000攻撃が激しく凶暴になる。', 307502, 0, 1, 307500, 270, 0, 0, 3, 0, 1.8, 1000, 'ジズ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】猛り狂う暴風を纏いし大怪鳥。\\n魔物図鑑を抜け出し、破壊の限りを尽くす。\\n\\n・敵全体にキャラの最大ＨＰに応じた\\n\u3000物理大ダメージを与える。\\n・最も近い敵を中心とした範囲内の\\n\u3000敵２キャラに物理中ダメージを与え、\\n\u3000さらにスタンさせる。\\n・前方範囲内の敵にキャラの最大ＨＰに応じた\\n\u3000物理中ダメージを与える。\\n・ジズ自身のＨＰが５０％を切ると、さらに\\n\u3000攻撃が激しく凶暴になる。', 307503, 0, 1, 307500, 270, 0, 0, 3, 0, 1.8, 1000, 'ジズ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】塔の魔力を喰らい、暴れ回る巨大魔鳥。\\n迂闊に近づくものは、暴風と雷豪が身を引き裂く。\\n\\n・ユニオンバーストは、敵全体に物理大ダメージ\\n\u3000を与える。\\n・前から２番目のキャラを中心にした小範囲に物\\n\u3000理小ダメージを与え、スタンさせる。\\n・前方範囲内の敵に物理中ダメージを与える。', 307504, 0, 1, 307504, 270, 0, 0, 3, 0, 1.8, 1000, '紅極鳥');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】猛り狂う暴風を纏いし大怪鳥。\\n魔物図鑑を抜け出し、破壊の限りを尽くす。\\n\\n・敵全体にキャラの最大ＨＰに応じた\\n\u3000物理大ダメージを与える。\\n・前方範囲内の敵に物理中ダメージを与え、\\n\u3000さらにスタンさせる。\\n・前方範囲内の敵にキャラの最大ＨＰに応じた\\n\u3000物理中ダメージを与える。\\n・ジズ自身のＨＰが50％を切ると、さらに\\n\u3000攻撃が激しく凶暴になる。', 307505, 0, 1, 307505, 270, 0, 0, 3, 0, 1.8, 1000, 'ジズ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】深域にのさばる獰猛な大怪鳥。紫電を\\n纏い嵐を巻き起こすさまは、天災と恐れられる。\\n\\n・ストーム・ジズから受けるすべてのダメージで\\n\u3000発生する、パーティキャラのＴＰ回復量を特大\\n\u3000ダウンさせる。\\n・ストーム・ジズから受けるすべての状態異常は\\n\u3000ダメージを無効化しても付与される。\\n・ユニオンバーストは、敵全体に魔法大ダメージ\\n\u3000を与え、魔法防御力を中ダウンさせる。このス\\n\u3000キルによるダメージでは、ＴＰが回復しない。\\n・最も近い敵２キャラに物理大ダメージを与え、\\n\u3000スタン状態を付与する。\\n・最も近い敵２キャラに物理大ダメージを与え、\\n\u3000物理防御力を小ダウンさせる。', 307506, 0, 1, 307506, 270, 0, 0, 3, 0, 1.8, 1000, 'ストーム・ジズ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】ルナの塔を己の舞台にしようと画策する、\\n魔界の道化。陽気な笑顔と狂気で観客の命を弄ぶ。\\n\\n・敵全体に魔法大ダメージを与え、\\n\u3000暗闇状態にする。\\n・6回、ランダムで1キャラに物理小ダメージを\\n\u3000与え、敵全体に物理大ダメージを与える。\\n\u3000この攻撃は前列にいるキャラほど\\n\u3000当たりやすくなる。\\n・時限式の爆弾を前方中距離に召喚する。\\n\u3000爆弾は召喚されてから8秒後に大爆発し、\\n\u3000範囲内の敵全体に物理中ダメージを与える。\\n\u3000ただし、爆発するまでに爆弾のＨＰが\\n\u30001％を切ると、マッドクラウンに\\n\u3000最大ＨＰの15％の物理ダメージを与える。', 307600, 0, 1, 307600, 270, 0, 0, 16, 0, 1.8, 1000, 'マッドクラウン');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】はるか古より迷宮を守護する防衛兵器。すべての罠を超えた最奥で侵入者を静かに待つ。\\n\\n・敵全体にキャラの最大ＨＰに応じた\\n\u3000魔法特大ダメージを与える。\\n・最も近い敵を中心とした近い敵\\n\u3000３体に、物理中ダメージを与える。', 307700, 0, 1, 307700, 270, 0, 0, 16, 0, 1.8, 1000, 'アルマ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】はるか古より迷宮を守護する防衛兵器。すべての罠を超えた最奥で侵入者を静かに待つ。\\n\\n・敵全体にキャラの最大ＨＰに応じた\\n\u3000魔法特大ダメージを与える。\\n・最も近い敵を中心とした敵３キャラ\\n\u3000に、物理中ダメージを与える。', 307701, 0, 1, 307700, 270, 0, 0, 16, 0, 1.8, 1000, 'アルマ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】はるか古より迷宮を守護する防衛兵器。すべての罠を超えた最奥で侵入者を静かに待つ。\\n\\n・敵全体にキャラの最大ＨＰに応じた\\n\u3000魔法特大ダメージを与える。\\n・最も近い敵を中心とした敵３キャラ\\n\u3000に、物理中ダメージを与える。\\n・残りＨＰの高い敵に対して最大ＨＰに応じた\\n\u3000魔法中ダメージを与えさらに麻痺させる。\\n・アルマ自身のＨＰが５０％を切ると、さらに\\n\u3000攻撃が激しく凶暴になる。', 307702, 0, 1, 307700, 270, 0, 0, 16, 0, 1.8, 1000, 'アルマ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】はるか古より迷宮を守護する防衛兵器。すべての罠を超えた最奥で侵入者を静かに待つ。\\n\\n・敵全体にキャラの最大ＨＰに応じた\\n\u3000魔法特大ダメージを与える。\\n・最も近い敵を中心とした敵３キャラ\\n\u3000に、物理中ダメージを与える。\\n・残りＨＰの高い敵に対して最大ＨＰに応じた\\n\u3000魔法中ダメージを与えさらに麻痺させる。\\n・アルマ自身のＨＰが５０％を切ると、さらに\\n\u3000攻撃が激しく凶暴になる。', 307703, 0, 1, 307700, 270, 0, 0, 16, 0, 1.8, 1000, 'アルマ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】ルナの塔の魔力で暴走する、古代兵器。\\n魔力で凶化した守護の力は全てを砕く災厄となる。\\n\\n・敵全体に物理特大ダメージを与える。\\n・前方小範囲内のランダムな敵キャラに\\n\u3000物理大ダメージを３回与える。\\n・最も魔法攻撃力が高い１キャラに\\n\u3000物理中ダメージを与え、麻痺させる。\\n\u3000さらに、その周りの小範囲の敵キャラに\\n\u3000物理中ダメージを与える。', 307704, 0, 1, 307704, 270, 0, 0, 16, 0, 1.8, 1000, 'カース・アルマ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【魔法】古より島の天候を見守ってきた守り神。\\n友の心を求め憂うあまり、禍禍しき姿に変貌する。\\nすべての大地を哀哭の雨で飲み込む。\\n\\n・ユニオンバーストは、敵全体に\\n\u3000魔法大ダメージを与えて吹き飛ばす。\\n\u3000さらに、前方範囲内の敵すべてに追加の\\n\u3000魔法中ダメージを与える。\\n・一番遠くの敵１キャラに魔法中ダメージを与え、\\n\u3000さらに小さく引き寄せる。', 307800, 0, 2, 307800, 270, 0, 0, 16, 0, 1.6, 3000, '雨神様');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【魔法】古より島の天候を見守ってきた守り神。\\n友の心を求め憂うあまり、禍禍しき姿に変貌する。\\nすべての大地を哀哭の雨で飲み込む。\\n\\n・ユニオンバーストは、敵全体にキャラの\\n\u3000最大ＨＰに応じた魔法割合ダメージを\\n\u3000与えて吹き飛ばす。\\n\u3000さらに、最も近い敵を中心とした範囲内の\\n\u3000敵すべてにキャラの最大ＨＰに応じた\\n\u3000追加の魔法割合ダメージを与える。\\n・一番遠くの敵１キャラに魔法中ダメージを与え、\\n\u3000さらに小さく引き寄せる。', 307801, 0, 2, 307800, 270, 0, 0, 16, 0, 1.6, 3000, '雨神様');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【魔法】古より島の天候を見守ってきた守り神。\\n友の心を求め憂うあまり、禍禍しき姿に変貌する。\\nすべての大地を哀哭の雨で飲み込む。\\n\\n・ユニオンバーストは、敵全体にキャラの\\n\u3000最大ＨＰに応じた魔法割合ダメージを\\n\u3000与えて吹き飛ばす。\\n\u3000さらに、最も近い敵を中心とした範囲内の\\n\u3000敵すべてにキャラの最大ＨＰに応じた\\n\u3000追加の魔法割合ダメージを与える。\\n・前方範囲内の敵すべてに魔法中ダメージを与え、\\n\u3000小さく吹き飛ばす。さらに最も近い敵１キャラ\\n\u3000に追加の魔法中ダメージを与える。\\n・一番遠くの敵１キャラに魔法中ダメージを与え、\\n\u3000さらに小さく引き寄せる。\\n・雨神様自身のＨＰが40%を切ると、\\n\u3000さらに攻撃が激しく狂暴になる。', 307802, 0, 2, 307800, 270, 0, 0, 16, 0, 1.6, 3000, '雨神様');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【魔法】古より島の天候を見守ってきた守り神。\\n友の心を求め憂うあまり、禍禍しき姿に変貌する。\\nすべての大地を哀哭の雨で飲み込む。\\n\\n・ユニオンバーストは、敵全体にキャラの\\n\u3000最大ＨＰに応じた魔法割合ダメージを\\n\u3000与えて吹き飛ばす。\\n\u3000さらに、最も近い敵を中心とした範囲内の\\n\u3000敵すべてにキャラの最大ＨＰに応じた\\n\u3000追加の魔法割合ダメージを与える。\\n・前方範囲内の敵すべてに魔法中ダメージを与え、\\n\u3000小さく吹き飛ばす。さらに最も近い敵１キャラ\\n\u3000に追加の魔法中ダメージを与える。\\n・一番遠くの敵１キャラに魔法中ダメージを与え、\\n\u3000さらに小さく引き寄せる。\\n・雨神様自身のＨＰが40%を切ると、\\n\u3000さらに攻撃が激しく狂暴になる。', 307803, 0, 2, 307800, 270, 0, 0, 16, 0, 1.6, 3000, '雨神様');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【MODE1】悲嘆に暮れるアメきちは\\nみんなの想いを拒絶し、心焦がれるほどに\\n求めたハレきちの声すら今のアメきちには\\n届かない。\\n\\n・バリアを張り、敵の攻撃を受け付けなくなる。\\n\u3000バリアはダメージ量に関係なく、攻撃を\\n\u3000命中させるたびに徐々に耐久性を失っていき、\\n\u3000２００回攻撃を命中させるとバリアは破壊\\n\u3000される。\\n・ユニオンバーストは、敵全体に魔法大ダメージ\\n\u3000を与えて吹き飛ばす。さらに、前方範囲内の\\n\u3000敵すべてに追加の魔法中ダメージを与える。\\n・前方範囲内の敵すべてに魔法中ダメージを与え、\\n\u3000小さく吹き飛ばす。さらに最も近い敵１キャラ\\n\u3000に追加の魔法中ダメージを与える。', 307804, 0, 2, 307801, 270, 0, 0, 16, 0, 1.6, 3000, '雨神様');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【MODE2】哀哭の雨が、哀しみとともに\\n降り注ぐ。その漆黒の雫は、悲哀の渇きで\\n人々の心身を蝕む。\\n\\n・バトル開始時に呪いのクリスタルを呼び出す。\\n\u3000呪いのクリスタルがバトル中に存在している間、\\n\u3000敵全体に継続ダメージを与える。さらに、\\n\u3000何らかの効果でＨＰを回復しようとした場合、\\n\u3000その回復を無効にし、本来の回復量の10%の\\n\u3000ダメージを与える。\\n・ユニオンバーストは、敵全体に魔法大ダメージ\\n\u3000を与えて吹き飛ばす。さらに、前方範囲内の\\n\u3000敵すべてに追加の魔法中ダメージを与える。\\n・前方範囲内の敵すべてに魔法中ダメージを与え、\\n\u3000小さく吹き飛ばす。さらに最も近い敵１キャラ\\n\u3000に追加の魔法中ダメージを与える。\\n・一番遠くの敵１キャラに魔法中ダメージを与え、\\n\u3000さらに小さく引き寄せる。', 307805, 0, 2, 307800, 270, 0, 0, 16, 0, 1.6, 3000, '雨神様');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【MODE3】ハレきちへの贖罪を乞う\\n慟哭の奔流が、対峙する者の心を引き裂く。\\n愛、友情、全ての感情が塵芥へと帰す。\\n\\n・ユニオンバーストは、敵全体に魔法大ダメージ\\n\u3000を与えて吹き飛ばす。さらに、前方範囲内の\\n\u3000敵すべてに追加の魔法中ダメージを与える。\\n・前方範囲内の敵すべてに魔法中ダメージを与え、\\n\u3000小さく吹き飛ばす。さらに最も近い敵１キャラ\\n\u3000に追加の魔法中ダメージを与える。\\n・一番遠くの敵１キャラに魔法中ダメージを与え、\\n\u3000さらに小さく引き寄せる。\\n・雨神様自身のＨＰが40%を切ると、\\n\u3000さらに攻撃が激しく狂暴になる。', 307806, 0, 2, 307800, 270, 0, 0, 16, 0, 1.6, 3000, '雨神様');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【魔法】古より島の天候を見守ってきた守り神。\\n友の心を求め憂うあまり、禍禍しき姿に変貌する。\\nすべての大地を哀哭の雨で飲み込む。\\n\\n・ユニオンバーストは、敵全体にキャラの\\n\u3000最大ＨＰに応じた魔法割合ダメージを\\n\u3000与えて吹き飛ばす。\\n\u3000さらに、前方範囲内の敵すべてにキャラの\\n\u3000最大ＨＰに応じた追加の魔法割合ダメージを\\n\u3000与える。\\n・一番遠くの敵１キャラに魔法中ダメージを与え、\\n\u3000さらに小さく引き寄せる。', 307807, 0, 2, 307800, 270, 0, 0, 16, 0, 1.6, 3000, '雨神様');
