insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【MODE3】ハレきちへの贖罪を乞う\\n慟哭の奔流が、対峙する者の心を引き裂く。\\n愛、友情、全ての感情が塵芥へと帰す。\\n\\n・ユニオンバーストは、敵全体にキャラの\\n\u3000最大ＨＰに応じた魔法割合ダメージを\\n\u3000与えて吹き飛ばす。\\n\u3000さらに、前方範囲内の敵すべてにキャラの\\n\u3000最大ＨＰに応じた追加の魔法割合ダメージを\\n\u3000与える。\\n・前方範囲内の敵すべてに魔法中ダメージを与え、\\n\u3000小さく吹き飛ばす。さらに最も近い敵１キャラ\\n\u3000に追加の魔法中ダメージを与える。\\n・一番遠くの敵１キャラに魔法中ダメージを与え、\\n\u3000さらに小さく引き寄せる。\\n・雨神様自身のＨＰが40%を切ると、\\n\u3000さらに攻撃が激しく狂暴になる。', 307813, 0, 2, 307800, 270, 0, 0, 16, 0, 1.6, 3000, '雨神様');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】屍肉を喰らう凶暴な大型魔獣。\\n強固な棘を全身に纏い獲物を執念深くつけ狙う。\\n\\n・敵全体にキャラの最大ＨＰに応じた\\n\u3000物理割合ダメージを与える。\\n・前から３番目、４番目、５番目のキャラに\\n\u3000物理中ダメージを与えさらにスタンさせる。', 307900, 0, 1, 307900, 270, 0, 0, 16, 0, 1.6, 1000, 'ガルグ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】屍肉を喰らう凶暴な大型魔獣。\\n強固な棘を全身に纏い獲物を執念深くつけ狙う。\\n\\n・敵全体にキャラの最大ＨＰに応じた\\n\u3000物理割合ダメージを与える。\\n・前から３番目、４番目、５番目のキャラに\\n\u3000物理中ダメージを与えさらにスタンさせる。', 307901, 0, 1, 307900, 270, 0, 0, 16, 0, 1.9, 1000, 'ガルグ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】屍肉を喰らう凶暴な大型魔獣。\\n強固な棘を全身に纏い獲物を執念深くつけ狙う。\\n\\n・敵全体にキャラの最大ＨＰに応じた\\n\u3000物理割合ダメージを与える。\\n・前から３番目、４番目、５番目のキャラに\\n\u3000物理中ダメージを与えさらにスタンさせる。\\n・前方２キャラに物理中ダメージを与える。\\n・ガルグ自身のＨＰが50%を切ると、さらに\\n\u3000攻撃が激しく凶暴になる。', 307902, 0, 1, 307900, 270, 0, 0, 16, 0, 1.6, 1000, 'ガルグ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】屍肉を喰らう凶暴な大型魔獣。\\n強固な棘を全身に纏い獲物を執念深くつけ狙う。\\n\\n・敵全体にキャラの最大ＨＰに応じた\\n\u3000物理割合ダメージを与える。\\n・前から３番目、４番目、５番目のキャラに\\n\u3000物理中ダメージを与えさらにスタンさせる。\\n・前方２キャラに物理中ダメージを与える。\\n・ガルグ自身のＨＰが50%を切ると、さらに\\n\u3000攻撃が激しく凶暴になる。', 307903, 0, 1, 307900, 270, 0, 0, 16, 0, 1.6, 1000, 'ガルグ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】善良なる魂を餌食とする、凶々しき悪霊。\\nより良き贄を求め、体躯を幾多にも分かち蠢く。\\n\\n・マジムンが保持している【吸魂】ステータス\\n\u3000の数に応じて、通常攻撃と各スキルの効果\\n\u3000が強化される。\\n・通常攻撃のたびに【吸魂】を6つ追加する。\\n・ユニオンバーストは全体に魔法特大\\n\u3000ダメージ。さらに【吸魂】を5つ追加する。\\n・全体に魔法小ダメージを与えてＴＰを減少させ、\\n\u3000さらにＴＰ上昇をダウンさせるフィールドを\\n\u3000展開する。ＴＰの減少量とフィールドの\\n\u3000効果値は、マジムンが保持している【吸魂】\\n\u3000の数が多い程強化される。\\n・攻撃するたびにマジムンに【吸魂】を1つ\\n\u3000追加する分身体を3体召喚し、さらに全体を\\n\u3000小さく吹き飛ばす。\\n・マジムンがクリティカルダメージを受ける\\n\u3000たびに、マジムンの【吸魂】が2つ減少する。\\n・分身体がクリティカルダメージを受ける\\n\u3000たびに、マジムンの【吸魂】が1つ減少する。\\n・マジムンのＨＰが40%を切ると、さらに\\n\u3000攻撃が激しく狂暴になる。\\n\u3000さらに【吸魂】を20追加する。', 308000, 0, 1, 308000, 270, 0, 0, 16, 0, 1.6, 3000, 'マジムン');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】善良なる魂を餌食とする、凶々しき悪霊。\\nより良き贄を求め、体躯を幾多にも分かち蠢く。\\n\\n・マジムンが保持している【吸魂】ステータス\\n\u3000の数に応じて、通常攻撃と各スキルの効果\\n\u3000が強化される。\\n・通常攻撃のたびに【吸魂】を6つ追加する。\\n・ユニオンバーストは全体に魔法特大\\n\u3000ダメージ。さらに【吸魂】を5つ追加する。\\n・全体に魔法小ダメージを与えてＴＰを減少させ、\\n\u3000さらにＴＰ上昇をダウンさせるフィールドを\\n\u3000展開する。ＴＰの減少量とフィールドの\\n\u3000効果値は、マジムンが保持している【吸魂】\\n\u3000の数が多い程強化される。\\n・攻撃するたびにマジムンに【吸魂】を1つ\\n\u3000追加する分身体を3体召喚し、さらに全体を\\n\u3000小さく吹き飛ばす。\\n・マジムンがクリティカルダメージを受ける\\n\u3000たびに、マジムンの【吸魂】が2つ減少する。\\n・分身体がクリティカルダメージを受ける\\n\u3000たびに、マジムンの【吸魂】が1つ減少する。', 308001, 0, 1, 308000, 270, 0, 0, 16, 0, 1.6, 3000, 'マジムン');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】善良なる魂を餌食とする、凶々しき悪霊。\\nより良き贄を求め、体躯を幾多にも分かち蠢く。\\n\\n・マジムンが保持している【吸魂】ステータス\\n\u3000の数に応じて、通常攻撃と各スキルの効果\\n\u3000が強化される。\\n・通常攻撃のたびに【吸魂】を6つ追加する。\\n・ユニオンバーストは全体に魔法特大\\n\u3000ダメージ。さらに【吸魂】を5つ追加する。\\n・全体に魔法小ダメージを与えてＴＰを減少させ、\\n\u3000さらにＴＰ上昇をダウンさせるフィールドを\\n\u3000展開する。ＴＰの減少量とフィールドの\\n\u3000効果値は、マジムンが保持している【吸魂】\\n\u3000の数が多い程強化される。\\n・攻撃するたびにマジムンに【吸魂】を1つ\\n\u3000追加する分身体を3体召喚し、さらに全体を\\n\u3000小さく吹き飛ばす。\\n・マジムンがクリティカルダメージを受ける\\n\u3000たびに、マジムンの【吸魂】が2つ減少する。\\n・分身体がクリティカルダメージを受ける\\n\u3000たびに、マジムンの【吸魂】が1つ減少する。\\n・マジムンのＨＰが40%を切ると、さらに\\n\u3000攻撃が激しく狂暴になる。\\n\u3000さらに【吸魂】を20追加する。', 308002, 0, 1, 308000, 270, 0, 0, 16, 0, 1.6, 3000, 'マジムン');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【MODE1】黄昏より出でし巨悪の化身は、\\n本能のまま幾百の魂を貪り喰う。\\n\\n・バトル開始と同時に、自身の魔法攻撃力を\\n\u3000特大アップさせ、さらに敵パーティの物理\\n\u3000クリティカルと魔法クリティカルを特大ダウン\\n\u3000させるフィールドを展開する。\\n・マジムンが保持している【吸魂】ステータス\\n\u3000の数に応じて、通常攻撃と各スキルの効果\\n\u3000が強化される。\\n・通常攻撃のたびに【吸魂】を6つ追加する。\\n・ユニオンバーストは全体に魔法特大ダメージ。\\n\u3000さらに【吸魂】を5つ追加する。\\n・全体に魔法小ダメージを与えてＴＰを減少させ、\\n\u3000さらにＴＰ上昇をダウンさせるフィールドを\\n\u3000展開する。ＴＰの減少量とフィールドの\\n\u3000効果値は、マジムンが保持している【吸魂】の\\n\u3000数が多い程強化される。\\n・マジムンがクリティカルダメージを受ける\\n\u3000たびに、マジムンの【吸魂】が5減少する。', 308003, 0, 1, 308000, 270, 0, 0, 16, 0, 1.6, 3000, 'マジムン');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【MODE2】宵闇より現れし怨霊の叢りは、\\n人々の魂を千々に引き裂く。\\n\\n・分身体を1体倒すたびに、残りマジムン数が\\n\u30001減少する。その後、分身体が再度召喚される。\\n・マジムンが保持している【吸魂】ステータス\\n\u3000の数に応じて、通常攻撃と各スキルの効果\\n\u3000が強化される。\\n・通常攻撃のたびに【吸魂】を6つ追加する。\\n・攻撃するたびにマジムンに【吸魂】を1つ\\n\u3000追加する分身体を3体召喚し、さらに全体を\\n\u3000小さく吹き飛ばす。\\n・マジムンがクリティカルダメージを受ける\\n\u3000たびに、マジムンの【吸魂】が2つ減少する。\\n・分身体がクリティカルダメージを受ける\\n\u3000たびに、マジムンの【吸魂】が1つ減少する。', 308004, 0, 1, 308000, 270, 0, 0, 16, 0, 1.6, 3000, 'マジムン');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【MODE3】暁闇の中で跋扈する魑魅は、\\n遂には三千世界の魂を食らわんと牙を剥く。\\n\\n・マジムンが保持している【吸魂】ステータス\\n\u3000の数に応じて、通常攻撃と各スキルの効果\\n\u3000が強化される。\\n・通常攻撃のたびに【吸魂】を6つ追加する。\\n・ユニオンバーストは全体に魔法特大\\n\u3000ダメージ。さらに【吸魂】を5つ追加する。\\n・全体に魔法小ダメージを与えてＴＰを減少させ、\\n\u3000さらにＴＰ上昇をダウンさせるフィールドを\\n\u3000展開する。ＴＰの減少量とフィールドの\\n\u3000効果値は、マジムンが保持している【吸魂】\\n\u3000の数が多い程強化される。\\n・攻撃するたびにマジムンに【吸魂】を1つ\\n\u3000追加する分身体を3体召喚し、さらに全体を\\n\u3000小さく吹き飛ばす。\\n・マジムンがクリティカルダメージを受ける\\n\u3000たびに、マジムンの【吸魂】が2つ減少する。\\n・分身体がクリティカルダメージを受ける\\n\u3000たびに、マジムンの【吸魂】が1つ減少する。\\n・残り時間が40秒を切ると、さらに\\n\u3000攻撃が激しく狂暴になる。\\n\u3000さらに【吸魂】を20追加する。', 308005, 0, 1, 308000, 270, 0, 0, 16, 0, 1.6, 3000, 'マジムン');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】善良なる魂を餌食とする、凶々しき悪霊。\\nより良き贄を求め、体躯を幾多にも分かち蠢く。\\n\\n・マジムンが保持している【吸魂】ステータス\\n\u3000の数に応じて、通常攻撃と各スキルの効果\\n\u3000が強化される。\\n・通常攻撃のたびに【吸魂】を６つ追加する。\\n・ユニオンバーストは、敵全体にキャラの\\n\u3000最大ＨＰに応じた魔法割合ダメージを与え、\\n\u3000さらに【吸魂】を５つ追加する。\\n・敵全体に魔法小ダメージを与えＴＰを減少させ、\\n\u3000さらにＴＰ上昇をダウンさせるフィールドを\\n\u3000展開する。ＴＰの減少量とフィールドの\\n\u3000効果値は、マジムンが保持している【吸魂】\\n\u3000の数が多い程強化される。\\n・攻撃するたびにマジムンに【吸魂】を１つ\\n\u3000追加する分身体を３体召喚し、さらに敵全体を\\n\u3000小さく吹き飛ばす。\\n・マジムンがクリティカルダメージを受ける\\n\u3000たびに、マジムンの【吸魂】が２つ減少する。\\n・分身体がクリティカルダメージを受ける\\n\u3000たびに、マジムンの【吸魂】が１つ減少する。\\n・マジムンのＨＰが30%を切ると、さらに\\n\u3000攻撃が激しく狂暴になる。\\n\u3000さらに【吸魂】を20追加する。', 308006, 0, 1, 308000, 270, 0, 0, 16, 0, 1.6, 3000, 'マジムン');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】善良なる魂を餌食とする、凶々しき悪霊。\\nより良き贄を求め、体躯を幾多にも分かち蠢く。\\n\\n・マジムンが保持している【吸魂】ステータス\\n\u3000の数に応じて、通常攻撃と各スキルの効果\\n\u3000が強化される。\\n・通常攻撃のたびに【吸魂】を６つ追加する。\\n・ユニオンバーストは、敵全体にマジムンが\\n\u3000保持している【吸魂】の数に応じた\\n\u3000魔法割合ダメージを与え、\\n\u3000さらに【吸魂】を５つ追加する。\\n・敵全体に魔法小ダメージを与えＴＰを減少させ、\\n\u3000さらにＴＰ上昇をダウンさせるフィールドを\\n\u3000展開する。ＴＰの減少量とフィールドの\\n\u3000効果値は、マジムンが保持している【吸魂】\\n\u3000の数が多い程強化される。\\n・攻撃するたびにマジムンに【吸魂】を１つ\\n\u3000追加する分身体を３体召喚し、さらに敵全体を\\n\u3000小さく吹き飛ばす。\\n・マジムンがクリティカルダメージを受ける\\n\u3000たびに、マジムンの【吸魂】が２つ減少する。\\n・分身体がクリティカルダメージを受ける\\n\u3000たびに、マジムンの【吸魂】が１つ減少する。', 308007, 0, 1, 308000, 270, 0, 0, 16, 0, 1.6, 3000, 'マジムン');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】善良なる魂を餌食とする、凶々しき悪霊。\\nより良き贄を求め、体躯を幾多にも分かち蠢く。\\n\\n・マジムンが保持している【吸魂】ステータス\\n\u3000の数に応じて、通常攻撃と各スキルの効果\\n\u3000が強化される。\\n・通常攻撃のたびに【吸魂】を６つ追加する。\\n・ユニオンバーストは、敵全体にマジムンが\\n\u3000保持している【吸魂】の数に応じた\\n\u3000魔法割合ダメージを与え、\\n\u3000さらに【吸魂】を５つ追加する。\\n・敵全体に魔法小ダメージを与えＴＰを減少させ、\\n\u3000さらにＴＰ上昇をダウンさせるフィールドを\\n\u3000展開する。ＴＰの減少量とフィールドの\\n\u3000効果値は、マジムンが保持している【吸魂】\\n\u3000の数が多い程強化される。\\n・攻撃するたびにマジムンに【吸魂】を１つ\\n\u3000追加する分身体を３体召喚し、さらに敵全体を\\n\u3000小さく吹き飛ばす。\\n・マジムンがクリティカルダメージを受ける\\n\u3000たびに、マジムンの【吸魂】が２つ減少する。\\n・分身体がクリティカルダメージを受ける\\n\u3000たびに、マジムンの【吸魂】が１つ減少する。\\n・マジムンのＨＰが30％を切ると、さらに\\n\u3000攻撃が激しく狂暴になる。\\n\u3000さらに【吸魂】を20追加する。', 308008, 0, 1, 308000, 270, 0, 0, 16, 0, 1.6, 3000, 'マジムン');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ１】黄昏より出でし巨悪の化身は、\\n本能のまま幾百の魂を貪り喰う。\\n\\n・バトル開始後に、自身の魔法攻撃力を\\n\u3000特大アップさせ、さらに敵全体の物理\\n\u3000クリティカルと魔法クリティカルを特大ダウン\\n\u3000させるフィールドを展開する。\\n・マジムンが保持している【吸魂】ステータス\\n\u3000の数に応じて、通常攻撃と各スキルの効果\\n\u3000が強化される。\\n・通常攻撃のたびに【吸魂】を６つ追加する。\\n・ユニオンバーストは、敵全体にマジムンが\\n\u3000保持している【吸魂】の数に応じた\\n\u3000魔法割合ダメージを与え、\\n\u3000さらに【吸魂】を５つ追加する。\\n・敵全体に魔法小ダメージを与えＴＰを減少させ、\\n\u3000さらにＴＰ上昇をダウンさせるフィールドを\\n\u3000展開する。ＴＰの減少量とフィールドの\\n\u3000効果値は、マジムンが保持している【吸魂】の\\n\u3000数が多い程強化される。\\n・マジムンがクリティカルダメージを受ける\\n\u3000たびに、マジムンの【吸魂】が５減少する。', 308009, 0, 1, 308000, 270, 0, 0, 16, 0, 1.6, 3000, 'マジムン');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ２】宵闇より現れし怨霊の叢りは、\\n人々の魂を千々に引き裂く。\\n\\n・分身体を１体倒すたびに、残りマジムン数が\\n\u3000１減少する。その後、分身体が再度召喚される。\\n・マジムンが保持している【吸魂】ステータス\\n\u3000の数に応じて、通常攻撃と各スキルの効果\\n\u3000が強化される。\\n・通常攻撃のたびに【吸魂】を６つ追加する。\\n・攻撃するたびにマジムンに【吸魂】を１つ\\n\u3000追加する分身体を３体召喚し、さらに敵全体を\\n\u3000小さく吹き飛ばす。\\n・マジムンがクリティカルダメージを受ける\\n\u3000たびに、マジムンの【吸魂】が２つ減少する。\\n・分身体がクリティカルダメージを受ける\\n\u3000たびに、マジムンの【吸魂】が１つ減少する。', 308010, 0, 1, 308000, 270, 0, 0, 16, 0, 1.6, 3000, 'マジムン');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ３】暁闇の中で跋扈する魑魅は、\\n遂には三千世界の魂を喰らわんと牙を剥く。\\n\\n・マジムンが保持している【吸魂】ステータス\\n\u3000の数に応じて、通常攻撃と各スキルの効果\\n\u3000が強化される。\\n・通常攻撃のたびに【吸魂】を６つ追加する。\\n・ユニオンバーストは、敵全体にマジムンが\\n\u3000保持している【吸魂】の数に応じた\\n\u3000魔法割合ダメージを与え、\\n\u3000さらに【吸魂】を５つ追加する。\\n・敵全体に魔法小ダメージを与えＴＰを減少させ、\\n\u3000さらにＴＰ上昇をダウンさせるフィールドを\\n\u3000展開する。ＴＰの減少量とフィールドの\\n\u3000効果値は、マジムンが保持している【吸魂】\\n\u3000の数が多い程強化される。\\n・攻撃するたびにマジムンに【吸魂】を１つ\\n\u3000追加する分身体を３体召喚し、さらに敵全体を\\n\u3000小さく吹き飛ばす。\\n・マジムンがクリティカルダメージを受ける\\n\u3000たびに、マジムンの【吸魂】が２つ減少する。\\n・分身体がクリティカルダメージを受ける\\n\u3000たびに、マジムンの【吸魂】が１つ減少する。\\n・残り時間が30秒を切ると、さらに\\n\u3000攻撃が激しく狂暴になる。\\n\u3000さらに【吸魂】を20追加する。', 308011, 0, 1, 308000, 270, 0, 0, 16, 0, 1.6, 3000, 'マジムン');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】善良なる魂を餌食とする、凶々しき悪霊。\\nより良き贄を求め、体躯を幾多にも分かち蠢く。\\n\\n・マジムンが保持している【吸魂】ステータス\\n\u3000の数に応じて、通常攻撃と各スキルの効果\\n\u3000が強化される。\\n・通常攻撃のたびに【吸魂】を６つ追加する。\\n・ユニオンバーストは、敵全体にマジムンが\\n\u3000保持している【吸魂】の数に応じた\\n\u3000魔法割合ダメージを与え、\\n\u3000さらに【吸魂】を５つ追加する。\\n・敵全体に魔法小ダメージを与えＴＰを減少させ、\\n\u3000さらにＴＰ上昇をダウンさせるフィールドを\\n\u3000展開する。ＴＰの減少量とフィールドの\\n\u3000効果値は、マジムンが保持している【吸魂】\\n\u3000の数が多い程強化される。\\n・攻撃するたびにマジムンに【吸魂】を１つ\\n\u3000追加する分身体を３体召喚し、さらに敵全体を\\n\u3000小さく吹き飛ばす。\\n・マジムンがクリティカルダメージを受ける\\n\u3000たびに、マジムンの【吸魂】が２つ減少する。\\n・分身体がクリティカルダメージを受ける\\n\u3000たびに、マジムンの【吸魂】が１つ減少する。', 308012, 0, 1, 308000, 270, 0, 0, 16, 0, 1.6, 3000, 'マジムン');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】海辺に君臨する巨大な軟体魔獣。\\n強靭な触手と鋼鉄の大銛で全てを破壊しつくす。\\n\\n・敵全体にキャラの最大ＨＰに応じた\\n\u3000物理大ダメージを与える。\\n・３番目に近い敵を中心とした遠い敵\\n\u3000３体に魔法中ダメージを与え、\\n\u3000麻痺状態を付与、さらに物理攻撃力、\\n\u3000魔法攻撃力を特大ダウン。\\n・一定時間経過すると敵単体に\\n\u3000物理超特大ダメージを与える。\\n・テンタパス自身のＨＰが40%を切ると、\\n\u3000さらに攻撃が激しく凶暴になる。', 308100, 0, 1, 308100, 270, 0, 0, 16, 0, 1.8, 1000, 'テンタパス');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】海辺に君臨する巨大な軟体魔獣。\\n強靭な触手と鋼鉄の大銛で全てを破壊しつくす。\\n\\n・敵全体にキャラの最大ＨＰに応じた\\n\u3000物理大ダメージを与える。\\n・最も遠い敵３キャラに魔法中ダメージ\\n\u3000を与え、麻痺状態を付与、さらに物理\\n\u3000攻撃力、魔法攻撃力を特大ダウン。', 308101, 0, 1, 308100, 270, 0, 0, 16, 0, 1.8, 1000, 'テンタパス');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】海辺に君臨する巨大な軟体魔獣。\\n強靭な触手と鋼鉄の大銛で全てを破壊しつくす。\\n\\n・敵全体にキャラの最大ＨＰに応じた\\n\u3000物理大ダメージを与える。\\n・最も遠い敵３キャラに魔法中ダメージ\\n\u3000を与え、麻痺状態を付与、さらに物理\\n\u3000攻撃力、魔法攻撃力を特大ダウン。\\n・テンタパス自身のＨＰが40%を切ると、\\n\u3000さらに攻撃が激しく凶暴になる。', 308102, 0, 1, 308100, 270, 0, 0, 16, 0, 1.8, 1000, 'テンタパス');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】海辺に君臨する巨大な軟体魔獣。\\n強靭な触手と鋼鉄の大銛で全てを破壊しつくす。\\n\\n・敵全体にキャラの最大ＨＰに応じた\\n\u3000物理大ダメージを与える。\\n・最も遠い敵３キャラに魔法中ダメージ\\n\u3000を与え、麻痺状態を付与、さらに物理\\n\u3000攻撃力、魔法攻撃力を特大ダウン。\\n・一定時間経過すると敵単体に\\n\u3000物理超特大ダメージを与える。\\n・テンタパス自身のＨＰが40%を切ると、\\n\u3000さらに攻撃が激しく凶暴になる。', 308103, 0, 1, 308100, 270, 0, 0, 16, 0, 1.8, 1000, 'テンタパス');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('', 308200, 0, 1, 308200, 270, 0, 0, 16, 0, 1.6, 3000, 'オオドクマンドラゴラ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】異常発達したアオイのマンドラゴラ。\\n強靭な根と種子の弾丸で眼前の敵を圧倒する。\\n\\n・前方２キャラに最大ＨＰに応じた物理割合\\n\u3000ダメージ。\\n・ユニオンバーストは、敵全体に\\n\u3000物理大ダメージを与え、与えた合計ダメー\\n\u3000ジに応じて自身のＨＰを回復させる。\\n・敵全体に連続で物理小ダメージを与えつつ、\\n\u3000物理防御力を３度ダウンさせる。\\n・自身の物理攻撃力をアップさせつつ、ＴＰ\\n\u3000を上昇させる。', 308201, 0, 1, 308200, 270, 0, 0, 16, 0, 1.6, 3000, 'オオドクマンドラゴラ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】異常発達したアオイのマンドラゴラ。\\n強靭な根と種子の弾丸で眼前の敵を圧倒する。\\n\\n・前方２キャラに最大ＨＰに応じた物理割合\\n\u3000ダメージ。\\n・ユニオンバーストは、敵全体に\\n\u3000物理大ダメージを与え、与えた合計ダメー\\n\u3000ジに応じて自身のＨＰを回復させる。\\n・敵全体に連続で物理小ダメージを与えつつ、\\n\u3000物理防御力を３度ダウンさせる。\\n・自身の物理攻撃力をアップさせつつ、ＴＰ\\n\u3000を上昇させる。', 308202, 0, 1, 308200, 270, 0, 0, 16, 0, 1.6, 3000, 'オオドクマンドラゴラ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】異常発達したアオイのマンドラゴラ。\\n強靭な根と種子の弾丸で眼前の敵を圧倒する。\\n\\n・前方２キャラに最大ＨＰに応じた物理割合\\n\u3000ダメージ。\\n・ユニオンバーストは、敵全体に\\n\u3000物理大ダメージを与え、与えた合計ダメー\\n\u3000ジに応じて自身のＨＰを回復させる。\\n・敵全体に連続で物理小ダメージを与えつつ、\\n\u3000物理防御力を３度ダウンさせる。\\n・自身の物理攻撃力をアップさせつつ、ＴＰ\\n\u3000を上昇させる。\\n・マンドラゴラ自身のＨＰが40％を切ると、\\n\u3000さらに攻撃が激しく狂暴になる。', 308203, 0, 1, 308200, 270, 0, 0, 16, 0, 1.6, 3000, 'オオドクマンドラゴラ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【MODE2】猛毒の胞子が降り注ぎ、大地は\\n荒野と化す。\\n数多の骸を苗床に、猛毒の大輪が鮮やかに\\n咲き誇る。\\n\\n下記の行動を順番に繰り返す。\\n・地面に埋まっている間、ダメージを受け付け\\n\u3000ない状態になる。\\n・敵全体を強力な毒状態にする。\\n・自身にかかっているステータスダウン効果を\\n\u3000解除したあと、自身の物理防御力と魔法防御\\n\u3000力を極大ダウン。', 308204, 0, 1, 308204, 270, 0, 0, 16, 0, 1.6, 3000, 'オオドクマンドラゴラ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【MODE1】触手から滴り落ちる猛毒の雫。\\nその一滴は泉を枯らし、森を腐らせ、命を侵す。\\n\\n・前方２キャラに物理ダメージを与え、さらに\\n\u3000毒状態にする。\\n・ユニオンバーストは、敵全体に\\n\u3000物理大ダメージを与え、与えた合計ダメー\\n\u3000ジに応じて自身のＨＰを回復させる。\\n\u3000毒状態のキャラには、ダメージが大アップ。\\n・敵全体に連続で物理小ダメージを与えつつ、\\n\u3000物理防御力を３度ダウンさせる。\\n・自身の物理攻撃力をアップさせつつ、ＴＰ\\n\u3000を上昇させる。', 308205, 0, 1, 308200, 270, 0, 0, 16, 0, 1.6, 3000, 'オオドクマンドラゴラ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【MODE3】絶命の咆哮、巨腕の蹂躙。\\n花のように散る命。自らの断末魔を子守歌に、\\n亡骸は永遠の眠りにつく。\\n\\n・前方２キャラに最大ＨＰに応じた物理割合\\n\u3000ダメージ。\\n・ユニオンバーストは、敵全体に\\n\u3000物理大ダメージを与え、与えた合計ダメー\\n\u3000ジに応じて自身のＨＰを回復させる。\\n・敵全体に連続で物理小ダメージを与えつつ、\\n\u3000物理防御力を３度ダウンさせる。\\n・自身の物理攻撃力をアップさせつつ、ＴＰ\\n\u3000を上昇させる。\\n・残り時間が40秒を切ると、さらに攻撃が\\n\u3000激しく狂暴になる。', 308206, 0, 1, 308200, 270, 0, 0, 16, 0, 1.6, 3000, 'オオドクマンドラゴラ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】塔の魔力で開花した劇毒を放つ死の大花。\\nその毒は、全ての感覚を狂わせ生ある全てを蝕む。\\n\\n・前方２キャラに物理ダメージを与える。\\n\u3000自身のＨＰが80％を切っている場合、さらに\\n\u3000毒状態にする。\\n・ユニオンバーストは敵全体に物理大ダメージを\\n\u3000与え、毒状態のキャラに割合ダメージを与える。\\n\u3000その後、敵全体の物理攻撃力を大ダウンさせ、\\n\u3000自身の物理攻撃力を大アップさせる。\\n・敵全体に物理中ダメージを与え、物理防御をダ\\n\u3000ウンさせる。\\n・自分の物理攻撃力とＴＰをアップする。\\n・残りＨＰが80％を切ると、さらに攻撃が激し\\n\u3000く狂暴になる。\\n・地面に埋まっている間、ダメージを受け付けな\\n\u3000い状態になり、敵全体に物理中ダメージを与え、\\n\u3000敵全体を長時間、毒状態にする。さらに、毒状\\n\u3000態のキャラを猛毒状態にする。\\n\u3000その後、地面から出てきた際に、物理防御力と\\n\u3000魔法防御力を極大ダウン。', 308207, 0, 1, 308207, 270, 0, 0, 16, 0, 1.6, 1000, 'ラフレシアマンドラゴラ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】数多の探検家を飲み込んだ幻島の巨鯨。欲望、幻想に憑りつかれた愚者を無慈悲に葬る。\\n\\n・敵全体にキャラの最大ＨＰに応じた\\n\u3000物理大ダメージを与える。\\n・敵全体に魔法中ダメージを与え、\\n\u3000さらに島クジラ自身の物理防御力、\\n\u3000魔法防御力を極大アップ。\\n・前から３キャラに魔法大ダメージを与え、\\n\u3000さらに大きく吹き飛ばす。\\n・島クジラ自身のＨＰが40％を切ると、\\n\u3000さらに攻撃が激しく凶暴になる。', 308300, 0, 1, 308300, 270, 0, 0, 16, 0, 1.8, 1000, '島クジラ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】数多の探検家を飲み込んだ幻島の巨鯨。欲望、幻想に憑りつかれた愚者を無慈悲に葬る。\\n\\n・敵全体にキャラの最大ＨＰに応じた\\n\u3000物理大ダメージを与える。\\n・敵全体に魔法中ダメージを与え、\\n\u3000さらに島クジラ自身の物理防御力、\\n\u3000魔法防御力を極大アップ。', 308301, 0, 1, 308300, 270, 0, 0, 16, 0, 1.8, 1000, '島クジラ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】数多の探検家を飲み込んだ幻島の巨鯨。欲望、幻想に憑りつかれた愚者を無慈悲に葬る。\\n\\n・敵全体にキャラの最大ＨＰに応じた\\n\u3000物理大ダメージを与える。\\n・敵全体に魔法中ダメージを与え、\\n\u3000さらに島クジラ自身の物理防御力、\\n\u3000魔法防御力を極大アップ。\\n・前から３キャラに魔法大ダメージを与え、\\n\u3000さらに大きく吹き飛ばす。\\n・島クジラ自身のＨＰが40％を切ると、\\n\u3000さらに攻撃が激しく凶暴になる。', 308302, 0, 1, 308300, 270, 0, 0, 16, 0, 1.8, 1000, '島クジラ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】数多の探検家を飲み込んだ幻島の巨鯨。欲望、幻想に憑りつかれた愚者を無慈悲に葬る。\\n\\n・敵全体にキャラの最大ＨＰに応じた\\n\u3000物理大ダメージを与える。\\n・敵全体に魔法中ダメージを与え、\\n\u3000さらに島クジラ自身の物理防御力、\\n\u3000魔法防御力を極大アップ。\\n・前から３キャラに魔法大ダメージを与え、\\n\u3000さらに大きく吹き飛ばす。\\n・島クジラ自身のＨＰが40％を切ると、\\n\u3000さらに攻撃が激しく凶暴になる。', 308303, 0, 1, 308300, 270, 0, 0, 16, 0, 1.8, 1000, '島クジラ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【魔法】我が子への妄執に囚われた亡親の霊。\\n娘と偽りの日々を享受すべく、\\n立ち塞がる者を容赦なく屠る。\\n\\n・ユニオンバーストは、敵全体にキャラの\\n\u3000最大ＨＰに応じた魔法割合ダメージを与え、\\n\u3000さらに魔法防御力をダウンさせる。\\n・最も近い敵１キャラに魔法大ダメージを与える。\\n\u3000さらに、前方３キャラにキャラの最大ＨＰに\\n\u3000応じた魔法割合ダメージを与え、\\n\u3000大きく吹き飛ばす。', 308400, 0, 2, 308400, 270, 0, 0, 16, 0, 1.6, 3000, 'ファントムバロン');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【魔法】我が子への妄執に囚われた亡親の霊。\\n娘と偽りの日々を享受すべく、\\n立ち塞がる者を容赦なく屠る。\\n\\n・ユニオンバーストは、敵全体にキャラの\\n\u3000最大ＨＰに応じた魔法割合ダメージを与え、\\n\u3000さらに魔法防御力をダウンさせる。\\n・最も近い敵１キャラに魔法大ダメージを与える。\\n\u3000さらに、前方３キャラにキャラの最大ＨＰに\\n\u3000応じた魔法割合ダメージを与え、\\n\u3000大きく吹き飛ばす。', 308401, 0, 2, 308400, 270, 0, 0, 16, 0, 1.6, 3000, 'ファントムバロン');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【魔法】我が子への妄執に囚われた亡親の霊。\\n娘と偽りの日々を享受すべく、\\n立ち塞がる者を容赦なく屠る。\\n\\n・ユニオンバーストは、敵全体にキャラの\\n\u3000最大ＨＰに応じた魔法割合ダメージを与え、\\n\u3000さらに魔法防御力をダウンさせる。\\n・最も近い敵１キャラに魔法大ダメージを与える。\\n\u3000さらに、前方３キャラにキャラの最大ＨＰに\\n\u3000応じた魔法割合ダメージを与え、\\n\u3000大きく吹き飛ばす。\\n・一番遠くの敵１キャラに物理中ダメージを\\n\u3000与え、さらに一番前にいるキャラの位置まで\\n\u3000引き寄せてスタンさせる。\\n・ファントムバロンのＨＰが40％を切ると、\\n\u3000さらに攻撃が激しく狂暴になる。', 308402, 0, 2, 308400, 270, 0, 0, 16, 0, 1.6, 3000, 'ファントムバロン');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【魔法】我が子への妄執に囚われた亡親の霊。\\n娘と偽りの日々を享受すべく、\\n立ち塞がる者を容赦なく屠る。\\n\\n・ユニオンバーストは、敵全体にキャラの\\n\u3000最大ＨＰに応じた魔法割合ダメージを与え、\\n\u3000さらに魔法防御力をダウンさせる。\\n・最も近い敵１キャラに魔法大ダメージを与える。\\n\u3000さらに、前方３キャラにキャラの最大ＨＰに\\n\u3000応じた魔法割合ダメージを与え、\\n\u3000大きく吹き飛ばす。\\n・一番遠くの敵１キャラに物理中ダメージを\\n\u3000与え、さらに一番前にいるキャラの位置まで\\n\u3000引き寄せてスタンさせる。\\n・ファントムバロンのＨＰが40％を切ると、\\n\u3000さらに攻撃が激しく狂暴になる。', 308403, 0, 2, 308400, 270, 0, 0, 16, 0, 1.6, 3000, 'ファントムバロン');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ１】【リトルリリカル】の\\nシャドウを召喚。\\n無垢な少女達が手招く先は、亡者が蠢く常夜の国。\\n\\n・前方１キャラに魔法ダメージを与える。', 308404, 0, 2, 308400, 270, 0, 0, 16, 0, 1.6, 3000, 'ファントムバロン');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ２】冥府の門が開かれ、\\n生者の魂は奈落に墜ちる。既に還る術もなく、\\n思い出を標に闇を漂う。\\n\\n・ユニオンバーストは、敵全体にキャラの\\n\u3000最大ＨＰに応じた魔法割合ダメージを与え、\\n\u3000さらに魔法防御力をダウンさせる。\\n・一番遠くの敵１キャラに物理中ダメージを\\n\u3000与え、さらに一番前にいるキャラの位置まで\\n\u3000引き寄せてスタンさせる。\\n・前方３キャラに魔法中ダメージを与えて\\n\u3000ＴＰを中ダウンさせ、ファントムバロン\\n\u3000のＴＰを中回復させる。\\n\u3000さらに、物理攻撃をするキャラのうち、\\n\u3000前から３キャラのステータスアップ効果を\\n\u3000解除し、魔法攻撃をするキャラのうち、\\n\u3000前から３キャラに追加の魔法大ダメージを\\n\u3000与える。', 308405, 0, 2, 308400, 270, 0, 0, 16, 0, 1.6, 3000, 'ファントムバロン');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ３】最愛との別離が刻々と近づく。\\n悲しき宿命に抗うべく、\\n怨霊は寂滅の慟哭をあげる。\\n\\n・ユニオンバーストは、敵全体にキャラの\\n\u3000最大ＨＰに応じた魔法割合ダメージを与え、\\n\u3000さらに魔法防御力をダウンさせる。\\n・最も近い敵１キャラに魔法大ダメージを与える。\\n\u3000さらに、前方３キャラにキャラの最大ＨＰに\\n\u3000応じた魔法割合ダメージを与え、\\n\u3000大きく吹き飛ばす。\\n・一番遠くの敵１キャラに物理中ダメージを\\n\u3000与え、さらに一番前にいるキャラの位置まで\\n\u3000引き寄せてスタンさせる。\\n・バトル開始直後に、自身の魔法攻撃力と\\n\u3000行動速度をアップさせる。', 308406, 0, 2, 308400, 270, 0, 0, 16, 0, 1.6, 3000, 'ファントムバロン');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【魔法】塔の魔力に群がる怨魂が姿を成した亡霊。\\n邪悪な手が生者を呼び込み、冥府へ引き摺り込む。\\n\\n・敵全体に魔法大ダメージを与え、\\n\u3000さらに魔法防御力をダウンさせる。\\n・最も近い敵１キャラに魔法大ダメージを与える。\\n\u3000さらに、前方３キャラに魔法中ダメージを与え、\\n\u3000大きく吹き飛ばす。\\n・一番遠くの敵１キャラに物理中ダメージを\\n\u3000与え、さらに一番前にいるキャラの位置まで\\n\u3000引き寄せてスタンさせる。', 308408, 0, 2, 308408, 270, 0, 0, 16, 0, 1.6, 3000, 'マッドファントム');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】ルナの魔力に魅入られ荒れ狂う水の神獣。\\n自らの役目を忘れ、万物を飲み込む狂獣と化す。\\n\\n・敵全体に魔法大ダメージを与え、畏怖を与える。\\n\u3000畏怖状態のキャラは、一定時間攻撃および\\n\u3000ＨＰ回復のユニオンバーストの効果が半減する。\\n・前方範囲内に魔法中ダメージを与え、\\n\u3000ヒットした数に応じて自身の物理防御力を\\n\u3000小アップ。さらに、魔法ダメージを与える\\n\u3000フィールドを展開する。\\n・前方１キャラに魔法大ダメージを与え、\\n\u3000自身のＨＰを消費し、敵全体に追加の\\n\u3000魔法中ダメージを与える。\\n\u3000さらに、自身の物理攻撃力と魔法攻撃力を\\n\u3000小アップ。', 308500, 0, 1, 308500, 270, 0, 0, 16, 0, 2.8, 1000, '水瑚麟');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('', 308600, 0, 1, 308600, 270, 0, 0, 16, 0, 1.8, 1000, 'ドラゴンもどき');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】ドラゴン？の如き翼で空を舞い\\nドラゴン？の如き灼熱のブレスで敵を焦がす。\\n\\n・バトルの開始時、自身に【火の実】を70追加。\\n・ユニオンバーストは、敵全体に\\n\u3000ドラゴンもどきが保持している【火の実】の\\n\u3000数に応じた物理割合ダメージを与える。\\n\u3000その後【火の実】が60減少する。\\n・前方の３キャラに、キャラの最大ＨＰに応じた\\n\u3000物理割合ダメージを与え、スタンさせる。\\n・しばらくの間、物理防御力と魔法防御力が大幅\\n\u3000に下がり、食事モーションをとっている間、\\n\u3000最大で60、【火の実】を継続して追加する。\\n\u3000モーション中にドラゴンもどきが5000\\n\u3000以上のダメージを受けるとスキルが中断され\\n\u3000【火の実】が30減少する。', 308601, 0, 1, 308600, 270, 0, 0, 16, 0, 1.8, 1000, 'ドラゴンもどき');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】ドラゴン？の如き翼で空を舞い\\nドラゴン？の如き灼熱のブレスで敵を焦がす。\\n\\n・バトルの開始時、自身に【火の実】を70追加。\\n・ユニオンバーストは、敵全体に\\n\u3000ドラゴンもどきが保持している【火の実】の\\n\u3000数に応じた物理割合ダメージを与える。\\n\u3000その後【火の実】が60減少する。\\n・前方の３キャラに、キャラの最大ＨＰに応じた\\n\u3000物理割合ダメージを与え、スタンさせる。\\n・しばらくの間、物理防御力と魔法防御力が大幅\\n\u3000に下がり、食事モーションをとっている間、\\n\u3000最大で60、【火の実】を継続して追加する。\\n\u3000モーション中にドラゴンもどきが20000\\n\u3000以上のダメージを受けるとスキルが中断され\\n\u3000【火の実】が30減少する。', 308602, 0, 1, 308600, 270, 0, 0, 16, 0, 1.8, 1000, 'ドラゴンもどき');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】ドラゴン？の如き翼で空を舞い\\nドラゴン？の如き灼熱のブレスで敵を焦がす。\\n\\n・バトルの開始時、自身に【火の実】を70追加。\\n・ユニオンバーストは、敵全体に\\n\u3000ドラゴンもどきが保持している【火の実】の\\n\u3000数に応じた物理割合ダメージを与える。\\n\u3000その後【火の実】が60減少する。\\n・前方の３キャラに、キャラの最大ＨＰに応じた\\n\u3000物理割合ダメージを与え、スタンさせる。\\n・しばらくの間、物理防御力と魔法防御力が大幅\\n\u3000に下がり、食事モーションをとっている間、\\n\u3000最大で60、【火の実】を継続して追加する。\\n\u3000モーション中にドラゴンもどきが160000\\n\u3000以上のダメージを受けるとスキルが中断され\\n\u3000【火の実】が30減少する。\\n・ドラゴンもどきのＨＰが40％を切ると、\\n\u3000さらに攻撃が激しく凶暴になる。', 308603, 0, 1, 308600, 270, 0, 0, 16, 0, 1.8, 1000, 'ドラゴンもどき');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ１】蒼天から降る咆哮が空を裂き、\\n陽光に輝く自慢の翼で巨大な偽竜が降臨する。\\n\\n・ドラゴンもどきの残りＨＰが80％を切ると\\n\u3000次のＭＯＤＥに移行する。\\n\\n・バトルの開始時、自身に【火の実】を70追加。\\n・ユニオンバーストは、敵全体に\\n\u3000ドラゴンもどきが保持している【火の実】の\\n\u3000数に応じた物理割合ダメージを与える。\\n\u3000その後【火の実】が60減少する。\\n・前方の３キャラに、キャラの最大ＨＰに応じた\\n\u3000物理割合ダメージを与え、スタンさせる。\\n・しばらくの間、物理防御力と魔法防御力が大幅\\n\u3000に下がり、食事モーションをとっている間\\n\u3000最大で60、【火の実】を継続して追加する。\\n\u3000モーション中にドラゴンもどきが150000\\n\u3000以上のダメージを受けるとスキルが中断され\\n\u3000【火の実】が30減少する。\\n・４体のモンスターを呼び寄せ、さらに敵全体\\n\u3000を小さくノックバック。', 308604, 0, 1, 308600, 270, 0, 0, 16, 0, 1.8, 2160, 'ドラゴンもどき');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ２】偽竜の呼びかけに森の魔物たちが\\n集結する。彼を守るべく死力を尽くす。\\n\\n・ゴーレム、トレント、ポイズンポッド\\n\u3000を倒すと、次のＭＯＤＥに移行する。\\n\\n・ドラゴンもどきは、目の前の敵１キャラへの\\n\u3000物理攻撃を行う。', 308605, 0, 1, 308600, 270, 0, 0, 16, 0, 1.8, 1000, 'ドラゴンもどき');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ３】竜への憧れが石竜子を覚醒\\nさせる。空を統べる覇者の息吹は島を絶やす\\n劫火となる。\\n\\n・バトルの開始時、自身に【火の実】を70追加。\\n・ユニオンバーストは、敵全体に\\n\u3000ドラゴンもどきが保持している【火の実】の\\n\u3000数に応じた物理割合ダメージを与える。\\n\u3000その後【火の実】が60減少する。\\n・前方の３キャラに、キャラの最大ＨＰに応じた\\n\u3000物理割合ダメージを与え、スタンさせる。\\n・しばらくの間、物理防御力と魔法防御力が大幅\\n\u3000に下がり、食事モーションをとっている間、\\n\u3000最大で60、【火の実】を継続して追加する。\\n\u3000モーション中にドラゴンもどきが250000\\n\u3000以上のダメージを受けるとスキルが中断され\\n\u3000【火の実】が30減少する。\\n・バトル開始直後に、さらに攻撃が激しく\\n\u3000凶暴になる。', 308606, 0, 1, 308606, 270, 0, 0, 16, 0, 1.8, 1000, 'ドラゴンもどき');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】夢うつつの狭間で惰眠を貪るナマケモノ。\\n眠りを妨げると怒り狂い、超能力で暴れまわる。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・ランドスロースから受けるすべてのダメージで\\n\u3000発生する、パーティキャラのＴＰ回復量を中ダ\\n\u3000ウンさせる。\\n・ユニオンバーストは、敵全体にキャラの最大Ｈ\\n\u3000Ｐに応じた魔法割合ダメージを与え、物理攻撃\\n\u3000力を特大ダウン、魔法攻撃力を中ダウンさせる。\\n\u3000このスキルの状態異常はダメージを無効化して\\n\u3000も付与される。\\n・敵全体に魔法中ダメージを与える。', 309000, 0, 1, 309000, 270, 0, 0, 16, 0, 1.8, 1000, 'ランドスロース');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】夢うつつの狭間で惰眠を貪るナマケモノ。\\n眠りを妨げると怒り狂い、超能力で暴れまわる。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を中アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・バトル開始時、敵全体のＨＰ吸収を特大ダウン\\n\u3000させる。 \\n・バトル開始時、敵全体のＴＰ上昇を小ダウンさ\\n\u3000せるフィールドを展開する。\\n・バトル開始時、自身にＴＰダウン50％カット\\n\u3000効果を付与する。\\n・ランドスロースから受けるすべてのダメージで\\n\u3000発生する、パーティキャラのＴＰ回復量を中ダ\\n\u3000ウンさせる。\\n・ユニオンバーストは、敵全体にキャラの最大Ｈ\\n\u3000Ｐに応じた魔法割合ダメージを与え、物理攻撃\\n\u3000力を特大ダウン、魔法攻撃力を中ダウンさせ、\\n\u3000スタン状態を付与する。このスキルの状態異常\\n\u3000はダメージを無効化しても付与される。\\n・敵全体に魔法中ダメージを与え、スタン状態を\\n\u3000付与する。このスキルの状態異常はダメージを\\n\u3000無効化しても付与される。', 309001, 0, 1, 309001, 270, 0, 0, 16, 0, 1.8, 1000, 'ランドスロース');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】広大な密林に棲む巨大な\\n獣。身の危険が迫ると防衛反応が\\n働き、大いなる野生を解き放つ。\\n\\n・ユニオンバーストは、敵全体に\\n\u3000キャラの最大ＨＰに応じた魔法\\n\u3000割合ダメージを与え、さらに物\\n\u3000理攻撃力と魔法攻撃力を大ダウ\\n\u3000ン。このスキルの状態異常はダ\\n\u3000メージを無効化しても付与され\\n\u3000る。\\n\\n・敵全体に魔法小ダメージを与え\\n\u3000スタンさせる。このスキルの状\\n\u3000態異常はダメージを無効化して\\n\u3000も付与される。', 309002, 0, 1, 309002, 270, 0, 0, 16, 0, 1.8, 1000, 'レイジーママル');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】夢うつつの狭間で惰眠を貪るナマケモノ。\\n眠りを妨げると怒り狂い、超能力で暴れまわる。\\n\\n・ランドスロースから受けるすべてのダメージで\\n\u3000発生する、パーティキャラのＴＰ回復量を中ダ\\n\u3000ウンさせる。\\n・ユニオンバーストは、敵全体にキャラの最大Ｈ\\n\u3000Ｐに応じた魔法割合ダメージを与え、物理攻撃\\n\u3000力と魔法攻撃力を中ダウンさせ、スタン状態を\\n\u3000付与する。このスキルの状態異常はダメージを\\n\u3000無効化しても付与される。\\n・敵全体に魔法中ダメージを与える。', 309003, 0, 1, 309003, 270, 0, 0, 16, 0, 1.8, 1000, 'ランドスロース');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】大河に棲む大ワニの魔物。\\nマヌケな顔で、不思議な槍で大地を\\n融解させ冒険者の動きを封じる。\\n\\n・敵全体に物理大ダメージを与え、\\n\u3000物理防御力と行動速度をダウン\\n\u3000させる。\\n\\n・前から３番目の敵を中心にした\\n\u3000小範囲に物理小ダメージを与え、\\n\u3000束縛状態にする。', 309100, 0, 1, 309100, 270, 0, 0, 16, 0, 1.8, 1000, 'ドロゲーター');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】大河に棲む大ワニの魔物。マヌケな顔で、\\n不思議な槍で大地を融解させ敵の動きを封じる。\\n\\n・飛行状態の敵を攻撃対象にできる。\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・ドロゲーターから受けるすべてのダメージで発\\n\u3000生する、パーティキャラのＴＰ回復量を中ダウ\\n\u3000ンさせる。\\n・ユニオンバーストは、敵の挑発を無視して前か\\n\u3000ら３番目の敵を中心にした小範囲内の敵すべて\\n\u3000に物理特大ダメージを与える。さらに敵全体の\\n\u3000行動速度を中ダウンさせ、このスキルでダメー\\n\u3000ジを与えた敵の数に応じてＴＰをダウンさせる。\\n\u3000このスキルの状態異常はダメージを無効化して\\n\u3000も付与される。\\n・敵の挑発を無視して、前から３番目の敵を中心\\n\u3000にした小範囲内の敵すべてに物理小ダメージを\\n\u3000与え、束縛状態を付与する。このスキルの状態\\n\u3000異常はダメージを無効化しても付与される。', 309101, 0, 1, 309101, 270, 0, 0, 16, 0, 1.8, 3000, 'ドロゲーター');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】大河に棲む大ワニの魔物。マヌケな顔で、\\n不思議な槍で大地を融解させ敵の動きを封じる。\\n\\n・飛行状態の敵を攻撃対象にできる。\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を中アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・バトル開始時、敵全体のＨＰ吸収を特大ダウン\\n\u3000させ、ＴＰ上昇を小ダウンさせる。\\n・バトル開始時、自身にＴＰダウン50％カット\\n\u3000効果を付与する。\\n・ドロゲーターから受けるすべてのダメージで発\\n\u3000生する、パーティキャラのＴＰ回復量を中ダウ\\n\u3000ンさせる。\\n・ユニオンバーストは、敵の挑発を無視して前か\\n\u3000ら３番目の敵を中心にした小範囲内の敵すべて\\n\u3000に物理特大ダメージを与える。さらに敵全体の\\n\u3000行動速度を中ダウンさせ、このスキルでダメー\\n\u3000ジを与えた敵の数に応じてＴＰをダウンさせる。\\n\u3000このスキルの状態異常はダメージを無効化して\\n\u3000も付与される。\\n・敵の挑発を無視して、前から３番目の敵を中心\\n\u3000にした小範囲内の敵すべてに物理小ダメージを\\n\u3000与え、束縛状態を付与する。このスキルの状態\\n\u3000異常はダメージを無効化しても付与される。', 309102, 0, 1, 309102, 270, 0, 0, 16, 0, 1.8, 3000, 'ドロゲーター');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】大河に棲む大ワニの魔物。マヌケな顔で、\\n不思議な槍で大地を融解させ敵の動きを封じる。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・ドロゲーターから受けるすべてのダメージで発\\n\u3000生する、パーティキャラのＴＰ回復量を中ダウ\\n\u3000ンさせる。\\n・ユニオンバーストは、挑発を無視して前から３\\n\u3000番目の敵を中心にした小範囲に物理大ダメージ\\n\u3000を与える。さらに敵全体の行動速度を大ダウン\\n\u3000させ、このスキルでダメージを与えた敵の数に\\n\u3000応じてＴＰをダウンさせる。このスキルの状態\\n\u3000異常はダメージを無効化しても付与される。\\n・挑発を無視して前から３番目の敵を中心にした\\n\u3000小範囲に物理小ダメージを与え、束縛状態を付\\n\u3000与する。このスキルの状態異常はダメージを無\\n\u3000効化しても付与される。', 309103, 0, 1, 309103, 270, 0, 0, 16, 0, 1.8, 3000, 'ドロゲーター');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】大河に棲む大ワニの魔物。マヌケな顔で、\\n不思議な槍で大地を融解させ敵の動きを封じる。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を中アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・バトル開始時、自身にＴＰダウン50％カット\\n\u3000効果を付与する。\\n・ドロゲーターから受けるすべてのダメージで発\\n\u3000生する、パーティキャラのＴＰ回復量を中ダウ\\n\u3000ンさせる。\\n・ユニオンバーストは、挑発を無視して前から３\\n\u3000番目の敵を中心にした小範囲に物理大ダメージ\\n\u3000を与える。さらに敵全体の行動速度を大ダウン\\n\u3000させ、このスキルでダメージを与えた敵の数に\\n\u3000応じてＴＰをダウンさせる。このスキルの状態\\n\u3000異常はダメージを無効化しても付与される。\\n・挑発を無視して前から３番目の敵を中心にした\\n\u3000小範囲に物理小ダメージを与え、束縛状態を付\\n\u3000与する。このスキルの状態異常はダメージを無\\n\u3000効化しても付与される。', 309104, 0, 1, 309104, 270, 0, 0, 16, 0, 1.8, 3000, 'ドロゲーター');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】戦空を駆け舞う、天上の戦乙女。\\n目にも留まらぬ連射で、敵の進行を射止める。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・スカイワルキューレから受けるすべてのダメー\\n\u3000ジで発生する、パーティキャラのＴＰ回復量を\\n\u3000中ダウンさせる。\\n・ユニオンバーストは、前方範囲内の敵最大４\\n\u3000キャラに物理特大ダメージを与え、ＴＰを中ダ\\n\u3000ウンさせ、行動速度を大ダウンさせる。このス\\n\u3000キルの状態異常はダメージを無効化しても付与\\n\u3000される。\\n・最も近い敵４キャラに物理中ダメージを与え、\\n\u3000物理攻撃力と魔法攻撃力を大ダウンさせる。さ\\n\u3000らに、自身の行動速度を特大アップさせる。', 309200, 0, 1, 309200, 270, 0, 0, 16, 0, 1.8, 1000, 'スカイワルキューレ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】戦空を駆け舞う、天上の戦乙女。\\n目にも留まらぬ連射で、敵の進行を射止める。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を中アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・バトル開始時、敵全体のＴＰ上昇を小ダウンさ\\n\u3000せるフィールドを展開する。\\n・バトル開始時、自身にＴＰダウン75％カット\\n\u3000効果を付与する。\\n・スカイワルキューレから受けるすべてのダメー\\n\u3000ジで発生する、パーティキャラのＴＰ回復量を\\n\u3000中ダウンさせる。\\n・敵から受けるすべてのダメージで発生する、ス\\n\u3000カイワルキューレのＴＰ回復量が大ダウンする。\\n・ユニオンバーストは、前方範囲内の敵最大４\\n\u3000キャラに物理特大ダメージを与え、ＴＰを大ダ\\n\u3000ウンさせ、ＴＰ上昇と行動速度を特大ダウンさ\\n\u3000せる。さらにこのスキルで敵を倒した場合、自\\n\u3000身の物理攻撃力を特大アップさせる。このスキ\\n\u3000ルの状態異常はダメージを無効化しても付与さ\\n\u3000れる。\\n・最も近い敵４キャラに物理中ダメージを与え、\\n\u3000物理攻撃力と魔法攻撃力を大ダウンさせる。さ\\n\u3000らに、自身の行動速度を特大アップさせる。こ\\n\u3000のスキルの状態異常はダメージを無効化しても\\n\u3000付与される。', 309201, 0, 1, 309201, 270, 0, 0, 16, 0, 1.8, 1000, 'スカイワルキューレ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】戦空を駆け舞う、天上の戦乙女。\\n目にも留まらぬ連射で、敵の進行を射止める。\\n\\n・スカイワルキューレから受けるすべてのダメー\\n\u3000ジで発生する、パーティキャラのＴＰ回復量を\\n\u3000中ダウンさせる。\\n・ユニオンバーストは、前方中範囲内の敵最大４\\n\u3000キャラに物理特大ダメージを与え、ＴＰを大ダ\\n\u3000ウンさせ、ＴＰ上昇と行動速度をバトル終了ま\\n\u3000で特大ダウンさせる。このスキルの状態異常は\\n\u3000ダメージを無効化しても付与される。\\n・最も近い敵４キャラに物理大ダメージを与え、\\n\u3000物理攻撃力と魔法攻撃力をバトル終了まで大ダ\\n\u3000ウンさせる。さらに、自身の行動速度を特大\\n\u3000アップさせる。このスキルの状態異常はダメー\\n\u3000ジを無効化しても付与される。', 309202, 0, 1, 309202, 270, 0, 0, 16, 0, 1.8, 1000, 'スカイワルキューレ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】戦空を駆け舞う、天上の戦乙女。\\n目にも留まらぬ連射で、敵の進行を射止める。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を中アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・バトル開始時、自身にＴＰダウン50％カット\\n\u3000効果を付与する。\\n・バトル開始時、敵全体のＨＰ吸収を特大ダウン\\n\u3000させる。\\n・自身が一度の行動で受けるダメージ値を減衰さ\\n\u3000せる。ダメージ値が上昇するほど減衰率も上昇\\n\u3000する。\\n・スカイワルキューレから受けるすべてのダメー\\n\u3000ジで発生する、パーティキャラのＴＰ回復量を\\n\u3000中ダウンさせる。\\n・ユニオンバーストは、前方中範囲内の敵最大４\\n\u3000キャラに物理特大ダメージを与え、ＴＰを大ダ\\n\u3000ウンさせ、ＴＰ上昇と行動速度をバトル終了ま\\n\u3000で特大ダウンさせる。このスキルの状態異常は\\n\u3000ダメージを無効化しても付与される。\\n・最も近い敵４キャラに物理大ダメージを与え、\\n\u3000物理攻撃力と魔法攻撃力をバトル終了まで大ダ\\n\u3000ウンさせる。さらに、自身の行動速度を特大\\n\u3000アップさせる。このスキルの状態異常はダメー\\n\u3000ジを無効化しても付与される。', 309203, 0, 1, 309203, 270, 0, 0, 16, 0, 1.8, 1000, 'スカイワルキューレ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('', 309300, 0, 1, 309300, 270, 0, 0, 16, 0, 1.8, 3000, 'トナカイ・ヴェンデッタ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】主人へ反逆を決めた、エリートトナカイ。\\n欲深いサンタたちへ、従者の心の鉄槌を下す。\\n\\n・ユニオンバーストは、召喚キャラを消滅させた\\n\u3000あと、敵全体にキャラの最大ＨＰに応じた\\n\u3000物理割合ダメージを与える。\\n\u3000このダメージを受けたあとにＨＰが40％を\\n\u3000切ったキャラを一定時間トナカイに変え、\\n\u3000さらに物理クリティカルと魔法クリティカルを\\n\u3000下げる。トナカイになったキャラは、通常攻撃\\n\u3000しか使用できなくなる。\\n\u3000一定時間、自身の物理防御力を大きく下げる。\\n・一番前のキャラを中心として、一定範囲に\\n\u3000キャラの最大ＨＰに応じた物理割合ダメージを\\n\u3000与える。さらに自身の物理攻撃力をアップ\\n\u3000させる。\\n・一番前のキャラに物理ダメージを与えて\\n\u3000ノックバックさせ、さらにスタンさせる。', 309301, 0, 1, 309300, 270, 0, 0, 16, 0, 1.8, 3000, 'トナカイ・ヴェンデッタ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】主人へ反逆を決めた、エリートトナカイ。\\n欲深いサンタたちへ、従者の心の鉄槌を下す。\\n\\n・ユニオンバーストは、召喚キャラを消滅させた\\n\u3000あと、敵全体にキャラの最大ＨＰに応じた\\n\u3000物理割合ダメージを与える。\\n\u3000このダメージを受けたあとにＨＰが40％を\\n\u3000切ったキャラを一定時間トナカイに変え、\\n\u3000さらに物理クリティカルと魔法クリティカルを\\n\u3000下げる。トナカイになったキャラは、通常攻撃\\n\u3000しか使用できなくなる。\\n\u3000一定時間、自身の物理防御力を大きく下げる。\\n・一番前のキャラを中心として、一定範囲に\\n\u3000キャラの最大ＨＰに応じた物理割合ダメージを\\n\u3000与える。さらに自身の物理攻撃力をアップ\\n\u3000させる。\\n・一番前のキャラに物理ダメージを与えて\\n\u3000ノックバックさせ、さらにスタンさせる。', 309302, 0, 1, 309300, 270, 0, 0, 16, 0, 1.8, 3000, 'トナカイ・ヴェンデッタ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】主人へ反逆を決めた、エリートトナカイ。\\n欲深いサンタたちへ、従者の心の鉄槌を下す。\\n\\n・ユニオンバーストは、召喚キャラを消滅させた\\n\u3000あと、敵全体にキャラの最大ＨＰに応じた\\n\u3000物理割合ダメージを与える。\\n\u3000このダメージを受けたあとにＨＰが40％を\\n\u3000切ったキャラを一定時間トナカイに変え、\\n\u3000さらに物理クリティカルと魔法クリティカルを\\n\u3000下げる。トナカイになったキャラは、通常攻撃\\n\u3000しか使用できなくなる。\\n\u3000一定時間、自身の物理防御力を大きく下げる。\\n・一番前のキャラを中心として、一定範囲に\\n\u3000キャラの最大ＨＰに応じた物理割合ダメージを\\n\u3000与える。さらに自身の物理攻撃力をアップ\\n\u3000させる。\\n・一番前のキャラに物理ダメージを与えて\\n\u3000ノックバックさせ、さらにスタンさせる。\\n・トナカイ・ヴェンデッタ自身のＨＰが50％を\\n\u3000切ると、さらに攻撃が激しく凶暴になる。', 309303, 0, 1, 309300, 270, 0, 0, 16, 0, 1.8, 3000, 'トナカイ・ヴェンデッタ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ１】クリスティーナ、ノゾミ、\\nイリヤのシャドウを召喚。３人の歪んだ欲望と\\n御節介が、かたちとなり聖夜を渾沌に変えていく。\\n\\n・一番前のキャラに物理ダメージを与える。', 309304, 0, 1, 309300, 270, 0, 0, 16, 0, 4.2, 3000, 'トナカイ・ヴェンデッタ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ２】聖夜の街に絶望が雪のように\\n降り積る。染まる欲望の袋より、積念の憎悪が\\n溢れだす。\\n\\n・ユニオンバーストは、召喚キャラを消滅させた\\n\u3000あと、敵全体にキャラの最大ＨＰに応じた\\n\u3000物理割合ダメージを与える。\\n\u3000このダメージを受けたあとにＨＰが40％を\\n\u3000切ったキャラを一定時間トナカイに変え、\\n\u3000さらに物理クリティカルと魔法クリティカルを\\n\u3000下げる。トナカイになったキャラは、通常攻撃\\n\u3000しか使用できなくなる。\\n\u3000一定時間、自身の物理防御力を大きく下げる。\\n・一番前のキャラを中心として、一定範囲に\\n\u3000キャラの最大ＨＰに応じた物理割合ダメージを\\n\u3000与える。さらに自身の物理攻撃力をアップ\\n\u3000させる。\\n・一定時間、前方にフィールドを発生させる。\\n\u3000このフィールド上にいるキャラに対して、\\n\u3000物理攻撃力と物理クリティカルと\\n\u3000ＴＰ上昇を大きく下げる。\\n・一番前のキャラに物理ダメージを与えて\\n\u3000ノックバックさせ、さらにスタンさせる。', 309305, 0, 1, 309300, 270, 0, 0, 16, 0, 1.8, 3000, 'トナカイ・ヴェンデッタ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ３】手負いの巨獣が、反撃の狼煙を\\n上げる。憎悪と憤怒に身を落とし、残虐の限りを\\n尽くす。\\n\\n・ユニオンバーストは、召喚キャラを消滅させた\\n\u3000あと、敵全体にキャラの最大ＨＰに応じた\\n\u3000物理割合ダメージを与える。\\n\u3000このダメージを受けたあとにＨＰが35％を\\n\u3000切ったキャラを一定時間トナカイに変え、\\n\u3000さらに物理クリティカルと魔法クリティカルを\\n\u3000下げる。トナカイになったキャラは、通常攻撃\\n\u3000しか使用できなくなる。\\n\u3000一定時間、自身の物理防御力を大きく下げる。\\n・一番前のキャラを中心として、一定範囲に\\n\u3000キャラの最大ＨＰに応じた物理割合ダメージを\\n\u3000与える。さらに自身の物理攻撃力をアップ\\n\u3000させる。\\n・一番前のキャラに物理ダメージを与えて\\n\u3000ノックバックさせ、さらにスタンさせる。\\n・バトル開始直後に、さらに攻撃が激しく\\n\u3000凶暴になる。', 309306, 0, 1, 309300, 270, 0, 0, 16, 0, 1.8, 3000, 'トナカイ・ヴェンデッタ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】覇瞳皇帝が生み出した動く力の貯蔵庫。\\n膂力の権能を司り、極大の剣戟で全てを斬破する。\\n\\n・スタンと吹き飛ばし効果が有効。\\n\\n・ユニオンバーストは、敵全体にキャラの\\n\u3000最大ＨＰに応じた物理割合ダメージを与える。\\n\\n・目の前の敵を中心に、範囲内の敵すべてに\\n\u3000キャラの最大ＨＰに応じた物理割合\\n\u3000ダメージを与える。\\n\\n・サーヴァント・ブレド（物理）自身の\\n\u3000ＨＰが40％を切ると、さらに攻撃が\\n\u3000激しく凶暴になる。', 309400, 0, 1, 309400, 270, 0, 0, 16, 0, 1.8, 1000, 'サーヴァント・ブレド（物理）');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【魔法】覇瞳皇帝が生み出した動く力の貯蔵庫。\\n魔道の権能を司り、無尽の魔力で全てを滅却する。\\n\\n・ユニオンバーストは、敵全体にキャラの\\n\u3000最大ＨＰに応じた魔法割合ダメージを与える。\\n\u3000さらに、物理攻撃力と魔法攻撃力を小ダウン。\\n\\n・ランダムな１キャラに魔法ダメージを与え、\\n\u3000さらに呪い、麻痺状態にしてＴＰを大ダウン。\\n\\n・サーヴァント・マギ（魔法）自身の\\n\u3000ＨＰが40％を切ると、さらに攻撃が\\n\u3000激しく凶暴になる。', 309500, 0, 2, 309500, 270, 0, 0, 16, 0, 1.8, 1000, 'サーヴァント・マギ（魔法）');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】覇瞳皇帝が生み出した動く力の貯蔵庫。\\n双肩の権能を司り、広闊たる領域で全てを屠る。\\n\\n・ユニオンバーストは、目の前の敵を中心に、\\n\u3000範囲内の敵すべてにキャラの最大ＨＰに\\n\u3000応じた物理割合ダメージを与え、さらに\\n\u3000目の前の敵に物理小ダメージを与える。\\n\\n・目の前の敵を中心にキャラの\\n\u3000最大ＨＰに応じた物理割合ダメージを\\n\u3000与える。\\n\\n・サーヴァント・ロクス（複部位）自身の\\n\u3000ＨＰが40％を切ると、さらに防御力が\\n\u3000上がり頑強になる。', 309600, 0, 1, 309600, 270, 0, 0, 16, 0, 1.8, 1000, 'サーヴァント・ロクス（複部位）');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【魔法】覇瞳皇帝が生み出した動く力の貯蔵庫。\\n守護の権能を司り、不侵の壁で全てを拒絶する。\\n\\n・ユニオンバーストは、自身の物理防御力、\\n\u3000魔法防御力を大アップ。\\n\\n・目の前の敵を中心に、範囲内の敵すべてに\\n\u3000魔法ダメージ。さらに、自身の物理防御力、\\n\u3000魔法防御力を小アップ。\\n\\n・サーヴァント・ウォル（防衛）自身の\\n\u3000ＨＰが40％を切ると、さらに防御力が\\n\u3000上がり頑強になる。', 309700, 0, 2, 309700, 270, 0, 0, 16, 0, 1.8, 1000, 'サーヴァント・ウォル（防衛）');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('王都終末決戦_ベースユニット', 309800, 0, 1, 309800, 270, 309800, 0, 16, 309800, 3.6, 1000, '覇瞳皇帝');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【MODE１】全てを、拒絶する悲しき王女。\\n自らを神とし、禍禍しき力にその身をのまれる。\\nそして狂乱の刃をアストルムの全てに向ける。\\n欺瞞の王女を守護する壁を、数多の刃で打ち破れ。\\n\\n・バリアを張り、敵の攻撃を受け付けなくなる。\\n\u3000バリアはダメージ量に関係なく、攻撃を\\n\u3000命中させるたびに徐々に耐久性を失っていき、\\n\u3000280回攻撃を命中させるとバリアは破壊\\n\u3000される。\\n\\n・ユニオンバーストは、敵全体に残りＨＰに\\n\u3000応じた割合特大ダメージを与える。\\n\\n・敵全体に、物理小ダメージと魔法\\n\u3000小ダメージを与える。', 309801, 0, 1, 309801, 270, 309800, 0, 16, 309800, 2.4, 1000, '覇瞳皇帝');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【MODE２】小さき者の反抗に僅かな焦燥を見せる。\\n希望を抱き、対向する全てに自らの理を科す。\\n悲憤の剣を突き立て、その魂を塵芥へと挫く。\\n仮初の神の放つ黒刃に、正しき魔法を以て\\n対抗せよ。\\n\\n・ユニオンバーストは、敵全体に残りＨＰに\\n\u3000応じた割合特大ダメージを与える。\\n\\n・目の前の敵１キャラに物理特大ダメージを与え、\\n\u3000さらにその周囲の敵すべてに魔法中ダメージを\\n\u3000与え、気絶させる。気絶したキャラは、\\n\u3000次に攻撃を受けるまで行動不能になる。\\n\\n・敵全体に、物理小ダメージと魔法\\n\u3000小ダメージを与える。', 309802, 0, 1, 309800, 270, 309800, 0, 16, 309800, 1.8, 1000, '覇瞳皇帝');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【MODE３】世界を創りし神の、最期の叫声。\\n怨嗟が放つ拒絶の言の葉は呪詛となり、\\n躰を、精神を、魂を削りすべてを闇に帰す。\\n遂に決着の時。皆、剣を取りその手で明日を\\n切り拓け。\\n\\n・ユニオンバーストは、敵全体に残りＨＰに\\n\u3000応じた割合特大ダメージを与える。\\n\\n・目の前の敵１キャラに物理特大ダメージを与え、\\n\u3000さらにその周囲の敵すべてに魔法中ダメージを\\n\u3000与え、気絶させる。気絶したキャラは、\\n\u3000次に攻撃を受けるまで行動不能になる。\\n\\n・敵全体に、物理小ダメージと魔法\\n\u3000小ダメージを与える。\\n\\n・最も後ろの敵１キャラを中心に、物理防御力と\\n\u3000魔法防御力を中ダウンさせるフィールドを\\n\u3000展開し、さらに魔法小ダメージを与え、\\n\u3000呪詛を付与する。呪詛による継続ダメージは、\\n\u3000毎秒ごとに増加する。\\n\\n・バトル開始直後に、自分の行動速度を\\n\u3000大アップさせ、さらに魔法防御力を\\n\u3000小アップさせる。', 309803, 0, 1, 309800, 270, 309800, 0, 16, 309800, 1.6, 1000, '覇瞳皇帝');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('マップ表示用', 309804, 0, 1, 309804, 270, 309800, 0, 16, 309800, 1.8, 1000, '覇瞳皇帝');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【魔法】塔の魔力を我が物に画策する小鬼学者。\\n禁術で土塊の人形を操り、全ての自由を強奪する。\\n\\n・敵全体に魔法大ダメージを与え、\\n\u3000すべての召喚体、分身を即死させる。\\n・前方広範囲に残りＨＰに応じた割合物理\\n\u3000中ダメージを与え、大きく吹き飛ばす。\\n\u3000さらに、泥人形を１体召喚する。\\n\u3000泥人形は最前衛または前から２番目のキャラに\\n\u3000物理ダメージを与え、行動速度を下げる。\\n・前から２番目のキャラを中心とした小範囲に\\n\u3000物理中ダメージと猛毒、スタンを与える。', 309900, 0, 2, 309900, 270, 0, 0, 17, 0, 1.8, 1100, 'ゴブリンメイスター');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【魔法】塔の魔力を我が物に画策する小鬼学者。\\n禁術で土塊の人形を操り、全ての自由を強奪する。\\n\\n・ゴブリンメイスターから受けるすべてのダメー\\n\u3000ジで発生する、パーティキャラのＴＰ回復量を\\n\u3000中ダウンさせる。\\n・ユニオンバーストは、敵全体に魔法大ダメージ\\n\u3000を与える。泥人形が存在する場合、追加魔法ダ\\n\u3000メージを与える。このスキルによるダメージで\\n\u3000は、ＴＰが回復しない。\\n・前方範囲に最大ＨＰに応じた物理割合ダメージ\\n\u3000を与え、ノックバックさせる。このスキルの状\\n\u3000態異常はダメージを無効化しても付与される。\\n\u3000このスキルによるダメージでは、ＴＰが回復し\\n\u3000ない。さらに、泥人形を１体召喚する。泥人形\\n\u3000は最も近い敵キャラまたは前から２番目のキャ\\n\u3000ラに物理ダメージを与え、行動速度を下げる。\\n・前から２番目の敵キャラを中心とした小範囲に\\n\u3000物理中ダメージを与え、さらに猛毒、スタン状\\n\u3000態を付与する。\\n・自身のＨＰが60％以下になると、魔法攻撃力\\n\u3000と行動速度が大アップし、さらに攻撃が激しく\\n\u3000凶暴になる。', 309901, 0, 2, 309901, 270, 0, 0, 17, 0, 1.8, 3000, 'ゴブリンメイスター');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【魔法】ロードの右腕にしてゴブリンの大魔導士。\\n禁忌の魔術を撃ち放ち、抗う全ての敵を滅却する。\\n\\n・バトル開始時、自身の物理防御力と魔法防御\\n\u3000力を小アップさせる。この防御力アップ効果\\n\u3000で上昇した防御力は、バトル中に受ける防御\\n\u3000力ダウンスキルの影響を受けない。\\n・バトル開始時、ダメージ上限スキルを使用し\\n\u3000て、一度の行動で与えるダメージの値が一定\\n\u3000を超えた場合、与えるダメージの値に応じて\\n\u3000ダメージ量を減少させる。\\n・ゴブリンメイスターから受けるすべての\\n\u3000ダメージで発生する、パーティキャラのＴＰ\\n\u3000回復量を中ダウンさせる。\\n・ダメージを受けるたびに【小鬼の紋章】を\\n\u3000１追加する。【小鬼の紋章】が10の時、\\n\u3000【小鬼の紋章】を10消費し、魔法の壷を爆破\\n\u3000しゴブリングレートとゴブリンメイスターに\\n\u3000魔法特大ダメージを与え、物理防御力と魔法\\n\u3000防御力を特大ダウンさせる。\\n・ユニオンバーストは、敵全体に魔法大\\n\u3000ダメージを与え、全ての召喚体を破壊する。\\n・前方１キャラにキャラの最大ＨＰに応じた\\n\u3000魔法割合ダメージを与える。\\n・残りＨＰが2400万を下回ると魔法攻撃力と\\n\u3000行動速度が特大アップし、攻撃行動を変更する。\\n・前から２番目のキャラを中心とした範囲内の\\n\u3000敵に魔法中ダメージを与えて、麻痺状態と\\n\u3000猛毒状態にする。', 309907, 0, 2, 309907, 270, 0, 0, 16, 0, 1.8, 2000, 'ゴブリンメイスター');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】駆走る神と伝承される山の土着神。\\n太古より好敵手を求め大地を雄々しく競奔する。\\n\\n・ユニオンバーストは、敵全体にキャラの最大\\n\u3000ＨＰに応じた物理割合ダメージを与え、\\n\u3000ノックバックさせる。\\n\u3000先頭のキャラにはさらに追加で物理\\n\u3000特大ダメージを与え、大きく吹き飛ばして\\n\u3000スタンさせる。\\n\u3000山神様がユニオンバーストを発動するたび\\n\u3000自身の物理防御力がダウンする。\\n\u3000この効果は累積する。\\n・魔法攻撃力の最も高い１キャラに、キャラの\\n\u3000最大ＨＰに応じた魔法割合ダメージを与え、\\n\u3000ＴＰを大きくダウンさせる。\\n・自身のＴＰと行動速度をアップさせる。\\n・山神様自身のＨＰが55％を切ると、さらに\\n\u3000攻撃が激しく凶暴になる代わりに\\n\u3000自身の物理防御力がダウンする。', 310000, 0, 1, 310000, 270, 0, 0, 16, 0, 1.6, 3000, '山神様');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】駆走る神と伝承される山の土着神。\\n太古より好敵手を求め大地を雄々しく競奔する。\\n\\n・ユニオンバーストは、敵全体にキャラの最大\\n\u3000ＨＰに応じた物理割合ダメージを与え、\\n\u3000ノックバックさせる。\\n\u3000先頭のキャラにはさらに追加で物理特大\\n\u3000ダメージを与え、ノックバックさせて\\n\u3000スタンさせる。\\n\u3000山神様がユニオンバーストを発動するたび\\n\u3000自身の物理防御力がダウンする。\\n\u3000この効果は累積する。\\n・自身のＴＰと行動速度をアップさせる。', 310001, 0, 1, 310000, 270, 0, 0, 16, 0, 1.6, 3000, '山神様');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】駆走る神と伝承される山の土着神。\\n太古より好敵手を求め大地を雄々しく競奔する。\\n\\n・ユニオンバーストは、敵全体にキャラの最大\\n\u3000ＨＰに応じた物理割合ダメージを与え、\\n\u3000ノックバックさせる。\\n\u3000先頭のキャラにはさらに追加で物理特大\\n\u3000ダメージを与え、ノックバックさせて\\n\u3000スタンさせる。\\n\u3000山神様がユニオンバーストを発動するたび\\n\u3000自身の物理防御力がダウンする。\\n\u3000この効果は累積する。\\n・魔法攻撃力の最も高い１キャラに、キャラの\\n\u3000最大ＨＰに応じた魔法割合ダメージを与え、\\n\u3000ＴＰをダウンさせる。\\n・自身のＴＰと行動速度をアップさせる。\\n・山神様自身のＨＰが55％を切ると、さらに\\n\u3000攻撃が激しく凶暴になる代わりに\\n\u3000自身の物理防御力がダウンする。', 310002, 0, 1, 310000, 270, 0, 0, 16, 0, 1.6, 3000, '山神様');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】駆走る神と伝承される山の土着神。\\n太古より好敵手を求め大地を雄々しく競奔する。\\n\\n・ユニオンバーストは、敵全体にキャラの最大\\n\u3000ＨＰに応じた物理割合ダメージを与え、\\n\u3000ノックバックさせる。\\n\u3000先頭のキャラにはさらに追加で物理特大\\n\u3000ダメージを与え、ノックバックさせて\\n\u3000スタンさせる。\\n\u3000山神様がユニオンバーストを発動するたび\\n\u3000自身の物理防御力がダウンする。\\n\u3000この効果は累積する。\\n・魔法攻撃力の最も高い１キャラに、キャラの\\n\u3000最大ＨＰに応じた魔法割合ダメージを与え、\\n\u3000ＴＰをダウンさせる。\\n・自身のＴＰと行動速度をアップさせる。\\n・山神様自身のＨＰが55％を切ると、さらに\\n\u3000攻撃が激しく凶暴になる代わりに\\n\u3000自身の物理防御力がダウンする。', 310003, 0, 1, 310000, 270, 0, 0, 16, 0, 1.6, 3000, '山神様');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ１】冒険者の力を試す、内なる影を\\n召喚。寒風吹き荒ぶ天下の険、自身の脆さが\\n試される。\\n\\n・一番前のキャラに物理ダメージを与える。', 310004, 0, 1, 310000, 270, 0, 0, 16, 0, 1.6, 3000, '山神様');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ２】益荒男の疾駆に大地が揺れる。\\nその様を祝賀するが如く、目出鯛は巌山を舞う。\\n\\n・ユニオンバーストは、敵全体にキャラの最大\\n\u3000ＨＰに応じた物理割合ダメージを与え、\\n\u3000ノックバックさせる。\\n\u3000先頭のキャラにはさらに追加で物理特大\\n\u3000ダメージを与え、大きく吹き飛ばして\\n\u3000スタンさせる。\\n\u3000山神様がユニオンバーストを発動するたび\\n\u3000自身の物理防御力がダウンする。\\n\u3000この効果は累積する。\\n・魔法攻撃力の最も高い２キャラに、キャラの\\n\u3000最大ＨＰに応じた魔法割合ダメージを与え、\\n\u3000ＴＰを大きくダウンさせる。\\n・後方に物理防御力ダウンフィールドを展開し、\\n\u3000さらに敵全体に物理中ダメージを与える。\\n\u3000目出鯛が背中を離れている間は、山神様の\\n\u3000魔法防御力が特大ダウン。', 310005, 0, 1, 310000, 270, 0, 0, 16, 0, 1.6, 3000, '山神様');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ３】神と競いし強者への、終の試煉。\\n互いの全てを以て、想い人へ駆け抜ける。\\n\\n・ユニオンバーストは、敵全体にキャラの最大\\n\u3000ＨＰに応じた物理割合ダメージを与え、\\n\u3000ノックバックさせる。\\n\u3000先頭のキャラにはさらに追加で物理特大\\n\u3000ダメージを与え、大きく吹き飛ばして\\n\u3000スタンさせる。\\n\u3000山神様がユニオンバーストを発動するたび\\n\u3000自身の物理防御力がダウンする。\\n\u3000この効果は累積する。\\n・魔法攻撃力の最も高い１キャラに、キャラの\\n\u3000最大ＨＰに応じた魔法割合ダメージを与え、\\n\u3000ＴＰを大きくダウンさせる。\\n・自身のＴＰと行動速度をアップさせる。\\n・バトル開始直後に、さらに攻撃が激しく\\n\u3000凶暴になる代わりに、自身の物理防御力が\\n\u3000ダウンする。', 310006, 0, 1, 310000, 270, 0, 0, 16, 0, 1.6, 3000, '山神様');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】忘却の秘境に、住まう若き巨竜。\\n禁忌に踏み入る冒険者を灼熱の業火で焼き払う。\\n\\n・ユニオンバーストは敵全体に物理割合ダメージ\\n\u3000を与え、さらにＴＰをダウンさせる。\\n・バトル開始時に、自身のＴＰを特大ダウン。\\n・前方1キャラを中心に一定範囲内のキャラに\\n\u3000魔法ダメージを与え、さらに物理防御力を\\n\u3000ダウンさせる。\\n・敵全体に物理ダメージを与え、さらに火傷\\n\u3000状態にする。\\n・敵全体に物理ダメージを与え、ノックバック\\n\u3000させる、さらに、ステータスアップ効果を\\n\u3000打ち消す。\\n\\n・全ターゲットがブレイクされると、自身のＴＰ\\n\u3000を特大ダウン。\\n・ラースドラゴン自身の残りＨＰが10％を切る\\n\u3000とさらに攻撃が激しく強暴になり、ブレイク\\n\u3000されなくなる。\\n・バトルがタイムアップすると、敵全体を戦闘\\n\u3000不能にする。\\n', 310100, 0, 1, 310100, 270, 0, 0, 14, 0, 2.6, 1000, 'ラースドラゴン');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】忘却の秘境に、住まう若き巨竜。\\n禁忌に踏み入る冒険者を灼熱の業火で焼き払う。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・ラースドラゴンから受けるすべてのダメージで\\n\u3000発生する、パーティキャラのＴＰ回復量を中ダ\\n\u3000ウンさせる。\\n・ユニオンバーストは、敵全体のバリアを解除\\n\u3000し、敵全体にキャラの最大ＨＰに応じた物理割\\n\u3000合ダメージを与え、さらにＴＰを小ダウンさせ\\n\u3000る。\\n・最も近い敵を中心にした範囲内の敵すべてに\\n\u3000キャラの最大ＨＰに応じた物理割合ダメージを\\n\u3000与え、さらに物理防御力を大ダウンさせる。\\n\u3000このスキルの効果はダメージを無効化しても付\\n\u3000与される。\\n・敵全体に物理中ダメージを与え、さらに火傷状\\n\u3000態にする。\\n\u3000このスキルにより付与された火傷のダメージで\\n\u3000は、ＴＰが回復しない。\\n・敵全体のバリアを解除し、敵全体に物理中ダ\\n\u3000メージを与え、ノックバックさせる、さらに、\\n\u3000ステータスアップ効果を打ち消す。\\n\u3000このスキルの状態異常と効果はダメージを無効\\n\u3000化しても付与される。\\n・向かって左側のターゲットのブレイク時、自身\\n\u3000の物理防御力と魔法防御力が大ダウン。\\n・中央のターゲットのブレイク時、自身の物理防\\n\u3000御力と魔法防御力が大ダウン。\\n・向かって右側のターゲットのブレイク時、自身\\n\u3000の物理防御力と魔法防御力が大ダウン。\\n・全ターゲットがブレイクされると、自身のＴＰ\\n\u3000を特大ダウン。\\n・ラースドラゴン自身の残りＨＰが30％を切る\\n\u3000とさらに攻撃が激しく強暴になり、ブレイク\\n\u3000されなくなるが、自身の物理防御力と魔法防御\\n\u3000力が大ダウンする。\\n・最も近い敵１キャラに物理大ダメージを与える。', 310101, 0, 1, 310101, 270, 0, 0, 14, 0, 2.6, 1000, 'ラースドラゴン');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】海蝕洞の支配者として\\n君臨する、サメエイの魔物。凶猛な\\n欲望を全て捕食に注ぐ海の大悪党。\\n\\n・敵全体に物理特大ダメージを与え\\n\u3000物理防御力と魔法攻撃力を\\n\u3000ダウンさせる。\\n\\n・前方範囲内の敵すべてに\\n\u3000魔法小ダメージを与え、ＴＰと\\n\u3000ＴＰ上昇率をダウンさせる。', 310200, 0, 1, 310200, 270, 0, 0, 16, 0, 1.6, 1000, 'シャークヘッドレイ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】塔の魔力を吸収した、暴食の巨大鮫鱏。\\n音波で感覚を狂わせ、鈍った獲物を喰らい尽くす。\\n\\n・敵全体に物理特大ダメージを与え、物理防御力\\n\u3000と魔法攻撃力をダウンさせる。\\n・最もＴＰの高い敵１キャラに魔法中ダメージを\\n\u3000与え、麻痺させる。\\n\u3000さらに挑発状態にする。\\n・挑発を無視して、最もＨＰの高い敵１キャラに\\n\u3000毎秒増加する継続ダメージを与える。', 310201, 0, 1, 310201, 270, 0, 0, 16, 0, 1.6, 1000, 'シャークグリード');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('', 310300, 0, 1, 310300, 270, 0, 0, 16, 0, 1.8, 3000, 'アンチビースト');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】愛の力を求め顕現した、負の魔法生物。\\n皆の心の中の愛の力を歪め世界に災いをもたらす。\\n\\n・ユニオンバーストは、異次元より取り出した\\n\u3000アイテムで攻撃を仕掛ける。アイテムによって\\n\u3000効果が変化する。\\n\u3000ハンマーの場合、敵全体にキャラの最大ＨＰに\\n\u3000応じた物理割合ダメージを与え、物理攻撃力を\\n\u3000大幅にダウンさせる。\\n\u3000シンバルの場合、敵全体にキャラの最大ＨＰに\\n\u3000応じた物理割合ダメージを与え、魔法攻撃力を\\n\u3000大幅にダウンさせる。\\n\u3000ボムの場合、敵全体にキャラの最大ＨＰに\\n\u3000応じた物理割合ダメージを与え、\\n\u3000呪い状態にする。\\n\u3000このスキルの状態異常はダメージを無効化して\\n\u3000も付与される。\\n・一番前の敵を中心に、範囲内の敵すべてに\\n\u3000物理中ダメージを与え、さらにノックバック\\n\u3000させる。\\n・一定範囲内の敵すべてに物理大ダメージを\\n\u3000与える。', 310301, 0, 1, 310300, 270, 0, 0, 16, 0, 1.8, 3000, 'アンチビースト');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】愛の力を求め顕現した、負の魔法生物。\\n皆の心の中の愛の力を歪め世界に災いをもたらす。\\n\\n・ユニオンバーストは、異次元より取り出した\\n\u3000アイテムで攻撃を仕掛ける。アイテムによって\\n\u3000効果が変化する。\\n\u3000ハンマーの場合、敵全体にキャラの最大ＨＰに\\n\u3000応じた物理割合ダメージを与え、物理攻撃力を\\n\u3000大幅にダウンさせる。\\n\u3000シンバルの場合、敵全体にキャラの最大ＨＰに\\n\u3000応じた物理割合ダメージを与え、魔法攻撃力を\\n\u3000大幅にダウンさせる。\\n\u3000ボムの場合、敵全体にキャラの最大ＨＰに\\n\u3000応じた物理割合ダメージを与え、\\n\u3000呪い状態にする。\\n\u3000このスキルの状態異常はダメージを無効化して\\n\u3000も付与される。\\n・一番前の敵を中心に、範囲内の敵すべてに\\n\u3000物理中ダメージを与え、さらにノックバック\\n\u3000させる。\\n・一定範囲内の敵すべてに物理大ダメージを\\n\u3000与える。', 310302, 0, 1, 310300, 270, 0, 0, 16, 0, 1.8, 3000, 'アンチビースト');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】愛の力を求め顕現した、負の魔法生物。\\n皆の心の中の愛の力を歪め世界に災いをもたらす。\\n\\n・ユニオンバーストは、異次元より取り出した\\n\u3000アイテムで攻撃を仕掛ける。アイテムによって\\n\u3000効果が変化する。\\n\u3000ハンマーの場合、敵全体にキャラの最大ＨＰに\\n\u3000応じた物理割合ダメージを与え、物理攻撃力を\\n\u3000大幅にダウンさせる。\\n\u3000シンバルの場合、敵全体にキャラの最大ＨＰに\\n\u3000応じた物理割合ダメージを与え、魔法攻撃力を\\n\u3000大幅にダウンさせる。\\n\u3000ボムの場合、敵全体にキャラの最大ＨＰに\\n\u3000応じた物理割合ダメージを与え、\\n\u3000呪い状態にする。\\n\u3000このスキルの状態異常はダメージを無効化して\\n\u3000も付与される。\\n・一番前の敵を中心に、範囲内の敵すべてに\\n\u3000物理中ダメージを与え、さらにノックバック\\n\u3000させる。\\n・一定範囲内の敵すべてに物理大ダメージを\\n\u3000与える。\\n・アンチビースト自身のＨＰが50％を切ると、\\n\u3000さらに攻撃が激しく凶暴になる。', 310303, 0, 1, 310300, 270, 0, 0, 16, 0, 1.8, 3000, 'アンチビースト');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ１】闇の力によって染め上げられた\\n愛と欲望が形となった負の魔法生物。世界を\\n無慈悲にただ歪めはじめる。\\n\\n・ユニオンバーストは、異次元より取り出した\\n\u3000アイテムで攻撃を仕掛ける。アイテムによって\\n\u3000効果が変化する。\\n\u3000ハンマーの場合、敵全体にキャラの最大ＨＰに\\n\u3000応じた物理割合ダメージを与え、物理攻撃力を\\n\u3000大幅にダウンさせる。\\n\u3000シンバルの場合、敵全体にキャラの最大ＨＰに\\n\u3000応じた物理割合ダメージを与え、魔法攻撃力を\\n\u3000大幅にダウンさせる。\\n\u3000ボムの場合、敵全体にキャラの最大ＨＰに\\n\u3000応じた物理割合ダメージを与え、\\n\u3000呪い状態にする。\\n・一番前の敵を中心に、範囲内の敵すべてに\\n\u3000物理中ダメージを与え、さらにノックバック\\n\u3000させる。\\n・一定範囲内の敵すべてに物理大ダメージを\\n\u3000与える。', 310304, 0, 1, 310304, 270, 0, 0, 16, 0, 4.2, 3000, 'アンチビースト');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ２】魔法少女のシャドウを召喚。\\n歪んだ負の絶望影が、魔法少女たちの愛と\\n希望の力を試す。\\n\\n・シャドウの戦いを静かに見守る。', 310305, 0, 1, 310300, 270, 0, 0, 16, 0, 1.8, 3000, 'アンチビースト');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ３】憤怒する負の魔法生物はとうとう\\n真の力を解放する。魔法少女の心を打ち砕かん\\nと、歪んだ愛の力ですべてを捻じ伏せる。\\n\\n・ユニオンバーストは、異次元より取り出した\\n\u3000アイテムで攻撃を仕掛ける。アイテムによって\\n\u3000効果が変化する。\\n\u3000ハンマーの場合、敵全体にキャラの最大ＨＰに\\n\u3000応じた物理割合ダメージを与え、物理攻撃力を\\n\u3000大幅にダウンさせる。\\n\u3000シンバルの場合、敵全体にキャラの最大ＨＰに\\n\u3000応じた物理割合ダメージを与え、魔法攻撃力を\\n\u3000大幅にダウンさせる。\\n\u3000ボムの場合、敵全体にキャラの最大ＨＰに\\n\u3000応じた物理割合ダメージを与え、\\n\u3000呪い状態にする。\\n・一番前の敵を中心に、範囲内の敵すべてに\\n\u3000物理中ダメージを与え、さらにノックバック\\n\u3000させる。\\n・一定範囲内の敵すべてに物理大ダメージを\\n\u3000与える。\\n・バトル開始直後に、さらに攻撃が激しく\\n\u3000凶暴になる。', 310306, 0, 1, 310300, 270, 0, 0, 16, 0, 1.8, 3000, 'アンチビースト');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】塔の魔力に導かれた無邪気な奇術師。\\n披露する手品は楽しめたものではなく凶悪な兵器。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を中アップさせる。\\n\u3000この防御力アップ効果で上昇した防御力は、バ\\n\u3000トル中に受ける防御力ダウンスキルの影響を受\\n\u3000けない。\\n・イノセントマジシャンから受けるすべての\\n\u3000ダメージで発生する、パーティキャラのＴＰ\\n\u3000回復量を中ダウンさせる。\\n・ユニオンバーストは、異次元より取り出した\\n\u3000アイテムで攻撃を仕掛ける。アイテムによって\\n\u3000効果が変化する。\\n\u3000ハンマーの場合、敵全体にキャラの最大ＨＰに\\n\u3000応じた物理割合ダメージを与え、物理攻撃力を\\n\u3000大幅にダウンさせる。\\n\u3000シンバルの場合、敵全体にキャラの最大ＨＰに\\n\u3000応じた物理割合ダメージを与え、魔法攻撃力を\\n\u3000大幅にダウンさせる。\\n\u3000ボムの場合、敵全体にキャラの最大ＨＰに\\n\u3000応じた物理割合ダメージを与え、\\n\u3000スタン状態にする。\\n\u3000このスキルの状態異常はダメージを無効化して\\n\u3000も付与される。\\n・一番前の敵を中心に、範囲内の敵すべてに\\n\u3000物理中ダメージを与え、さらにノックバック\\n\u3000させる。\\n・一定範囲内の敵すべてに物理中ダメージを\\n\u3000与える。\\n・イノセントマジシャン自身のＨＰが50％を\\n\u3000切ると、さらに攻撃が激しく凶暴になる。', 310307, 0, 1, 310307, 270, 0, 0, 16, 0, 2.0, 3000, 'イノセントマジシャン');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】湿林に潜み獲物を付け狙う\\nカメレオンの魔物。臆病で狡猾な気\\n性だが、怒るとツノを向け猛突進。\\n\\n・ユニオンバーストは、敵全体に物\\n\u3000理大ダメージを与え、物理防御力\\n\u3000を大ダウンさせる。\\n\\n・ランダムな１キャラに\\n\u3000物理中ダメージを与える。\\n\\n・カメレオプスが一定時間背景に擬\\n\u3000態し、回避を極大アップ、行動速\\n\u3000度を特大アップ、物理防御力が大\\n\u3000ダウンする。\\n\\n・前方３キャラに物理中ダメージを\\n\u3000与える。', 310400, 0, 1, 310400, 270, 0, 0, 11, 0, 2.4, 1000, 'カメレオプス');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】湿林に潜み獲物を付け狙う\\nカメレオンの魔物。臆病で狡猾な気\\n性だが、怒るとツノを向け猛突進。\\n\\n・ユニオンバーストは、敵全体に物\\n\u3000理大ダメージを与え、物理防御力\\n\u3000を大ダウンさせる。\\n\\n・ランダムな１キャラに\\n\u3000物理中ダメージを与える。\\n\\n・カメレオプスが一定時間背景に擬\\n\u3000態し、回避を極大アップ、行動速\\n\u3000度を特大アップ、物理防御力が大\\n\u3000ダウンする。\\n\\n・前方３キャラに物理中ダメージを\\n\u3000与える。', 310401, 0, 1, 310401, 270, 0, 0, 11, 0, 2.4, 1000, 'カメレオプス');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('', 310500, 0, 1, 310500, 270, 0, 0, 16, 0, 1.6, 3000, 'ラウドラパーン');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】ポップな体色をした大ウサギの魔物。\\n見た目とは裏腹に迷惑極まりないその歌声は、\\n大地を震わせ冒険者の心をも折る。\\n\\n・ユニオンバーストは、敵全体にキャラの最大\\n\u3000ＨＰに応じた物理割合ダメージを与え、\\n\u3000ノックバックさせる。その後、目を\\n\u3000回している間、自身の物理・魔法防御力が\\n\u3000大幅にダウンする。\\n・一番前のキャラを中心として、一定範囲に\\n\u3000物理中ダメージを与え、さらに行動速度を\\n\u3000ダウンさせる。', 310501, 0, 1, 310500, 270, 0, 0, 16, 0, 1.6, 3000, 'ラウドラパーン');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】ポップな体色をした大ウサギの魔物。\\n見た目とは裏腹に迷惑極まりないその歌声は、\\n大地を震わせ冒険者の心をも折る。\\n\\n・ユニオンバーストは、敵全体にキャラの最大\\n\u3000ＨＰに応じた物理割合ダメージを与え、\\n\u3000ノックバックさせる。その後、目を\\n\u3000回している間、自身の物理・魔法防御力が\\n\u3000大幅にダウンする。\\n・一番前のキャラを中心として、一定範囲に\\n\u3000物理中ダメージを与え、さらに行動速度を\\n\u3000ダウンさせる。\\n・前から３キャラに物理小ダメージを与え、\\n\u3000さらに物理防御力を大ダウンさせる。', 310502, 0, 1, 310500, 270, 0, 0, 16, 0, 1.6, 3000, 'ラウドラパーン');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】ポップな体色をした大ウサギの魔物。\\n見た目とは裏腹に迷惑極まりないその歌声は、\\n大地を震わせ冒険者の心をも折る。\\n\\n・ユニオンバーストは、敵全体にキャラの最大\\n\u3000ＨＰに応じた物理割合ダメージを与え、\\n\u3000ノックバックさせる。その後、目を\\n\u3000回している間、自身の物理・魔法防御力が\\n\u3000大幅にダウンする。\\n・一番前のキャラを中心として、一定範囲に\\n\u3000物理中ダメージを与え、さらに行動速度を\\n\u3000ダウンさせる。\\n・前から３キャラに物理小ダメージを与え、\\n\u3000さらに物理防御力を大ダウンさせる。\\n・ラウドラパーン自身のＨＰが40％を切ると、\\n\u3000さらに攻撃が激しく凶暴になる。', 310503, 0, 1, 310500, 270, 0, 0, 16, 0, 1.6, 3000, 'ラウドラパーン');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ１】ニュージェネレーションズの\\nシャドウを召喚。森で出会った大ウサギ。\\n３人は夢をあきらめない心を貫き通せるか、\\n大ウサギは各個の弱さを見せつける。\\n\\n・一番前のキャラに物理ダメージを与える。', 310504, 0, 1, 310500, 270, 0, 0, 16, 0, 1.6, 3000, 'ラウドラパーン');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ２】森の人気者の歌声に魔物たちが\\n大挙する。血沸き肉躍る野生の宴会が今、\\n開幕する。\\n\\n・ブルーゴーレム、スリーピィオウル、\\n\u3000ツキツキを倒すと次のＭＯＤＥに移行する。\\n\\n・ラウドラパーンは、一番前のキャラに\\n\u3000物理ダメージを与える。', 310505, 0, 1, 310500, 270, 0, 0, 16, 0, 1.6, 3000, 'ラウドラパーン');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ３】宴も終焉、大兎が最後の力を振り\\n絞る。咆哮にも似た壊震の歌声が、３人の夢道を\\n阻む。\\n\\n・ユニオンバーストは、敵全体にキャラの最大\\n\u3000ＨＰに応じた物理割合ダメージを与え、\\n\u3000ノックバックさせる。その後、目を\\n\u3000回している間、自身の物理・魔法防御力が\\n\u3000大幅にダウンする。\\n・一番前のキャラを中心として、一定範囲に\\n\u3000物理中ダメージを与え、さらに行動速度を\\n\u3000ダウンさせる。\\n・前から３キャラに物理小ダメージを与え、\\n\u3000さらに物理防御力を大ダウンさせる。\\n・バトル開始直後に、さらに攻撃が激しく\\n\u3000凶暴になる。', 310506, 0, 1, 310500, 270, 0, 0, 16, 0, 1.6, 3000, 'ラウドラパーン');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】世にも奇妙な歌う大ウサギ\\nの魔獣。その歌声はとても褒められ\\nたものではなく、甚だ迷惑である。\\n\\n・ユニオンバーストは、敵全体に\\n\u3000キャラの最大ＨＰに応じた物理割\\n\u3000合ダメージを与え、ノックバック\\n\u3000させる。その後、目を回している\\n\u3000間、自身の物理防御力と魔法防御\\n\u3000力を特大ダウン。\\n\\n・一番前のキャラを中心として、\\n\u3000一定範囲に物理中ダメージを与\\n\u3000え、さらに行動速度を特大ダウン\\n\u3000とスタンさせる。\\n\\n・前から３キャラに物理小ダメージ\\n\u3000を与え、さらに物理防御力を大ダ\\n\u3000ウンさせる。', 310507, 0, 1, 310507, 270, 0, 0, 16, 0, 1.6, 3000, 'バニフォルテ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('', 310600, 0, 1, 310600, 270, 310600, 0, 16, 310600, 1.6, 3000, '葛藤のうえきちゃん');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【魔法】魔物かはたまた精霊なのか、謎多き巨躯\\nのいきもの。如何ともし難いその表情のまま謎の\\n花粉を噴霧し、市中を混乱へと誘い落とす。\\n\\n・ユニオンバーストは、敵全体に魔法大ダメージ\\n\u3000を与え、物理防御力と魔法防御力をダウンさせ\\n\u3000る。\\n・前方範囲内の敵に物理ダメージを与え、ノック\\n\u3000バックさせる。\\n・左右の葉っぱは、ブレイクすると一定時間消滅\\n\u3000する。\\n・向かって左側の葉っぱのブレイク時、物理防御\\n\u3000力と魔法防御力が小ダウン。\\n・本体のブレイク時、物理防御力と魔法防御力が\\n\u3000大ダウン。\\n・向かって右側の葉っぱのブレイク時、物理防御\\n\u3000力と魔法防御力が小ダウン。', 310601, 0, 1, 310600, 270, 310600, 0, 16, 310600, 1.6, 3000, '葛藤のうえきちゃん');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【魔法】魔物かはたまた精霊なのか、謎多き巨躯\\nのいきもの。如何ともし難いその表情のまま謎の\\n花粉を噴霧し、市中を混乱へと誘い落とす。\\n\\n・ユニオンバーストは、敵全体に魔法大ダメージ\\n\u3000を与え、物理防御力と魔法防御力をダウンさせ\\n\u3000る。\\n・前方範囲内の敵に物理ダメージを与え、ノック\\n\u3000バックさせる。\\n・きゅうこんちゃんを召喚。\\n\u3000きゅうこんちゃんは攻撃の対象にならず、一定\\n\u3000時間が経つと自爆して前方範囲内のキャラに魔\\n\u3000法ダメージを与える。\\n・左右の葉っぱは、ブレイクすると一定時間消滅\\n\u3000する。\\n・向かって左側の葉っぱのブレイク時、物理防御\\n\u3000力と魔法防御力が小ダウン。\\n・本体のブレイク時、物理防御力と魔法防御力が\\n\u3000大ダウン。\\n・向かって右側の葉っぱのブレイク時、物理防御\\n\u3000力と魔法防御力が小ダウン。', 310602, 0, 1, 310600, 270, 310600, 0, 16, 310600, 1.6, 3000, '葛藤のうえきちゃん');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【魔法】魔物かはたまた精霊なのか、謎多き巨躯\\nのいきもの。如何ともし難いその表情のまま謎の\\n花粉を噴霧し、市中を混乱へと誘い落とす。\\n\\n・ユニオンバーストは、敵全体に魔法大ダメージ\\n\u3000を与え、物理防御力と魔法防御力をダウンさせ\\n\u3000る。\\n・前方範囲内の敵に物理ダメージを与え、ノック\\n\u3000バックさせる。\\n・きゅうこんちゃんを召喚。\\n\u3000きゅうこんちゃんは攻撃の対象にならず、一定\\n\u3000時間が経つと自爆して前方範囲内のキャラに魔\\n\u3000法ダメージを与える。\\n・左右の葉っぱは、ブレイクすると一定時間消滅\\n\u3000する。\\n・向かって左側の葉っぱのブレイク時、物理防御\\n\u3000力と魔法防御力が小ダウン。\\n・本体のブレイク時、物理防御力と魔法防御力が\\n\u3000大ダウン。\\n・向かって右側の葉っぱのブレイク時、物理防御\\n\u3000力と魔法防御力が小ダウン。\\n・うえきちゃん自身のＨＰが40％を切ると、\\n\u3000さらに攻撃が激しく凶暴になる。', 310603, 0, 1, 310603, 270, 310600, 0, 16, 310600, 1.6, 3000, '葛藤のうえきちゃん');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('', 310604, 0, 1, 310604, 270, 310600, 0, 16, 310600, 1.6, 3000, '葛藤のうえきちゃん');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【MODE１】終に極大化した謎のいきもの。\\nまたしても如何ともし難い表情で、大滝の涙が\\n大地を濡らしその涙は意思なく皆を蝕んでゆく。\\n\\n・ユニオンバーストは、敵全体に魔法大ダメージ\\n\u3000を与え、物理防御力と魔法防御力をダウンさせ\\n\u3000る。\\n・敵全体のＴＰを上昇させたのち、継続魔法ダメ\\n\u3000ージを与えるフィールドを展開する。\\n・左右の葉っぱは、ブレイクすると一定時間消滅\\n\u3000する。\\n・向かって左側の葉っぱのブレイク時、物理防御\\n\u3000力と魔法防御力が小ダウン。\\n・本体のブレイク時、物理防御力と魔法防御力が\\n\u3000大ダウン。\\n・向かって右側の葉っぱのブレイク時、物理防御\\n\u3000力と魔法防御力が小ダウン。', 310605, 0, 1, 310604, 270, 310600, 0, 16, 310600, 1.6, 3000, '葛藤のうえきちゃん');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【MODE２】冒険者の抵抗に怯んだか、両葉と\\nその巨躯を晒しつつ佇む。だが、その表情は相も\\n変わらず、如何ともし難い表情のまま。\\n\\n・全てのターゲットがブレイク無効。\\n・ユニオンバーストは、敵全体に魔法大ダメージ\\n\u3000を与え、物理防御力と魔法防御力をダウンさせ\\n\u3000る。\\n・前方範囲内の敵に物理ダメージを与え、ノック\\n\u3000バックさせる。\\n・きゅうこんちゃんを召喚。\\n\u3000きゅうこんちゃんは攻撃の対象にならず、一定\\n\u3000時間が経つと自爆して前方範囲内のキャラに魔\\n\u3000法ダメージを与える。\\n', 310606, 0, 1, 310604, 270, 310600, 0, 16, 310600, 1.6, 3000, '葛藤のうえきちゃん');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【MODE３】その変わらぬ表情は、終にも\\n変わらず冒険者は、そのいきものの狂気と畏怖に\\n慄く。果たしていきものの謎は解かれるのか…。\\n\\n・ユニオンバーストは、敵全体に魔法大ダメージ\\n\u3000を与え、物理防御力と魔法防御力をダウンさせ\\n\u3000る。\\n・前方範囲内の敵に物理ダメージを与え、ノック\\n\u3000バックさせる。\\n・きゅうこんちゃんを召喚。\\n\u3000きゅうこんちゃんは攻撃の対象にならず、一定\\n\u3000時間が経つと自爆して前方範囲内のキャラに魔\\n\u3000法ダメージを与える。\\n・左右の葉っぱは、ブレイクすると一定時間消滅\\n\u3000する。\\n・向かって左側の葉っぱのブレイク時、物理防御\\n\u3000力と魔法防御力が小ダウン。\\n・本体のブレイク時、物理防御力と魔法防御力が\\n\u3000大ダウン。\\n・向かって右側の葉っぱのブレイク時、物理防御\\n\u3000力と魔法防御力が小ダウン。', 310607, 0, 1, 310604, 270, 310600, 0, 16, 310600, 1.6, 3000, '葛藤のうえきちゃん');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('', 310700, 0, 1, 310700, 270, 0, 0, 16, 0, 1.4, 3000, 'なかよしＸ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】規格外のアイデアと歪んだ情熱から爆誕\\nした鋼鉄の巨人。礎となった者の特性を、異常な\\n解釈で再構築し敵の言語中枢と精神を破壊する。\\n\\n・自身が毒、猛毒、呪い、呪詛、火傷の効果を\\n\u3000受けると、自身の物理防御力と魔法防御力と\\n\u3000行動速度が大ダウンする。\\n・ユニオンバーストは、敵全体にキャラの\\n\u3000最大ＨＰに応じた魔法割合ダメージを与える。\\n・自身の物理攻撃力をアップさせたあと、\\n\u3000敵全体に物理ダメージを与える。\\n・前方３キャラに最大ＨＰに応じた魔法割合\\n\u3000ダメージを与え、行動速度をダウンさせる。', 310701, 0, 1, 310700, 270, 0, 0, 16, 0, 1.4, 3000, 'なかよしＸ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】規格外のアイデアと歪んだ情熱から爆誕\\nした鋼鉄の巨人。礎となった者の特性を、異常な\\n解釈で再構築し敵の言語中枢と精神を破壊する。\\n\\n・自身が毒、猛毒、呪い、呪詛、火傷の効果を\\n\u3000受けると、自身の物理防御力と魔法防御力と\\n\u3000行動速度が大ダウンする。\\n・ユニオンバーストは、敵全体にキャラの\\n\u3000最大ＨＰに応じた魔法割合ダメージを与える。\\n・自身の物理攻撃力をアップさせたあと、\\n\u3000敵全体に物理ダメージを与える。\\n・前方３キャラに最大ＨＰに応じた魔法割合\\n\u3000ダメージを与え、行動速度をダウンさせる。', 310702, 0, 1, 310700, 270, 0, 0, 16, 0, 1.4, 3000, 'なかよしＸ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】規格外のアイデアと歪んだ情熱から爆誕\\nした鋼鉄の巨人。礎となった者の特性を、異常な\\n解釈で再構築し敵の言語中枢と精神を破壊する。\\n\\n・自身が毒、猛毒、呪い、呪詛、火傷の効果を\\n\u3000受けると、自身の物理防御力と魔法防御力と\\n\u3000行動速度が大ダウンする。\\n・ユニオンバーストは、敵全体にキャラの\\n\u3000最大ＨＰに応じた魔法割合ダメージを与える。\\n・自身の物理攻撃力をアップさせたあと、\\n\u3000敵全体に物理ダメージを与える。\\n・前方３キャラに最大ＨＰに応じた魔法割合\\n\u3000ダメージを与え、行動速度をダウンさせる。\\n・なかよしＸ自身のＨＰが40％を切ると、\\n\u3000さらに攻撃が激しく凶暴になる。', 310703, 0, 1, 310700, 270, 0, 0, 16, 0, 1.4, 3000, 'なかよしＸ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ１】【メルクリウス財団】の\\nシャドウを召喚。自分たちの過ちを\\n嘲笑うかのように、影の姿で皆を翻弄する。\\n\\n・自身が毒、猛毒、呪い、火傷の効果を受けると、\\n\u3000自身の物理防御力と魔法防御力と行動速度\\n\u3000が大ダウンする。\\n・目の前の敵１キャラに物理ダメージを与える。', 310704, 0, 1, 310700, 270, 0, 0, 16, 0, 4.2, 3000, 'なかよしＸ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ２】鋼鉄の球体が、完璧なちぇる語で\\n囁きかける。「ちぇる～ん」。心を掴み離さない\\n洗脳の言の葉は、確実に世界をちぇるへと誘う。\\n\\n・ランダムな１キャラに魔法中ダメージを与え、\\n\u3000沈黙と誘惑状態にする。', 310705, 0, 1, 310700, 270, 0, 0, 16, 0, 1.4, 3000, 'なかよしＸ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ３】鋼鉄の絡繰が再び大地に立つ。\\n諸刃の剣・ファイナルモードを解放し、\\nなかよし部の３人を追い詰める。\\n\\n・自身が毒、猛毒、呪い、火傷の効果を受けると、\\n\u3000自身の物理防御力と魔法防御力と行動速度\\n\u3000が大ダウンする。\\n・ユニオンバーストは、敵全体にキャラの\\n\u3000最大ＨＰに応じた魔法割合ダメージを与える。\\n・自身の物理攻撃力をアップさせたあと、\\n\u3000敵全体に物理ダメージを与える。\\n・前方３キャラに最大ＨＰに応じた魔法割合\\n\u3000ダメージを与え、行動速度をダウンさせる。\\n・バトル開始直後に、さらに攻撃が激しく\\n\u3000凶暴になる。', 310706, 0, 1, 310700, 270, 0, 0, 16, 0, 1.4, 3000, 'なかよしＸ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】悪徳監査官に雇われた忍びの頭領。\\n義を失った忍びは、その身を金に落とす。だが\\nしかし、円熟の業は健在で皆の行く手を阻む。\\n\\n・バトル開始後、監査官が登場する。監査官がダ\\n\u3000メージを受けると、その直後に忍びの頭領ハン\\n\u3000ゾウの物理防御力と魔法防御力を特大ダウンさ\\n\u3000せる。\\n・ユニオンバーストは、敵全体にキャラの最大Ｈ\\n\u3000Ｐに応じた物理割合ダメージを与える。\\n・大ガマに変化して毒を吐き、敵全体を毒状態に\\n\u3000する。この攻撃は必ず命中する。\\n・敵全体に物理中ダメージを与える。', 310800, 0, 1, 310800, 270, 0, 0, 16, 0, 2.8, 3000, '忍びの頭領ハンゾウ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】悪徳監査官に雇われた忍びの頭領。\\n義を失った忍びは、その身を金に落とす。だが\\nしかし、円熟の業は健在で皆の行く手を阻む。\\n\\n・バトル開始後、監査官が登場する。監査官がダ\\n\u3000メージを受けると、その直後に忍びの頭領ハン\\n\u3000ゾウの物理防御力と魔法防御力を特大ダウンさ\\n\u3000せる。\\n・ユニオンバーストは、敵全体にキャラの最大Ｈ\\n\u3000Ｐに応じた物理割合ダメージを与える。\\n・大ガマに変化して毒を吐き、敵全体を毒状態に\\n\u3000する。この攻撃は必ず命中する。\\n・敵全体に物理中ダメージを与える。', 310801, 0, 1, 310800, 270, 0, 0, 16, 0, 2.8, 3000, '忍びの頭領ハンゾウ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】悪徳監査官に雇われた忍びの頭領。\\n義を失った忍びは、その身を金に落とす。だが\\nしかし、円熟の業は健在で皆の行く手を阻む。\\n\\n・バトル開始後、監査官が登場する。監査官がダ\\n\u3000メージを受けると、その直後に忍びの頭領ハン\\n\u3000ゾウの物理防御力と魔法防御力を特大ダウンさ\\n\u3000せる。\\n・ユニオンバーストは、敵全体にキャラの最大Ｈ\\n\u3000Ｐに応じた物理割合ダメージを与える。\\n・大ガマに変化して毒を吐き、敵全体を毒状態に\\n\u3000する。自身のＨＰが30%以下の場合、敵全体\\n\u3000を猛毒状態にする。この攻撃は必ず命中する。\\n・敵全体に物理中ダメージを与える。自身のＨＰ\\n\u3000が30%以下の場合、さらに敵全体をスタンさ\\n\u3000せる。\\n・忍びの頭領ハンゾウ自身のＨＰが30％を切る\\n\u3000と、スキルの効果が変化する。', 310802, 0, 1, 310800, 270, 0, 0, 16, 0, 2.8, 3000, '忍びの頭領ハンゾウ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】悪徳監査官に雇われた忍びの頭領。\\n義を失った忍びは、その身を金に落とす。だが\\nしかし、円熟の業は健在で皆の行く手を阻む。\\n\\n・バトル開始後、監査官が登場する。監査官がダ\\n\u3000メージを受けると、その直後に忍びの頭領ハン\\n\u3000ゾウの物理防御力と魔法防御力を特大ダウンさ\\n\u3000せる。\\n・ユニオンバーストは、敵全体にキャラの最大Ｈ\\n\u3000Ｐに応じた物理割合ダメージを与える。\\n・大ガマに変化して毒を吐き、敵全体を毒状態に\\n\u3000する。自身のＨＰが30%以下の場合、敵全体\\n\u3000を猛毒状態にする。この攻撃は必ず命中する。\\n・敵全体に物理中ダメージを与える。自身のＨＰ\\n\u3000が30%以下の場合、さらに敵全体をスタンさ\\n\u3000せる。\\n・忍びの頭領ハンゾウ自身のＨＰが30％を切る\\n\u3000と、スキルの効果が変化する。', 310803, 0, 1, 310800, 270, 0, 0, 16, 0, 2.8, 3000, '忍びの頭領ハンゾウ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ１】【牧場（エリザベスパーク）】の\\nシャドウを召喚。幻術で造りだした四農士の幻影\\nが皆の帰る場所を再び窮地に陥れる。\\n\\n・目の前の敵１キャラに物理ダメージを与える。', 310804, 0, 1, 310801, 270, 0, 0, 16, 0, 2.8, 3000, '忍びの頭領ハンゾウ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ２】秘伝の口寄せで忍蛙に化け、\\nガマの猛毒をあたり一帯に噴霧する。その猛毒は\\nひと吸いで全身を蝕み、徐々に躰を爛れ落とす。\\n\\n・バトル開始後、監査官が登場する。監査官がダ\\n\u3000メージを受けると、その直後に忍びの頭領ハン\\n\u3000ゾウの物理防御力と魔法防御力を特大ダウンさ\\n\u3000せる。\\n・ユニオンバーストは、敵全体にキャラの最大Ｈ\\n\u3000Ｐに応じた物理割合ダメージを与える。\\n・大ガマに変化して猛毒を吐き、敵全体を猛毒状\\n\u3000態にする。この攻撃は必ず命中する。\\n・敵全体に物理中ダメージを与え、さらに敵全体\\n\u3000をスタンさせる。', 310805, 0, 1, 310800, 270, 0, 0, 16, 0, 2.8, 3000, '忍びの頭領ハンゾウ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ３】最期は、忍びとしての尊厳を取り\\n戻し、己が真の力を発揮する。紫電一閃の早業に\\n叫声を上げる間もなく屍と化す。\\n\\n・バトル開始直後に、自身のスキル威力をアップ\\n\u3000させる。\\n・ユニオンバーストは、敵全体にキャラの最大Ｈ\\n\u3000Ｐに応じた物理割合ダメージを与える。\\n・大ガマに変化して猛毒を吐き、敵全体を猛毒状\\n\u3000態にする。この攻撃は必ず命中する。\\n・敵全体に物理中ダメージを与え、さらに敵全体\\n\u3000をスタンさせる。', 310806, 0, 1, 310800, 270, 0, 0, 16, 0, 2.8, 3000, '忍びの頭領ハンゾウ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】平和な収穫祭を急襲する、謎の飛行物体。\\nランドソル各地に突如現れ、破壊と略奪を行う。\\n\\n・ユニオンバーストは、敵全体に物理大ダメージ。\\n・前方１キャラに物理小ダメージ。\\n・残りＨＰの高い１キャラに物理小ダメージ。\\n・ランダムな１キャラに物理小ダメージ。', 310900, 0, 1, 310900, 270, 0, 0, 16, 0, 0.1, 3000, 'ランドソル各地に襲来した謎の円盤');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】塔の魔力で変異し要塞と化した巨大魔樹。\\n大地の力を砲弾に変え、堅牢なその身を以って\\n破壊の限りを尽くす。\\n\\n・敵全体に物理大ダメージを与える。\\n・範囲内の敵すべてに継続魔法ダメージを与え\\n\u3000物理防御力を下げるフィールドを展開する。\\n・後ろから２番目のキャラを中心とした小範囲内\\n\u3000に物理中ダメージを与え、ＴＰを下げる。\\n\u3000その後、味方全体のＴＰを回復する。', 311000, 0, 1, 311000, 270, 0, 0, 16, 0, 2.8, 3000, 'トレントキャッスル');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】塔の魔力で変異し要塞と化した巨大魔樹。\\n大地の力を砲弾に変え、堅牢なその身を以って\\n破壊の限りを尽くす。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を中アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・トレントキャッスルから受けるすべてのダメー\\n\u3000ジで発生する、パーティキャラのＴＰ回復量を\\n\u3000中ダウンさせる。\\n・ユニオンバーストは、敵全体のバリアを解除\\n\u3000し、物理大ダメージを与える。このスキルによ\\n\u3000るダメージでは、敵のＴＰが回復しない。\\n・後方範囲内の敵すべてに物理防御力を特大ダウ\\n\u3000ンさせるフィールドを展開する。\\n・最も遠い１キャラを中心とした小範囲内に魔法\\n\u3000大ダメージを与え、ＴＰを中ダウンさせる。そ\\n\u3000の後、このスキルでダメージを与えた敵の数に\\n\u3000応じて自身のＴＰを回復する。\\n・前方１キャラに物理大ダメージを与える。', 311001, 0, 1, 311001, 270, 0, 0, 16, 0, 2.8, 3000, 'トレントキャッスル');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】塔の魔力で変異し要塞と化した巨大魔樹。\\n大地の力を砲弾に変え、堅牢なその身を以って\\n破壊の限りを尽くす。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を中アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・トレントキャッスルから受けるすべてのダメー\\n\u3000ジで発生する、パーティキャラのＴＰ回復量を\\n\u3000中ダウンさせる。\\n・ユニオンバーストは、敵全体のバリアを解除\\n\u3000し、物理大ダメージを与える。さらにスタン状\\n\u3000態を付与する。このスキルによるダメージで\\n\u3000は、敵のＴＰが回復しない。このスキルの状態\\n\u3000異常はダメージを無効化しても付与される。\\n・後方範囲内の敵すべてに物理防御力を特大ダウ\\n\u3000ンさせるフィールドを展開する。\\n・最も遠い１キャラを中心とした小範囲内に魔法\\n\u3000大ダメージを与え、ＴＰを中ダウンさせる。そ\\n\u3000の後、このスキルでダメージを与えた敵の数に\\n\u3000応じて自身のＴＰを回復する。\\n・前方１キャラに物理大ダメージを与える。', 311002, 0, 1, 311002, 270, 0, 0, 16, 0, 2.8, 3000, 'トレントキャッスル');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】世界を歪ませ狭界より顕現した黒の王。\\n暗黒の瘴気を纏い不思議の国を蹂躙せんとする。\\n\\n・ユニオンバーストは、敵全体にキャラの最大Ｈ\\n\u3000Ｐに応じた魔法割合ダメージを与え、毒状態に\\n\u3000し、さらにノックバックさせる。\\n\u3000このスキルの状態異常はダメージを無効化して\\n\u3000も付与される。\\n・前から２キャラに物理中ダメージを与え、物理\\n\u3000防御力とＴＰをダウンさせる。', 311100, 0, 1, 311100, 270, 0, 0, 16, 0, 2.1, 1000, '黒の王ジャバウォック');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】世界を歪ませ狭界より顕現した黒の王。\\n暗黒の瘴気を纏い不思議の国を蹂躙せんとする。\\n\\n・ユニオンバーストは、敵全体にキャラの最大Ｈ\\n\u3000Ｐに応じた魔法割合ダメージを与え、毒状態に\\n\u3000し、さらにノックバックさせる。\\n\u3000このスキルの状態異常はダメージを無効化して\\n\u3000も付与される。\\n・前から２キャラに物理中ダメージを与え、物理\\n\u3000防御力とＴＰを中ダウンさせる。', 311101, 0, 1, 311100, 270, 0, 0, 16, 0, 2.1, 1000, '黒の王ジャバウォック');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】世界を歪ませ狭界より顕現した黒の王。\\n暗黒の瘴気を纏い不思議の国を蹂躙せんとする。\\n\\n・ユニオンバーストは、敵全体にキャラの最大Ｈ\\n\u3000Ｐに応じた魔法割合ダメージを与え、毒状態に\\n\u3000し、さらにノックバックさせる。\\n\u3000このスキルの状態異常はダメージを無効化して\\n\u3000も付与される。\\n・前から２キャラに物理中ダメージを与え、物理\\n\u3000防御力とＴＰを中ダウンさせる。\\n・前方範囲内のキャラに魔法中ダメージを与え、\\n\u3000魔法防御力を大ダウンさせる。\\n\u3000さらにキャラのＨＰが50％未満の場合、行動\\n\u3000速度をダウンさせる。', 311102, 0, 1, 311100, 270, 0, 0, 16, 0, 2.1, 1000, '黒の王ジャバウォック');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】世界を歪ませ狭界より顕現した黒の王。\\n暗黒の瘴気を纏い不思議の国を蹂躙せんとする。\\n\\n・ユニオンバーストは、敵全体にキャラの最大Ｈ\\n\u3000Ｐに応じた魔法割合ダメージを与え、毒状態に\\n\u3000し、さらにノックバックさせる。\\n\u3000このスキルの状態異常はダメージを無効化して\\n\u3000も付与される。\\n・前から２キャラに物理中ダメージを与え、物理\\n\u3000防御力とＴＰを中ダウンさせる。\\n・前方範囲内のキャラに魔法中ダメージを与え、\\n\u3000魔法防御力を大ダウンさせる。\\n\u3000さらにキャラのＨＰが50％未満の場合、行動\\n\u3000速度をダウンさせる。\\n・黒の王ジャバウォック自身のＨＰが35％を切\\n\u3000ると、さらに攻撃が激しく凶暴になる。', 311103, 0, 1, 311100, 270, 0, 0, 16, 0, 2.1, 1000, '黒の王ジャバウォック');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ１】瘴黒の幕を身に纏い、黒の王が再\\n臨する。闇と混沌を集約した障壁は、救世主の光\\nの一射をも耐えるという。\\n\\n・バリアを張り、敵の攻撃を受け付けなくなる。\\n\u3000バリアはダメージを与えるたびに徐々に耐久性\\n\u3000を失っていき、2400000ダメージを与え\\n\u3000るとバリアは破壊される。\\n・ユニオンバーストは、敵全体にキャラの最大Ｈ\\n\u3000Ｐに応じた魔法割合ダメージを与え、毒状態に\\n\u3000し、さらにノックバックさせる。\\n\u3000このスキルの状態異常はダメージを無効化して\\n\u3000も付与される。\\n・前方範囲内のキャラに魔法中ダメージを与え、\\n\u3000魔法防御力を大ダウンさせる。', 311104, 0, 1, 311101, 270, 0, 0, 16, 0, 2.1, 1000, '黒の王ジャバウォック');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ２】リノ、アユミ、ヒヨリのシャドウ\\nを召喚。心の闇が具現化し、自己の弱さを露見さ\\nせる。希望の心を取り戻せるか？今、問われる。\\n\\n・目の前の敵１キャラに物理ダメージを与える。', 311105, 0, 1, 311100, 270, 0, 0, 16, 0, 2.1, 1000, '黒の王ジャバウォック');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ３】黒の王が終の力を解放し、世界は\\n常闇へと堕ちていく。本の殆どの頁は黒に染まり\\n救世主の物語は終焉を迎えようとする。\\n\\n・ユニオンバーストは、敵全体にキャラの最大Ｈ\\n\u3000Ｐに応じた魔法割合ダメージを与え、毒状態に\\n\u3000し、さらにノックバックさせる。\\n\u3000このスキルの状態異常はダメージを無効化して\\n\u3000も付与される。\\n・前から２キャラに物理中ダメージを与え、物理\\n\u3000防御力とＴＰをダウンさせる。\\n・前方範囲内のキャラに魔法中ダメージを与え、\\n\u3000魔法防御力を大ダウンさせる。\\n\u3000さらにキャラのＨＰが50％未満の場合、行動\\n\u3000速度を大ダウンさせる。\\n・バトル開始直後に、さらに攻撃が激しく\\n\u3000凶暴になる。', 311106, 0, 1, 311100, 270, 0, 0, 16, 0, 2.1, 1000, '黒の王ジャバウォック');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】大輪の花に擬態する魔物。\\nその美しさに惹かれた、不用意な\\n獲物の前に絶望の光が花開く。\\n\\n・前方３キャラに物理大ダメージを\\n\u3000与え、さらに敵全体に物理大\\n\u3000ダメージを与える。\\n\\n・前方２キャラに物理小ダメージを\\n\u3000与え、さらに自分の物理攻撃力を\\n\u3000中アップさせる。\\n\\n・前から１番目のキャラに物理中\\n\u3000ダメージを与え、物理防御力を\\n\u3000中ダウンさせる。\\n\\n・前から２番目のキャラに物理中\\n\u3000ダメージを与え、物理防御力を\\n\u3000中ダウンさせる。', 311200, 0, 1, 311200, 270, 0, 0, 16, 0, 2.8, 3000, 'フラワーシュバリエ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】大輪の花に擬態する魔物。\\nその美しさに惹かれた、不用意な\\n獲物の前に絶望の光が花開く。\\n\\n・前方３キャラに物理大ダメージを\\n\u3000与え、さらに敵全体に物理大\\n\u3000ダメージを与える。\\n\\n・前方２キャラに物理小ダメージを\\n\u3000与え、さらに自分の物理攻撃力を\\n\u3000中アップさせる。\\n\\n・前から１番目のキャラに物理中\\n\u3000ダメージを与え、物理防御力を\\n\u3000中ダウンさせる。\\n\\n・前から２番目のキャラに物理中\\n\u3000ダメージを与え、物理防御力を\\n\u3000中ダウンさせる。', 311201, 0, 1, 311200, 270, 0, 0, 16, 0, 2.8, 3000, 'フラワーシュバリエ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】大輪の花に擬態する魔物。その美しさに\\n惹かれた、不用意な獲物の前に絶望の光が花開く。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・フラワーシュバリエから受けるすべてのダメー\\n\u3000ジで発生する、パーティキャラのＴＰ回復量を\\n\u3000中ダウンさせる。\\n・ユニオンバーストは、最も近い敵１キャラを中\\n\u3000心にした小範囲に物理特大ダメージを与える。\\n\u3000その後、敵全体にこのスキルで与えたダメージ\\n\u3000量に応じた物理ダメージを与える。\\n・自身の物理攻撃力と魔法防御力を特大アップさ\\n\u3000せ、ＴＰを小回復する。\\n・通常攻撃は、最も近い敵１キャラを中心にした\\n\u3000小範囲内の敵最大２キャラに物理特大ダメージ\\n\u3000を与える。', 311202, 0, 1, 311202, 270, 0, 0, 16, 0, 2.8, 3000, 'フラワーシュバリエ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】大輪の花に擬態する魔物。その美しさに\\n惹かれた、不用意な獲物の前に絶望の光が花開く。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を中アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・バトル開始時、敵全体のＴＰ上昇を小ダウンさ\\n\u3000せるフィールドを展開する。\\n・バトル開始時、自身にＴＰダウン50％カット\\n\u3000効果を付与する。\\n・フラワーシュバリエから受けるすべてのダメー\\n\u3000ジで発生する、パーティキャラのＴＰ回復量を\\n\u3000中ダウンさせる。\\n・敵から受けるすべてのダメージで発生する、フ\\n\u3000ラワーシュバリエのＴＰ回復量が大ダウンする。\\n・ユニオンバーストは、最も近い敵１キャラを中\\n\u3000心にした小範囲に物理特大ダメージを与える。\\n\u3000その後、敵全体にこのスキルで与えたダメージ\\n\u3000量に応じた物理ダメージを与える。このスキル\\n\u3000による全体ダメージでは、ＴＰが回復しない。\\n・自身の物理攻撃力と物理防御力と魔法防御力を\\n\u3000特大アップさせ、ＴＰを中回復する。\\n・通常攻撃は、最も近い敵１キャラを中心にした\\n\u3000小範囲内の敵最大２キャラに物理特大ダメージ\\n\u3000を与える。', 311203, 0, 1, 311203, 270, 0, 0, 16, 0, 2.8, 3000, 'フラワーシュバリエ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】大輪の花に擬態する魔物。その美しさに\\n惹かれた、不用意な獲物の前に絶望の光が花開く。\\n\\n・環境効果【百花繚乱】を発動する。このスキル\\n\u3000の効果は敵、味方すべてに適用される。一定時\\n\u3000間が経過するごとに、敵、味方全体のＴＰを中\\n\u3000回復させる。\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を中アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・バトル開始時、自身にＴＰダウン100％カッ\\n\u3000ト効果を付与する。\\n・バトル開始時、敵全体のＨＰ吸収を特大ダウン\\n\u3000させる。\\n・自身が一度の行動で受けるダメージ値を減衰さ\\n\u3000せる。ダメージ値が上昇するほど減衰率も上昇\\n\u3000する。\\n・バトル開始時、敵全体にＴＰ上昇上限効果を付\\n\u3000与する。\\n・フラワーシュバリエから受けるすべてのダメー\\n\u3000ジで発生する、パーティキャラのＴＰ回復量を\\n\u3000中ダウンさせる。\\n・ユニオンバーストは、最も近い敵１キャラを中\\n\u3000心にした小範囲に物理特大ダメージを与える。\\n\u3000その後、敵全体にこのスキルで与えたダメージ\\n\u3000量に応じた物理ダメージを与える。このスキル\\n\u3000による全体ダメージでは、ＴＰが回復しない。\\n・自身の物理攻撃力と物理防御力と魔法防御力を\\n\u3000特大アップさせ、ＴＰを中回復する。\\n・通常攻撃は、最も近い敵１キャラを中心にした\\n\u3000小範囲内の敵最大２キャラに物理特大ダメージ\\n\u3000を与える。', 311204, 0, 1, 311204, 270, 0, 0, 16, 0, 2.8, 3000, 'フラワーシュバリエ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('', 311300, 0, 2, 311300, 270, 0, 0, 16, 0, 2.8, 3000, '覚醒・浮気星');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【魔法】ぽっかり空いた心のスキマに取り憑く\\n星の精霊。過剰な自意識とピュアな下心で相手\\nを惑わせる。\\n\\n・ユニオンバーストは、敵全体に浮気星が保持し\\n\u3000ている【ふた心】の数に応じた魔法割合ダメー\\n\u3000ジを与える。\\n\u3000また、浮気星の残りＨＰが50％未満の場合、\\n\u3000さらに与えるダメージがアップする。\\n\u3000スキル発動後、浮気星が保持している\\n\u3000【ふた心】の数は０になる。\\n・一番後ろの敵を中心として、一定範囲に\\n\u3000魔法小ダメージを与え、さらに誘惑状態にして\\n\u3000物理攻撃力と魔法攻撃力を小アップさせる。\\n\u3000このスキルでダメージを与えた敵の数だけ、\\n\u3000浮気星に一定時間【ふた心】を追加する。\\n・前方範囲内の敵をノックバックさせ、\\n\u3000魔法小ダメージを与える。\\n\u3000さらに誘惑状態にして物理攻撃力と魔法攻撃力\\n\u3000を小アップさせる。\\n\u3000このスキルでダメージを与えた敵の数だけ、\\n\u3000浮気星に一定時間【ふた心】を追加する。', 311301, 0, 2, 311300, 270, 0, 0, 16, 0, 2.8, 3000, '覚醒・浮気星');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【魔法】ぽっかり空いた心のスキマに取り憑く\\n星の精霊。過剰な自意識とピュアな下心で相手\\nを惑わせる。\\n\\n・ユニオンバーストは、敵全体に浮気星が保持し\\n\u3000ている【ふた心】の数に応じた魔法割合ダメー\\n\u3000ジを与える。\\n\u3000また、浮気星の残りＨＰが50％未満の場合、\\n\u3000さらに与えるダメージがアップする。\\n\u3000スキル発動後、浮気星が保持している\\n\u3000【ふた心】の数は０になる。\\n・一番後ろの敵を中心として、一定範囲に\\n\u3000魔法小ダメージを与え、さらに誘惑状態にして\\n\u3000物理攻撃力と魔法攻撃力を小アップさせる。\\n\u3000このスキルでダメージを与えた敵の数だけ、\\n\u3000浮気星に一定時間【ふた心】を追加する。\\n・前方範囲内の敵をノックバックさせ、\\n\u3000魔法小ダメージを与える。\\n\u3000さらに誘惑状態にして物理攻撃力を小アップ、\\n\u3000魔法攻撃力を中アップさせる。\\n\u3000このスキルでダメージを与えた敵の数だけ、\\n\u3000浮気星に一定時間【ふた心】を追加する。', 311302, 0, 2, 311300, 270, 0, 0, 16, 0, 3.0, 3000, '覚醒・浮気星');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【魔法】ぽっかり空いた心のスキマに取り憑く\\n星の精霊。過剰な自意識とピュアな下心で相手\\nを惑わせる。\\n\\n・ユニオンバーストは、敵全体に浮気星が保持し\\n\u3000ている【ふた心】の数に応じた魔法割合ダメー\\n\u3000ジを与える。\\n\u3000また、浮気星の残りＨＰが50％未満の場合、\\n\u3000さらに与えるダメージがアップする。\\n\u3000スキル発動後、浮気星が保持している\\n\u3000【ふた心】の数は０になる。\\n・敵全体にキャラの最大ＨＰに応じた魔法割合\\n\u3000ダメージを与える。\\n・一番後ろの敵を中心として、一定範囲に\\n\u3000魔法中ダメージを与え、さらに誘惑状態にして\\n\u3000物理攻撃力と魔法攻撃力を大アップさせる。\\n\u3000このスキルでダメージを与えた敵の数だけ、\\n\u3000浮気星に一定時間【ふた心】を追加する。\\n・前方範囲内の敵をノックバックさせ、\\n\u3000魔法中ダメージを与える。\\n\u3000さらに誘惑状態にして物理攻撃力と魔法攻撃力\\n\u3000を大アップさせる。\\n\u3000このスキルでダメージを与えた敵の数だけ、\\n\u3000浮気星に一定時間【ふた心】を追加する。', 311303, 0, 2, 311300, 270, 0, 0, 16, 0, 3.0, 3000, '覚醒・浮気星');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ１】自身のハーレムドリームを築き\\n上げるため手当たり次第、乙女たちを強制的に\\n惑わす。\\n\\n・ユニオンバーストは、敵全体に浮気星が保持し\\n\u3000ている【ふた心】の数に応じた魔法割合ダメー\\n\u3000ジを与える。\\n\u3000ダメージを与えた後、浮気星が保持している\\n\u3000【ふた心】の数は０になる。\\n・敵全体にキャラの最大ＨＰに応じた魔法割合\\n\u3000ダメージを与える。\\n・挑発を無視して、最も後ろの敵１キャラに魔法\\n\u3000ダメージを与え、さらに引き寄せる。\\n・一番前の敵を中心として、一定範囲に\\n\u3000魔法ダメージを与え、さらに誘惑状態にして\\n\u3000物理攻撃力と魔法攻撃力をアップさせる。\\n\u3000このスキルの状態異常はダメージを無効化して\\n\u3000も付与される。\\n\u3000このスキルの攻撃対象の数だけ、浮気星に\\n\u3000一定時間【ふた心】を追加する。', 311304, 0, 2, 311300, 270, 0, 0, 16, 0, 3.0, 3000, '覚醒・浮気星');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ２】綺羅星すらも霞ませると、己の\\n輝きに自信をのぞかせ、その盲信と乙女への思い\\nが銀河を巻き込み、全てを幻惑させる。\\n\\n・ユニオンバーストは、敵全体に浮気星が保持し\\n\u3000ている【ふた心】の数に応じた魔法割合ダメー\\n\u3000ジを与える。\\n\u3000また、浮気星の残りＨＰが60％未満の場合、\\n\u3000さらに与えるダメージがアップする。\\n\u3000ダメージを与えた後、浮気星が保持している\\n\u3000【ふた心】の数は０になる。\\n・一番前の敵を中心として、一定範囲に\\n\u3000魔法ダメージを与え、さらに誘惑状態にして\\n\u3000物理攻撃力と魔法攻撃力をアップさせる。\\n\u3000このスキルの状態異常はダメージを無効化して\\n\u3000も付与される。\\n\u3000このスキルの攻撃対象の数だけ、浮気星に\\n\u3000一定時間【ふた心】を追加する。', 311305, 0, 2, 311300, 270, 0, 0, 16, 0, 3.0, 3000, '覚醒・浮気星');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ３】夢見たハーレムが潰え、全てを\\n無に還そうと真の力を解放する。銀河の星々を\\n天の川に沈めるべく、全ての下心をブチ撒ける。\\n\\n・ユニオンバーストは、敵全体に浮気星が保持し\\n\u3000ている【ふた心】の数に応じた魔法割合ダメー\\n\u3000ジを与える。\\n\u3000また、バトル開始直後に、さらに与えるダメー\\n\u3000ジがアップする。\\n\u3000ダメージを与えた後、浮気星が保持している\\n\u3000【ふた心】の数は０になる。\\n・敵全体にキャラの最大ＨＰに応じた魔法割合\\n\u3000ダメージを与える。\\n・一番後ろの敵を中心として、一定範囲に\\n\u3000魔法ダメージを与え、さらに誘惑状態にして\\n\u3000物理攻撃力と魔法攻撃力をアップさせる。\\n\u3000このスキルでダメージを与えた敵の数だけ、\\n\u3000浮気星に一定時間【ふた心】を追加する。\\n・前方範囲内の敵をノックバックさせ、\\n\u3000魔法ダメージを与える。\\n\u3000さらに誘惑状態にして物理攻撃力と魔法攻撃力\\n\u3000をアップさせる。\\n\u3000このスキルでダメージを与えた敵の数だけ、\\n\u3000浮気星に一定時間【ふた心】を追加する。', 311306, 0, 2, 311300, 270, 0, 0, 16, 0, 3.0, 3000, '覚醒・浮気星');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('', 311400, 0, 1, 311400, 270, 0, 0, 16, 0, 2.8, 3000, '渚の暴君・鮫吉');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】ビーチ一帯の近海をシメる海洋族の暴君。\\n売られた喧嘩には、ただの一度も背を向けず、\\nシマを荒らすヤツは絶対に許さない。\\n\\n・ユニオンバーストは、敵全体にキャラの最大\\n\u3000ＨＰに応じた物理割合ダメージを与え、物理\\n\u3000防御力をダウンさせ、物理攻撃力をアップさ\\n\u3000せる。\\n・前方範囲内の敵すべてに物理大ダメージを与え、\\n\u3000物理防御力をダウンさせる。\\n・敵全体をノックバックさせる。その後一定時間、\\n\u3000雷を身にまとい、自身の物理防御力と魔法防御\\n\u3000力を極大アップさせる。\\n\u3000鮫吉が毒、猛毒、呪い、火傷、呪詛の効果を\\n\u3000受けていると、自身の物理防御力と魔法防御力\\n\u3000がアップする時間が短くなる。', 311401, 0, 1, 311400, 270, 0, 0, 16, 0, 2.8, 3000, '渚の暴君・鮫吉');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】ビーチ一帯の近海をシメる海洋族の暴君。\\n売られた喧嘩には、ただの一度も背を向けず、\\nシマを荒らすヤツは絶対に許さない。\\n\\n・ユニオンバーストは、敵全体にキャラの最大\\n\u3000ＨＰに応じた物理割合ダメージを与え、物理\\n\u3000防御力をダウンさせ、物理攻撃力をアップさ\\n\u3000せる。\\n・前方範囲内の敵すべてに物理大ダメージを与え、\\n\u3000物理防御力をダウンさせる。\\n・敵全体をノックバックさせる。その後一定時間、\\n\u3000雷を身にまとい、自身の物理防御力と魔法防御\\n\u3000力を極大アップさせる。\\n\u3000鮫吉が毒、猛毒、呪い、火傷、呪詛の効果を\\n\u3000受けていると、自身の物理防御力と魔法防御力\\n\u3000がアップする時間が短くなる。\\n・鮫吉自身のＨＰが20％を切ると、敵全体に\\n\u3000キャラの最大ＨＰに応じた物理割合ダメージを\\n\u3000与え、一定時間、ユニオンバーストのみ使用で\\n\u3000きない状態にし、魔法攻撃力をダウンさせる。\\n\u3000このスキルの状態異常はダメージを無効化して\\n\u3000も付与される。\\n\u3000さらに攻撃が激しく凶暴になる。', 311402, 0, 1, 311400, 270, 0, 0, 16, 0, 2.8, 3000, '渚の暴君・鮫吉');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】ビーチ一帯の近海をシメる海洋族の暴君。\\n売られた喧嘩には、ただの一度も背を向けず、\\nシマを荒らすヤツは絶対に許さない。\\n\\n・ユニオンバーストは、敵全体にキャラの最大\\n\u3000ＨＰに応じた物理割合ダメージを与え、物理\\n\u3000防御力を大ダウンさせ、物理攻撃力をアップ\\n\u3000させる。\\n・前方範囲内の敵すべてに物理大ダメージを与え、\\n\u3000物理防御力をダウンさせる。\\n・敵全体をノックバックさせる。その後一定時間、\\n\u3000雷を身にまとい、自身の物理防御力と魔法防御\\n\u3000力を極大アップさせる。\\n\u3000鮫吉が毒、猛毒、呪い、火傷、呪詛の効果を\\n\u3000受けていると、自身の物理防御力と魔法防御力\\n\u3000がアップする時間が短くなる。\\n・鮫吉自身のＨＰが20％を切ると、敵全体に\\n\u3000キャラの最大ＨＰに応じた物理割合ダメージを\\n\u3000与え、一定時間、ユニオンバーストのみ使用で\\n\u3000きない状態にし、魔法攻撃力をダウンさせる。\\n\u3000このスキルの状態異常はダメージを無効化して\\n\u3000も付与される。\\n\u3000さらに攻撃が激しく凶暴になる。', 311403, 0, 1, 311400, 270, 0, 0, 16, 0, 2.8, 3000, '渚の暴君・鮫吉');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ１】シマを荒らす不届きモノには、幾\\n千もの抗争を潜り抜けた鋼の肉体から繰り出す、\\n全身全霊のガチンコタックルをブチかます。\\n\\n・ユニオンバーストは、敵全体にキャラの最大\\n\u3000ＨＰに応じた物理割合ダメージを与え、物理\\n\u3000防御力をダウンさせ、物理攻撃力をアップさ\\n\u3000せる。\\n・前方範囲内の敵すべてに物理大ダメージを与え、\\n\u3000物理防御力を大ダウンさせる。\\n・前方３キャラに物理大ダメージを与える。さら\\n\u3000に、自身にも物理ダメージを与え、物理防御力\\n\u3000と魔法防御力を一定時間極大ダウンさせる。', 311404, 0, 1, 311404, 270, 0, 0, 16, 0, 2.8, 3000, '渚の暴君・鮫吉');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ２】圧倒的なカリスマ性と絶望的な暴\\n力につき従う、舎弟たちが集結する。海洋族の精\\n鋭によるカチコミが、いま幕を開ける。\\n\\n・鮫吉は目の前の敵１キャラへの物理攻撃を行う。\\n・前方３キャラに物理大ダメージを与える。さら\\n\u3000に、自身にも物理ダメージを与え、物理防御力\\n\u3000と魔法防御力を一定時間極大ダウンさせる。', 311405, 0, 1, 311405, 270, 0, 0, 16, 0, 2.8, 3000, '渚の暴君・鮫吉');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ３】獰猛な雄叫びとともに、暴君は追\\n撃を繰り出す。刃向かう者を完膚なきまでに殴り\\n潰すまで、降り注ぐ轟拳の嵐は決してやまない。\\n\\n・ユニオンバーストは、敵全体にキャラの最大\\n\u3000ＨＰに応じた物理割合ダメージを与え、物理\\n\u3000防御力を大ダウンさせ、物理攻撃力をアップ\\n\u3000させる。\\n・前方範囲内の敵すべてに物理大ダメージを与え、\\n\u3000物理防御力をダウンさせる。\\n・敵全体をノックバックさせる。その後一定時間、\\n\u3000雷を身にまとい、自身の物理防御力と魔法防御\\n\u3000力を極大アップさせる。\\n\u3000鮫吉が毒、猛毒、呪い、火傷の効果を受けてい\\n\u3000ると、自身の物理防御力と魔法防御力がアップ\\n\u3000する時間が短くなる。\\n・鮫吉自身のＨＰが10％を切ると、敵全体に\\n\u3000キャラの最大ＨＰに応じた物理割合ダメージを\\n\u3000与え、一定時間、ユニオンバーストのみ使用で\\n\u3000きない状態にし、魔法攻撃力をダウンさせる。\\n\u3000このスキルの状態異常はダメージを無効化して\\n\u3000も付与される。\\n\u3000さらに攻撃が激しく凶暴になる。', 311406, 0, 1, 311404, 270, 0, 0, 16, 0, 2.8, 3000, '渚の暴君・鮫吉');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】塔の魔力で狂化した、海洋族の狂戦士。\\n獰猛な雄叫びとともに、猛々しく拳撃を繰り出す。\\n\\n・ユニオンバーストは、敵全体にキャラの最大\\n\u3000ＨＰに応じた物理割合ダメージを与え、物理\\n\u3000防御力を大ダウンさせ、さらに物理攻撃力を\\n\u3000中アップさせる。\\n・最も近い１キャラを中心とした小範囲内の敵す\\n\u3000べてに物理大ダメージを与え、物理防御力を大\\n\u3000ダウンさせる。\\n\u3000このスキルの状態異常はダメージを無効化して\\n\u3000も付与される。\\n・敵全体をノックバックさせる。その後一定時間、\\n\u3000雷を身にまとい、自身の物理防御力と魔法防御\\n\u3000力を極大アップさせる。\\n\u3000レイジングジョーが毒、猛毒、呪い、呪詛、火\\n\u3000傷の効果を受けていると、自身の物理防御力と\\n\u3000魔法防御力がアップする時間が短くなる。\\n・レイジングジョー自身のＨＰが40％を切ると、\\n\u3000敵全体にキャラの最大ＨＰに応じた物理割合ダ\\n\u3000メージを与え、一定時間、ユニオンバーストの\\n\u3000み使用できない状態にする。\\n\u3000さらにバトル中、魔法攻撃力を大ダウンさせる。\\n\u3000このスキルの状態異常はダメージを無効化して\\n\u3000も付与される。\\n\u3000さらに攻撃が激しく凶暴になる。', 311407, 0, 1, 311407, 270, 0, 0, 16, 0, 2.8, 3000, 'レイジングジョー');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('', 311500, 0, 2, 311500, 270, 0, 0, 16, 0, 2.4, 3000, '暴走のイノセントボウ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【魔法】過大な無垢なる願いにより暴走した聖弓。\\nその矢に貫かれると、非力なエンジェルと化す。\\n\\n・ユニオンバーストは、敵全体にキャラの最大Ｈ\\n\u3000Ｐに応じた魔法割合ダメージを与え、エンジェ\\n\u3000ル状態のキャラに呪いを付与する。\\n\u3000この効果により付与された呪いのダメージでは、\\n\u3000ＴＰが回復しない。\\n・ＨＰが低い３キャラに最大ＨＰに応じた魔法\\n\u3000割合ダメージを与え、さらにＨＰが60％を\\n\u3000切ったキャラを一定時間エンジェル状態にする。\\n\u3000エンジェルになったキャラは、通常攻撃しか使\\n\u3000用できなくなり、かかっているステータスアッ\\n\u3000プ効果を解除される。', 311501, 0, 2, 311500, 270, 0, 0, 16, 0, 2.4, 3000, '暴走のイノセントボウ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【魔法】過大な無垢なる願いにより暴走した聖弓。\\nその矢に貫かれると、非力なエンジェルと化す。\\n\\n・ユニオンバーストは、敵全体にキャラの最大Ｈ\\n\u3000Ｐに応じた魔法割合ダメージを与え、エンジェ\\n\u3000ル状態のキャラに呪いを付与する。\\n\u3000この効果により付与された呪いのダメージでは、\\n\u3000ＴＰが回復しない。\\n・ＨＰが低い３キャラに最大ＨＰに応じた魔法\\n\u3000割合ダメージを与え、さらにＨＰが60％を\\n\u3000切ったキャラを一定時間エンジェル状態にする。\\n\u3000エンジェルになったキャラは、通常攻撃しか使\\n\u3000用できなくなり、かかっているステータスアッ\\n\u3000プ効果を解除される。\\n・ＨＰが高い２キャラに魔法中ダメージを与え、\\n\u3000行動速度を中ダウンさせる。\\n・イノセントボウ自身のＨＰが50％を切ると、\\n\u3000魔法攻撃力が小アップし、さらに攻撃が激しく\\n\u3000凶暴になる。', 311502, 0, 2, 311500, 270, 0, 0, 16, 0, 2.4, 3000, '暴走のイノセントボウ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【魔法】過大な無垢なる願いにより暴走した聖弓。\\nその矢に貫かれると、非力なエンジェルと化す。\\n\\n・ユニオンバーストは、敵全体にキャラの最大Ｈ\\n\u3000Ｐに応じた魔法割合ダメージを与え、エンジェ\\n\u3000ル状態のキャラに呪いを付与する。\\n\u3000この効果により付与された呪いのダメージでは、\\n\u3000ＴＰが回復しない。\\n・ＨＰが低い３キャラに最大ＨＰに応じた魔法\\n\u3000割合ダメージを与え、さらにＨＰが60％を\\n\u3000切ったキャラを一定時間エンジェル状態にする。\\n\u3000エンジェルになったキャラは、通常攻撃しか使\\n\u3000用できなくなり、かかっているステータスアッ\\n\u3000プ効果を解除される。\\n・ＨＰが高い２キャラに魔法中ダメージを与え、\\n\u3000行動速度を中ダウンさせる。\\n・イノセントボウ自身のＨＰが50％を切ると、\\n\u3000魔法攻撃力とＴＰが中アップし、さらに攻撃が\\n\u3000激しく凶暴になる。', 311503, 0, 2, 311500, 270, 0, 0, 16, 0, 2.4, 3000, '暴走のイノセントボウ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ１】歪みし願いは結晶となり、人々を\\n狂わせる。その結晶はすべての進攻を封殺する。\\n\\n・バトル開始時に歪願のクリスタルを呼び出す。\\n・歪願のクリスタルがバトル中に存在している間、\\n\u3000イノセントボウの物理防御力と魔法防御力を大\\n\u3000幅にアップさせる。\\n・歪願のクリスタルが破壊されると、イノセント\\n\u3000ボウの物理防御力と魔法防御力を大幅にダウン\\n\u3000させる。\\n・ユニオンバーストは、敵全体にキャラの最大Ｈ\\n\u3000Ｐに応じた魔法割合ダメージを与える。\\n・ＨＰが高い２キャラに魔法中ダメージを与え、\\n\u3000行動速度をダウンさせ、さらに魔法防御力を\\n\u3000ダウンさせる。', 311504, 0, 2, 311500, 270, 0, 0, 16, 0, 2.4, 3000, '暴走のイノセントボウ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ２】ヨリとアカリのシャドウを召喚。\\n自分たちの負の姿に、双子の真の絆が試される。\\n\\n・ＨＰが低い３キャラに最大ＨＰに応じた魔法\\n\u3000割合ダメージを与え、さらにＨＰが60％を\\n\u3000切ったキャラを一定時間エンジェル状態にする。\\n\u3000エンジェルになったキャラは、通常攻撃しか使\\n\u3000用できなくなり、かかっているステータスアッ\\n\u3000プ効果を解除される。', 311505, 0, 2, 311500, 270, 0, 0, 16, 0, 2.4, 3000, '暴走のイノセントボウ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ３】叶わぬ願いに囚われ、聖弓の権能\\nは極致に至る。解放された力は天地を揺るがし、\\n一切の邪念を滅却する。\\n\\n・ユニオンバーストは、敵全体にキャラの最大Ｈ\\n\u3000Ｐに応じた魔法割合ダメージを与え、エンジェ\\n\u3000ル状態のキャラに呪いを付与する。\\n\u3000この効果により付与された呪いのダメージでは、\\n\u3000ＴＰが回復しない。\\n・ＨＰが低い３キャラに最大ＨＰに応じた魔法\\n\u3000割合ダメージを与え、さらにＨＰが60％を\\n\u3000切ったキャラを一定時間エンジェル状態にする。\\n\u3000エンジェルになったキャラは、通常攻撃しか使\\n\u3000用できなくなり、かかっているステータスアッ\\n\u3000プ効果を解除される。\\n・ＨＰが高い２キャラに魔法中ダメージを与え、\\n\u3000行動速度をダウンさせ、さらに魔法防御力を\\n\u3000ダウンさせる。\\n・残り時間が35秒を切ると、魔法攻撃力とＴＰ\\n\u3000がアップし、さらに攻撃が激しく凶暴になる。', 311506, 0, 2, 311500, 270, 0, 0, 16, 0, 2.4, 3000, '暴走のイノセントボウ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【魔法】人間を恐怖に慄かせるお化けたちの首領。\\n手下をけしかけ、シマの拡大を密かに画策する。\\n\\n・ユニオンバーストは、敵全体にキャラの元々の\\n\u3000最大ＨＰに応じた魔法割合ダメージを与える。\\n\u3000さらに、敵全体のキャラの最大ＨＰを10％減\\n\u3000少させる。減少したＨＰは、バトル終了まで解\\n\u3000除できない。\\n\u3000このスキルの状態異常はダメージを無効化して\\n\u3000も付与される。', 311600, 0, 2, 311600, 270, 0, 0, 16, 0, 4.0, 3000, '叫怖のゴーストファーザー');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【魔法】人間を恐怖に慄かせるお化けたちの首領。\\n手下をけしかけ、シマの拡大を密かに画策する。\\n\\n・ユニオンバーストは、敵全体にキャラの元々の\\n\u3000最大ＨＰに応じた魔法割合ダメージを与える。\\n\u3000さらに、敵全体のキャラの最大ＨＰを10％減\\n\u3000少させる。減少したＨＰは、バトル終了まで解\\n\u3000除できない。\\n\u3000このスキルの状態異常はダメージを無効化して\\n\u3000も付与される。', 311601, 0, 2, 311600, 270, 0, 0, 16, 0, 4.0, 3000, '叫怖のゴーストファーザー');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【魔法】人間を恐怖に慄かせるお化けたちの首領。\\n手下をけしかけ、シマの拡大を密かに画策する。\\n\\n・ユニオンバーストは、敵全体にキャラの元々の\\n\u3000最大ＨＰに応じた魔法割合ダメージを与える。\\n\u3000さらに、敵全体のキャラの最大ＨＰを10％減\\n\u3000少させる。減少したＨＰは、バトル終了まで解\\n\u3000除できない。\\n\u3000このスキルの状態異常はダメージを無効化して\\n\u3000も付与される。\\n・ゴーストファーザー自身のＨＰが40％を切る\\n\u3000と、さらに攻撃が激しく凶暴になる。', 311602, 0, 2, 311600, 270, 0, 0, 16, 0, 4.0, 3000, '叫怖のゴーストファーザー');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【魔法】人間を恐怖に慄かせるお化けたちの首領。\\n手下をけしかけ、シマの拡大を密かに画策する。\\n\\n・ユニオンバーストは、敵全体にキャラの元々の\\n\u3000最大ＨＰに応じた魔法割合ダメージを与える。\\n\u3000さらに、敵全体のキャラの最大ＨＰを10％減\\n\u3000少させる。減少したＨＰは、バトル終了まで解\\n\u3000除できない。\\n\u3000このスキルの状態異常はダメージを無効化して\\n\u3000も付与される。\\n・ゴーストファーザー自身のＨＰが40％を切る\\n\u3000と、さらに攻撃が激しく凶暴になる。', 311603, 0, 2, 311600, 270, 0, 0, 16, 0, 4.0, 3000, '叫怖のゴーストファーザー');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ１】美味な魂を求め、お化けたちの首\\n領が再び姿を現す。残虐なファミリーを従え、\\n人々を蹂躙することで街を極上の悲鳴で満たす。\\n\\n・バトル開始時、ゴーストミニオンズを３体召喚\\n\u3000する。\\n・ゴーストミニオンズを１体倒すたびに、残り\\n\u3000ゴーストミニオンズ数が１減少する。\\n\u3000その後、ゴーストミニオンズが再度召喚される。\\n・ゴーストミニオンズは、目の前の敵１キャラの\\n\u3000ＴＰを減少させ、ゴーストファーザーのＴＰを\\n\u3000回復させる。\\n・ユニオンバーストは、敵全体にキャラの元々の\\n\u3000最大ＨＰに応じた魔法割合ダメージを与える。\\n\u3000さらに、敵全体のキャラの最大ＨＰを10％減\\n\u3000少させる。減少したＨＰは、バトル終了まで解\\n\u3000除できない。', 311604, 0, 2, 311600, 270, 0, 0, 16, 0, 4.0, 3000, '叫怖のゴーストファーザー');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ２】シマを荒らす、すべてに制裁を\\n下す。ひとたび彼のシマに踏み入れば、はびこる\\n魍魎が命を蝕み、生きながら地獄の苦しみを\\n与える。\\n\\n・バトル開始時、キャラの最大ＨＰが35％減少\\n\u3000する。減少したＨＰは、バトル終了まで解除\\n\u3000できない。\\n・ユニオンバーストは、敵全体にキャラの元々の\\n\u3000最大ＨＰに応じた魔法割合ダメージを与える。\\n\u3000さらに、敵全体のキャラの最大ＨＰを10％減\\n\u3000少させる。減少したＨＰは、バトル終了まで解\\n\u3000除できない。', 311605, 0, 2, 311600, 270, 0, 0, 16, 0, 999.0, 3000, '叫怖のゴーストファーザー');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ３】蓄えた力をすべて吐き出し、真の\\n力を解放する。この世界を支配すべく、残虐非道\\nの限りを尽くし、地獄へと染め上げる。\\n\\n・ユニオンバーストは、敵全体にキャラの元々の\\n\u3000最大ＨＰに応じた魔法割合ダメージを与える。\\n\u3000さらに、敵全体のキャラの最大ＨＰを10％減\\n\u3000少させる。減少したＨＰは、バトル終了まで解\\n\u3000除できない。\\n・自身に物理/魔法無効バリアを展開する。\\n・ゴーストファーザー自身のＨＰが40％を\\n\u3000切ると、さらに攻撃が激しく凶暴になる。', 311606, 0, 2, 311600, 270, 0, 0, 16, 0, 4.0, 3000, '叫怖のゴーストファーザー');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('ゴーストファーザーの側近の手下。\\n自身の体を盾にして、一切の攻撃から首領を守る。', 311700, 0, 2, 311700, 270, 0, 0, 16, 0, 999.0, 3000, 'ゴーストブラザーズ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('ゴーストファーザーの側近の手下。\\n鍛え上げた鉄砲玉で、街に特攻をしかける。血気\\n盛んに突撃し、逃げ惑う人々を恐怖の底に陥れる。\\n\\n・ゴーストブラザーズは攻撃の対象にならない。', 311701, 0, 2, 311700, 270, 0, 0, 16, 0, 999.0, 3000, 'ゴーストブラザーズ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('ゴーストファーザーの側近の手下。\\n鉄砲玉たちと集めた上質な精気を首領へ献上する。\\n\\n・ゴーストブラザーズは攻撃の対象にならない。\\n・ゴーストファーザーのＴＰを回復させる。\\n\u3000ゴーストファーザーが行動不能状態のときは、\\n\u3000ＴＰを回復しない。', 311702, 0, 2, 311700, 270, 0, 0, 16, 0, 999.0, 3000, 'ゴーストブラザーズ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('いよいよ訪れた出番に、鼻息荒く推参する。\\n気合十分の最強の盾が、歯向かう相手の心を折る。', 311703, 0, 2, 311700, 270, 0, 0, 16, 0, 999.0, 3000, 'ゴーストブラザーズ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('ゴーストファーザーの側近の手下。\\n取り立てた精気を首領へ渡し、補佐を務めあげる。\\n\\n・ゴーストファーザーのＴＰを小回復させる。', 311800, 0, 2, 311800, 270, 0, 0, 16, 0, 999.0, 3000, 'ゴーストブラザーズ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('ゴーストファーザーの側近の手下。\\n首領の近辺を警護し、一分の隙も見せない。裏で\\nは密かに街の人々を絶望へ追い込もうと暗躍する。\\n\\n・ゴーストブラザーズは攻撃の対象にならない。', 311801, 0, 2, 311800, 270, 0, 0, 16, 0, 999.0, 3000, 'ゴーストブラザーズ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('ゴーストファーザーの側近の手下。\\n部下と取り立てた極上の精気を首領へ差し出す。\\n\\n・ゴーストブラザーズは攻撃の対象にならない。\\n・ゴーストファーザーのＴＰを回復させる。\\n\u3000ゴーストファーザーが行動不能状態のときは、\\n\u3000ＴＰを回復しない。', 311802, 0, 2, 311800, 270, 0, 0, 16, 0, 999.0, 3000, 'ゴーストブラザーズ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('ファミリーの危機を守るべく、冷静に戦況を見極\\nめる。命尽きる直前まで、首領の忠実なる右腕と\\nして補佐に徹する。\\n\\n・ゴーストファーザーのＴＰを回復させる。', 311803, 0, 2, 311800, 270, 0, 0, 16, 0, 999.0, 3000, 'ゴーストブラザーズ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】霞を食み、自身の姿も霞の\\n如く掴みどころがない。人を嫌い、\\n近づく者は容赦なく踏み潰す。\\n\\n・敵全体に魔法大ダメージを与え\\n\u3000る。さらに、火傷状態の敵はダ\\n\u3000メージがアップする。\\n\\n・最も物理攻撃力が高い敵を中心に\\n\u3000した範囲内に魔法中ダメージを与\\n\u3000え、火傷状態にする。', 311900, 0, 1, 311900, 270, 0, 0, 13, 0, 2.0, 1000, 'ブライトホーン');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】魔力を宿せし黒曜の結晶竜。美しい体躯\\nの輝きは冥府を彷徨いし魂の嘆きといわれている。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・オブシダンワイバーンから受けるすべてのダ\\n\u3000メージで発生する、パーティキャラのＴＰ回\\n\u3000復量を中ダウンさせる。\\n・ユニオンバーストは、敵全体にキャラの最大Ｈ\\n\u3000Ｐに応じた魔法割合ダメージを与え、さらにＴ\\n\u3000Ｐを大ダウンさせる。このスキルはダメージを\\n\u3000無効化してもＴＰをダウンさせる。\\n・敵全体のＨＰ吸収を特大ダウンし、さらに物理\\n\u3000防御力を大ダウンさせる。\\n・物理攻撃力、魔法攻撃力いずれかで、最も攻撃\\n\u3000力が高い１キャラに物理大ダメージを与える。\\n\u3000さらにそのキャラを中心にした小範囲に物理中\\n\u3000ダメージを与え、ＴＰを中ダウンさせる。この\\n\u3000スキルはダメージを無効化してもＴＰをダウン\\n\u3000させる。', 312000, 0, 1, 312000, 270, 0, 0, 16, 0, 2.0, 3000, 'オブシダンワイバーン');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】魔力を宿せし黒曜の結晶竜。美しい体躯\\nの輝きは冥府を彷徨いし魂の嘆きといわれている。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を中アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・オブシダンワイバーンから受けるすべてのダ\\n\u3000メージで発生する、パーティキャラのＴＰ回\\n\u3000復量を中ダウンさせる。\\n・ユニオンバーストは、敵全体にキャラの最大Ｈ\\n\u3000Ｐに応じた魔法割合ダメージを与え、さらにＴ\\n\u3000Ｐを大ダウンさせる。このスキルはダメージを\\n\u3000無効化してもＴＰをダウンさせる。\\n・敵全体のＨＰ吸収を特大ダウンし、さらに物理\\n\u3000防御力を大ダウンさせる。\\n・物理攻撃力、魔法攻撃力いずれかで、最も攻撃\\n\u3000力が高い１キャラに物理大ダメージを与える。\\n\u3000さらにそのキャラを中心にした小範囲に物理中\\n\u3000ダメージを与え、ＴＰを中ダウンさせる。この\\n\u3000スキルはダメージを無効化してもＴＰをダウン\\n\u3000させる。', 312001, 0, 1, 312001, 270, 0, 0, 16, 0, 2.0, 3000, 'オブシダンワイバーン');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】魔力を宿せし黒曜の結晶竜。美しい体躯\\nの輝きは冥府を彷徨いし魂の嘆きといわれている。\\n\\n・オブシダンワイバーンから受けるすべてのダ\\n\u3000メージで発生する、パーティキャラのＴＰ回\\n\u3000復量を中ダウンさせる。\\n・ユニオンバーストは、敵全体にキャラの最大Ｈ\\n\u3000Ｐに応じた魔法割合ダメージを与え、さらにＴ\\n\u3000Ｐを大ダウンさせる。このスキルはダメージを\\n\u3000無効化してもＴＰをダウンさせる。\\n・敵全体のＨＰ吸収を特大ダウンし、さらに物理\\n\u3000防御力を大ダウンさせる。\\n・物理攻撃力、魔法攻撃力いずれかで、最も攻撃\\n\u3000力が高い１キャラに物理大ダメージを与える。\\n\u3000さらにそのキャラを中心にした小範囲に物理中\\n\u3000ダメージを与え、ＴＰを中ダウンさせる。この\\n\u3000スキルはダメージを無効化してもＴＰをダウン\\n\u3000させる。', 312002, 0, 1, 312002, 270, 0, 0, 16, 0, 2.0, 3000, 'オブシダンワイバーン');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】人々の夢を奪い去る、負の魔法生物。\\n陰鬱な黒い霧で希望を覆い、人々の心を蝕む。', 312100, 0, 1, 312100, 270, 0, 0, 16, 0, 2.7, 3000, 'アンチビースト de M');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】人々の夢を奪い去る、負の魔法生物。\\n陰鬱な黒い霧で希望を覆い、人々の心を蝕む。\\n\\n・ユニオンバーストは、敵全体のバリアを解除し、\\n\u3000魔法中ダメージを与える。さらに、物理防御力\\n\u3000を小ダウン、魔法防御力を中ダウンさせ、\\n\u3000一定時間ＨＰ回復量を70％ダウンさせる。\\n・前方２キャラに物理中ダメージを与える。', 312101, 0, 1, 312100, 270, 0, 0, 16, 0, 2.7, 3000, 'アンチビースト de M');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】人々の夢を奪い去る、負の魔法生物。\\n陰鬱な黒い霧で希望を覆い、人々の心を蝕む。\\n\\n・ユニオンバーストは、敵全体のバリアを解除し、\\n\u3000魔法中ダメージを与える。さらに、物理防御力\\n\u3000を小ダウン、魔法防御力を中ダウンさせ、\\n\u3000一定時間ＨＰ回復量を70％ダウンさせる。\\n・前方２キャラに物理中ダメージを与える。', 312102, 0, 1, 312100, 270, 0, 0, 16, 0, 2.7, 3000, 'アンチビースト de M');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】人々の夢を奪い去る、負の魔法生物。\\n陰鬱な黒い霧で希望を覆い、人々の心を蝕む。\\n\\n・ユニオンバーストは、敵全体のバリアを解除し、\\n\u3000魔法中ダメージを与える。さらに、物理防御力\\n\u3000と魔法防御力を中ダウンさせ、一定時間ＨＰ回\\n\u3000復量を70％ダウンさせる。\\n・前方２キャラに物理大ダメージを与える。\\n・アンチビースト de M自身のＨＰが15％\\n\u3000を切ると、自分のＴＰを中アップさせ、\\n\u3000さらに攻撃が激しく凶暴になる。', 312103, 0, 1, 312100, 270, 0, 0, 16, 0, 2.7, 3000, 'アンチビースト de M');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ１】街から愛と希望を吸い上げ奪う\\nアンチビースト。魔法少女たちをもねじ伏せ、\\n街中の全ての輝く力を取り込もうとする。\\n\\n・ユニオンバーストは、敵全体のバリアを解除し、\\n\u3000魔法大ダメージを与える。さらに、物理防御力\\n\u3000と魔法防御力を大ダウンさせ、一定時間ＨＰ回\\n\u3000復量を70％ダウンさせる。\\n・最も後ろの敵１キャラに最大ＨＰに応じた物理\\n\u3000割合ダメージを与え、束縛状態にし、ＴＰを\\n\u3000特大ダウンさせる。\\n\u3000さらに、アンチビースト de M自身のＴＰ\\n\u3000を中アップ。', 312104, 0, 1, 312100, 270, 0, 0, 16, 0, 2.7, 3000, 'アンチビースト de M');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ２】魔法少女たちの猛攻をも取り込み\\nさらに膨れ上がるアンチビーストの渇望。更には\\n人々を守るための勇気までも溶蝕されてゆく。\\n\\n・ユニオンバーストは、敵全体のバリアを解除し、\\n\u3000魔法大ダメージを与える。さらに、物理防御力\\n\u3000と魔法防御力を大ダウンさせ、一定時間ＨＰ回\\n\u3000復量を70％ダウンさせる。\\n・敵全体のバリアを解除し、最大ＨＰに応じた\\n\u3000魔法割合ダメージを与え、毒状態にする。', 312105, 0, 1, 312100, 270, 0, 0, 16, 0, 2.7, 3000, 'アンチビースト de M');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ３】負の情念は最高潮に達し、歪んだ\\n渇望が一帯を包み込む。魔法少女たちの信念を\\n挫き、守護者なき街を我が一部とせんとする。\\n\\n・ユニオンバーストは、敵全体のバリアを解除し、\\n\u3000魔法大ダメージを与える。さらに、物理防御力\\n\u3000と魔法防御力を大ダウンさせ、一定時間ＨＰ回\\n\u3000復量を70％ダウンさせる。\\n・前方２キャラに物理大ダメージを与える。\\n・アンチビースト de M自身のＨＰが12％\\n\u3000を切ると、さらに攻撃が激しく凶暴になる。', 312106, 0, 1, 312100, 270, 0, 0, 16, 0, 2.7, 3000, 'アンチビースト de M');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】でっぷりとした眼光鋭い最恐雪ダルマ。\\n狂気をその身に纏いながら聖夜の街中を縷々転々。\\n年に一度の特別な夜がブラッククリスマスと化す。', 312200, 0, 1, 312200, 270, 0, 0, 16, 0, 2.7, 3000, 'ドミネイテッドスノーマン');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】でっぷりとした眼光鋭い最恐雪ダルマ。\\n狂気をその身に纏いながら聖夜の街中を縷々転々。\\n年に一度の特別な夜がブラッククリスマスと化す。\\n\\n・ユニオンバーストは、敵全体にキャラの最大\\n\u3000ＨＰに応じた物理割合ダメージを与え、大きく\\n\u3000吹き飛ばす。さらに、自身のターゲットがブレ\\n\u3000イクしていない場合、物理防御力を中アップ、\\n\u3000魔法防御力を小アップ。このスキルの効果は\\n\u3000ダメージを無効化しても付与される。\\n・敵全体にキャラの最大ＨＰに応じた物理割合ダ\\n\u3000メージを与える。自身のターゲットがブレイク\\n\u3000していない場合、追加でスタン状態を付与。\\n\u3000このスキルの状態異常はダメージを無効化して\\n\u3000も付与される。\\n・残り時間が20秒を切ると、プレゼント型爆弾\\n\u3000を取り出し、その後一定時間が経過で、敵全体\\n\u3000にキャラの最大ＨＰに応じた物理割合ダメージ\\n\u3000を与える。\\n\u3000さらに、ドミネイテッドスノーマンにも自身の\\n\u3000残りＨＰに応じた物理割合ダメージを与え、\\n\u3000ＴＰを特大ダウンさせる。\\n・頭部のブレイク時、物理防御力と魔法防御力\\n\u3000が小ダウン。\\n・胴部のブレイク時、物理防御力と魔法防御力\\n\u3000が小ダウン。', 312201, 0, 1, 312200, 270, 0, 0, 16, 0, 4.0, 3000, 'ドミネイテッドスノーマン');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】でっぷりとした眼光鋭い最恐雪ダルマ。\\n狂気をその身に纏いながら聖夜の街中を縷々転々。\\n年に一度の特別な夜がブラッククリスマスと化す。\\n\\n・ユニオンバーストは、敵全体にキャラの最大\\n\u3000ＨＰに応じた物理割合ダメージを与え、大きく\\n\u3000吹き飛ばす。さらに、自身のターゲットがブレ\\n\u3000イクしていない場合、物理防御力を中アップ、\\n\u3000魔法防御力を小アップ。このスキルの効果は\\n\u3000ダメージを無効化しても付与される。\\n・敵全体にキャラの最大ＨＰに応じた物理割合ダ\\n\u3000メージを与える。自身のターゲットがブレイク\\n\u3000していない場合、追加でスタン状態を付与。\\n\u3000このスキルの状態異常はダメージを無効化して\\n\u3000も付与される。\\n・残り時間が20秒を切ると、プレゼント型爆弾\\n\u3000を取り出し、その後一定時間が経過で、敵全体\\n\u3000にキャラの最大ＨＰに応じた物理割合ダメージ\\n\u3000を与える。\\n\u3000さらに、ドミネイテッドスノーマンにも自身の\\n\u3000残りＨＰに応じた物理割合ダメージを与え、\\n\u3000ＴＰを特大ダウンさせる。\\n・頭部のブレイク時、物理防御力と魔法防御力\\n\u3000が小ダウン。\\n・胴部のブレイク時、物理防御力と魔法防御力\\n\u3000が小ダウン。', 312202, 0, 1, 312200, 270, 0, 0, 16, 0, 3.6, 3000, 'ドミネイテッドスノーマン');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】でっぷりとした眼光鋭い最恐雪ダルマ。\\n狂気をその身に纏いながら聖夜の街中を縷々転々。\\n年に一度の特別な夜がブラッククリスマスと化す。\\n\\n・ユニオンバーストは、敵全体にキャラの最大\\n\u3000ＨＰに応じた物理割合ダメージを与え、大きく\\n\u3000吹き飛ばす。さらに、自身のターゲットがブレ\\n\u3000イクしていない場合、物理防御力を中アップ、\\n\u3000魔法防御力を小アップ。このスキルの効果は\\n\u3000ダメージを無効化しても付与される。\\n・敵全体にキャラの最大ＨＰに応じた物理割合ダ\\n\u3000メージを与える。自身のターゲットがブレイク\\n\u3000していない場合、追加でスタン状態を付与。\\n\u3000このスキルの状態異常はダメージを無効化して\\n\u3000も付与される。\\n・残り時間が30秒を切ると、さらに攻撃が激し\\n\u3000く凶暴になる。\\n・残り時間が20秒を切ると、プレゼント型爆弾\\n\u3000を取り出し、その後一定時間が経過で、敵全体\\n\u3000にキャラの最大ＨＰに応じた物理割合ダメージ\\n\u3000を与える。\\n\u3000さらに、ドミネイテッドスノーマンにも自身の\\n\u3000残りＨＰに応じた物理割合ダメージを与え、\\n\u3000ＴＰを特大ダウンさせる。\\n・頭部のブレイク時、物理防御力と魔法防御力\\n\u3000が小ダウン。\\n・胴部のブレイク時、物理防御力と魔法防御力\\n\u3000が小ダウン。', 312203, 0, 1, 312200, 270, 0, 0, 16, 0, 2.7, 3000, 'ドミネイテッドスノーマン');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ１】パーティー会場を大混乱の渦に落\\nとす巨大雪ダルマ。もとは人々から愛された心優\\nしきマスコット。みんなの声援が攻略のカギとなる。\\n\\n・ユニオンバーストは、敵全体にキャラの最大\\n\u3000ＨＰに応じた物理割合ダメージを与え、大きく\\n\u3000吹き飛ばす。さらに、自身のターゲットがブレ\\n\u3000イクしていない場合、物理防御力を中アップ、\\n\u3000魔法防御力を小アップ。\\n・敵全体に魔法大ダメージを与え、凍結状態にす\\n\u3000る。\\n\u3000さらに、行動速度と物理防御力を大ダウンさせ\\n\u3000る。\\n\u3000このスキルの状態異常はダメージを無効化して\\n\u3000も付与される。\\n・頭部のブレイク時、物理防御力と魔法防御力が\\n\u3000小ダウン。\\n・胴部のブレイク時、物理防御力と魔法防御力が\\n\u3000小ダウン。\\n・バトル中、ドミネイテッドスノーマン自身に付\\n\u3000与されている状態異常効果およびステータスダ\\n\u3000ウン効果の数に応じて、与えられるダメージの\\n\u3000量が大きく上昇する。', 312204, 0, 1, 312200, 270, 0, 0, 16, 0, 2.7, 3000, 'ドミネイテッドスノーマン');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ２】聖夜に浮かれる３人娘のシャドウ\\nを召喚。それは巨大雪ダルマの作った虚像。\\n自身の名誉のために、今こそ立ち上がれ乙女たち！\\n\\n・ユニオンバーストは、敵全体にキャラの最大\\n\u3000ＨＰに応じた物理割合ダメージを与え、大きく\\n\u3000吹き飛ばす。さらに、自身のターゲットがブレ\\n\u3000イクしていない場合、物理防御力を中アップ、\\n\u3000魔法防御力を小アップ。\\n・敵全体にキャラの最大ＨＰに応じた物理割合ダ\\n\u3000メージを与える。自身のターゲットがブレイク\\n\u3000していない場合、追加でスタン状態を付与。\\n\u3000このスキルの状態異常はダメージを無効化して\\n\u3000も付与される。\\n・頭部のブレイク時、物理防御力と魔法防御力が\\n\u3000小ダウン。\\n・胴部のブレイク時、物理防御力と魔法防御力が\\n\u3000小ダウン。', 312205, 0, 1, 312200, 270, 0, 0, 16, 0, 20.0, 3000, 'ドミネイテッドスノーマン');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ３】すべての思いを轢殺せんと転がり\\n続ける巨大雪ダルマ。すべての寂しき人々へ、爆\\n炎の贈物を優しくプレゼントフォー・ユー♪\\n\\n・ユニオンバーストは、敵全体にキャラの最大\\n\u3000ＨＰに応じた物理割合ダメージを与え、大きく\\n\u3000吹き飛ばす。さらに、自身のターゲットがブレ\\n\u3000イクしていない場合、物理防御力を中アップ、\\n\u3000魔法防御力を小アップ。\\n・敵全体にキャラの最大ＨＰに応じた物理割合\\n\u3000ダメージを与える。自身のターゲットがブレ\\n\u3000イクしていない場合、追加でスタン状態を付\\n\u3000与。\\n\u3000このスキルの状態異常はダメージを無効化して\\n\u3000も付与される。\\n・残り時間が30秒を切ると、さらに攻撃が激し\\n\u3000く凶暴になる。\\n・残り時間が20秒を切ると、プレゼント型爆弾\\n\u3000を取り出し、その後一定時間が経過で、敵全\\n\u3000体にキャラの最大ＨＰに応じた物理割合ダメ\\n\u3000ージを与える。\\n\u3000さらに、ドミネイテッドスノーマンにも自身\\n\u3000の残りＨＰに応じた物理割合ダメージを与え、\\n\u3000ＴＰを特大ダウンさせる。\\n・頭部のブレイク時、物理防御力と魔法防御力\\n\u3000が小ダウン。\\n・胴部のブレイク時、物理防御力と魔法防御力\\n\u3000が小ダウン。', 312206, 0, 1, 312200, 270, 0, 0, 16, 0, 2.7, 3000, 'ドミネイテッドスノーマン');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('', 312300, 0, 1, 312300, 270, 0, 0, 16, 0, 1.1, 3000, 'グレートトゥンヌス');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】オーマの漁師に古くから伝わる幻の巨魚。\\n巨躯超速の突進は、全ての船を海の藻屑と化す。\\nしかしその身はこの世のものと思えぬ絶品らしい。\\n\\n・ユニオンバーストは、敵全体にキャラの最大\\n\u3000ＨＰに応じた物理割合ダメージを与える。\\n\u3000さらにノックバックさせる。\\n\u3000このスキルの状態異常はダメージを無効化\\n\u3000しても付与される。\\n\u3000自身の物理攻撃力に応じて与えるダメージ\\n\u3000の割合が増加する。', 312301, 0, 1, 312300, 270, 0, 0, 16, 0, 4.0, 3000, 'グレートトゥンヌス');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】オーマの漁師に古くから伝わる幻の巨魚。\\n巨躯超速の突進は、全ての船を海の藻屑と化す。\\nしかしその身はこの世のものと思えぬ絶品らしい。\\n\\n・ユニオンバーストは、敵全体にキャラの最大\\n\u3000ＨＰに応じた物理割合ダメージを与える。\\n\u3000さらにノックバックさせる。\\n\u3000このスキルの状態異常はダメージを無効化\\n\u3000しても付与される。\\n\u3000自身の物理攻撃力に応じて与えるダメージ\\n\u3000の割合が増加する。\\n・残り時間が35秒を切ると、さらに攻撃が激し\\n\u3000く凶暴になる。', 312302, 0, 1, 312302, 270, 0, 0, 16, 0, 3.3, 3000, 'グレートトゥンヌス');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】オーマの漁師に古くから伝わる幻の巨魚。\\n巨躯超速の突進は、全ての船を海の藻屑と化す。\\nしかしその身はこの世のものと思えぬ絶品らしい。\\n\\n・ユニオンバーストは、敵全体にキャラの最大\\n\u3000ＨＰに応じた物理割合ダメージを与える。\\n\u3000さらにノックバックさせる。\\n\u3000このスキルの状態異常はダメージを無効化\\n\u3000しても付与される。\\n\u3000自身の物理攻撃力に応じて与えるダメージ\\n\u3000の割合が増加する。\\n・残り時間が35秒を切ると、さらに攻撃が激し\\n\u3000く凶暴になる。', 312303, 0, 1, 312302, 270, 0, 0, 16, 0, 1.1, 3000, 'グレートトゥンヌス');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ１】数多の漁師を波間に沈めた海の王。\\n黄金に輝くヒレで大漁船の竜骨をも圧し折る。\\nその様はさながら大海原の解体ショー\\n\\n・ユニオンバーストは、敵全体にキャラの最大\\n\u3000ＨＰに応じた物理割合ダメージを与える。\\n\u3000さらにノックバックさせる。\\n・前方範囲内の敵すべてに物理大ダメージを与え、\\n\u3000さらに後ろから２キャラに物理中ダメージを\\n\u3000与える。また、自身の物理攻撃力を小アップ\\n\u3000させる。', 312304, 0, 1, 312302, 270, 0, 0, 16, 0, 0.0, 3000, 'グレートトゥンヌス');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ２】海を駆ける怪魚はさらに力を増す。\\nひと泳ぎで自身を鼓舞するかのように大渦をおこ\\nし大海を分かつ巨大な砲弾となって敵に激突する。\\n\\n・ユニオンバーストは、前から３キャラに\\n\u3000物理特大ダメージを与え\\n\u3000さらにノックバックさせる。\\n・自身の物理攻撃力を大アップ、行動速度を\\n\u3000中アップ、ＴＰを小アップさせる。', 312305, 0, 1, 312305, 270, 0, 0, 16, 0, 1.0, 3000, 'グレートトゥンヌス');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ３】幾度もその黒い巨体に銛を受けよ\\nうとも、伝説の巨魚の猛進は止められない。\\n永きにわたる海の漢たちとの勝負の決着の時。\\n\\n・ユニオンバーストは、敵全体にキャラの最大\\n\u3000ＨＰに応じた物理割合ダメージを与える。\\n\u3000さらにノックバックさせる。\\n・自身の物理攻撃力を大アップ、行動速度を\\n\u3000中アップ、ＴＰを大アップさせる。\\n・残り時間が35秒を切ると、さらに攻撃が激し\\n\u3000く凶暴になる。', 312306, 0, 1, 312302, 270, 0, 0, 16, 0, 1.0, 3000, 'グレートトゥンヌス');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】氷翼を広げ、冒険者を威嚇\\nする大鷲。縄張りに踏み込んだ者\\nを、容赦なく氷漬けにし子どもたち\\nの贄とする。\\n\\n・ユニオンバーストは、前方小範囲\\n\u3000に物理大ダメージを与え、さらに\\n\u3000大きく吹き飛ばし、氷結状態に\\n\u3000する。', 312400, 0, 1, 312400, 270, 0, 0, 11, 0, 1.6, 1000, 'アイスグリフォン');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】氷翼を広げ、冒険者を威嚇\\nする大鷲。縄張りに踏み込んだ者\\nを、容赦なく氷漬けにし子どもたち\\nの贄とする。\\n\\n・ユニオンバーストは、前方小範囲\\n\u3000に物理大ダメージを与え、さらに\\n\u3000大きく吹き飛ばし、氷結状態に\\n\u3000する。', 312401, 0, 1, 312400, 270, 0, 0, 11, 0, 1.6, 1000, 'アイスグリフォン');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【魔法】塔の魔力を蓄え雷撃として放電する怪鳥。\\n雷雲と共に顕現し、天災の如き雷で敵を葬り去る。\\n\\n・敵全体に魔法大ダメージを与え、自分の魔法\\n\u3000攻撃力と、行動速度を小アップさせる。\\n\u3000物理攻撃をする敵にはさらに追加ダメージ。\\n・前方範囲内の敵すべてに魔法中ダメージを与え\\n\u3000物理防御力と魔法防御力を中ダウンさせる。\\n・物理攻撃力が最も高い敵１キャラに魔法大\\n\u3000ダメージを与え、長時間麻痺状態にする。\\n\u3000自分のＨＰが85％を切ると、魔法攻撃力が\\n\u3000最も高い敵にもこの攻撃を行う。', 312500, 0, 2, 312500, 270, 0, 0, 6, 0, 1.6, 1000, 'マダムエレクトラ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【魔法】魔力を蓄え雷撃として放電する怪鳥。\\n雷雲と共に顕現し、天災の如き雷で敵を葬り去る。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・マダムエレクトラから受けるすべてのダメージ\\n\u3000で発生する、パーティキャラのＴＰ回復量を中\\n\u3000ダウンさせる。\\n・ユニオンバーストは、自身の魔法攻撃力と魔法\\n\u3000防御力をバトル終了まで小アップさせ、最も近\\n\u3000い敵１キャラに魔法特大ダメージを与える。', 312501, 0, 2, 312501, 270, 0, 0, 6, 0, 1.6, 1000, 'マダムエレクトラ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【魔法】魔力を蓄え雷撃として放電する怪鳥。\\n雷雲と共に顕現し、天災の如き雷で敵を葬り去る。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を中アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・バトル開始時、自身にＴＰダウン100％カッ\\n\u3000ト効果を付与する。\\n・バトル開始時、敵全体のＨＰ吸収を特大ダウン\\n\u3000させ、ＴＰ上昇を小ダウンさせる。\\n・マダムエレクトラから受けるすべてのダメージ\\n\u3000で発生する、パーティキャラのＴＰ回復量を中\\n\u3000ダウンさせる。\\n・ユニオンバーストは、バトル終了まで自身の魔\\n\u3000法攻撃力を小アップ、魔法防御力を中アップさ\\n\u3000せる。その後、最も近い敵１キャラに魔法特大\\n\u3000ダメージを与え、麻痺状態を付与する。このス\\n\u3000キルの状態異常はダメージを無効化しても付与\\n\u3000される。\\n・最も近い敵１キャラに魔法特大ダメージを与え、\\n\u3000麻痺状態を付与する。このスキルの状態異常は\\n\u3000ダメージを無効化しても付与される。', 312502, 0, 2, 312502, 270, 0, 0, 6, 0, 1.6, 1000, 'マダムエレクトラ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【魔法】魔力を蓄え雷撃として放電する怪鳥。\\n雷雲と共に顕現し、天災の如き雷で敵を葬り去る。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を中アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・バトル開始時、自身にＴＰダウン50％カット\\n\u3000効果を付与する。\\n・マダムエレクトラから受けるすべてのダメージ\\n\u3000で発生する、パーティキャラのＴＰ回復量を中\\n\u3000ダウンさせる。\\n・ユニオンバーストは、自身の魔法攻撃力と魔法\\n\u3000防御力を小アップさせ、最も近い敵１キャラに\\n\u3000魔法特大ダメージを与え、麻痺状態を付与する。\\n\u3000このスキルの状態異常はダメージを無効化して\\n\u3000も付与される。\\n・最も近い敵１キャラに魔法特大ダメージを与え、\\n\u3000麻痺状態を付与する。このスキルの状態異常は\\n\u3000ダメージを無効化しても付与される。', 312503, 0, 2, 312503, 270, 0, 0, 6, 0, 1.6, 3000, 'マダムエレクトラ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【魔法】魔力を蓄え雷撃として放電する怪鳥。\\n雷雲と共に顕現し、天災の如き雷で敵を葬り去る。\\n\\n・マダムエレクトラから受けるすべてのダメージ\\n\u3000で発生する、パーティキャラのＴＰ回復量を中\\n\u3000ダウンさせる。\\n・ユニオンバーストは、最も近い敵１キャラに魔\\n\u3000法特大ダメージを与え、さらに麻痺状態を付与\\n\u3000する。その後自身の魔法攻撃力と魔法防御力を\\n\u3000バトル終了まで小アップさせる。このスキルの\\n\u3000状態異常はダメージを無効化しても付与される。\\n・最も近い敵１キャラに魔法特大ダメージを与え、\\n\u3000麻痺状態を付与する。このスキルの状態異常は\\n\u3000ダメージを無効化しても付与される。', 312504, 0, 2, 312504, 270, 0, 0, 6, 0, 1.6, 3000, 'マダムエレクトラ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('', 312600, 0, 1, 312600, 270, 0, 0, 16, 0, 2.7, 3000, 'ジェネラルホーン');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】立派な麋角をもつ大型魔物。大岩をも\\n軽々粉砕する大角で冒険者をまとめて薙ぎ払う。\\n\\n・通常攻撃は、前方１キャラを中心とした範囲内\\n\u3000に物理小ダメージを与える。\\n・ユニオンバーストは、敵全体にキャラの最大Ｈ\\n\u3000Ｐに応じた魔法割合ダメージを与える。\\n\u3000さらに、自身の物理・魔法防御力を中ダウンさ\\n\u3000せる。\\n・前方範囲内に物理中ダメージを与え、麻痺さ\\n\u3000せる。さらに、自身の物理・魔法防御力を大ダ\\n\u3000ウンさせる。\\n\u3000このスキルの状態異常はダメージを無効化\\n\u3000しても付与される。', 312601, 0, 1, 312600, 270, 0, 0, 16, 0, 2.7, 3000, 'ジェネラルホーン');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】立派な麋角をもつ大型魔物。大岩をも\\n軽々粉砕する大角で冒険者をまとめて薙ぎ払う。\\n\\n・通常攻撃は、前方１キャラを中心とした範囲内\\n\u3000に物理小ダメージを与える。\\n・ユニオンバーストは、敵全体にキャラの最大Ｈ\\n\u3000Ｐに応じた魔法割合ダメージを与える。\\n\u3000さらに、自身の物理・魔法防御力を中ダウンさ\\n\u3000せる。\\n・前方範囲内に物理中ダメージを与え、麻痺さ\\n\u3000せる。さらに、自身の物理・魔法防御力を大ダ\\n\u3000ウンさせる。\\n\u3000このスキルの状態異常はダメージを無効化\\n\u3000しても付与される。\\n・残り時間が25秒を切ると、さらに攻撃が激し\\n\u3000く凶暴になる。', 312602, 0, 1, 312600, 270, 0, 0, 16, 0, 2.7, 3000, 'ジェネラルホーン');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】立派な麋角をもつ大型魔物。大岩をも\\n軽々粉砕する大角で冒険者をまとめて薙ぎ払う。\\n\\n・通常攻撃は、前方１キャラを中心とした範囲内\\n\u3000に物理小ダメージを与える。\\n・ユニオンバーストは、敵全体にキャラの最大Ｈ\\n\u3000Ｐに応じた魔法割合ダメージを与える。\\n\u3000さらに、自身の物理・魔法防御力を中ダウンさ\\n\u3000せる。\\n・前方範囲内に物理中ダメージを与え、麻痺さ\\n\u3000せる。さらに、自身の物理・魔法防御力を大ダ\\n\u3000ウンさせる。\\n\u3000このスキルの状態異常はダメージを無効化\\n\u3000しても付与される。\\n・残り時間が25秒を切ると、さらに攻撃が激し\\n\u3000く凶暴になる。', 312603, 0, 1, 312600, 270, 0, 0, 16, 0, 2.7, 3000, 'ジェネラルホーン');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ１】首領の雄たけびで、手先の牡鹿が\\n群れを成し押し寄せる。捨て身の突進を食い止め\\nられるか？\\n\\n・バトル開始時、ワイルドホーンを３体召喚し、\\n\u3000さらにノックバックさせる。\\n・ワイルドホーンを１体倒すたびに、残りワイル\\n\u3000ドホーン数が１減少する。\\n\u3000その後、ワイルドホーンが再度召喚され、ノッ\\n\u3000クバックさせる。\\n・通常攻撃は、前方１キャラを中心とした範囲内\\n\u3000に物理小ダメージを与える。\\n・ユニオンバーストは、敵全体にキャラの最大Ｈ\\n\u3000Ｐに応じた魔法割合ダメージを与える。\\n\u3000さらに、自身の物理・魔法防御力を中ダウンさ\\n\u3000せる。', 312604, 0, 1, 312600, 270, 0, 0, 16, 0, 2.7, 3000, 'ジェネラルホーン');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ２】朽木の魔物を従え、冒険者を追い\\n詰める。共生の朽木を失うとその身もともに破滅\\nへと向かう。朽木の撃滅が攻略のカギとなる。\\n\\n・バトル開始時、トレントを２体召喚し、さらに\\n\u3000ノックバックさせる。\\n・前方のトレントのＨＰが０になった時、ジェネ\\n\u3000ラルホーンの物理・魔法防御力を小ダウンさせ\\n\u3000る。\\n・後方のトレントのＨＰが０になった時、ジェネ\\n\u3000ラルホーンの物理・魔法防御力を極大ダウンさ\\n\u3000せる。\\n・通常攻撃は、前方１キャラを中心とした範囲内\\n\u3000に物理小ダメージを与える。\\n・ユニオンバーストは、敵全体にキャラの最大Ｈ\\n\u3000Ｐに応じた魔法割合ダメージを与える。\\n\u3000さらに、自身の物理・魔法防御力を中ダウンさ\\n\u3000せる。\\n・前方範囲内に物理中ダメージを与え、麻痺さ\\n\u3000せる。さらに、自身の物理・魔法防御力を大ダ\\n\u3000ウンさせる。', 312605, 0, 1, 312600, 270, 0, 0, 16, 0, 2.7, 3000, 'ジェネラルホーン');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ３】手負いの角獣が死力を振り絞る。\\n命を賭した突進は体躯を紫電に変え、光の如き\\n一閃は歴戦の冒険者一行を瓦解させる。\\n\\n・通常攻撃は、前方１キャラを中心とした範囲内\\n\u3000に物理小ダメージを与える。\\n・ユニオンバーストは、敵全体にキャラの最大Ｈ\\n\u3000Ｐに応じた魔法割合ダメージを与える。\\n\u3000さらに、自身の物理・魔法防御力を中ダウンさ\\n\u3000せる。\\n・前方範囲内に物理中ダメージを与え、麻痺さ\\n\u3000せる。さらに、自身の物理・魔法防御力を大ダ\\n\u3000ウンさせる。\\n・残り時間が25秒を切ると、さらに攻撃が激し\\n\u3000く凶暴になる。', 312606, 0, 1, 312600, 270, 0, 0, 16, 0, 2.7, 3000, 'ジェネラルホーン');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('', 312700, 0, 2, 312700, 270, 0, 0, 16, 0, 2.7, 3000, '黒風の精霊');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【魔法】使役者の真の力を試す黒き風の精霊。\\nそこには悪意はなく、純粋に己の内に秘めた想い\\nと絆が試される。\\n\\n・ユニオンバーストは、敵全体に黒風の精霊\\n\u3000の物理攻撃力とキャラの最大ＨＰに応じた\\n\u3000魔法割合ダメージを与える。さらに、\\n\u3000残りＨＰが最も低い１キャラにカウントダウン\\n\u3000を付与し、５秒後に最大ＨＰの80%の魔法\\n\u3000割合ダメージを与える。\\n\u3000黒風の精霊がユニオンバーストを使用してから\\n\u3000一定時間が経過するまでは再度ユニオン\\n\u3000バーストを使用しない。', 312701, 0, 2, 312700, 270, 0, 0, 16, 0, 2.7, 3000, '黒風の精霊');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【魔法】使役者の真の力を試す黒き風の精霊。\\nそこには悪意はなく、純粋に己の内に秘めた想い\\nと絆が試される。\\n\\n・ユニオンバーストは、敵全体に黒風の精霊\\n\u3000の物理攻撃力とキャラの最大ＨＰに応じた\\n\u3000魔法割合ダメージを与える。さらに、\\n\u3000残りＨＰが最も低い１キャラにカウントダウン\\n\u3000を付与し、５秒後に最大ＨＰの80%の魔法\\n\u3000割合ダメージを与える。\\n\u3000黒風の精霊がユニオンバーストを使用してから\\n\u3000一定時間が経過するまでは再度ユニオン\\n\u3000バーストを使用しない。\\n・敵全体を猛毒状態にし、さらに物理・魔法攻撃\\n\u3000力を大ダウンさせる。\\n・残り時間が25秒を切ると、さらに攻撃が激し\\n\u3000く凶暴になる。', 312702, 0, 2, 312700, 270, 0, 0, 16, 0, 2.7, 3000, '黒風の精霊');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【魔法】使役者の真の力を試す黒き風の精霊。\\nそこには悪意はなく、純粋に己の内に秘めた想い\\nと絆が試される。\\n\\n・ユニオンバーストは、敵全体に黒風の精霊\\n\u3000の物理攻撃力とキャラの最大ＨＰに応じた\\n\u3000魔法割合ダメージを与える。さらに、\\n\u3000残りＨＰが最も低い１キャラにカウントダウン\\n\u3000を付与し、５秒後に最大ＨＰの80%の魔法\\n\u3000割合ダメージを与える。\\n\u3000黒風の精霊がユニオンバーストを使用してから\\n\u3000一定時間が経過するまでは再度ユニオン\\n\u3000バーストを使用しない。\\n・敵全体を猛毒状態にし、さらに物理・魔法攻撃\\n\u3000力を大ダウンさせる。\\n・残り時間が25秒を切ると、さらに攻撃が激し\\n\u3000く凶暴になる。', 312703, 0, 2, 312700, 270, 0, 0, 16, 0, 2.7, 3000, '黒風の精霊');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ１】第一の試練。黒き風の精霊の暴風\\nの継ぎ目を見切れば、自ずと己の進むべき道が\\n切り拓かれん。\\n\\n・敵全体に物理ダメージとスタンを与え、ノック\\n\u3000バックさせる。\\n\u3000黒風の精霊が眠っている間、自身の物理防御力\\n\u3000が大幅にダウンし、その間に100000以上\\n\u3000のダメージを与えると、防御力ダウンが延長さ\\n\u3000れ行動速度もダウンする。', 312704, 0, 2, 312700, 270, 0, 0, 16, 0, 2.7, 3000, '黒風の精霊');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ２】第二の試練。己の弱き心と対峙\\nせよ。いつも答えは己の内にある。今一度、仲間\\nの力を信じ立ち向かえ。\\n\\n・前から２キャラに物理小ダメージを与え、さら\\n\u3000にノックバックさせ、スタンを与える。', 312705, 0, 2, 312705, 270, 0, 0, 16, 0, 2.7, 3000, '黒風の精霊');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ３】第三の試練。終の試練は、己の\\nすべてを懸け黒き風の精霊に本当の想いと絆を\\n顕現し、己の想いを確かめよ。\\n\\n・ユニオンバーストは、敵全体に黒風の精霊\\n\u3000の物理攻撃力とキャラの最大ＨＰに応じた\\n\u3000魔法割合ダメージを与える。さらに、\\n\u3000残りＨＰが最も低い１キャラにカウントダウン\\n\u3000を付与し、５秒後に最大ＨＰの80%の魔法\\n\u3000割合ダメージを与える。\\n・敵全体を猛毒状態にし、さらに物理・魔法攻撃\\n\u3000力を大ダウンさせる。\\n・残り時間が25秒を切ると、さらに攻撃が激し\\n\u3000く凶暴になる。', 312706, 0, 2, 312700, 270, 0, 0, 16, 0, 2.7, 3000, '黒風の精霊');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('', 312800, 0, 1, 312800, 270, 0, 0, 16, 0, 1.8, 3000, '魔物の姫');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】辺境の城に座する、孤高な魔物の姫君。\\n悲哀なる恋慕を胸に、自らに挑む者を打ち砕く。\\n\\n・ユニオンバーストは、前から２キャラに\\n\u3000最大ＨＰに応じた物理割合ダメージを与える。\\n\u3000力を溜めることに成功した場合、ダメージが\\n\u3000アップし、敵全体を畏怖状態にする。\\n\u3000畏怖状態のキャラは、一定時間攻撃およびＨＰ\\n\u3000回復のユニオンバーストとスキルの効果が\\n\u3000ダウン。\\n\u3000このスキルの状態異常はダメージを無効化して\\n\u3000も付与される。\\n・物理防御力と魔法防御力が大幅にダウンした後、\\n\u3000一定時間、力を溜める。\\n\u3000力が溜まると、ＴＰが特大回復する。\\n\u3000力を溜めている間に魔物の姫が7000以上の\\n\u3000ダメージを受けると、力を溜めることに失敗し、\\n\u3000ＴＰが大ダウン。 \\n・目の前の敵１キャラに物理ダメージを与える。\\n\u3000この攻撃は物理攻撃力アップ・ダウン効果の\\n\u3000影響を受けやすい。\\n・前から３キャラに最大ＨＰに応じた物理割合\\n\u3000ダメージを与える。\\n\u3000この攻撃は物理攻撃力アップ・ダウン効果の\\n\u3000影響を受けやすい。', 312801, 0, 1, 312800, 270, 0, 0, 16, 0, 1.8, 3000, '魔物の姫');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】辺境の城に座する、孤高な魔物の姫君。\\n悲哀なる恋慕を胸に、自らに挑む者を打ち砕く。\\n\\n・ユニオンバーストは、前から２キャラに\\n\u3000最大ＨＰに応じた物理割合ダメージを与える。\\n\u3000力を溜めることに成功した場合、ダメージが\\n\u3000アップし、敵全体を畏怖状態にする。\\n\u3000畏怖状態のキャラは、一定時間攻撃およびＨＰ\\n\u3000回復のユニオンバーストとスキルの効果が\\n\u3000ダウン。\\n\u3000このスキルの状態異常はダメージを無効化して\\n\u3000も付与される。\\n・物理防御力と魔法防御力が大幅にダウンした後、\\n\u3000一定時間、力を溜める。\\n\u3000力が溜まると、ＴＰが特大回復する。\\n\u3000力を溜めている間に魔物の姫が35000以上\\n\u3000のダメージを受けると、力を溜めることに失敗\\n\u3000し、ＴＰが大ダウン。 \\n・目の前の敵１キャラに物理ダメージを与える。\\n\u3000この攻撃は物理攻撃力アップ・ダウン効果の\\n\u3000影響を受けやすい。\\n・前から３キャラに最大ＨＰに応じた物理割合\\n\u3000ダメージを与える。\\n\u3000この攻撃は物理攻撃力アップ・ダウン効果の\\n\u3000影響を受けやすい。', 312802, 0, 1, 312800, 270, 0, 0, 16, 0, 1.8, 3000, '魔物の姫');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】辺境の城に座する、孤高な魔物の姫君。\\n悲哀なる恋慕を胸に、自らに挑む者を打ち砕く。\\n\\n・ユニオンバーストは、前から２キャラに\\n\u3000最大ＨＰに応じた物理割合ダメージを与える。\\n\u3000力を溜めることに成功した場合、ダメージが\\n\u3000アップし、敵全体を畏怖状態にする。\\n\u3000畏怖状態のキャラは、一定時間攻撃およびＨＰ\\n\u3000回復のユニオンバーストとスキルの効果が\\n\u3000ダウン。\\n\u3000このスキルの状態異常はダメージを無効化して\\n\u3000も付与される。\\n・物理防御力と魔法防御力が大幅にダウンした後、\\n\u3000一定時間、力を溜める。\\n\u3000力が溜まると、ＴＰが特大回復する。\\n\u3000力を溜めている間に魔物の姫が180000\\n\u3000以上のダメージを受けると、力を溜めることに\\n\u3000失敗し、ＴＰが大ダウン。 \\n・目の前の敵１キャラに物理ダメージを与える。\\n\u3000この攻撃は物理攻撃力アップ・ダウン効果の\\n\u3000影響を受けやすい。\\n・前から３キャラに最大ＨＰに応じた物理割合\\n\u3000ダメージを与える。\\n\u3000この攻撃は物理攻撃力アップ・ダウン効果の\\n\u3000影響を受けやすい。\\n・魔物の姫自身のＨＰが25％を切ると、さらに\\n\u3000攻撃が激しく凶暴になる。', 312803, 0, 1, 312800, 270, 0, 0, 16, 0, 1.8, 3000, '魔物の姫');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ１】高潔なる姫君は従兵を以て対敵を\\n拒絶する。さながら内なる嘆きを虚飾するが如く。\\n\\n・ユニオンバーストは、前方２キャラに最大ＨＰ\\n\u3000に応じた物理割合ダメージを与える。\\n・目の前の敵１キャラに物理ダメージを与える。\\n\u3000この攻撃は物理攻撃力アップ・ダウン効果の\\n\u3000影響を受けやすい。\\n・前方３キャラに最大ＨＰに応じた物理割合\\n\u3000ダメージを与える。\\n\u3000この攻撃は物理攻撃力アップ・ダウン効果の\\n\u3000影響を受けやすい。', 312804, 0, 1, 312800, 270, 0, 0, 16, 0, 1.8, 3000, '魔物の姫');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ２】姫君は更なる力を解き放つ。\\n歪曲した強き恋慕で、全てを拒み屠らんとする。\\n\\n・敵からの攻撃による麻痺、スタン、束縛、凍結、\\n\u3000時間停止、行動速度低下効果への耐性を持たな\\n\u3000い。\\n・ユニオンバーストは、前方２キャラに最大ＨＰ\\n\u3000に応じた物理割合ダメージを与える。\\n・目の前の敵１キャラに物理ダメージを与える。\\n\u3000この攻撃は物理攻撃力アップ・ダウン効果の\\n\u3000影響を受けやすい。\\n・前方３キャラに最大ＨＰに応じた物理割合\\n\u3000ダメージを与える。\\n\u3000この攻撃は物理攻撃力アップ・ダウン効果の\\n\u3000影響を受けやすい。\\n・短時間無敵状態になり、敵全体のステータス\\n\u3000アップ効果を解除した後、一定時間バトルフ\\n\u3000ィールドを展開する。\\n\\n【バトルフィールド効果】\\n・敵全体の物理攻撃力と魔法攻撃力を100％\\n\u3000ダウンした後、物理攻撃力と魔法攻撃力を\\n\u3000特大アップ。\\n・魔物の姫の物理攻撃力を特大アップ。', 312805, 0, 1, 312800, 270, 0, 0, 16, 0, 1.8, 3000, '魔物の姫');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ３】大いなる悲哀に呼応して、姫君の\\n進攻は苛烈を極める。乙女の熱情を以て、その\\n悲しみに救いをもたらさん。\\n\\n・ユニオンバーストは、前方２キャラに最大ＨＰ\\n\u3000に応じた物理割合ダメージを与える。\\n\u3000力を溜めることに成功した場合、ダメージが\\n\u3000アップし、敵全体を畏怖状態にする。\\n\u3000畏怖状態のキャラは、一定時間攻撃およびＨＰ\\n\u3000回復のユニオンバーストとスキルの効果が\\n\u3000ダウン。\\n・物理防御力と魔法防御力が大幅にダウンした後、\\n\u3000一定時間、力を溜める。\\n\u3000力が溜まると、ＴＰが特大回復する。\\n\u3000力を溜めている間に魔物の姫が600000\\n\u3000以上のダメージを受けると、力を溜めることに\\n\u3000失敗し、ＴＰが大ダウン。 \\n・目の前の敵１キャラに物理ダメージを与える。\\n\u3000この攻撃は物理攻撃力アップ・ダウン効果の\\n\u3000影響を受けやすい。\\n・前方３キャラに最大ＨＰに応じた物理割合\\n\u3000ダメージを与える。\\n\u3000この攻撃は物理攻撃力アップ・ダウン効果の\\n\u3000影響を受けやすい。\\n・魔物の姫自身のＨＰが25％を切ると、さらに\\n\u3000攻撃が激しく凶暴になる。', 312806, 0, 1, 312800, 270, 0, 0, 16, 0, 1.8, 3000, '魔物の姫');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】天上の聖域を護る、黒月に祝福されし像。\\n聖域に踏み入る、冒険者を常世の闇に葬り去る。\\n\\n・ユニオンバーストは、敵全体にキャラの最大\\n\u3000ＨＰに応じた物理割合ダメージを与える。\\n・敵全体に物理大ダメージを与え、ステータス\\n\u3000アップ効果を解除する。このスキルの効果は\\n\u3000ダメージを無効化しても付与される。\\n・自身の物理攻撃力と魔法攻撃力を大アップさ\\n\u3000せる。白陽の守護像が討伐されている場合、\\n\u3000このスキルを使用する。\\n・黒月の守護像のＨＰが50％を切ると、物理\\n\u3000攻撃力を大アップさせ、物理防御力を中アップ\\n\u3000する。\\n・黒月の守護像のターゲットがブレイクしてい\\n\u3000る場合、物理防御力と魔法防御力が小ダウンす\\n\u3000る。\\n・白陽の守護像が討伐されていた場合、バトルス\\n\u3000タートの際、もしくは黒月の守護像が通常攻撃\\n\u3000を行った際に、黒月の守護像の攻撃行動を変更\\n\u3000する。', 312900, 0, 1, 312900, 270, 0, 0, 16, 0, 2.5, 3000, '黒月の守護像');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【魔法】天上の聖域を護る、白陽に祝福されし像。\\n全てを浄化する白雷で、冒険者に審判を下す。\\n\\n・ユニオンバーストは、敵全体にキャラの最大\\n\u3000ＨＰに応じた魔法割合ダメージを与える。\\n・敵全体に魔法大ダメージを与え、ステータス\\n\u3000アップ効果を解除する。さらに白陽の守護像の\\n\u3000魔法攻撃力を大アップする。このスキルの効果\\n\u3000はダメージを無効化しても付与される。黒月の\\n\u3000守護像が討伐されている場合、このスキルを使\\n\u3000用する。\\n・味方全体の物理防御力と魔法防御力を中アップ\\n\u3000させる。\\n・白陽の守護像のＨＰが50％を切ると、魔法攻\\n\u3000撃力を特大アップさせ、魔法防御力を小アップ\\n\u3000する。\\n・白陽の守護像のターゲットがブレイクしている\\n\u3000場合、物理防御力と魔法防御力が小ダウンする。\\n・黒月の守護像が討伐されていた場合、バトルス\\n\u3000タートの際、もしくは白陽の守護像が通常攻撃\\n\u3000を行った際に、白陽の守護像の攻撃行動を変更\\n\u3000する。', 313000, 0, 2, 313000, 270, 0, 0, 16, 0, 2.5, 3000, '白陽の守護像');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('', 313100, 0, 2, 313100, 270, 0, 0, 16, 0, 1.4, 3000, 'バースト・タイムラーベ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【魔法】ホマレ所蔵の魔道具が、臨界を超え暴走\\nした姿。本来の役目も忘れ、冒険者を混沌へと\\n導く水先案内人と化す。\\n\\n・ユニオンバーストは、敵全体に魔法大ダメージ\\n\u3000を与え、さらに行動速度を中ダウン、魔法防御\\n\u3000力を中ダウンさせる。このスキルの状態異常は\\n\u3000ダメージを無効化しても付与される。\\n・自分の魔法攻撃力を中アップ、行動速度を大\\n\u3000アップさせる。\\n・向かって左側のターゲットのブレイク時、\\n\u3000物理/魔法防御力が中ダウン。\\n・中央下部のターゲットのブレイク時、\\n\u3000物理/魔法防御力が大ダウン。\\n・中央上部のターゲットのブレイク時、\\n\u3000物理/魔法防御力が大ダウン。\\n・向かって右側のターゲットのブレイク時、\\n\u3000物理/魔法防御力が特大ダウン。', 313101, 0, 2, 313100, 270, 0, 0, 16, 0, 1.4, 3000, 'バースト・タイムラーベ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【魔法】ホマレ所蔵の魔道具が、臨界を超え暴走\\nした姿。本来の役目も忘れ、冒険者を混沌へと\\n導く水先案内人と化す。\\n\\n・ユニオンバーストは、敵全体に魔法大ダメージ\\n\u3000を与え、さらに行動速度を中ダウン、魔法防御\\n\u3000力を中ダウンさせる。このスキルの状態異常は\\n\u3000ダメージを無効化しても付与される。\\n・自分の魔法攻撃力を中アップ、行動速度を大\\n\u3000アップさせる。\\n・向かって左側のターゲットのブレイク時、\\n\u3000物理/魔法防御力が中ダウン。\\n・中央下部のターゲットのブレイク時、\\n\u3000物理/魔法防御力が大ダウン。\\n・中央上部のターゲットのブレイク時、\\n\u3000物理/魔法防御力が大ダウン。\\n・向かって右側のターゲットのブレイク時、\\n\u3000物理/魔法防御力が特大ダウン。', 313102, 0, 2, 313100, 270, 0, 0, 16, 0, 1.4, 3000, 'バースト・タイムラーベ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【魔法】ホマレ所蔵の魔道具が、臨界を超え暴走\\nした姿。本来の役目も忘れ、冒険者を混沌へと\\n導く水先案内人と化す。\\n\\n・ユニオンバーストは、敵全体に魔法大ダメージ\\n\u3000を与え、さらに行動速度を中ダウン、魔法防御\\n\u3000力を中ダウンさせる。このスキルの状態異常は\\n\u3000ダメージを無効化しても付与される。\\n・自分の魔法攻撃力を中アップ、行動速度を大\\n\u3000アップさせる。\\n・残り時間が25秒を切ると、自分のTPを大アッ\\n\u3000プさせ、さらに攻撃が激しく凶暴になる。\\n・向かって左側のターゲットのブレイク時、\\n\u3000物理/魔法防御力が中ダウン。\\n・中央下部のターゲットのブレイク時、\\n\u3000物理/魔法防御力が大ダウン。\\n・中央上部のターゲットのブレイク時、\\n\u3000物理/魔法防御力が大ダウン。\\n・向かって右側のターゲットのブレイク時、\\n\u3000物理/魔法防御力が特大ダウン。', 313103, 0, 2, 313100, 270, 0, 0, 16, 0, 1.4, 3000, 'バースト・タイムラーベ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ１】暴走した魔道具は、すべてのもの\\nを自身の領域に留めようとする。幾重もの障壁に\\nも屈せず、己を信じ未来を切り拓け。\\n\\n・このバトルでは、全てのターゲットがブレイク\\n\u3000無効。\\n・バリアを張り、敵の攻撃を受け付けなくなる。\\n\u3000バリアはダメージを与えるたびに徐々に耐久性\\n\u3000を失っていき、一定量のダメージを与えるとバ\\n\u3000リアは破壊される。\\n・ユニオンバーストは、敵全体に魔法大ダメージ\\n\u3000を与え、さらに行動速度を中ダウン、魔法防御\\n\u3000力を中ダウンさせる。\\n\u3000このスキルの状態異常はダメージを無効化して\\n\u3000も付与される。\\n・自分の魔法攻撃力を中アップ、行動速度を大\\n\u3000アップさせる。', 313104, 0, 2, 313104, 270, 0, 0, 16, 0, 1.4, 3000, 'バースト・タイムラーベ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ２】イノリとカヤのシャドウを召喚。\\n自身の「もしも」の姿に二人は何を見るのか。\\n虚構を打ち破り己の道筋の正しさを証明する時。\\n\\n・このバトルでは、全てのターゲットがブレイク\\n\u3000無効。\\n・自分の魔法攻撃力を中アップ、行動速度を大\\n\u3000アップさせる。', 313105, 0, 2, 313100, 270, 0, 0, 16, 0, 1.4, 3000, 'バースト・タイムラーベ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ３】主を失った魔道具はコントロール\\nを失い、暴走を続ける。降り注ぐ絶望に抗い続け\\nれば、一筋の希望の光の道が開かれん。\\n\\n・ユニオンバーストは、敵全体に魔法大ダメージ\\n\u3000を与え、さらに行動速度を中ダウン、魔法防御\\n\u3000力を中ダウンさせる。\\n\u3000このスキルの状態異常はダメージを無効化して\\n\u3000も付与される。\\n・自分の魔法攻撃力を中アップ、行動速度を大\\n\u3000アップさせる。\\n・残り時間が25秒を切ると、自分のTPを大アッ\\n\u3000プさせ、さらに攻撃が激しく凶暴になる。\\n・向かって左側のターゲットのブレイク時、\\n\u3000物理/魔法防御力が中ダウン。\\n・中央下部のターゲットのブレイク時、\\n\u3000物理/魔法防御力が大ダウン。\\n・中央上部のターゲットのブレイク時、\\n\u3000物理/魔法防御力が大ダウン。\\n・向かって右側のターゲットのブレイク時、\\n\u3000物理/魔法防御力が特大ダウン。', 313106, 0, 2, 313100, 270, 0, 0, 16, 0, 0.8, 3000, 'バースト・タイムラーベ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('', 313200, 0, 1, 313200, 270, 0, 0, 16, 0, 2.0, 3000, '名もなき芸術');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】制作者の深淵が表出した？異形の芸術\\n作品の魔物。その風貌は常人の尺度では到底理解\\n不能で、分かる人には分かる、とは制作者の談。\\n\\n・ユニオンバーストは、敵全体にキャラの最大\\n\u3000ＨＰに応じた魔法割合ダメージを与える。\\n\u3000さらに、キャラのＨＰが50％未満の場合、\\n\u3000火傷状態にする。\\n\u3000このスキルの状態異常はダメージを無効化して\\n\u3000も付与される。\\n\u3000このスキルにより付与された火傷のダメージ\\n\u3000では、ＴＰがアップしない。\\n・前から３番目のキャラを中心とした範囲に、\\n\u3000最大ＨＰに応じた物理割合ダメージを与える。\\n\u3000さらに、火傷状態のキャラには追加で最大\\n\u3000ＨＰに応じた物理割合ダメージを与える。', 313201, 0, 1, 313200, 270, 0, 0, 16, 0, 2.0, 3000, '名もなき芸術');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】制作者の深淵が表出した？異形の芸術\\n作品の魔物。その風貌は常人の尺度では到底理解\\n不能で、分かる人には分かる、とは制作者の談。\\n\\n・ユニオンバーストは、敵全体にキャラの最大\\n\u3000ＨＰに応じた魔法割合ダメージを与える。\\n\u3000さらに、キャラのＨＰが50％未満の場合、\\n\u3000火傷状態にする。\\n\u3000このスキルの状態異常はダメージを無効化して\\n\u3000も付与される。\\n\u3000このスキルにより付与された火傷のダメージ\\n\u3000では、ＴＰがアップしない。\\n・前から３番目のキャラを中心とした範囲に、\\n\u3000最大ＨＰに応じた物理割合ダメージを与える。\\n\u3000さらに、火傷状態のキャラには追加で最大\\n\u3000ＨＰに応じた物理割合ダメージを与える。', 313202, 0, 1, 313200, 270, 0, 0, 16, 0, 2.0, 3000, '名もなき芸術');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】制作者の深淵が表出した？異形の芸術\\n作品の魔物。その風貌は常人の尺度では到底理解\\n不能で、分かる人には分かる、とは制作者の談。\\n\\n・ユニオンバーストは、敵全体にキャラの最大\\n\u3000ＨＰに応じた魔法割合ダメージを与える。\\n\u3000さらに、キャラのＨＰが50％未満の場合、\\n\u3000火傷状態にする。\\n\u3000このスキルの状態異常はダメージを無効化して\\n\u3000も付与される。\\n\u3000このスキルにより付与された火傷のダメージ\\n\u3000では、ＴＰがアップしない。\\n・前から３番目のキャラを中心とした範囲に、\\n\u3000最大ＨＰに応じた物理割合ダメージを与える。\\n\u3000さらに、火傷状態のキャラには追加で最大\\n\u3000ＨＰに応じた物理割合ダメージを与える。\\n・残り時間が30秒を切ると、自分のＴＰを\\n\u3000小アップさせ、さらに攻撃が激しく凶暴になる。', 313203, 0, 1, 313200, 270, 0, 0, 16, 0, 2.0, 3000, '名もなき芸術');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ１】命を宿した粘土人形は止まらない。\\n内なる異形の魔力を放出し、繰り出される光線に\\n少女たちは、レジスト済みの校舎は耐えられるか？\\n\\n・ユニオンバーストは、敵全体にキャラの最大\\n\u3000ＨＰに応じた魔法割合ダメージを与える。\\n\u3000さらに、キャラのＨＰが50％未満の場合、\\n\u3000火傷状態にする。\\n\u3000このスキルの状態異常はダメージを無効化して\\n\u3000も付与される。\\n\u3000このスキルにより付与された火傷のダメージ\\n\u3000では、ＴＰがアップしない。\\n・前方範囲内の敵のバリアを解除し、最大ＨＰに\\n\u3000応じた魔法割合ダメージを与える。\\n\u3000さらに、束縛状態にする。\\n\u3000ただし、名もなき芸術が毒、猛毒、呪い、火傷、\\n\u3000呪詛の効果を受けている場合、束縛は付与\\n\u3000されない。\\n・自分が毒、猛毒、呪い、火傷、呪詛の効果を\\n\u3000受けると、自分の物理・魔法防御力が特大\\n\u3000ダウンする。', 313204, 0, 1, 313200, 270, 0, 0, 16, 0, 2.0, 3000, '名もなき芸術');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ２】粘土人形が描くはこれまた独創的\\nなデザインの魔法陣。そのビジュアルに騙される\\nことなかれ、気を抜けば一瞬にしてぺしゃんこに。\\n\\n・ユニオンバーストは、敵全体にキャラの最大\\n\u3000ＨＰに応じた魔法割合ダメージを与える。\\n\u3000さらに、キャラのＨＰが50％未満の場合、\\n\u3000火傷状態にする。\\n\u3000このスキルの状態異常はダメージを無効化して\\n\u3000も付与される。\\n\u3000このスキルにより付与された火傷のダメージ\\n\u3000では、ＴＰがアップしない。\\n・通常攻撃は、前方１キャラに物理中ダメージを\\n\u3000与える。\\n\u3000名もなき芸術が保持している【せんす】の数が\\n\u3000多いほどダメージがアップする。\\n・前から３番目のキャラを中心とした範囲に\\n\u3000物理中ダメージを与える。\\n\u3000名もなき芸術が保持している【せんす】の数が\\n\u3000多いほどダメージがアップする。\\n・バトル開始時、魔法陣を展開する。\\n\\n【魔法陣効果】\\n・名もなき芸術に毎秒【せんす】を３つ追加する。\\n・名もなき芸術がダメージを受けるたびに\\n\u3000名もなき芸術の【せんす】を１つ減少させる。', 313205, 0, 1, 313200, 270, 0, 0, 16, 0, 2.0, 3000, '名もなき芸術');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ３】残された力を振り絞り、最期の狂\\n気をまき散らす粘土人形。彼女らの輝かしい学生\\n生活は守れるのか。立ち向かえ、なかよし部！\\n\\n・ユニオンバーストは、敵全体にキャラの最大\\n\u3000ＨＰに応じた魔法割合ダメージを与える。\\n\u3000さらに、キャラのＨＰが50％未満の場合、\\n\u3000火傷状態にする。\\n\u3000このスキルの状態異常はダメージを無効化して\\n\u3000も付与される。\\n\u3000このスキルにより付与された火傷のダメージ\\n\u3000では、ＴＰがアップしない。\\n・前から３番目のキャラを中心とした範囲に、\\n\u3000最大ＨＰに応じた物理割合ダメージを与える。\\n\u3000さらに、火傷状態のキャラには追加で最大\\n\u3000ＨＰに応じた物理割合ダメージを与える。\\n・残り時間が30秒を切ると、自分のＴＰを\\n\u3000大アップさせ、さらに攻撃が激しく凶暴になる。', 313206, 0, 1, 313200, 270, 0, 0, 16, 0, 2.0, 3000, '名もなき芸術');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('', 313300, 0, 1, 313300, 270, 0, 0, 16, 0, 3.0, 3000, '究極玩具王 メガトイキング');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】忘れられ暴走する悲しき玩具の王さま。\\n三度、子供たちに忘れられる、恐怖と悲しみに\\n震える。さぁ！今こそＢＢ団の立ち上がるとき！\\n\\n・ユニオンバーストは、敵全体にキャラの最大\\n\u3000ＨＰに応じた物理割合ダメージを与え、最も\\n\u3000近い敵１キャラの物理攻撃力と魔法攻撃力を\\n\u3000特大ダウン。このスキルの効果はダメージを\\n\u3000無効化しても付与される。\\n・最も近い敵１キャラにキャラの最大ＨＰに\\n\u3000応じた物理割合ダメージを与える。\\n・物理攻撃力、魔法攻撃力いずれかで、攻撃力\\n\u3000が高い２キャラにキャラの最大ＨＰに応じた\\n\u3000物理割合ダメージを与える。', 313301, 0, 1, 313300, 270, 0, 0, 16, 0, 3.0, 3000, '究極玩具王 メガトイキング');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】忘れられ暴走する悲しき玩具の王さま。\\n三度、子供たちに忘れられる、恐怖と悲しみに\\n震える。さぁ！今こそＢＢ団の立ち上がるとき！\\n\\n・ユニオンバーストは、敵全体にキャラの最大\\n\u3000ＨＰに応じた物理割合ダメージを与え、最も\\n\u3000近い敵１キャラの物理攻撃力と魔法攻撃力を\\n\u3000特大ダウン。このスキルの効果はダメージを\\n\u3000無効化しても付与される。\\n・最も近い敵１キャラにキャラの最大ＨＰに\\n\u3000応じた物理割合ダメージを与える。\\n・物理攻撃力、魔法攻撃力いずれかで、攻撃力\\n\u3000が高い２キャラにキャラの最大ＨＰに応じた\\n\u3000物理割合ダメージを与える。', 313302, 0, 1, 313300, 270, 0, 0, 16, 0, 3.0, 3000, '究極玩具王 メガトイキング');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】忘れられ暴走する悲しき玩具の王さま。\\n三度、子供たちに忘れられる、恐怖と悲しみに\\n震える。さぁ！今こそＢＢ団の立ち上がるとき！\\n\\n・究極玩具王 メガトイキング自身のＨＰが40％\\n\u3000を切ると両腕が輝き出し、攻撃が激しく凶暴\\n\u3000になる。\\n・ユニオンバーストは、敵全体にキャラの最大\\n\u3000ＨＰに応じた物理割合ダメージを与え、最も\\n\u3000近い敵１キャラの物理攻撃力と魔法攻撃力を\\n\u3000特大ダウン。このスキルの効果はダメージを\\n\u3000無効化しても付与される。両腕が輝いている\\n\u3000場合、ダメージがアップし、さらに最も近い\\n\u3000敵１キャラに物理大ダメージを与える。\\n・最も近い敵１キャラにキャラの最大ＨＰに応\\n\u3000じた物理割合ダメージを与える。両腕が輝い\\n\u3000ている場合、ダメージがアップし、このスキ\\n\u3000ルによるダメージではＴＰが回復しない。\\n・物理攻撃力、魔法攻撃力いずれかで、攻撃力\\n\u3000が高い２キャラにキャラの最大ＨＰに応じた\\n\u3000物理割合ダメージを与える。両腕が輝いてい\\n\u3000る場合、このスキルによるダメージではＴＰ\\n\u3000が回復しない。', 313303, 0, 1, 313300, 270, 0, 0, 16, 0, 3.0, 3000, '究極玩具王 メガトイキング');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ１】暴走する友の前に小さきヒーロー\\nが立ちはだかる。彼を悲しみから救い出せるか？\\nマイフレくんと共にさぁ立ち向かえ、ＢＢ団！\\n\\n・ユニオンバーストは、敵全体にキャラの最大\\n\u3000ＨＰに応じた物理割合ダメージを与え、目の\\n\u3000前の敵１キャラの物理攻撃力と魔法攻撃力を\\n\u3000特大ダウン。\\n\u3000このスキルの効果はダメージを無効化しても\\n\u3000付与される。\\n・目の前の敵１キャラにキャラの最大ＨＰに\\n\u3000応じた物理割合ダメージを与える。\\n・物理攻撃力、魔法攻撃力いずれかで、攻撃力\\n\u3000が高い２キャラに最大ＨＰに応じた物理割合\\n\u3000ダメージを与える。\\n・マイフレンドくんがキャラの味方として一定\\n\u3000時間現れ、究極玩具王 メガトイキングが行動\\n\u3000不能になる。\\n\u3000さらにマイフレンドくんを中心に、範囲内の\\n\u3000キャラの物理攻撃力と物理クリティカルと\\n\u3000ＴＰ上昇を特大アップさせるフィールドを\\n\u3000展開する。', 313304, 0, 1, 313300, 270, 0, 0, 16, 0, 3.0, 3000, '究極玩具王 メガトイキング');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ２】悲しき玩具王がみせる虚像。自分\\n自身と向き合うのは怖いもの。一人じゃない！\\nそんな強い思いを胸に、負けるな、ＢＢ団！\\n\\n・アオイ、ミフユ、タマキのシャドウを召喚。\\n・目の前の敵１キャラにキャラの最大ＨＰに\\n\u3000応じた物理割合ダメージを与える。', 313305, 0, 1, 313305, 270, 0, 0, 16, 0, 3.0, 3000, '究極玩具王 メガトイキング');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ３】悲しき玩具王の最後の抵抗。\\n忘却の寂しさに支配された力は破滅的で強大。\\n友を思う気持ちを力に変え、救い出せ、ＢＢ団！\\n\\n・究極玩具王 メガトイキング自身のＨＰが15％\\n\u3000を切ると両腕が輝き出す。物理防御力と魔法\\n\u3000防御力が特大ダウンし、攻撃が激しく凶暴に\\n\u3000なる。\\n・ユニオンバーストは、敵全体にキャラの最大\\n\u3000ＨＰに応じた物理割合ダメージを与え、目の\\n\u3000前の敵１キャラの物理攻撃力と魔法攻撃力を\\n\u3000特大ダウン。\\n\u3000このスキルの効果はダメージを無効化しても\\n\u3000付与される。\\n\u3000両腕が輝いている場合、ダメージがアップし、\\n\u3000さらに目の前の敵１キャラに物理大ダメージ\\n\u3000を与える。\\n・目の前の敵１キャラにキャラの最大ＨＰに\\n\u3000応じた物理割合ダメージを与える。\\n\u3000両腕が輝いている場合、ダメージがアップし、\\n\u3000このスキルによるダメージではＴＰが回復し\\n\u3000ない。\\n・物理攻撃力、魔法攻撃力いずれかで、攻撃力\\n\u3000が高い２キャラに最大ＨＰに応じた物理割合\\n\u3000ダメージを与える。\\n\u3000両腕が輝いている場合、このスキルによる\\n\u3000ダメージではＴＰが回復しない。', 313306, 0, 1, 313300, 270, 0, 0, 16, 0, 3.0, 3000, '究極玩具王 メガトイキング');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】紅き邪剣を尾に宿す、凶暴な大毒蛇。\\n獲物を毒息で弱らせ、一撃必殺の剣で葬り去る。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・ソードコブラから受けるすべてのダメージで発\\n\u3000生する、パーティキャラのＴＰ回復量を中ダウ\\n\u3000ンさせる。\\n・ユニオンバーストは、物理攻撃力、魔法攻撃力\\n\u3000いずれかで、最も攻撃力が高い敵１キャラに物\\n\u3000理固定ダメージを与える。毒状態の場合はさら\\n\u3000に追加の物理固定ダメージを与える。その後、\\n\u3000敵全体のＨＰ吸収を特大ダウンさせる。このス\\n\u3000キルの状態異常はダメージを無効化しても付与\\n\u3000される。\\n・敵全体に魔法中ダメージを与え、毒状態を付与\\n\u3000する。このスキルの状態異常はダメージを無効\\n\u3000化しても付与される。\\n・通常攻撃は最も近い敵１キャラに物理大ダメー\\n\u3000ジを与え、毒状態を付与する。\\n・ソードコブラの付与する毒のダメージでは、\\n\u3000ＴＰが回復しない。', 313400, 0, 1, 313400, 270, 0, 0, 16, 0, 3.0, 3000, 'ソードコブラ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】紅き邪剣を尾に宿す、凶暴な大毒蛇。\\n獲物を毒息で弱らせ、一撃必殺の剣で葬り去る。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を中アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・バトル開始時、敵全体のＴＰ上昇を小ダウンさ\\n\u3000せるフィールドを展開する。\\n・バトル開始時、自身にＴＰダウン25％カット\\n\u3000効果を付与する。\\n・ソードコブラから受けるすべてのダメージで発\\n\u3000生する、パーティキャラのＴＰ回復量を中ダウ\\n\u3000ンさせる。\\n・敵から受けるすべてのダメージで発生する、\\n\u3000ソードコブラのＴＰ回復量が大ダウンする。\\n・ユニオンバーストは、物理攻撃力、魔法攻撃力\\n\u3000いずれかで、最も攻撃力が高い敵１キャラに物\\n\u3000理固定ダメージを与える。毒状態の場合はさら\\n\u3000に追加の物理固定ダメージを与える。その後、\\n\u3000敵全体のＨＰ吸収を特大ダウンさせる。このス\\n\u3000キルの状態異常はダメージを無効化しても付与\\n\u3000される。このスキルを使用した後、敵を攻撃す\\n\u3000るたび、以降その敵にソードコブラが与えるダ\\n\u3000メージがアップする。この効果は最大１回まで\\n\u3000累積する。\\n・敵全体に魔法中ダメージを与え、毒状態を付与\\n\u3000する。このスキルの状態異常はダメージを無効\\n\u3000化しても付与される。\\n・通常攻撃は最も近い敵１キャラに物理大ダメー\\n\u3000ジを与え、毒状態を付与する。\\n・ソードコブラの付与する毒のダメージでは、\\n\u3000ＴＰが回復しない。', 313401, 0, 1, 313401, 270, 0, 0, 16, 0, 3.0, 3000, 'ソードコブラ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】紅き邪剣を尾に宿す、凶暴な大毒蛇。\\n獲物を毒息で弱らせ、一撃必殺の剣で葬り去る。\\n\\n・ソードコブラから受けるすべてのダメージで発\\n\u3000生する、パーティキャラのＴＰ回復量を中ダウ\\n\u3000ンさせる。\\n・ユニオンバーストは、物理攻撃力、魔法攻撃力\\n\u3000いずれかで、最も攻撃力が高い敵１キャラに物\\n\u3000理固定ダメージを与える。毒状態の場合は追加\\n\u3000の物理固定ダメージを与え、猛毒状態の場合は\\n\u3000さらに追加の物理固定ダメージを与える。その\\n\u3000後、敵全体のＨＰ吸収を特大ダウンさせる。こ\\n\u3000のスキルの状態異常はダメージを無効化しても\\n\u3000付与される。\\n・敵全体に魔法中ダメージを与える。さらに毒状\\n\u3000態ではない場合は毒状態を付与し、毒状態の場\\n\u3000合は猛毒状態を付与する。\\n・通常攻撃は最も近い敵１キャラに物理大ダメー\\n\u3000ジを与え、毒状態を付与する。\\n・ソードコブラの付与する毒のダメージでは、\\n\u3000ＴＰが回復しない。', 313402, 0, 1, 313402, 270, 0, 0, 16, 0, 3.0, 3000, 'ソードコブラ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('魔物を意のままに操り、強化する辣鞭の少年。\\n赤青黄のスライムを従え、機敏なる猛攻を行う。\\n\\n・ユニオンバーストは、前方範囲内の敵にカリザ\\n\u3000の物理攻撃力に応じた物理割合ダメージを与え\\n\u3000る。\\n・カリザの物理攻撃力を大アップ。\\n・前から１番目のキャラにカリザの物理攻撃力に\\n\u3000応じた物理割合ダメージを与える。', 313500, 0, 1, 313500, 270, 0, 0, 16, 0, 2.0, 3000, 'カリザ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('魔物を意のままに操り、強化する辣鞭の少年。\\n赤青黄のスライムを従え、機敏なる猛攻を行う。\\n\\n・ユニオンバーストは、前方範囲内の敵にカリザ\\n\u3000の物理攻撃力に応じた物理割合ダメージを与え\\n\u3000る。\\n・カリザの物理攻撃力を大アップ。\\n・前から１番目のキャラにカリザの物理攻撃力に\\n\u3000応じた物理割合ダメージを与える。', 313501, 0, 1, 313501, 270, 0, 0, 16, 0, 2.0, 3000, 'カリザ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('天稟の才と過敏な感覚に懊悩する、幽寂の歌姫。\\n争いは好まないが、願いと仲間のため奮戦する。\\n\\n・ユニオンバーストは、前方範囲内の敵に魔法中\\n\u3000ダメージを与え、結晶化状態にする。\\n\u3000このスキルの状態異常はダメージを無効化して\\n\u3000も付与される。\\n\u3000結晶化状態では行動不能になり、継続ダメージ\\n\u3000を受ける。\\n\u3000結晶化状態はＨＰが全回復するか、一定時間経\\n\u3000過すると解除される。\\n・前方範囲内の敵に猛毒状態を付与する。\\n\u3000結晶化状態の敵には追加の魔法大ダメージを与\\n\u3000える。\\n・前から１番目のキャラに魔法小ダメージ。', 313600, 0, 2, 313600, 270, 0, 0, 16, 0, 3.0, 3001, 'ランファ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('天稟の才と過敏な感覚に懊悩する、幽寂の歌姫。\\n争いは好まないが、願いと仲間のため奮戦する。\\n\\n・ユニオンバーストは、前方範囲内の敵に魔法中\\n\u3000ダメージを与え、結晶化状態にする。\\n\u3000このスキルの状態異常はダメージを無効化して\\n\u3000も付与される。\\n\u3000結晶化状態では行動不能になり、継続ダメージ\\n\u3000を受ける。\\n\u3000結晶化状態はＨＰが全回復するか、一定時間経\\n\u3000過すると解除される。\\n・前方範囲内の敵に猛毒状態を付与する。\\n\u3000結晶化状態の敵には追加の魔法大ダメージを与\\n\u3000える。\\n・前から１番目のキャラに魔法小ダメージ。', 313601, 0, 2, 313601, 270, 0, 0, 16, 0, 3.0, 3001, 'ランファ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('常に明朗快活、誰とでも友達になれる溌溂少女。\\n回転式銃を愛用し、単独で飽和攻撃を仕掛ける。\\n\\n・バトル開始時、ぺんぽこりんを召喚する。\\n\u3000召喚時、前方範囲内の敵全てをノックバックす\\n\u3000る。\\n\u3000ぺんぽこりんは前から２キャラに物理大ダメー\\n\u3000ジを与える。\\n・ユニオンバーストは、敵全体に物理割合ダメー\\n\u3000ジを与える。\\n\u3000さらに、ぺんぽこりんの物理攻撃力と行動速度\\n\u3000を大アップ。\\n・ぺんぽこりんのＨＰを回復する。\\n・前から１番目のキャラに物理小ダメージを与え\\n\u3000る。', 313700, 0, 1, 313700, 270, 0, 0, 16, 0, 2.0, 3000, 'ミソラ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('常に明朗快活、誰とでも友達になれる溌溂少女。\\n回転式銃を愛用し、単独で飽和攻撃を仕掛ける。\\n\\n・バトル開始時、ぺんぽこりんを召喚する。\\n\u3000召喚時、前方範囲内の敵全てをノックバックす\\n\u3000る。\\n\u3000ぺんぽこりんは前から２キャラに物理大ダメー\\n\u3000ジを与える。\\n・ユニオンバーストは、敵全体に物理割合ダメー\\n\u3000ジを与える。\\n\u3000さらに、ぺんぽこりんの物理攻撃力と行動速度\\n\u3000を大アップ。\\n\u3000このスキルによるダメージでは、ＴＰ回復量は\\n\u3000減少する。\\n・ぺんぽこりんのＨＰを回復する。\\n・前から１番目のキャラに物理小ダメージを与え\\n\u3000る。', 313701, 0, 1, 313701, 270, 0, 0, 16, 0, 2.0, 3000, 'ミソラ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【魔法】ミソラクエスト最後の関門。「退治でき\\nなかったら…ぜーんいん。ミナゴロシです♪」\\n\\n・ユニオンバーストは、敵全体にキャラの最大\\n\u3000ＨＰに応じた魔法割合ダメージを与える。\\n・前から１番目、２番目、３番目の敵に魔法小ダ\\n\u3000メージを与える。\\n・敵全体の魔法防御力を中ダウンさせ、火傷状態\\n\u3000を付与する。敵のＨＰが50％未満の場合、混\\n\u3000乱状態を付与する。', 313702, 0, 2, 313702, 270, 0, 0, 16, 0, 2.0, 3000, 'ミソラ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【魔法】ミソラクエスト最後の関門。「退治でき\\nなかったら…ぜーんいん。ミナゴロシです♪」\\n\\n・ユニオンバーストは、敵全体にキャラの最大\\n\u3000ＨＰに応じた魔法割合ダメージを与える。\\n・前から１番目、２番目、３番目の敵に魔法小ダ\\n\u3000メージを与える。\\n・敵全体の魔法防御力を中ダウンさせ、火傷状態\\n\u3000を付与する。敵のＨＰが50％未満の場合、混\\n\u3000乱状態を付与する。', 313703, 0, 2, 313702, 270, 0, 0, 16, 0, 2.0, 3000, 'ミソラ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【魔法】ミソラクエスト最後の関門。「退治でき\\nなかったら…ぜーんいん。ミナゴロシです♪」\\n\\n・ユニオンバーストは、敵全体にキャラの最大\\n\u3000ＨＰに応じた魔法割合ダメージを与える。\\n・前から１番目、２番目、３番目の敵に魔法小ダ\\n\u3000メージを与える。\\n・敵全体の魔法防御力を中ダウンさせ、火傷状態\\n\u3000を付与する。敵のＨＰが50％未満の場合、混\\n\u3000乱状態を付与する。', 313704, 0, 2, 313702, 270, 0, 0, 16, 0, 2.0, 3000, 'ミソラ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ１】蝦蟇口から召喚されしは狂気なる\\nぬいぐるみ。その不気味な躯体は、ミソラの盾に\\nも矛にも成り得る。「ゴーゴー、ぺんぽこりん★」\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・バトル開始時、ぺんぽこりんを召喚する。召喚\\n\u3000時、敵全体をノックバックする。\\n\u3000ぺんぽこりんは前から２キャラに物理大ダメー\\n\u3000ジを与える。\\n・ミソラから受けるすべてのダメージで発生する、\\n\u3000パーティキャラのＴＰ回復量を中ダウンさせる。\\n・ユニオンバーストは、敵全体にキャラの最大\\n\u3000ＨＰに応じた魔法割合ダメージを与える。さら\\n\u3000に、ぺんぽこりんの物理攻撃力と行動速度を\\n\u3000大アップさせる。\\n・ぺんぽこりんのＨＰを小回復する。\\n・前から１番目、２番目、３番目の敵に魔法小ダ\\n\u3000メージを与える。', 313705, 0, 2, 313705, 270, 0, 0, 16, 0, 2.0, 3000, 'ミソラ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ２】現れたのはリリ達のシャドウ。\\n降りかかる刃が、忌まわしき過去との対峙を迫る。\\nだが打ち克たなければ、前には進めない…！\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を中アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・ミソラから受けるすべてのダメージで発生する、\\n\u3000パーティキャラのＴＰ回復量を中ダウンさせる。\\n・前から１番目、２番目、３番目の敵に魔法小ダ\\n\u3000メージを与える。', 313706, 0, 2, 313706, 270, 0, 0, 16, 0, 2.0, 3000, 'ミソラ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ３】戦いを止められるのは黒い天使\\nのみ。大切なものを守るため、冒険者として踏み\\n出すため…その迷いなき翼で巨悪を薙ぎ払え！\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を中アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・ミソラから受けるすべてのダメージで発生する、\\n\u3000パーティキャラのＴＰ回復量を中ダウンさせる。\\n・ユニオンバーストは、敵全体にキャラの最大\\n\u3000ＨＰに応じた魔法割合ダメージを与える。\\n・前から１番目、２番目、３番目の敵に魔法小ダ\\n\u3000メージを与える。\\n・敵全体の魔法防御力を中ダウンさせ、火傷状態\\n\u3000を付与する。敵のＨＰが50％未満の場合、混\\n\u3000乱状態を付与する。このスキルにより付与され\\n\u3000た火傷のダメージでは、ＴＰが回復しない。', 313707, 0, 2, 313705, 270, 0, 0, 16, 0, 2.0, 3000, 'ミソラ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('常に幾つもの奥の手を隠し持つ、大食の紳士。\\n万能人形を駆使し、知略戦略で敵を追い詰める。\\n\\n・ユニオンバーストは、敵全体にアゾールドの物\\n\u3000理攻撃力に応じた物理割合ダメージを与える。\\n\u3000さらに、アゾールドの物理防御力と魔法防御力\\n\u3000を大ダウン。\\n・万能人形を召喚し敵全体をノックバックさせる。\\n\u3000万能人形は前から１番目のキャラに物理小ダメー\\n\u3000ジを与える。\\n\u3000万能人形のＨＰが一定値以下になった時、アゾー\\n\u3000ルドの物理防御力と魔法防御力を大ダウンさせ\\n\u3000る。\\n・前から１番目のキャラに物理小ダメージ。', 313800, 0, 1, 313800, 270, 0, 0, 16, 0, 1.5, 3000, 'アゾールド');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('常に幾つもの奥の手を隠し持つ、大食の紳士。\\n万能人形を駆使し、知略戦略で敵を追い詰める。\\n\\n・ユニオンバーストは、敵全体にアゾールドの物\\n\u3000理攻撃力に応じた物理割合ダメージを与える。\\n\u3000さらに、アゾールドの物理防御力と魔法防御力\\n\u3000を大ダウン。\\n・万能人形を召喚し敵全体をノックバックさせる。\\n\u3000万能人形は前から１番目のキャラに物理小ダメー\\n\u3000ジを与える。\\n\u3000万能人形のＨＰが一定値以下になった時、アゾー\\n\u3000ルドの物理防御力と魔法防御力を大ダウンさせ\\n\u3000る。\\n・前から１番目のキャラに物理小ダメージ。', 313801, 0, 1, 313801, 270, 0, 0, 16, 0, 1.5, 3000, 'アゾールド');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('一騎当千、万夫不当の実力を揮う寡黙な剣士。\\n覚醒することで、龍は更なる高みへと昇る。\\n\\n・ユニオンバーストは、敵全体にゼーンの物理\\n\u3000攻撃力と残りＨＰに応じた物理割合ダメージ\\n\u3000を与える。\\n\u3000このスキルによるダメージでは、ＴＰ回復量\\n\u3000は減少する。\\n・敵全体に物理中ダメージを与え、スタンさせ\\n\u3000る。\\n・ゼーンのＴＰ上昇、行動速度、物理攻撃力を\\n\u3000大アップ。\\n\u3000このスキルの効果は発動するたびにアップす\\n\u3000る。\\n\u3000３回目の発動時は、さらにＴＰ1000アップ。\\n・前から１番目のキャラに物理中ダメージを与\\n\u3000え、小さく吹き飛ばす。', 313900, 0, 1, 313900, 270, 313900, 0, 16, 313900, 1.0, 3000, 'ゼーン');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('', 313901, 0, 1, 313901, 270, 313900, 0, 16, 313900, 1.0, 3000, 'ゼーン');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('', 314000, 0, 1, 314000, 270, 0, 0, 16, 0, 1.0, 3000, '宿題');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('まずは手始めに得意な宿題を終わらせよう。\\nここでつまづいてはいられない。夏休みの宿題は\\nほかにもまだまだあるぞ！！\\n\\n・バトル開始後、大量の宿題が降り注ぎ、\\n\u3000敵全体に物理中ダメージ。このスキル\\n\u3000によるダメージでは、キャラのＴＰが\\n\u3000回復しない。\\n・バトル中、一定時間が経過するごとに\\n\u3000モンスターが押し寄せてくる。', 314001, 0, 1, 314001, 270, 0, 0, 16, 0, 1.0, 3000, '得意な宿題');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('誰にでもある苦手科目の宿題。ついつい後回しに\\nしがちで、溜まってしまうとなかなか大変。\\nここで立ち止まるわけにはいかないぞ！\\n\\n・バトル開始後、大量の宿題が降り注ぎ、\\n\u3000敵全体に物理中ダメージ。このスキル\\n\u3000によるダメージでは、キャラのＴＰが\\n\u3000回復しない。\\n・バトル中、一定時間が経過するごとに\\n\u3000モンスターが押し寄せてくる。', 314002, 0, 1, 314002, 270, 0, 0, 16, 0, 1.0, 3000, 'ちょっと苦手な宿題');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('眺めているだけで眩暈のするいや～な宿題。\\nペンを置いて外に飛び出したくなる衝動を耐え、\\nコツコツ進めていくことが攻略のカギ！\\n\\n・バトル開始後、大量の宿題が降り注ぎ、\\n\u3000敵全体に物理中ダメージ。このスキル\\n\u3000によるダメージでは、キャラのＴＰが\\n\u3000回復しない。\\n・バトル中、一定時間が経過するごとに\\n\u3000モンスターが押し寄せてくる。', 314003, 0, 1, 314003, 270, 0, 0, 16, 0, 1.0, 3000, 'すごく苦手な宿題');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('SP MODE1', 314004, 0, 1, 314004, 270, 0, 0, 16, 0, 1.0, 3000, '夏休み最後まで残りし宿題');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('SP MODE2', 314005, 0, 1, 314005, 270, 0, 0, 16, 0, 1.0, 3000, '夏休み最後まで残りし宿題');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('夏休みの間ずっと、目を背けてきた最後の宿題。\\nここまで放置してきた後悔が一気に襲い掛かる。\\nすべてやり遂げて笑顔で登校できるか！？\\n\\n・バトル開始後、大量の宿題が降り注ぎ、\\n\u3000敵全体に物理中ダメージ。\\n・バトル中、一定時間が経過するごとに\\n\u3000モンスターが押し寄せてくる。', 314006, 0, 1, 314006, 270, 0, 0, 16, 0, 1.0, 3000, '夏休み最後まで残りし宿題');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('', 314100, 0, 2, 314100, 270, 0, 0, 16, 0, 1.6, 3000, 'クイーンウタクラゲ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【魔法】華のように大海をゆらめき、歌声を奏で\\nるウタクラゲの女王。美しく飾られたその姿の内\\nには猛毒の体液を隠し持つ。\\n\\n・ユニオンバーストは、敵全体にキャラの最大Ｈ\\n\u3000Ｐに応じた魔法割合ダメージを与える。猛毒状\\n\u3000態の敵には追加で最大ＨＰに応じた魔法割合ダ\\n\u3000メージを与える。さらに敵全体に毒状態を付与\\n\u3000し、既に毒か猛毒状態の敵には猛毒状態を付与\\n\u3000する。\\n・最も近い敵１キャラに魔法大ダメージを与える。\\n・敵全体に魔法小ダメージを与え、毒状態を付与\\n\u3000する。敵が猛毒状態の場合、スタンさせる。\\n・クイーンウタクラゲの付与する毒および猛毒の\\n\u3000ダメージでは、キャラのＴＰが回復しない。', 314101, 0, 2, 314100, 270, 0, 0, 16, 0, 1.6, 3000, 'クイーンウタクラゲ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【魔法】華のように大海をゆらめき、歌声を奏で\\nるウタクラゲの女王。美しく飾られたその姿の内\\nには猛毒の体液を隠し持つ。\\n\\n・ユニオンバーストは、敵全体にキャラの最大Ｈ\\n\u3000Ｐに応じた魔法割合ダメージを与える。猛毒状\\n\u3000態の敵には追加で最大ＨＰに応じた魔法割合ダ\\n\u3000メージを与える。さらに敵全体に毒状態を付与\\n\u3000し、既に毒か猛毒状態の敵には猛毒状態を付与\\n\u3000する。\\n・最も近い敵１キャラに魔法大ダメージを与える。\\n・敵全体に魔法小ダメージを与え、毒状態を付与\\n\u3000する。敵が猛毒状態の場合、スタンさせる。\\n・クイーンウタクラゲの付与する毒および猛毒の\\n\u3000ダメージでは、キャラのＴＰが回復しない。', 314102, 0, 2, 314100, 270, 0, 0, 16, 0, 1.6, 3000, 'クイーンウタクラゲ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【魔法】華のように大海をゆらめき、歌声を奏で\\nるウタクラゲの女王。美しく飾られたその姿の内\\nには猛毒の体液を隠し持つ。\\n\\n・ユニオンバーストは、敵全体にキャラの最大Ｈ\\n\u3000Ｐに応じた魔法割合ダメージを与える。猛毒状\\n\u3000態の敵には追加で最大ＨＰに応じた魔法割合ダ\\n\u3000メージを与える。さらに敵全体に毒状態を付与\\n\u3000し、既に毒か猛毒状態の敵には猛毒状態を付与\\n\u3000する。\\n・最も近い敵１キャラに魔法大ダメージを与える。\\n・敵全体に魔法小ダメージを与え、毒状態を付与\\n\u3000する。敵が猛毒状態の場合、スタンさせる。\\n・クイーンウタクラゲの付与する毒および猛毒の\\n\u3000ダメージでは、キャラのＴＰが回復しない。\\n・残り時間が25秒を切ると、さらに攻撃が激し\\n\u3000く凶暴になる。', 314103, 0, 2, 314100, 270, 0, 0, 16, 0, 1.6, 3000, 'クイーンウタクラゲ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ１】襲い来る無数の魔物たち。その歌\\n声は轟然とこだまし舞台を脅かす。ファンの笑顔\\nを守るため、少女たちは歌い踊り、そして戦う。\\n\\n・バトル開始時に、ウタクラゲを３体召喚し\\n\u3000敵全体をノックバックさせる。\\n・ウタクラゲを１体倒すたびに、残りウタクラゲ\\n\u3000数が１減少する。\\n\u3000その後、ウタクラゲが再度召喚され、敵全体を\\n\u3000ノックバックさせる。\\n・ウタクラゲは、残りＨＰが最も高い敵１キャラ\\n\u3000に魔法中ダメージを与え、毒状態を付与する。\\n・ユニオンバーストは、敵全体にキャラのＨＰに\\n\u3000応じた魔法割合ダメージを与える。\\n\u3000猛毒状態の敵にはダメージがアップする。\\n\u3000さらに敵に毒状態を付与し、既に毒か猛毒状態\\n\u3000の敵には猛毒状態を付与する。\\n・目の前の敵１キャラに魔法大ダメージを与える。\\n・クイーンウタクラゲとウタクラゲの付与する毒\\n\u3000および猛毒のダメージでは、キャラのＴＰが回\\n\u3000復しない。', 314104, 0, 2, 314104, 270, 0, 0, 16, 0, 1.6, 3000, 'クイーンウタクラゲ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ２】目の前に現れたのは、過去の\\n自分たち。成長の果て、少女たちは過去を越え、\\nその一瞬一瞬の輝きを歌声に乗せる。\\n\\n・カルミナのシャドウを召喚。\\n・目の前の敵１キャラに魔法大ダメージを与える。', 314105, 0, 2, 314105, 270, 0, 0, 16, 0, 1.6, 3000, 'クイーンウタクラゲ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ３】優艶なる華は乱れ、内なる魔性\\nを解き放つ。劇毒の雨音をメロディーに、\\n歌姫は歌う――最期の歌を。\\n\\n・ユニオンバーストは、敵全体にキャラのＨＰに\\n\u3000応じた魔法割合ダメージを与える。\\n\u3000猛毒状態の敵にはダメージがアップする。\\n\u3000さらに敵に毒状態を付与し、既に毒か猛毒状態\\n\u3000の敵には猛毒状態を付与する。\\n・目の前の敵１キャラに魔法大ダメージを与える。\\n・敵全体に魔法小ダメージを与え、毒状態を付与\\n\u3000する。\\n\u3000敵が猛毒状態の場合、スタンさせる。\\n・クイーンウタクラゲの付与する毒および猛毒の\\n\u3000ダメージでは、キャラのＴＰが回復しない。\\n・残り時間が25秒を切ると、さらに攻撃が激し\\n\u3000く凶暴になる。', 314106, 0, 2, 314104, 270, 0, 0, 16, 0, 1.6, 3000, 'クイーンウタクラゲ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('', 314200, 0, 1, 314200, 270, 0, 0, 16, 0, 1.6, 3000, 'ドクターギグル');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】卑劣なる本性を現したオーエドの怪医。\\n研究で手にした究極の肉体で、世界への復讐を\\n果たさんとする。\\n\\n・ユニオンバーストは、敵全体にドクターギグル\\n\u3000の物理攻撃力に応じた物理割合ダメージを与え、\\n\u3000毒状態にする。\\n・デモンフラスコを召喚し敵全体をノックバック\\n\u3000させる。\\n・デモンフラスコは、一定時間経過するとドク\\n\u3000ターギグルの物理攻撃力を中アップさせ、ＴＰ\\n\u3000を特大回復させたあと、消滅する。ただしデモ\\n\u3000ンフラスコのＨＰが一定値以下になった場合は、\\n\u3000敵全体の物理攻撃力と魔法攻撃力を特大アップ\\n\u3000させ、ＴＰを特大回復させたあと、消滅する。\\n\u3000またその時に、次にドクターギグルが召喚する\\n\u3000デモンフラスコが１段階強化される。\\n・物理攻撃力、魔法攻撃力いずれかで、攻撃力が\\n\u3000最も高い敵１キャラに物理小ダメージを与え、\\n\u3000さらに行動速度を中ダウンさせる。このスキル\\n\u3000の状態異常はダメージを無効化しても付与され\\n\u3000る。', 314201, 0, 1, 314200, 270, 0, 0, 16, 0, 1.6, 3000, 'ドクターギグル');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】卑劣なる本性を現したオーエドの怪医。\\n研究で手にした究極の肉体で、世界への復讐を\\n果たさんとする。\\n\\n・ユニオンバーストは、敵全体にドクターギグル\\n\u3000の物理攻撃力に応じた物理割合ダメージを与え、\\n\u3000毒状態にする。\\n・デモンフラスコを召喚し敵全体をノックバック\\n\u3000させる。\\n・デモンフラスコは、一定時間経過するとドク\\n\u3000ターギグルの物理攻撃力を中アップさせ、ＴＰ\\n\u3000を特大回復させたあと、消滅する。ただしデモ\\n\u3000ンフラスコのＨＰが一定値以下になった場合は、\\n\u3000敵全体の物理攻撃力と魔法攻撃力を特大アップ\\n\u3000させ、ＴＰを特大回復させたあと、消滅する。\\n\u3000またその時に、次にドクターギグルが召喚する\\n\u3000デモンフラスコが１段階強化される。\\n・物理攻撃力、魔法攻撃力いずれかで、攻撃力が\\n\u3000最も高い敵１キャラに物理小ダメージを与え、\\n\u3000さらに行動速度を中ダウンさせる。このスキル\\n\u3000の状態異常はダメージを無効化しても付与され\\n\u3000る。', 314202, 0, 1, 314200, 270, 0, 0, 16, 0, 1.6, 3000, 'ドクターギグル');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】卑劣なる本性を現したオーエドの怪医。\\n研究で手にした究極の肉体で、世界への復讐を\\n果たさんとする。\\n\\n・ユニオンバーストは、敵全体にドクターギグル\\n\u3000の物理攻撃力に応じた物理割合ダメージを与え、\\n\u3000毒状態にする。\\n・デモンフラスコを召喚し敵全体をノックバック\\n\u3000させる。\\n・デモンフラスコは、一定時間経過するとドク\\n\u3000ターギグルの物理攻撃力を特大アップさせ、Ｔ\\n\u3000Ｐを特大回復させたあと、消滅する。ただしデ\\n\u3000モンフラスコのＨＰが一定値以下になった場合\\n\u3000は、敵全体の物理攻撃力と魔法攻撃力を特大\\n\u3000アップさせ、ＴＰを特大回復させたあと、消滅\\n\u3000する。またその時に、次にドクターギグルが召\\n\u3000喚するデモンフラスコが１段階強化される。\\n・物理攻撃力、魔法攻撃力いずれかで、攻撃力が\\n\u3000最も高い敵１キャラに物理小ダメージを与え、\\n\u3000さらに行動速度を中ダウンさせる。このスキル\\n\u3000の状態異常はダメージを無効化しても付与され\\n\u3000る。\\n・ドクターギグル自身のＨＰが30％を切ると、\\n\u3000さらに攻撃が激しく凶暴になる。', 314203, 0, 1, 314200, 270, 0, 0, 16, 0, 1.6, 3000, 'ドクターギグル');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ１】幻薬により見せられるは己の虚像。\\n眼前に立ち塞がる邪道の具現を、誠なる医道を\\n以って打ち崩せ。\\n\\n・ミツキとユキのシャドウと魔物を召喚。\\n・目の前の敵１キャラに物理中ダメージを与える。', 314204, 0, 1, 314204, 270, 0, 0, 16, 0, 1.6, 3000, 'ドクターギグル');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ２】魔腕から放たれる妖光が地を駆け\\nる。その魔性に呑まれし実験体たちは、我を忘れ\\nて猛り狂う。\\n\\n・魔物を召喚し、敵全体をノックバックさせる。\\n・召喚された魔物を１体倒すたびに、\\n\u3000残りターゲット数が１減少する。\\n\u3000その後、魔物が再度召喚され、敵全体をノック\\n\u3000バックさせる。\\n・ドクターギグルを除く味方全体の物理防御力と\\n\u3000魔法防御力を特大アップ。\\n\u3000ドクターギグルのＨＰが、バトル開始から\\n\u30002000以上と4000以上減少すると、ド\\n\u3000クターギグルの姿が変化し、このスキルの効果\\n\u3000がダウン。', 314205, 0, 1, 314205, 270, 0, 0, 16, 0, 0.0, 3000, 'ドクターギグル');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ３】肉体の進化は極限へと昇華する。\\n進化の果て、野望の果て、この魔腕で世界を掴ま\\nんと、怪医の激憤が轟く。\\n\\n・ユニオンバーストは、敵全体にドクターギグル\\n\u3000の物理攻撃力に応じた物理割合ダメージを与え、\\n\u3000毒状態にする。\\n・デモンフラスコを召喚し敵全体をノックバック\\n\u3000させる。\\n・デモンフラスコは、一定時間経過すると\\n\u3000ドクターギグルの物理攻撃力と物理防御力と魔\\n\u3000法防御力を特大アップさせ、ＴＰを特大回復さ\\n\u3000せたあと、消滅する。\\n\u3000ただしデモンフラスコのＨＰが一定値以下に\\n\u3000なった場合は、パーティ全体の物理攻撃力と魔\\n\u3000法攻撃力をバトル終了まで中アップさせ、\\n\u3000ＴＰを特大回復させたあと、消滅する。\\n\u3000またその時に、次にドクターギグルが召喚する\\n\u3000デモンフラスコが1段階強化される。\\n・物理攻撃力、魔法攻撃力いずれかで、攻撃力が\\n\u3000最も高い敵１キャラに物理特大ダメージを与え、\\n\u3000さらに行動速度を中ダウンさせる。\\n\u3000このスキルの状態異常はダメージを無効化して\\n\u3000も付与される。\\n・ドクターギグル自身のＨＰが30％を切ると、\\n\u3000さらに攻撃が激しく凶暴になる。', 314206, 0, 1, 314200, 270, 0, 0, 16, 0, 1.6, 3000, 'ドクターギグル');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('', 314300, 0, 1, 314300, 270, 0, 0, 16, 0, 1.6, 3000, '哀暴のわたあめちゃん');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】独り心細いなか、金儲けの道具にされ\\n悲哀の感情が暴走し、真の力を解き放った魔犬。\\nその暴走は全てを押し潰すまで止まらない。\\n\\n・ユニオンバーストは、敵全体のバリアを解除し、\\n\u3000物理大ダメージを与える。さらに自身の物理攻\\n\u3000撃力を小アップさせる。\\n・目の前の敵１キャラに物理小ダメージを与える。\\n・最も近い３キャラの物理/魔法攻撃力を大ダウ\\n\u3000ンさせ、さらにバトル終了まで物理防御力を大\\n\u3000ダウンさせる。\\n・自身の物理攻撃力を小アップさせる。', 314301, 0, 1, 314301, 270, 0, 0, 16, 0, 1.6, 3000, '哀暴のわたあめちゃん');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】独り心細いなか、金儲けの道具にされ\\n悲哀の感情が暴走し、真の力を解き放った魔犬。\\nその暴走は全てを押し潰すまで止まらない。\\n\\n・ユニオンバーストは、敵全体のバリアを解除し、\\n\u3000物理大ダメージを与える。さらに自身の物理攻\\n\u3000撃力を小アップさせる。\\n・目の前の敵１キャラに物理小ダメージを与える。\\n・最も近い３キャラの物理/魔法攻撃力を大ダウ\\n\u3000ンさせ、さらにバトル終了まで物理防御力を大\\n\u3000ダウンさせる。\\n・自身の物理攻撃力を小アップさせる。', 314302, 0, 1, 314301, 270, 0, 0, 16, 0, 1.6, 3000, '哀暴のわたあめちゃん');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】独り心細いなか、金儲けの道具にされ\\n悲哀の感情が暴走し、真の力を解き放った魔犬。\\nその暴走は全てを押し潰すまで止まらない。\\n\\n・ユニオンバーストは、敵全体のバリアを解除し、\\n\u3000物理中ダメージを与える。さらに自身の物理攻\\n\u3000撃力を小アップさせる。この攻撃は物理攻撃力\\n\u3000アップ・ダウン効果の影響を受けやすい。\\n・目の前の敵１キャラに物理中ダメージを与える。\\n\u3000この攻撃は物理攻撃力アップ・ダウン効果の\\n\u3000影響を受けやすい。\\n・最も近い３キャラの物理/魔法攻撃力を大ダウ\\n\u3000ンさせ、さらにバトル終了まで物理防御力を大\\n\u3000ダウンさせる。\\n・自身の物理攻撃力を中アップさせる。\\n・残り時間が30秒を切ると、敵全体の物理防御\\n\u3000力を大ダウン、自身の物理/魔法防御力を大\\n\u3000アップさせ、さらに攻撃が激しく凶暴になる。', 314303, 0, 1, 314300, 270, 0, 0, 16, 0, 1.6, 3000, '哀暴のわたあめちゃん');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ１】異界から迷い込んだ霊が写し鏡\\nの如く皆に化け立ちはだかる。見事勝利をおさ\\nめ世界を救えるか、ハロウィンセイバーズ。\\n\\n・ユニオンバーストは、敵全体のバリアを解除し、\\n\u3000物理大ダメージを与える。さらに自身の物理攻\\n\u3000撃力を小アップさせる。この攻撃は物理攻撃力\\n\u3000アップ・ダウン効果の影響を受けやすい。\\n・目の前の敵１キャラに物理中ダメージを与える。', 314304, 0, 1, 314304, 270, 0, 0, 16, 0, 1.6, 3000, '哀暴のわたあめちゃん');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ２】暴走から一転、球体のように丸\\nまってあらゆる攻撃を遮断する。全力を賭した\\n一撃も、この姿の前では一撫でに等しいだろう。\\n\\n・バトル開始時、自身の物理/魔法防御力を極大\\n\u3000アップさせる。\\n・バトル中、哀暴のわたあめちゃんは行動しない。', 314305, 0, 1, 314305, 270, 0, 0, 16, 0, 1.6, 3000, '哀暴のわたあめちゃん');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ３】超特級妖魔としての霊力を最大\\n解放し、世界の均衡を崩す勢いでじゃれる\\nわたあめちゃん。その愛情を全て包み込めるか。\\n\\n・ユニオンバーストは、敵全体のバリアを解除し、\\n\u3000物理中ダメージを与える。さらに自身の物理攻\\n\u3000撃力を小アップさせる。この攻撃は物理攻撃力\\n\u3000アップ・ダウン効果の影響を受けやすい。\\n・目の前の敵１キャラに物理中ダメージを与える。\\n\u3000この攻撃は物理攻撃力アップ・ダウン効果の\\n\u3000影響を受けやすい。\\n・最も近い３キャラの物理/魔法攻撃力を大ダウ\\n\u3000ンさせ、さらにバトル終了まで物理防御力を中\\n\u3000ダウンさせる。\\n・自身の物理攻撃力を小アップさせる。\\n・残り時間が30秒を切ると、敵全体の物理防御\\n\u3000力を中ダウン、自身の物理/魔法防御力を中\\n\u3000アップさせ、さらに攻撃が激しく凶暴になる。', 314306, 0, 1, 314300, 270, 0, 0, 16, 0, 1.6, 3000, '哀暴のわたあめちゃん');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('', 314400, 0, 2, 314400, 270, 0, 0, 16, 0, 1.6, 3000, 'アンチビースト・トリニティ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【魔法】魔法少女たちのパワーを吸い取って進化\\nしたアンチビースト。ランドソルはこのまま魔の\\n手に堕ちてしまうのか！？負けるなノワールズ！\\n\\n・ユニオンバーストは、自身に近い敵３キャラの\\n\u3000うち、ＨＰが80％未満のキャラを誘惑状態に\\n\u3000する。その後、自身に近い敵３キャラにキャラ\\n\u3000の最大ＨＰに応じた魔法割合ダメージを与える。\\n\u3000誘惑状態の敵にはダメージがアップする。\\n・アンチビーストの下僕を召喚し敵全体をノック\\n\u3000バックさせる。アンチビーストの下僕は、一定\\n\u3000時間経過すると最も近い敵１キャラを誘惑状態\\n\u3000にしたあと、消滅する。ただしアンチビースト\\n\u3000の下僕のＨＰが一定値以下になった場合は、\\n\u3000パーティ全体の物理攻撃力と魔法攻撃力を特大\\n\u3000アップさせたあと、消滅する。\\n・自身に近い敵２キャラに魔法小ダメージを与え\\n\u3000る。さらに、自身に物理無効バリアを展開する。\\n・自身に近い敵２キャラにキャラの最大ＨＰに応\\n\u3000じた魔法割合ダメージを与える。', 314401, 0, 2, 314400, 270, 0, 0, 16, 0, 1.6, 3000, 'アンチビースト・トリニティ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【魔法】魔法少女たちのパワーを吸い取って進化\\nしたアンチビースト。ランドソルはこのまま魔の\\n手に堕ちてしまうのか！？負けるなノワールズ！\\n\\n・ユニオンバーストは、自身に近い敵３キャラの\\n\u3000うち、ＨＰが80％未満のキャラを誘惑状態に\\n\u3000する。その後、自身に近い敵３キャラにキャラ\\n\u3000の最大ＨＰに応じた魔法割合ダメージを与える。\\n\u3000誘惑状態の敵にはダメージがアップする。\\n・アンチビーストの下僕を召喚し敵全体をノック\\n\u3000バックさせる。アンチビーストの下僕は、一定\\n\u3000時間経過すると最も近い敵１キャラを誘惑状態\\n\u3000にしたあと、消滅する。ただしアンチビースト\\n\u3000の下僕のＨＰが一定値以下になった場合は、\\n\u3000パーティ全体の物理攻撃力と魔法攻撃力を特大\\n\u3000アップさせたあと、消滅する。\\n・自身に近い敵２キャラに魔法小ダメージを与え\\n\u3000る。さらに、自身に物理無効バリアを展開する。\\n・自身に近い敵２キャラにキャラの最大ＨＰに応\\n\u3000じた魔法割合ダメージを与える。', 314402, 0, 2, 314400, 270, 0, 0, 16, 0, 1.6, 3000, 'アンチビースト・トリニティ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【魔法】魔法少女たちのパワーを吸い取って進化\\nしたアンチビースト。ランドソルはこのまま魔の\\n手に堕ちてしまうのか！？負けるなノワールズ！\\n\\n・ユニオンバーストは、自身に近い敵３キャラの\\n\u3000うち、ＨＰが80％未満のキャラを誘惑状態に\\n\u3000する。その後、自身に近い敵３キャラにキャラ\\n\u3000の最大ＨＰに応じた魔法割合ダメージを与える。\\n\u3000誘惑状態の敵にはダメージがアップする。\\n・アンチビーストの下僕を召喚し敵全体をノック\\n\u3000バックさせる。アンチビーストの下僕は、一定\\n\u3000時間経過すると最も近い敵１キャラを誘惑状態\\n\u3000にしたあと、消滅する。ただしアンチビースト\\n\u3000の下僕のＨＰが一定値以下になった場合は、\\n\u3000パーティ全体の物理攻撃力と魔法攻撃力を特大\\n\u3000アップさせたあと、消滅する。\\n・自身に近い敵２キャラに魔法小ダメージを与え\\n\u3000る。さらに、自身に物理無効バリアを展開する。\\n・自身に近い敵２キャラにキャラの最大ＨＰに応\\n\u3000じた魔法割合ダメージを与える。\\n・アンチビースト・トリニティ自身のＨＰが\\n\u300030％を切ると、さらに攻撃が激しく凶暴にな\\n\u3000る。', 314403, 0, 2, 314400, 270, 0, 0, 16, 0, 1.6, 3000, 'アンチビースト・トリニティ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ１】闇の渦に囚われ希望を失いかけた\\n魔法少女たち―そのとき聞こえてきたのは大事\\nな人からのエールの声。立ち上がれ魔法少女よ！\\n\\n・ユニオンバーストは、前方３キャラのうち、\\n\u3000ＨＰが75%未満のキャラを誘惑状態にする。\\n\u3000その後、前方３キャラにキャラの最大ＨＰに\\n\u3000応じた魔法割合ダメージを与える。\\n\u3000誘惑状態の敵にはダメージがアップする。\\n・バトル開始時、敵全体を呪い状態にする。\\n\u3000このスキルにより付与された呪いのダメージ\\n\u3000では、ＴＰが回復しない。\\n\u3000さらに、何らかの効果でＨＰを回復しようと\\n\u3000した場合、本来の回復量の60%をダウンさせ\\n\u3000る。\\n・前方２キャラに魔法小ダメージを与える。', 314404, 0, 2, 314405, 270, 0, 0, 16, 0, 1.6, 3000, 'アンチビースト・トリニティ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ２】再び闇のパワーを蓄え出した仇敵。\\nしかし、暴走し始めていたのは敵だけではなかっ\\nた―！？\u3000もう誰も、この３人を止められない！\\n\\n・バリアを張り、敵の攻撃を受け付けなくなる。\\n\u3000バリアはダメージ量に関係なく、攻撃を命中\\n\u3000させるたびに徐々に耐久性を失っていき、\\n\u3000490回攻撃を命中させるとバリアは破壊され\\n\u3000る。\\n・前方２キャラに魔法小ダメージを与える。', 314405, 0, 2, 314405, 270, 0, 0, 16, 0, 1.6, 3000, 'アンチビースト・トリニティ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ３】戦いはついにクライマックスへ。\\nいとしき生徒の、弟くんの、ドＳさんのために\\n愛と希望と闇を抱いて、突き進めノワールズ！\\n\\n・ユニオンバーストは、前方３キャラのうち、\\n\u3000ＨＰが80％未満のキャラを誘惑状態にする。\\n\u3000その後、前方３キャラにキャラの最大ＨＰに\\n\u3000応じた魔法割合ダメージを与える。\\n\u3000誘惑状態の敵にはダメージがアップする。\\n・アンチビーストの下僕を召喚し敵全体をノック\\n\u3000バックさせる。\\n\u3000アンチビーストの下僕は、一定時間経過すると\\n\u3000目の前の敵１キャラを誘惑状態にしたあと、消\\n\u3000滅する。\\n\u3000ただしアンチビーストの下僕のＨＰが一定値\\n\u3000以下になった場合は、パーティ全体の物理攻撃\\n\u3000力と魔法攻撃力を特大アップさせたあと、消滅\\n\u3000する。\\n・前方２キャラに魔法小ダメージを与える。\\n\u3000さらに、自分に物理無効バリアを展開する。\\n・前方２キャラにキャラの最大ＨＰに応じた\\n\u3000魔法割合ダメージを与える。\\n・アンチビースト・トリニティ自身のＨＰが\\n\u300030％を切ると、さらに攻撃が激しく凶暴にな\\n\u3000る。', 314406, 0, 2, 314400, 270, 0, 0, 16, 0, 1.6, 3000, 'アンチビースト・トリニティ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('', 314500, 0, 1, 314500, 270, 0, 0, 16, 0, 1.6, 3000, 'ひとりぼっちの聖夜の妖精');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】遠い昔に人々から忘れられた悲しき妖精。\\n信仰を失い、寂しさを紛らわすかのように悪戯を\\n働き人目を集めようとする。コンテスト会場の混\\n乱を治め、再び信仰を取り戻せるのか！？\\n\\n・ユニオンバーストは、敵全体にひとりぼっちの\\n\u3000聖夜の妖精の物理攻撃力とキャラの最大ＨＰに\\n\u3000応じた物理割合ダメージを与える。\\n・前から３キャラにひとりぼっちの聖夜の妖精の\\n\u3000魔法攻撃力とキャラの最大ＨＰに応じた魔法割\\n\u3000合ダメージを与え、大きく吹き飛ばす。このス\\n\u3000キルの状態異常はダメージを無効化しても付与\\n\u3000される。\\n・ひとりぼっちの聖夜の妖精自身の物理/魔法防\\n\u3000御力を極大アップ。', 314501, 0, 1, 314500, 270, 0, 0, 16, 0, 1.6, 3000, 'ひとりぼっちの聖夜の妖精');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】遠い昔に人々から忘れられた悲しき妖精。\\n信仰を失い、寂しさを紛らわすかのように悪戯を\\n働き人目を集めようとする。コンテスト会場の混\\n乱を治め、再び信仰を取り戻せるのか！？\\n\\n・ユニオンバーストは、敵全体にひとりぼっちの\\n\u3000聖夜の妖精の物理攻撃力とキャラの最大ＨＰに\\n\u3000応じた物理割合ダメージを与える。\\n・前から３キャラにひとりぼっちの聖夜の妖精の\\n\u3000魔法攻撃力とキャラの最大ＨＰに応じた魔法割\\n\u3000合ダメージを与え、大きく吹き飛ばす。このス\\n\u3000キルの状態異常はダメージを無効化しても付与\\n\u3000される。\\n・ひとりぼっちの聖夜の妖精自身の物理/魔法防\\n\u3000御力を極大アップ。', 314502, 0, 1, 314500, 270, 0, 0, 16, 0, 1.6, 3000, 'ひとりぼっちの聖夜の妖精');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】遠い昔に人々から忘れられた悲しき妖精。\\n信仰を失い、寂しさを紛らわすかのように悪戯を\\n働き人目を集めようとする。コンテスト会場の混\\n乱を治め、再び信仰を取り戻せるのか！？\\n\\n・ユニオンバーストは、敵全体にひとりぼっちの\\n\u3000聖夜の妖精の物理攻撃力とキャラの最大ＨＰに\\n\u3000応じた物理割合ダメージを与える。\\n・前から３キャラにひとりぼっちの聖夜の妖精の\\n\u3000魔法攻撃力とキャラの最大ＨＰに応じた魔法割\\n\u3000合ダメージを与え、大きく吹き飛ばす。このス\\n\u3000キルの状態異常はダメージを無効化しても付与\\n\u3000される。\\n・ひとりぼっちの聖夜の妖精自身の物理/魔法防\\n\u3000御力を極大アップ。\\n・ひとりぼっちの聖夜の妖精自身のＨＰが40％\\n\u3000を切ると、自身の物理/魔法防御力を大ダウン\\n\u3000させ、さらに攻撃が激しく凶暴になる。', 314503, 0, 1, 314500, 270, 0, 0, 16, 0, 1.6, 3000, 'ひとりぼっちの聖夜の妖精');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ１】妖精がお菓子で形作ったミヤコた\\nちの甘い猛攻と妖精の悪戯が押し寄せる。聖夜に\\n育んだ輝く絆でニセモノたちを打ち砕け！\\n\\n・ミヤコ、マヒル、リノのシャドウを召喚。\\n・前から３キャラに魔法中ダメージを与え、物理\\n\u3000防御力を特大ダウン。このスキルの効果はダ\\n\u3000メージを無効化しても付与される。', 314504, 0, 1, 314500, 270, 0, 0, 16, 0, 1.6, 3000, 'ひとりぼっちの聖夜の妖精');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ２】妖精が袋から取り出したるは魅惑\\nのお菓子。一瞬でも気を許したが最期、甘味な罠\\nに堕ちていく。プリンパワーで甘い幻想を打ち砕\\nけ！\\n\\n・ユニオンバーストは、敵全体にひとりぼっちの\\n\u3000聖夜の妖精の物理攻撃力とキャラの最大ＨＰに\\n\u3000応じた物理割合ダメージを与える。\\n・前から３キャラにひとりぼっちの聖夜の妖精の\\n\u3000魔法攻撃力とキャラの最大ＨＰに応じた魔法割\\n\u3000合ダメージを与え、大きく吹き飛ばす。このス\\n\u3000キルの状態異常はダメージを無効化しても付与\\n\u3000される。\\n・敵全体にキャラの最大ＨＰに応じた物理割合ダ\\n\u3000メージを与え、キャラのＨＰが60%を切って\\n\u3000いる場合、誘惑状態にする。このスキルの状態\\n\u3000異常はダメージを無効化しても付与される。', 314505, 0, 1, 314500, 270, 0, 0, 16, 0, 0.0, 3000, 'ひとりぼっちの聖夜の妖精');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ３】聖夜に独り妖精の哀叫が鳴り響く。\\n傍若無人に暴れる妖精をなだめ、プリンの絆で皆\\nの幸せのクリスマスと妖精の笑顔を取り戻せ！\\n\\n・ユニオンバーストは、敵全体にひとりぼっちの\\n\u3000聖夜の妖精の物理攻撃力とキャラの最大ＨＰに\\n\u3000応じた物理割合ダメージを与える。\\n・前から３キャラにひとりぼっちの聖夜の妖精の\\n\u3000魔法攻撃力とキャラの最大ＨＰに応じた魔法割\\n\u3000合ダメージを与え、大きく吹き飛ばす。このス\\n\u3000キルの状態異常はダメージを無効化しても付与\\n\u3000される。\\n・ひとりぼっちの聖夜の妖精自身の物理/魔法防\\n\u3000御力を極大アップ。\\n・ひとりぼっちの聖夜の妖精自身のＨＰが30％\\n\u3000を切ると、さらに攻撃が激しく凶暴になる。', 314506, 0, 1, 314500, 270, 0, 0, 16, 0, 1.6, 3000, 'ひとりぼっちの聖夜の妖精');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('', 314600, 0, 1, 314600, 270, 0, 0, 16, 0, 1.6, 3000, '邪牛神モーモン');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】縁起物を取り込み、願いの力を吸収して\\n猛り荒ぶる牛の魔物。怒りに身を落とした猛牛が\\n周囲の願いを打ち砕く。\\n\\n・ユニオンバーストは、敵全体に邪牛神モーモン\\n\u3000の物理攻撃力とキャラの最大ＨＰに応じた\\n\u3000物理割合ダメージを与え、火傷状態にする。\\n・最も魔法攻撃力の高い敵１キャラにキャラの最\\n\u3000大ＨＰに応じた物理割合ダメージを与え、ノッ\\n\u3000クバックさせると同時にスタンさせる。\\n・前から１番目と２番目のキャラに物理大ダメー\\n\u3000ジを与える。スキル発動後、自身の物理攻撃力\\n\u3000を大アップさせ、物理/魔法防御力が大ダウン。', 314601, 0, 1, 314600, 270, 0, 0, 16, 0, 1.6, 3000, '邪牛神モーモン');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】縁起物を取り込み、願いの力を吸収して\\n猛り荒ぶる牛の魔物。怒りに身を落とした猛牛が\\n周囲の願いを打ち砕く。\\n\\n・ユニオンバーストは、敵全体に邪牛神モーモン\\n\u3000の物理攻撃力とキャラの最大ＨＰに応じた\\n\u3000物理割合ダメージを与え、火傷状態にする。\\n・最も魔法攻撃力の高い敵１キャラにキャラの最\\n\u3000大ＨＰに応じた物理割合ダメージを与え、ノッ\\n\u3000クバックさせると同時にスタンさせる。\\n・前から１番目と２番目のキャラに物理大ダメー\\n\u3000ジを与える。スキル発動後、自身の物理攻撃力\\n\u3000を大アップさせ、物理/魔法防御力が大ダウン。', 314602, 0, 1, 314600, 270, 0, 0, 16, 0, 1.6, 3000, '邪牛神モーモン');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】縁起物を取り込み、願いの力を吸収して\\n猛り荒ぶる牛の魔物。怒りに身を落とした猛牛が\\n周囲の願いを打ち砕く。\\n\\n・ユニオンバーストは、敵全体に邪牛神モーモン\\n\u3000の物理攻撃力とキャラの最大ＨＰに応じた\\n\u3000物理割合ダメージを与え、火傷状態にする。\\n・通常攻撃は、目の前の敵１キャラに邪牛神モー\\n\u3000モンの物理攻撃力とキャラの最大ＨＰに応じた\\n\u3000物理割合ダメージを与える。\\n・最も魔法攻撃力の高い敵１キャラにキャラの最\\n\u3000大ＨＰに応じた物理割合ダメージを与え、ノッ\\n\u3000クバックさせると同時にスタンさせる。\\n・前から１番目と２番目のキャラに物理大ダメー\\n\u3000ジを与える。スキル発動後、自身の物理攻撃力\\n\u3000を大アップさせ、物理/魔法防御力が大ダウン。\\n・残り時間が30秒を切ると、さらに攻撃が激し\\n\u3000く凶暴になる。', 314603, 0, 1, 314600, 270, 0, 0, 16, 0, 1.6, 3000, '邪牛神モーモン');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ１】力への渇望から魔物は子分を率\\nい、再び略奪へ踏みだす。迫り来るならず者た\\nちを打倒し、おせちの具材を守り抜け。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。\\n\u3000この防御力アップ効果で上昇した防御力は、バ\\n\u3000トル中に受ける防御力ダウンスキルの影響を受\\n\u3000けない。\\n・邪牛神モーモンおよびハイオークから受けるす\\n\u3000べてのダメージで発生する、パーティキャラの\\n\u3000ＴＰ回復量を中ダウンさせる。\\n・バトル開始時、ハイオークを３体召喚する。\\n・ハイオークを１体倒すたびに、残りハイオーク\\n\u3000数が１減少する。その後、ハイオークが再度\\n\u3000召喚される。\\n・目の前の敵１キャラに魔法小ダメージを与え、\u3000物理防御力を大ダウンさせる。このスキルの状\\n\u3000態異常はダメージを無効化しても付与される。', 314604, 0, 1, 314600, 270, 0, 0, 16, 0, 1.6, 3000, '邪牛神モーモン');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ２】猛牛の強靭な肉体が爆ぜる。\\n怪腕から繰り出される殴打をまともに受けると\\n肉体と、そこに宿る全ての煩悩をも吹き飛ばす。\\n\\n・敵からの攻撃による麻痺、スタン、束縛、凍結、\\n\u3000時間停止、行動速度低下効果への耐性を持たな\\n\u3000い。\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。\\n\u3000この防御力アップ効果で上昇した防御力は、バ\\n\u3000トル中に受ける防御力ダウンスキルの影響を受\\n\u3000けない。\\n・邪牛神モーモンから受けるすべてのダメージで\\n\u3000発生する、パーティキャラのＴＰ回復量を中ダ\\n\u3000ウンさせる。\\n・ユニオンバーストは、敵全体に邪牛神モーモン\\n\u3000の物理攻撃力とキャラの最大ＨＰに応じた\\n\u3000物理割合ダメージを与え、火傷状態にする。\\n・通常攻撃は、目の前の敵１キャラに邪牛神モー\\n\u3000モンの物理攻撃力とキャラの最大ＨＰに応じた\\n\u3000物理割合ダメージを与える。\\n・前から１番目と２番目のキャラに物理大ダメー\\n\u3000ジを与える。スキル発動後、自身の物理攻撃力\\n\u3000を大アップさせ、物理/魔法防御力が大ダウン。\\n・敵全体のステータスアップ効果を解除し、一定\\n\u3000時間バトルフィールドを展開する。\\n【バトルフィールド効果】\\n・敵全体の物理攻撃力と魔法攻撃力を100％\\n\u3000ダウンした後、物理攻撃力と魔法攻撃力を極大\\n\u3000アップ。\\n・邪牛神モーモンの物理攻撃力を100％ダウン\\n\u3000した後、物理攻撃力を極大アップ。', 314605, 0, 1, 314605, 270, 0, 0, 16, 0, 1.6, 3000, '邪牛神モーモン');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ３】猛牛は痛手を負おうとも、鼻息\\nを荒げ立ちはだかる。妄執に取りつかれた迷惑\\nな魔物を打ち倒し、謹賀新年を取り戻せ！\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。\\n\u3000この防御力アップ効果で上昇した防御力は、バ\\n\u3000トル中に受ける防御力ダウンスキルの影響を受\\n\u3000けない。\\n・邪牛神モーモンから受けるすべてのダメージで\\n\u3000発生する、パーティキャラのＴＰ回復量を中ダ\\n\u3000ウンさせる。\\n・ユニオンバーストは、敵全体に邪牛神モーモン\\n\u3000の物理攻撃力とキャラの最大ＨＰに応じた\\n\u3000物理割合ダメージを与え、火傷状態にする。\\n・最も魔法攻撃力の高い敵１キャラに物理割合\\n\u3000ダメージを与え、ノックバックさせると同時に\\n\u3000スタンさせる。\\n・前から１番目と２番目のキャラに物理大ダメー\\n\u3000ジを与える。スキル発動後、自身の物理攻撃力\\n\u3000を大アップさせ、物理/魔法防御力が大ダウン。\\n・残り時間が30秒を切ると、さらに攻撃が激し\\n\u3000く凶暴になる。', 314606, 0, 1, 314605, 270, 0, 0, 16, 0, 1.6, 3000, '邪牛神モーモン');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('', 314700, 0, 1, 314700, 270, 0, 0, 16, 0, 1.6, 3000, 'グレーターゴーレム');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】同族のゴーレムを次々に呼び寄せる\\n岩石の魔物。大地を揺さぶる巨腕が冒険者たちに\\n襲い掛かる。\\n\\n・主人公が目覚めていないため、バトル開始時\\n\u3000に全キャラクターのユニオンバーストが発動\\n\u3000不能状態になる。\\n・ぺコリーヌが目覚めていないため、本バトルで\\n\u3000はペコリーヌ（同名キャラ含む）が編成不可。\\n・ユニオンバーストは、前から4キャラにグレー\\n\u3000ターゴーレムの物理攻撃力とキャラの最大ＨＰ\\n\u3000に応じた物理割合ダメージを与える。\\n・敵全体をノックバックさせ、ゴーレムを召喚す\\n\u3000る。さらに自分の物理攻撃力を中アップさせ\\n\u3000る。\\n・前から１番目のキャラに物理大ダメージ。', 314701, 0, 1, 314700, 270, 0, 0, 16, 0, 1.6, 3000, 'グレーターゴーレム');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】同族のゴーレムを次々に呼び寄せる\\n岩石の魔物。大地を揺さぶる巨腕が冒険者たちに\\n襲い掛かる。\\n\\n・主人公が目覚めていないため、バトル開始時\\n\u3000に全キャラクターのユニオンバーストが発動\\n\u3000不能状態になる。\\n・ぺコリーヌが目覚めていないため、本バトルで\\n\u3000はペコリーヌ（同名キャラ含む）が編成不可。\\n・ユニオンバーストは、前から4キャラにグレー\\n\u3000ターゴーレムの物理攻撃力とキャラの最大ＨＰ\\n\u3000に応じた物理割合ダメージを与える。\\n・敵全体をノックバックさせ、ゴーレムを召喚す\\n\u3000る。さらに自分の物理攻撃力を中アップさせ\\n\u3000る。\\n・前から１番目のキャラに物理大ダメージ。', 314702, 0, 1, 314700, 270, 0, 0, 16, 0, 1.6, 3000, 'グレーターゴーレム');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】同族のゴーレムを次々に呼び寄せる\\n岩石の魔物。大地を揺さぶる巨腕が冒険者たちに\\n襲い掛かる。\\n\\n・主人公が目覚めていないため、バトル開始時\\n\u3000に全キャラクターのユニオンバーストが発動\\n\u3000不能状態になる。\\n・ぺコリーヌが目覚めていないため、本バトルで\\n\u3000はペコリーヌ（同名キャラ含む）が編成不可。\\n・ユニオンバーストは、前から4キャラにグレー\\n\u3000ターゴーレムの物理攻撃力とキャラの最大ＨＰ\\n\u3000に応じた物理割合ダメージを与える。\\n・敵全体をノックバックさせ、ゴーレムを召喚す\\n\u3000る。さらに自分の物理攻撃力を中アップさせ\\n\u3000る。\\n・前から１番目のキャラに物理大ダメージ。', 314703, 0, 1, 314700, 270, 0, 0, 16, 0, 1.6, 3000, 'グレーターゴーレム');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ１】巨岩の合図に隷属したゴーレムが\\n冒険者の前に立ち塞がる。岩の魔物たちは、ただ\\nひたすら大地を震わせ、侵攻する。\\n\\n・主人公が目覚めていないため、バトル開始時\\n\u3000に全キャラクターのユニオンバーストが発動\\n\u3000不能状態になる。\\n・ぺコリーヌが目覚めていないため、本バトルで\\n\u3000はペコリーヌ（同名キャラ含む）が編成不可。\\n・バトル開始時、自分の物理防御力と魔法防御力\\n\u3000を小アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・ユニオンバーストは、前から4キャラにグレー\\n\u3000ターゴーレムの物理攻撃力とキャラの最大ＨＰ\\n\u3000に応じた物理割合ダメージを与える。', 314704, 0, 1, 314704, 270, 0, 0, 16, 0, 1.6, 3000, 'グレーターゴーレム');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ２】森の奥から突如、現れた数多の\\n虚像たち。自分たちの似姿の前に本当の絆が\\n試される。\\n\\n・主人公が目覚めていないため、バトル開始時\\n\u3000に全キャラクターのユニオンバーストが発動\\n\u3000不能状態になる。\\n・ぺコリーヌが目覚めていないため、本バトルで\\n\u3000はペコリーヌ（同名キャラ含む）が編成不可。\\n・バトル開始時、自分の物理防御力と魔法防御力\\n\u3000を小アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・敵全体をノックバックさせ複数のシャドウを召\\n\u3000喚する。\\n・前から１番目のキャラに物理小ダメージ。', 314705, 0, 1, 314704, 270, 0, 0, 16, 0, 1.6, 3000, 'グレーターゴーレム');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ３】ひび割れた巨岩の咆哮に岩々が\\n再び立ちはだかる。岩の躯体の奥から覗く紅き\\n瞳が敵を見据え、巨大な剛腕で全てを薙ぎ払う。\\n\\n・主人公が目覚めていないため、バトル開始時\\n\u3000に全キャラクターのユニオンバーストが発動\\n\u3000不能状態になる。\\n・ぺコリーヌが目覚めていないため、本バトルで\\n\u3000はペコリーヌ（同名キャラ含む）が編成不可。\\n・バトル開始時、自分の物理防御力と魔法防御力\\n\u3000を小アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・ユニオンバーストは、前から4キャラにグレー\\n\u3000ターゴーレムの物理攻撃力とキャラの最大ＨＰ\\n\u3000に応じた物理割合ダメージを与える。\\n・敵全体をノックバックさせ、ゴーレムを召喚す\\n\u3000る。さらに自分の物理攻撃力を中アップさせ\\n\u3000る。このスキルの効果は発動するたびにアッ\\n\u3000プする。\\n・前から１番目のキャラに物理大ダメージ。', 314706, 0, 1, 314706, 270, 0, 0, 16, 0, 1.6, 3000, 'グレーターゴーレム');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('', 314800, 0, 1, 314800, 270, 0, 0, 16, 0, 1.6, 3000, 'オーバーロードフォース');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】『強さを求める願い』から生まれた力。\\n本当の強さとは何か？\u3000自分自身に問い続け答え\\nを見つけられるのか。絆を取り戻すべく立ち上が\\nれ。\\n\\n・ユニオンバーストは、敵全体に物理大ダメージ\\n\u3000を与える。オーバーロードスフィアのターゲッ\\n\u3000トがブレイクしていない場合、ダメージがアッ\\n\u3000プする。\\n・敵全体の物理防御力を中ダウンさせ、物理中ダ\\n\u3000メージを与える。オーバーロードスフィアの\\n\u3000ターゲットがブレイクしていない場合、ダメー\\n\u3000ジとスキルの効果がアップする。このスキルの\\n\u3000効果はダメージを無効化しても付与される。\\n・前から1番目のキャラに物理大ダメージ。\\n・オーバーロードスフィアのターゲットのブレイ\\n\u3000ク時、自身の物理防御力と魔法防御力が中ダウ\\n\u3000ン。', 314801, 0, 1, 314800, 270, 0, 0, 16, 0, 1.6, 3000, 'オーバーロードフォース');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】『強さを求める願い』から生まれた力。\\n本当の強さとは何か？\u3000自分自身に問い続け答え\\nを見つけられるのか。絆を取り戻すべく立ち上が\\nれ。\\n\\n・ユニオンバーストは、敵全体に物理大ダメージ\\n\u3000を与える。オーバーロードスフィアのターゲッ\\n\u3000トがブレイクしていない場合、ダメージがアッ\\n\u3000プする。\\n・敵全体の物理防御力を中ダウンさせ、物理中ダ\\n\u3000メージを与える。オーバーロードスフィアの\\n\u3000ターゲットがブレイクしていない場合、ダメー\\n\u3000ジとスキルの効果がアップする。このスキルの\\n\u3000効果はダメージを無効化しても付与される。\\n・前から1番目のキャラに物理大ダメージ。\\n・オーバーロードスフィアのターゲットのブレイ\\n\u3000ク時、自身の物理防御力と魔法防御力が中ダウ\\n\u3000ン。', 314802, 0, 1, 314800, 270, 0, 0, 16, 0, 1.6, 3000, 'オーバーロードフォース');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】『強さを求める願い』から生まれた力。\\n本当の強さとは何か？\u3000自分自身に問い続け答え\\nを見つけられるのか。絆を取り戻すべく立ち上が\\nれ。\\n\\n・ユニオンバーストは、敵全体に物理大ダメージ\\n\u3000を与える。オーバーロードスフィアのターゲッ\\n\u3000トがブレイクしていない場合、ダメージがアッ\\n\u3000プする。\\n・敵全体の物理防御力を中ダウンさせ、物理中ダ\\n\u3000メージを与える。オーバーロードスフィアの\\n\u3000ターゲットがブレイクしていない場合、ダメー\\n\u3000ジとスキルの効果がアップする。このスキルの\\n\u3000効果はダメージを無効化しても付与される。\\n・前から1番目のキャラに物理大ダメージ。\\n・オーバーロードスフィアのターゲットのブレイ\\n\u3000ク時、自身の物理防御力と魔法防御力が中ダウ\\n\u3000ン。', 314803, 0, 1, 314800, 270, 0, 0, 16, 0, 1.6, 3000, 'オーバーロードフォース');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ１】器から溢れ出した過負荷の力に\\nより創造された仮初の【美食殿】。再び繋がった\\nこの絆で、自分を超えていけ！\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・オーバーロードフォースから受けるすべてのダ\\n\u3000メージで発生する、パーティキャラのＴＰ回復\\n\u3000量を中ダウンさせる。\\n・ペコリーヌ、コッコロ、キャル、シェフィの\\n\u3000シャドウを召喚。\\n・前から1番目のキャラに物理大ダメージ。\\n・オーバーロードスフィアのターゲットのブレイ\\n\u3000ク時、自身の物理防御力と魔法防御力が中ダウ\\n\u3000ン。', 314804, 0, 1, 314804, 270, 0, 0, 16, 0, 1.6, 3000, 'オーバーロードフォース');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ２】溢れ出た力の球塊の脈動が変化し\\n殲滅の強襲をかける。剣の雨を突破し、思いの刃\\nは届くのか？\u3000全力を超越し、進むべき道を\\n示せ！\\n\\n・バトル開始時、オーバーロードスフィアが起動\\n\u3000し、本体のさらなる力を解放する。\\n\u3000敵全体のＨＰ吸収を特大ダウンさせ、さらに攻\\n\u3000撃が激しく強力になる。\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・オーバーロードフォースから受けるすべてのダ\\n\u3000メージで発生する、パーティキャラのＴＰ回復\\n\u3000量を中ダウンさせる。\\n・ユニオンバーストは、敵全体に物理特大\\n\u3000ダメージを与える。\\n・敵全体に物理中ダメージを与え、物理防御力を\\n\u3000小ダウンさせる。さらに、オーバーロード\\n\u3000スフィアのターゲットがブレイクしていない場\\n\u3000合、スキルの効果がアップする。このスキルの\\n\u3000効果はダメージを無効化しても付与される。\\n・オーバーロードスフィアのターゲットのブレイ\\n\u3000ク時、自身の物理防御力と魔法防御力が大ダウ\\n\u3000ン。', 314805, 0, 1, 314805, 270, 0, 0, 16, 0, 1.6, 3000, 'オーバーロードフォース');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ３】溢れ出たもう一つの力は形を変え\\n蒼き剣閃となり、流星のごとく降り注ぐ。歩んだ\\n道と結んだ絆の証明。僕のつなぐ未来へ！\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・オーバーロードフォースから受けるすべてのダ\\n\u3000メージで発生する、パーティキャラのＴＰ回復\\n\u3000量を中ダウンさせる。\\n・ユニオンバーストは、敵全体に物理大ダメージ\\n\u3000を与える。さらに、オーバーロードスフィアの\\n\u3000ターゲットがブレイクしていない場合、\\n\u3000ダメージがアップする。\\n・敵全体に物理中ダメージを与え、物理防御力を\\n\u3000中ダウンさせる。さらに、オーバーロード\\n\u3000スフィアのターゲットがブレイクしていない場\\n\u3000合、ダメージとスキルの効果がアップする。こ\\n\u3000のスキルの効果はダメージを無効化しても付与\\n\u3000される。\\n・前から1番目のキャラに物理大ダメージ。\\n・オーバーロードスフィアのターゲットのブレイ\\n\u3000ク時、自身の物理防御力と魔法防御力が中ダウ\\n\u3000ン。', 314806, 0, 1, 314804, 270, 0, 0, 16, 0, 1.6, 3000, 'オーバーロードフォース');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ１】砂瀑一帯を根城にするゴブリン族\\nの首魁。居城までたどり着いた手練れの冒険者を\\n子分を引き連れ、一斉攻撃で迎え撃つ。\\n\\n▼ＭＯＤＥ１突破条件\\nダメージを与え、ゴブリンロード＆ゴブミニオン\\nのＨＰを8880万以下にすること。\\n\\n・バトル開始時、自身の物理防御力と魔法防御\\n\u3000力を小アップさせる。この防御力アップ効果\\n\u3000で上昇した防御力は、バトル中に受ける防御\\n\u3000力ダウンスキルの影響を受けない。\\n・バトル開始時、ダメージ上限スキルを使用し\\n\u3000て、一度の行動で与えるダメージの値が一定\\n\u3000を超えた場合、与えるダメージの値に応じて\\n\u3000ダメージ量を減少させる。\\n・ゴブリンロード＆ゴブミニオンから受けるす\\n\u3000べてのダメージで発生する、パーティキャラ\\n\u3000のＴＰ回復量を中ダウンさせる。\\n・ユニオンバーストは、敵全体にキャラの最大\\n\u3000ＨＰに応じた物理割合ダメージを与え、大き\\n\u3000く吹き飛ばす。このスキルの状態異常は\\n\u3000ダメージを無効化しても付与される。\\n・敵全体にキャラの最大ＨＰに応じた物理割合\\n\u3000ダメージを与える。\\n・装甲車に乗っているゴブミニオンのターゲッ\\n\u3000トは、ブレイクすると消滅し、ゴブリンロー\\n\u3000ド＆ゴブミニオンの物理防御力と魔法防御力\\n\u3000が小ダウンする。\\n・装甲車のコアのターゲットは、ブレイクする\\n\u3000と、ゴブリンロード＆ゴブミニオンの物理防\\n\u3000御力と魔法防御力が小ダウンする。\\n・ゴブリンロード＆ゴブミニオンのターゲット\\n\u3000が全てブレイクした時、物理防御力と魔法防\\n\u3000御力が特大ダウンし、攻撃行動を変更する。\\n・行動変更後、コアにエネルギーを溜め始めて\\n\u3000一定時間経過すると、自身にＴＰ継続回復状\\n\u3000態を付与する。エネルギーを溜めている間に\\n\u3000一定ダメージを与えると、スキルが中断され、\\n\u3000自身を火傷状態にする。\\n・バトルがタイムアップすると、敵全体を戦闘\\n\u3000不能にする。', 314901, 0, 1, 314901, 270, 0, 0, 16, 0, 1.8, 3000, 'ゴブリンロード＆ゴブミニオン');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ２】装甲車を木端に破壊され怒る首魁。\\nゴブリン族のつわものを配し、冒険者の次なる壁\\nとし、容易く突破を許さない。\\n\\n▼ＭＯＤＥ２突破条件\\nダメージを与え、ゴブリングレートとゴブリン\\nメイスターのＨＰを０にすること。\\n\\n・バトル開始時、自身を無敵状態にして攻撃を\\n\u3000受け付けなくする。\\n・ゴブリンロードから受けるすべてのダメージ\\n\u3000で発生する、パーティキャラのＴＰ回復量を\\n\u3000中ダウンさせる。\\n・ユニオンバーストは、敵全体にキャラの残り\\n\u3000ＨＰに応じた物理割合ダメージを与える。\\n・バトルがタイムアップすると、敵全体を戦闘\\n\u3000不能にする。', 315001, 0, 1, 315001, 270, 0, 0, 16, 0, 1.8, 3000, 'ゴブリンロード');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ３】砂瀑に君臨するゴブリン族の首魁。\\n配下を屠られた怒りを武器にのせ、圧倒的な力で\\n眼前の全てを塵に変える。\\n\\n▼ＭＯＤＥ３突破条件\\nダメージを与え、ゴブリンロードのＨＰを０にす\\nること。\\n\\n・バトル開始時、自身の物理防御力と魔法防御\\n\u3000力を小アップさせる。この防御力アップ効果\\n\u3000で上昇した防御力は、バトル中に受ける防御\\n\u3000力ダウンスキルの影響を受けない。\\n・バトル開始時、ダメージ上限スキルを使用し\\n\u3000て、一度の行動で与えるダメージの値が一定\\n\u3000を超えた場合、与えるダメージの値に応じて\\n\u3000ダメージ量を減少させる。\\n・ゴブリンロードから受けるすべてのダメージ\\n\u3000で発生する、パーティキャラのＴＰ回復量を\\n\u3000中ダウンさせる。\\n・ユニオンバーストは、敵全体にキャラの残り\\n\u3000ＨＰに応じた物理割合ダメージを与え、自身\\n\u3000の物理攻撃力を大アップさせる。自身の物理\\n\u3000攻撃力に応じて与えるダメージの割合が増加\\n\u3000する。\\n・敵全体に物理大ダメージを与え、スタンさせ\\n\u3000る。このスキルの状態異常はダメージを無効\\n\u3000化しても付与される。\\n・前方範囲内の敵に物理大ダメージを与え、大\\n\u3000きく吹き飛ばす。このスキルの状態異常は\\n\u3000ダメージを無効化しても付与される。\\n・前方１キャラにキャラの最大ＨＰに応じた\\n\u3000物理割合ダメージを与える。\\n・残りＨＰが1872万を下回ると、物理攻撃力\\n\u3000と行動速度が特大アップし、さらに攻撃が\\n\u3000激しく凶暴になる。\\n・バトルがタイムアップすると、敵全体を戦闘\\n\u3000不能にする。', 315002, 0, 1, 315002, 270, 0, 0, 16, 0, 1.8, 3000, 'ゴブリンロード');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】砂瀑に君臨するゴブリン族の首魁。\\n配下を屠られた怒りを武器にのせ、圧倒的な力で\\n眼前の全てを塵に変える。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を中アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・バトル開始時、自身にＴＰダウン50％カット\\n\u3000効果を付与する。\\n・バトル開始時、敵全体のＨＰ吸収を特大ダウン\\n\u3000させる。\\n・自身が一度の行動で受けるダメージ値を減衰さ\\n\u3000せる。ダメージ値が上昇するほど減衰率も上昇\\n\u3000する。\\n・ゴブリンロードから受けるすべてのダメージで\\n\u3000発生する、パーティキャラのＴＰ回復量を中ダ\\n\u3000ウンさせる。\\n・ユニオンバーストは、敵全体のバリアを解除し、\\n\u3000敵全体に自身の物理攻撃力に応じた物理割合ダ\\n\u3000メージを与える。さらに、自身の物理攻撃力を\\n\u3000バトル終了まで中アップさせる。このスキルに\\n\u3000よるダメージでは、ＴＰが回復しない。\\n・敵全体に自身の物理攻撃力に応じた物理固定ダ\\n\u3000メージを与え、短時間スタン状態を付与する。\\n\u3000キャラのＨＰが70％未満の場合、長時間スタ\\n\u3000ン状態を付与する。このスキルの状態異常はダ\\n\u3000メージを無効化しても付与される。このスキル\\n\u3000によるダメージでは、ＴＰが回復しない。\\n・前方範囲に自身の物理攻撃力に応じた物理固定\\n\u3000ダメージを与え、ノックバックさせる。このス\\n\u3000キルの状態異常はダメージを無効化しても付与\\n\u3000される。\\n・残り時間が30秒を切ると、物理攻撃力と行動\\n\u3000速度が大アップし、さらに攻撃が激しく凶暴に\\n\u3000なる。', 315003, 0, 1, 315003, 270, 0, 0, 16, 0, 1.8, 3000, 'ゴブリンロード');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('', 315100, 0, 1, 315100, 270, 0, 0, 16, 0, 1.6, 3000, '讐鼠・怒髪天のチュウジ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】ネズミ一家の偉大な大親分。牧場で敗北\\nを喫し、救護院へと落ち延びた。今、時は満ち、\\n故郷を取り戻すためのリベンジを仕掛ける。\\n\\n・ユニオンバーストは、敵全体に物理小ダメージ\\n\u3000を与え、物理防御力を中ダウンさせる。復讐の\\n\u3000炎に燃えている場合、物理防御力ダウンが無く\\n\u3000なる代わりに、与えるダメージがアップする。\\n・前から１番目のキャラを中心とした範囲内の敵\\n\u3000の物理防御力と魔法防御力を中ダウンさせる。\\n・味方全体の物理攻撃力を中アップさせ、自身の\\n\u3000ＴＰを特大回復させる。\\n・前から１番目のキャラに物理小ダメージ。\\n・讐鼠・ステゴロのチュウザが討伐されていた場\\n\u3000合、バトルスタートの際、もしくは讐鼠・怒髪\\n\u3000天のチュウジが通常攻撃を行った際に、復讐の\\n\u3000炎に燃え、攻撃が激しく凶暴になる。', 315101, 0, 1, 315100, 270, 0, 0, 16, 0, 1.6, 3000, '讐鼠・怒髪天のチュウジ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】ネズミ一家の偉大な大親分。牧場で敗北\\nを喫し、救護院へと落ち延びた。今、時は満ち、\\n故郷を取り戻すためのリベンジを仕掛ける。\\n\\n・ユニオンバーストは、敵全体に物理小ダメージ\\n\u3000を与え、物理防御力を中ダウンさせる。復讐の\\n\u3000炎に燃えている場合、物理防御力ダウンが無く\\n\u3000なる代わりに、与えるダメージがアップする。\\n・前から１番目のキャラを中心とした範囲内の敵\\n\u3000の物理防御力と魔法防御力を大ダウンさせる。\\n・味方全体の物理攻撃力を中アップさせ、自身の\\n\u3000ＴＰを特大回復させる。\\n・前から１番目のキャラに物理小ダメージ。\\n・讐鼠・ステゴロのチュウザが討伐されていた場\\n\u3000合、バトルスタートの際、もしくは讐鼠・怒髪\\n\u3000天のチュウジが通常攻撃を行った際に、復讐の\\n\u3000炎に燃え、攻撃が激しく凶暴になる。', 315102, 0, 1, 315100, 270, 0, 0, 16, 0, 1.6, 3000, '讐鼠・怒髪天のチュウジ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】ネズミ一家の偉大な大親分。牧場で敗北\\nを喫し、救護院へと落ち延びた。今、時は満ち、\\n故郷を取り戻すためのリベンジを仕掛ける。\\n\\n・ユニオンバーストは、敵全体に物理小ダメージ\\n\u3000を与え、物理防御力を中ダウンさせる。復讐の\\n\u3000炎に燃えている場合、物理防御力ダウンが無く\\n\u3000なる代わりに、与えるダメージがアップする。\\n・前から１番目のキャラを中心とした範囲内の敵\\n\u3000の物理防御力と魔法防御力を大ダウンさせる。\\n・味方全体の物理攻撃力を中アップさせ、自身の\\n\u3000ＴＰを特大回復させる。\\n・前から１番目のキャラに物理小ダメージ。\\n・讐鼠・ステゴロのチュウザが討伐されていた場\\n\u3000合、バトルスタートの際、もしくは讐鼠・怒髪\\n\u3000天のチュウジが通常攻撃を行った際に、復讐の\\n\u3000炎に燃え、攻撃が激しく凶暴になる。', 315103, 0, 1, 315100, 270, 0, 0, 16, 0, 1.6, 3000, '讐鼠・怒髪天のチュウジ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ１】大親分の威光が、再び牧場に輝く。\\n舎弟ネズミが会場内を埋め尽くし、一家総出の\\n抗争の幕が切って落とされる。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・讐鼠・怒髪天のチュウジから受けるすべてのダ\\n\u3000メージで発生する、パーティキャラのＴＰ回復\\n\u3000量を中ダウンさせる。\\n・バトル開始時、舎弟ネズミを３体召喚し、敵全\\n\u3000体をノックバックさせる。\\n・舎弟ネズミを１体倒すたびに、残り舎弟ネズミ\\n\u3000数が１減少する。その後、舎弟ネズミが再度召\\n\u3000喚され、敵全体をノックバックさせる。\\n・前から１番目のキャラに物理小ダメージ。', 315104, 0, 1, 315104, 270, 0, 0, 16, 0, 1.6, 3000, '讐鼠・怒髪天のチュウジ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ２】次々倒される舎弟ネズミに、過去\\nの惨劇を重ねる。捲土重来、この劣勢を押し返さ\\nんと大親分自ら武器を取る。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・讐鼠・怒髪天のチュウジから受けるすべてのダ\\n\u3000メージで発生する、パーティキャラのＴＰ回復\\n\u3000量を中ダウンさせる。\\n・ユニオンバーストは、敵全体に物理小ダメージ\\n\u3000を与え、物理防御力を小ダウンさせる。\\n・前から１番目のキャラに物理小ダメージ。', 315105, 0, 1, 315104, 270, 0, 0, 16, 0, 1.6, 3000, '讐鼠・怒髪天のチュウジ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ３】一家の暮らしを守らんと、赤鼠の\\n怒号が会場に響く。社会から除け者にされた悲し\\nき魔物は、家族の存続を懸けて全力の拳を振るう。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・讐鼠・怒髪天のチュウジから受けるすべてのダ\\n\u3000メージで発生する、パーティキャラのＴＰ回復\\n\u3000量を中ダウンさせる。\\n・ユニオンバーストは、敵全体に物理小ダメージ\\n\u3000を与え、物理防御力を小ダウンさせる。復讐の\\n\u3000炎に燃えている場合、物理防御力ダウンが無く\\n\u3000なる代わりに、与えるダメージがアップする。\\n・前から１番目のキャラを中心とした範囲内の敵\\n\u3000の物理防御力と魔法防御力を中ダウンさせる。\\n・味方全体の物理攻撃力を中アップさせ、自身の\\n\u3000ＴＰを特大回復させる。\\n・前から１番目のキャラに物理小ダメージ。\\n・讐鼠・ステゴロのチュウザが討伐されていた場\\n\u3000合、バトルスタートの際、もしくは讐鼠・怒髪\\n\u3000天のチュウジが通常攻撃を行った際に、復讐の\\n\u3000炎に燃え、攻撃が激しく凶暴になる。', 315106, 0, 1, 315104, 270, 0, 0, 16, 0, 1.6, 3000, '讐鼠・怒髪天のチュウジ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('', 315200, 0, 1, 315200, 270, 0, 0, 16, 0, 1.6, 3000, '讐鼠・ステゴロのチュウザ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】ネズミ一家の頼れる若頭。かつて拳一つ\\nで漢を見せた猛き闘鼠は、一家の危機を救うため、\\nヒカリモノに手を染めて抗争に身を投じる。\\n\\n・ユニオンバーストは、前から１番目のキャラを\\n\u3000中心とした範囲内に物理大ダメージ。\\n・前から１番目のキャラに物理中ダメージを与え、\\n\u3000物理防御力を中ダウンさせる。\\n・前から１番目のキャラに物理小ダメージ。', 315201, 0, 1, 315200, 270, 0, 0, 16, 0, 1.6, 3000, '讐鼠・ステゴロのチュウザ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】ネズミ一家の頼れる若頭。かつて拳一つ\\nで漢を見せた猛き闘鼠は、一家の危機を救うため、\\nヒカリモノに手を染めて抗争に身を投じる。\\n\\n・ユニオンバーストは、前から１番目のキャラを\\n\u3000中心とした範囲内に物理大ダメージ。\\n・前から１番目のキャラに物理中ダメージを与え、\\n\u3000物理防御力を中ダウンさせる。\\n・前から１番目のキャラに物理小ダメージ。', 315202, 0, 1, 315200, 270, 0, 0, 16, 0, 1.6, 3000, '讐鼠・ステゴロのチュウザ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】ネズミ一家の頼れる若頭。かつて拳一つ\\nで漢を見せた猛き闘鼠は、一家の危機を救うため、\\nヒカリモノに手を染めて抗争に身を投じる。\\n\\n・ユニオンバーストは、前から１番目のキャラを\\n\u3000中心とした範囲内に物理大ダメージ。\\n・前から１番目のキャラに物理中ダメージを与え、\\n\u3000物理防御力を中ダウンさせる。\\n・前から１番目のキャラに物理小ダメージ。', 315203, 0, 1, 315200, 270, 0, 0, 16, 0, 1.6, 3000, '讐鼠・ステゴロのチュウザ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('ネズミ一家随一の武闘派。再び一家総出で事を\\n構えることに血を滾らせ、好戦的な目を光らせる。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・讐鼠・ステゴロのチュウザから受けるすべての\\n\u3000ダメージで発生する、パーティキャラのＴＰ回\\n\u3000復量を中ダウンさせる。\\n・前から１番目のキャラに物理小ダメージ。', 315204, 0, 1, 315204, 270, 0, 0, 16, 0, 1.6, 3000, '讐鼠・ステゴロのチュウザ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('暴れ切り裂く一家の特攻隊長。常に前線に立ち、\\nその背中で若い衆を導いてきた。一刀入魂、気合\\nを入れた決死の一撃で相手の鎧を削ぎ落す。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・讐鼠・ステゴロのチュウザから受けるすべての\\n\u3000ダメージで発生する、パーティキャラのＴＰ回\\n\u3000復量を中ダウンさせる。\\n・ユニオンバーストは、前から１番目のキャラを\\n\u3000中心とした範囲内に物理大ダメージ。\\n・前から１番目のキャラに物理小ダメージを与え、\\n\u3000物理防御力を中ダウンさせる。\\n・バトル中に讐鼠・ステゴロのチュウザ自身の残\\n\u3000りＨＰが50％以下になると、自身のＴＰを特\\n\u3000大ダウンさせ、気絶してしまい、行動しなくな\\n\u3000る。さらに、攻撃の対象にならなくなる。\\n・バトル開始時、讐鼠・ステゴロのチュウザ自身\\n\u3000の残りＨＰが50％未満の場合、気絶してしま\\n\u3000い、行動しなくなる。さらに、攻撃の対象にな\\n\u3000らなくなる。', 315205, 0, 1, 315204, 270, 0, 0, 16, 0, 1.6, 3000, '讐鼠・ステゴロのチュウザ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('恐れられながらも慕われる一家の兄貴分。家族の\\nため、散ることさえ厭わない熱き若頭は、自分た\\nちの未来を全身全霊の一刀で切り拓かんとする。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・讐鼠・ステゴロのチュウザから受けるすべての\\n\u3000ダメージで発生する、パーティキャラのＴＰ回\\n\u3000復量を中ダウンさせる。\\n・ユニオンバーストは、前から１番目のキャラを\\n\u3000中心とした範囲内に物理大ダメージ。\\n・前から１番目のキャラに物理小ダメージを与え、\\n\u3000物理防御力を中ダウンさせる。\\n・前から１番目のキャラに物理小ダメージ。', 315206, 0, 1, 315206, 270, 0, 0, 16, 0, 1.6, 3000, '讐鼠・ステゴロのチュウザ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】塔の魔力により顕現した、凶々しき霊蛇。\\n怨嗟に満ちたその咢で、冒険者の魂を貪り食う。\\n\\n・魂喰らいの凶蛇が保持している【吸魂】の数に\\n\u3000応じて、通常攻撃と各スキルの効果が強化され\\n\u3000る。\\n・通常攻撃のたびに【吸魂】を６つ追加する。\\n・ユニオンバーストは、敵全体に魂喰らいの凶蛇\\n\u3000が保持している【吸魂】の数に応じた魔法割合\\n\u3000ダメージを与え、さらに【吸魂】を５つ追加す\\n\u3000る。\\n・敵全体に魔法小ダメージを与えＴＰを減少させ、\\n\u3000さらにＴＰ上昇をダウンさせるフィールドを展\\n\u3000開する。ＴＰの減少量とフィールドの効果値は、\\n\u3000魂喰らいの凶蛇が保持している【吸魂】の数が\\n\u3000多い程強化される。\\n・攻撃するたびに魂喰らいの凶蛇に【吸魂】を１\\n\u3000つ追加する分身体を２体召喚し、さらに敵全体\\n\u3000を小さく吹き飛ばす。\\n・バトル開始時に、自身の物理攻撃力と魔法攻撃\\n\u3000力を中アップさせるが、ダメージを受けるたび\\n\u3000に、魂喰らいの凶蛇の【吸魂】が１つ減少する\\n\u3000状態にする。\\n・残りＨＰが30％を切ると、魔法攻撃力が大\\n\u3000アップし、さらに【吸魂】を20追加する。', 315300, 0, 1, 315300, 270, 0, 0, 16, 0, 1.6, 3000, '魂喰らいの凶蛇');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('', 315400, 0, 1, 315400, 270, 0, 0, 16, 0, 1.6, 3000, '大慾暴君・カジノ王');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】利己心にまみれた、非道なる大慾暴君。\\n『龍の卵』による蛮力で対敵を排除せんとする。\\n\\n・ユニオンバーストは、前から１番目のキャラに\\n\u3000大慾暴君・カジノ王の物理攻撃力とキャラの最\\n\u3000大ＨＰに応じた物理割合ダメージを与える。\\n・バリアを張り、大慾暴君・カジノ王自身の\\n\u3000物理/魔法防御力を極大アップ。\\n・大慾暴君・カジノ王自身のＨＰが50％以下に\\n\u3000なるとさらに攻撃が激しく強力になる。\\n・サイコロを振り、大慾暴君・カジノ王自身の物\\n\u3000理攻撃力がアップする。出目によって物理攻撃\\n\u3000力アップの効果が変化する。\\n\u3000出目が１の場合、物理攻撃力を小アップ。\\n\u3000出目が２及び３の場合、物理攻撃力を中アップ。\\n\u3000出目が４及び５の場合、物理攻撃力を大アップ。\\n\u3000出目が６の場合、物理攻撃力を極大アップ。\\n\u3000大慾暴君・カジノ王のＨＰが50％以下の場合、\\n\u3000このスキルを使用する。\\n・前から１番目のキャラに物理大ダメージ。', 315401, 0, 1, 315400, 270, 0, 0, 16, 0, 1.6, 3000, '大慾暴君・カジノ王');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】利己心にまみれた、非道なる大慾暴君。\\n『龍の卵』による蛮力で対敵を排除せんとする。\\n\\n・ユニオンバーストは、前から１番目のキャラに\\n\u3000大慾暴君・カジノ王の物理攻撃力とキャラの最\\n\u3000大ＨＰに応じた物理割合ダメージを与える。\\n・バリアを張り、大慾暴君・カジノ王自身の\\n\u3000物理/魔法防御力を極大アップ。\\n・大慾暴君・カジノ王自身のＨＰが50％以下に\\n\u3000なるとさらに攻撃が激しく強力になる。\\n・サイコロを振り、大慾暴君・カジノ王自身の物\\n\u3000理攻撃力がアップする。出目によって物理攻撃\\n\u3000力アップの効果が変化する。\\n\u3000出目が１の場合、物理攻撃力を小アップ。\\n\u3000出目が２及び３の場合、物理攻撃力を中アップ。\\n\u3000出目が４及び５の場合、物理攻撃力を大アップ。\\n\u3000出目が６の場合、物理攻撃力を極大アップ。\\n\u3000大慾暴君・カジノ王のＨＰが50％以下の場合、\\n\u3000このスキルを使用する。\\n・前から１番目のキャラに物理大ダメージ。', 315402, 0, 1, 315400, 270, 0, 0, 16, 0, 1.6, 3000, '大慾暴君・カジノ王');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】利己心にまみれた、非道なる大慾暴君。\\n『龍の卵』による蛮力で対敵を排除せんとする。\\n\\n・ユニオンバーストは、前から１番目のキャラに\\n\u3000大慾暴君・カジノ王の物理攻撃力とキャラの最\\n\u3000大ＨＰに応じた物理割合ダメージを与える。\\n・バリアを張り、大慾暴君・カジノ王自身の\\n\u3000物理/魔法防御力を極大アップ。\\n・大慾暴君・カジノ王自身のＨＰが50％以下に\\n\u3000なるとさらに攻撃が激しく強力になる。\\n・サイコロを振り、大慾暴君・カジノ王自身の物\\n\u3000理攻撃力がアップする。出目によって物理攻撃\\n\u3000力アップの効果が変化する。\\n\u3000出目が１の場合、物理攻撃力を小アップ。\\n\u3000出目が２及び３の場合、物理攻撃力を中アップ。\\n\u3000出目が４及び５の場合、物理攻撃力を大アップ。\\n\u3000出目が６の場合、物理攻撃力を極大アップ。\\n\u3000大慾暴君・カジノ王のＨＰが50％以下の場合、\\n\u3000このスキルを使用する。\\n・前から１番目のキャラに物理大ダメージ。', 315403, 0, 1, 315400, 270, 0, 0, 16, 0, 1.6, 3000, '大慾暴君・カジノ王');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ１】狂える無数の遊戯台が襲い来る。\\nリールが示すギャンブルの結末は、生か死か…？\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・大慾暴君・カジノ王及びスロットから受けるす\\n\u3000べてのダメージで発生する、パーティキャラの\\n\u3000ＴＰ回復量を中ダウンさせる。\\n・ユニオンバーストは、前から１番目のキャラに\\n\u3000大慾暴君・カジノ王の物理攻撃力とキャラの最\\n\u3000大ＨＰに応じた物理割合ダメージを与える。\\n・バトル開始時に、スロットを３体召喚し敵全体\\n\u3000をノックバックさせる。一定時間経過すると、\\n\u3000さらにスロットを召喚する。\\n\u3000スロットは前から１番目のキャラに物理中ダ\\n\u3000メージを与える。スロットのＨＰが一定値以下\\n\u3000になった時、味方全体の物理防御力と魔法防御\\n\u3000力を大ダウンさせる。\\n・前から１番目のキャラに物理小ダメージ。', 315404, 0, 1, 315404, 270, 0, 0, 16, 0, 1.6, 3000, '大慾暴君・カジノ王');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ２】傲慢なる無頼漢は『龍の卵』の力\\nで少女たちを退け、その顔に嘲笑を浮かべる。\\n不屈の覚悟をもって、怪しく煌めく障壁を穿け。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・バリアを張り、敵の攻撃を受け付けなくなる。\\n\u3000バリアはダメージ量に関係なく、攻撃を命中\\n\u3000させるたびに徐々に耐久性を失っていき、\\n\u3000300回攻撃を命中させるとバリアは破壊され\\n\u3000る。', 315405, 0, 1, 315405, 270, 0, 0, 16, 0, 1.6, 3000, '大慾暴君・カジノ王');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ３】カジノ王は秘宝の真なる力を解放\\nし、肥大した我欲をもって邪魔者を葬らんとする\\n怪盗少女よ、今こそ暴君の野望を打ち砕け！\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・大慾暴君・カジノ王から受けるすべてのダメー\\n\u3000ジで発生する、パーティキャラのＴＰ回復量を\\n\u3000中ダウンさせる。\\n・ユニオンバーストは、前から１番目のキャラに\\n\u3000大慾暴君・カジノ王の物理攻撃力とキャラの最\\n\u3000大ＨＰに応じた物理割合ダメージを与える。\\n・バリアを張り、大慾暴君・カジノ王自身の\\n\u3000物理/魔法防御力を極大アップ。\\n・大慾暴君・カジノ王自身のＨＰが50％以下に\\n\u3000なるとさらに攻撃が激しく強力になる。\\n・サイコロを振り、大慾暴君・カジノ王自身の物\\n\u3000理攻撃力がアップする。出目によって物理攻撃\\n\u3000力アップの効果が変化する。\\n\u3000出目が１の場合、物理攻撃力を小アップ。\\n\u3000出目が２及び３の場合、物理攻撃力を中アップ。\\n\u3000出目が４及び５の場合、物理攻撃力を大アップ。\\n\u3000出目が６の場合、物理攻撃力を極大アップ。\\n\u3000大慾暴君・カジノ王のＨＰが50％以下の場合、\\n\u3000このスキルを使用する。\\n・前から１番目のキャラに物理大ダメージ。', 315406, 0, 1, 315406, 270, 0, 0, 16, 0, 1.6, 3000, '大慾暴君・カジノ王');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】亡き主の命に従い続ける、砂岩の像。\\n苛烈になっていく攻撃が冒険者を追い詰める。\\n\\n・ユニオンバーストは、敵全体に物理小ダメージ\\n\u3000を与える。\\n\u3000このスキルによるダメージでは、ＴＰが回復し\\n\u3000ない。\\n・最も近い敵１キャラに物理小ダメージを与える。', 315500, 0, 1, 315500, 270, 0, 0, 16, 0, 2.0, 3000, 'ガーゴイル');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】亡き主の命に従い続ける、砂岩の像。\\n苛烈になっていく攻撃が冒険者を追い詰める。\\n\\n・ユニオンバーストは、敵全体に物理小ダメージ\\n\u3000を与える。\\n\u3000このスキルによるダメージでは、ＴＰが回復し\\n\u3000ない。\\n・自身に近い敵３キャラに物理小ダメージを与え\\n\u3000自身の物理攻撃力を小アップする。\\n・最も近い敵１キャラに物理小ダメージを与える。', 315501, 0, 1, 315500, 270, 0, 0, 16, 0, 2.0, 3000, 'ガーゴイル');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】亡き主の命に従い続ける、砂岩の像。\\n苛烈になっていく攻撃が冒険者を追い詰める。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。\\n\u3000この防御力アップ効果で上昇した防御力は、バ\\n\u3000トル中に受ける防御力ダウンスキルの影響を受\\n\u3000けない。\\n・ユニオンバーストは、敵全体に物理中ダメージ\\n\u3000を与える。\\n\u3000このスキルによるダメージでは、ＴＰが回復し\\n\u3000ない。\\n・自身に近い敵３キャラに物理小ダメージを与え\\n\u3000自身の物理攻撃力を小アップする。\\n・敵全体の物理防御力を中ダウンさせる。\\n・最も近い敵１キャラに物理中ダメージを与える。', 315502, 0, 1, 315500, 270, 0, 0, 16, 0, 2.0, 3000, 'ガーゴイル');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】亡き主の命に従い続ける、砂岩の像。\\n苛烈になっていく攻撃が冒険者を追い詰める。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。\\n\u3000この防御力アップ効果で上昇した防御力は、バ\\n\u3000トル中に受ける防御力ダウンスキルの影響を受\\n\u3000けない。\\n・ユニオンバーストは、敵全体に物理大ダメージ\\n\u3000を与える。\\n\u3000このスキルによるダメージでは、ＴＰが回復し\\n\u3000ない。\\n・自身に近い敵３キャラに物理中ダメージを与え\\n\u3000自身の物理攻撃力を中アップする。\\n・敵全体の物理防御力を大ダウンさせる。\\n・最も近い敵１キャラに物理大ダメージを与える。\\n・ガーゴイル自身のＨＰが50％を切ると、さら\\n\u3000に攻撃が激しく凶暴になる。', 315503, 0, 1, 315500, 270, 0, 0, 16, 0, 2.0, 3000, 'ガーゴイル');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】亡き主の命に従い続ける、砂岩の像。\\n苛烈になっていく攻撃が冒険者を追い詰める。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を中アップさせる。\\n\u3000この防御力アップ効果で上昇した防御力は、バ\\n\u3000トル中に受ける防御力ダウンスキルの影響を受\\n\u3000けない。\\n・ユニオンバーストは、敵全体に物理特大ダメー\\n\u3000ジを与える。\\n\u3000このスキルによるダメージでは、ＴＰが回復し\\n\u3000ない。\\n・自身に近い敵３キャラに物理大ダメージを与え\\n\u3000自身の物理攻撃力を中アップする。\\n・敵全体の物理防御力を大ダウンさせる。\\n・最も近い敵１キャラに物理大ダメージを与える。\\n・ガーゴイル自身のＨＰが50％を切ると、さら\\n\u3000に攻撃が激しく凶暴になる。', 315504, 0, 1, 315503, 270, 0, 0, 16, 0, 2.0, 3000, 'ガーゴイル');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【魔法】亡き主の命に従い続ける、魔鉱石の像。\\n苛烈になっていく攻撃が冒険者を追い詰める。\\n\\n・ユニオンバーストは、敵全体に魔法小ダメージ\\n\u3000を与える。\\n\u3000このスキルによるダメージでは、ＴＰが回復し\\n\u3000ない。\\n・最も近い敵１キャラに魔法小ダメージを与える。', 315600, 0, 2, 315600, 270, 0, 0, 16, 0, 2.0, 3000, 'マグスガーゴイル');
