insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【魔法】亡き主の命に従い続ける、魔鉱石の像。\\n苛烈になっていく攻撃が冒険者を追い詰める。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。\\n\u3000この防御力アップ効果で上昇した防御力は、バ\\n\u3000トル中に受ける防御力ダウンスキルの影響を受\\n\u3000けない。\\n・ユニオンバーストは、敵全体に魔法大ダメージ\\n\u3000を与える。\\n\u3000このスキルによるダメージでは、ＴＰが回復し\\n\u3000ない。\\n・自身に近い敵３キャラに魔法中ダメージを与え\\n\u3000自身の魔法攻撃力を中アップする。\\n・敵全体の魔法防御力を大ダウンさせる。\\n・最も近い敵１キャラに魔法大ダメージを与える。\\n・マグスガーゴイル自身のＨＰが50％を切ると\\n\u3000さらに攻撃が激しく凶暴になる。', 315603, 0, 2, 315600, 270, 0, 0, 16, 0, 2.0, 3000, 'マグスガーゴイル');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【魔法】亡き主の命に従い続ける、魔鉱石の像。\\n苛烈になっていく攻撃が冒険者を追い詰める。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を中アップさせる。\\n\u3000この防御力アップ効果で上昇した防御力は、バ\\n\u3000トル中に受ける防御力ダウンスキルの影響を受\\n\u3000けない。\\n・ユニオンバーストは、敵全体に魔法特大ダメー\\n\u3000ジを与える。\\n\u3000このスキルによるダメージでは、ＴＰが回復し\\n\u3000ない。\\n・自身に近い敵３キャラに魔法大ダメージを与え\\n\u3000自身の魔法攻撃力を中アップする。\\n・敵全体の魔法防御力を大ダウンさせる。\\n・最も近い敵１キャラに魔法大ダメージを与える。\\n・マグスガーゴイル自身のＨＰが50％を切ると\\n\u3000さらに攻撃が激しく凶暴になる。', 315604, 0, 2, 315603, 270, 0, 0, 16, 0, 2.0, 3000, 'マグスガーゴイル');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】亡き主の命に従い続ける、鋼の像。\\n堅牢な体で冒険者の矛を試さんと立ちはだかる。\\n\\n・ユニオンバーストは、自身の物理防御力と魔法\\n\u3000防御力を小アップする。\\n・最も近い敵１キャラに物理小ダメージを与える。', 315700, 0, 1, 315700, 270, 0, 0, 16, 0, 2.0, 3000, 'ガードガーゴイル');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】亡き主の命に従い続ける、鋼の像。\\n堅牢な体で冒険者の矛を試さんと立ちはだかる。\\n\\n・ユニオンバーストは、自身の物理防御力と魔法\\n\u3000防御力を小アップする。\\n・敵全体の物理攻撃力と魔法攻撃力を大ダウンさ\\n\u3000せる。\\n・最も近い敵１キャラに物理小ダメージを与える。', 315701, 0, 1, 315700, 270, 0, 0, 16, 0, 2.0, 3000, 'ガードガーゴイル');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】亡き主の命に従い続ける、鋼の像。\\n堅牢な体で冒険者の矛を試さんと立ちはだかる。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。\\n\u3000この防御力アップ効果で上昇した防御力は、バ\\n\u3000トル中に受ける防御力ダウンスキルの影響を受\\n\u3000けない。\\n・バトル開始時、ダメージ上限スキルを使用し\\n\u3000て一度の行動で与えるダメージの値が200万\\n\u3000を超えた場合、与えるダメージの値に応じて\\n\u3000ダメージ量を減少させる。\\n・ユニオンバーストは、自身の物理防御力と魔法\\n\u3000防御力を中アップする。\\n・敵全体の物理攻撃力と魔法攻撃力を大ダウンさ\\n\u3000せる。\\n・自身のＴＰを小回復する。\\n・最も近い敵１キャラに物理中ダメージを与える。', 315702, 0, 1, 315700, 270, 0, 0, 16, 0, 2.0, 3000, 'ガードガーゴイル');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】亡き主の命に従い続ける、鋼の像。\\n堅牢な体で冒険者の矛を試さんと立ちはだかる。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。\\n\u3000この防御力アップ効果で上昇した防御力は、バ\\n\u3000トル中に受ける防御力ダウンスキルの影響を受\\n\u3000けない。\\n・バトル開始時、ダメージ上限スキルを使用し\\n\u3000て一度の行動で与えるダメージの値が200万\\n\u3000を超えた場合、与えるダメージの値に応じて\\n\u3000ダメージ量を減少させる。\\n・ユニオンバーストは、自身の物理防御力と魔法\\n\u3000防御力を大アップする。\\n・敵全体の物理攻撃力と魔法攻撃力を大ダウンさ\\n\u3000せる。\\n・自身のＴＰを中回復する。\\n・最も近い敵１キャラに物理大ダメージを与える。\\n・ガードガーゴイル自身のＨＰが50％を切ると\\n\u3000行動速度が上がり、激しく凶暴になる。', 315703, 0, 1, 315700, 270, 0, 0, 16, 0, 2.0, 3000, 'ガードガーゴイル');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】亡き主の命に従い続ける、鋼の像。\\n堅牢な体で冒険者の矛を試さんと立ちはだかる。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を中アップさせる。\\n\u3000この防御力アップ効果で上昇した防御力は、バ\\n\u3000トル中に受ける防御力ダウンスキルの影響を受\\n\u3000けない。\\n・バトル開始時、ダメージ上限スキルを使用し\\n\u3000て一度の行動で与えるダメージの値が200万\\n\u3000を超えた場合、与えるダメージの値に応じて\\n\u3000ダメージ量を減少させる。\\n・ユニオンバーストは、自身の物理防御力と魔法\\n\u3000防御力を特大アップする。\\n・敵全体の物理攻撃力と魔法攻撃力を大ダウンさ\\n\u3000せる。\\n・自身のＴＰを大回復する。\\n・最も近い敵１キャラに物理大ダメージを与える。\\n・ガードガーゴイル自身のＨＰが50％を切ると\\n\u3000行動速度が上がり、激しく凶暴になる。', 315704, 0, 1, 315703, 270, 0, 0, 16, 0, 2.0, 3000, 'ガードガーゴイル');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】亡き主の命に従い続ける、砂岩の像。\\n苛烈になっていく攻撃が冒険者を追い詰める。\\n\\n・ユニオンバーストは、敵全体に物理小ダメージ\\n\u3000を与える。\\n\u3000このスキルによるダメージでは、ＴＰが回復し\\n\u3000ない。\\n・最も近い敵１キャラに物理小ダメージを与える。', 315800, 0, 1, 315800, 270, 0, 0, 16, 0, 2.0, 3000, 'ガーゴイル・バースト');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】亡き主の命に従い続ける、砂岩の像。\\n苛烈になっていく攻撃が冒険者を追い詰める。\\n\\n・ユニオンバーストは、敵全体に物理小ダメージ\\n\u3000を与える。\\n\u3000このスキルによるダメージでは、ＴＰが回復し\\n\u3000ない。\\n・自身に近い敵３キャラに物理小ダメージを与え\\n\u3000自身の物理攻撃力を小アップする。\\n・最も近い敵１キャラに物理小ダメージを与える。', 315801, 0, 1, 315800, 270, 0, 0, 16, 0, 2.0, 3000, 'ガーゴイル・バースト');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】亡き主の命に従い続ける、砂岩の像。\\n苛烈になっていく攻撃が冒険者を追い詰める。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。\\n\u3000この防御力アップ効果で上昇した防御力は、バ\\n\u3000トル中に受ける防御力ダウンスキルの影響を受\\n\u3000けない。\\n・ユニオンバーストは、敵全体に物理中ダメージ\\n\u3000を与える。\\n\u3000このスキルによるダメージでは、ＴＰが回復し\\n\u3000ない。\\n・自身に近い敵３キャラに物理小ダメージを与え\\n\u3000自身の物理攻撃力を小アップする。\\n・敵全体の物理防御力を中ダウンさせる。\\n・最も近い敵１キャラに物理中ダメージを与える。', 315802, 0, 1, 315800, 270, 0, 0, 16, 0, 2.0, 3000, 'ガーゴイル・バースト');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】亡き主の命に従い続ける、砂岩の像。\\n苛烈になっていく攻撃が冒険者を追い詰める。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。\\n\u3000この防御力アップ効果で上昇した防御力は、バ\\n\u3000トル中に受ける防御力ダウンスキルの影響を受\\n\u3000けない。\\n・ユニオンバーストは、敵全体に物理大ダメージ\\n\u3000を与える。\\n\u3000このスキルによるダメージでは、ＴＰが回復し\\n\u3000ない。\\n・自身に近い敵３キャラに物理中ダメージを与え\\n\u3000自身の物理攻撃力を中アップする。\\n・敵全体の物理防御力を大ダウンさせる。\\n・最も近い敵１キャラに物理大ダメージを与える。\\n・ガーゴイル・バースト自身のＨＰが50％を切\\n\u3000ると、さらに攻撃が激しく凶暴になる。', 315803, 0, 1, 315800, 270, 0, 0, 16, 0, 2.0, 3000, 'ガーゴイル・バースト');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】亡き主の命に従い続ける、砂岩の像。\\n苛烈になっていく攻撃が冒険者を追い詰める。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を中アップさせる。\\n\u3000この防御力アップ効果で上昇した防御力は、バ\\n\u3000トル中に受ける防御力ダウンスキルの影響を受\\n\u3000けない。\\n・ユニオンバーストは、敵全体に物理特大ダメー\\n\u3000ジを与える。\\n\u3000このスキルによるダメージでは、ＴＰが回復し\\n\u3000ない。\\n・自身に近い敵３キャラに物理大ダメージを与え\\n\u3000自身の物理攻撃力を中アップする。\\n・敵全体の物理防御力を大ダウンさせる。\\n・最も近い敵１キャラに物理大ダメージを与える。\\n・ガーゴイル・バースト自身のＨＰが50％を切\\n\u3000ると、さらに攻撃が激しく凶暴になる。', 315804, 0, 1, 315803, 270, 0, 0, 16, 0, 2.0, 3000, 'ガーゴイル・バースト');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【魔法】亡き主の命に従い続ける、魔鉱石の像。\\n苛烈になっていく攻撃が冒険者を追い詰める。\\n\\n・ユニオンバーストは、敵全体に魔法小ダメージ\\n\u3000を与える。\\n\u3000このスキルによるダメージでは、ＴＰが回復し\\n\u3000ない。\\n・最も近い敵１キャラに魔法小ダメージを与える。', 315900, 0, 2, 315900, 270, 0, 0, 16, 0, 2.0, 3000, 'ガーゴイル・マギ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【魔法】亡き主の命に従い続ける、魔鉱石の像。\\n苛烈になっていく攻撃が冒険者を追い詰める。\\n\\n・ユニオンバーストは、敵全体に魔法小ダメージ\\n\u3000を与える。\\n\u3000このスキルによるダメージでは、ＴＰが回復し\\n\u3000ない。\\n・自身に近い敵３キャラに魔法小ダメージを与え\\n\u3000自身の魔法攻撃力を小アップする。\\n・最も近い敵１キャラに魔法小ダメージを与える。', 315901, 0, 2, 315900, 270, 0, 0, 16, 0, 2.0, 3000, 'ガーゴイル・マギ');
