insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【魔法】亡き主の命に従い続ける、魔鉱石の像。\\n苛烈になっていく攻撃が冒険者を追い詰める。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。\\n\u3000この防御力アップ効果で上昇した防御力は、バ\\n\u3000トル中に受ける防御力ダウンスキルの影響を受\\n\u3000けない。\\n・ユニオンバーストは、敵全体に魔法大ダメージ\\n\u3000を与える。\\n\u3000このスキルによるダメージでは、ＴＰが回復し\\n\u3000ない。\\n・自身に近い敵３キャラに魔法中ダメージを与え\\n\u3000自身の魔法攻撃力を中アップする。\\n・敵全体の魔法防御力を大ダウンさせる。\\n・最も近い敵１キャラに魔法大ダメージを与える。\\n・ガーゴイル・マギ自身のＨＰが50％を切ると\\n\u3000さらに攻撃が激しく凶暴になる。', 315903, 0, 2, 315900, 270, 0, 0, 16, 0, 2.0, 3000, 'ガーゴイル・マギ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【魔法】亡き主の命に従い続ける、魔鉱石の像。\\n苛烈になっていく攻撃が冒険者を追い詰める。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を中アップさせる。\\n\u3000この防御力アップ効果で上昇した防御力は、バ\\n\u3000トル中に受ける防御力ダウンスキルの影響を受\\n\u3000けない。\\n・ユニオンバーストは、敵全体に魔法特大ダメー\\n\u3000ジを与える。\\n\u3000このスキルによるダメージでは、ＴＰが回復し\\n\u3000ない。\\n・自身に近い敵３キャラに魔法大ダメージを与え\\n\u3000自身の魔法攻撃力を中アップする。\\n・敵全体の魔法防御力を大ダウンさせる。\\n・最も近い敵１キャラに魔法大ダメージを与える。\\n・ガーゴイル・マギ自身のＨＰが50％を切ると\\n\u3000さらに攻撃が激しく凶暴になる。', 315904, 0, 2, 315903, 270, 0, 0, 16, 0, 2.0, 3000, 'ガーゴイル・マギ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('', 316000, 0, 1, 316000, 270, 0, 0, 16, 0, 1.6, 3000, '解放されし財宝の守護者');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】大海賊の財宝を守る高度な自動人形。\\n数多の試練を乗り越えた冒険者の前に立ち塞がる。\\n\\n・ユニオンバーストは、敵全体にキャラの最大Ｈ\\n\u3000Ｐに応じた物理割合ダメージを与え、自身の物\\n\u3000理攻撃力を大アップさせる。\\n・最も近い敵１キャラを中心にした小範囲内の敵\\n\u3000すべてに物理大ダメージを与え、物理防御力を\\n\u3000大ダウンさせる。\\n・自身の物理防御力と魔法防御力を極大アップさ\\n\u3000せる。財宝の守護者が毒、猛毒、呪い、火傷、\\n\u3000呪詛の効果を受けていると、自身の物理防御力\\n\u3000と魔法防御力がアップする時間が短くなり、極\\n\u3000大アップではなく小アップさせる。\\n・財宝の守護者自身のＨＰが40％を切ると、自\\n\u3000身の物理攻撃力を大アップさせ、さらに攻撃が\\n\u3000激しく凶暴になる。その後、敵全体にキャラの\\n\u3000最大ＨＰに応じた物理割合ダメージを与え、一\\n\u3000定時間、ユニオンバーストのみ使用できない状\\n\u3000態にする。このスキルの状態異常はダメージを\\n\u3000無効化しても付与される。\\n・最も近い敵１キャラに物理大ダメージ。', 316001, 0, 1, 316000, 270, 0, 0, 16, 0, 1.6, 3000, '解放されし財宝の守護者');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】大海賊の財宝を守る高度な自動人形。\\n数多の試練を乗り越えた冒険者の前に立ち塞がる。\\n\\n・ユニオンバーストは、敵全体にキャラの最大Ｈ\\n\u3000Ｐに応じた物理割合ダメージを与え、自身の物\\n\u3000理攻撃力を大アップさせる。\\n・最も近い敵１キャラを中心にした小範囲内の敵\\n\u3000すべてに物理大ダメージを与え、物理防御力を\\n\u3000大ダウンさせる。\\n・自身の物理防御力と魔法防御力を極大アップさ\\n\u3000せる。財宝の守護者が毒、猛毒、呪い、火傷、\\n\u3000呪詛の効果を受けていると、自身の物理防御力\\n\u3000と魔法防御力がアップする時間が短くなり、極\\n\u3000大アップではなく小アップさせる。\\n・財宝の守護者自身のＨＰが40％を切ると、自\\n\u3000身の物理攻撃力を大アップさせ、さらに攻撃が\\n\u3000激しく凶暴になる。その後、敵全体にキャラの\\n\u3000最大ＨＰに応じた物理割合ダメージを与え、一\\n\u3000定時間、ユニオンバーストのみ使用できない状\\n\u3000態にする。このスキルの状態異常はダメージを\\n\u3000無効化しても付与される。\\n・最も近い敵１キャラに物理大ダメージ。', 316002, 0, 1, 316000, 270, 0, 0, 16, 0, 1.6, 3000, '解放されし財宝の守護者');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】大海賊の財宝を守る高度な自動人形。\\n数多の試練を乗り越えた冒険者の前に立ち塞がる。\\n\\n・ユニオンバーストは、敵全体にキャラの最大Ｈ\\n\u3000Ｐに応じた物理割合ダメージを与え、自身の物\\n\u3000理攻撃力を大アップさせる。\\n・最も近い敵１キャラを中心にした小範囲内の敵\\n\u3000すべてに物理大ダメージを与え、物理防御力を\\n\u3000大ダウンさせる。\\n・自身の物理防御力と魔法防御力を極大アップさ\\n\u3000せる。財宝の守護者が毒、猛毒、呪い、火傷、\\n\u3000呪詛の効果を受けていると、自身の物理防御力\\n\u3000と魔法防御力がアップする時間が短くなり、極\\n\u3000大アップではなく小アップさせる。\\n・財宝の守護者自身のＨＰが40％を切ると、自\\n\u3000身の物理攻撃力を大アップさせ、さらに攻撃が\\n\u3000激しく凶暴になる。その後、敵全体にキャラの\\n\u3000最大ＨＰに応じた物理割合ダメージを与え、一\\n\u3000定時間、ユニオンバーストのみ使用できない状\\n\u3000態にする。このスキルの状態異常はダメージを\\n\u3000無効化しても付与される。\\n・最も近い敵１キャラに物理大ダメージ。', 316003, 0, 1, 316000, 270, 0, 0, 16, 0, 1.6, 3000, '解放されし財宝の守護者');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ１】侵入者を前にオートマタは再び動\\nき出す。使命を果たさんと機体の耐久限界を超え\\nて放たれる光線は、眼前の障害を全て焼き尽くす。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・財宝の守護者から受けるすべてのダメージで発\\n\u3000生する、パーティキャラのＴＰ回復量を中ダウ\\n\u3000ンさせる。\\n・ユニオンバーストは、敵全体にキャラの最大Ｈ\\n\u3000Ｐに応じた物理割合ダメージを与え、自身の物\\n\u3000理攻撃力を大アップさせる。\\n・前方１キャラを中心にした小範囲内の敵すべて\\n\u3000に物理大ダメージを与え、物理防御力を大ダウ\\n\u3000ンさせる。\\n・最も近い敵３キャラに物理大ダメージを与える。\\n\u3000さらに自身にも物理大ダメージを与え、物理防\\n\u3000御力と魔法防御力を一定時間極大ダウンさせ、\\n\u3000機能停止する。\\n・最も近い敵１キャラに物理大ダメージ。', 316004, 0, 1, 316004, 270, 0, 0, 16, 0, 1.6, 3000, '解放されし財宝の守護者');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ２】自動人形の咆哮に呼応し、暗き巌\\n窟の奥より頑強な魔物たちが姿を現す。不気味に\\n残響する堅岩の軋みが、冒険者を恐怖に陥れる。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・財宝の守護者及びブルーゴーレム、ゲートキー\\n\u3000パーから受けるすべてのダメージで発生する、\\n\u3000パーティキャラのＴＰ回復量を中ダウンさせる。\\n・最も近い敵１キャラを中心にした小範囲内の敵\\n\u3000すべてに物理大ダメージを与え、物理防御力を\\n\u3000大ダウンさせる。\\n・最も近い敵１キャラに物理大ダメージ。', 316005, 0, 1, 316005, 270, 0, 0, 16, 0, 1.6, 3000, '解放されし財宝の守護者');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ３】財宝を護り続けた躯体が最後の力\\nを解き放つ。リミッターを失ったマリオネットを\\n必殺の一撃で打ち倒せ！\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・財宝の守護者から受けるすべてのダメージで発\\n\u3000生する、パーティキャラのＴＰ回復量を中ダウ\\n\u3000ンさせる。\\n・ユニオンバーストは、敵全体にキャラの最大Ｈ\\n\u3000Ｐに応じた物理割合ダメージを与え、自身の物\\n\u3000理攻撃力を大アップさせる。\\n・最も近い敵１キャラを中心にした小範囲内の敵\\n\u3000すべてに物理大ダメージを与え、物理防御力を\\n\u3000大ダウンさせる。\\n・自身の物理防御力と魔法防御力を極大アップさ\\n\u3000せる。財宝の守護者が毒、猛毒、呪い、火傷、\\n\u3000呪詛の効果を受けていると、自身の物理防御力\\n\u3000と魔法防御力がアップする時間が短くなり、極\\n\u3000大アップではなく小アップさせる。\\n・財宝の守護者自身のＨＰが30％を切ると、自\\n\u3000身の物理攻撃力を大アップさせ、さらに攻撃が\\n\u3000激しく凶暴になる。その後、敵全体にキャラの\\n\u3000最大ＨＰに応じた物理割合ダメージを与え、一\\n\u3000定時間、ユニオンバーストのみ使用できない状\\n\u3000態にする。このスキルの状態異常はダメージを\\n\u3000無効化しても付与される。\\n・最も近い敵１キャラに物理大ダメージ。', 316006, 0, 1, 316004, 270, 0, 0, 16, 0, 1.6, 3000, '解放されし財宝の守護者');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【魔法】塔の魔力が集まり形を成した冷酷な水霊。\\n吹き荒れる暴雨は、無慈悲に冒険者を飲み込む。\\n\\n・ユニオンバーストは、敵全体にキャラの\\n\u3000最大ＨＰに応じた魔法割合ダメージを\\n\u3000与えて吹き飛ばす。\\n\u3000さらに、前方範囲内の敵すべてにキャラの\\n\u3000最大ＨＰに応じた追加の魔法割合ダメージを\\n\u3000与える。\\n・前方範囲内の敵すべてに魔法中ダメージを与え、\\n\u3000小さく吹き飛ばす。さらに最も近い敵１キャラ\\n\u3000に追加の魔法中ダメージを与える。\\n・一番遠くの敵１キャラに魔法中ダメージを与え、\\n\u3000さらに小さく引き寄せる。\\n・レインスピリット自身のＨＰが40%を切ると、\\n\u3000自分の魔法防御力を特大アップさせ、\\n\u3000さらに攻撃が激しく狂暴になる。', 316100, 0, 2, 316100, 270, 0, 0, 16, 0, 1.6, 3000, 'レインスピリット');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【魔法】深域の魔力が集まり形成した冷酷な水霊。\\n吹き荒れる暴雨は、無慈悲に冒険者を飲み込む。\\n\\n・ユニオンバーストは、敵全体に魔法大ダメージ\\n\u3000を与え、さらに前方中範囲内のＨＰが70％未\\n\u3000満の敵全てをノックバックさせ、最も遠い敵\\n\u3000１体を中心にした中範囲内のＨＰが70％未満\\n\u3000の敵全てを引き寄せる。このスキルの状態異常\\n\u3000はダメージを無効化しても付与される。このス\\n\u3000キルによるダメージでは、ＴＰが回復しない。\\n・敵の挑発を無視して、最も遠い敵キャラ１体に\\n\u3000キャラの最大ＨＰに応じた魔法割合ダメージを\\n\u3000与え、行動速度を中ダウンさせ、小さく引き寄\\n\u3000せる。このスキルによるダメージでは、ＴＰ回\\n\u3000復量が中ダウンする。\\n・通常攻撃は、最も近い敵１キャラを中心にした\\n\u3000小範囲に魔法大ダメージを与える。このスキル\\n\u3000によるダメージでは、ＴＰ回復量が特大ダウン\\n\u3000する。', 316101, 0, 2, 316101, 270, 0, 0, 16, 0, 1.6, 3000, 'レインスピリット');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【魔法】魔力の雨が集まり形を成した冷酷な水霊。\\n吹き荒れる暴雨は、無慈悲に冒険者を飲み込む。\\n\\n・飛行状態の敵を攻撃対象にできる。\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・ユニオンバーストは、敵全体に魔法大ダメージ\\n\u3000を与え、キャラのＨＰが70％未満の場合スタ\\n\u3000ン状態を付与する。さらに、前方中範囲内の\\n\u3000ＨＰが70％未満の敵全てをノックバックさせ、\\n\u3000最も遠い敵１体を中心にした中範囲内のＨＰが\\n\u300070％未満の敵全てを引き寄せる。このスキル\\n\u3000の状態異常はダメージを無効化しても付与され\\n\u3000る。このスキルによるダメージでは、ＴＰが回\\n\u3000復しない。\\n・敵の挑発を無視して、最も遠い敵キャラ１体に\\n\u3000キャラの最大ＨＰに応じた魔法割合ダメージを\\n\u3000与え、行動速度を中ダウンさせ、小さく引き寄\\n\u3000せる。このスキルによるダメージでは、ＴＰ回\\n\u3000復量が中ダウンする。\\n・通常攻撃は、最も近い敵１キャラを中心にした\\n\u3000小範囲内の敵全てに魔法中ダメージを与え、物\\n\u3000理攻撃力と魔法攻撃力を特大ダウンさせる。こ\\n\u3000のスキルによるダメージでは、ＴＰ回復量が特\\n\u3000大ダウンする。', 316102, 0, 2, 316102, 270, 0, 0, 16, 0, 1.6, 3000, 'レインスピリット');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【魔法】魔力の雨が集まり形を成した冷酷な水霊。\\n吹き荒れる暴雨は、無慈悲に冒険者を飲み込む。\\n\\n・飛行状態の敵を攻撃対象にできる。\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を中アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・バトル開始時、自身にＴＰダウン100％カッ\\n\u3000ト効果を付与する。\\n・バトル開始時、敵全体のＨＰ吸収を特大ダウン\\n\u3000させ、ＴＰ上昇を小ダウンさせる。\\n・ユニオンバーストは、敵全体に魔法大ダメージ\\n\u3000を与え、キャラのＨＰが70％未満の場合スタ\\n\u3000ン状態を付与する。さらに、前方中範囲内の\\n\u3000ＨＰが70％未満の敵全てをノックバックさせ、\\n\u3000最も遠い敵１体を中心にした中範囲内のＨＰが\\n\u300070％未満の敵全てを引き寄せる。このスキル\\n\u3000の状態異常はダメージを無効化しても付与され\\n\u3000る。このスキルによるダメージでは、ＴＰが回\\n\u3000復しない。\\n・敵の挑発を無視して、最も遠い敵キャラ１体に\\n\u3000キャラの最大ＨＰに応じた魔法割合ダメージを\\n\u3000与え、行動速度を中ダウンさせ、小さく引き寄\\n\u3000せる。このスキルによるダメージでは、ＴＰ回\\n\u3000復量が中ダウンする。\\n・通常攻撃は、最も近い敵１キャラを中心にした\\n\u3000小範囲内の敵全てに魔法中ダメージを与え、物\\n\u3000理攻撃力と魔法攻撃力を特大ダウンさせる。こ\\n\u3000のスキルによるダメージでは、ＴＰ回復量が特\\n\u3000大ダウンする。', 316103, 0, 2, 316103, 270, 0, 0, 16, 0, 1.6, 3000, 'レインスピリット');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('', 316200, 0, 1, 316200, 270, 0, 0, 16, 0, 1.6, 3000, 'アストライアタケモドキ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】偽キノコで獲物を誘う、恐ろしき化け茸。\\nキノコを口にした者は幻覚に囚われ、何も知らぬ\\n間に大自然の餌食となってしまう。\\n\\n・ユニオンバーストは、敵全体に自身の物理攻撃\\n\u3000力とキャラの最大ＨＰに応じた物理割合ダメー\\n\u3000ジを与え、ＨＰが40％未満のキャラを誘惑状\\n\u3000態にする。このスキルの状態異常はダメージを\\n\u3000無効化しても付与される。\\n・自身を中心とした範囲内の敵を誘惑状態にし、\\n\u3000物理攻撃力と魔法攻撃力をバトル終了まで\\n\u3000小アップさせる。\\n・前から１番目のキャラに物理大ダメージ。', 316201, 0, 1, 316200, 270, 0, 0, 16, 0, 1.6, 3000, 'アストライアタケモドキ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】偽キノコで獲物を誘う、恐ろしき化け茸。\\nキノコを口にした者は幻覚に囚われ、何も知らぬ\\n間に大自然の餌食となってしまう。\\n\\n・ユニオンバーストは、敵全体に自身の物理攻撃\\n\u3000力とキャラの最大ＨＰに応じた物理割合ダメー\\n\u3000ジを与え、ＨＰが40％未満のキャラを誘惑状\\n\u3000態にする。このスキルの状態異常はダメージを\\n\u3000無効化しても付与される。\\n・自身を中心とした範囲内の敵を誘惑状態にし、\\n\u3000物理攻撃力と魔法攻撃力をバトル終了まで\\n\u3000小アップさせる。\\n・前から１番目のキャラに物理大ダメージ。', 316202, 0, 1, 316200, 270, 0, 0, 16, 0, 1.6, 3000, 'アストライアタケモドキ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】偽キノコで獲物を誘う、恐ろしき化け茸。\\nキノコを口にした者は幻覚に囚われ、何も知らぬ\\n間に大自然の餌食となってしまう。\\n\\n・ユニオンバーストは、敵全体に自身の物理攻撃\\n\u3000力とキャラの最大ＨＰに応じた物理割合ダメー\\n\u3000ジを与え、ＨＰが40％未満のキャラを誘惑状\\n\u3000態にする。このスキルの状態異常はダメージを\\n\u3000無効化しても付与される。\\n・自身を中心とした範囲内の敵を誘惑状態にし、\\n\u3000物理攻撃力と魔法攻撃力をバトル終了まで\\n\u3000大アップさせる。\\n・自身のＨＰが50％以下になるとさらに攻撃が\\n\u3000激しく凶暴になる。\\n・前から１番目のキャラに物理大ダメージ。', 316203, 0, 1, 316200, 270, 0, 0, 16, 0, 1.6, 3000, 'アストライアタケモドキ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ１】林林総総たるしもべ共を従え、\\n化け茸は攻勢を層一層強める。捕食者となった\\n異類異形たちの反撃が今、幕を開ける。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・子分から受けるすべてのダメージで発生する、\\n\u3000パーティキャラのＴＰ回復量を中ダウンさせ\\n\u3000る。\\n・バトル開始時に、子分を４体召喚し敵全体を\\n\u3000ノックバックさせる。\\n\u3000子分は前から１番目のキャラに物理中ダメージ\\n\u3000を与える。\\n\u3000子分を１体倒すたびに、のこり子分数が１減少\\n\u3000する。その後、子分が再度召喚され、敵全体を\\n\u3000ノックバックさせる。', 316204, 0, 1, 316204, 270, 0, 0, 16, 0, 1.6, 3000, 'アストライアタケモドキ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ２】大自然の猛威は幻覚のみに留まら\\nず、しもべは強烈な麻痺攻撃を繰り出す。その威\\n力に、獲物は指先一つ動かすことすら許されない。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・アストライアタケモドキから受けるすべてのダ\\n\u3000メージで発生する、パーティキャラのＴＰ回復\\n\u3000量を中ダウンさせる。\\n・ユニオンバーストは、敵全体に自身の物理攻撃\\n\u3000力とキャラの最大ＨＰに応じた物理割合ダメー\\n\u3000ジを与える。\\n・前から１番目のキャラに物理大ダメージ。\\n・子分が胞子を集めている間、アストライアタケ\\n\u3000モドキの物理防御力と魔法防御力が特大ダウン\\n\u3000する。その後、子分が胞子を放ち前方３キャラ\\n\u3000を麻痺状態にする。\\n\u3000子分が胞子を集めている間にアストライアタケ\\n\u3000モドキが700000以上のダメージを受ける\\n\u3000と、アストライアタケモドキと子分が気絶し、\\n\u3000物理防御力と魔法防御力が特大ダウンする。', 316205, 0, 1, 316205, 270, 0, 0, 16, 0, 1.6, 3000, 'アストライアタケモドキ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ３】互いの身命が懸かった狩りの時間\\nは終盤を迎える。狩るか、それとも狩られるか。\\n万緑の戦野に、最後の胞子が撒き散らされる。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・アストライアタケモドキから受けるすべてのダ\\n\u3000メージで発生する、パーティキャラのＴＰ回復\\n\u3000量を中ダウンさせる。\\n・ユニオンバーストは、敵全体に自身の物理攻撃\\n\u3000力とキャラの最大ＨＰに応じた物理割合ダメー\\n\u3000ジを与え、ＨＰが40％未満のキャラを誘惑状\\n\u3000態にする。このスキルの状態異常はダメージを\\n\u3000無効化しても付与される。\\n・自身を中心とした範囲内の敵を誘惑状態にし、\\n\u3000物理攻撃力と魔法攻撃力をバトル終了まで\\n\u3000大アップさせる。\\n・自身のＨＰが50％以下になるとさらに攻撃が\\n\u3000激しく凶暴になる。\\n・前から１番目のキャラに物理大ダメージ。', 316206, 0, 1, 316206, 270, 0, 0, 16, 0, 1.6, 3000, 'アストライアタケモドキ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】化け茸を統べる気高きキノコの貴族。\\n幻覚性の胞子をまき散らし、敵の精神を侵食する。\\n\\n・環境効果【秋高馬肥】を発動する。このスキル\\n\u3000の効果は敵、味方すべてに適用される。一定時\\n\u3000間が経過するごとに、敵、味方全体の物理攻撃\\n\u3000力、魔法攻撃力、物理防御力、魔法防御力を\\n\u3000アップさせる。この効果の効果量は敵、味方を\\n\u3000合わせた数に応じて増加する。\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を中アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・バトル開始時、自身にＴＰダウン50％カット\\n\u3000効果を付与する。\\n・バトル開始時、敵全体のＨＰ吸収を特大ダウン\\n\u3000させる。\\n・自身が一度の行動で受けるダメージ値を減衰さ\\n\u3000せる。ダメージ値が上昇するほど減衰率も上昇\\n\u3000する。\\n・バトル開始時、敵全体にＴＰ上昇上限効果を付\\n\u3000与する。\\n・バロン・ファンガスから受けるすべてのダメー\\n\u3000ジで発生する、パーティキャラのＴＰ回復量を\\n\u3000中ダウンさせる。\\n・ユニオンバーストは、敵全体に自身の物理攻撃\\n\u3000力に応じた物理割合ダメージを与える。さらに、\\n\u3000キャラのＨＰが40％未満のキャラを混乱状態\\n\u3000にする。このスキルによるダメージでは、ＴＰ\\n\u3000が回復しない。このスキルの状態異常はダメー\\n\u3000ジを無効化しても付与される。\\n・前方範囲内の敵に混乱状態を付与し、味方全体\\n\u3000の物理防御力と魔法防御力をバトル終了まで大\\n\u3000アップさせる。\\n・子分を４体召喚し、敵全体をノックバックさせ\\n\u3000る。子分は前から１番目の敵キャラに物理中ダ\\n\u3000メージを与える。', 316207, 0, 1, 316207, 270, 0, 0, 16, 0, 1.6, 3000, 'バロン・ファンガス');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('', 316300, 0, 1, 316300, 270, 0, 0, 16, 0, 1.6, 3000, '海将タツノココマンダー');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】強靭な肉体で三叉槍を操る海獣。人間に\\n捕われた怒りで暴れ回り、ビーチを恐怖に染める。\\n\\n・ユニオンバーストは、前から３番目のキャラに\\n\u3000魔法大ダメージを与え、前から３番目のキャラ\\n\u3000を中心にした小範囲の敵を気絶させる。このス\\n\u3000キルの状態異常はダメージを無効化しても付与\\n\u3000される。\\n・自身の魔法攻撃力を大アップさせ、さらにＴＰ\\n\u3000を中回復する。\\n・前から３番目のキャラに物理中ダメージを与え\\n\u3000る。', 316301, 0, 1, 316300, 270, 0, 0, 16, 0, 1.6, 3000, '海将タツノココマンダー');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】強靭な肉体で三叉槍を操る海獣。人間に\\n捕われた怒りで暴れ回り、ビーチを恐怖に染める。\\n\\n・ユニオンバーストは、前から３番目のキャラに\\n\u3000魔法大ダメージを与え、前から３番目のキャラ\\n\u3000を中心にした小範囲の敵を気絶させる。このス\\n\u3000キルの状態異常はダメージを無効化しても付与\\n\u3000される。\\n・自身の魔法攻撃力を大アップさせ、さらにＴＰ\\n\u3000を中回復する。\\n・前から３番目のキャラに物理中ダメージを与え\\n\u3000る。', 316302, 0, 1, 316300, 270, 0, 0, 16, 0, 1.6, 3000, '海将タツノココマンダー');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】強靭な肉体で三叉槍を操る海獣。人間に\\n捕われた怒りで暴れ回り、ビーチを恐怖に染める。\\n\\n・ユニオンバーストは、前から３番目のキャラに\\n\u3000魔法大ダメージを与え、前から３番目のキャラ\\n\u3000を中心にした小範囲の敵を気絶させる。このス\\n\u3000キルの状態異常はダメージを無効化しても付与\\n\u3000される。\\n・自身の魔法攻撃力を大アップさせ、さらにＴＰ\\n\u3000を中回復する。\\n・前から３番目のキャラに物理中ダメージを与え\\n\u3000る。\\n・海将タツノココマンダーのＨＰが50％以下に\\n\u3000なると攻撃が激しく凶暴になる代わりに物理防\\n\u3000御力が大ダウンする。', 316303, 0, 1, 316300, 270, 0, 0, 16, 0, 1.6, 3000, '海将タツノココマンダー');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ１】海将の圧倒的な力は、三叉槍を\\n一振りすれば忽ちに激流を生み、人々を襲う。\\n勇気を奮い立たせ、猛然たる水流に立ち向かえ！\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・海将タツノココマンダーから受けるすべてのダ\\n\u3000メージで発生する、パーティキャラのＴＰ回復\\n\u3000量を中ダウンさせる。\\n・ユニオンバーストは、挑発を無視して、前から\\n\u3000３番目のキャラに魔法大ダメージを与え、前か\\n\u3000ら３番目のキャラを中心にした小範囲の敵を気\\n\u3000絶させる。このスキルの状態異常はダメージを\\n\u3000無効化しても付与される。\\n・敵全体に魔法中ダメージを与え、さらに魔法防\\n\u3000御力を大ダウンさせて大きく吹き飛ばす。その\\n\u3000後、自身のＴＰを大回復する。\\n・挑発を無視して、前から３番目のキャラに物理\\n\u3000中ダメージを与える。', 316304, 0, 1, 316304, 270, 0, 0, 16, 0, 1.6, 3000, '海将タツノココマンダー');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ２】海将の怒りで渚に沸き立つ蜃気楼\\nより、少女たちの幻影が襲い来る。ひと夏に賭け\\nた想いを貫くため、いざ試練を乗り越えん！\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・海将タツノココマンダーから受けるすべてのダ\\n\u3000メージで発生する、パーティキャラのＴＰ回復\\n\u3000量を中ダウンさせる。\\n・ヒヨリ、レイ、ユイのシャドウを召喚。\\n・前から３番目のキャラに物理中ダメージを与え\\n\u3000る。', 316305, 0, 1, 316305, 270, 0, 0, 16, 0, 1.6, 3000, '海将タツノココマンダー');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ３】憤怒は最高潮を迎え、海将は全身\\n全霊を賭した猛攻を見せる。平穏を取り戻すため\\n秘めたる愛と友情を力に変えて強敵を打ち破れ！\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・海将タツノココマンダーから受けるすべてのダ\\n\u3000メージで発生する、パーティキャラのＴＰ回復\\n\u3000量を中ダウンさせる。\\n・ユニオンバーストは、前から３番目のキャラに\\n\u3000魔法大ダメージを与え、前から３番目のキャラ\\n\u3000を中心にした小範囲の敵を気絶させる。このス\\n\u3000キルの状態異常はダメージを無効化しても付与\\n\u3000される。\\n・自身の魔法攻撃力を大アップさせ、さらにＴＰ\\n\u3000を中回復する。\\n・前から３番目のキャラに物理中ダメージを与え\\n\u3000る。\\n・海将タツノココマンダーのＨＰが50％以下に\\n\u3000なると攻撃が激しく凶暴になる代わりに物理防\\n\u3000御力が大ダウンする。', 316306, 0, 1, 316305, 270, 0, 0, 16, 0, 1.6, 3000, '海将タツノココマンダー');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('', 316400, 0, 2, 316400, 270, 0, 0, 16, 0, 1.6, 3000, 'ムーンレイゲート');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【魔法】月の満ち欠けに応じて現れる、異なる二\\nつの世界を繋ぐゲート。みゅ～ちゃんをゲートま\\nで導いて、元の世界に戻してあげよう！\\n\\n・ユニオンバーストは、敵全体にムーンレイゲー\\n\u3000トの【月の光印】の数に応じた魔法割合ダメー\\n\u3000ジを与える。\\n・敵全体をノックバックさせ行動速度を中ダウン\\n\u3000させる。さらに、敵全体にムーンレイゲートの\\n\u3000【月の光印】の数に応じた魔法割合ダメージを\\n\u3000与える。\\n\u3000その後ムーンレイゲートに【月の光印】を10\\n\u3000個付与する。\\n\u3000このスキルの状態異常はダメージを無効化して\\n\u3000も付与される。\\n・敵全体にムーンレイゲートの【月の光印】の数\\n\u3000に応じた魔法小ダメージを与える。\\n\u3000さらにムーンレイゲートを中心とした範囲内の\\n\u3000敵全てにムーンレイゲートの【月の光印】の数\\n\u3000に応じた魔法小ダメージを与える。\\n・【月の光印】は最大50個まで付与される。', 316401, 0, 2, 316400, 270, 0, 0, 16, 0, 1.6, 3000, 'ムーンレイゲート');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【魔法】月の満ち欠けに応じて現れる、異なる二\\nつの世界を繋ぐゲート。みゅ～ちゃんをゲートま\\nで導いて、元の世界に戻してあげよう！\\n\\n・ユニオンバーストは、敵全体にムーンレイゲー\\n\u3000トの【月の光印】の数に応じた魔法割合ダメー\\n\u3000ジを与える。\\n・敵全体をノックバックさせ行動速度を中ダウン\\n\u3000させる。さらに、敵全体にムーンレイゲートの\\n\u3000【月の光印】の数に応じた魔法割合ダメージを\\n\u3000与える。\\n\u3000その後ムーンレイゲートに【月の光印】を10\\n\u3000個付与する。\\n\u3000このスキルの状態異常はダメージを無効化して\\n\u3000も付与される。\\n・敵全体にムーンレイゲートの【月の光印】の数\\n\u3000に応じた魔法小ダメージを与える。\\n\u3000さらにムーンレイゲートを中心とした範囲内の\\n\u3000敵全てにムーンレイゲートの【月の光印】の数\\n\u3000に応じた魔法小ダメージを与える。\\n・【月の光印】は最大50個まで付与される。', 316402, 0, 2, 316400, 270, 0, 0, 16, 0, 1.6, 3000, 'ムーンレイゲート');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【魔法】月の満ち欠けに応じて現れる、異なる二\\nつの世界を繋ぐゲート。みゅ～ちゃんをゲートま\\nで導いて、元の世界に戻してあげよう！\\n\\n・ユニオンバーストは、敵全体にムーンレイゲー\\n\u3000トの【月の光印】の数に応じた魔法割合ダメー\\n\u3000ジを与える。\\n・敵全体をノックバックさせ行動速度を中ダウン\\n\u3000させる。さらに、敵全体にムーンレイゲートの\\n\u3000【月の光印】の数に応じた魔法割合ダメージを\\n\u3000与える。\\n\u3000その後ムーンレイゲートに【月の光印】を10\\n\u3000個付与する。\\n\u3000このスキルの状態異常はダメージを無効化して\\n\u3000も付与される。\\n・敵全体にムーンレイゲートの【月の光印】の数\\n\u3000に応じた魔法小ダメージを与える。\\n\u3000さらにムーンレイゲートを中心とした範囲内の\\n\u3000敵全てにムーンレイゲートの【月の光印】の数\\n\u3000に応じた魔法小ダメージを与える。\\n・残り体力が50％を切るとムーンレイゲートの\\n\u3000物理防御力、魔法防御力を中アップさせる。\\n\u3000さらにムーンレイゲートに【月の光印】を20\\n\u3000個付与し、行動パターンが変化する。\\n・【月の光印】は最大50個まで付与される。', 316403, 0, 2, 316400, 270, 0, 0, 16, 0, 1.6, 3000, 'ムーンレイゲート');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ１】ひと夏を共に過ごしたみゅ～ちゃ\\nんへの哀惜の念が生んだ、【リトルリリカル】の\\n影。それは無慈悲にもゲートへの道を立ち塞ぐ。\\n\\n・バトル開始時、ムーンレイゲートの物理防御力\\n\u3000と魔法防御力を小アップさせる。この防御力ア\\n\u3000ップ効果で上昇した防御力は、バトル中に受け\\n\u3000る防御力ダウンスキルの影響を受けない。', 316404, 0, 2, 316406, 270, 0, 0, 16, 0, 1.6, 3000, 'ムーンレイゲート');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ２】門を通して滲み伝わる、彼方の世\\n界の魔力で強化された海の魔物。圧倒的な魔力の\\n奔流が、少女たちにさらなる試練を与える。\\n\\n・バトル開始時、ムーンレイゲートの物理防御力\\n\u3000と魔法防御力を小アップさせる。この防御力ア\\n\u3000ップ効果で上昇した防御力は、バトル中に受け\\n\u3000る防御力ダウンスキルの影響を受けない。\\n・このバトルのモンスターから受けるすべてのダ\\n\u3000メージで発生する、パーティキャラのＴＰ回復\\n\u3000量を中ダウンさせる。\\n・ムーンレイゲート以外の味方の物理攻撃力、魔\\n\u3000法攻撃力を中アップさせる。\\n・ムーンレイゲートがダメージを受けると、ムー\\n\u3000ンレイゲート以外の味方の物理防御力、魔法防\\n\u3000御力を極大ダウンさせる。', 316405, 0, 2, 316405, 270, 0, 0, 16, 0, 1.6, 3000, 'ムーンレイゲート');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ３】二つの世界を繋ぐ最後のゲート。\\nかけがえのないひと夏の思い出を胸に、小さき友\\nを煌めく月光の彼方へと導こう！\\n\\n・バトル開始時、ムーンレイゲートの物理防御力\\n\u3000と魔法防御力を小アップさせる。この防御力ア\\n\u3000ップ効果で上昇した防御力は、バトル中に受け\\n\u3000る防御力ダウンスキルの影響を受けない。\\n・ムーンレイゲートから受けるすべてのダメージ\\n\u3000で発生する、パーティキャラのＴＰ回復量を中\\n\u3000ダウンさせる。\\n・ユニオンバーストは、敵全体にムーンレイゲー\\n\u3000トの【月の光印】の数に応じた魔法割合ダメー\\n\u3000ジを与える。\\n・敵全体をノックバックさせ行動速度を中ダウン\\n\u3000させる。さらに、敵全体にムーンレイゲートの\\n\u3000【月の光印】の数に応じた魔法割合ダメージを\\n\u3000与える。\\n\u3000その後ムーンレイゲートに【月の光印】を15\\n\u3000個付与する。\\n\u3000このスキルの状態異常はダメージを無効化して\\n\u3000も付与される。\\n・敵全体にムーンレイゲートの【月の光印】の数\\n\u3000に応じた魔法中ダメージを与える。\\n\u3000さらにムーンレイゲートを中心とした範囲内の\\n\u3000敵全てにムーンレイゲートの【月の光印】の数\\n\u3000に応じた魔法大ダメージを与える。\\n・残り体力が40％を切るとムーンレイゲートの\\n\u3000物理防御力、魔法防御力を中アップさせる。\\n\u3000さらにムーンレイゲートに【月の光印】を40\\n\u3000個付与し、行動パターンが変化する。\\n・【月の光印】は最大70個まで付与される。', 316406, 0, 2, 316404, 270, 0, 0, 16, 0, 1.6, 3000, 'ムーンレイゲート');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('', 316500, 0, 1, 316500, 270, 0, 0, 16, 0, 1.6, 3000, '哀執のバロメッツ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】最果ての大樹に住まう伝説の植物羊。老\\n人との再会を望み続けたが、その長い時間が彼を\\n追い詰め他者を拒絶する魔獣へと変えてしまった。\\n\\n・哀執のバロメッツに毎秒【憂いの棘】を３つ追\\n\u3000加する。\\n・哀執のバロメッツがダメージを受けるたびに哀\\n\u3000執のバロメッツの【憂いの棘】を１つ減少させ\\n\u3000る。\\n・ユニオンバーストは、敵全体のバリアを解除し\\n\u3000敵全体に哀執のバロメッツの【憂いの棘】の数\\n\u3000に応じた物理割合ダメージを与える。\\n・残りＨＰ割合が少ない敵３キャラに哀執のバロ\\n\u3000メッツの【憂いの棘】の数に応じた物理割合ダ\\n\u3000メージを与える。\\n・前方３キャラに哀執のバロメッツの【憂いの\\n\u3000棘】の数に応じた物理割合ダメージを与える。', 316501, 0, 1, 316500, 270, 0, 0, 16, 0, 1.6, 3000, '哀執のバロメッツ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】最果ての大樹に住まう伝説の植物羊。老\\n人との再会を望み続けたが、その長い時間が彼を\\n追い詰め他者を拒絶する魔獣へと変えてしまった。\\n\\n・哀執のバロメッツに毎秒【憂いの棘】を３つ追\\n\u3000加する。\\n・哀執のバロメッツがダメージを受けるたびに哀\\n\u3000執のバロメッツの【憂いの棘】を１つ減少させ\\n\u3000る。\\n・ユニオンバーストは、敵全体のバリアを解除し\\n\u3000敵全体に哀執のバロメッツの【憂いの棘】の数\\n\u3000に応じた物理割合ダメージを与える。\\n・残りＨＰ割合が少ない敵３キャラに哀執のバロ\\n\u3000メッツの【憂いの棘】の数に応じた物理割合ダ\\n\u3000メージを与える。\\n・前方３キャラに哀執のバロメッツの【憂いの\\n\u3000棘】の数に応じた物理割合ダメージを与える。', 316502, 0, 1, 316500, 270, 0, 0, 16, 0, 1.6, 3000, '哀執のバロメッツ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】最果ての大樹に住まう伝説の植物羊。老\\n人との再会を望み続けたが、その長い時間が彼を\\n追い詰め他者を拒絶する魔獣へと変えてしまった。\\n\\n・哀執のバロメッツに毎秒【憂いの棘】を４つ追\\n\u3000加する。\\n・哀執のバロメッツがダメージを受けるたびに哀\\n\u3000執のバロメッツの【憂いの棘】を１つ減少させ\\n\u3000る。\\n・ユニオンバーストは、敵全体のバリアを解除し\\n\u3000敵全体に哀執のバロメッツの【憂いの棘】の数\\n\u3000に応じた物理割合ダメージを与える。\\n・残りＨＰ割合が少ない敵３キャラに哀執のバロ\\n\u3000メッツの【憂いの棘】の数に応じた物理割合ダ\\n\u3000メージを与える。\\n・前方３キャラに哀執のバロメッツの【憂いの\\n\u3000棘】の数に応じた物理割合ダメージを与える。\\n・残り体力が25％を切ると哀執のバロメッツ\\n\u3000に【憂いの棘】を35個付与する。', 316503, 0, 1, 316500, 270, 0, 0, 16, 0, 1.6, 3000, '哀執のバロメッツ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ１】孤独と猜疑と言う名の被毛に閉じ\\n籠った獣を守るが如く、森の魔物たちが冒険者の\\n前に立ち塞がる。魔物を制し道を切り開け。\\n\\n・バトル開始時、哀執のバロメッツの物理防御力\\n\u3000と魔法防御力を小アップさせる。この防御力\\n\u3000アップ効果で上昇した防御力は、バトル中に受\\n\u3000ける防御力ダウンスキルの影響を受けない。\\n・哀執のバロメッツとお供のモンスターから受け\\n\u3000るすべてのダメージで発生する、パーティキャ\\n\u3000ラのＴＰ回復量を中ダウンさせる。\\n・哀執のバロメッツは環境効果によるダメージを\\n\u3000受けない。\\n・残りＨＰ割合が少ない敵３キャラに物理割合ダ\\n\u3000メージを与える。', 316504, 0, 1, 316504, 270, 0, 0, 16, 0, 1.6, 3000, '哀執のバロメッツ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ２】哀しき羊は被毛の鎧を硬化させ\\nあらゆるものを拒絶する。刃も拳も魔法も\\n差し伸べられた手でさえも。\\n\\n・バトル開始時、哀執のバロメッツの物理防御力\\n\u3000を中アップさせ、魔法防御力を小アップさせる。\\n\u3000この防御力アップ効果で上昇した防御力は、バ\\n\u3000トル中に受ける防御力ダウンスキルの影響を受\\n\u3000けない。\\n・哀執のバロメッツから受けるすべてのダメージ\\n\u3000で発生する、パーティキャラのＴＰ回復量を中\\n\u3000ダウンさせる。\\n・ユニオンバーストは、敵全体のバリアを解除し\\n\u3000物理割合ダメージを与える。哀執のバロメッツ\\n\u3000が毒、猛毒、呪い、火傷、呪詛の効果を受けて\\n\u3000いると、与えるダメージがダウンする。\\n・残りＨＰ割合が少ない敵３キャラに物理大\\n\u3000ダメージを与える。哀執のバロメッツが毒、猛\\n\u3000毒、呪い、火傷、呪詛の効果を受けている\\n\u3000と、与えるダメージがダウンする。\\n・哀執のバロメッツが毒、猛毒、呪い、火傷、呪\\n\u3000詛の効果を受けると、哀執のバロメッツの\\n\u3000物理・魔法防御力が特大ダウンする。', 316505, 0, 1, 316505, 270, 0, 0, 16, 0, 1.6, 3000, '哀執のバロメッツ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ３】老旅人と結んだ約束と臆病な心の\\n間で揺れる葛藤は、憂いの棘となり狂気を生む。\\nその暴威に立ち向かい、かの獣に想いを届けろ。\\n\\n・バトル開始時、哀執のバロメッツの物理防御力\\n\u3000と魔法防御力を小アップさせる。この防御力\\n\u3000アップ効果で上昇した防御力は、バトル中に受\\n\u3000ける防御力ダウンスキルの影響を受けない。\\n・哀執のバロメッツから受けるすべてのダメージ\\n\u3000で発生する、パーティキャラのＴＰ回復量を中\\n\u3000ダウンさせる。\\n・哀執のバロメッツに毎秒【憂いの棘】を４つ追\\n\u3000加する。\\n・哀執のバロメッツがダメージを受けるたびに哀\\n\u3000執のバロメッツの【憂いの棘】を１つ減少させ\\n\u3000る。\\n・ユニオンバーストは、敵全体のバリアを解除し\\n\u3000敵全体に哀執のバロメッツの【憂いの棘】の数\\n\u3000に応じた物理割合ダメージを与える。\\n・残りＨＰ割合が少ない敵３キャラに哀執のバロ\\n\u3000メッツの【憂いの棘】の数に応じた物理割合ダ\\n\u3000メージを与える。\\n・前方３キャラに哀執のバロメッツの【憂いの\\n\u3000棘】の数に応じた物理割合ダメージを与える。\\n・残り体力が25％を切ると哀執のバロメッツ\\n\u3000に【憂いの棘】を20個付与する。', 316506, 0, 1, 316506, 270, 0, 0, 16, 0, 1.6, 3000, '哀執のバロメッツ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】人竜一体となって戦うゴブリン騎手。\\n敏速に空を駆け巡り、地上の敵に襲いかかる。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・ゴブリンライダーから受けるすべてのダメージ\\n\u3000で発生する、パーティキャラのＴＰ回復量を特\\n\u3000大ダウンさせる。\\n・ユニオンバーストは、最も遠い敵３キャラに物\\n\u3000理大ダメージを与え、スタン状態を付与する。\\n\u3000このスキルの状態異常はダメージを無効化して\\n\u3000も付与される。\\n・最も遠い敵２キャラに物理小ダメージを与え、\\n\u3000物理防御力を中ダウンさせる。このスキルの状\\n\u3000態異常はダメージを無効化しても付与される。\\n・通常攻撃は、挑発を無視して最も遠い敵１キャ\\n\u3000ラに物理中ダメージを与える。このスキルによ\\n\u3000るダメージでは、ＴＰが回復しない。', 316600, 0, 1, 316600, 270, 0, 0, 6, 0, 1.5, 1000, 'ゴブリンライダー');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】人竜一体となって戦うゴブリン騎手。\\n敏速に空を駆け巡り、地上の敵に襲いかかる。\\n\\n・バトル開始時、自身の物理防御力を中アップさ\\n\u3000せ、魔法防御力を中アップさせる。この防御力\\n\u3000アップ効果で上昇した防御力は、バトル中に受\\n\u3000ける防御力ダウンスキルの影響を受けない。\\n・バトル開始時、自身にＴＰダウン50％カット\\n\u3000効果を付与する。\\n・バトル開始時、敵全体のＨＰ吸収を特大ダウン\\n\u3000させ、ＴＰ上昇を小ダウンさせる。\\n・ゴブリンライダーから受けるすべてのダメージ\\n\u3000で発生する、パーティキャラのＴＰ回復量を特\\n\u3000大ダウンさせる。\\n・ユニオンバーストは、最も遠い敵３キャラに物\\n\u3000理大ダメージを与え、スタン状態を付与する。\\n\u3000このスキルの状態異常はダメージを無効化して\\n\u3000も付与される。\\n・最も遠い敵２キャラに物理小ダメージを与え、\\n\u3000物理防御力とＴＰを大ダウンさせる。このスキ\\n\u3000ルの状態異常はダメージを無効化しても付与さ\\n\u3000れる。このスキルはダメージを無効化しても\\n\u3000ＴＰをダウンさせる。\\n・通常攻撃は、挑発を無視して最も遠い敵１キャ\\n\u3000ラに物理中ダメージを与える。このスキルによ\\n\u3000るダメージでは、ＴＰが回復しない。', 316601, 0, 1, 316601, 270, 0, 0, 6, 0, 1.5, 1000, 'ゴブリンライダー');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】人竜一体となって戦うゴブリン騎手。\\n敏速に空を駆け巡り、地上の敵に襲いかかる。\\n\\n・ゴブリンライダーから受けるすべてのダメージ\\n\u3000で発生する、パーティキャラのＴＰ回復量を特\\n\u3000大ダウンさせる。\\n・ユニオンバーストは、召喚体、分身を除いた最\\n\u3000も遠い敵３キャラに物理大ダメージを与え、ス\\n\u3000タン状態を付与する。このスキルの状態異常は\\n\u3000ダメージを無効化しても付与される。\\n・召喚体、分身を除いた最も遠い敵２キャラに物\\n\u3000理小ダメージを与え、物理防御力を大ダウンさ\\n\u3000せる。このスキルの状態異常はダメージを無効\\n\u3000化しても付与される。\\n・通常攻撃は、挑発を無視して最も遠い敵１キャ\\n\u3000ラに物理中ダメージを与える。このスキルによ\\n\u3000るダメージでは、ＴＰが回復しない。', 316602, 0, 1, 316602, 270, 0, 0, 6, 0, 1.5, 1000, 'ゴブリンライダー');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('', 316700, 0, 1, 316700, 270, 0, 0, 16, 0, 1.6, 3000, '狂乱の配信者・カガミ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】自身の存在を絶対的なものにするべく、\\n狂気を重ねる配信者。欲望にとり憑かれ、純粋な\\n想いを持つ者たちに刃を向ける。\\n\\n・バトル開始時、狂乱の配信者・カガミに【いい\\n\u3000ね】を５個付与する。\\n・ユニオンバーストは、目の前の敵１キャラに物\\n\u3000理特大ダメージを与える。狂乱の配信者・カガ\\n\u3000ミの【いいね】の数に応じてダメージ量がアッ\\n\u3000プする。さらに【いいね】を15個付与する。\\n・狂乱の配信者・カガミの物理防御力と魔法防御\\n\u3000力を特大ダウンし、狂乱の配信者・カガミに\\n\u3000【いいね】を10個付与する。さらに、【いい\\n\u3000ね】の数に応じて自身の物理攻撃力とＴＰを\\n\u3000アップする。\\n・前方２キャラに物理大ダメージを与え、狂乱の\\n\u3000配信者・カガミに【いいね】を５個付与する。\\n・狂乱の配信者・カガミが毒、猛毒、呪い、火\\n\u3000傷、呪詛の効果を受けると、狂乱の配信者・\\n\u3000カガミの【いいね】が５個減少する。', 316701, 0, 1, 316700, 270, 0, 0, 16, 0, 1.6, 3000, '狂乱の配信者・カガミ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】自身の存在を絶対的なものにするべく、\\n狂気を重ねる配信者。欲望にとり憑かれ、純粋な\\n想いを持つ者たちに刃を向ける。\\n\\n・バトル開始時、狂乱の配信者・カガミに【いい\\n\u3000ね】を５個付与する。\\n・ユニオンバーストは、目の前の敵１キャラに物\\n\u3000理特大ダメージを与える。狂乱の配信者・カガ\\n\u3000ミの【いいね】の数に応じてダメージ量がアッ\\n\u3000プする。さらに【いいね】を15個付与する。\\n・狂乱の配信者・カガミの物理防御力と魔法防御\\n\u3000力を特大ダウンし、狂乱の配信者・カガミに\\n\u3000【いいね】を10個付与する。さらに、【いい\\n\u3000ね】の数に応じて自身の物理攻撃力とＴＰを\\n\u3000アップする。\\n・前方２キャラに物理大ダメージを与え、狂乱の\\n\u3000配信者・カガミに【いいね】を５個付与する。\\n・狂乱の配信者・カガミが毒、猛毒、呪い、火\\n\u3000傷、呪詛の効果を受けると、狂乱の配信者・\\n\u3000カガミの【いいね】が５個減少する。', 316702, 0, 1, 316700, 270, 0, 0, 16, 0, 1.6, 3000, '狂乱の配信者・カガミ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】自身の存在を絶対的なものにするべく、\\n狂気を重ねる配信者。欲望にとり憑かれ、純粋な\\n想いを持つ者たちに刃を向ける。\\n\\n・バトル開始時、狂乱の配信者・カガミに【いい\\n\u3000ね】を５個付与する。\\n・ユニオンバーストは、目の前の敵１キャラに物\\n\u3000理特大ダメージを与える。狂乱の配信者・カガ\\n\u3000ミの【いいね】の数に応じてダメージ量がアッ\\n\u3000プする。さらに【いいね】を15個付与する。\\n・狂乱の配信者・カガミの物理防御力と魔法防御\\n\u3000力を特大ダウンし、狂乱の配信者・カガミに\\n\u3000【いいね】を10個付与する。さらに、【いい\\n\u3000ね】の数に応じて自身の物理攻撃力とＴＰを\\n\u3000アップする。\\n・前方２キャラに物理大ダメージを与え、狂乱の\\n\u3000配信者・カガミに【いいね】を５個付与する。\\n・自身のＨＰが50％を切ると狂乱の配信者・カ\\n\u3000ガミの物理攻撃力と行動速度が大アップする。\\n・狂乱の配信者・カガミが毒、猛毒、呪い、火\\n\u3000傷、呪詛の効果を受けると、狂乱の配信者・\\n\u3000カガミの【いいね】が５個減少する。', 316703, 0, 1, 316700, 270, 0, 0, 16, 0, 1.6, 3000, '狂乱の配信者・カガミ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ１】欲望に支配された対敵は、舞台に\\n火を放ちショーを激化させる。さながら彼の者の\\n行く末を喩すがごとく、舞台は轟々と炎上する。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・狂乱の配信者・カガミから受けるすべてのダ\\n\u3000メージで発生する、パーティキャラのＴＰ回復\\n\u3000量を中ダウンさせる。\\n・バトル開始時、狂乱の配信者・カガミに【いい\\n\u3000ね】を99個付与する。\\n・ユニオンバーストは、目の前の敵１キャラに物\\n\u3000理特大ダメージを与える。狂乱の配信者・カガ\\n\u3000ミの【いいね】の数に応じてダメージ量がアッ\\n\u3000プする。\\n・前方２キャラに物理大ダメージを与える。\\n・バトル開始時、バトルフィールドを展開する。\\n\\n【バトルフィールド効果】\\n・狂乱の配信者・カガミの物理防御力と魔法防御\\n\u3000力を特大ダウンする。\\n・パーティキャラ全員の物理防御力と魔法防御力\\n\u3000とＨＰ吸収を特大ダウンし、毎秒物理小ダメー\\n\u3000ジを与える。', 316704, 0, 1, 316704, 270, 0, 0, 16, 0, 1.6, 3000, '狂乱の配信者・カガミ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ２】苛烈な演出により、敵は人ならざ\\nる者すらも味方につける。迫る脅威を退け、狂気\\nの舞台を終わらせる為――急げ、配信者の元へ！\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・狂乱の配信者・カガミから受けるすべてのダ\\n\u3000メージで発生する、パーティキャラのＴＰ回復\\n\u3000量を中ダウンさせる。\\n・狂乱の配信者・カガミは環境効果によるダメー\\n\u3000ジを受けない。\\n・トモ、リン、ナナカのシャドウを召喚する。\\n・前方２キャラに物理大ダメージを与える。', 316705, 0, 1, 316705, 270, 0, 0, 16, 0, 1.6, 3000, '狂乱の配信者・カガミ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ３】舞台も大詰め、壇上に残るは欲に\\nまみれた魔物。己の信念を貫き、敵を打ち倒せ。\\n人々の笑顔を――そして『好き』を守るため。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\u3000\\n・狂乱の配信者・カガミから受けるすべてのダ\\n\u3000メージで発生する、パーティキャラのＴＰ回復\\n\u3000量を中ダウンさせる。\\n・バトル開始時、狂乱の配信者・カガミに【いい\\n\u3000ね】を10個付与する。\\n・ユニオンバーストは、目の前の敵１キャラに物\\n\u3000理特大ダメージを与える。狂乱の配信者・カガ\\n\u3000ミの【いいね】の数に応じてダメージ量がアッ\\n\u3000プする。さらに【いいね】を15個付与する。\\n・狂乱の配信者・カガミの物理防御力と魔法防御\\n\u3000力を特大ダウンし、狂乱の配信者・カガミに\\n\u3000【いいね】を10個付与する。さらに、【いい\\n\u3000ね】の数に応じて自身の物理攻撃力とＴＰを\\n\u3000アップする。\\n・前方２キャラに物理大ダメージを与え、狂乱の\\n\u3000配信者・カガミに【いいね】を５個付与する。\\n・自身のＨＰが50％を切ると狂乱の配信者・カ\\n\u3000ガミの物理攻撃力と行動速度が大アップする。\\n・狂乱の配信者・カガミが毒、猛毒、呪い、火\\n\u3000傷、呪詛の効果を受けると、狂乱の配信者・カ\\n\u3000ガミの【いいね】が５個減少する。', 316706, 0, 1, 316705, 270, 0, 0, 16, 0, 1.6, 3000, '狂乱の配信者・カガミ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】ミロクにより再び狭界より顕現した黒の\\n王。暗黒の瘴気で世界を蹂躙せんとする。\\n希望の力のみが黒の王の逆風となる。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・ユニオンバーストは、敵全体に物理大ダメージ\\n\u3000を与え、毒状態にする。\\n・前から３キャラに物理中ダメージを与え、物理\\n\u3000防御力とＴＰを大ダウンさせる。\\n\u3000このスキルの効果はダメージを無効化しても\\n\u3000付与される。\\n・敵全体に物理中ダメージを与え、物理防御力を\\n\u3000大ダウンさせる。\\n\u3000さらにキャラのＨＰが50％未満の場合、行動\\n\u3000速度を中ダウンさせる。\\n\u3000このスキルの効果はダメージを無効化しても\\n\u3000付与される。\\n・黒の王ジャバウォック自身のＨＰが40％を切\\n\u3000ると、さらに攻撃が激しく凶暴になる。\\n・各ターゲットのブレイク時、物理防御力と魔法\\n\u3000防御力がそれぞれ大ダウン。', 316800, 0, 1, 316800, 270, 0, 0, 16, 0, 1.6, 3000, '黒の王ジャバウォック');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【魔法】ミロクの弩級な力を受け、再び暴走した\\nラフィの聖弓。その矢に貫かれると非力なエン\\nジェルと化し、歪な呪いで生を侵蝕される。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・ユニオンバーストは、敵全体に魔法大ダメージ\\n\u3000を与え、魔法防御力を大ダウンさせる。\\n\u3000エンジェル状態の場合は呪いを付与する。\\n\u3000このスキルの効果はダメージを無効化しても\\n\u3000付与される。\\n・敵全体に魔法中ダメージを与え、さらにＨＰが\\n\u300070％未満のキャラを一定時間エンジェル状態\\n\u3000にする。\\n\u3000エンジェルになったキャラは、通常攻撃しか使\\n\u3000用できなくなり、かかっているステータスアッ\\n\u3000プ効果を解除される。\\n\u3000エンジェル状態はＨＰを回復することで解除\\n\u3000される。\\n\u3000このスキルの状態異常はダメージを無効化して\\n\u3000も付与される。\\n・前から３キャラに魔法中ダメージを与え、スタ\\n\u3000ンさせる。\\n\u3000このスキルの状態異常はダメージを無効化して\\n\u3000も付与される。\\n・暴走のイノセントボウ自身のＨＰが40％を切\\n\u3000ると、さらに攻撃が激しく凶暴になる。', 316900, 0, 2, 316900, 270, 0, 0, 16, 0, 1.6, 3000, '暴走のイノセントボウ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【魔法】禍々しい呪縛で幽冥より誘われた悲しき\\n亡親の霊。天に昇ったはずの魂がミロクの術で絶\\n大な魔力となり、立ち塞がる者を容赦なく屠る。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・ユニオンバーストは、最も近い敵１キャラに\\n\u3000魔法大ダメージを与え、さらに魔法防御力を\\n\u3000大ダウンさせる。\\n\u3000このスキルの効果はダメージを無効化しても\\n\u3000付与される。\\n・一番遠くの敵１キャラに物理中ダメージを\\n\u3000与え、さらに一番前にいるキャラの位置まで\\n\u3000引き寄せてスタンさせる。\\n\u3000このスキルの状態異常はダメージを無効化して\\n\u3000も付与される。\\n・最も近い敵１キャラに魔法中ダメージを\\n\u3000与える。\\n\u3000さらに、前方３キャラに魔法中ダメージを\\n\u3000与え、ノックバックさせる。\\n\u3000このスキルの状態異常はダメージを無効化して\\n\u3000も付与される。\\n・ファントムバロン自身のＨＰが40％を切ると、\\n\u3000さらに攻撃が激しく狂暴になる。', 317000, 0, 2, 317000, 270, 0, 0, 16, 0, 1.6, 3000, 'ファントムバロン');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】暴食娘により踊り食いの餌食とされた憤\\n怒の軟体魔獣。体に刻まれた歯形は魔獣の決意。\\nミロクの力を携え、雪辱を晴らすべく猛り狂う。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・ユニオンバーストは、敵全体にキャラの最大\\n\u3000ＨＰに応じた物理割合ダメージを与える。\\n・敵全体にキャラの最大ＨＰに応じた物理割合ダ\\n\u3000メージを与え、物理防御力を大ダウンさせ、麻\\n\u3000痺させる。\\n\u3000このスキルの効果や状態異常はダメージを\\n\u3000無効化しても付与される。\\n・目の前の敵１キャラに物理大ダメージを\\n\u3000与える。\\n・目の前の敵１キャラにキャラの最大ＨＰに応じ\\n\u3000た物理割合ダメージを与える。\\n・テンタパス自身のＨＰが40％を切ると、さら\\n\u3000に攻撃が激しく凶暴になる。', 317100, 0, 1, 317100, 270, 0, 0, 16, 0, 1.6, 3000, 'テンタパス');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】《救い手》から力を授かり変貌を遂げた\\n元貴族議会議長。闇の力を揮い、痛恨の単体攻撃\\nで目の前の敵から順に敵陣を豪腕粉砕する。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・ユニオンバーストは、目の前の敵１キャラに物\\n\u3000理極大ダメージを与える。\\n・目の前の敵１キャラに物理大ダメージを与え、\\n\u3000ノックバックさせる。\\n\u3000このスキルの状態異常はダメージを無効化して\\n\u3000も付与される。\\n・自身の物理攻撃力を大アップさせる。\\n・目の前の敵１キャラに物理大ダメージを与え、\\n\u3000物理防御力を中ダウンさせる。\\n\u3000このスキルの効果はダメージを無効化しても\\n\u3000付与される。\\n・ゴウシン自身のＨＰが50％を切ると、さらに\\n\u3000攻撃が激しく凶暴になる。', 317200, 0, 1, 317200, 270, 0, 0, 16, 0, 1.6, 3000, 'ゴウシン');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】はるか古より迷宮を守護する防衛兵器。\\nミロクの闇の力により凶化された守護の力は、全\\nてを砕く災厄となって世界の前に立ちはだかる。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・ユニオンバーストは、敵全体に物理大ダメージ\\n\u3000を与える。\\n・敵全体に魔法中ダメージを与え、物理防御力と\\n\u3000魔法防御力を大ダウンさせる。\\n\u3000このスキルの効果はダメージを無効化しても\\n\u3000付与される。\\n・目の前の敵１キャラに物理大ダメージを\\n\u3000与える。\\n・アルマ自身のＨＰが40％を切ると、さらに攻\\n\u3000撃が激しく凶暴になる。', 317300, 0, 1, 317300, 270, 0, 0, 16, 0, 1.6, 3000, 'アルマ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】はるか古に生み出された、防衛兵器。\\nミロクの魔能で古代兵器の呪力が解き放たれ、そ\\nの禍は懸河となり無慈悲にも人々に襲い掛かる。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・ユニオンバーストは、敵全体に魔法大ダメージ\\n\u3000を与える。\\n・敵全体に物理中ダメージを与え、物理攻撃力と\\n\u3000魔法攻撃力を中ダウンさせる。\\n\u3000このスキルの効果はダメージを無効化しても\\n\u3000付与される。\\n・敵全体に魔法中ダメージを与え、短時間スタン\\n\u3000させる。\\n\u3000ＨＰが40％未満の場合、長時間スタンさせる。\\n\u3000このスキルの効果はダメージを無効化しても\\n\u3000付与される。\\n・オラム自身のＨＰが70％を切ると、さらに攻\\n\u3000撃が激しく凶暴になる。\\n', 317400, 0, 1, 317400, 270, 0, 0, 16, 0, 1.6, 3000, 'オラム');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】鋼鉄のからくり巨人が再来し、奇怪なる\\n芸術と災厄のコラボレーション。慈悲なき呪言で\\n再び学徒たちの自我を破壊せんとする。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・ユニオンバーストは、敵全体に魔法大ダメージ\\n\u3000を与え、火傷状態にする。\\n\u3000毒状態の場合は火傷ダメージが増加する。\\n\u3000このスキルの状態異常はダメージを無効化して\\n\u3000も付与される。\\n・自身の物理攻撃力を中アップさせたあと、\\n\u3000敵全体に物理中ダメージを与える。\\n\u3000さらに、敵全体のバリアを解除する。\\n・敵全体に魔法中ダメージを与える。\\n\u3000毒状態の場合は行動速度を特大ダウンさせる。\\n\u3000このスキルの効果はダメージを無効化しても\\n\u3000付与される。\\n・なかよしＸ自身のＨＰが40％を切ると、さら\\n\u3000に攻撃が激しく凶暴になる。', 317500, 0, 1, 317500, 270, 0, 0, 16, 0, 1.6, 3000, 'なかよしX');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】人類には早すぎた異形の芸術が再降臨し\\n毒舌ロボと災厄のコラボレーション。作者の奇才\\nも、今や世界を滅ぼす爪牙となるか……？ \\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・ユニオンバーストは、敵全体に魔法大ダメージ\\n\u3000を与え、毒状態にする。\\n・敵全体に物理大ダメージを与える。\\n\u3000毒状態の場合はさらに追加ダメージを与える。\\n・名もなき芸術自身のＨＰが40％を切ると、味\\n\u3000方全員のＴＰを特大アップさせ、さらに攻撃が\\n\u3000激しく凶暴になる。', 317600, 0, 1, 317600, 270, 0, 0, 16, 0, 1.6, 3000, '名もなき芸術');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ１】人々の魂を幽閉すべく、世界を終\\n焉へ導く偽りの救済者。強力な魔法と状態異常を\\n振りまく特殊な術で、抗う者の生命を滅却する。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・ユニオンバーストは、敵全体にキャラの残り\\n\u3000ＨＰに応じた魔法割合ダメージを与える。\\n\u3000さらに、敵全体のＴＰを毎秒小ダウンさせ、\\n\u3000ミロクのＴＰを毎秒小アップさせるフィールド\\n\u3000を展開する。\\n・敵全体に魔法中ダメージを与え、ノックバック\\n\u3000させる。\\n\u3000このスキルの状態異常はダメージを無効化して\\n\u3000も付与される。\\n・敵全体に魔法中ダメージを与え、黒炎状態に\\n\u3000する。\\n\u3000黒炎状態になったキャラは、毎秒ダメージを受\\n\u3000ける。黒炎によるダメージは毎秒10％ずつ\\n\u3000アップする。\\n\u3000このスキルの状態異常はダメージを無効化して\\n\u3000も付与される。', 317700, 0, 2, 317700, 270, 317700, 0, 16, 317700, 1.6, 3000, 'ミロク');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('', 317701, 0, 1, 317701, 270, 0, 0, 16, 0, 1.6, 3000, 'ミロク');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('', 317702, 0, 1, 317702, 270, 0, 0, 16, 0, 1.6, 3000, 'ミロク');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ２】世界を終焉へ導く炎の勢いに乗じ\\n救済者は秘儀を発動する。魔力の無効化により、\\n刻一刻と攻勢を削ぎ人々の絆と絆を打ち砕く。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・バトル開始時、敵全体のＨＰ吸収、ＴＰ上昇、\\n\u3000物理攻撃力、魔法攻撃力、物理防御力、魔法\\n\u3000防御力をバトル終了まで大ダウンさせる。\\n・ユニオンバーストは、敵全体にキャラの残り\\n\u3000ＨＰに応じた魔法割合ダメージを与える。\\n・敵全体に魔法中ダメージを与え、ノックバック\\n\u3000させる。\\n\u3000このスキルの状態異常はダメージを無効化して\\n\u3000も付与される。', 317800, 0, 2, 317800, 270, 317700, 0, 16, 317700, 1.6, 3000, 'ミロク');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ３】真の力を解放し、魔力を暴走させ\\nるミロク。魔法の威力は更に熾烈さを増し、神と\\nの邂逅を隔てんとする全ての敵を尽滅する。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・ユニオンバーストは、敵全体に残りＨＰの\\n\u300099％の魔法割合ダメージを与える。\\n・敵全体に魔法大ダメージを与え、魔法防御力を\\n\u3000中ダウンさせ、バリアを解除する。\\n・自身の魔法攻撃力とＴＰを大アップさせる。\\n・ミロク自身のＨＰが1600万を下回ると、\\n\u3000行動パターンが変化し、さらに攻撃が激しく\\n\u3000凶暴になる。', 317900, 0, 2, 317900, 270, 317700, 0, 16, 317700, 1.6, 3000, 'ミロク');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】和平を引き裂かんと仕掛けられた、牢固\\nたる魔物。黒く輝くその身は何者にも砕けず、圧\\n倒的な質量とパワーを誇る。\\n\\n・ユニオンバーストは、敵全体の最大ＨＰを\\n\u300015％減少させ、物理小ダメージを与える。減\\n\u3000少したＨＰは、バトル終了まで解除できない。\\n\u3000このスキルによるダメージではＴＰが回復\\n\u3000せず、このスキルの状態異常はダメージを\\n\u3000無効化しても付与される。\\n・自身のＴＰを小回復する。\\n・敵全体に物理中ダメージを与え、さらにバトル\\n\u3000終了まで物理防御力を小ダウンさせる。\\n\u3000このスキルの状態異常はダメージを無効化して\\n\u3000も付与される。\\n・前から１番目のキャラに物理中ダメージ。', 318000, 0, 1, 318000, 270, 0, 0, 16, 0, 1.6, 3000, 'オブシダンゴーレム');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】和平を引き裂かんと仕掛けられた、牢固\\nたる魔物。黒く輝くその身は何者にも砕けず、圧\\n倒的な質量とパワーを誇る。\\n\\n・ユニオンバーストは、敵全体の最大ＨＰを\\n\u300015％減少させ、物理小ダメージを与える。減\\n\u3000少したＨＰは、バトル終了まで解除できない。\\n\u3000このスキルによるダメージではＴＰが回復\\n\u3000せず、このスキルの状態異常はダメージを\\n\u3000無効化しても付与される。\\n・自身のＴＰを小回復する。\\n・敵全体に物理中ダメージを与え、さらにバトル\\n\u3000終了まで物理防御力を小ダウンさせる。\\n\u3000このスキルの状態異常はダメージを無効化して\\n\u3000も付与される。\\n・前から１番目のキャラに物理中ダメージ。', 318001, 0, 1, 318000, 270, 0, 0, 16, 0, 1.6, 3000, 'オブシダンゴーレム');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】和平を引き裂かんと仕掛けられた、牢固\\nたる魔物。黒く輝くその身は何者にも砕けず、圧\\n倒的な質量とパワーを誇る。\\n\\n・ユニオンバーストは、敵全体の最大ＨＰを\\n\u300015％減少させ、物理小ダメージを与える。減\\n\u3000少したＨＰは、バトル終了まで解除できない。\\n\u3000このスキルによるダメージではＴＰが回復\\n\u3000せず、このスキルの状態異常はダメージを\\n\u3000無効化しても付与される。\\n・自身のＴＰを小回復する。\\n・敵全体に物理中ダメージを与え、さらにバトル\\n\u3000終了まで物理防御力を小ダウンさせる。\\n\u3000このスキルの状態異常はダメージを無効化して\\n\u3000も付与される。\\n・前から１番目のキャラに物理大ダメージ。', 318002, 0, 1, 318000, 270, 0, 0, 16, 0, 1.6, 3000, 'オブシダンゴーレム');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】和平を引き裂かんと仕掛けられた、牢固\\nたる魔物。黒く輝くその身は何者にも砕けず、圧\\n倒的な質量とパワーを誇る。\\n\\n・ユニオンバーストは、敵全体の最大ＨＰを\\n\u300015％減少させ、物理小ダメージを与える。減\\n\u3000少したＨＰは、バトル終了まで解除できない。\\n\u3000このスキルによるダメージではＴＰが回復\\n\u3000せず、このスキルの状態異常はダメージを\\n\u3000無効化しても付与される。\\n・自身のＴＰを中回復する。\\n・敵全体に物理中ダメージを与え、さらにバトル\\n\u3000終了まで物理防御力を小ダウンさせる。\\n\u3000このスキルの状態異常はダメージを無効化して\\n\u3000も付与される。\\n・前から１番目のキャラに物理大ダメージ。\\n・残りＨＰが40％以下になると自身の物理攻撃\\n\u3000力を中アップさせ、さらに攻撃が激しく凶暴に\\n\u3000なる。', 318003, 0, 1, 318000, 270, 0, 0, 16, 0, 1.6, 3000, 'オブシダンゴーレム');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ１】第一の試練は、岩の魔物と偽りの\\n自身。周りの目を恐れていた、幼き虎はもう居な\\nい。影を乗り越え、ヒーローと成れ。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を中アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・オブシダンゴーレムは環境効果によるダメージ\\n\u3000を受けない。\\n・前から１番目のキャラに物理中ダメージ。', 318004, 0, 1, 318004, 270, 0, 0, 16, 0, 1.6, 3000, 'オブシダンゴーレム');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ２】第二の試練は、如何なる剣戟も阻\\nむ最強の鎧。然し、正攻法だけが総てではない。\\n大義を成すため、持てる術を尽くし敵を打ち崩せ。\\n\\n・バトル開始時、自身の物理防御力を大アップ、\\n\u3000魔法防御力を中アップさせる。この防御力\\n\u3000アップ効果で上昇した防御力は、バトル中に\\n\u3000受ける防御力ダウンスキルの影響を受けない。\\n・オブシダンゴーレムから受けるすべてのダメー\\n\u3000ジで発生する、パーティキャラのＴＰ回復量を\\n\u3000中ダウンさせる。\\n・ユニオンバーストは、敵全体の最大ＨＰを\\n\u300015％減少させ、物理小ダメージを与える。減\\n\u3000少したＨＰは、バトル終了まで解除できない。\\n\u3000このスキルによるダメージではＴＰが回復\\n\u3000せず、このスキルの状態異常はダメージを\\n\u3000無効化しても付与される。\\n・敵全体に物理中ダメージを与え、さらにバトル\\n\u3000終了まで物理防御力を小ダウンさせる。\\n\u3000このスキルの状態異常はダメージを無効化して\\n\u3000も付与される。\\n・前から１番目のキャラに物理中ダメージ。\\n・バトル中、オブシダンゴーレム自身に付与され\\n\u3000ている状態異常効果およびステータスダウン\\n\u3000効果の数に応じて、与えられるダメージの量が\\n\u3000大きく上昇する。', 318005, 0, 1, 318004, 270, 0, 0, 16, 0, 1.6, 3000, 'オブシダンゴーレム');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ３】第三の試練、幕引きの時。追い込\\nまれた魔物は死力を尽くし、万物を圧し潰さんと\\nする。和平の使者よ、その手で未来を切り開け。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を中アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\u3000\\n・オブシダンゴーレムから受けるすべてのダメー\\n\u3000ジで発生する、パーティキャラのＴＰ回復量を\\n\u3000大ダウンさせる。\\n・ユニオンバーストは、敵全体の最大ＨＰを\\n\u300015％減少させ、物理小ダメージを与える。減\\n\u3000少したＨＰは、バトル終了まで解除できない。\\n\u3000このスキルによるダメージではＴＰが回復\\n\u3000せず、このスキルの状態異常はダメージを\\n\u3000無効化しても付与される。\\n・自身のＴＰを中回復する。\\n・敵全体に物理中ダメージを与え、さらにバトル\\n\u3000終了まで物理防御力を小ダウンさせる。\\n\u3000このスキルの状態異常はダメージを無効化して\\n\u3000も付与される。\\n・前から１番目のキャラに物理大ダメージ。\\n・残りＨＰが11％以下になると自身の物理攻撃\\n\u3000力を中アップさせ、さらに攻撃が激しく凶暴に\\n\u3000なる。', 318006, 0, 1, 318004, 270, 0, 0, 16, 0, 1.6, 3000, 'オブシダンゴーレム');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('', 318100, 0, 1, 318100, 270, 0, 0, 16, 0, 1.6, 3000, '穢れし湯ノ神・陽卵');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】『神酔』の力でタガが外れた温泉の神。\\nその身に溜め込んだ罪と穢れを解き放ち、忘年会\\n会場を大混乱の渦に陥れる。\\n\\n・ユニオンバーストは、敵全体に魔法特大ダメー\\n\u3000ジを与え、呪い状態を付与する。既に呪い状態\\n\u3000の敵には代わりに呪詛状態を付与する。呪詛に\\n\u3000よる継続ダメージは毎秒ごとに増加する。\\n・敵全体に魔法小ダメージを与え、呪い状態を付\\n\u3000与する。\\n・自身に近い敵３キャラに物理中ダメージを与え\\n\u3000る。敵のＨＰが30％未満の場合、混乱状態に\\n\u3000する。\\n・自身に近い敵３キャラに物理中ダメージを与え\\n\u3000る。\\n・穢れし湯ノ神・陽卵の付与する呪いおよび呪詛\\n\u3000のダメージでは、キャラのＴＰが回復しない。', 318101, 0, 1, 318100, 270, 0, 0, 16, 0, 1.6, 3000, '穢れし湯ノ神・陽卵');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】『神酔』の力でタガが外れた温泉の神。\\nその身に溜め込んだ罪と穢れを解き放ち、忘年会\\n会場を大混乱の渦に陥れる。\\n\\n・ユニオンバーストは、敵全体に魔法特大ダメー\\n\u3000ジを与え、呪い状態を付与する。既に呪い状態\\n\u3000の敵には代わりに呪詛状態を付与する。呪詛に\\n\u3000よる継続ダメージは毎秒ごとに増加する。\\n・敵全体に魔法小ダメージを与え、呪い状態を付\\n\u3000与する。\\n・自身に近い敵３キャラに物理中ダメージを与え\\n\u3000る。敵のＨＰが30％未満の場合、混乱状態に\\n\u3000する。\\n・自身に近い敵３キャラに物理中ダメージを与え\\n\u3000る。\\n・穢れし湯ノ神・陽卵の付与する呪いおよび呪詛\\n\u3000のダメージでは、キャラのＴＰが回復しない。', 318102, 0, 1, 318100, 270, 0, 0, 16, 0, 1.6, 3000, '穢れし湯ノ神・陽卵');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】『神酔』の力でタガが外れた温泉の神。\\nその身に溜め込んだ罪と穢れを解き放ち、忘年会\\n会場を大混乱の渦に陥れる。\\n\\n・ユニオンバーストは、敵全体に魔法特大ダメー\\n\u3000ジを与え、呪い状態を付与する。既に呪い状態\\n\u3000の敵には代わりに呪詛状態を付与する。呪詛に\\n\u3000よる継続ダメージは毎秒ごとに増加する。\\n・敵全体に魔法小ダメージを与え、呪い状態を付\\n\u3000与する。\\n・自身に近い敵３キャラに物理中ダメージを与え\\n\u3000る。敵のＨＰが30％未満の場合、混乱状態に\\n\u3000する。\\n・自身に近い敵３キャラに物理中ダメージを与え\\n\u3000る。\\n・穢れし湯ノ神・陽卵自身のＨＰが50％を切る\\n\u3000と、さらに攻撃が激しく凶暴になる。\\n・穢れし湯ノ神・陽卵の付与する呪いおよび呪詛\\n\u3000のダメージでは、キャラのＴＰが回復しない。', 318103, 0, 1, 318100, 270, 0, 0, 16, 0, 1.6, 3000, '穢れし湯ノ神・陽卵');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ１】悦楽に溺れる御身から、罪と穢れ\\nが煮え滾る。限外に溢れ出る負の瘴気は、人々に\\n禍をもたらすと供に、自らの身をも蝕む。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・穢れし湯ノ神・陽卵から受けるすべてのダメー\\n\u3000ジで発生する、パーティキャラのＴＰ回復量を\\n\u3000中ダウンさせる。\\n・ユニオンバーストは、敵全体に魔法特大ダメー\\n\u3000ジを与え、呪い状態を付与する。既に呪い状態\\n\u3000の敵には代わりに呪詛状態を付与する。呪詛に\\n\u3000よる継続ダメージは毎秒ごとに増加する。\\n・敵全体に魔法大ダメージを与え、呪い状態を付\\n\u3000与する。さらに、魔法防御力を大ダウンさせる。\\n\u3000その後、自身に呪い状態を付与する。このスキ\\n\u3000ルの状態異常と効果はダメージを無効化しても\\n\u3000付与される。\\n・自身に近い敵３キャラに物理大ダメージを与え\\n\u3000る。\\n・穢れし湯ノ神・陽卵の付与する呪いおよび呪詛\\n\u3000のダメージでは、キャラのＴＰが回復しない。', 318104, 0, 1, 318104, 270, 0, 0, 16, 0, 1.6, 3000, '穢れし湯ノ神・陽卵');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ２】名湯の権化は、争いの最中すら気\\nままに湯を浴み寛ぐ。神をも骨抜きにする至極の\\n湯は、御身を鎮めんとする者への好機となるか？\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・穢れし湯ノ神・陽卵から受けるすべてのダメー\\n\u3000ジで発生する、パーティキャラのＴＰ回復量を\\n\u3000中ダウンさせる。\\n・敵全体に物理小ダメージを与え、ノックバック\\n\u3000させる。さらに、一定範囲内の敵すべての行動\\n\u3000速度を大ダウンさせる。その後、お風呂に浸か\\n\u3000り始める。穢れし湯ノ神・陽卵がお風呂に浸\\n\u3000かっている間、自身の物理防御力と魔法防御力\\n\u3000を極大ダウンさせる。このスキルの状態異常と\\n\u3000効果はダメージを無効化しても付与される。\\n・自身に近い敵３キャラに物理小ダメージを与え\\n\u3000る。', 318105, 0, 1, 318106, 270, 0, 0, 16, 0, 1.6, 3000, '穢れし湯ノ神・陽卵');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ３】宴もたけなわ、初日の出の刻も幾\\nばくも無し。陽卵の宿一同、全身全霊の御もてな\\nし。罪と穢れを取払い、清らかなる新年を迎えん。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・穢れし湯ノ神・陽卵から受けるすべてのダメー\\n\u3000ジで発生する、パーティキャラのＴＰ回復量を\\n\u3000中ダウンさせる。\\n・ユニオンバーストは、敵全体にキャラの最大Ｈ\\n\u3000Ｐに応じた魔法割合ダメージを与え、呪い状態\\n\u3000を付与する。既に呪い状態の敵には代わりに呪\\n\u3000詛状態を付与する。呪詛による継続ダメージは\\n\u3000毎秒ごとに増加する。\\n・敵全体に魔法小ダメージを与え、呪い状態を付\\n\u3000与する。\\n・自身に近い敵３キャラに物理中ダメージを与え\\n\u3000る。敵のＨＰが30％未満の場合、混乱状態に\\n\u3000する。\\n・自身に近い敵３キャラに物理大ダメージを与え\\n\u3000る。\\n・穢れし湯ノ神・陽卵自身のＨＰが50％を切る\\n\u3000と、さらに攻撃が激しく凶暴になる。\\n・穢れし湯ノ神・陽卵の付与する呪いおよび呪詛\\n\u3000のダメージでは、キャラのＴＰが回復しない。', 318106, 0, 1, 318106, 270, 0, 0, 16, 0, 1.6, 3000, '穢れし湯ノ神・陽卵');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('ベースユニット', 318200, 0, 1, 318200, 270, 0, 0, 16, 0, 1.6, 3000, 'アンハッピートレント');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】暴走した魔法により命を得たクリスマス\\nツリー。負の感情に突き動かされ、聖夜の街に不\\n幸を撒き散らそうと大暴れする。\\n\\n・ユニオンバーストは、敵全体にキャラの最大Ｈ\\n\u3000Ｐに応じた物理割合ダメージを与え、短時間ス\\n\u3000タンさせる。\\n\u3000ＨＰが50％未満の敵を長時間スタンさせる。\\n\u3000長時間スタンはダメージを無効化しても付与さ\\n\u3000れる。\\n・敵全体の物理攻撃力と魔法攻撃力を大アップさ\\n\u3000せ、行動速度を中ダウンさせるフィールドを展\\n\u3000開する。\\n・敵全体に物理中ダメージを与える。さらに、後\\n\u3000ろから２番目のキャラを中心とした小範囲内に\\n\u3000継続ＨＰ回復状態を付与する。その後、敵全体\\n\u3000のＴＰを中ダウンさせる。\\n・残り時間が30秒を切るとアンハッピートレン\\n\u3000トの行動速度が中アップし、行動パターンが変\\n\u3000化する。\\n・敵全体の物理攻撃力と魔法攻撃力を中ダウンさ\\n\u3000せるフィールドを展開する。\\n・敵全体に物理中ダメージを与え、ＴＰを中ダウ\\n\u3000ンさせる。\\n・敵全体にキャラの最大ＨＰに応じた物理割合ダ\\n\u3000メージを与える。', 318201, 0, 1, 318200, 270, 0, 0, 16, 0, 1.6, 3000, 'アンハッピートレント');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】暴走した魔法により命を得たクリスマス\\nツリー。負の感情に突き動かされ、聖夜の街に不\\n幸を撒き散らそうと大暴れする。\\n\\n・ユニオンバーストは、敵全体にキャラの最大Ｈ\\n\u3000Ｐに応じた物理割合ダメージを与え、短時間ス\\n\u3000タンさせる。\\n\u3000ＨＰが50％未満の敵を長時間スタンさせる。\\n\u3000長時間スタンはダメージを無効化しても付与さ\\n\u3000れる。\\n・敵全体の物理攻撃力と魔法攻撃力を大アップさ\\n\u3000せ、行動速度を中ダウンさせるフィールドを展\\n\u3000開する。\\n・敵全体に物理中ダメージを与える。さらに、後\\n\u3000ろから２番目のキャラを中心とした小範囲内に\\n\u3000継続ＨＰ回復状態を付与する。その後、敵全体\\n\u3000のＴＰを中ダウンさせる。\\n・残り時間が30秒を切るとアンハッピートレン\\n\u3000トの行動速度が中アップし、行動パターンが変\\n\u3000化する。\\n・敵全体の物理攻撃力と魔法攻撃力を中ダウンさ\\n\u3000せるフィールドを展開する。\\n・敵全体に物理中ダメージを与え、ＴＰを中ダウ\\n\u3000ンさせる。\\n・敵全体にキャラの最大ＨＰに応じた物理割合ダ\\n\u3000メージを与える。', 318202, 0, 1, 318200, 270, 0, 0, 16, 0, 1.6, 3000, 'アンハッピートレント');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】暴走した魔法により命を得たクリスマス\\nツリー。負の感情に突き動かされ、聖夜の街に不\\n幸を撒き散らそうと大暴れする。\\n\\n・ユニオンバーストは、敵全体にキャラの最大Ｈ\\n\u3000Ｐに応じた物理割合ダメージを与え、短時間ス\\n\u3000タンさせる。\\n\u3000ＨＰが50％未満の敵を長時間スタンさせる。\\n\u3000長時間スタンはダメージを無効化しても付与さ\\n\u3000れる。\\n・敵全体の物理攻撃力と魔法攻撃力を大アップさ\\n\u3000せ、行動速度を中ダウンさせるフィールドを展\\n\u3000開する。\\n・敵全体に物理中ダメージを与える。さらに、後\\n\u3000ろから２番目のキャラを中心とした小範囲内に\\n\u3000継続ＨＰ回復状態を付与する。その後、敵全体\\n\u3000のＴＰを中ダウンさせる。\\n・残り時間が45秒を切るとアンハッピートレン\\n\u3000トの行動速度が中アップし、行動パターンが変\\n\u3000化する。\\n・敵全体の物理攻撃力と魔法攻撃力を中ダウンさ\\n\u3000せるフィールドを展開する。\\n・敵全体に物理中ダメージを与え、ＴＰを中ダウ\\n\u3000ンさせる。\\n・敵全体にキャラの最大ＨＰに応じた物理割合ダ\\n\u3000メージを与える。', 318203, 0, 1, 318200, 270, 0, 0, 16, 0, 1.6, 3000, 'アンハッピートレント');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ１】その身が纏う悲憤のオーラが、不\\n幸と共に魔物を雪崩の如く呼び寄せる。人々の幸\\nせと願いを守るために、戦え双子天使！\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・アンハッピートレントとお供のモンスターから\\n\u3000受けるすべてのダメージで発生する、パーティ\\n\u3000キャラのＴＰ回復量を中ダウンさせる。\\n・アンハッピートレントは環境効果によるダメー\\n\u3000ジを受けない。\\n・魔物を召喚し、敵全体をノックバックさせる。\\n・召喚された魔物を１体倒すたびに、残りター\\n\u3000ゲット数が１減少する。\\n\u3000その後、魔物が再度召喚され、敵全体をノック\\n\u3000バックさせる。\\n・敵全体にキャラの最大ＨＰに応じた物理割合ダ\\n\u3000メージを与える。', 318204, 0, 1, 318204, 270, 0, 0, 16, 0, 1.6, 3000, 'アンハッピートレント');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ２】歪んだ祝福により、人々の心を奈\\n落の底へ引きずり込む、悍ましき大木の魔物。聖\\n夜の象徴としての姿は、そこにはもうない。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・アンハッピートレントから受けるすべてのダメ\\n\u3000ージで発生する、パーティキャラのＴＰ回復量\\n\u3000を中ダウンさせる。\\n・ユニオンバーストは、敵全体にキャラの最大Ｈ\\n\u3000Ｐに応じた物理割合ダメージを与える。さらに\\n\u3000ＨＰが65％以上の場合、沈黙状態にする。こ\\n\u3000のスキルの状態異常はダメージを無効化しても\\n\u3000付与される。\\n・後ろから２番目のキャラを中心とした範囲内の\\n\u3000敵に最大ＨＰに応じた物理割合ダメージを与\\n\u3000え、行動速度を大アップさせる。さらにＴＰ\\n\u3000を中ダウンさせる。\\n・敵全体にキャラの最大ＨＰに応じた物理割合ダ\\n\u3000メージを与える。さらにＨＰが85％以上の場\\n\u3000合、ＴＰを中ダウンさせる。', 318205, 0, 1, 318205, 270, 0, 0, 16, 0, 1.6, 3000, 'アンハッピートレント');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ３】姉妹の不和が生んだ怪物が、聖夜\\nの幸せを願う人々の前に立ち塞がる。今こそ姉妹\\nの絆で取り戻せ、ウルトラハッピークリスマス！\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・アンハッピートレントから受けるすべてのダメ\\n\u3000ージで発生する、パーティキャラのＴＰ回復量\\n\u3000を中ダウンさせる。\\n・ユニオンバーストは、敵全体にキャラの最大Ｈ\\n\u3000Ｐに応じた物理割合ダメージを与え、短時間ス\\n\u3000タンさせる。ＨＰが50％未満の敵を長時間ス\\n\u3000タンさせる。長時間スタンはダメージを無効化\\n\u3000しても付与される。\\n・敵全体の物理攻撃力と魔法攻撃力を大アップさ\\n\u3000せ、行動速度を中ダウンさせるフィールドを展\\n\u3000開する。\\n・敵全体に物理中ダメージを与える。さらに、後\\n\u3000ろから２番目のキャラを中心とした小範囲内に\\n\u3000継続ＨＰ回復状態を付与する。その後、敵全体\\n\u3000のＴＰを中ダウンさせる。\\n・残り時間が45秒を切るとアンハッピートレン\\n\u3000トの行動速度が中アップし、行動パターンが変\\n\u3000化する。\\n・敵全体の物理攻撃力と魔法攻撃力を中ダウンさ\\n\u3000せるフィールドを展開する。\\n・敵全体に物理中ダメージを与え、ＴＰを中ダウ\\n\u3000ンさせる。\\n・敵全体にキャラの最大ＨＰに応じた物理割合ダ\\n\u3000メージを与える。', 318206, 0, 1, 318204, 270, 0, 0, 16, 0, 1.6, 3000, 'アンハッピートレント');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('ベースユニット', 318300, 0, 2, 318300, 270, 0, 0, 16, 0, 1.6, 3000, '願福寄災の招き猫');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【魔法】自らの使命に執着し、呪物となり果てた\\n招き猫。行き過ぎたその願いは、幸福だけでなく\\n災いをも引き寄せる。\\n\\n・ユニオンバーストは、最も近い敵１キャラを中\\n\u3000心にした小範囲に魔法大ダメージを与え、スタ\\n\u3000ン状態にし、さらにＴＰを中ダウンさせる。こ\\n\u3000のスキルの状態異常はダメージを無効化しても\\n\u3000付与される。\\n・敵全体に魔法中ダメージを与える。挑発を無視\\n\u3000して、最も近い敵１キャラを自身の目の前まで\\n\u3000引き寄せ、２番目以降に近い敵を小さく引き寄\\n\u3000せる。\\n・最も近い敵１キャラを中心にした小範囲に魔法\\n\u3000小ダメージを与える。\\n・残り時間が50秒を切ると自身を中心に、範囲\\n\u3000内の敵キャラの物理攻撃力と魔法攻撃力を中ダ\\n\u3000ウンさせるフィールドを展開する。', 318301, 0, 2, 318300, 270, 0, 0, 16, 0, 1.6, 3000, '願福寄災の招き猫');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【魔法】自らの使命に執着し、呪物となり果てた\\n招き猫。行き過ぎたその願いは、幸福だけでなく\\n災いをも引き寄せる。\\n\\n・ユニオンバーストは、最も近い敵１キャラを中\\n\u3000心にした小範囲に魔法大ダメージを与え、スタ\\n\u3000ン状態にし、さらにＴＰを中ダウンさせる。こ\\n\u3000のスキルの状態異常はダメージを無効化しても\\n\u3000付与される。\\n・敵全体に魔法中ダメージを与える。挑発を無視\\n\u3000して、最も近い敵１キャラを自身の目の前まで\\n\u3000引き寄せ、２番目以降に近い敵を小さく引き寄\\n\u3000せる。\\n・最も近い敵１キャラを中心にした小範囲に魔法\\n\u3000小ダメージを与える。\\n・残り時間が50秒を切ると自身を中心に、範囲\\n\u3000内の敵キャラの物理攻撃力と魔法攻撃力を中ダ\\n\u3000ウンさせるフィールドを展開する。', 318302, 0, 2, 318300, 270, 0, 0, 16, 0, 1.6, 3000, '願福寄災の招き猫');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【魔法】自らの使命に執着し、呪物となり果てた\\n招き猫。行き過ぎたその願いは、幸福だけでなく\\n災いをも引き寄せる。\\n\\n・ユニオンバーストは、最も近い敵１キャラを中\\n\u3000心にした小範囲に魔法大ダメージを与え、スタ\\n\u3000ン状態にし、さらにＴＰを中ダウンさせる。こ\\n\u3000のスキルの状態異常はダメージを無効化しても\\n\u3000付与される。\\n・敵全体に魔法中ダメージを与える。挑発を無視\\n\u3000して、最も近い敵１キャラを自身の目の前まで\\n\u3000引き寄せ、２番目以降に近い敵を小さく引き寄\\n\u3000せる。\\n・最も近い敵１キャラを中心にした小範囲に魔法\\n\u3000小ダメージを与える。\\n・残り時間が50秒を切ると自身を中心に、範囲\\n\u3000内の敵キャラの物理攻撃力と魔法攻撃力を特大\\n\u3000ダウンさせるフィールドを展開する。', 318303, 0, 2, 318300, 270, 0, 0, 16, 0, 1.6, 3000, '願福寄災の招き猫');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ１】呪物の暴走は止まることなく、数\\n多のしもべを従えて攻勢を層一層強める。白と黒\\nのしもべたちは、あらゆる対敵を拒み退ける。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・願福寄災の招き猫とお供のモンスターから受け\\n\u3000るすべてのダメージで発生する、パーティキャ\\n\u3000ラのＴＰ回復量を中ダウンさせる。\\n・最も近い敵１キャラを中心にした小範囲に魔法\\n\u3000小ダメージを与える。\\n・お供を召喚し、敵全体をノックバックさせる。\\n・召喚されたお供を１体倒すたびに、残りター\\n\u3000ゲット数が１減少する。その後、お供が再度召\\n\u3000喚され、敵全体をノックバックさせる。\\n・白まねきは、物理防御力が高く、最も近い敵１\\n\u3000キャラに物理小ダメージを与える。\\n・黒まねきは、魔法防御力が高く、最も遠くの敵\\n\u3000１キャラに物理小ダメージを与える。', 318304, 0, 2, 318304, 270, 0, 0, 16, 0, 1.6, 3000, '願福寄災の招き猫');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ２】積年の哀しみが込められた招き猫\\nの嘆きは、眼前のすべてに沈黙を強いる。それは\\n自らを救わんとする者の声すらも遮ってしまう。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・願福寄災の招き猫から受けるすべてのダメージ\\n\u3000で発生する、パーティキャラのＴＰ回復量を中\\n\u3000ダウンさせる。\\n・ユニオンバーストは、敵全体に魔法中ダメージ\\n\u3000を与え、沈黙状態を付与する。このスキルの状\\n\u3000態異常はダメージを無効化しても付与される。\\n・敵全体に魔法中ダメージを与え、自身の魔法防\\n\u3000御力を特大アップさせる。\\n・最も近い敵１キャラを中心にした小範囲に魔法\\n\u3000中ダメージを与える。\\n・敵全体に物理中ダメージを与える。', 318305, 0, 2, 318305, 270, 0, 0, 16, 0, 1.6, 3000, '願福寄災の招き猫');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ３】招き猫の真なる力は全てを引き寄\\nせ、止めを刺さんとする。悲歎に塗れたその呪い\\nを解き放ち、笑顔の集うカフェを取り戻せ！\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・願福寄災の招き猫から受けるすべてのダメージ\\n\u3000で発生する、パーティキャラのＴＰ回復量を中\\n\u3000ダウンさせる。\\n・ユニオンバーストは、最も近い敵１キャラを中\\n\u3000心にした小範囲に魔法大ダメージを与え、スタ\\n\u3000ン状態にし、さらにＴＰを中ダウンさせる。こ\\n\u3000のスキルの状態異常はダメージを無効化しても\\n\u3000付与される。\\n・敵全体に魔法中ダメージを与える。挑発を無視\\n\u3000して、最も近い敵１キャラを自身の目の前まで\\n\u3000引き寄せ、２番目以降に近い敵を小さく引き寄\\n\u3000せる。\\n・最も近い敵１キャラを中心にした小範囲に魔法\\n\u3000小ダメージを与える。\\n・残り時間が50秒を切ると自身を中心に、範囲\\n\u3000内の敵キャラの物理攻撃力と魔法攻撃力を特大\\n\u3000ダウン、行動速度を大ダウンさせるフィールド\\n\u3000を展開する。', 318306, 0, 2, 318304, 270, 0, 0, 16, 0, 1.6, 3000, '願福寄災の招き猫');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】深き大海の底にて挑戦者を待ち受ける\\n雄々しき海の化身。その腕が振るう大剣の一閃\\nを前に、立ちはだかる者は海の藻屑へと成り果\\nてる。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・ポセイドンから受けるすべてのダメージで発生\\n\u3000する、パーティキャラのＴＰ回復量を中ダウン\\n\u3000させる。\\n・ユニオンバーストは、最も近い敵１キャラに物\\n\u3000理特大ダメージを与え、さらに敵全体に物理攻\\n\u3000撃力中ダウンと魔法攻撃力中ダウンを付与する。\\n\u3000このスキルの状態異常はダメージを無効化して\\n\u3000も付与される。\\n・最も近い敵１キャラに物理中ダメージを与え、\\n\u3000さらに物理防御力中ダウンを付与する。このス\\n\u3000キルの状態異常はダメージを無効化しても付与\\n\u3000される。\\n・最も近い敵１キャラに物理特大ダメージを与え\\n\u3000る。', 318400, 0, 1, 318400, 600, 0, 0, 0, 0, 1.6, 3000, 'ポセイドン・海神の剣');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【魔法】深き大海の底にて挑戦者を待ち受ける\\n雄々しき海の化身。その杖が放つ魔術は嵐を巻\\nき起こし恵みの海を荒らす不届き者に天罰を下\\nす。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・ポセイドンから受けるすべてのダメージで発生\\n\u3000する、パーティキャラのＴＰ回復量を中ダウン\\n\u3000させる。\\n・ユニオンバーストは、最も近い敵１キャラに魔\\n\u3000法中ダメージを与える。その後、敵全体に魔法\\n\u3000大ダメージを与え、短時間スタン状態を付与す\\n\u3000る。キャラのＨＰが80%未満の場合、長時間\\n\u3000スタン状態を付与する。このスキルの状態異常\\n\u3000はダメージを無効化しても付与される。\\n・敵全体に魔法中ダメージを与える。キャラのＨ\\n\u3000Ｐが80%未満の場合、ＴＰを中ダウンさせる。\\n\u3000このスキルによるダメージでは、敵のＴＰが回\\n\u3000復しない。\\n・最も遠い敵１キャラに魔法大ダメージを与える。', 318401, 0, 2, 318401, 600, 0, 0, 0, 0, 1.6, 3000, 'ポセイドン・大洋の杖');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】深き大海の底にて挑戦者を待ち受ける\\n雄々しき海の化身。その槍の乱撃は荒々しく渦\\nを巻き、万有万物をも水底へと引きずり込む。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・ポセイドンから受けるすべてのダメージで発生\\n\u3000する、パーティキャラのＴＰ回復量を中ダウン\\n\u3000させる。\\n・ユニオンバーストは、前から３番目の敵１キャ\\n\u3000ラを中心にした小範囲の敵３キャラまでに物理\\n\u3000防御力中ダウンと魔法防御力中ダウンを付与し、\\n\u3000その後物理特大ダメージを与える。このスキル\\n\u3000の状態異常はダメージを無効化しても付与され\\n\u3000る。このスキルによるダメージでは、敵のＴＰ\\n\u3000が回復しない。\\n・最も近い敵１キャラに物理大ダメージを与え、\\n\u3000ノックバックさせる。このスキルの状態異常は\\n\u3000ダメージを無効化しても付与される。\\n・前から３番目の敵１キャラを中心にした小範囲\\n\u3000に魔法特大ダメージを与える。\\n・最も近い敵１キャラに物理特大ダメージを与え\\n\u3000る。\\n・残り時間が45秒を切ると、攻撃が激しく凶暴\\n\u3000になり、さらに防御力が上がり頑強になる。\\n・向かって左側のターゲットのブレイク時、自身\\n\u3000の物理防御力と魔法防御力が中ダウン。\\n・中央のターゲットのブレイク時、自身の物理防\\n\u3000御力と魔法防御力が中ダウン。\\n・向かって右側のターゲットのブレイク時、自身\\n\u3000の物理防御力と魔法防御力が中ダウン。', 318402, 0, 1, 318402, 600, 0, 0, 0, 0, 1.6, 3000, 'ポセイドン・嵐撃の槍');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】深き大海の底にて挑戦者を待ち受ける\\n雄々しき海の化身。その拳が放つ一撃は、広大\\n無辺たる海原すらも二つに分かつ必殺の神技。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・ポセイドンから受けるすべてのダメージで発生\\n\u3000する、パーティキャラのＴＰ回復量を中ダウン\\n\u3000させる。\\n・敵全体に物理小ダメージを与え、ＴＰを小ダ\\n\u3000ウンさせる。このスキルはダメージを無効化\\n\u3000してもＴＰをダウンさせる。このスキルによ\\n\u3000るダメージでは、敵のＴＰが回復しない。\\n・最も近い敵１キャラに物理小ダメージを与える。', 318403, 0, 1, 318403, 600, 0, 0, 0, 0, 1.6, 3000, 'ポセイドン・激波の拳');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【魔法】身命を賭す奮戦の末、海神はその比類な\\nき真の力を示す。海の怒りを象るが如き雷槍の一\\n撃でこの戦いに終局をもたらさんとする。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・ポセイドンから受けるすべてのダメージで発生\\n\u3000する、パーティキャラのＴＰ回復量を中ダウン\\n\u3000させる。\\n・ユニオンバーストは、敵全体に物理防御力中ダ\\n\u3000ウンと魔法防御力中ダウンを付与し、その後物\\n\u3000理特大ダメージと魔法特大ダメージを与える。\\n\u3000このスキルの状態異常はダメージを無効化して\\n\u3000も付与される。このスキルによるダメージでは、\\n\u3000敵のＴＰが回復しない。\\n・最も近い敵１キャラに物理大ダメージを与え、\\n\u3000ノックバックさせる。さらにスタン状態を付与\\n\u3000する。このスキルの状態異常はダメージを無効\\n\u3000化しても付与される。\\n・敵全体に魔法大ダメージを与える。\\n・最も近い敵１キャラに物理大ダメージと魔法大\\n\u3000ダメージを与える。\\n・残り時間が30秒を切ると、さらに攻撃が激し\\n\u3000く凶暴になる。', 318404, 0, 2, 318404, 600, 0, 0, 0, 0, 1.6, 3000, 'ポセイドン・雷撃の槍');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('', 318405, 0, 1, 318405, 600, 0, 0, 0, 0, 1.6, 3000, 'ポセイドン');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('', 318500, 0, 2, 318500, 270, 0, 0, 16, 0, 1.4, 3000, '楽園の守護者');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【魔法】思い出の中へ囚われゆくランドソルに\\n突如として現れた異質な魔物。楽園を護らんと\\n冷たく硬い両槍で解放者たちを拒絶する。\\n\\n・ユニオンバーストは、敵全体に魔法大ダメージ\\n\u3000を与え、さらに行動速度を中ダウン、魔法防御\\n\u3000力を小ダウンさせる。\\n\u3000このスキルの状態異常はダメージを無効化して\\n\u3000も付与される。\\n・自身の魔法攻撃力を小アップ、行動速度を大\\n\u3000アップさせる。\\n・前から１番目のキャラに魔法中ダメージ。\\n・向かって左側のターゲットのブレイク時、\\n\u3000物理/魔法防御力が中ダウン。\\n・中央下部のターゲットのブレイク時、\\n\u3000物理/魔法防御力が大ダウン。\\n・中央上部のターゲットのブレイク時、\\n\u3000物理/魔法防御力が大ダウン。\\n・向かって右側のターゲットのブレイク時、\\n\u3000物理/魔法防御力が特大ダウン。', 318501, 0, 2, 318500, 270, 0, 0, 16, 0, 1.4, 3000, '楽園の守護者');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【魔法】思い出の中へ囚われゆくランドソルに\\n突如として現れた異質な魔物。楽園を護らんと\\n冷たく硬い両槍で解放者たちを拒絶する。\\n\\n・ユニオンバーストは、敵全体に魔法大ダメージ\\n\u3000を与え、さらに行動速度を中ダウン、魔法防御\\n\u3000力を小ダウンさせる。\\n\u3000このスキルの状態異常はダメージを無効化して\\n\u3000も付与される。\\n・自身の魔法攻撃力を小アップ、行動速度を大\\n\u3000アップさせる。\\n・前から１番目のキャラに魔法中ダメージ。\\n・向かって左側のターゲットのブレイク時、\\n\u3000物理/魔法防御力が中ダウン。\\n・中央下部のターゲットのブレイク時、\\n\u3000物理/魔法防御力が大ダウン。\\n・中央上部のターゲットのブレイク時、\\n\u3000物理/魔法防御力が大ダウン。\\n・向かって右側のターゲットのブレイク時、\\n\u3000物理/魔法防御力が特大ダウン。', 318502, 0, 2, 318500, 270, 0, 0, 16, 0, 1.4, 3000, '楽園の守護者');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【魔法】思い出の中へ囚われゆくランドソルに\\n突如として現れた異質な魔物。楽園を護らんと\\n冷たく硬い両槍で解放者たちを拒絶する。\\n\\n・ユニオンバーストは、敵全体に魔法大ダメージ\\n\u3000を与え、さらに行動速度を中ダウン、魔法防御\\n\u3000力を小ダウンさせる。\\n\u3000このスキルの状態異常はダメージを無効化して\\n\u3000も付与される。\\n・自身の魔法攻撃力を小アップ、行動速度を大\\n\u3000アップさせる。\\n・前から１番目のキャラに魔法中ダメージ。\\n・残り時間が25秒を切ると、自身の魔法攻撃力\\n\u3000を小アップ、自身のＴＰを大アップさせる。\\n・向かって左側のターゲットのブレイク時、\\n\u3000物理/魔法防御力が中ダウン。\\n・中央下部のターゲットのブレイク時、\\n\u3000物理/魔法防御力が大ダウン。\\n・中央上部のターゲットのブレイク時、\\n\u3000物理/魔法防御力が大ダウン。\\n・向かって右側のターゲットのブレイク時、\\n\u3000物理/魔法防御力が特大ダウン。', 318503, 0, 2, 318500, 270, 0, 0, 16, 0, 1.4, 3000, '楽園の守護者');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ１】堅牢な障壁が幾層にも重なり行く\\n手を阻む。必死に己を守る姿は、歪んだこの園に\\nすがるかのごとく、どこか虚しさと儚さが滲む。\\n\\n・このバトルでは、全てのターゲットがブレイク\\n\u3000無効。\\n・バリアを張り、敵の攻撃を受け付けなくなる。\\n\u3000バリアはダメージを与えるたびに徐々に耐久性\\n\u3000を失っていき、一定量のダメージを与えるとバ\\n\u3000リアは破壊される。\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を中アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・ユニオンバーストは、敵全体に魔法大ダメージ\\n\u3000を与え、さらに行動速度を中ダウン、魔法防御\\n\u3000力を小ダウンさせる。\\n\u3000このスキルの状態異常はダメージを無効化して\\n\u3000も付与される。\\n・自身の魔法攻撃力を小アップ、行動速度を大\\n\u3000アップさせる。\\n・前から１番目のキャラに魔法中ダメージ。この\\n\u3000スキルによるダメージでは、ＴＰ回復量は減少\\n\u3000する。', 318504, 0, 2, 318504, 270, 0, 0, 16, 0, 1.4, 3000, '楽園の守護者');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ２】思い出の一端から、大切な二人の\\n虚像が立ち浮かぶ。かけがえのない宝物をこれ以\\n上汚させまいと、少女は自身を奮い立たせる。\\n\\n・このバトルでは、全てのターゲットがブレイク\\n\u3000無効。\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を中アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・楽園の守護者とお供のモンスターから受けるす\\n\u3000べてのダメージで発生する、パーティキャラの\\n\u3000ＴＰ回復量を大ダウンさせる。\\n・自身の魔法攻撃力を小アップ、行動速度を大\\n\u3000アップさせる。\\n・前から１番目のキャラに魔法中ダメージ。', 318505, 0, 2, 318505, 270, 0, 0, 16, 0, 1.4, 3000, '楽園の守護者');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ３】暗く淀んだ不気味な魔物は、最期\\nの時まで足掻くように戦い続ける。不屈なる想い\\nと目覚めし力を手に、未来への道を切り拓け。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を中アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\u3000\\n・楽園の守護者から受けるすべてのダメージで発\\n\u3000生する、パーティキャラのＴＰ回復量を大ダウ\\n\u3000ンさせる。\\n・ユニオンバーストは、敵全体に魔法大ダメージ\\n\u3000を与え、さらに行動速度を中ダウン、魔法防御\\n\u3000力を小ダウンさせる。\\n\u3000このスキルの状態異常はダメージを無効化して\\n\u3000も付与される。\\n・自身の魔法攻撃力を中アップ、行動速度を大\\n\u3000アップさせる。\\n・前から１番目のキャラに魔法中ダメージ。\\n・残り体力が25％を切ると自身の魔法攻撃力を\\n\u3000大アップ、自身のＴＰを大アップさせる。\\n・向かって左側のターゲットのブレイク時、\\n\u3000物理/魔法防御力が中ダウン。\\n・中央下部のターゲットのブレイク時、\\n\u3000物理/魔法防御力が大ダウン。\\n・中央上部のターゲットのブレイク時、\\n\u3000物理/魔法防御力が大ダウン。\\n・向かって右側のターゲットのブレイク時、\\n\u3000物理/魔法防御力が特大ダウン。', 318506, 0, 2, 318505, 270, 0, 0, 16, 0, 0.8, 3000, '楽園の守護者');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('', 318600, 0, 2, 318600, 270, 0, 0, 16, 0, 1.6, 3000, '久遠の園を象る者');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【魔法】永遠の幸福に満ちた楽園の創造主。未来\\nを拒み、己が姿を変え、明日を望む者たちの行く\\n手を阻む。\\n\\n・ユニオンバーストは、敵全体のバリアを解除し、\\n\u3000敵全体に自身の魔法攻撃力とキャラの最大ＨＰ\\n\u3000に応じた魔法割合ダメージを与える。敵のＨＰ\\n\u3000が50％未満の場合、束縛状態にする。このス\\n\u3000キルの状態異常はダメージを無効化しても付与\\n\u3000される。\\n・敵全体のステータスアップ効果を解除した後、\\n\u3000敵全体に魔法小ダメージを与え、沈黙状態を付\\n\u3000与する。さらに、自身の物理防御力と魔法防御\\n\u3000力を中ダウンさせる。このスキルの状態異常は\\n\u3000ダメージを無効化しても付与される。\\n・最も近い敵１キャラに魔法小ダメージを与える。', 318601, 0, 2, 318600, 270, 0, 0, 16, 0, 1.6, 3000, '久遠の園を象る者');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【魔法】永遠の幸福に満ちた楽園の創造主。未来\\nを拒み、己が姿を変え、明日を望む者たちの行く\\n手を阻む。\\n\\n・ユニオンバーストは、敵全体のバリアを解除し、\\n\u3000敵全体に自身の魔法攻撃力とキャラの最大ＨＰ\\n\u3000に応じた魔法割合ダメージを与える。敵のＨＰ\\n\u3000が50％未満の場合、束縛状態にする。このス\\n\u3000キルの状態異常はダメージを無効化しても付与\\n\u3000される。\\n・敵全体のステータスアップ効果を解除した後、\\n\u3000敵全体に魔法小ダメージを与え、沈黙状態を付\\n\u3000与する。さらに、自身の物理防御力と魔法防御\\n\u3000力を中ダウンさせる。このスキルの状態異常は\\n\u3000ダメージを無効化しても付与される。\\n・最も近い敵１キャラに魔法小ダメージを与える。', 318602, 0, 2, 318600, 270, 0, 0, 16, 0, 1.6, 3000, '久遠の園を象る者');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【魔法】永遠の幸福に満ちた楽園の創造主。未来\\nを拒み、己が姿を変え、明日を望む者たちの行く\\n手を阻む。\\n\\n・ユニオンバーストは、敵全体のバリアを解除し、\\n\u3000敵全体に自身の魔法攻撃力とキャラの最大ＨＰ\\n\u3000に応じた魔法割合ダメージを与える。敵のＨＰ\\n\u3000が50％未満の場合、束縛状態にする。このス\\n\u3000キルの状態異常はダメージを無効化しても付与\\n\u3000される。\\n・敵全体のステータスアップ効果を解除した後、\\n\u3000敵全体に魔法小ダメージを与え、沈黙状態を付\\n\u3000与する。さらに、自身の物理防御力と魔法防御\\n\u3000力を中ダウンさせる。このスキルの状態異常は\\n\u3000ダメージを無効化しても付与される。\\n・最も近い敵１キャラに魔法大ダメージを与える。\\n・自身のＨＰが50％を切ると、行動パターンが\\n\u3000変化し、さらに攻撃が激しく凶暴になる。', 318603, 0, 2, 318600, 270, 0, 0, 16, 0, 1.6, 3000, '久遠の園を象る者');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ１】明日から目を背けし創造主は、己\\nを縛る鎖で解放者達を楽園に捕わんとする。未来\\nへと進む強い決意で、幾重にも連なる鎖を断て。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・ユニオンバーストは、敵全体のバリアを解除し、\\n\u3000敵全体に自身の魔法攻撃力とキャラの最大ＨＰ\\n\u3000に応じた魔法割合ダメージを与える。敵のＨＰ\\n\u3000が50％未満の場合、束縛状態にする。このス\\n\u3000キルの状態異常はダメージを無効化しても付与\\n\u3000される。このスキルによるダメージでは、パー\\n\u3000ティキャラのＴＰ回復量は中ダウンする。\\n・自身の物理防御力と魔法防御力を特大ダウンさ\\n\u3000せ、鎖を展開する。一定時間後、敵全体にキャ\\n\u3000ラの最大ＨＰに応じた魔法割合ダメージを与え\\n\u3000束縛状態にする。鎖を展開中、自身が一定ダメ\\n\u3000ージを受けると、スキルが中断され、バトル終\\n\u3000了まで自身の物理防御力と魔法防御力を中ダウ\\n\u3000ンさせる。このスキルを中断させるために必要\\n\u3000なダメージは、このスキルが使用される毎に増\\n\u3000加する。\\n・最も近い敵１キャラに魔法小ダメージを与える。\\n\u3000このスキルによるダメージでは、パーティキャ\\n\u3000ラのＴＰ回復量は中ダウンする。', 318604, 0, 2, 318604, 270, 0, 0, 16, 0, 1.6, 3000, '久遠の園を象る者');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ２】甘美な追想の幸福と未来への不安\\nは、楽園に解放者達の虚像を生み出す。未来への\\n希望を力に変えて、自らの贋物を打ち砕け。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・久遠の園を象る者から受けるすべてのダメージ\\n\u3000で発生する、パーティキャラのＴＰ回復量を中\\n\u3000ダウンさせる。\\n・ノゾミ、ムイミ、カヤのシャドウを召喚。\\n・最も近い敵１キャラに魔法小ダメージを与える。', 318605, 0, 2, 318605, 270, 0, 0, 16, 0, 1.6, 3000, '久遠の園を象る者');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ３】大切な人の声すら届かず、創造主\\nは己を拒む者たちに終の力を放たんとする。仲間\\nとともに、相棒とともに、眩き未来を取り戻せ。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・久遠の園を象る者から受けるすべてのダメージ\\n\u3000で発生する、パーティキャラのＴＰ回復量を中\\n\u3000ダウンさせる。\\n・ユニオンバーストは、敵全体のバリアを解除し、\\n\u3000敵全体に自身の魔法攻撃力とキャラの最大ＨＰ\\n\u3000に応じた魔法割合ダメージを与える。敵のＨＰ\\n\u3000が50％未満の場合、束縛状態にする。このス\\n\u3000キルの状態異常はダメージを無効化しても付与\\n\u3000される。\\n・敵全体のステータスアップ効果を解除した後、\\n\u3000敵全体に魔法中ダメージを与え、沈黙状態を付\\n\u3000与し、ＨＰ吸収を特大ダウンさせる。さらに、\\n\u3000自身の物理防御力と魔法防御力を中ダウンさせ\\n\u3000る。このスキルの状態異常と効果はダメージを\\n\u3000無効化しても付与される。\\n・最も近い敵１キャラに魔法大ダメージを与える。\\n・自身のＨＰが50％を切ると、行動パターンが\\n\u3000変化し、さらに攻撃が激しく凶暴になる。', 318606, 0, 2, 318605, 270, 0, 0, 16, 0, 1.6, 3000, '久遠の園を象る者');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】次元の狭間に誕生した、生きた財宝。\\n煌めく財貨を散しながら、冒険者に襲い掛かる。\\n\\n・ユニオンバーストは、敵全体に物理大ダメージ\\n\u3000を与え、物理攻撃力と魔法攻撃力を大ダウンさ\\n\u3000せる。その後、自身の物理防御力と魔法防御力\\n\u3000を特大ダウン。このスキルの状態異常はダメー\\n\u3000ジを無効化しても付与される。\\n・敵全体に物理中ダメージを与え、スタンさせる。\\n\u3000その後、自身の物理防御力と魔法防御力を特大\\n\u3000ダウン。このスキルの状態異常はダメージを無\\n\u3000効化しても付与される。\\n・前方３キャラに物理中ダメージを与え、ノック\\n\u3000バックさせる。その後、自身の物理防御力と魔\\n\u3000法防御力を特大ダウン。このスキルの状態異常\\n\u3000はダメージを無効化しても付与される。\\n・目の前の１キャラに物理中ダメージを与える。\\n\u3000その後、自身の物理防御力と魔法防御力を特大\\n\u3000ダウン。', 318700, 0, 1, 318700, 270, 0, 0, 16, 0, 1.6, 3000, 'リッチゴーレム');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('', 318800, 0, 1, 318800, 270, 0, 0, 16, 0, 1.6, 3000, 'ダイオウショウジョウ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】森の奥深くにて生き物たちを見守る心優\\nしき猿の魔物。しかし虫歯の苦痛に我を忘れ、森\\nを傷付ける荒くれ者へと変貌した。\\n\\n・ユニオンバーストは、最も近い敵１キャラに物\\n\u3000理特大ダメージを与え、スタンさせる。さら\\n\u3000に敵全体に物理大ダメージを与える。その後、\\n\u3000自身の物理防御力と魔法防御力を小ダウンする。\\n・最も近い敵１キャラを中心にした小範囲に物理\\n\u3000防御力を大ダウンさせ、物理特大ダメージを与\\n\u3000える。さらにスタンさせる。このスキルの状態\\n\u3000異常はダメージを無効化しても付与される。そ\\n\u3000の後、自身の物理防御力と魔法防御力を小ダウ\\n\u3000ンする。\\n・自身のＴＰを中回復し、行動速度を大アップす\\n\u3000る。その後、自身の物理防御力と魔法防御力を\\n\u3000小ダウンする。\\n・最も近い敵１キャラに物理特大ダメージを与え\\n\u3000る。その後、自身の物理防御力と魔法防御力を\\n\u3000小ダウンする。', 318801, 0, 1, 318800, 270, 0, 0, 16, 0, 1.6, 3000, 'ダイオウショウジョウ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】森の奥深くにて生き物たちを見守る心優\\nしき猿の魔物。しかし虫歯の苦痛に我を忘れ、森\\nを傷付ける荒くれ者へと変貌した。\\n\\n・ユニオンバーストは、最も近い敵１キャラに物\\n\u3000理特大ダメージを与え、スタンさせる。さら\\n\u3000に敵全体に物理大ダメージを与える。その後、\\n\u3000自身の物理防御力と魔法防御力を小ダウンする。\\n・最も近い敵１キャラを中心にした小範囲に物理\\n\u3000防御力を大ダウンさせ、物理特大ダメージを与\\n\u3000える。さらにスタンさせる。このスキルの状態\\n\u3000異常はダメージを無効化しても付与される。そ\\n\u3000の後、自身の物理防御力と魔法防御力を小ダウ\\n\u3000ンする。\\n・自身のＴＰを中回復し、行動速度を大アップす\\n\u3000る。その後、自身の物理防御力と魔法防御力を\\n\u3000小ダウンする。\\n・最も近い敵１キャラに物理特大ダメージを与え\\n\u3000る。その後、自身の物理防御力と魔法防御力を\\n\u3000小ダウンする。', 318802, 0, 1, 318800, 270, 0, 0, 16, 0, 1.6, 3000, 'ダイオウショウジョウ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】森の奥深くにて生き物たちを見守る心優\\nしき猿の魔物。しかし虫歯の苦痛に我を忘れ、森\\nを傷付ける荒くれ者へと変貌した。\\n\\n・ユニオンバーストは、最も近い敵１キャラに物\\n\u3000理特大ダメージを与え、スタンさせる。さら\\n\u3000に敵全体に物理大ダメージを与える。その後、\\n\u3000自身の物理防御力と魔法防御力を小ダウンする。\\n・最も近い敵１キャラを中心にした小範囲に物理\\n\u3000防御力を大ダウンさせ、物理特大ダメージを与\\n\u3000える。さらにスタンさせる。このスキルの状態\\n\u3000異常はダメージを無効化しても付与される。そ\\n\u3000の後、自身の物理防御力と魔法防御力を小ダウ\\n\u3000ンする。\\n・自身のＴＰを中回復し、行動速度を大アップす\\n\u3000る。その後、自身の物理防御力と魔法防御力を\\n\u3000小ダウンする。\\n・自身のＨＰが50％を切ると、さらに攻撃が激\\n\u3000しく凶暴になる。その後、自身の物理防御力と\\n\u3000魔法防御力を小ダウンする。\\n・最も近い敵１キャラに物理特大ダメージを与え\\n\u3000る。その後、自身の物理防御力と魔法防御力を\\n\u3000小ダウンする。', 318803, 0, 1, 318800, 270, 0, 0, 16, 0, 1.6, 3000, 'ダイオウショウジョウ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ１】苦痛に我を失った大猿は、愛する\\n森の仲間たちをも拒絶する。憩える自然を願い戦\\nうレンジャーたちの、強き想いが今試される。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・バトル開始時、自身にＴＰダウン50%カット\\n\u3000効果を付与する。\\n・ダイオウショウジョウから受けるすべてのダ\\n\u3000メージで発生する、パーティキャラのＴＰ回復\\n\u3000量を中ダウンさせる。\\n・ユニオンバーストは、最も近い敵１キャラに物\\n\u3000理大ダメージを与え、スタンさせる。さらに敵\\n\u3000全体に物理大ダメージを与える。\\n・自身の物理攻撃力を大アップし、行動速度を極\\n\u3000大アップする。\\n・最も近い敵１キャラに物理大ダメージを与え\\n\u3000る。', 318804, 0, 1, 318804, 270, 0, 0, 16, 0, 1.6, 3000, 'ダイオウショウジョウ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ２】魔物を想うレンジャーたちに、大\\n猿は森をも揺すぶり震わす咆哮で迎え撃つ。\\n人と魔物は、分かりあうことができるのか――\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・ダイオウショウジョウから受けるすべてのダ\\n\u3000メージで発生する、パーティキャラのＴＰ回復\\n\u3000量を中ダウンさせる。\\n・ユニオンバーストは、最も近い敵１キャラに物\\n\u3000理特大ダメージを与える。さらに敵全体に物理\\n\u3000大ダメージを与え、スタンさせる。このスキル\\n\u3000によるダメージでは、敵のＴＰが回復しない。\\n\u3000このスキルの状態異常はダメージを無効化して\\n\u3000も付与される。\\n・最も近い敵１キャラを中心にした小範囲に物理\\n\u3000防御力を大ダウンさせ、物理特大ダメージを与\\n\u3000える。このスキルの状態異常はダメージを無効\\n\u3000化しても付与される。\\n・最も近い敵１キャラに物理大ダメージを与え\\n\u3000る。\\n・力を溜め始め、毎秒ＴＰを中回復する。その\\n\u3000間、自身の物理防御力と魔法防御力を特大ダウ\\n\u3000ンさせる。力を溜めている最中、自身が一定ダ\\n\u3000メージを受けると、スキルが中断され、自身の\\n\u3000ＴＰを大ダウンする。\\n\u3000力を溜め終えると、自身の物理攻撃力を特大ア\\n\u3000ップする。', 318805, 0, 1, 318805, 270, 0, 0, 16, 0, 1.6, 3000, 'ダイオウショウジョウ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ３】魔物との共存を賭した戦いも、ま\\nもなく幕切れの時。傷つけるためでなく想いを届\\nけるために、レンジャーは最後の力を振り絞る！\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・ダイオウショウジョウから受けるすべてのダ\\n\u3000メージで発生する、パーティキャラのＴＰ回復\\n\u3000量を中ダウンさせる。\\n・ユニオンバーストは、最も近い敵１キャラに物\\n\u3000理特大ダメージを与え、スタンさせる。さら\\n\u3000に敵全体に物理大ダメージを与える。その後、\\n\u3000自身の物理防御力と魔法防御力を小ダウンする。\\n・最も近い敵１キャラを中心にした小範囲に物理\\n\u3000防御力を大ダウンさせ、物理特大ダメージを与\\n\u3000える。さらにスタンさせる。このスキルの状態\\n\u3000異常はダメージを無効化しても付与される。そ\\n\u3000の後、自身の物理防御力と魔法防御力を小ダウ\\n\u3000ンする。\\n・自身のＴＰを中回復し、行動速度を大アップす\\n\u3000る。その後、自身の物理防御力と魔法防御力を\\n\u3000小ダウンする。\\n・自身のＨＰが50％を切ると、さらに攻撃が激\\n\u3000しく凶暴になる。その後、自身の物理防御力と\\n\u3000魔法防御力を小ダウンする。\\n・最も近い敵１キャラに物理特大ダメージを与え\\n\u3000る。その後、自身の物理防御力と魔法防御力を\\n\u3000小ダウンする。', 318806, 0, 1, 318806, 270, 0, 0, 16, 0, 1.6, 3000, 'ダイオウショウジョウ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('', 318900, 0, 1, 318900, 270, 0, 0, 16, 0, 1.6, 3000, '変貌せし従者・ブラド');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】己の身に余るほどの魔力を取り込み変貌\\nした従者。我を忘れ、信奉するものにさえその牙\\nを向ける。\\n\\n・ユニオンバーストは、敵全体のバリアを解除\\n\u3000し、自身の物理攻撃力に応じた物理割合ダメー\\n\u3000ジを与える。このスキルのバリア解除はダメー\\n\u3000ジを無効化しても付与される。\\n・敵全体の物理攻撃力と魔法攻撃力を大ダウンさ\\n\u3000せる。さらに自身の物理攻撃力を特大アップさ\\n\u3000せる。\\n・物理攻撃力もしくは魔法攻撃力が最も高い敵\\n\u3000１キャラに魔法小ダメージを与え、誘惑状態を\\n\u3000付与する。さらにステータスアップ効果を解除\\n\u3000する。このスキルの効果はダメージを無効化し\\n\u3000ても付与される。\\n・最も近い敵１キャラに物理大ダメージを与え\\n\u3000る。', 318901, 0, 1, 318900, 270, 0, 0, 16, 0, 1.6, 3000, '変貌せし従者・ブラド');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】己の身に余るほどの魔力を取り込み変貌\\nした従者。我を忘れ、信奉するものにさえその牙\\nを向ける。\\n\\n・ユニオンバーストは、敵全体のバリアを解除\\n\u3000し、自身の物理攻撃力に応じた物理割合ダメー\\n\u3000ジを与える。このスキルのバリア解除はダメー\\n\u3000ジを無効化しても付与される。\\n・敵全体の物理攻撃力と魔法攻撃力を大ダウンさ\\n\u3000せる。さらに自身の物理攻撃力を特大アップさ\\n\u3000せる。\\n・物理攻撃力もしくは魔法攻撃力が最も高い敵\\n\u3000１キャラに魔法小ダメージを与え、誘惑状態を\\n\u3000付与する。さらにステータスアップ効果を解除\\n\u3000する。このスキルの効果はダメージを無効化し\\n\u3000ても付与される。\\n・最も近い敵１キャラに物理大ダメージを与え\\n\u3000る。', 318902, 0, 1, 318900, 270, 0, 0, 16, 0, 1.6, 3000, '変貌せし従者・ブラド');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】己の身に余るほどの魔力を取り込み変貌\\nした従者。我を忘れ、信奉するものにさえその牙\\nを向ける。\\n\\n・ユニオンバーストは、敵全体のバリアを解除\\n\u3000し、自身の物理攻撃力に応じた物理割合ダメー\\n\u3000ジを与える。このスキルのバリア解除はダメー\\n\u3000ジを無効化しても付与される。\\n・敵全体の物理攻撃力と魔法攻撃力を大ダウンさ\\n\u3000せる。さらに自身の物理攻撃力を特大アップさ\\n\u3000せる。\\n・物理攻撃力もしくは魔法攻撃力が最も高い敵\\n\u3000１キャラに魔法小ダメージを与え、誘惑状態を\\n\u3000付与する。さらにステータスアップ効果を解除\\n\u3000する。このスキルの効果はダメージを無効化し\\n\u3000ても付与される。\\n・自身のＨＰが50％を切ると、自身の物理攻撃\\n\u3000力を大アップさせ、行動速度を特大アップさせ\\n\u3000る。\\n・最も近い敵１キャラに物理大ダメージを与え\\n\u3000る。', 318903, 0, 1, 318900, 270, 0, 0, 16, 0, 1.6, 3000, '変貌せし従者・ブラド');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ１】膨大な魔力をその身に宿し、強大\\nな魔物となった敬虔な従者。その力は刻一刻と増\\n幅し続け、触れるもの全てを闇へ葬る。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を中アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・変貌せし従者・ブラドから受けるすべてのダ\\n\u3000メージで発生する、パーティキャラのＴＰ回復\\n\u3000量を中ダウンさせる。\\n・ユニオンバーストは、敵全体のバリアを解除\\n\u3000し、自身の物理攻撃力に応じた物理割合ダメー\\n\u3000ジを与える。このスキルのバリア解除はダメー\\n\u3000ジを無効化しても付与される。\\n・敵全体の物理攻撃力を特大ダウンさせ、魔法攻\\n\u3000撃力を小ダウンさせる。さらに自身の物理攻撃\\n\u3000力を大アップさせ、ＴＰを中回復する。このス\\n\u3000キルの効果は発動するたびにアップする。', 318904, 0, 1, 318904, 270, 0, 0, 16, 0, 1.6, 3000, '変貌せし従者・ブラド');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ２】魔物たちの憧憬の思いが堰を切っ\\nた。多大なる恩恵を我先に得ようと狂暴化した魔\\n物たちが、大群となって押し寄せる。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を中アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・変貌せし従者・ブラドは環境効果によるダメー\\n\u3000ジを受けない。\\n・敵全体の物理攻撃力と魔法攻撃力を大ダウンさ\\n\u3000せる。さらに味方全体の物理攻撃力を特大アッ\\n\u3000プさせる。', 318905, 0, 1, 318905, 270, 0, 0, 16, 0, 1.6, 3000, '変貌せし従者・ブラド');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ３】己が大願の希望の手綱を逃すまい\\nとして、莫大な魔力を纏い荒れ狂う従者。古の意\\n思を打ち砕き、美しく勝利を飾れ！\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・変貌せし従者・ブラドから受けるすべてのダ\\n\u3000メージで発生する、パーティキャラのＴＰ回復\\n\u3000量を中ダウンさせる。\\n・ユニオンバーストは、敵全体のバリアを解除\\n\u3000し、自身の物理攻撃力に応じた物理割合ダメー\\n\u3000ジを与える。このスキルのバリア解除はダメー\\n\u3000ジを無効化しても付与される。\\n・敵全体の物理攻撃力と魔法攻撃力を大ダウンさ\\n\u3000せる。さらに自身の物理攻撃力を大アップさ\\n\u3000せる。\\n・敵の挑発を無視して、物理攻撃力もしくは魔法\\n\u3000攻撃力が最も高い敵１キャラに魔法小ダメージ\\n\u3000を与え、誘惑状態を付与する。さらにステータ\\n\u3000スアップ効果を解除する。このスキルの効果は\\n\u3000ダメージを無効化しても付与される。\\n・自身のＨＰが50％を切ると、自身の物理攻撃\\n\u3000力を大アップさせ、行動速度を特大アップさせ\\n\u3000る。\\n・最も近い敵１キャラに物理大ダメージを与え\\n\u3000る。', 318906, 0, 1, 318904, 270, 0, 0, 16, 0, 1.6, 3000, '変貌せし従者・ブラド');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】遥か北の海で再び相見えた幻島の巨鯨。\\n人々の秘密に潜む欲望を貪り海底深くで生きなが\\nらえる。\\n\\n・ユニオンバーストは、敵全体にキャラの最大\\n\u3000ＨＰに応じた物理割合ダメージを与える。さら\\n\u3000に、物理攻撃力と魔法攻撃力を大ダウンさせ\\n\u3000る。このスキルの状態異常はダメージを無効化\\n\u3000しても付与される。\\n・敵全体にキャラの最大ＨＰに応じた魔法割合ダ\\n\u3000メージを与える。このスキルの割合ダメージ\\n\u3000は、秘密ブツの数に応じて、与えられるダメー\\n\u3000ジ量が大きく上昇する。\\n・最も近い敵３キャラに魔法中ダメージを与え、\\n\u3000ノックバックさせると同時にスタンさせる。こ\\n\u3000のスキルの状態異常はダメージを無効化しても\\n\u3000付与される。\\n・最も近い敵１キャラに物理大ダメージを与え\\n\u3000る。\\n・秘密ブツを３体召喚する。召喚する際は敵全体\\n\u3000をノックバックさせる。秘密ブツは敵全体の物\\n\u3000理攻撃力と魔法攻撃力を小ダウンさせる。秘密\\n\u3000ブツのＨＰが一定値以下になった時、敵全体の\\n\u3000物理攻撃力と魔法攻撃力を大アップさせ、消滅\\n\u3000する。', 319000, 0, 1, 319000, 270, 0, 0, 16, 0, 1.6, 3000, '復活の白き島クジラ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】遥か北の海で再び相見えた幻島の巨鯨。\\n人々の秘密に潜む欲望を貪り海底深くで生きなが\\nらえる。\\n\\n・ユニオンバーストは、敵全体にキャラの最大\\n\u3000ＨＰに応じた物理割合ダメージを与える。さら\\n\u3000に、物理攻撃力と魔法攻撃力を大ダウンさせ\\n\u3000る。このスキルの状態異常はダメージを無効化\\n\u3000しても付与される。\\n・敵全体にキャラの最大ＨＰに応じた魔法割合ダ\\n\u3000メージを与える。このスキルの割合ダメージ\\n\u3000は、秘密ブツの数に応じて、与えられるダメー\\n\u3000ジ量が大きく上昇する。\\n・最も近い敵３キャラに魔法中ダメージを与え、\\n\u3000ノックバックさせると同時にスタンさせる。こ\\n\u3000のスキルの状態異常はダメージを無効化しても\\n\u3000付与される。\\n・最も近い敵１キャラに物理大ダメージを与え\\n\u3000る。\\n・秘密ブツを３体召喚する。召喚する際は敵全体\\n\u3000をノックバックさせる。秘密ブツは敵全体の物\\n\u3000理攻撃力と魔法攻撃力を小ダウンさせる。秘密\\n\u3000ブツのＨＰが一定値以下になった時、敵全体の\\n\u3000物理攻撃力と魔法攻撃力を大アップさせ、消滅\\n\u3000する。', 319001, 0, 1, 319000, 270, 0, 0, 16, 0, 1.6, 3000, '復活の白き島クジラ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】遥か北の海で再び相見えた幻島の巨鯨。\\n人々の秘密に潜む欲望を貪り海底深くで生きなが\\nらえる。\\n\\n・ユニオンバーストは、敵全体にキャラの最大\\n\u3000ＨＰに応じた物理割合ダメージを与える。さら\\n\u3000に、物理攻撃力と魔法攻撃力を大ダウンさせ\\n\u3000る。このスキルの状態異常はダメージを無効化\\n\u3000しても付与される。\\n・敵全体にキャラの最大ＨＰに応じた魔法割合ダ\\n\u3000メージを与える。このスキルの割合ダメージ\\n\u3000は、秘密ブツの数に応じて、与えられるダメー\\n\u3000ジ量が大きく上昇する。\\n・最も近い敵３キャラに魔法中ダメージを与え、\\n\u3000ノックバックさせると同時にスタンさせる。こ\\n\u3000のスキルの状態異常はダメージを無効化しても\\n\u3000付与される。\\n・最も近い敵１キャラに物理大ダメージを与え\\n\u3000る。\\n・自身のＨＰが50％を切ると、自身の行動速度\\n\u3000を小アップさせる。\\n・秘密ブツを３体召喚する。召喚する際は敵全体\\n\u3000をノックバックさせる。秘密ブツは敵全体の物\\n\u3000理攻撃力と魔法攻撃力を小ダウンさせる。秘密\\n\u3000ブツのＨＰが一定値以下になった時、敵全体の\\n\u3000物理攻撃力と魔法攻撃力を大アップさせ、消滅\\n\u3000する。', 319002, 0, 1, 319000, 270, 0, 0, 16, 0, 1.6, 3000, '復活の白き島クジラ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ１】溢れ出た欲望を身にまとい、強大\\nな力を得た巨鯨。白波荒立つオーマの海原にて\\n蘇った巨鯨との戦いが再び幕を開ける。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・復活の白き島クジラから受けるすべてのダメー\\n\u3000ジで発生する、パーティキャラのＴＰ回復量を\\n\u3000中ダウンさせる。\\n・ユニオンバーストは、敵全体にキャラの最大\\n\u3000ＨＰに応じた物理割合ダメージを与える。さら\\n\u3000に、物理攻撃力と魔法攻撃力を大ダウンさせ\\n\u3000る。このスキルの状態異常はダメージを無効化\\n\u3000しても付与される。\\n・敵全体にキャラの最大ＨＰに応じた魔法割合ダ\\n\u3000メージを与える。\\n・最も近い敵３キャラに魔法中ダメージを与え、\\n\u3000ノックバックさせると同時にスタンさせる。こ\\n\u3000のスキルの状態異常はダメージを無効化しても\\n\u3000付与される。\\n・最も近い敵１キャラに物理大ダメージを与え\\n\u3000る。', 319003, 0, 1, 319003, 270, 0, 0, 16, 0, 1.6, 3000, '復活の白き島クジラ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ２】巨鯨の力で象られし秘密と欲望\\nの影。行く手を阻む己が幻影を打ち砕き、暴虐\\nなる怨敵の元へと急げ！\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・復活の白き島クジラから受けるすべてのダメー\\n\u3000ジで発生する、パーティキャラのＴＰ回復量を\\n\u3000中ダウンさせる。\\n・復活の白き島クジラは環境効果によるダメージ\\n\u3000を受けない。\\n・最も近い敵１キャラに物理大ダメージを与え\\n\u3000る。', 319004, 0, 1, 319004, 270, 0, 0, 16, 0, 1.6, 3000, '復活の白き島クジラ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ３】凄まじい勢いで秘密ブツを噴射\\nする巨鯨。オーマの海を、人々の尊厳を守る\\n為、蘇りし白き巨鯨を打ち倒せ！\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を中アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・復活の白き島クジラから受けるすべてのダメー\\n\u3000ジで発生する、パーティキャラのＴＰ回復量を\\n\u3000中ダウンさせる。\\n・ユニオンバーストは、敵全体にキャラの最大\\n\u3000ＨＰに応じた物理割合ダメージを与える。さら\\n\u3000に、物理攻撃力と魔法攻撃力を大ダウンさせ\\n\u3000る。このスキルの状態異常はダメージを無効化\\n\u3000しても付与される。\\n・敵全体にキャラの最大ＨＰに応じた魔法割合ダ\\n\u3000メージを与える。このスキルの割合ダメージ\\n\u3000は、秘密ブツの数に応じて、与えられるダメー\\n\u3000ジ量が大きく上昇する。\\n・最も近い敵３キャラに魔法中ダメージを与え、\\n\u3000ノックバックさせると同時にスタンさせる。こ\\n\u3000のスキルの状態異常はダメージを無効化しても\\n\u3000付与される。\\n・最も近い敵１キャラに物理大ダメージを与え\\n\u3000る。\\n・自身のＨＰが50％を切ると、自身の行動速度\\n\u3000を小アップさせる。\\n・秘密ブツを３体召喚する。召喚する際は敵全体\\n\u3000をノックバックさせる。秘密ブツは敵全体の物\\n\u3000理攻撃力と魔法攻撃力を小ダウンさせる。秘密\\n\u3000ブツのＨＰが一定値以下になった時、敵全体の\\n\u3000物理攻撃力と魔法攻撃力を大アップさせ、消滅\\n\u3000する。', 319005, 0, 1, 319003, 270, 0, 0, 16, 0, 1.6, 3000, '復活の白き島クジラ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('ベースユニット', 319100, 0, 1, 319100, 270, 0, 0, 16, 0, 1.6, 3000, '叡智の錬金術師・モーヴ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】知識こそが力と信じ、叡智の研鑽を重ね\\nる錬金術師。あらゆる学問の粋を集めたグレート\\nアームを身に纏い、冒険者たちの行く手を阻む。\\n\\n・ユニオンバーストは、敵全体に自身の物理攻撃\\n\u3000力に応じた物理割合ダメージを与え、短時間麻\\n\u3000痺状態にする。キャラのＨＰが50％未満の場\\n\u3000合は長時間麻痺状態にする。このスキルの状態\\n\u3000異常はダメージを無効化しても付与される。\\n・最も近い敵３キャラに自身の物理攻撃力に応じ\\n\u3000た物理割合ダメージを与える。\\n・自身の物理攻撃力を中アップさせる。\\n・最も近い敵１キャラに物理特大ダメージを与え\\n\u3000る。', 319101, 0, 1, 319100, 270, 0, 0, 16, 0, 1.6, 3000, '叡智の錬金術師・モーヴ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】知識こそが力と信じ、叡智の研鑽を重ね\\nる錬金術師。あらゆる学問の粋を集めたグレート\\nアームを身に纏い、冒険者たちの行く手を阻む。\\n\\n・ユニオンバーストは、敵全体に自身の物理攻撃\\n\u3000力に応じた物理割合ダメージを与え、短時間麻\\n\u3000痺状態にする。キャラのＨＰが50％未満の場\\n\u3000合は長時間麻痺状態にする。このスキルの状態\\n\u3000異常はダメージを無効化しても付与される。\\n・最も近い敵３キャラに自身の物理攻撃力に応じ\\n\u3000た物理割合ダメージを与える。\\n・自身の物理攻撃力を中アップさせる。\\n・最も近い敵１キャラに物理特大ダメージを与え\\n\u3000る。', 319102, 0, 1, 319100, 270, 0, 0, 16, 0, 1.6, 3000, '叡智の錬金術師・モーヴ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】知識こそが力と信じ、叡智の研鑽を重ね\\nる錬金術師。あらゆる学問の粋を集めたグレート\\nアームを身に纏い、冒険者たちの行く手を阻む。\\n\\n・ユニオンバーストは、敵全体に自身の物理攻撃\\n\u3000力に応じた物理割合ダメージを与え、短時間麻\\n\u3000痺状態にする。キャラのＨＰが50％未満の場\\n\u3000合は長時間麻痺状態にする。このスキルの状態\\n\u3000異常はダメージを無効化しても付与される。\\n・最も近い敵３キャラに自身の物理攻撃力に応じ\\n\u3000た物理割合ダメージを与える。\\n・自身の物理攻撃力を中アップさせる。\\n・自身のＨＰが50％を切ると、物理攻撃力を大\\n\u3000アップさせる。\\n・最も近い敵１キャラに物理特大ダメージを与え\\n\u3000る。', 319103, 0, 1, 319100, 270, 0, 0, 16, 0, 1.6, 3000, '叡智の錬金術師・モーヴ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ１】錬金術師は、研究の結晶たる鋼の\\n剛腕に力を溜め渾身の一撃を繰り出す。巨岩をも\\n打ち砕くその衝撃が、容赦なく冒険者たちを襲う。\\n\\n・バトル開始直後、自身の物理防御力と魔法防御\\n\u3000力を小アップさせる。この防御力アップ効果で\\n\u3000上昇した防御力は、バトル中に受ける防御力ダ\\n\u3000ウンスキルの影響を受けない。\\n・ＣＴが最大まで溜まると、最も近い敵１キャラ\\n\u3000に9999999の物理ダメージを与える。', 319104, 0, 1, 319104, 270, 0, 0, 16, 0, 1.6, 3000, '叡智の錬金術師・モーヴ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ２】縦横無尽に動き回る両の腕は、対\\n敵がどこにいようとも捕らえ逃がさない。執拗に\\n追駆するその手腕から、思考を巡らせ切り抜けろ。\\n\\n・バトル開始直後、自身の物理防御力と魔法防御\\n\u3000力を小アップさせる。この防御力アップ効果で\\n\u3000上昇した防御力は、バトル中に受ける防御力ダ\\n\u3000ウンスキルの影響を受けない。\\n・叡智の錬金術師・モーヴから受けるすべてのダ\\n\u3000メージで発生する、パーティキャラのＴＰ回復\\n\u3000量を中ダウンさせる。\\n・ユニオンバーストは、敵全体に自身の物理攻撃\\n\u3000力に応じた物理割合ダメージを与え、短時間麻\\n\u3000痺状態にする。キャラのＨＰが50％未満の場\\n\u3000合は長時間麻痺状態にする。このスキルの状態\\n\u3000異常はダメージを無効化しても付与される。\\n・最も近い敵１キャラに物理特大ダメージを与え\\n\u3000る。\\n・敵全体に物理大ダメージを与える。さらに最も\\n\u3000遠い敵２キャラを大きく引き寄せ、スタンさせ\\n\u3000る。このスキルの状態異常はダメージを無効化\\n\u3000しても付与される。\\n・自身を中心とした範囲内の敵に物理大ダメージ\\n\u3000を与え、物理攻撃力と魔法攻撃力を中ダウンさ\\n\u3000せる。さらにノックバックさせる。このスキル\\n\u3000の状態異常はダメージを無効化しても付与され\\n\u3000る。', 319105, 0, 1, 319104, 270, 0, 0, 16, 0, 1.6, 3000, '叡智の錬金術師・モーヴ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ３】失敗の経験さえも己の知恵とし、\\nさらなる進化を遂げた錬金術師。独りよがりな野\\n望を叶えんとする傲慢な賢者を、力を合わせて打\\nち破れ。\\n\\n・バトル開始直後、自身の物理防御力と魔法防御\\n\u3000力を中アップさせる。この防御力アップ効果で\\n\u3000上昇した防御力は、バトル中に受ける防御力ダ\\n\u3000ウンスキルの影響を受けない。\\n・叡智の錬金術師・モーヴから受けるすべてのダ\\n\u3000メージで発生する、パーティキャラのＴＰ回復\\n\u3000量を中ダウンさせる。\\n・ユニオンバーストは、敵全体に自身の物理攻撃\\n\u3000力に応じた物理割合ダメージを与え、短時間麻\\n\u3000痺状態にする。キャラのＨＰが50％未満の場\\n\u3000合は長時間麻痺状態にする。このスキルの状態\\n\u3000異常はダメージを無効化しても付与される。\\n・最も近い敵３キャラに自身の物理攻撃力に応じ\\n\u3000た物理割合ダメージを与える。\\n・自身の物理攻撃力を中アップさせる。\\n・自身のＨＰが50％を切ると、物理攻撃力を大\\n\u3000アップさせる。\\n・最も近い敵１キャラに物理特大ダメージを与え\\n\u3000る。', 319106, 0, 1, 319104, 270, 0, 0, 16, 0, 1.6, 3000, '叡智の錬金術師・モーヴ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【魔法】大輪の蓮花を模した魔物。\\n絢爛なる装いから放たれる花吹雪は\\n美しくも烈々と獲物に襲い掛かる。\\n\\n・ユニオンバーストは、\\n\u3000前方２キャラに魔法大ダメージを\\n\u3000与え、さらに敵全体に麻痺を\\n\u3000与える。このスキルの状態異常\\n\u3000はダメージを無効化しても\\n\u3000付与される。\\n\\n・前方２キャラに魔法中ダメージ\\n\u3000を与え、ノックバックさせる。\\n\\n・前方２キャラに魔法中\\n\u3000ダメージを与え、魔法防御力を\\n\u3000中ダウンさせる。', 319200, 0, 2, 319200, 270, 0, 0, 16, 0, 2.8, 3000, 'フラワーマドンナ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【魔法】大輪の蓮花を模した魔物。その絢爛なる\\n花吹雪は美しくも烈々と獲物に襲い掛かる。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・フラワーマドンナから受けるすべてのダメージ\\n\u3000で発生する、パーティキャラのＴＰ回復量を中\\n\u3000ダウンさせる。\\n・ユニオンバーストは、敵全体に魔法特大ダメー\\n\u3000ジを与え、さらに麻痺状態を付与する。このス\\n\u3000キルによるダメージでは、ＴＰが回復しない。\\n\u3000このスキルの状態異常はダメージを無効化して\\n\u3000も付与される。\\n・召喚体、分身を除いた最も近い敵２キャラに魔\\n\u3000法小ダメージを与え、ノックバックさせる。\\n・通常攻撃は、召喚体、分身を除いた最も近い敵\\n\u3000２キャラに魔法大ダメージを与え、魔法防御力\\n\u3000を小ダウンさせる。このスキルの効果はダメー\\n\u3000ジを無効化しても付与される。', 319201, 0, 2, 319201, 270, 0, 0, 16, 0, 2.8, 3000, 'フラワーマドンナ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【魔法】大輪の蓮花を模した魔物。その絢爛なる\\n花吹雪は美しくも烈々と獲物に襲い掛かる。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を中アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・バトル開始時、敵全体のＨＰ吸収を特大ダウン\\n\u3000させ、ＴＰ上昇を小ダウンさせる。\\n・バトル開始時、自身にＴＰダウン50％カット\\n\u3000効果を付与する。\\n・フラワーマドンナから受けるすべてのダメージ\\n\u3000で発生する、パーティキャラのＴＰ回復量を特\\n\u3000大ダウンさせる。\\n・ユニオンバーストは、敵全体に魔法特大ダメー\\n\u3000ジを与え、さらに麻痺状態を付与する。このス\\n\u3000キルによるダメージでは、ＴＰが回復しない。\\n\u3000このスキルの状態異常はダメージを無効化して\\n\u3000も付与される。\\n・召喚体、分身を除いた最も近い敵２キャラに魔\\n\u3000法小ダメージを与え、ノックバックさせ、さら\\n\u3000に魔法大ダメージを与える。\\n・通常攻撃は、召喚体、分身を除いた最も近い敵\\n\u3000２キャラに魔法大ダメージを与え、魔法防御力\\n\u3000を小ダウンさせる。このスキルの効果はダメー\\n\u3000ジを無効化しても付与される。', 319202, 0, 2, 319202, 270, 0, 0, 16, 0, 2.8, 3000, 'フラワーマドンナ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【魔法】リゾートに訪れた人々を襲う悪霊。幾度\\nも呪殺を阻まれ、蔑ろにされた怒りと怨念で海岸\\nを恐怖に染める。\\n\\n・ユニオンバーストは、敵全体に魔法特大ダメー\\n\u3000ジを与える。さらに、物理攻撃力と魔法攻撃力\\n\u3000を小ダウンさせ、一定時間ＨＰ回復量を大ダウ\\n\u3000ンさせる。このスキルの状態異常はダメージを\\n\u3000無効化しても付与される。\\n・自身を中心とした範囲内の敵すべてに魔法大ダ\\n\u3000メージを与え、さらに呪い状態を付与する。敵\\n\u3000のＨＰが60％未満の場合、スタン状態を付与\\n\u3000する。このスキルの状態異常はダメージを無効\\n\u3000化しても付与される。\\n・敵全体に魔法中ダメージを与える。敵のＨＰが\\n\u300060％未満の場合、混乱状態を付与する。この\\n\u3000スキルの状態異常はダメージを無効化しても付\\n\u3000与される。\\n・最も近い敵１キャラに魔法大ダメージを与え\\n\u3000る。', 319300, 0, 2, 319300, 270, 0, 0, 16, 0, 1.6, 3000, 'グラッジレイス');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【魔法】リゾートに訪れた人々を襲う悪霊。幾度\\nも呪殺を阻まれ、蔑ろにされた怒りと怨念で海岸\\nを恐怖に染める。\\n\\n・ユニオンバーストは、敵全体に魔法特大ダメー\\n\u3000ジを与える。さらに、物理攻撃力と魔法攻撃力\\n\u3000を小ダウンさせ、一定時間ＨＰ回復量を大ダウ\\n\u3000ンさせる。このスキルの状態異常はダメージを\\n\u3000無効化しても付与される。\\n・自身を中心とした範囲内の敵すべてに魔法大ダ\\n\u3000メージを与え、さらに呪い状態を付与する。敵\\n\u3000のＨＰが60％未満の場合、スタン状態を付与\\n\u3000する。このスキルの状態異常はダメージを無効\\n\u3000化しても付与される。\\n・敵全体に魔法中ダメージを与える。敵のＨＰが\\n\u300060％未満の場合、混乱状態を付与する。この\\n\u3000スキルの状態異常はダメージを無効化しても付\\n\u3000与される。\\n・最も近い敵１キャラに魔法大ダメージを与え\\n\u3000る。', 319301, 0, 2, 319300, 270, 0, 0, 16, 0, 1.6, 3000, 'グラッジレイス');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【魔法】リゾートに訪れた人々を襲う悪霊。幾度\\nも呪殺を阻まれ、蔑ろにされた怒りと怨念で海岸\\nを恐怖に染める。\\n\\n・ユニオンバーストは、敵全体に魔法特大ダメー\\n\u3000ジを与える。さらに、物理攻撃力と魔法攻撃力\\n\u3000を小ダウンさせ、一定時間ＨＰ回復量を大ダウ\\n\u3000ンさせる。このスキルの状態異常はダメージを\\n\u3000無効化しても付与される。\\n・自身を中心とした範囲内の敵すべてに魔法大ダ\\n\u3000メージを与え、さらに呪い状態を付与する。敵\\n\u3000のＨＰが60％未満の場合、スタン状態を付与\\n\u3000する。このスキルの状態異常はダメージを無効\\n\u3000化しても付与される。\\n・敵全体に魔法中ダメージを与える。敵のＨＰが\\n\u300060％未満の場合、混乱状態を付与する。この\\n\u3000スキルの状態異常はダメージを無効化しても付\\n\u3000与される。\\n・自身のＨＰが50％を切ると、さらに攻撃が激\\n\u3000しく凶暴になる。\\n・最も近い敵１キャラに魔法大ダメージを与え\\n\u3000る。', 319302, 0, 2, 319300, 270, 0, 0, 16, 0, 1.6, 3000, 'グラッジレイス');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ１】悲憤の声に引き寄せられし、シャ\\nドウたち。災禍の根源たる悪霊を守護せんと、邪\\n悪な気を放ち、祓い手の前に立ち塞がる。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・バトル開始時、自身にＴＰダウン50％カット\\n\u3000効果を付与する。\\n・バトル開始時、敵全体のＨＰ吸収を特大ダウン\\n\u3000させる。\\n・グラッジレイスから受けるすべてのダメージで\\n\u3000発生する、パーティキャラのＴＰ回復量を中ダ\\n\u3000ウンさせる。\\n・最も近い敵１キャラに魔法大ダメージを与え\\n\u3000る。', 319303, 0, 2, 319303, 270, 0, 0, 16, 0, 1.6, 3000, 'グラッジレイス');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ２】怨憎の力により引き起こされるポ\\nルターガイスト。飛来する数多の呪いを撃ち落と\\nし、呪詛返しで敵を穿て！\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を中アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・バトル開始時、自身にＴＰダウン50％カット\\n\u3000効果を付与する。\\n・バトル開始時、敵全体のＨＰ吸収を特大ダウン\\n\u3000させる。\\n・グラッジレイスから受けるすべてのダメージで\\n\u3000発生する、パーティキャラのＴＰ回復量を中ダ\\n\u3000ウンさせる。\\n・最も近い敵１キャラに魔法大ダメージを与え\\n\u3000る。\\n・敵全体をノックバックさせ、呪怨の墓石、呪火\\n\u3000の蝋燭、呪毒の包丁を召喚する。\\n・呪怨の墓石は、一定時間経過するとランダムな\\n\u3000敵１キャラに物理大ダメージを与え、さらに呪\\n\u3000い状態を付与したあと、消滅する。ただし呪怨\\n\u3000の墓石のＨＰが一定値以下になった場合は、\\n\u3000グラッジレイスに物理割合ダメージを与え、呪\\n\u3000い状態を付与したあと、消滅する。\\n・呪火の蝋燭は、一定時間経過するとランダムな\\n\u3000敵１キャラに物理大ダメージを与え、さらに火\\n\u3000傷状態を付与したあと、消滅する。ただし呪火\\n\u3000の蝋燭のＨＰが一定値以下になった場合は、\\n\u3000グラッジレイスに物理割合ダメージを与え、火\\n\u3000傷状態を付与したあと、消滅する。\\n・呪毒の包丁は、一定時間経過するとランダムな\\n\u3000敵１キャラに物理大ダメージを与え、さらに毒\\n\u3000状態を付与したあと、消滅する。ただし呪毒の\\n\u3000包丁のＨＰが一定値以下になった場合は、\\n\u3000グラッジレイスに物理割合ダメージを与え、毒\\n\u3000状態を付与したあと、消滅する。\\n・呪怨の墓石、呪火の蝋燭、呪毒の包丁がキャラ\\n\u3000に与える状態異常のダメージでは、ＴＰが回復\\n\u3000しない。', 319304, 0, 2, 319303, 270, 0, 0, 16, 0, 1.6, 3000, 'グラッジレイス');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ３】激しい憎悪と憤怒の叫びをあげる\\n悪霊。苛烈な呪いを打ち破り、全身全霊、最後の\\n除霊で怨気衝天の悪霊を祓え！\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を中アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・バトル開始時、自身にＴＰダウン50％カット\\n\u3000効果を付与する。\\n・バトル開始時、敵全体のＨＰ吸収を特大ダウン\\n\u3000させる。\\n・グラッジレイスから受けるすべてのダメージで\\n\u3000発生する、パーティキャラのＴＰ回復量を中ダ\\n\u3000ウンさせる。\\n・ユニオンバーストは、敵全体に魔法特大ダメー\\n\u3000ジを与える。さらに、物理攻撃力と魔法攻撃力\\n\u3000を大ダウンさせ、一定時間ＨＰ回復量を特大ダ\\n\u3000ウンさせる。このスキルによるダメージでは、\\n\u3000キャラのＴＰが回復しない。このスキルの状態\\n\u3000異常はダメージを無効化しても付与される。\\n・自身を中心とした範囲内の敵すべてに魔法大ダ\\n\u3000メージを与え、さらに呪い状態を付与する。敵\\n\u3000のＨＰが80％未満の場合、スタン状態を付与\\n\u3000する。このスキルにより付与された呪い状態の\\n\u3000ダメージでは、ＴＰが回復しない。このスキル\\n\u3000の状態異常はダメージを無効化しても付与され\\n\u3000る。\\n・敵全体に魔法特大ダメージを与える。敵のＨＰ\\n\u3000が80％未満の場合、混乱状態を付与する。こ\\n\u3000のスキルの状態異常はダメージを無効化しても\\n\u3000付与される。\\n・自身のＨＰが50％を切ると、さらに攻撃が激\\n\u3000しく凶暴になる。\\n・最も近い敵１キャラに魔法大ダメージを与え\\n\u3000る。', 319305, 0, 2, 319303, 270, 0, 0, 16, 0, 1.6, 3000, 'グラッジレイス');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】完全な力を取り戻した太古の人工生命体。\\n無限の動力から編み出された防壁は、いかなる攻\\n撃も無に帰す。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・バトル開始時、自身にＴＰダウン50％カット\\n\u3000効果を付与する。\\n・アルティマガーディアンから受けるすべてのダ\\n\u3000メージで発生する、パーティキャラのＴＰ回復\\n\u3000量を中ダウンさせる。\\n・ユニオンバーストは、敵全体にキャラの最大Ｈ\\n\u3000Ｐに応じた魔法割合ダメージを与え、物理攻撃\\n\u3000力を中ダウン、魔法攻撃力を中ダウン、ＴＰを\\n\u3000大ダウンさせ、ステータスアップ効果を解除す\\n\u3000る。このスキルによるダメージでは、キャラの\\n\u3000ＴＰが回復しない。このスキルの状態異常はダ\\n\u3000メージを無効化しても付与される。\\n・最も近い敵１キャラを中心とした小範囲に物理\\n\u3000大ダメージを与える。\\n・敵全体に魔法中ダメージを与え、沈黙状態を付\\n\u3000与する。このスキルの状態異常はダメージを無\\n\u3000効化しても付与される。\\n・自身のＨＰが50％以上の場合、自身の物理防\\n\u3000御力を大ダウンさせ、物理無効バリアを展開す\\n\u3000る。自身のＨＰが50％未満の場合、自身の魔\\n\u3000法防御力を大ダウンさせ、魔法無効バリアを展\\n\u3000開する。\\n・自身の物理攻撃力と魔法攻撃力を特大アップす\\n\u3000る。さらに自身にバリアが展開されている場合、\\n\u3000自身のＴＰを特大回復させ、自身にバリアが展\\n\u3000開されていない場合、自身のＴＰを特大ダウン\\n\u3000させる。', 319400, 0, 1, 319400, 270, 0, 0, 16, 0, 1.6, 3000, 'アルティマガーディアン');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【魔法】800年の封印から目覚めし、一つ目の\\n魔物。封じられし魔力を解き放ち、忌まわしき魔\\n術師の名を冠する学園を破壊せんとする。\\n\\n・ユニオンバーストは、最も近い敵１キャラのバ\\n\u3000リアを解除し、魔法固定ダメージを与える。さ\\n\u3000らに自身の魔法攻撃力を特大アップさせる。こ\\n\u3000のスキルで与えたダメージ量に応じて、攻撃力\\n\u3000の上昇量がアップする。\\n・敵全体に魔法特大ダメージを与える。\\n・敵全体に魔法大ダメージを与える。\\n・自身の魔法攻撃力を中アップし、自身のＴＰを\\n\u3000中回復する。\\n・最も近い敵１キャラに魔法大ダメージを与え\\n\u3000る。', 319500, 0, 2, 319500, 270, 0, 0, 16, 0, 1.6, 3000, '放たれし暴魔・アルゲース');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【魔法】800年の封印から目覚めし、一つ目の\\n魔物。封じられし魔力を解き放ち、忌まわしき魔\\n術師の名を冠する学園を破壊せんとする。\\n\\n・ユニオンバーストは、最も近い敵１キャラのバ\\n\u3000リアを解除し、魔法固定ダメージを与える。さ\\n\u3000らに自身の魔法攻撃力を特大アップさせる。こ\\n\u3000のスキルで与えたダメージ量に応じて、攻撃力\\n\u3000の上昇量がアップする。\\n・敵全体に魔法特大ダメージを与える。\\n・敵全体に魔法大ダメージを与える。\\n・自身の魔法攻撃力を中アップし、自身のＴＰを\\n\u3000中回復する。\\n・最も近い敵１キャラに魔法大ダメージを与え\\n\u3000る。', 319501, 0, 2, 319500, 270, 0, 0, 16, 0, 1.6, 3000, '放たれし暴魔・アルゲース');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【魔法】800年の封印から目覚めし、一つ目の\\n魔物。封じられし魔力を解き放ち、忌まわしき魔\\n術師の名を冠する学園を破壊せんとする。\\n\\n・ユニオンバーストは、最も近い敵１キャラのバ\\n\u3000リアを解除し、魔法固定ダメージを与える。さ\\n\u3000らに自身の魔法攻撃力を特大アップさせる。こ\\n\u3000のスキルで与えたダメージ量に応じて、攻撃力\\n\u3000の上昇量がアップする。\\n・敵全体に魔法特大ダメージを与える。\\n・敵全体に魔法大ダメージを与える。\\n・自身の魔法攻撃力を中アップし、自身のＴＰを\\n\u3000中回復する。\\n・最も近い敵１キャラに魔法大ダメージを与え\\n\u3000る。', 319502, 0, 2, 319500, 270, 0, 0, 16, 0, 1.6, 3000, '放たれし暴魔・アルゲース');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ１】猛悪の四つ手から繰り出される多\\n彩な魔法球の嵐。その熾烈な攻撃を一度受ければ、\\n何人たりとも立ち上がることはできない。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・バトル開始時、自身にＴＰダウン25％カット\\n\u3000効果を付与する。\\n・放たれし暴魔・アルゲースから受けるすべての\\n\u3000ダメージで発生する、パーティキャラのＴＰ回\\n\u3000復量を中ダウンさせる。\\n・ユニオンバーストは、最も近い敵１キャラのバ\\n\u3000リアを解除し、魔法固定ダメージを与える。さ\\n\u3000らに自身の魔法攻撃力を特大アップさせる。こ\\n\u3000のスキルで与えたダメージ量に応じて、攻撃力\\n\u3000の上昇量がアップする。このスキルで敵を倒し\\n\u3000た場合、自身の魔法攻撃力を特大アップさせ\\n\u3000る。\\n・敵全体に魔法中ダメージを与え、最も近い敵１\\n\u3000キャラに凍結状態と火傷状態を付与する。この\\n\u3000スキルの状態異常はダメージを無効化しても付\\n\u3000与される。\\n・敵全体に魔法中ダメージを与え、ノックバック\\n\u3000させると同時にスタンさせる。このスキルの状\\n\u3000態異常はダメージを無効化しても付与される。', 319503, 0, 2, 319503, 270, 0, 0, 16, 0, 1.6, 3000, '放たれし暴魔・アルゲース');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ２】立ち込める瘴気が偽りの学友たち\\nの姿となる。悪辣なる醜行に、輝かしき思い出を\\n決して汚させはしない――\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・バトル開始時、自身にＴＰダウン25％カット\\n\u3000効果を付与する。\\n・放たれし暴魔・アルゲースから受けるすべての\\n\u3000ダメージで発生する、パーティキャラのＴＰ回\\n\u3000復量を中ダウンさせる。\\n・最も近い敵１キャラに魔法大ダメージを与え\\n\u3000る。', 319504, 0, 2, 319503, 270, 0, 0, 16, 0, 1.6, 3000, '放たれし暴魔・アルゲース');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ３】極限まで高められた魔力が、今、\\n解き放たれる。学園の皆の声援を力に変えて、青\\n春魔法でぶっ飛ばせ！\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・バトル開始時、自身にＴＰダウン25％カット\\n\u3000効果を付与する。\\n・放たれし暴魔・アルゲースから受けるすべての\\n\u3000ダメージで発生する、パーティキャラのＴＰ回\\n\u3000復量を中ダウンさせる。\\n・ユニオンバーストは、最も近い敵１キャラのバ\\n\u3000リアを解除し、魔法固定ダメージを与える。さ\\n\u3000らに自身の魔法攻撃力を特大アップさせる。こ\\n\u3000のスキルで与えたダメージ量に応じて、攻撃力\\n\u3000の上昇量がアップする。このスキルで敵を倒し\\n\u3000た場合、自身の魔法攻撃力を特大アップさせ\\n\u3000る。\\n・敵全体に魔法特大ダメージを与える。\\n・敵全体に魔法大ダメージを与える。\\n・自身の魔法攻撃力を中アップし、自身のＴＰを\\n\u3000中回復する。\\n・最も近い敵１キャラに魔法大ダメージを与え\\n\u3000る。', 319505, 0, 2, 319503, 270, 0, 0, 16, 0, 1.6, 3000, '放たれし暴魔・アルゲース');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【魔法】氷河地帯を支配する厳霜の魔狼。\\n冷酷な仔らが標的を貫き、氷爪が獲物を引き裂く。\\n\\n・一定間隔で発生する火傷、毒、猛毒ダメージの\\n\u3000影響を受けやすい。\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・フロストハウンドから受けるすべてのダメージ\\n\u3000で発生する、パーティキャラのＴＰ回復量を中\\n\u3000ダウンさせる。\\n・ユニオンバーストは、召喚体、分身を除いた最\\n\u3000も近い敵３キャラに魔法特大ダメージを与え、\\n\u3000凍結状態を付与し、自身の魔法防御力をバトル\\n\u3000終了まで小アップさせる。このスキルの状態異\\n\u3000常はダメージを無効化しても付与される。', 319600, 0, 2, 319600, 270, 0, 0, 16, 0, 1.6, 3000, 'フロストハウンド');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【魔法】氷河地帯を支配する厳霜の魔狼。\\n冷酷な仔らが標的を貫き、氷爪が獲物を引き裂く。\\n\\n・一定間隔で発生する火傷、毒、猛毒ダメージの\\n\u3000影響を受けやすい。\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を中アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・バトル開始時、敵全体のＨＰ吸収を特大ダウン\\n\u3000させる。 \\n・バトル開始時、敵全体のＴＰ上昇を小ダウンさ\\n\u3000せるフィールドを展開する。\\n・バトル開始時、自身にＴＰダウン50％カット\\n\u3000効果を付与する。\\n・フロストハウンドから受けるすべてのダメージ\\n\u3000で発生する、パーティキャラのＴＰ回復量を中\\n\u3000ダウンさせる。\\n・ユニオンバーストは、召喚体、分身を除いた最\\n\u3000も近い敵３キャラに魔法特大ダメージを与え、\\n\u3000凍結状態を付与し、自身の魔法防御力をバトル\\n\u3000終了まで小アップさせる。このスキルの状態異\\n\u3000常はダメージを無効化しても付与される。\\n・召喚体、分身を除いた最も近い敵３キャラに魔\\n\u3000法大ダメージを与え、魔法防御力を中ダウンさ\\n\u3000せる。このスキルの状態異常はダメージを無効\\n\u3000化しても付与される。', 319601, 0, 2, 319601, 270, 0, 0, 16, 0, 1.6, 3000, 'フロストハウンド');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【魔法】氷河地帯を支配する厳霜の魔狼。\\n冷酷な仔らが標的を貫き、氷爪が獲物を引き裂く。\\n\\n・フロストハウンドから受けるすべてのダメージ\\n\u3000で発生する、パーティキャラのＴＰ回復量を中\\n\u3000ダウンさせる。\\n・ユニオンバーストは、召喚体、分身を除いた最\\n\u3000も近い敵３キャラに魔法特大ダメージを与え、\\n\u3000凍結状態を付与し、自身の魔法防御力をバトル\\n\u3000終了まで小アップさせる。このスキルの状態異\\n\u3000常はダメージを無効化しても付与される。\\n・召喚体、分身を除いた最も近い敵３キャラに魔\\n\u3000法大ダメージを与え、魔法防御力を中ダウンさ\\n\u3000せる。このスキルの状態異常はダメージを無効\\n\u3000化しても付与される。', 319602, 0, 2, 319602, 270, 0, 0, 16, 0, 1.6, 3000, 'フロストハウンド');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【魔法】氷河地帯を支配する厳霜の魔狼。\\n冷酷な仔らが標的を貫き、氷爪が獲物を引き裂く。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を中アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・バトル開始時、自身にＴＰダウン50％カット\\n\u3000効果を付与する。\\n・バトル開始時、敵全体のＨＰ吸収を特大ダウン\\n\u3000させる。\\n・自身が一度の行動で受けるダメージ値を減衰さ\\n\u3000せる。ダメージ値が上昇するほど減衰率も上昇\\n\u3000する。\\n・フロストハウンドから受けるすべてのダメージ\\n\u3000で発生する、パーティキャラのＴＰ回復量を中\\n\u3000ダウンさせる。\\n・ユニオンバーストは、召喚体、分身を除いた最\\n\u3000も近い敵３キャラに魔法特大ダメージを与え、\\n\u3000凍結状態を付与し、自身の魔法防御力をバトル\\n\u3000終了まで小アップさせる。このスキルの状態異\\n\u3000常はダメージを無効化しても付与される。\\n・召喚体、分身を除いた最も近い敵３キャラに魔\\n\u3000法大ダメージを与え、魔法防御力を中ダウンさ\\n\u3000せる。このスキルの状態異常はダメージを無効\\n\u3000化しても付与される。', 319603, 0, 2, 319603, 270, 0, 0, 16, 0, 1.6, 3000, 'フロストハウンド');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】王家の装備を狙う、天才発明家の三女。\\n浮遊兵器から銃撃の嵐や特大爆弾をお見舞いし、\\n敵が慌てふためく姿を上空から嘲笑う。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を極大アップさせる。この防御力アップ効果で\\n\u3000上昇した防御力は、バトル中に受ける防御力ダ\\n\u3000ウンスキルの影響を受けない。\\n・バトル開始時、自身にＴＰダウン100％\\n\u3000カット効果を付与する。\\n・フブキから受けるすべてのダメージで発生\\n\u3000する、パーティキャラのＴＰ回復量を中ダウン\\n\u3000させる。\\n・フブキのＨＰが一定値以下になると、浮遊兵器\\n\u3000が墜落し行動不能になる。行動不能の間、自身\\n\u3000の物理防御力と魔法防御力が０になる。\\n・ユニオンバーストは、敵全体のバリアを解除\\n\u3000し、物理特大ダメージを与え、さらにスタンさ\\n\u3000せる。このスキルの状態異常はダメージを無効\\n\u3000化しても付与される。\\n・通常攻撃は最も近い敵１キャラに物理大ダ\\n\u3000メージを与え、さらにスタンさせる。このスキ\\n\u3000ルの状態異常はダメージを無効化しても付与さ\\n\u3000れる。\\n・敵全体をノックバックさせ、フブキちゃんダイ\\n\u3000ナマイツ♡を召喚する。\\n・フブキちゃんダイナマイツ♡は、一定時間経過\\n\u3000すると敵全体に物理大ダメージを与え、さらに\\n\u3000スタンを付与したあと、消滅する。このスキル\\n\u3000の状態異常はダメージを無効化しても付与され\\n\u3000る。ただしフブキちゃんダイナマイツ♡のＨＰ\\n\u3000が一定値以下になった場合は、フブキに物理固\\n\u3000定ダメージを与えたあと、消滅する。', 319700, 0, 1, 319700, 270, 0, 0, 16, 0, 1.6, 3000, 'フブキ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】盗賊ギルド、バンディ・シスターズ次女。\\n戦闘中後方でおびえているワカナを助けるために、\\nスパイク・ブラザーズが冒険者の行く手を阻む。\\n\\n・バトル開始時、自分の物理防御力と魔法防御力\\n\u3000を小アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力はバトル中に受ける防御力ダウン\\n\u3000スキルの影響を受けない。\\n・バトル開始時、自分にＴＰダウン100％カッ\\n\u3000ト効果を付与する。\\n・ワカナとスパイク・ブラザーズから受けるすべ\\n\u3000てのダメージで発生する、パーティキャラの\\n\u3000ＴＰ回復量を中ダウンさせる。\\n・ユニオンバーストは、敵全体に物理大ダメージ\\n\u3000を与え、さらにスタンさせる。このスキルの状\\n\u3000態異常はダメージを無効化しても付与される。\\n\u3000同時に、ワカナに物理固定ダメージを与える。\\n・自分を除く味方全体の物理攻撃力を大アップ\\n\u3000させ、自分のＴＰを中回復させる。\\n・バトル開始時、スパイク・ブラザーズが助けに\\n\u3000くる。その際、敵全体をノックバックさせる。\\n・スパイク・ブラザーズは、行動する度にワカナ\\n\u3000の物理防御力と魔法防御力を極大アップさせる。\\n・スパイク・ブラザーズは、自分の行動速度を特\\n\u3000大アップさせる。', 319800, 0, 1, 319800, 270, 0, 0, 16, 0, 1.6, 3000, 'ワカナ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】豪放磊落、バンディシスターズの長女。\\n序盤は強力な斬撃と弱体化で猛攻を仕掛けるが、\\n追い詰められると博打に出て戦況を一変させる。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を中アップさせる。この防御力アップ効果で\\n\u3000上昇した防御力は、バトル中に受ける防御力\\n\u3000ダウンスキルの影響を受けない。\\n・バトル開始時、自身にＴＰダウン50％カット\\n\u3000効果を付与する。\\n・ヤマトから受けるすべてのダメージで発生する、\\n\u3000パーティキャラのＴＰ回復量を中ダウンさせる。\\n・ヤマトのＨＰが一定値以下になると自身のＴＰ\\n\u3000を小ダウン後、一定時間無敵になり、敵全体に\\n\u3000沈黙状態を付与する。その後、爆弾を投げ、博\\n\u3000打を打つ。ヤマトが博打に勝った場合、前方２\\n\u3000キャラにキャラの最大ＨＰに応じた物理割合ダ\\n\u3000メージを与える。ヤマトが博打に負けた場合、\\n\u3000自身の物理防御力と魔法防御力を極大ダウンし\\n\u3000行動不能になる。\\n・ユニオンバーストは、最も近い敵１キャラの物\\n\u3000理防御力を特大ダウンさせる。その後、物理極\\n\u3000大ダメージを与える。\\n・最も遠い敵１キャラに物理特大ダメージを与え\\n\u3000大きく引き寄せ、さらにスタンさせる。このス\\n\u3000キルの状態異常はダメージを無効化しても付与\\n\u3000される。', 319900, 0, 1, 319900, 270, 0, 0, 16, 0, 1.6, 3000, 'ヤマト');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【魔法】はるか古に作られし防衛兵器。邪なる者\\nの願いにより封を解かれ、地中深くより現れる。\\n\\n・ユニオンバーストは、敵全体に魔法固定ダメー\\n\u3000ジを与え、魔法防御力を小ダウンさせる。この\\n\u3000スキルの状態異常はダメージを無効化しても付\\n\u3000与される。\\n・最も近い敵１キャラを中心とした小範囲に魔法\\n\u3000大ダメージを与える。\\n・自身に魔法小ダメージを与え、さらに物理防御\\n\u3000力と魔法防御力を小ダウンさせる。\\n・自身のＨＰが50％を切ると、右腕部が破損\\n\u3000し、行動パターンが変化する。さらに自身の物\\n\u3000理防御力、魔法防御力を特大ダウンさせる。\\n・最も近い敵１キャラに魔法大ダメージを与え\\n\u3000る。', 320000, 0, 2, 320000, 270, 0, 0, 16, 0, 1.6, 3000, 'カリド');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【魔法】はるか古に作られし防衛兵器。邪なる者\\nの願いにより封を解かれ、地中深くより現れる。\\n\\n・ユニオンバーストは、敵全体に魔法固定ダメー\\n\u3000ジを与え、魔法防御力を小ダウンさせる。この\\n\u3000スキルの状態異常はダメージを無効化しても付\\n\u3000与される。\\n・最も近い敵１キャラを中心とした小範囲に魔法\\n\u3000大ダメージを与える。\\n・自身に魔法小ダメージを与え、さらに物理防御\\n\u3000力と魔法防御力を小ダウンさせる。\\n・自身のＨＰが50％を切ると、右腕部が破損\\n\u3000し、行動パターンが変化する。さらに自身の物\\n\u3000理防御力、魔法防御力を特大ダウンさせる。\\n・最も近い敵１キャラに魔法大ダメージを与え\\n\u3000る。', 320001, 0, 2, 320000, 270, 0, 0, 16, 0, 1.6, 3000, 'カリド');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【魔法】はるか古に作られし防衛兵器。邪なる者\\nの願いにより封を解かれ、地中深くより現れる。\\n\\n・ユニオンバーストは、敵全体に魔法固定ダメー\\n\u3000ジを与え、魔法防御力を小ダウンさせる。この\\n\u3000スキルの状態異常はダメージを無効化しても付\\n\u3000与される。\\n・最も近い敵１キャラを中心とした小範囲に魔法\\n\u3000大ダメージを与える。\\n・自身に魔法小ダメージを与え、さらに物理防御\\n\u3000力と魔法防御力を小ダウンさせる。\\n・自身のＨＰが50％を切ると、右腕部が破損\\n\u3000し、行動パターンが変化する。さらに自身の物\\n\u3000理防御力、魔法防御力を特大ダウンさせる。\\n・最も近い敵１キャラに魔法大ダメージを与え\\n\u3000る。', 320002, 0, 2, 320000, 270, 0, 0, 16, 0, 1.6, 3000, 'カリド');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ１】かつて共に街を守りし兵らを従え\\nながらも巨兵は砂漠の国を混乱に陥れんとする。\\n一糸乱れぬ連携は、時を越えても衰えず。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・カリドから受けるすべてのダメージで発生す\\n\u3000る、パーティキャラのＴＰ回復量を中ダウンさ\\n\u3000せる。\\n・最も近い敵１キャラに魔法大ダメージを与え\\n\u3000る。\\n・バトル開始時、古代小兵を３体召喚し、敵全体\\n\u3000をノックバックさせる。\\n・古代小兵を１体倒すたびに、のこりターゲット\\n\u3000数が１減少する。その後、古代小兵が再度召喚\\n\u3000され、敵全体をノックバックさせる。', 320003, 0, 2, 320003, 270, 0, 0, 16, 0, 1.6, 3000, 'カリド');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ２】古の叡智を結集し作られた兵器は\\n秘めし力を解放する。巨大な体躯より出でし紅蓮\\nの光芒は、いかなるものも砂漠の灰燼に変える。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を中アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・カリドから受けるすべてのダメージで発生す\\n\u3000る、パーティキャラのＴＰ回復量を中ダウンさ\\n\u3000せる。\\n・エネルギーをチャージし、最も近い３キャラに\\n\u3000999999の魔法固定ダメージを与え、飛行\\n\u3000状態のキャラを含む敵全体に魔法特大ダメージ\\n\u3000を与える。その後自身の物理防御力、魔法防御\\n\u3000力、ステータスアップ効果を特大ダウンさせ、\\n\u3000火傷状態を付与する。', 320004, 0, 2, 320003, 270, 0, 0, 16, 0, 1.6, 3000, 'カリド');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ３】邪心を抱きし愚者の命により、古\\nの兵器は、砂漠の民に恐怖をもたらす。甚大なる\\nその脅威を打ち砕き、皆の笑顔を取り戻せ。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を中アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・カリドから受けるすべてのダメージで発生す\\n\u3000る、パーティキャラのＴＰ回復量を中ダウンさ\\n\u3000せる。\\n・ユニオンバーストは、敵全体に魔法固定ダメー\\n\u3000ジを与え、魔法防御力を小ダウンさせる。この\\n\u3000スキルの状態異常はダメージを無効化しても付\\n\u3000与される。\\n・最も近い敵１キャラを中心とした小範囲に魔法\\n\u3000大ダメージを与える。\\n・自身に魔法小ダメージを与え、さらに物理防御\\n\u3000力と魔法防御力を小ダウンさせる。\\n・自身のＨＰが50％を切ると、右腕部が破損\\n\u3000し、行動パターンが変化する。さらに自身の物\\n\u3000理防御力、魔法防御力、ステータスアップ効果\\n\u3000を特大ダウンさせる。\\n・最も近い敵１キャラに魔法大ダメージを与え\\n\u3000る。', 320005, 0, 2, 320003, 270, 0, 0, 16, 0, 1.6, 3000, 'カリド');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】四季入り乱れる霊山を棲み処とする妖狐。\\n不可思議な妖術で四季を操り、百花咲き誇る春へ\\nと季節を巡らせ、生命の力を芽吹かせる。\\n\\n・環境効果【百花繚乱】を発動する。このスキル\\n\u3000の効果は敵、味方すべてに適用される。一定時\\n\u3000間が経過するごとに、敵、味方全体のＴＰを中\\n\u3000回復させる。\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を中アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・バトル開始時、自身にＴＰダウン100％カッ\\n\u3000ト効果を付与する。\\n・バトル開始時、敵全体のＨＰ吸収を特大ダウン\\n\u3000させる。\\n・自身が一度の行動で受けるダメージ値を減衰さ\\n\u3000せる。ダメージ値が上昇するほど減衰率も上昇\\n\u3000する。\\n・バトル開始時、敵全体にＴＰ上昇上限効果を付\\n\u3000与する。\\n・妖狐カムラヲから受けるすべてのダメージで発\\n\u3000生する、パーティキャラのＴＰ回復量を中ダウ\\n\u3000ンさせる。\\n・ユニオンバーストは、敵全体に自身の物理攻撃\\n\u3000力に応じた物理割合ダメージと自身の魔法攻撃\\n\u3000力に応じた魔法割合ダメージを与える。さらに、\\n\u3000味方全体の行動速度をアップさせる。この効果\\n\u3000の効果量は式神の数に応じて増加する。このス\\n\u3000キルによるダメージでは、ＴＰが回復しない。\\n・最も近い敵１キャラに物理大ダメージと魔法大\\n\u3000ダメージを与える。\\n・敵全体の物理防御力と魔法防御力を中ダウンさ\\n\u3000せる。さらに、キャラのＨＰが70％未満の場\\n\u3000合、物理攻撃力と魔法攻撃力を中ダウンさせる。\\n・自身の後方に式神を３体召喚する。左から１番\\n\u3000目の式神は、前から２番目の敵キャラに物理小\\n\u3000ダメージと魔法小ダメージを与える。左から２\\n\u3000番目の式神は、前から３番目の敵キャラに物理\\n\u3000小ダメージと魔法小ダメージを与える。左から\\n\u3000３番目の式神は、前から４番目の敵キャラに物\\n\u3000理小ダメージと魔法小ダメージを与える。\\n・味方全体の物理攻撃力と魔法攻撃力を特大アッ\\n\u3000プさせ、物理防御力と魔法防御力を大アップさ\\n\u3000せる。', 320100, 0, 1, 320100, 600, 0, 0, 0, 0, 1.6, 3000, '妖狐カムラヲ・春臨');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】四季入り乱れる霊山を棲み処とする妖狐。\\n不可思議な妖術で四季を操り、その力で顕現させ\\nる炎天の夏は彼我の区別なく万物を焼き焦がす。\\n\\n・環境効果【炎天烈日】を発動する。このスキル\\n\u3000の効果は敵、味方すべてに適用される。一定時\\n\u3000間が経過するごとに、敵、味方全体に最大ＨＰ\\n\u3000に応じた最大20万の割合ダメージを与える。\\n\u3000さらに、付与される継続ダメージが上昇する。\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を中アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・バトル開始時、自身にＴＰダウン50％カット\\n\u3000効果を付与する。\\n・バトル開始時、敵全体のＨＰ吸収を特大ダウン\\n\u3000させる。\\n・自身が一度の行動で受けるダメージ値を減衰さ\\n\u3000せる。ダメージ値が上昇するほど減衰率も上昇\\n\u3000する。\\n・バトル開始時、敵全体にＴＰ上昇上限効果を付\\n\u3000与する。\\n・妖狐カムラヲから受けるすべてのダメージで発\\n\u3000生する、パーティキャラのＴＰ回復量を中ダウ\\n\u3000ンさせる。\\n・ユニオンバーストは、敵全体に自身の物理攻撃\\n\u3000力に応じた物理割合ダメージと自身の魔法攻撃\\n\u3000力に応じた魔法割合ダメージを与える。さらに、\\n\u3000敵全体のＨＰ回復量をダウンさせる。この効果\\n\u3000の効果量は式神の数に応じて増加する。このス\\n\u3000キルによるダメージでは、ＴＰが回復しない。\\n\u3000このスキルの状態異常はダメージを無効化して\\n\u3000も付与される。\\n・最も近い敵１キャラに物理大ダメージと魔法大\\n\u3000ダメージを与える。\\n・敵全体の物理防御力と魔法防御力を中ダウンさ\\n\u3000せる。さらに、キャラのＨＰが70％未満の場\\n\u3000合、物理攻撃力と魔法攻撃力を中ダウンさせる。\\n・自身の後方に式神を３体召喚する。左から１番\\n\u3000目の式神は、前から２番目の敵キャラに物理小\\n\u3000ダメージと魔法小ダメージを与える。左から２\\n\u3000番目の式神は、前から３番目の敵キャラに物理\\n\u3000小ダメージと魔法小ダメージを与える。左から\\n\u3000３番目の式神は、前から４番目の敵キャラに物\\n\u3000理小ダメージと魔法小ダメージを与える。\\n・敵全体のＨＰ吸収を特大ダウンさせる。さらに、\\n\u3000敵全体に火傷効果を付与する。キャラのＨＰが\\n\u300080％未満の場合、火傷のダメージが上昇する。\\n\u3000このスキルにより付与された火傷のダメージで\\n\u3000は、ＴＰが回復しない。', 320101, 0, 1, 320101, 600, 0, 0, 0, 0, 1.6, 3000, '妖狐カムラヲ・炎夏');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】四季入り乱れる霊山を棲み処とする妖狐。\\n不可思議な妖術で四季を操り、落葉散る秋に実り\\nをもたらすことで艱難辛苦に耐え忍ぶ力を与える。\\n\\n・環境効果【秋高馬肥】を発動する。このスキル\\n\u3000の効果は敵、味方すべてに適用される。一定時\\n\u3000間が経過するごとに、敵、味方全体の物理攻撃\\n\u3000力、魔法攻撃力、物理防御力、魔法防御力を\\n\u3000アップさせる。この効果の効果量は敵、味方を\\n\u3000合わせた数に応じて増加する。\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を中アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・バトル開始時、自身にＴＰダウン50％カット\\n\u3000効果を付与する。\\n・バトル開始時、敵全体のＨＰ吸収を特大ダウン\\n\u3000させる。\\n・自身が一度の行動で受けるダメージ値を減衰さ\\n\u3000せる。ダメージ値が上昇するほど減衰率も上昇\\n\u3000する。\\n・バトル開始時、敵全体にＴＰ上昇上限効果を付\\n\u3000与する。\\n・妖狐カムラヲから受けるすべてのダメージで発\\n\u3000生する、パーティキャラのＴＰ回復量を中ダウ\\n\u3000ンさせる。\\n・ユニオンバーストは、敵全体に自身の物理攻撃\\n\u3000力に応じた物理割合ダメージと自身の魔法攻撃\\n\u3000力に応じた魔法割合ダメージを与える。さらに、\\n\u3000味方全体の物理防御力と魔法防御力をアップさ\\n\u3000せる。この効果の効果量は式神の数に応じて増\\n\u3000加する。このスキルによるダメージでは、ＴＰ\\n\u3000が回復しない。\\n・最も近い敵１キャラに物理大ダメージと魔法大\\n\u3000ダメージを与える。\\n・敵全体の物理防御力と魔法防御力を中ダウンさ\\n\u3000せる。さらに、キャラのＨＰが70％未満の場\\n\u3000合、物理攻撃力と魔法攻撃力を中ダウンさせる。\\n・自身の後方に式神を３体召喚する。左から１番\\n\u3000目の式神は、前から２番目の敵キャラに物理小\\n\u3000ダメージと魔法小ダメージを与える。左から２\\n\u3000番目の式神は、前から３番目の敵キャラに物理\\n\u3000小ダメージと魔法小ダメージを与える。左から\\n\u3000３番目の式神は、前から４番目の敵キャラに物\\n\u3000理小ダメージと魔法小ダメージを与える。\\n・敵全体に自身の物理防御力に応じた物理固定ダ\\n\u3000メージと自身の魔法防御力に応じた魔法固定ダ\\n\u3000メージを与える。このスキルによるダメージで\\n\u3000は、ＴＰが回復しない。', 320102, 0, 1, 320102, 600, 0, 0, 0, 0, 1.6, 3000, '妖狐カムラヲ・爽秋');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】四季入り乱れる霊山を棲み処とする妖狐。\\n不可思議な妖術で四季を操り、あらゆる者を凍て\\nつかせる凛冽の冬へと世界を染める。\\n\\n・環境効果【寒気凛冽】を発動する。このスキル\\n\u3000の効果は敵、味方すべてに適用される。敵、味\\n\u3000方全体の行動速度を小ダウンさせる。このスキ\\n\u3000ルの効果は他の行動速度変化スキルと重複する。\\n\u3000さらに一定時間が経過するごとに、初期値より\\n\u3000行動速度が低い状態のキャラに凍結状態を付与\\n\u3000する。\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を中アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・バトル開始時、自身にＴＰダウン25％カット\\n\u3000効果を付与する。\\n・バトル開始時、敵全体のＨＰ吸収を特大ダウン\\n\u3000させる。\\n・自身が一度の行動で受けるダメージ値を減衰さ\\n\u3000せる。ダメージ値が上昇するほど減衰率も上昇\\n\u3000する。\\n・バトル開始時、敵全体にＴＰ上昇上限効果を付\\n\u3000与する。\\n・妖狐カムラヲから受けるすべてのダメージで発\\n\u3000生する、パーティキャラのＴＰ回復量を中ダウ\\n\u3000ンさせる。\\n・ユニオンバーストは、敵全体に自身の物理攻撃\\n\u3000力に応じた物理割合ダメージと自身の魔法攻撃\\n\u3000力に応じた魔法割合ダメージを与える。さらに、\\n\u3000敵全体の行動速度をダウンさせる。この効果の\\n\u3000効果量は式神の数に応じて増加する。このスキ\\n\u3000ルによるダメージでは、ＴＰが回復しない。こ\\n\u3000のスキルの状態異常はダメージを無効化しても\\n\u3000付与される。\\n・最も近い敵１キャラに物理大ダメージと魔法大\\n\u3000ダメージを与える。\\n・敵全体の物理防御力と魔法防御力を中ダウンさ\\n\u3000せる。さらに、キャラのＨＰが70％未満の場\\n\u3000合、物理攻撃力と魔法攻撃力を中ダウンさせる。\\n・自身の後方に式神を３体召喚する。左から１番\\n\u3000目の式神は、前から２番目の敵キャラに物理小\\n\u3000ダメージと魔法小ダメージを与える。左から２\\n\u3000番目の式神は、前から３番目の敵キャラに物理\\n\u3000小ダメージと魔法小ダメージを与える。左から\\n\u3000３番目の式神は、前から４番目の敵キャラに物\\n\u3000理小ダメージと魔法小ダメージを与える。\\n・敵全体に物理小ダメージと魔法小ダメージを与\\n\u3000える。このスキルのダメージは、召喚体、分身\\n\u3000を除いた敵キャラの数が少ないほど、大きく上\\n\u3000昇する。さらに、敵全体の行動速度を小ダウン\\n\u3000させ、味方全体の行動速度を中アップさせる。\\n\u3000このスキルによるダメージでは、ＴＰが回復し\\n\u3000ない。このスキルの状態異常はダメージを無効\\n\u3000化しても付与される。', 320103, 0, 1, 320103, 600, 0, 0, 0, 0, 1.6, 3000, '妖狐カムラヲ・寒威');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【魔法】突如雪山に現れたバジリスクの変異種。\\n異相の巨体を羽ばたかせ、聖夜を控えた人々や\\n魔物を絶望に突き落とす。\\n\\n・ユニオンバーストは、最も近い敵１キャラに魔\\n\u3000法特大ダメージを与える。さらに敵全体に魔法\\n\u3000中ダメージを与え、石化状態を付与する。この\\n\u3000スキルの状態異常はダメージを無効化しても付\\n\u3000与される。\\n・敵全体に魔法中ダメージを与え、石化状態を付\\n\u3000与する。このスキルの状態異常はダメージを無\\n\u3000効化しても付与される。\\n・最も近い敵１キャラに魔法特大ダメージを与え\\n\u3000る。\\n・最も近い敵１キャラに魔法中ダメージを与える。', 320200, 0, 2, 320200, 270, 0, 0, 16, 0, 1.6, 3000, 'バジリスク・アロス');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【魔法】突如雪山に現れたバジリスクの変異種。\\n異相の巨体を羽ばたかせ、聖夜を控えた人々や\\n魔物を絶望に突き落とす。\\n\\n・ユニオンバーストは、最も近い敵１キャラに魔\\n\u3000法特大ダメージを与える。さらに敵全体に魔法\\n\u3000中ダメージを与え、石化状態を付与する。この\\n\u3000スキルの状態異常はダメージを無効化しても付\\n\u3000与される。\\n・敵全体に魔法中ダメージを与え、石化状態を付\\n\u3000与する。このスキルの状態異常はダメージを無\\n\u3000効化しても付与される。\\n・最も近い敵１キャラに魔法特大ダメージを与え\\n\u3000る。\\n・最も近い敵１キャラに魔法中ダメージを与える。', 320201, 0, 2, 320200, 270, 0, 0, 16, 0, 1.6, 3000, 'バジリスク・アロス');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【魔法】突如雪山に現れたバジリスクの変異種。\\n異相の巨体を羽ばたかせ、聖夜を控えた人々や\\n魔物を絶望に突き落とす。\\n\\n・ユニオンバーストは、最も近い敵１キャラに魔\\n\u3000法特大ダメージを与える。さらに敵全体に魔法\\n\u3000中ダメージを与え、石化状態を付与する。この\\n\u3000スキルの状態異常はダメージを無効化しても付\\n\u3000与される。\\n・敵全体に魔法中ダメージを与え、石化状態を付\\n\u3000与する。このスキルの状態異常はダメージを無\\n\u3000効化しても付与される。\\n・最も近い敵１キャラに魔法特大ダメージを与え\\n\u3000る。\\n・自身のＨＰが50％を切ると、行動パターンが\\n\u3000変化する。さらに自身の魔法攻撃力を中アップ\\n\u3000させる。\\n・最も近い敵１キャラに魔法中ダメージを与える。', 320202, 0, 2, 320200, 270, 0, 0, 16, 0, 1.6, 3000, 'バジリスク・アロス');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ１】荒れ狂う怪鳥の猛威は波及し、山\\nに住まう魔物たちが暴れ出す。襲い来る群れを華\\n麗に捌き、宴を彩る食材を手に入れろ！\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を中アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・バトル開始時、自身にＴＰダウン50％カット\\n\u3000効果を付与する。\\n・バジリスク・アロス、スノウゴート、アイス\\n\u3000チック、アイスフィッシュ、アイスモールから\\n\u3000受けるすべてのダメージで発生する、パーティ\\n\u3000キャラのＴＰ回復量を中ダウンさせる。\\n・最も近い敵１キャラに魔法中ダメージを与える。\\n・バトル開始時、スノウゴート、アイスチック、\\n\u3000アイスフィッシュ、アイスモールを召喚し、敵\\n\u3000全体をノックバックさせる。\\n・召喚されたモンスターを１体倒すたびに、のこ\\n\u3000りターゲット数が１減少する。その後、倒され\\n\u3000たモンスターが再度召喚され、敵全体をノック\\n\u3000バックさせる。', 320203, 0, 2, 320203, 270, 0, 0, 16, 0, 1.6, 3000, 'バジリスク・アロス');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ２】天高く舞い上がった怪鳥は光の速\\nさで幽天を裂き、歯向かう者を巨躯で撥ね飛ばす。\\n反動の隙を突けるか否かが勝敗を左右する。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を中アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・バトル開始時、自身にＴＰダウン50％カット\\n\u3000効果を付与する。\\n・一定時間力を溜め、上空に飛び上がる。\\n\u3000空を飛んでいる間、自身に無敵状態を付与する。\\n\u3000その後急降下し、最も近い敵１キャラに最大\\n\u3000ＨＰに応じた物理割合ダメージを与える。\\n\u3000さらに、自身にこのスキルで与えたダメージ量\\n\u3000に応じた物理特大ダメージを与え、自身の物理\\n\u3000防御力と魔法防御力を特大ダウンさせる。', 320204, 0, 2, 320204, 270, 0, 0, 16, 0, 1.6, 3000, 'バジリスク・アロス');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ３】獰猛なバジリスクは心を鎮め、か\\nつてない強敵に力の全てを傾ける。雪山での狩り\\nもいよいよ大詰め。ローストチキンは目の前だ！\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・バトル開始時、自身にＴＰダウン50％カット\\n\u3000効果を付与する。\\n・バジリスク・アロスから受けるすべてのダメー\\n\u3000ジで発生する、パーティキャラのＴＰ回復量を\\n\u3000中ダウンさせる。\\n・ユニオンバーストは、最も近い敵１キャラに魔\\n\u3000法特大ダメージを与える。さらに敵全体に魔法\\n\u3000中ダメージを与え、石化状態を付与する。この\\n\u3000スキルの状態異常はダメージを無効化しても付\\n\u3000与される。\\n・敵全体に魔法中ダメージを与え、石化状態を付\\n\u3000与する。このスキルの状態異常はダメージを無\\n\u3000効化しても付与される。\\n・最も近い敵１キャラに魔法特大ダメージを与え\\n\u3000る。\\n・自身のＨＰが50％を切ると、行動パターンが\\n\u3000変化する。さらに自身の魔法攻撃力を中アップ\\n\u3000させる。\\n・最も近い敵１キャラに魔法中ダメージを与える。', 320205, 0, 2, 320204, 270, 0, 0, 16, 0, 1.6, 3000, 'バジリスク・アロス');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ１】荒れ狂う怪鳥の猛威は波及し、山\\nに住まう魔物たちが暴れ出す。襲い来る群れを華\\n麗に捌き、宴を彩る食材を手に入れろ！\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を中アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・バトル開始時、自身にＴＰダウン50％カット\\n\u3000効果を付与する。\\n・バジリスク・アロス、スノウゴート、アイス\\n\u3000チック、アイスフィッシュ、アイスモールから\\n\u3000受けるすべてのダメージで発生する、パーティ\\n\u3000キャラのＴＰ回復量を中ダウンさせる。\\n・最も近い敵１キャラに魔法中ダメージを与える。\\n・バトル開始時、スノウゴート、アイスチック、\\n\u3000アイスフィッシュ、アイスモールを召喚し、敵\\n\u3000全体をノックバックさせる。\\n・召喚されたモンスターを１体倒すたびに、のこ\\n\u3000りターゲット数が１減少する。その後、倒され\\n\u3000たモンスターが再度召喚され、敵全体をノック\\n\u3000バックさせる。', 320206, 0, 2, 320203, 270, 0, 0, 16, 0, 1.6, 3000, 'バジリスク・アロス');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ２】天高く舞い上がった怪鳥は光の速\\nさで幽天を裂き、歯向かう者を巨躯で撥ね飛ばす。\\n反動の隙を突けるか否かが勝敗を左右する。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を大アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・バトル開始時、自身にＴＰダウン50％カット\\n\u3000効果を付与する。\\n・一定時間力を溜め、上空に飛び上がる。\\n\u3000空を飛んでいる間、自身に無敵状態を付与する。\\n\u3000その後急降下し、最も近い敵１キャラに最大\\n\u3000ＨＰに応じた物理割合ダメージを与える。\\n\u3000さらに、自身にこのスキルで与えたダメージ量\\n\u3000に応じた物理特大ダメージを与え、自身の物理\\n\u3000防御力と魔法防御力を特大ダウンさせる。', 320207, 0, 2, 320204, 270, 0, 0, 16, 0, 1.6, 3000, 'バジリスク・アロス');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ３】獰猛なバジリスクは心を鎮め、か\\nつてない強敵に力の全てを傾ける。雪山での狩り\\nもいよいよ大詰め。ローストチキンは目の前だ！\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を大アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・バトル開始時、自身にＴＰダウン50％カット\\n\u3000効果を付与する。\\n・バジリスク・アロスから受けるすべてのダメー\\n\u3000ジで発生する、パーティキャラのＴＰ回復量を\\n\u3000中ダウンさせる。\\n・ユニオンバーストは、最も近い敵１キャラに魔\\n\u3000法特大ダメージを与える。さらに敵全体に魔法\\n\u3000中ダメージを与え、石化状態を付与する。この\\n\u3000スキルの状態異常はダメージを無効化しても付\\n\u3000与される。\\n・敵全体に魔法中ダメージを与え、石化状態を付\\n\u3000与する。このスキルの状態異常はダメージを無\\n\u3000効化しても付与される。\\n・最も近い敵１キャラに魔法特大ダメージを与え\\n\u3000る。\\n・自身のＨＰが50％を切ると、行動パターンが\\n\u3000変化する。さらに自身の魔法攻撃力を中アップ\\n\u3000させる。\\n・最も近い敵１キャラに魔法中ダメージを与える。', 320208, 0, 2, 320204, 270, 0, 0, 16, 0, 1.6, 3000, 'バジリスク・アロス');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】幻想的な宇宙空間。煌びやかな星の上。\\nそして目の前には……迫りくる巨大隕石！？混乱\\nの最中で脳裏をよぎるのは、心地良い枕の感触。\\n\\n・ユニオンバーストは、敵全体のバリアを解除し、\\n\u3000残りＨＰに応じた物理割合ダメージを与える。\\n\u3000さらにスタン状態を付与する。このスキルの状\\n\u3000態異常はダメージを無効化しても付与される。\\n・敵全体に残りＨＰに応じた物理割合ダメージを\\n\u3000与え、短時間スタン状態を付与する。さらに残\\n\u3000りＨＰが20％未満の場合、長時間スタン状態\\n\u3000を付与する。このスキルの状態異常はダメージ\\n\u3000を無効化しても付与される。\\n・自身を中心とした範囲内の敵すべてに残りＨＰ\\n\u3000に応じた物理割合ダメージを与え、ノックバッ\\n\u3000クさせる。さらに残りＨＰが30％未満の場合、\\n\u3000ステータスアップ効果を解除する。このスキル\\n\u3000の効果はダメージを無効化しても付与される。\\n・後方範囲内の敵すべてに残りＨＰに応じた物理\\n\u3000割合ダメージを与え、ＴＰを中ダウンさせる。\\n\u3000さらに残りＨＰが30％未満の場合、物理攻撃\\n\u3000力と魔法攻撃力を中ダウンさせる。このスキル\\n\u3000の状態異常はダメージを無効化しても付与され\\n\u3000る。', 320300, 0, 1, 320300, 270, 0, 0, 16, 0, 1.6, 3000, 'メテオ・イン・ドリーム');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】幻想的な宇宙空間。煌びやかな星の上。\\nそして目の前には……迫りくる巨大隕石！？混乱\\nの最中で脳裏をよぎるのは、心地良い枕の感触。\\n\\n・ユニオンバーストは、敵全体のバリアを解除し、\\n\u3000残りＨＰに応じた物理割合ダメージを与える。\\n\u3000さらにスタン状態を付与する。このスキルの状\\n\u3000態異常はダメージを無効化しても付与される。\\n・敵全体に残りＨＰに応じた物理割合ダメージを\\n\u3000与え、短時間スタン状態を付与する。さらに残\\n\u3000りＨＰが20％未満の場合、長時間スタン状態\\n\u3000を付与する。このスキルの状態異常はダメージ\\n\u3000を無効化しても付与される。\\n・自身を中心とした範囲内の敵すべてに残りＨＰ\\n\u3000に応じた物理割合ダメージを与え、ノックバッ\\n\u3000クさせる。さらに残りＨＰが30％未満の場合、\\n\u3000ステータスアップ効果を解除する。このスキル\\n\u3000の効果はダメージを無効化しても付与される。\\n・後方範囲内の敵すべてに残りＨＰに応じた物理\\n\u3000割合ダメージを与え、ＴＰを中ダウンさせる。\\n\u3000さらに残りＨＰが30％未満の場合、物理攻撃\\n\u3000力と魔法攻撃力を中ダウンさせる。このスキル\\n\u3000の状態異常はダメージを無効化しても付与され\\n\u3000る。', 320301, 0, 1, 320300, 270, 0, 0, 16, 0, 1.6, 3000, 'メテオ・イン・ドリーム');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】幻想的な宇宙空間。煌びやかな星の上。\\nそして目の前には……迫りくる巨大隕石！？混乱\\nの最中で脳裏をよぎるのは、心地良い枕の感触。\\n\\n・ユニオンバーストは、敵全体のバリアを解除し、\\n\u3000残りＨＰに応じた物理割合ダメージを与える。\\n\u3000さらにスタン状態を付与する。このスキルの状\\n\u3000態異常はダメージを無効化しても付与される。\\n・敵全体に残りＨＰに応じた物理割合ダメージを\\n\u3000与え、短時間スタン状態を付与する。さらに残\\n\u3000りＨＰが20％未満の場合、長時間スタン状態\\n\u3000を付与する。このスキルの状態異常はダメージ\\n\u3000を無効化しても付与される。\\n・自身を中心とした範囲内の敵すべてに残りＨＰ\\n\u3000に応じた物理割合ダメージを与え、ノックバッ\\n\u3000クさせる。さらに残りＨＰが30％未満の場合、\\n\u3000ステータスアップ効果を解除する。このスキル\\n\u3000の効果はダメージを無効化しても付与される。\\n・後方範囲内の敵すべてに残りＨＰに応じた物理\\n\u3000割合ダメージを与え、ＴＰを中ダウンさせる。\\n\u3000さらに残りＨＰが30％未満の場合、物理攻撃\\n\u3000力と魔法攻撃力を中ダウンさせる。このスキル\\n\u3000の状態異常はダメージを無効化しても付与され\\n\u3000る。', 320302, 0, 1, 320300, 270, 0, 0, 16, 0, 1.6, 3000, 'メテオ・イン・ドリーム');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ１】隕石に続けて現れたのは、なんと\\n超・超・特大除夜の鐘！煩悩ごと滅さんと響く重\\n低音を耐え凌ぎ、行く年にお別れを告げるべし！\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を中アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・バトル開始時、自身にＴＰダウン50％カット\\n\u3000効果を付与する。\\n・バトル開始時、敵全体のＨＰ吸収を特大ダウン\\n\u3000させる。\\n・バトル開始時、敵全体のＨＰ回復量を特大ダウ\\n\u3000ンさせる。\\n・メテオ・イン・ドリームから受けるすべてのダ\\n\u3000メージで発生する、パーティキャラのＴＰ回復\\n\u3000量を中ダウンさせる。\\n・敵全体に残りＨＰに応じた物理割合ダメージを\\n\u3000与え、短時間スタン状態を付与する。さらに残\\n\u3000りＨＰが20％未満の場合、長時間スタン状態\\n\u3000を付与する。このスキルの状態異常はダメージ\\n\u3000を無効化しても付与される。\\n・バトル開始時、除夜の鐘を召喚する。\\n・除夜の鐘は攻撃の対象にならず、敵全体にボス\\n\u3000の魔法攻撃力に応じた魔法固定ダメージを与え、\\n\u30002024の追加魔法固定ダメージを与える。さ\\n\u3000らにボスに物理と魔法の割合ダメージを与える。\\n\u3000このスキルで受けるダメージではＴＰは回復し\\n\u3000ない。', 320303, 0, 1, 320303, 270, 0, 0, 16, 0, 1.6, 3000, 'メテオ・イン・ドリーム');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ２】地上から見れば美しい流星群も、\\n間近で拝めば脅威そのもの。剣や魔法で太刀打ち\\nできるのか？大丈夫！ここは夢の中なのだから。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を中アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・バトル開始時、自身にＴＰダウン50％カット\\n\u3000効果を付与する。\\n・バトル開始時、敵全体のＨＰ吸収を特大ダウン\\n\u3000させる。\\n・バトル開始時、敵全体のＨＰ回復量を特大ダウ\\n\u3000ンさせる。\\n・メテオ・イン・ドリームから受けるすべてのダ\\n\u3000メージで発生する、パーティキャラのＴＰ回復\\n\u3000量を中ダウンさせる。\\n・自身を中心とした範囲内の敵すべてに残りＨＰ\\n\u3000に応じた物理割合ダメージを与え、ノックバッ\\n\u3000クさせる。さらに残りＨＰが30％未満の場合、\\n\u3000ステータスアップ効果を解除する。このスキル\\n\u3000の効果はダメージを無効化しても付与される。\\n・後方範囲内の敵すべてに残りＨＰに応じた物理\\n\u3000割合ダメージを与え、ＴＰを中ダウンさせる。\\n\u3000さらに残りＨＰが30％未満の場合、物理攻撃\\n\u3000力と魔法攻撃力を中ダウンさせる。このスキル\\n\u3000の状態異常はダメージを無効化しても付与され\\n\u3000る。このスキルによるダメージでは、敵のＴＰ\\n\u3000が回復しない。\\n・バトル開始時、プチメテオが飛来し、敵全体を\\n\u3000ノックバックさせる。\\n・飛来したプチメテオを１つ破壊するたびに、の\\n\u3000こりターゲット数が１減少する。その後、プチ\\n\u3000メテオが再度飛来する。', 320304, 0, 1, 320303, 270, 0, 0, 16, 0, 1.6, 3000, 'メテオ・イン・ドリーム');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ３】次から次へ奇想天外な出来事ばか\\nり、こんな夢はもううんざり！最後はパーッと隕\\n石を打砕き、晴れやかな気持ちで目を覚まそう！\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を中アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・バトル開始時、自身にＴＰダウン50％カット\\n\u3000効果を付与する。\\n・バトル開始時、敵全体のＨＰ吸収を特大ダウン\\n\u3000させる。\\n・バトル開始時、敵全体のＨＰ回復量を特大ダウ\\n\u3000ンさせる。\\n・メテオ・イン・ドリームから受けるすべてのダ\\n\u3000メージで発生する、パーティキャラのＴＰ回復\\n\u3000量を中ダウンさせる。\\n・ユニオンバーストは、敵全体のバリアを解除し、\\n\u3000魔法固定ダメージと残りＨＰに応じた物理割合\\n\u3000ダメージを与える。さらにスタン状態を付与す\\n\u3000る。このスキルの状態異常はダメージを無効化\\n\u3000しても付与される。このスキルによるダメージ\\n\u3000では、敵のＴＰが回復しない。\\n・敵全体に残りＨＰに応じた物理割合ダメージを\\n\u3000与え、短時間スタン状態を付与する。さらに残\\n\u3000りＨＰが20％未満の場合、長時間スタン状態\\n\u3000を付与する。このスキルの状態異常はダメージ\\n\u3000を無効化しても付与される。\\n・自身を中心とした範囲内の敵すべてに残りＨＰ\\n\u3000に応じた物理割合ダメージを与え、ノックバッ\\n\u3000クさせる。さらに残りＨＰが30％未満の場合、\\n\u3000ステータスアップ効果を解除する。このスキル\\n\u3000の効果はダメージを無効化しても付与される。\\n・後方範囲内の敵すべてに残りＨＰに応じた物理\\n\u3000割合ダメージを与え、ＴＰを中ダウンさせる。\\n\u3000さらに残りＨＰが30％未満の場合、物理攻撃\\n\u3000力と魔法攻撃力を中ダウンさせる。このスキル\\n\u3000の状態異常はダメージを無効化しても付与され\\n\u3000る。このスキルによるダメージでは、敵のＴＰ\\n\u3000が回復しない。', 320305, 0, 1, 320303, 270, 0, 0, 16, 0, 1.6, 3000, 'メテオ・イン・ドリーム');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ１】隕石に続けて現れたのは、なんと\\n超・超・特大除夜の鐘！煩悩ごと滅さんと響く重\\n低音を耐え凌ぎ、行く年にお別れを告げるべし！\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を中アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・バトル開始時、自身にＴＰダウン50％カット\\n\u3000効果を付与する。\\n・バトル開始時、敵全体のＨＰ吸収を特大ダウン\\n\u3000させる。\\n・バトル開始時、敵全体のＨＰ回復量を特大ダウ\\n\u3000ンさせる。\\n・メテオ・イン・ドリームから受けるすべてのダ\\n\u3000メージで発生する、パーティキャラのＴＰ回復\\n\u3000量を中ダウンさせる。\\n・敵全体に残りＨＰに応じた物理割合ダメージを\\n\u3000与え、短時間スタン状態を付与する。さらに残\\n\u3000りＨＰが20％未満の場合、長時間スタン状態\\n\u3000を付与する。このスキルの状態異常はダメージ\\n\u3000を無効化しても付与される。\\n・バトル開始時、除夜の鐘を召喚する。\\n・除夜の鐘は攻撃の対象にならず、敵全体にボス\\n\u3000の魔法攻撃力に応じた魔法固定ダメージを与え、\\n\u30002024の追加魔法固定ダメージを与える。さ\\n\u3000らにボスに物理と魔法の割合ダメージを与える。\\n\u3000このスキルで受けるダメージではＴＰは回復し\\n\u3000ない。', 320306, 0, 1, 320303, 270, 0, 0, 16, 0, 1.6, 3000, 'メテオ・イン・ドリーム');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ２】地上から見れば美しい流星群も、\\n間近で拝めば脅威そのもの。剣や魔法で太刀打ち\\nできるのか？大丈夫！ここは夢の中なのだから。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を中アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・バトル開始時、自身にＴＰダウン50％カット\\n\u3000効果を付与する。\\n・バトル開始時、敵全体のＨＰ吸収を特大ダウン\\n\u3000させる。\\n・バトル開始時、敵全体のＨＰ回復量を特大ダウ\\n\u3000ンさせる。\\n・メテオ・イン・ドリームから受けるすべてのダ\\n\u3000メージで発生する、パーティキャラのＴＰ回復\\n\u3000量を中ダウンさせる。\\n・自身を中心とした範囲内の敵すべてに残りＨＰ\\n\u3000に応じた物理割合ダメージを与え、ノックバッ\\n\u3000クさせる。さらに残りＨＰが30％未満の場合、\\n\u3000ステータスアップ効果を解除する。このスキル\\n\u3000の効果はダメージを無効化しても付与される。\\n・後方範囲内の敵すべてに残りＨＰに応じた物理\\n\u3000割合ダメージを与え、ＴＰを中ダウンさせる。\\n\u3000さらに残りＨＰが30％未満の場合、物理攻撃\\n\u3000力と魔法攻撃力を中ダウンさせる。このスキル\\n\u3000の状態異常はダメージを無効化しても付与され\\n\u3000る。このスキルによるダメージでは、敵のＴＰ\\n\u3000が回復しない。\\n・バトル開始時、プチメテオが飛来し、敵全体を\\n\u3000ノックバックさせる。\\n・飛来したプチメテオを１つ破壊するたびに、の\\n\u3000こりターゲット数が１減少する。その後、プチ\\n\u3000メテオが再度飛来する。', 320307, 0, 1, 320303, 270, 0, 0, 16, 0, 1.6, 3000, 'メテオ・イン・ドリーム');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ３】次から次へ奇想天外な出来事ばか\\nり、こんな夢はもううんざり！最後はパーッと隕\\n石を打砕き、晴れやかな気持ちで目を覚まそう！\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を中アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・バトル開始時、自身にＴＰダウン50％カット\\n\u3000効果を付与する。\\n・バトル開始時、敵全体のＨＰ吸収を特大ダウン\\n\u3000させる。\\n・バトル開始時、敵全体のＨＰ回復量を特大ダウ\\n\u3000ンさせる。\\n・メテオ・イン・ドリームから受けるすべてのダ\\n\u3000メージで発生する、パーティキャラのＴＰ回復\\n\u3000量を中ダウンさせる。\\n・ユニオンバーストは、敵全体のバリアを解除し、\\n\u3000魔法固定ダメージと残りＨＰに応じた物理割合\\n\u3000ダメージを与える。さらにスタン状態を付与す\\n\u3000る。このスキルの状態異常はダメージを無効化\\n\u3000しても付与される。このスキルによるダメージ\\n\u3000では、敵のＴＰが回復しない。\\n・敵全体に残りＨＰに応じた物理割合ダメージを\\n\u3000与え、短時間スタン状態を付与する。さらに残\\n\u3000りＨＰが20％未満の場合、長時間スタン状態\\n\u3000を付与する。このスキルの状態異常はダメージ\\n\u3000を無効化しても付与される。\\n・自身を中心とした範囲内の敵すべてに残りＨＰ\\n\u3000に応じた物理割合ダメージを与え、ノックバッ\\n\u3000クさせる。さらに残りＨＰが30％未満の場合、\\n\u3000ステータスアップ効果を解除する。このスキル\\n\u3000の効果はダメージを無効化しても付与される。\\n・後方範囲内の敵すべてに残りＨＰに応じた物理\\n\u3000割合ダメージを与え、ＴＰを中ダウンさせる。\\n\u3000さらに残りＨＰが30％未満の場合、物理攻撃\\n\u3000力と魔法攻撃力を中ダウンさせる。このスキル\\n\u3000の状態異常はダメージを無効化しても付与され\\n\u3000る。このスキルによるダメージでは、敵のＴＰ\\n\u3000が回復しない。', 320308, 0, 1, 320303, 270, 0, 0, 16, 0, 1.6, 3000, 'メテオ・イン・ドリーム');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【魔法】『レジェンドオブアストルム』を守護す\\nる精霊。世界の調和を保つため、外部より紛れ込\\nんだ異端を排除すべく始動する。\\n\\n・ユニオンバーストは、敵全体に魔法大ダメージ\\n\u3000を与える。\\n・敵全体の物理攻撃力と魔法攻撃力を大ダウンさ\\n\u3000せる。さらに自身にＴＰ継続回復状態を付与す\\n\u3000る。\\n・最も近い敵１キャラに魔法大ダメージを与える。\\n・残り時間が15秒を切ると、さらに攻撃が激し\\n\u3000く凶暴になる。その後、自身のＴＰを特大ダウ\\n\u3000ンする。', 320400, 0, 2, 320400, 270, 0, 0, 16, 0, 1.6, 3000, '赤い霧の精霊');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【魔法】『レジェンドオブアストルム』を守護す\\nる精霊。世界の調和を保つため、外部より紛れ込\\nんだ異端を排除すべく始動する。\\n\\n・ユニオンバーストは、敵全体に魔法大ダメージ\\n\u3000を与える。\\n・敵全体の物理攻撃力と魔法攻撃力を大ダウンさ\\n\u3000せる。さらに自身にＴＰ継続回復状態を付与す\\n\u3000る。\\n・最も近い敵１キャラに魔法大ダメージを与える。\\n・残り時間が15秒を切ると、さらに攻撃が激し\\n\u3000く凶暴になる。その後、自身のＴＰを特大ダウ\\n\u3000ンする。', 320401, 0, 2, 320400, 270, 0, 0, 16, 0, 1.6, 3000, '赤い霧の精霊');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【魔法】『レジェンドオブアストルム』を守護す\\nる精霊。世界の調和を保つため、外部より紛れ込\\nんだ異端を排除すべく始動する。\\n\\n・ユニオンバーストは、敵全体に魔法特大ダメー\\n\u3000ジを与える。\\n・敵全体の物理攻撃力と魔法攻撃力を大ダウンさ\\n\u3000せる。さらに自身にＴＰ継続回復状態を付与す\\n\u3000る。\\n・最も近い敵１キャラに魔法大ダメージを与える。\\n・残り時間が15秒を切ると、さらに攻撃が激し\\n\u3000く凶暴になる。その後、自身のＴＰを特大ダウ\\n\u3000ンする。', 320402, 0, 2, 320400, 270, 0, 0, 16, 0, 1.6, 3000, '赤い霧の精霊');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ１】自在に姿形を移せし赤霧は、理を\\n乱す敵対者の虚影を造り上げる。目覚めし力と絆\\nの輝きで、無情の幻を照らし払え。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を中アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・赤い霧の精霊から受けるすべてのダメージで発\\n\u3000生する、パーティキャラのＴＰ回復量を中ダウ\\n\u3000ンさせる。\\n・最も近い敵１キャラに魔法大ダメージを与える。', 320403, 0, 2, 320403, 270, 0, 0, 16, 0, 1.6, 3000, '赤い霧の精霊');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ２】対象への憑依と無力化を謀り生み\\n出されていく精霊の分裂体。ひとたび取り憑かれ\\nれば、その者の武や智は枯渇してしまうだろう。\\n\\n・赤い霧の精霊、分裂体から受けるすべてのダ\\n\u3000メージで発生する、パーティキャラのＴＰ回復\\n\u3000量を中ダウンさせる。\\n・ユニオンバーストは、敵全体に魔法特大ダメー\\n\u3000ジを与える。\\n・最も近い敵１キャラに魔法大ダメージを与える。\\n・敵全体をノックバックさせ、分裂体を召喚し、\\n\u3000自身のステータスダウン効果を解除する。\\n\u3000分裂体が召喚された際に既に別の分裂体が存在\\n\u3000する場合は、先に存在していた分裂体は消滅す\\n\u3000る。\\n・分裂体は、挑発を無視して、物理攻撃力もしく\\n\u3000は魔法攻撃力が最も高い敵１キャラの物理攻撃\\n\u3000力と魔法攻撃力を自身の魔法攻撃力に吸収する。\\n\u3000ただし分裂体のＨＰが一定値以下になった場合\\n\u3000は、挑発を無視して、物理攻撃力もしくは魔法\\n\u3000攻撃力が最も低い敵１キャラのステータスダウ\\n\u3000ン効果を解除し、赤い霧の精霊の物理防御力と\\n\u3000魔法防御力を特大ダウンさせ、消滅する。\\n・分裂体は、最も近い敵１キャラに魔法大ダメー\\n\u3000ジを与える。', 320404, 0, 2, 320403, 270, 0, 0, 16, 0, 1.6, 3000, '赤い霧の精霊');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ３】幾重にも渡る更新で格段に防衛力\\nを増強させたセキュリティプログラム。迫り来る\\n番人を退け、複製された世界の望みを繋げるか。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を中アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・赤い霧の精霊から受けるすべてのダメージで発\\n\u3000生する、パーティキャラのＴＰ回復量を中ダウ\\n\u3000ンさせる。\\n・ユニオンバーストは、敵全体に魔法特大ダメー\\n\u3000ジを与える。\\n・敵全体の物理攻撃力と魔法攻撃力を大ダウンさ\\n\u3000せる。さらに自身にＴＰ継続回復状態を付与す\\n\u3000る。\\n・最も近い敵１キャラに魔法大ダメージを与える。\\n・残り時間が30秒を切ると、さらに攻撃が激し\\n\u3000く凶暴になる。その後、自身のＴＰを特大ダウ\\n\u3000ンする。', 320405, 0, 2, 320403, 270, 0, 0, 16, 0, 1.6, 3000, '赤い霧の精霊');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ１】自在に姿形を移せし赤霧は、理を\\n乱す敵対者の虚影を造り上げる。目覚めし力と絆\\nの輝きで、無情の幻を照らし払え。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を中アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・赤い霧の精霊から受けるすべてのダメージで発\\n\u3000生する、パーティキャラのＴＰ回復量を中ダウ\\n\u3000ンさせる。\\n・最も近い敵１キャラに魔法大ダメージを与える。', 320406, 0, 2, 320403, 270, 0, 0, 16, 0, 1.6, 3000, '赤い霧の精霊');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ２】対象への憑依と無力化を謀り生み\\n出されていく精霊の分裂体。ひとたび取り憑かれ\\nれば、その者の武や智は枯渇してしまうだろう。\\n\\n・赤い霧の精霊、分裂体から受けるすべてのダ\\n\u3000メージで発生する、パーティキャラのＴＰ回復\\n\u3000量を中ダウンさせる。\\n・ユニオンバーストは、敵全体に魔法特大ダメー\\n\u3000ジを与える。\\n・最も近い敵１キャラに魔法大ダメージを与える。\\n・敵全体をノックバックさせ、分裂体を召喚し、\\n\u3000自身のステータスダウン効果を解除する。\\n\u3000分裂体が召喚された際に既に別の分裂体が存在\\n\u3000する場合は、先に存在していた分裂体は消滅す\\n\u3000る。\\n・分裂体は、挑発を無視して、物理攻撃力もしく\\n\u3000は魔法攻撃力が最も高い敵１キャラの物理攻撃\\n\u3000力と魔法攻撃力を自身の魔法攻撃力に吸収する。\\n\u3000ただし分裂体のＨＰが一定値以下になった場合\\n\u3000は、挑発を無視して、物理攻撃力もしくは魔法\\n\u3000攻撃力が最も低い敵１キャラのステータスダウ\\n\u3000ン効果を解除し、赤い霧の精霊の物理防御力と\\n\u3000魔法防御力を特大ダウンさせ、消滅する。\\n・分裂体は、最も近い敵１キャラに魔法大ダメー\\n\u3000ジを与える。', 320407, 0, 2, 320403, 270, 0, 0, 16, 0, 1.6, 3000, '赤い霧の精霊');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ３】幾重にも渡る更新で格段に防衛力\\nを増強させたセキュリティプログラム。迫り来る\\n番人を退け、複製された世界の望みを繋げるか。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を中アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・赤い霧の精霊から受けるすべてのダメージで発\\n\u3000生する、パーティキャラのＴＰ回復量を中ダウ\\n\u3000ンさせる。\\n・ユニオンバーストは、敵全体に魔法特大ダメー\\n\u3000ジを与える。\\n・敵全体の物理攻撃力と魔法攻撃力を大ダウンさ\\n\u3000せる。さらに自身にＴＰ継続回復状態を付与す\\n\u3000る。\\n・最も近い敵１キャラに魔法大ダメージを与える。\\n・残り時間が30秒を切ると、さらに攻撃が激し\\n\u3000く凶暴になる。その後、自身のＴＰを特大ダウ\\n\u3000ンする。', 320408, 0, 2, 320403, 270, 0, 0, 16, 0, 1.6, 3000, '赤い霧の精霊');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】赤い霧に憑かれし『複製の世界』の管理\\n者たち。超常の力を絡繰られ、苦衷の矛先は\\n『この世界』で紡いだ尊き絆へと向かう。\\n\\n・ユニオンバーストは、敵全体に物理割合ダメー\\n\u3000ジを与える。さらにＴＰを小ダウンさせ、ノッ\\n\u3000クバックさせる。このスキルはダメージを無効\\n\u3000化してもＴＰをダウンさせる。\\n・物理攻撃力が最も高い敵１キャラを中心とした\\n\u3000中範囲内の敵すべてに物理中ダメージを与え、\\n\u3000物理攻撃力と魔法攻撃力を中ダウンさせる。こ\\n\u3000のスキルの状態異常はダメージを無効化しても\\n\u3000付与される。\\n・魔法攻撃力が最も高い敵１キャラに物理中ダ\\n\u3000メージを与え、物理防御力を中ダウンさせる。\\n\u3000このスキルの状態異常はダメージを無効化して\\n\u3000も付与される。\\n・物理攻撃力が最も高い敵１キャラに物理大ダ\\n\u3000メージを与える。\\n・魔法攻撃力が最も高い敵１キャラに物理大ダ\\n\u3000メージを与える。さらに残りＨＰが50％未満\\n\u3000の場合、ノックバックさせ、スタン状態を付与\\n\u3000する。\\n・向かって左側のターゲットのブレイク時、\\n\u3000物理/魔法防御力が特大ダウン。\\n・向かって右側のターゲットのブレイク時、\\n\u3000物理/魔法防御力が特大ダウン。', 320500, 0, 1, 320500, 270, 0, 0, 16, 0, 1.6, 3000, '顕れる苦衷 アイラ＆シナツ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】赤い霧に憑かれし『複製の世界』の管理\\n者たち。超常の力を絡繰られ、苦衷の矛先は\\n『この世界』で紡いだ尊き絆へと向かう。\\n\\n・ユニオンバーストは、敵全体に物理割合ダメー\\n\u3000ジを与える。さらにＴＰを小ダウンさせ、ノッ\\n\u3000クバックさせる。このスキルはダメージを無効\\n\u3000化してもＴＰをダウンさせる。\\n・物理攻撃力が最も高い敵１キャラを中心とした\\n\u3000中範囲内の敵すべてに物理中ダメージを与え、\\n\u3000物理攻撃力と魔法攻撃力を中ダウンさせる。こ\\n\u3000のスキルの状態異常はダメージを無効化しても\\n\u3000付与される。\\n・魔法攻撃力が最も高い敵１キャラに物理中ダ\\n\u3000メージを与え、物理防御力を中ダウンさせる。\\n\u3000このスキルの状態異常はダメージを無効化して\\n\u3000も付与される。\\n・物理攻撃力が最も高い敵１キャラに物理大ダ\\n\u3000メージを与える。\\n・魔法攻撃力が最も高い敵１キャラに物理大ダ\\n\u3000メージを与える。さらに残りＨＰが50％未満\\n\u3000の場合、ノックバックさせ、スタン状態を付与\\n\u3000する。\\n・向かって左側のターゲットのブレイク時、\\n\u3000物理/魔法防御力が特大ダウン。\\n・向かって右側のターゲットのブレイク時、\\n\u3000物理/魔法防御力が特大ダウン。', 320501, 0, 1, 320500, 270, 0, 0, 16, 0, 1.6, 3000, '顕れる苦衷 アイラ＆シナツ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】赤い霧に憑かれし『複製の世界』の管理\\n者たち。超常の力を絡繰られ、苦衷の矛先は\\n『この世界』で紡いだ尊き絆へと向かう。\\n\\n・ユニオンバーストは、敵全体に物理割合ダメー\\n\u3000ジを与える。さらにＴＰを小ダウンさせ、ノッ\\n\u3000クバックさせる。このスキルはダメージを無効\\n\u3000化してもＴＰをダウンさせる。\\n・物理攻撃力が最も高い敵１キャラを中心とした\\n\u3000中範囲内の敵すべてに物理中ダメージを与え、\\n\u3000物理攻撃力と魔法攻撃力を中ダウンさせる。こ\\n\u3000のスキルの状態異常はダメージを無効化しても\\n\u3000付与される。\\n・魔法攻撃力が最も高い敵１キャラに物理中ダ\\n\u3000メージを与え、物理防御力を中ダウンさせる。\\n\u3000このスキルの状態異常はダメージを無効化して\\n\u3000も付与される。\\n・物理攻撃力が最も高い敵１キャラに物理大ダ\\n\u3000メージを与える。\\n・魔法攻撃力が最も高い敵１キャラに物理大ダ\\n\u3000メージを与える。さらに残りＨＰが50％未満\\n\u3000の場合、ノックバックさせ、スタン状態を付与\\n\u3000する。\\n・向かって左側のターゲットのブレイク時、\\n\u3000物理/魔法防御力が特大ダウン。\\n・向かって右側のターゲットのブレイク時、\\n\u3000物理/魔法防御力が特大ダウン。', 320502, 0, 1, 320500, 270, 0, 0, 16, 0, 1.6, 3000, '顕れる苦衷 アイラ＆シナツ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ１】赤き帳の下りた空から、紅の剛拳\\nが振り堕ちる。割ける大地、爆ぜる業火。理性を\\n失い荒狂う姿は、さながら藻掻く獣のようで――\\n\\n・シナツは赤い霧の精霊による支配に抗っており、\\n\u3000その場から動くことができない。\\n・物理攻撃力ダウン効果の影響を受けやすい。\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・バトル開始時、自身にＴＰダウン100％カッ\\n\u3000ト効果を付与する。\\n・バトル開始時、敵全体のＨＰ吸収を特大ダウン\\n\u3000させる。\\n・顕れる苦衷 アイラ＆シナツから受けるすべて\\n\u3000のダメージで発生する、パーティキャラのＴＰ\\n\u3000回復量を中ダウンさせる。\\n・自身を中心とした中範囲内の敵すべてに自身の\\n\u3000物理攻撃力に応じた物理割合ダメージを与え、\\n\u3000物理攻撃力と魔法攻撃力を中ダウンさせる。こ\\n\u3000のスキルの状態異常はダメージを無効化しても\\n\u3000付与される。\\n・最も近い敵１キャラに自身の物理攻撃力に応じ\\n\u3000た物理割合ダメージを与える。\\n・向かって左側のターゲットのブレイク時、\\n\u3000物理/魔法防御力が特大ダウン。\\n・向かって右側のターゲットのブレイク時、\\n\u3000物理/魔法防御力が特大ダウン。', 320503, 0, 1, 320503, 270, 0, 0, 16, 0, 1.6, 3000, '顕れる苦衷 アイラ＆シナツ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ２】青き瘴雷の陰より、藍の瞬剣が迸\\nる。震える大気、舞い荒ぶ嵐刃。無我に振り続け\\nる刀には、行き場のない憤りと鬱積が滲む――\\n\\n・アイラは赤い霧の精霊による支配に抗っており、\\n\u3000その場から動くことができない。\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・バトル開始時、自身にＴＰダウン100％カッ\\n\u3000ト効果を付与する。\\n・バトル開始時、敵全体のＨＰ吸収を特大ダウン\\n\u3000させる。\\n・顕れる苦衷 アイラ＆シナツから受けるすべて\\n\u3000のダメージで発生する、パーティキャラのＴＰ\\n\u3000回復量を中ダウンさせる。\\n・最も遠い３キャラに物理中ダメージを与え、物\\n\u3000理防御力を中ダウンさせる。さらにスタン状態\\n\u3000を付与する。このスキルの状態異常はダメージ\\n\u3000を無効化しても付与される。\\n・最も遠い２キャラに物理大ダメージを与える。\\n・向かって左側のターゲットのブレイク時、\\n\u3000物理/魔法防御力が特大ダウン。\\n・向かって右側のターゲットのブレイク時、\\n\u3000物理/魔法防御力が特大ダウン。', 320504, 0, 1, 320504, 270, 0, 0, 16, 0, 1.6, 3000, '顕れる苦衷 アイラ＆シナツ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ３】荒野に轟く悲哀の叫び。悠久の果\\nてに至りし絶望へ、少女たちは毅然と向き合い歩\\nみ寄る。もう一度、その手を握りしめるために。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を中アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・バトル開始時、自身にＴＰダウン100％カッ\\n\u3000ト効果を付与する。\\n・バトル開始時、敵全体のＨＰ吸収を特大ダウン\\n\u3000させる。\\n・顕れる苦衷 アイラ＆シナツから受けるすべて\\n\u3000のダメージで発生する、パーティキャラのＴＰ\\n\u3000回復量を中ダウンさせる。\\n・ユニオンバーストは、敵全体に物理割合ダメー\\n\u3000ジを与える。さらにＴＰを小ダウンさせ、ノッ\\n\u3000クバックさせる。このスキルはダメージを無効\\n\u3000化してもＴＰをダウンさせる。\\n・物理攻撃力が最も高い敵１キャラを中心とした\\n\u3000中範囲内の敵すべてに物理中ダメージを与え、\\n\u3000物理攻撃力と魔法攻撃力を中ダウンさせる。こ\\n\u3000のスキルの状態異常はダメージを無効化しても\\n\u3000付与される。\\n・魔法攻撃力が最も高い敵１キャラに物理中ダ\\n\u3000メージを与え、物理防御力を中ダウンさせる。\\n\u3000このスキルの状態異常はダメージを無効化して\\n\u3000も付与される。\\n・物理攻撃力が最も高い敵１キャラに物理大ダ\\n\u3000メージを与える。\\n・魔法攻撃力が最も高い敵１キャラに物理大ダ\\n\u3000メージを与える。さらに残りＨＰが50％未満\\n\u3000の場合、ノックバックさせ、スタン状態を付与\\n\u3000する。このスキルの状態異常はダメージを無効\\n\u3000化しても付与される。\\n・向かって左側のターゲットのブレイク時、\\n\u3000物理/魔法防御力が特大ダウン。\\n・向かって右側のターゲットのブレイク時、\\n\u3000物理/魔法防御力が特大ダウン。', 320505, 0, 1, 320505, 270, 0, 0, 16, 0, 1.6, 3000, '顕れる苦衷 アイラ＆シナツ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ１】赤き帳の下りた空から、紅の剛拳\\nが振り堕ちる。割ける大地、爆ぜる業火。理性を\\n失い荒狂う姿は、さながら藻掻く獣のようで――\\n\\n・シナツは赤い霧の精霊による支配に抗っており、\\n\u3000その場から動くことができない。\\n・物理攻撃力ダウン効果の影響を受けやすい。\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を中アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・バトル開始時、自身にＴＰダウン100％カッ\\n\u3000ト効果を付与する。\\n・バトル開始時、敵全体のＨＰ吸収を特大ダウン\\n\u3000させる。\\n・顕れる苦衷 アイラ＆シナツから受けるすべて\\n\u3000のダメージで発生する、パーティキャラのＴＰ\\n\u3000回復量を中ダウンさせる。\\n・自身を中心とした中範囲内の敵すべてに自身の\\n\u3000物理攻撃力に応じた物理割合ダメージを与え、\\n\u3000物理攻撃力と魔法攻撃力を中ダウンさせる。こ\\n\u3000のスキルの状態異常はダメージを無効化しても\\n\u3000付与される。\\n・最も近い敵１キャラに自身の物理攻撃力に応じ\\n\u3000た物理割合ダメージを与える。\\n・向かって左側のターゲットのブレイク時、\\n\u3000物理/魔法防御力が特大ダウン。\\n・向かって右側のターゲットのブレイク時、\\n\u3000物理/魔法防御力が特大ダウン。', 320506, 0, 1, 320503, 270, 0, 0, 16, 0, 1.6, 3000, '顕れる苦衷 アイラ＆シナツ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ２】青き瘴雷の陰より、藍の瞬剣が迸\\nる。震える大気、舞い荒ぶ嵐刃。無我に振り続け\\nる刀には、行き場のない憤りと鬱積が滲む――\\n\\n・アイラは赤い霧の精霊による支配に抗っており、\\n\u3000その場から動くことができない。\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を中アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・バトル開始時、自身にＴＰダウン100％カッ\\n\u3000ト効果を付与する。\\n・バトル開始時、敵全体のＨＰ吸収を特大ダウン\\n\u3000させる。\\n・顕れる苦衷 アイラ＆シナツから受けるすべて\\n\u3000のダメージで発生する、パーティキャラのＴＰ\\n\u3000回復量を中ダウンさせる。\\n・最も遠い３キャラに物理中ダメージを与え、物\\n\u3000理防御力を中ダウンさせる。さらにスタン状態\\n\u3000を付与する。このスキルの状態異常はダメージ\\n\u3000を無効化しても付与される。\\n・最も遠い２キャラに物理大ダメージを与える。\\n・向かって左側のターゲットのブレイク時、\\n\u3000物理/魔法防御力が特大ダウン。\\n・向かって右側のターゲットのブレイク時、\\n\u3000物理/魔法防御力が特大ダウン。', 320507, 0, 1, 320504, 270, 0, 0, 16, 0, 1.6, 3000, '顕れる苦衷 アイラ＆シナツ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ３】荒野に轟く悲哀の叫び。悠久の果\\nてに至りし絶望へ、少女たちは毅然と向き合い歩\\nみ寄る。もう一度、その手を握りしめるために。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を中アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・バトル開始時、自身にＴＰダウン100％カッ\\n\u3000ト効果を付与する。\\n・バトル開始時、敵全体のＨＰ吸収を特大ダウン\\n\u3000させる。\\n・顕れる苦衷 アイラ＆シナツから受けるすべて\\n\u3000のダメージで発生する、パーティキャラのＴＰ\\n\u3000回復量を中ダウンさせる。\\n・ユニオンバーストは、敵全体に物理割合ダメー\\n\u3000ジを与える。さらにＴＰを小ダウンさせ、ノッ\\n\u3000クバックさせる。このスキルはダメージを無効\\n\u3000化してもＴＰをダウンさせる。\\n・物理攻撃力が最も高い敵１キャラを中心とした\\n\u3000中範囲内の敵すべてに物理中ダメージを与え、\\n\u3000物理攻撃力と魔法攻撃力を中ダウンさせる。こ\\n\u3000のスキルの状態異常はダメージを無効化しても\\n\u3000付与される。\\n・魔法攻撃力が最も高い敵１キャラに物理中ダ\\n\u3000メージを与え、物理防御力を中ダウンさせる。\\n\u3000このスキルの状態異常はダメージを無効化して\\n\u3000も付与される。\\n・物理攻撃力が最も高い敵１キャラに物理大ダ\\n\u3000メージを与える。\\n・魔法攻撃力が最も高い敵１キャラに物理大ダ\\n\u3000メージを与える。さらに残りＨＰが50％未満\\n\u3000の場合、ノックバックさせ、スタン状態を付与\\n\u3000する。このスキルの状態異常はダメージを無効\\n\u3000化しても付与される。\\n・向かって左側のターゲットのブレイク時、\\n\u3000物理/魔法防御力が特大ダウン。\\n・向かって右側のターゲットのブレイク時、\\n\u3000物理/魔法防御力が特大ダウン。', 320508, 0, 1, 320505, 270, 0, 0, 16, 0, 1.6, 3000, '顕れる苦衷 アイラ＆シナツ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】ジオ・ゲヘナに棲む恐竜魔\\n物。頭のエリマキは威嚇だけでなく\\n刃のように変形し獲物を両断する。\\n\\n・バトル開始時、自身にＴＰダウン\\n\u300050％カット効果を付与する。\\n・エリマキレックスから受けるすべ\\n\u3000てのダメージで発生する、パー\\n\u3000ティキャラのＴＰ回復量を中ダ\\n\u3000ウンさせる。\\n・ユニオンバーストは、敵全体に\\n\u3000エリマキレックスの物理攻撃力\\n\u3000に応じた物理割合ダメージを与\\n\u3000える。\\n・前から２キャラに物理中ダメージ\\n\u3000を与え、ノックバックさせると同\\n\u3000時にスタンさせる。このスキルの\\n\u3000状態異常はダメージを無効化して\\n\u3000も付与される。', 320600, 0, 1, 320600, 270, 0, 0, 16, 0, 1.6, 3000, 'エリマキレックス');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】聖なる学舎の秘されし暗部を預かる獄卒。\\n教義絶対を掲げる『鋼の聖女』の正義を守るべく\\nまつろわぬ咎人に容赦なき服従と更生を強いる。\\n\\n・ユニオンバーストは、敵全体にキャラの最大\\n\u3000ＨＰに応じた物理割合ダメージを与える。自身\\n\u3000の物理攻撃力に応じて与えるダメージの割合が\\n\u3000増加する。\\n・最も近い敵３キャラにキャラの残りＨＰに応じ\\n\u3000た物理割合ダメージを与える。自身の物理攻撃\\n\u3000力に応じて与えるダメージの割合が増加する。\\n・自身の物理攻撃力を特大アップし、ＴＰを特大\\n\u3000回復する。自身のＨＰが低いほど、物理攻撃力\\n\u3000の上昇量がアップする。\\n・最も近い敵１キャラに物理特大ダメージを与え\\n\u3000る。', 320700, 0, 1, 320700, 270, 0, 0, 16, 0, 1.6, 3000, '奈落の聖女トミヱ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】聖なる学舎の秘されし暗部を預かる獄卒。\\n教義絶対を掲げる『鋼の聖女』の正義を守るべく\\nまつろわぬ咎人に容赦なき服従と更生を強いる。\\n\\n・ユニオンバーストは、敵全体にキャラの最大\\n\u3000ＨＰに応じた物理割合ダメージを与える。自身\\n\u3000の物理攻撃力に応じて与えるダメージの割合が\\n\u3000増加する。\\n・最も近い敵３キャラにキャラの残りＨＰに応じ\\n\u3000た物理割合ダメージを与える。自身の物理攻撃\\n\u3000力に応じて与えるダメージの割合が増加する。\\n・自身の物理攻撃力を特大アップし、ＴＰを特大\\n\u3000回復する。自身のＨＰが低いほど、物理攻撃力\\n\u3000の上昇量がアップする。\\n・最も近い敵１キャラに物理特大ダメージを与え\\n\u3000る。', 320701, 0, 1, 320700, 270, 0, 0, 16, 0, 1.6, 3000, '奈落の聖女トミヱ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】聖なる学舎の秘されし暗部を預かる獄卒。\\n教義絶対を掲げる『鋼の聖女』の正義を守るべく\\nまつろわぬ咎人に容赦なき服従と更生を強いる。\\n\\n・ユニオンバーストは、敵全体にキャラの最大\\n\u3000ＨＰに応じた物理割合ダメージを与える。自身\\n\u3000の物理攻撃力に応じて与えるダメージの割合が\\n\u3000増加する。\\n・最も近い敵３キャラにキャラの残りＨＰに応じ\\n\u3000た物理割合ダメージを与える。自身の物理攻撃\\n\u3000力に応じて与えるダメージの割合が増加する。\\n・自身の物理攻撃力を特大アップし、ＴＰを特大\\n\u3000回復する。自身のＨＰが低いほど、物理攻撃力\\n\u3000の上昇量がアップする。\\n・最も近い敵１キャラに物理特大ダメージを与え\\n\u3000る。', 320702, 0, 1, 320700, 270, 0, 0, 16, 0, 1.6, 3000, '奈落の聖女トミヱ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ１】最も強きを問う、過激派聖女の\\n個別矯正が始まる。鋼の頑健を試す奈落の聖槌は\\n魔道に恃み肉体の鍛錬を怠った者を赦さない。\\n\\n・奈落の聖女トミヱから受けるすべてのダメージ\\n\u3000で発生する、パーティキャラのＴＰ回復量を\\n\u3000特大アップさせる。\\n・ユニオンバーストは、最も近い敵１キャラに\\n\u3000キャラの最大ＨＰに応じた物理割合ダメージを\\n\u3000与える。\\n・最も近い敵１キャラが物理攻撃キャラの場合、\\n\u3000キャラの残りＨＰに応じた物理割合ダメージを\\n\u3000与える。自身の物理攻撃力に応じて与えるダ\\n\u3000メージの割合が増加する。魔法攻撃キャラの場\\n\u3000合、37564×７ヒットの物理固定ダメージ\\n\u3000を与える。この物理固定ダメージでは、敵のＴ\\n\u3000Ｐが回復しない。\\n・最も近い敵１キャラが物理攻撃キャラの場合、\\n\u3000物理特大ダメージを与える。魔法攻撃キャラの\\n\u3000場合、37564×６ヒットの物理固定ダメー\\n\u3000ジを与える。この物理固定ダメージでは、敵の\\n\u3000ＴＰが回復しない。\\n・タイマンフィールドを展開し、自身に魔法ダ\\n\u3000メージ100％カット効果を付与する。\\n\\n【タイマンフィールド効果】\\n以下の効果が発動する。\\n・飛行状態のキャラを含む敵全体をノックバック\\n\u3000させ、物理固定１ダメージを与える。さらに束\\n\u3000縛状態を付与する。\\n・物理攻撃力もしくは魔法攻撃力が最も高い敵１\\n\u3000キャラにボスから受ける行動不能を無効化する\\n\u3000状態を付与する。さらに挑発状態を付与し、タ\\n\u3000イマンバトルを仕掛ける。\\n・物理攻撃力もしくは魔法攻撃力が最も高い敵１\\n\u3000キャラが行動不能状態の場合、ボス自身のＴＰ\\n\u3000を特大ダウンさせ、再度タイマンフィールド効\\n\u3000果を発動する。', 320703, 0, 1, 320703, 270, 0, 0, 16, 0, 1.6, 3000, '奈落の聖女トミヱ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ２】騒乱の息吹に昂揚した聖女が、\\n戦場をあまねく業火に包んで煉獄の狂宴を開く。\\n互いの命を削り合った先に立っているのは誰か。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を大アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・奈落の聖女トミヱから受けるすべてのダメージ\\n\u3000で発生する、パーティキャラのＴＰ回復量を中\\n\u3000ダウンさせる。\\n・ユニオンバーストは、敵全体にキャラの最大\\n\u3000ＨＰに応じた物理割合ダメージを与える。自身\\n\u3000の物理攻撃力に応じて与えるダメージの割合が\\n\u3000増加する。\\n・最も近い敵３キャラにキャラの残りＨＰに応じ\\n\u3000た物理割合ダメージを与える。自身の物理攻撃\\n\u3000力に応じて与えるダメージの割合が増加する。\\n・最も近い敵１キャラに物理特大ダメージを与え\\n\u3000る。\\n・根性試しフィールドを展開する。\\n\\n【根性試しフィールド効果】\\n以下の効果が発動する。\\n・敵全体のＨＰ吸収を特大ダウンさせる。\\n・敵全体のＨＰ回復量を特大ダウンさせる。\\n・自身と敵全体に毎秒継続ダメージを与える。こ\\n\u3000のスキルによるダメージでは、敵のＴＰが回復\\n\u3000しない。', 320704, 0, 1, 320704, 270, 0, 0, 16, 0, 1.6, 3000, '奈落の聖女トミヱ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ３】咎人の眼に覚悟を認めた聖女は、\\n自らの魂を燃やし尽くし本気の向こう側へ挑む。\\n最後の激闘を制して真ひゃん人を炙り出せ。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を中アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・奈落の聖女トミヱから受けるすべてのダメージ\\n\u3000で発生する、パーティキャラのＴＰ回復量を中\\n\u3000ダウンさせる。\\n・ユニオンバーストは、敵全体にキャラの最大\\n\u3000ＨＰに応じた物理割合ダメージを与える。自身\\n\u3000の物理攻撃力に応じて与えるダメージの割合が\\n\u3000増加する。\\n・最も近い敵３キャラにキャラの残りＨＰに応じ\\n\u3000た物理割合ダメージを与える。自身の物理攻撃\\n\u3000力に応じて与えるダメージの割合が増加する。\\n・自身の物理攻撃力を特大アップし、ＴＰを特大\\n\u3000回復する。自身のＨＰが低いほど、物理攻撃力\\n\u3000の上昇量がアップする。\\n・最も近い敵１キャラに物理特大ダメージを与え\\n\u3000る。', 320705, 0, 1, 320704, 270, 0, 0, 16, 0, 1.6, 3000, '奈落の聖女トミヱ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ１】最も強きを問う、過激派聖女の\\n個別矯正が始まる。鋼の頑健を試す奈落の聖槌は\\n魔道に恃み肉体の鍛錬を怠った者を赦さない。\\n\\n・奈落の聖女トミヱから受けるすべてのダメージ\\n\u3000で発生する、パーティキャラのＴＰ回復量を\\n\u3000特大アップさせる。\\n・ユニオンバーストは、最も近い敵１キャラに\\n\u3000キャラの最大ＨＰに応じた物理割合ダメージを\\n\u3000与える。\\n・最も近い敵１キャラが物理攻撃キャラの場合、\\n\u3000キャラの残りＨＰに応じた物理割合ダメージを\\n\u3000与える。自身の物理攻撃力に応じて与えるダ\\n\u3000メージの割合が増加する。魔法攻撃キャラの場\\n\u3000合、37564×７ヒットの物理固定ダメージ\\n\u3000を与える。この物理固定ダメージでは、敵のＴ\\n\u3000Ｐが回復しない。\\n・最も近い敵１キャラが物理攻撃キャラの場合、\\n\u3000物理特大ダメージを与える。魔法攻撃キャラの\\n\u3000場合、37564×６ヒットの物理固定ダメー\\n\u3000ジを与える。この物理固定ダメージでは、敵の\\n\u3000ＴＰが回復しない。\\n・タイマンフィールドを展開し、自身に魔法ダ\\n\u3000メージ100％カット効果を付与する。\\n\\n【タイマンフィールド効果】\\n以下の効果が発動する。\\n・飛行状態のキャラを含む敵全体をノックバック\\n\u3000させ、物理固定１ダメージを与える。さらに束\\n\u3000縛状態を付与する。\\n・物理攻撃力もしくは魔法攻撃力が最も高い敵１\\n\u3000キャラにボスから受ける行動不能を無効化する\\n\u3000状態を付与する。さらに挑発状態を付与し、タ\\n\u3000イマンバトルを仕掛ける。\\n・物理攻撃力もしくは魔法攻撃力が最も高い敵１\\n\u3000キャラが行動不能状態の場合、ボス自身のＴＰ\\n\u3000を特大ダウンさせ、再度タイマンフィールド効\\n\u3000果を発動する。', 320706, 0, 1, 320703, 270, 0, 0, 16, 0, 1.6, 3000, '奈落の聖女トミヱ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ２】騒乱の息吹に昂揚した聖女が、\\n戦場をあまねく業火に包んで煉獄の狂宴を開く。\\n互いの命を削り合った先に立っているのは誰か。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を大アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・奈落の聖女トミヱから受けるすべてのダメージ\\n\u3000で発生する、パーティキャラのＴＰ回復量を中\\n\u3000ダウンさせる。\\n・ユニオンバーストは、敵全体にキャラの最大\\n\u3000ＨＰに応じた物理割合ダメージを与える。自身\\n\u3000の物理攻撃力に応じて与えるダメージの割合が\\n\u3000増加する。\\n・最も近い敵３キャラにキャラの残りＨＰに応じ\\n\u3000た物理割合ダメージを与える。自身の物理攻撃\\n\u3000力に応じて与えるダメージの割合が増加する。\\n・最も近い敵１キャラに物理特大ダメージを与え\\n\u3000る。\\n・根性試しフィールドを展開する。\\n\\n【根性試しフィールド効果】\\n以下の効果が発動する。\\n・敵全体のＨＰ吸収を特大ダウンさせる。\\n・敵全体のＨＰ回復量を特大ダウンさせる。\\n・自身と敵全体に毎秒継続ダメージを与える。こ\\n\u3000のスキルによるダメージでは、敵のＴＰが回復\\n\u3000しない。', 320707, 0, 1, 320704, 270, 0, 0, 16, 0, 1.6, 3000, '奈落の聖女トミヱ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ３】咎人の眼に覚悟を認めた聖女は、\\n自らの魂を燃やし尽くし本気の向こう側へ挑む。\\n最後の激闘を制して真ひゃん人を炙り出せ。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を大アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・奈落の聖女トミヱから受けるすべてのダメージ\\n\u3000で発生する、パーティキャラのＴＰ回復量を中\\n\u3000ダウンさせる。\\n・ユニオンバーストは、敵全体にキャラの最大\\n\u3000ＨＰに応じた物理割合ダメージを与える。自身\\n\u3000の物理攻撃力に応じて与えるダメージの割合が\\n\u3000増加する。\\n・最も近い敵３キャラにキャラの残りＨＰに応じ\\n\u3000た物理割合ダメージを与える。自身の物理攻撃\\n\u3000力に応じて与えるダメージの割合が増加する。\\n・自身の物理攻撃力を特大アップし、ＴＰを特大\\n\u3000回復する。自身のＨＰが低いほど、物理攻撃力\\n\u3000の上昇量がアップする。\\n・最も近い敵１キャラに物理特大ダメージを与え\\n\u3000る。', 320708, 0, 1, 320704, 270, 0, 0, 16, 0, 1.6, 3000, '奈落の聖女トミヱ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【魔法】死してなお強敵を求め続けるタフガイ。\\n生前の腕力と死後の霊力を駆使し相手を圧倒する。\\n\\n・物理攻撃力ダウンと魔法攻撃力ダウン効果の影\\n\u3000響を受けやすい。\\n・付与される継続ダメージの影響を受けやすい。\\n・バトル中、タフガイスト自身に付与されている\\n\u3000状態異常効果およびステータスダウン効果の数\\n\u3000に応じて、与えられるダメージの量が大きく上\\n\u3000昇する。\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を特大アップさせる。この防御力アップ効果で\\n\u3000上昇した防御力は、バトル中に受ける防御力ダ\\n\u3000ウンスキルの影響を受けない。\\n・タフガイストから受けるすべてのダメージで発\\n\u3000生する、パーティキャラのＴＰ回復量を中ダウ\\n\u3000ンさせる。\\n・ユニオンバーストは、飛行状態のキャラを含む\\n\u3000敵全体に自身の物理攻撃力に応じた物理割合ダ\\n\u3000メージと自身の魔法攻撃力に応じた魔法割合ダ\\n\u3000メージを与える。このスキルによるダメージで\\n\u3000は、ＴＰが回復しない。\\n・自身の物理攻撃力、魔法攻撃力、物理防御力、\\n\u3000魔法防御力をバトル終了まで小アップさせる。\\n・通常攻撃は、最も近い敵１キャラに物理大ダ\\n\u3000メージと魔法大ダメージを与える。\\n・右拳のブレイク時、自身の物理攻撃力が特大ダ\\n\u3000ウンする。\\n・胴体のブレイク時、自身の物理防御力と魔法防\\n\u3000御力が大ダウンする。\\n・左拳のブレイク時、自身の魔法攻撃力が特大ダ\\n\u3000ウンする。', 320800, 0, 2, 320800, 270, 0, 0, 16, 0, 1.6, 3000, 'タフガイスト');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【魔法】死してなお強敵を求め続けるタフガイ。\\n生前の腕力と死後の霊力を駆使し相手を圧倒する。\\n\\n・物理攻撃力ダウンと魔法攻撃力ダウン効果の影\\n\u3000響を受けやすい。\\n・付与される継続ダメージの影響を受けやすい。\\n・バトル中、タフガイスト自身に付与されている\\n\u3000状態異常効果およびステータスダウン効果の数\\n\u3000に応じて、与えられるダメージの量が大きく上\\n\u3000昇する。\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を特大アップさせる。この防御力アップ効果で\\n\u3000上昇した防御力は、バトル中に受ける防御力ダ\\n\u3000ウンスキルの影響を受けない。\\n・バトル開始時、敵全体のＨＰ吸収を特大ダウン\\n\u3000させる。\\n・バトル開始時、敵全体のＴＰ上昇を小ダウンさ\\n\u3000せるフィールドを展開する。\\n・バトル開始時、自身にＴＰダウン100％カッ\\n\u3000ト効果を付与する。\\n・タフガイストから受けるすべてのダメージで発\\n\u3000生する、パーティキャラのＴＰ回復量を中ダウ\\n\u3000ンさせる。\\n・ユニオンバーストは、飛行状態のキャラを含む\\n\u3000敵全体に自身の物理攻撃力に応じた物理割合ダ\\n\u3000メージと自身の魔法攻撃力に応じた魔法割合ダ\\n\u3000メージを与える。このスキルによるダメージで\\n\u3000は、ＴＰが回復しない。\\n・自身の物理攻撃力、魔法攻撃力、物理防御力、\\n\u3000魔法防御力をバトル終了まで小アップさせ、\\n\u3000ＴＰを大回復する。\\n・通常攻撃は、最も近い敵１キャラに物理大ダ\\n\u3000メージと魔法大ダメージを与える。\\n・右拳のブレイク時、自身の物理攻撃力が特大ダ\\n\u3000ウンする。\\n・胴体のブレイク時、自身の物理防御力と魔法防\\n\u3000御力が大ダウンする。\\n・左拳のブレイク時、自身の魔法攻撃力が特大ダ\\n\u3000ウンする。', 320801, 0, 2, 320801, 270, 0, 0, 16, 0, 1.6, 3000, 'タフガイスト');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】最終訓練にて遭遇した剛力無双の一角獣。\\n筋骨隆々の怪腕が大地を割り、稲妻纏う雷角が\\n新兵たちの喉元に突き立てられる。\\n\\n・ユニオンバーストは、敵全体に自身の物理防御\\n\u3000力に応じた物理大ダメージと、自身の魔法防御\\n\u3000力に応じた魔法大ダメージを与える。\\n・最も近い敵３キャラに物理大ダメージを与える。\\n・最も近い敵１キャラに物理特大ダメージを与え、\\n\u3000スタン状態を付与する。このスキルの状態異常\\n\u3000はダメージを無効化しても付与される。', 320900, 0, 1, 320900, 270, 0, 0, 16, 0, 1.6, 3000, '剛雷獣・ライガホーン');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】最終訓練にて遭遇した剛力無双の一角獣。\\n筋骨隆々の怪腕が大地を割り、稲妻纏う雷角が\\n新兵たちの喉元に突き立てられる。\\n\\n・ユニオンバーストは、敵全体に自身の物理防御\\n\u3000力に応じた物理大ダメージと、自身の魔法防御\\n\u3000力に応じた魔法大ダメージを与える。\\n・最も近い敵３キャラに物理大ダメージを与える。\\n・最も近い敵１キャラに物理特大ダメージを与え、\\n\u3000スタン状態を付与する。このスキルの状態異常\\n\u3000はダメージを無効化しても付与される。', 320901, 0, 1, 320900, 270, 0, 0, 16, 0, 1.6, 3000, '剛雷獣・ライガホーン');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】最終訓練にて遭遇した剛力無双の一角獣。\\n筋骨隆々の怪腕が大地を割り、稲妻纏う雷角が\\n新兵たちの喉元に突き立てられる。\\n\\n・ユニオンバーストは、敵全体に自身の物理防御\\n\u3000力に応じた物理大ダメージと、自身の魔法防御\\n\u3000力に応じた魔法大ダメージを与える。\\n・最も近い敵３キャラに物理大ダメージを与える。\\n・最も近い敵１キャラに物理特大ダメージを与え、\\n\u3000スタン状態を付与する。このスキルの状態異常\\n\u3000はダメージを無効化しても付与される。\\n・自身のＨＰが30％を切ると、自身の物理防御\\n\u3000力と魔法防御力が大アップする。さらに自身の\\n\u3000行動速度が大アップする。', 320902, 0, 1, 320900, 270, 0, 0, 16, 0, 1.6, 3000, '剛雷獣・ライガホーン');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ１】巨角を蒼く輝かせ、雄々しき肉体\\nは雷を蓄える。臨界点に達せば勝負はそれまで。\\n降り注ぐ蛮雷はあたり一面を塵へと変えるだろう。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・剛雷獣・ライガホーンから受けるすべてのダ\\n\u3000メージで発生する、パーティキャラのＴＰ回復\\n\u3000量を中ダウンさせる。\\n・ユニオンバーストは、敵全体に物理特大ダメー\\n\u3000ジと魔法特大ダメージを与える。\\n\u3000さらに【滅却の蛮雷】使用までのカウントダウ\\n\u3000ンが進む。\\n\u3000【滅却の蛮雷】使用までのカウントダウンが\\n\u3000０回になった時、【滅却の蛮雷】を使用する。\\n・最も近い敵３キャラに物理大ダメージを与える。\\n・最も近い敵１キャラに物理特大ダメージを与え、\\n\u3000スタン状態を付与する。このスキルの状態異常\\n\u3000はダメージを無効化しても付与される。\\n\\n【滅却の蛮雷】\\n・飛行状態のキャラを含む敵全体に999999\\n\u3000×５ヒットの魔法固定ダメージを与える。この\\n\u3000スキルで受けるダメージでは、敵のＴＰが回復\\n\u3000しない。', 320903, 0, 1, 320903, 270, 0, 0, 16, 0, 1.6, 3000, '剛雷獣・ライガホーン');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ２】森の魔物を従属させるは恐れ慕い\\nし教官たちの影。真の『壊し屋』の教え子なれば、\\n紛いものになど屈することは許されない。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・剛雷獣・ライガホーンから受けるすべてのダ\\n\u3000メージで発生する、パーティキャラのＴＰ回復\\n\u3000量を中ダウンさせる。\\n・剛雷獣・ライガホーンは環境効果によるダメー\\n\u3000ジを受けない。\\n・最も近い敵１キャラに物理特大ダメージを与え、\\n\u3000スタン状態を付与する。このスキルの状態異常\\n\u3000はダメージを無効化しても付与される。', 320904, 0, 1, 320904, 270, 0, 0, 16, 0, 1.6, 3000, '剛雷獣・ライガホーン');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ３】猛る獣は死力を尽くし雷光を迸ら\\nせる。厳しくも実り豊かなブートキャンプの集大\\n成！恐怖に打ち勝ち、一人前の『騎士』と成れ！\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を中アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・バトル開始時、自身にＴＰダウン50％カット\\n\u3000効果を付与する。\\n・剛雷獣・ライガホーンから受けるすべてのダ\\n\u3000メージで発生する、パーティキャラのＴＰ回復\\n\u3000量を中ダウンさせる。\\n・ユニオンバーストは、敵全体に自身の物理防御\\n\u3000力に応じた物理大ダメージと、自身の魔法防御\\n\u3000力に応じた魔法大ダメージを与える。\\n・最も近い敵３キャラに物理大ダメージを与える。\\n・最も近い敵１キャラに物理特大ダメージを与え、\\n\u3000スタン状態を付与する。このスキルの状態異常\\n\u3000はダメージを無効化しても付与される。\\n・自身のＨＰが50％を切ると、自身の物理防御\\n\u3000力と魔法防御力が大アップする。さらに自身の\\n\u3000行動速度が大アップする。', 320905, 0, 1, 320904, 270, 0, 0, 16, 0, 1.6, 3000, '剛雷獣・ライガホーン');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ１】巨角を蒼く輝かせ、雄々しき肉体\\nは雷を蓄える。臨界点に達せば勝負はそれまで。\\n降り注ぐ蛮雷はあたり一面を塵へと変えるだろう。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を中アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・剛雷獣・ライガホーンから受けるすべてのダ\\n\u3000メージで発生する、パーティキャラのＴＰ回復\\n\u3000量を中ダウンさせる。\\n・ユニオンバーストは、敵全体に物理特大ダメー\\n\u3000ジと魔法特大ダメージを与える。\\n\u3000さらに【滅却の蛮雷】使用までのカウントダウ\\n\u3000ンが進む。\\n\u3000【滅却の蛮雷】使用までのカウントダウンが\\n\u3000０回になった時、【滅却の蛮雷】を使用する。\\n・最も近い敵３キャラに物理大ダメージを与える。\\n・最も近い敵１キャラに物理特大ダメージを与え、\\n\u3000スタン状態を付与する。このスキルの状態異常\\n\u3000はダメージを無効化しても付与される。\\n\\n【滅却の蛮雷】\\n・飛行状態のキャラを含む敵全体に999999\\n\u3000×５ヒットの魔法固定ダメージを与える。この\\n\u3000スキルで受けるダメージでは、敵のＴＰが回復\\n\u3000しない。', 320906, 0, 1, 320903, 270, 0, 0, 16, 0, 1.6, 3000, '剛雷獣・ライガホーン');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ２】森の魔物を従属させるは恐れ慕い\\nし教官たちの影。真の『壊し屋』の教え子なれば、\\n紛いものになど屈することは許されない。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を中アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・剛雷獣・ライガホーンから受けるすべてのダ\\n\u3000メージで発生する、パーティキャラのＴＰ回復\\n\u3000量を中ダウンさせる。\\n・剛雷獣・ライガホーンは環境効果によるダメー\\n\u3000ジを受けない。\\n・最も近い敵１キャラに物理特大ダメージを与え、\\n\u3000スタン状態を付与する。このスキルの状態異常\\n\u3000はダメージを無効化しても付与される。', 320907, 0, 1, 320904, 270, 0, 0, 16, 0, 1.6, 3000, '剛雷獣・ライガホーン');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ３】猛る獣は死力を尽くし雷光を迸ら\\nせる。厳しくも実り豊かなブートキャンプの集大\\n成！恐怖に打ち勝ち、一人前の『騎士』と成れ！\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を中アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・バトル開始時、自身にＴＰダウン50％カット\\n\u3000効果を付与する。\\n・剛雷獣・ライガホーンから受けるすべてのダ\\n\u3000メージで発生する、パーティキャラのＴＰ回復\\n\u3000量を中ダウンさせる。\\n・ユニオンバーストは、敵全体に自身の物理防御\\n\u3000力に応じた物理大ダメージと、自身の魔法防御\\n\u3000力に応じた魔法大ダメージを与える。\\n・最も近い敵３キャラに物理大ダメージを与える。\\n・最も近い敵１キャラに物理特大ダメージを与え、\\n\u3000スタン状態を付与する。このスキルの状態異常\\n\u3000はダメージを無効化しても付与される。\\n・自身のＨＰが50％を切ると、自身の物理防御\\n\u3000力と魔法防御力が大アップする。さらに自身の\\n\u3000行動速度が大アップする。', 320908, 0, 1, 320904, 270, 0, 0, 16, 0, 1.6, 3000, '剛雷獣・ライガホーン');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】ジオ・ゲヘナに聳える巨大\\n怪獣型魔物。口から熱光線を放出し\\n豪腕と尾で矮小な獲物を蹂躙する。\\n\\n・ユニオンバーストは、敵全体のバ\\n\u3000リアを解除し、敵全体に魔法割合\\n\u3000ダメージを与え、さらに物理防御\\n\u3000力を60％ダウンし、ＨＰ吸収を\\n\u3000特大ダウンさせる。このスキルの\\n\u3000状態異常はダメージを無効化して\\n\u3000も付与される。\\n・敵全体に物理大ダメージを与え\\n\u3000る。さらに、キャラのＨＰが\\n\u300090％未満の場合スタンさせる。\\n\u3000このスキルの状態異常はダメージ\\n\u3000を無効化しても付与される。\\n・敵全体に物理特大ダメージ。\\n・強獣ゲドンのＨＰが一定値以下に\\n\u3000なると、ユニオンバーストが強化\\n\u3000され、スキルが物理と魔法ダメー\\n\u3000ジになる。', 321000, 0, 1, 321000, 200, 0, 0, 16, 0, 1.6, 3000, '強獣ゲドン');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【魔法】品種改良を施され、卑劣漢に服従するよ\\nう仕立てられた魔物植物。絢爛と咲き誇る巨躯は\\n悪意に操られるがまま花祭りの開催を脅かす。\\n\\n・ユニオンバーストは、敵全体に最大ＨＰに応じ\\n\u3000た魔法割合ダメージを与え、ＴＰを中ダウンさ\\n\u3000せる。さらに物理防御力と魔法防御力を大ダウ\\n\u3000ンさせる。自身の物理防御力と魔法防御力を\\n\u3000特大アップさせる。このスキルの状態異常は\\n\u3000ダメージを無効化しても付与される。このスキ\\n\u3000ルはダメージを無効化してもＴＰダウンさせる。\\n・敵全体に魔法大ダメージを与え、行動速度を中\\n\u3000ダウンさせる。このスキルの状態異常は\\n\u3000ダメージを無効化しても付与される。\\n・自身の魔法攻撃力を大アップさせる。\\n・魔法攻撃力が最も低い敵１キャラに魔法特大ダ\\n\u3000メージを与え、スタン状態を付与する。このス\\n\u3000キルの状態異常はダメージを無効化しても付与\\n\u3000される。', 321100, 0, 2, 321100, 270, 0, 0, 16, 0, 1.6, 3000, '魔物植物・モベルベ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【魔法】品種改良を施され、卑劣漢に服従するよ\\nう仕立てられた魔物植物。絢爛と咲き誇る巨躯は\\n悪意に操られるがまま花祭りの開催を脅かす。\\n\\n・ユニオンバーストは、敵全体に最大ＨＰに応じ\\n\u3000た魔法割合ダメージを与え、ＴＰを中ダウンさ\\n\u3000せる。さらに物理防御力と魔法防御力を大ダウ\\n\u3000ンさせる。自身の物理防御力と魔法防御力を\\n\u3000特大アップさせる。このスキルの状態異常は\\n\u3000ダメージを無効化しても付与される。このスキ\\n\u3000ルはダメージを無効化してもＴＰダウンさせる。\\n・敵全体に魔法大ダメージを与え、行動速度を中\\n\u3000ダウンさせる。このスキルの状態異常は\\n\u3000ダメージを無効化しても付与される。\\n・自身の魔法攻撃力を大アップさせる。\\n・魔法攻撃力が最も低い敵１キャラに魔法特大ダ\\n\u3000メージを与え、スタン状態を付与する。このス\\n\u3000キルの状態異常はダメージを無効化しても付与\\n\u3000される。', 321101, 0, 2, 321100, 270, 0, 0, 16, 0, 1.6, 3000, '魔物植物・モベルベ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【魔法】品種改良を施され、卑劣漢に服従するよ\\nう仕立てられた魔物植物。絢爛と咲き誇る巨躯は\\n悪意に操られるがまま花祭りの開催を脅かす。\\n\\n・ユニオンバーストは、敵全体に最大ＨＰに応じ\\n\u3000た魔法割合ダメージを与え、ＴＰを中ダウンさ\\n\u3000せる。さらに物理防御力と魔法防御力を大ダウ\\n\u3000ンさせる。自身の物理防御力と魔法防御力を\\n\u3000特大アップさせる。このスキルの状態異常は\\n\u3000ダメージを無効化しても付与される。このスキ\\n\u3000ルはダメージを無効化してもＴＰダウンさせる。\\n・敵全体に魔法大ダメージを与え、行動速度を中\\n\u3000ダウンさせる。このスキルの状態異常は\\n\u3000ダメージを無効化しても付与される。\\n・自身の魔法攻撃力を大アップさせる。\\n・魔法攻撃力が最も低い敵１キャラに魔法特大ダ\\n\u3000メージを与え、スタン状態を付与する。このス\\n\u3000キルの状態異常はダメージを無効化しても付与\\n\u3000される。', 321102, 0, 2, 321100, 270, 0, 0, 16, 0, 1.6, 3000, '魔物植物・モベルベ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ１】鮮やかな大輪を地表に残し、魔物\\nは土中深くに身を潜める。再びその姿があらわと\\nなるとき、辺りは猛毒の花粉で満たされるだろう。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を中アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・地面に潜り、敵全体に毒状態を付与し続ける。\\n\u3000さらに、敵全体のＨＰ回復量を大ダウンさせる。\\n\u3000地面に潜っている最中、自身が一定ダメージを\\n\u3000受けると、スキルが中断され、自身のステータ\\n\u3000スダウン効果を解除し、物理防御力と魔法防御\\n\u3000力を特大ダウンさせる。中断されずに毒を撒き\\n\u3000終えると、敵全体に長時間のスタン状態を付与\\n\u3000する。このスキルにより付与された毒の\\n\u3000ダメージでは、ＴＰが回復しない。', 321103, 0, 2, 321103, 270, 0, 0, 16, 0, 1.6, 3000, '魔物植物・モベルベ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ２】森に潜む脅威が魔物植物に呼応す\\nるかのごとく押し寄せる。思わぬドジが命取りと\\nならぬよう、冷静に草木の群れを打ち破れ。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を中アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・魔物植物・モベルベから受けるすべての\\n\u3000ダメージで発生する、パーティキャラのＴＰ\\n\u3000回復量を中ダウンさせる。\\n・魔法攻撃力が最も低い敵１キャラに魔法特大ダ\\n\u3000メージを与え、スタン状態を付与する。このス\\n\u3000キルの状態異常はダメージを無効化しても付与\\n\u3000される。', 321104, 0, 2, 321103, 270, 0, 0, 16, 0, 1.6, 3000, '魔物植物・モベルベ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ３】主の命を遂行すべく、魔物植物は\\nひたすら愚直に村を目指す。不屈の覚悟で進行を\\n食い止め、笑顔咲く祭典を始めよう！ \\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を中アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・魔物植物・モベルベから受けるすべての\\n\u3000ダメージで発生する、パーティキャラのＴＰ\\n\u3000回復量を中ダウンさせる。\\n・ユニオンバーストは、敵全体に最大ＨＰに応じ\\n\u3000た魔法割合ダメージを与え、ＴＰを中ダウンさ\\n\u3000せる。さらに物理防御力と魔法防御力を大ダウ\\n\u3000ンさせる。自身の物理防御力と魔法防御力を\\n\u3000特大アップさせる。このスキルの状態異常は\\n\u3000ダメージを無効化しても付与される。このスキ\\n\u3000ルはダメージを無効化してもＴＰダウンさせる。\\n・敵全体に魔法大ダメージを与え、行動速度を\\n\u3000特大ダウンさせる。このスキルの状態異常は\\n\u3000ダメージを無効化しても付与される。\\n・自身の魔法攻撃力を大アップさせる。\\n・魔法攻撃力が最も低い敵１キャラに魔法特大ダ\\n\u3000メージを与え、スタン状態を付与する。このス\\n\u3000キルの状態異常はダメージを無効化しても付与\\n\u3000される。', 321105, 0, 2, 321103, 270, 0, 0, 16, 0, 1.6, 3000, '魔物植物・モベルベ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ１】鮮やかな大輪を地表に残し、魔物\\nは土中深くに身を潜める。再びその姿があらわと\\nなるとき、辺りは猛毒の花粉で満たされるだろう。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を中アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・地面に潜り、敵全体に毒状態を付与し続ける。\\n\u3000さらに、敵全体のＨＰ回復量を大ダウンさせる。\\n\u3000地面に潜っている最中、自身が一定ダメージを\\n\u3000受けると、スキルが中断され、自身のステータ\\n\u3000スダウン効果を解除し、物理防御力と魔法防御\\n\u3000力を特大ダウンさせる。中断されずに毒を撒き\\n\u3000終えると、敵全体に長時間のスタン状態を付与\\n\u3000する。このスキルにより付与された毒の\\n\u3000ダメージでは、ＴＰが回復しない。', 321106, 0, 2, 321103, 270, 0, 0, 16, 0, 1.6, 3000, '魔物植物・モベルベ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ２】森に潜む脅威が魔物植物に呼応す\\nるかのごとく押し寄せる。思わぬドジが命取りと\\nならぬよう、冷静に草木の群れを打ち破れ。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を中アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・魔物植物・モベルベから受けるすべての\\n\u3000ダメージで発生する、パーティキャラのＴＰ\\n\u3000回復量を中ダウンさせる。\\n・魔法攻撃力が最も低い敵１キャラに魔法特大ダ\\n\u3000メージを与え、スタン状態を付与する。このス\\n\u3000キルの状態異常はダメージを無効化しても付与\\n\u3000される。', 321107, 0, 2, 321103, 270, 0, 0, 16, 0, 1.6, 3000, '魔物植物・モベルベ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【ＭＯＤＥ３】主の命を遂行すべく、魔物植物は\\nひたすら愚直に村を目指す。不屈の覚悟で進行を\\n食い止め、笑顔咲く祭典を始めよう！ \\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を中アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・魔物植物・モベルベから受けるすべての\\n\u3000ダメージで発生する、パーティキャラのＴＰ\\n\u3000回復量を中ダウンさせる。\\n・ユニオンバーストは、敵全体に最大ＨＰに応じ\\n\u3000た魔法割合ダメージを与え、ＴＰを中ダウンさ\\n\u3000せる。さらに物理防御力と魔法防御力を大ダウ\\n\u3000ンさせる。自身の物理防御力と魔法防御力を\\n\u3000特大アップさせる。このスキルの状態異常は\\n\u3000ダメージを無効化しても付与される。このスキ\\n\u3000ルはダメージを無効化してもＴＰダウンさせる。\\n・敵全体に魔法大ダメージを与え、行動速度を\\n\u3000特大ダウンさせる。このスキルの状態異常は\\n\u3000ダメージを無効化しても付与される。\\n・自身の魔法攻撃力を大アップさせる。\\n・魔法攻撃力が最も低い敵１キャラに魔法特大ダ\\n\u3000メージを与え、スタン状態を付与する。このス\\n\u3000キルの状態異常はダメージを無効化しても付与\\n\u3000される。', 321108, 0, 2, 321103, 270, 0, 0, 16, 0, 1.6, 3000, '魔物植物・モベルベ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】清掃員に扮して虎視眈々と『グランド\\nリームパーク』の乗っ取りを謀っていた元・カジ\\nノ王。これまでの働きぶりはどこへやら、屈辱を\\n晴らすべくパレード間近の園内で反旗を翻す。\\n\\n・ユニオンバーストは、最も近い敵１キャラに\\n\u3000自身の物理攻撃力とキャラの最大ＨＰに応じた\\n\u3000物理割合ダメージを与える。\\n・自身のＨＰが50％以下になるとさらに攻撃が\\n\u3000激しく強力になる。\\n・敵全体の物理防御力を大ダウンさせ、キャラの\\n\u3000ＨＰが70％未満の場合、毒状態を付与する。\\n・敵全体に物理中ダメージを与える。毒状態の場\\n\u3000合、残りＨＰに応じた物理割合ダメージを与え\\n\u3000る。さらに敵全体のステータスアップ効果とバ\\n\u3000リアを解除する。', 321200, 0, 1, 321200, 270, 0, 0, 16, 0, 1.6, 3000, '捲土重来・ジーノ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】清掃員に扮して虎視眈々と『グランド\\nリームパーク』の乗っ取りを謀っていた元・カジ\\nノ王。これまでの働きぶりはどこへやら、屈辱を\\n晴らすべくパレード間近の園内で反旗を翻す。\\n\\n・ユニオンバーストは、最も近い敵１キャラに\\n\u3000自身の物理攻撃力とキャラの最大ＨＰに応じた\\n\u3000物理割合ダメージを与える。\\n・自身のＨＰが50％以下になるとさらに攻撃が\\n\u3000激しく強力になる。\\n・敵全体の物理防御力を大ダウンさせ、キャラの\\n\u3000ＨＰが70％未満の場合、毒状態を付与する。\\n・敵全体に物理中ダメージを与える。毒状態の場\\n\u3000合、残りＨＰに応じた物理割合ダメージを与え\\n\u3000る。さらに敵全体のステータスアップ効果とバ\\n\u3000リアを解除する。', 321201, 0, 1, 321200, 270, 0, 0, 16, 0, 1.6, 3000, '捲土重来・ジーノ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】清掃員に扮して虎視眈々と『グランド\\nリームパーク』の乗っ取りを謀っていた元・カジ\\nノ王。これまでの働きぶりはどこへやら、屈辱を\\n晴らすべくパレード間近の園内で反旗を翻す。\\n\\n・ユニオンバーストは、最も近い敵１キャラに\\n\u3000自身の物理攻撃力とキャラの最大ＨＰに応じた\\n\u3000物理割合ダメージを与える。\\n・自身のＨＰが50％以下になるとさらに攻撃が\\n\u3000激しく強力になる。\\n・敵全体の物理防御力を大ダウンさせ、キャラの\\n\u3000ＨＰが70％未満の場合、毒状態を付与する。\\n・敵全体に物理中ダメージを与える。毒状態の場\\n\u3000合、残りＨＰに応じた物理割合ダメージを与え\\n\u3000る。さらに敵全体のステータスアップ効果とバ\\n\u3000リアを解除する。', 321202, 0, 1, 321200, 270, 0, 0, 16, 0, 1.6, 3000, '捲土重来・ジーノ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】清掃員に扮して虎視眈々と『グランド\\nリームパーク』の乗っ取りを謀っていた元・カジ\\nノ王。これまでの働きぶりはどこへやら、屈辱を\\n晴らすべくパレード間近の園内で反旗を翻す。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を中アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・捲土重来・ジーノは環境効果によるダメージを\\n\u3000受けない。\\n・捲土重来・ジーノから受けるすべてのダメージ\\n\u3000で発生する、パーティキャラのＴＰ回復量を\\n\u3000中ダウンさせる。\\n・最も近い敵１キャラに物理大ダメージを与える。', 321203, 0, 1, 321203, 270, 0, 0, 16, 0, 1.6, 3000, '捲土重来・ジーノ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】清掃員に扮して虎視眈々と『グランド\\nリームパーク』の乗っ取りを謀っていた元・カジ\\nノ王。これまでの働きぶりはどこへやら、屈辱を\\n晴らすべくパレード間近の園内で反旗を翻す。\\n\\n・物理攻撃力ダウン効果の影響を受けやすい。\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を中アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・バトル開始時、自身にＴＰダウン100％カッ\\n\u3000ト効果を付与する。\\n・捲土重来・ジーノから受けるすべてのダメージ\\n\u3000で発生する、パーティキャラのＴＰ回復量を\\n\u3000中ダウンさせる。\\n・ユニオンバーストは、最も近い敵１キャラに\\n\u3000自身の物理攻撃力とキャラの最大ＨＰに応じた\\n\u3000物理割合ダメージを与える。\\n・サイコロを振り、自身の物理攻撃力をアップさ\\n\u3000せる。出目によって物理攻撃力アップの効果が\\n\u3000変化する。\\n\u3000出目が１の場合、物理攻撃力を中アップ。\\n\u3000出目が２～５の場合、物理攻撃力を特大アップ。\\n\u3000出目が６の場合、物理攻撃力を極大アップ。\\n・最も近い敵１キャラに物理特大ダメージを与え\\n\u3000る。', 321204, 0, 1, 321203, 270, 0, 0, 16, 0, 1.6, 3000, '捲土重来・ジーノ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】清掃員に扮して虎視眈々と『グランド\\nリームパーク』の乗っ取りを謀っていた元・カジ\\nノ王。これまでの働きぶりはどこへやら、屈辱を\\n晴らすべくパレード間近の園内で反旗を翻す。\\n\\n・物理攻撃力ダウン効果の影響を受けやすい。\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・捲土重来・ジーノから受けるすべてのダメージ\\n\u3000で発生する、パーティキャラのＴＰ回復量を\\n\u3000中ダウンさせる。\\n・ユニオンバーストは、最も近い敵１キャラに\\n\u3000自身の物理攻撃力とキャラの最大ＨＰに応じた\\n\u3000物理割合ダメージを与える。\\n・自身のＨＰが50％以下になるとさらに攻撃が\\n\u3000激しく強力になる。\\n・敵全体の物理防御力を大ダウンさせ、キャラの\\n\u3000ＨＰが70％未満の場合、毒状態を付与する。\\n\u3000さらに敵全体のＨＰ吸収を特大ダウンさせ、\\n\u3000ＨＰ回復量を大ダウンさせる。このスキルによ\\n\u3000り付与された毒のダメージでは、ＴＰが回復し\\n\u3000ない。\\n・敵全体に物理中ダメージを与える。毒状態の場\\n\u3000合、残りＨＰに応じた物理割合ダメージを与え\\n\u3000る。さらに敵全体のステータスアップ効果とバ\\n\u3000リアを解除する。このスキルによるダメージで\\n\u3000は、ＴＰ回復量が大ダウンする。', 321205, 0, 1, 321203, 270, 0, 0, 16, 0, 1.6, 3000, '捲土重来・ジーノ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】清掃員に扮して虎視眈々と『グランド\\nリームパーク』の乗っ取りを謀っていた元・カジ\\nノ王。これまでの働きぶりはどこへやら、屈辱を\\n晴らすべくパレード間近の園内で反旗を翻す。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を中アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・捲土重来・ジーノは環境効果によるダメージを\\n\u3000受けない。\\n・捲土重来・ジーノから受けるすべてのダメージ\\n\u3000で発生する、パーティキャラのＴＰ回復量を\\n\u3000中ダウンさせる。\\n・最も近い敵１キャラに物理大ダメージを与える。', 321206, 0, 1, 321203, 270, 0, 0, 16, 0, 1.6, 3000, '捲土重来・ジーノ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】清掃員に扮して虎視眈々と『グランド\\nリームパーク』の乗っ取りを謀っていた元・カジ\\nノ王。これまでの働きぶりはどこへやら、屈辱を\\n晴らすべくパレード間近の園内で反旗を翻す。\\n\\n・物理攻撃力ダウン効果の影響を受けやすい。\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を中アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・バトル開始時、自身にＴＰダウン100％カッ\\n\u3000ト効果を付与する。\\n・捲土重来・ジーノから受けるすべてのダメージ\\n\u3000で発生する、パーティキャラのＴＰ回復量を\\n\u3000中ダウンさせる。\\n・ユニオンバーストは、最も近い敵１キャラに\\n\u3000自身の物理攻撃力とキャラの最大ＨＰに応じた\\n\u3000物理割合ダメージを与える。\\n・サイコロを振り、自身の物理攻撃力をアップさ\\n\u3000せる。出目によって物理攻撃力アップの効果が\\n\u3000変化する。\\n\u3000出目が１の場合、物理攻撃力を中アップ。\\n\u3000出目が２～５の場合、物理攻撃力を特大アップ。\\n\u3000出目が６の場合、物理攻撃力を極大アップ。\\n・最も近い敵１キャラに物理特大ダメージを与え\\n\u3000る。', 321207, 0, 1, 321203, 270, 0, 0, 16, 0, 1.6, 3000, '捲土重来・ジーノ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】清掃員に扮して虎視眈々と『グランド\\nリームパーク』の乗っ取りを謀っていた元・カジ\\nノ王。これまでの働きぶりはどこへやら、屈辱を\\n晴らすべくパレード間近の園内で反旗を翻す。\\n\\n・物理攻撃力ダウン効果の影響を受けやすい。\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を中アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・捲土重来・ジーノから受けるすべてのダメージ\\n\u3000で発生する、パーティキャラのＴＰ回復量を\\n\u3000中ダウンさせる。\\n・ユニオンバーストは、最も近い敵１キャラに\\n\u3000自身の物理攻撃力とキャラの最大ＨＰに応じた\\n\u3000物理割合ダメージを与える。\\n・自身のＨＰが50％以下になるとさらに攻撃が\\n\u3000激しく強力になる。\\n・敵全体の物理防御力を大ダウンさせ、キャラの\\n\u3000ＨＰが70％未満の場合、毒状態を付与する。\\n\u3000さらに敵全体のＨＰ吸収を特大ダウンさせ、\\n\u3000ＨＰ回復量を大ダウンさせる。このスキルによ\\n\u3000り付与された毒のダメージでは、ＴＰが回復し\\n\u3000ない。\\n・敵全体に物理中ダメージを与える。毒状態の場\\n\u3000合、残りＨＰに応じた物理割合ダメージを与え\\n\u3000る。さらに敵全体のステータスアップ効果とバ\\n\u3000リアを解除する。このスキルによるダメージで\\n\u3000は、ＴＰ回復量が大ダウンする。', 321208, 0, 1, 321203, 270, 0, 0, 16, 0, 1.6, 3000, '捲土重来・ジーノ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】魔道具の影響で制御不能に陥ったスライ\\nム。濃厚な粘液は夏の装いなどいとも容易く溶解\\nし、秘められた素肌を炎天下に曝け出させる。\\n\\n・召喚体、分身を攻撃対象にしない。\\n・ユニオンバーストは、最も近い１～５番目の敵\\n\u3000にそれぞれのキャラの現在ＨＰに応じた物理割\\n\u3000合ダメージを与え、キャラの最大ＨＰをバトル\\n\u3000終了まで15％減少させる。\\n・最も近い１～３番目の敵にそれぞれ物理小ダ\\n\u3000メージを与える。さらに物理防御力を大ダウン\\n\u3000させる。このスキルの効果はダメージを無効化\\n\u3000しても付与される。\\n・最も近い敵１キャラに物理特大ダメージを与え、\\n\u3000ＴＰを小ダウンさせる。このスキルはダメージ\\n\u3000を無効化してもＴＰをダウンさせる。', 321300, 0, 1, 321300, 270, 0, 0, 16, 0, 1.6, 3000, '真夏のバーサークスライム');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】魔道具の影響で制御不能に陥ったスライ\\nム。濃厚な粘液は夏の装いなどいとも容易く溶解\\nし、秘められた素肌を炎天下に曝け出させる。\\n\\n・召喚体、分身を攻撃対象にしない。\\n・ユニオンバーストは、最も近い１～５番目の敵\\n\u3000にそれぞれのキャラの現在ＨＰに応じた物理割\\n\u3000合ダメージを与え、キャラの最大ＨＰをバトル\\n\u3000終了まで15％減少させる。\\n・最も近い１～３番目の敵にそれぞれ物理小ダ\\n\u3000メージを与える。さらに物理防御力を大ダウン\\n\u3000させる。このスキルの効果はダメージを無効化\\n\u3000しても付与される。\\n・最も近い敵１キャラに物理特大ダメージを与え、\\n\u3000ＴＰを小ダウンさせる。このスキルはダメージ\\n\u3000を無効化してもＴＰをダウンさせる。', 321301, 0, 1, 321300, 270, 0, 0, 16, 0, 1.6, 3000, '真夏のバーサークスライム');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】魔道具の影響で制御不能に陥ったスライ\\nム。濃厚な粘液は夏の装いなどいとも容易く溶解\\nし、秘められた素肌を炎天下に曝け出させる。\\n\\n・召喚体、分身を攻撃対象にしない。\\n・ユニオンバーストは、最も近い１～５番目の敵\\n\u3000にそれぞれのキャラの現在ＨＰに応じた物理割\\n\u3000合ダメージを与え、キャラの最大ＨＰをバトル\\n\u3000終了まで15％減少させる。\\n・最も近い１～３番目の敵にそれぞれ物理小ダ\\n\u3000メージを与える。さらに物理防御力を大ダウン\\n\u3000させる。このスキルの効果はダメージを無効化\\n\u3000しても付与される。\\n・最も近い敵１キャラに物理特大ダメージを与え、\\n\u3000ＴＰを小ダウンさせる。このスキルはダメージ\\n\u3000を無効化してもＴＰをダウンさせる。', 321302, 0, 1, 321300, 270, 0, 0, 16, 0, 1.6, 3000, '真夏のバーサークスライム');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】魔道具の影響で制御不能に陥ったスライ\\nム。濃厚な粘液は夏の装いなどいとも容易く溶解\\nし、秘められた素肌を炎天下に曝け出させる。\\n\\n・召喚体、分身を攻撃対象にしない。\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・真夏のバーサークスライムは環境効果によるダ\\n\u3000メージを受けない。\\n・真夏のバーサークスライムから受けるすべての\\n\u3000ダメージで発生する、パーティキャラのＴＰ回\\n\u3000復量を中ダウンさせる。\\n・最も近い敵１キャラに物理特大ダメージを与え、\\n\u3000ＴＰを小ダウンさせる。このスキルはダメージ\\n\u3000を無効化してもＴＰをダウンさせる。', 321303, 0, 1, 321303, 270, 0, 0, 16, 0, 1.6, 3000, '真夏のバーサークスライム');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】魔道具の影響で制御不能に陥ったスライ\\nム。濃厚な粘液は夏の装いなどいとも容易く溶解\\nし、秘められた素肌を炎天下に曝け出させる。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・バトル開始時、自身にＴＰダウン100％カッ\\n\u3000ト効果を付与する。\\n・真夏のバーサークスライムから受けるすべての\\n\u3000ダメージで発生する、パーティキャラのＴＰ回\\n\u3000復量を中ダウンさせる。\\n・ユニオンバーストは、召喚体、分身を除いた最\\n\u3000も近い１～５番目の敵にそれぞれのキャラの\\n\u3000元々のＨＰに応じた物理割合ダメージを与え、\\n\u3000キャラの最大ＨＰをバトル終了まで40％減少\\n\u3000させる。\\n・召喚体、分身を除いた最も近い１～３番目の敵\\n\u3000にそれぞれ物理小ダメージを与える。さらに物\\n\u3000理防御力を大ダウンさせ、バリアを解除する。\\n\u3000このスキルの効果はダメージを無効化しても付\\n\u3000与される。\\n・召喚体、分身を除いた最も近い敵１キャラに物\\n\u3000理特大ダメージを与え、ＴＰを小ダウンさせる。\\n\u3000このスキルはダメージを無効化してもＴＰを\\n\u3000ダウンさせる。\\n・スライムフィールドを展開し、飛行状態のキャ\\n\u3000ラを含む敵全体の行動速度を中ダウンさせる。\\n\\n【スライムフィールド効果】\\n以下の効果が発動する。\\n・毎秒飛行状態のキャラを含む敵全体の物理攻撃\\n\u3000力と魔法攻撃力をバトル終了まで小ダウンさせ\\n\u3000る。', 321304, 0, 1, 321303, 270, 0, 0, 16, 0, 1.6, 3000, '真夏のバーサークスライム');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】魔道具の影響で制御不能に陥ったスライ\\nム。濃厚な粘液は夏の装いなどいとも容易く溶解\\nし、秘められた素肌を炎天下に曝け出させる。\\n\\n・召喚体、分身を攻撃対象にしない。\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・バトル開始時、自身にＴＰダウン50％カット\\n\u3000効果を付与する。\\n・真夏のバーサークスライムから受けるすべての\\n\u3000ダメージで発生する、パーティキャラのＴＰ回\\n\u3000復量を中ダウンさせる。\\n・ユニオンバーストは、最も近い１～５番目の敵\\n\u3000にそれぞれのキャラの元々のＨＰに応じた物理\\n\u3000割合ダメージを与え、キャラの最大ＨＰをバト\\n\u3000ル終了まで40％減少させる。\\n・最も近い１～３番目の敵にそれぞれ物理小ダ\\n\u3000メージを与える。さらに物理防御力を大ダウン\\n\u3000させ、バリアを解除する。このスキルの効果は\\n\u3000ダメージを無効化しても付与される。\\n・最も近い敵１キャラに物理特大ダメージを与え、\\n\u3000ＴＰを小ダウンさせる。このスキルはダメージ\\n\u3000を無効化してもＴＰをダウンさせる。', 321305, 0, 1, 321303, 270, 0, 0, 16, 0, 1.6, 3000, '真夏のバーサークスライム');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】魔道具の影響で制御不能に陥ったスライ\\nム。濃厚な粘液は夏の装いなどいとも容易く溶解\\nし、秘められた素肌を炎天下に曝け出させる。\\n\\n・召喚体、分身を攻撃対象にしない。\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を中アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・真夏のバーサークスライムは環境効果によるダ\\n\u3000メージを受けない。\\n・真夏のバーサークスライムから受けるすべての\\n\u3000ダメージで発生する、パーティキャラのＴＰ回\\n\u3000復量を中ダウンさせる。\\n・最も近い敵１キャラに物理特大ダメージを与え、\\n\u3000ＴＰを小ダウンさせる。このスキルはダメージ\\n\u3000を無効化してもＴＰをダウンさせる。', 321306, 0, 1, 321303, 270, 0, 0, 16, 0, 1.6, 3000, '真夏のバーサークスライム');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】魔道具の影響で制御不能に陥ったスライ\\nム。濃厚な粘液は夏の装いなどいとも容易く溶解\\nし、秘められた素肌を炎天下に曝け出させる。\\n\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を中アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・バトル開始時、自身にＴＰダウン100％カッ\\n\u3000ト効果を付与する。\\n・真夏のバーサークスライムから受けるすべての\\n\u3000ダメージで発生する、パーティキャラのＴＰ回\\n\u3000復量を中ダウンさせる。\\n・ユニオンバーストは、召喚体、分身を除いた最\\n\u3000も近い１～５番目の敵にそれぞれのキャラの\\n\u3000元々のＨＰに応じた物理割合ダメージを与え、\\n\u3000キャラの最大ＨＰをバトル終了まで40％減少\\n\u3000させる。\\n・召喚体、分身を除いた最も近い１～３番目の敵\\n\u3000にそれぞれ物理小ダメージを与える。さらに物\\n\u3000理防御力を大ダウンさせ、バリアを解除する。\\n\u3000このスキルの効果はダメージを無効化しても付\\n\u3000与される。\\n・召喚体、分身を除いた最も近い敵１キャラに物\\n\u3000理特大ダメージを与え、ＴＰを小ダウンさせる。\\n\u3000このスキルはダメージを無効化してもＴＰを\\n\u3000ダウンさせる。\\n・スライムフィールドを展開し、飛行状態のキャ\\n\u3000ラを含む敵全体の行動速度を中ダウンさせる。\\n\\n【スライムフィールド効果】\\n以下の効果が発動する。\\n・毎秒飛行状態のキャラを含む敵全体の物理攻撃\\n\u3000力と魔法攻撃力をバトル終了まで小ダウンさせ\\n\u3000る。', 321307, 0, 1, 321303, 270, 0, 0, 16, 0, 1.6, 3000, '真夏のバーサークスライム');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】魔道具の影響で制御不能に陥ったスライ\\nム。濃厚な粘液は夏の装いなどいとも容易く溶解\\nし、秘められた素肌を炎天下に曝け出させる。\\n\\n・召喚体、分身を攻撃対象にしない。\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を中アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・バトル開始時、自身にＴＰダウン50％カット\\n\u3000効果を付与する。\\n・真夏のバーサークスライムから受けるすべての\\n\u3000ダメージで発生する、パーティキャラのＴＰ回\\n\u3000復量を中ダウンさせる。\\n・ユニオンバーストは、最も近い１～５番目の敵\\n\u3000にそれぞれのキャラの元々のＨＰに応じた物理\\n\u3000割合ダメージを与え、キャラの最大ＨＰをバト\\n\u3000ル終了まで40％減少させる。\\n・最も近い１～３番目の敵にそれぞれ物理小ダ\\n\u3000メージを与える。さらに物理防御力を大ダウン\\n\u3000させ、バリアを解除する。このスキルの効果は\\n\u3000ダメージを無効化しても付与される。\\n・最も近い敵１キャラに物理特大ダメージを与え、\\n\u3000ＴＰを小ダウンさせる。このスキルはダメージ\\n\u3000を無効化してもＴＰをダウンさせる。', 321308, 0, 1, 321303, 270, 0, 0, 16, 0, 1.6, 3000, '真夏のバーサークスライム');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】環境システムの暴走により誕生した嵐の\\n化身。非情な暴風は周囲一帯を遍く飲み込み、\\n万物を無に帰すことで世界に混沌をもたらす。\\n\\n・環境効果【雷雲】を発動する。このスキルの効\\n\u3000果は敵すべてに適用される。一定時間が経過す\\n\u3000るごとに、敵全体に最大ＨＰに応じた魔法割合\\n\u3000ダメージを与える。この効果によるダメージで\\n\u3000は、ＴＰが回復しない。\\n・物理攻撃力ダウン効果の影響を受けやすい。\\n・挑発効果の影響を受けやすい。\\n・ユニオンバーストは、飛行状態のキャラを含む\\n\u3000敵全体に物理大ダメージを与え、混乱状態、麻\\n\u3000痺状態、物理防御力中ダウンのいずれかを付与\\n\u3000する。このスキルの状態異常はダメージを無効\\n\u3000化しても付与される。\\n・ランダムな敵１キャラを中心にした小範囲に、\\n\u3000物理大ダメージを与え、スタン状態を付与する。\\n\u3000このスキルの状態異常はダメージを無効化して\\n\u3000も付与される。\\n・ランダムな敵１キャラを中心にした小範囲に、\\n\u3000物理中ダメージを与える。\\n・ランダムな敵１キャラを中心にした小範囲に、\\n\u3000物理大ダメージを与える。\\n・向かって左側のターゲットのブレイク時、\\n\u3000自身の物理攻撃力が中ダウンする。\\n・中央左部のターゲットのブレイク時、\\n\u3000自身の物理攻撃力が中ダウンする。\\n・中央右部のターゲットのブレイク時、\\n\u3000自身の物理攻撃力が中ダウンする。\\n・向かって右側のターゲットのブレイク時、\\n\u3000自身の物理攻撃力が中ダウンする。', 321400, 0, 1, 321400, 270, 0, 0, 16, 0, 1.6, 3000, 'カオス・ジェネレーター');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】環境システムの暴走により誕生した嵐の\\n化身。非情な暴風は周囲一帯を遍く飲み込み、\\n万物を無に帰すことで世界に混沌をもたらす。\\n\\n・環境効果【雷雲】を発動する。このスキルの効\\n\u3000果は敵すべてに適用される。一定時間が経過す\\n\u3000るごとに、敵全体に最大ＨＰに応じた魔法割合\\n\u3000ダメージを与える。この効果によるダメージで\\n\u3000は、ＴＰが回復しない。\\n・物理攻撃力ダウン効果の影響を受けやすい。\\n・挑発効果の影響を受けやすい。\\n・ユニオンバーストは、飛行状態のキャラを含む\\n\u3000敵全体に物理大ダメージを与え、混乱状態、麻\\n\u3000痺状態、物理防御力中ダウンのいずれかを付与\\n\u3000する。このスキルの状態異常はダメージを無効\\n\u3000化しても付与される。\\n・ランダムな敵１キャラを中心にした小範囲に、\\n\u3000物理大ダメージを与え、スタン状態を付与する。\\n\u3000このスキルの状態異常はダメージを無効化して\\n\u3000も付与される。\\n・ランダムな敵１キャラを中心にした小範囲に、\\n\u3000物理中ダメージを与える。\\n・ランダムな敵１キャラを中心にした小範囲に、\\n\u3000物理大ダメージを与える。\\n・向かって左側のターゲットのブレイク時、\\n\u3000自身の物理攻撃力が中ダウンする。\\n・中央左部のターゲットのブレイク時、\\n\u3000自身の物理攻撃力が中ダウンする。\\n・中央右部のターゲットのブレイク時、\\n\u3000自身の物理攻撃力が中ダウンする。\\n・向かって右側のターゲットのブレイク時、\\n\u3000自身の物理攻撃力が中ダウンする。', 321401, 0, 1, 321400, 270, 0, 0, 16, 0, 1.6, 3000, 'カオス・ジェネレーター');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】環境システムの暴走により誕生した嵐の\\n化身。非情な暴風は周囲一帯を遍く飲み込み、\\n万物を無に帰すことで世界に混沌をもたらす。\\n\\n・環境効果【雷雲】を発動する。このスキルの効\\n\u3000果は敵すべてに適用される。一定時間が経過す\\n\u3000るごとに、敵全体に最大ＨＰに応じた魔法割合\\n\u3000ダメージを与える。この効果によるダメージで\\n\u3000は、ＴＰが回復しない。\\n・物理攻撃力ダウン効果の影響を受けやすい。\\n・挑発効果の影響を受けやすい。\\n・ユニオンバーストは、飛行状態のキャラを含む\\n\u3000敵全体に物理大ダメージを与え、混乱状態、麻\\n\u3000痺状態、物理防御力中ダウンのいずれかを付与\\n\u3000する。このスキルの状態異常はダメージを無効\\n\u3000化しても付与される。\\n・ランダムな敵１キャラを中心にした小範囲に、\\n\u3000物理大ダメージを与え、スタン状態を付与する。\\n\u3000このスキルの状態異常はダメージを無効化して\\n\u3000も付与される。\\n・ランダムな敵１キャラを中心にした小範囲に、\\n\u3000物理中ダメージを与える。\\n・ランダムな敵１キャラを中心にした小範囲に、\\n\u3000物理大ダメージを与える。\\n・向かって左側のターゲットのブレイク時、\\n\u3000自身の物理攻撃力が中ダウンする。\\n・中央左部のターゲットのブレイク時、\\n\u3000自身の物理攻撃力が中ダウンする。\\n・中央右部のターゲットのブレイク時、\\n\u3000自身の物理攻撃力が中ダウンする。\\n・向かって右側のターゲットのブレイク時、\\n\u3000自身の物理攻撃力が中ダウンする。', 321402, 0, 1, 321400, 270, 0, 0, 16, 0, 1.6, 3000, 'カオス・ジェネレーター');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】環境システムの暴走により誕生した嵐の\\n化身。非情な暴風は周囲一帯を遍く飲み込み、\\n万物を無に帰すことで世界に混沌をもたらす。\\n\\n・環境効果【暴風】を発動する。このスキルの効\\n\u3000果は敵すべてに適用される。一定時間が経過す\\n\u3000るごとに、敵全体をノックバックさせる。\\n・物理攻撃力ダウン効果の影響を受けやすい。\\n・挑発効果の影響を受けやすい。\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・バトル開始時、カオス・ジェネレーターはブレ\\n\u3000イクされなくなる。\\n・カオス・ジェネレーターから受けるすべてのダ\\n\u3000メージで発生する、パーティキャラのＴＰ回復\\n\u3000量を中ダウンさせる。\\n・ユニオンバーストは、飛行状態のキャラを含む\\n\u3000敵全体に物理大ダメージを与え、混乱状態、麻\\n\u3000痺状態、物理防御力中ダウンのいずれかを付与\\n\u3000する。このスキルの状態異常はダメージを無効\\n\u3000化しても付与される。\\n・ランダムな敵１キャラを中心にした小範囲に、\\n\u3000物理大ダメージを与え、スタン状態を付与する。\\n\u3000このスキルの状態異常はダメージを無効化して\\n\u3000も付与される。\\n・ランダムな敵１キャラを中心にした小範囲に、\\n\u3000物理中ダメージを与える。\\n・ランダムな敵１キャラを中心にした小範囲に、\\n\u3000物理大ダメージを与える。', 321403, 0, 1, 321403, 270, 0, 0, 16, 0, 1.6, 3000, 'カオス・ジェネレーター');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】環境システムの暴走により誕生した嵐の\\n化身。非情な暴風は周囲一帯を遍く飲み込み、\\n万物を無に帰すことで世界に混沌をもたらす。\\n\\n・環境効果【豪雨】を発動する。このスキルの効\\n\u3000果は敵すべてに適用される。一定時間が経過す\\n\u3000るごとに、敵全体の行動速度をバトル終了まで\\n\u3000小ダウンさせる。さらに、物理攻撃力と魔法攻\\n\u3000撃力をバトル終了まで小ダウンさせる。\\n・物理攻撃力ダウン効果の影響を受けやすい。\\n・挑発効果の影響を受けやすい。\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を小アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・カオス・ジェネレーターから受けるすべてのダ\\n\u3000メージで発生する、パーティキャラのＴＰ回復\\n\u3000量を中ダウンさせる。\\n・ユニオンバーストは、飛行状態のキャラを含む\\n\u3000敵全体に物理大ダメージを与え、混乱状態、麻\\n\u3000痺状態、物理防御力中ダウンのいずれかを付与\\n\u3000する。このスキルの状態異常はダメージを無効\\n\u3000化しても付与される。\\n・ランダムな敵１キャラを中心にした小範囲に、\\n\u3000物理大ダメージを与え、スタン状態を付与する。\\n\u3000このスキルの状態異常はダメージを無効化して\\n\u3000も付与される。\\n・ランダムな敵１キャラを中心にした小範囲に、\\n\u3000物理中ダメージを与える。\\n・ランダムな敵１キャラを中心にした小範囲に、\\n\u3000物理大ダメージを与える。\\n・向かって左側のターゲットのブレイク時、\\n\u3000自身の物理防御力と魔法防御力が小ダウンする。\\n・中央左部のターゲットのブレイク時、\\n\u3000自身の物理防御力と魔法防御力が小ダウンする。\\n・中央右部のターゲットのブレイク時、\\n\u3000自身の物理防御力と魔法防御力が中ダウンする。\\n・向かって右側のターゲットのブレイク時、\\n\u3000自身の物理防御力と魔法防御力が大ダウンする。', 321404, 0, 1, 321404, 270, 0, 0, 16, 0, 1.6, 3000, 'カオス・ジェネレーター');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】環境システムの暴走により誕生した嵐の\\n化身。非情な暴風は周囲一帯を遍く飲み込み、\\n万物を無に帰すことで世界に混沌をもたらす。\\n\\n・環境効果【雷雲】を発動する。このスキルの効\\n\u3000果は敵すべてに適用される。一定時間が経過す\\n\u3000るごとに、敵全体に最大ＨＰに応じた魔法割合\\n\u3000ダメージを与える。さらに、キャラのＨＰが\\n\u300050％未満の場合、麻痺状態を付与する。この\\n\u3000効果によるダメージでは、ＴＰが回復しない。\\n\u3000この効果の状態異常はダメージを無効化しても\\n\u3000付与される。\\n・物理攻撃力ダウン効果の影響を受けやすい。\\n・挑発効果の影響を受けやすい。\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を中アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・バトル開始時、敵全体のＨＰ吸収を特大ダウン\\n\u3000させる。\\n・カオス・ジェネレーターから受けるすべてのダ\\n\u3000メージで発生する、パーティキャラのＴＰ回復\\n\u3000量を中ダウンさせる。\\n・ユニオンバーストは、飛行状態のキャラを含む\\n\u3000敵全体に物理大ダメージを与え、混乱状態、麻\\n\u3000痺状態、物理防御力中ダウンのいずれかを付与\\n\u3000する。このスキルの状態異常はダメージを無効\\n\u3000化しても付与される。\\n・ランダムな敵１キャラを中心にした小範囲に、\\n\u3000物理大ダメージを与え、スタン状態を付与する。\\n\u3000このスキルの状態異常はダメージを無効化して\\n\u3000も付与される。\\n・ランダムな敵１キャラを中心にした小範囲に、\\n\u3000物理中ダメージを与える。\\n・ランダムな敵１キャラを中心にした小範囲に、\\n\u3000物理大ダメージを与える。\\n・向かって左側のターゲットのブレイク時、\\n\u3000自身の物理攻撃力が中ダウンする。\\n・中央左部のターゲットのブレイク時、\\n\u3000自身の物理攻撃力が中ダウンする。\\n・中央右部のターゲットのブレイク時、\\n\u3000自身の物理攻撃力が中ダウンする。\\n・向かって右側のターゲットのブレイク時、\\n\u3000自身の物理攻撃力が中ダウンする。', 321405, 0, 1, 321403, 270, 0, 0, 16, 0, 1.6, 3000, 'カオス・ジェネレーター');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】環境システムの暴走により誕生した嵐の\\n化身。非情な暴風は周囲一帯を遍く飲み込み、\\n万物を無に帰すことで世界に混沌をもたらす。\\n\\n・環境効果【暴風】を発動する。このスキルの効\\n\u3000果は敵すべてに適用される。一定時間が経過す\\n\u3000るごとに、敵全体をノックバックさせる。\\n・物理攻撃力ダウン効果の影響を受けやすい。\\n・挑発効果の影響を受けやすい。\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を中アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・バトル開始時、カオス・ジェネレーターはブレ\\n\u3000イクされなくなる。\\n・カオス・ジェネレーターから受けるすべてのダ\\n\u3000メージで発生する、パーティキャラのＴＰ回復\\n\u3000量を中ダウンさせる。\\n・ユニオンバーストは、飛行状態のキャラを含む\\n\u3000敵全体に物理大ダメージを与え、混乱状態、麻\\n\u3000痺状態、物理防御力中ダウンのいずれかを付与\\n\u3000する。このスキルの状態異常はダメージを無効\\n\u3000化しても付与される。\\n・ランダムな敵１キャラを中心にした小範囲に、\\n\u3000物理大ダメージを与え、スタン状態を付与する。\\n\u3000このスキルの状態異常はダメージを無効化して\\n\u3000も付与される。\\n・ランダムな敵１キャラを中心にした小範囲に、\\n\u3000物理中ダメージを与える。\\n・ランダムな敵１キャラを中心にした小範囲に、\\n\u3000物理大ダメージを与える。', 321406, 0, 1, 321403, 270, 0, 0, 16, 0, 1.6, 3000, 'カオス・ジェネレーター');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】環境システムの暴走により誕生した嵐の\\n化身。非情な暴風は周囲一帯を遍く飲み込み、\\n万物を無に帰すことで世界に混沌をもたらす。\\n\\n・環境効果【豪雨】を発動する。このスキルの効\\n\u3000果は敵すべてに適用される。一定時間が経過す\\n\u3000るごとに、敵全体の行動速度をバトル終了まで\\n\u3000小ダウンさせる。さらに、物理攻撃力と魔法攻\\n\u3000撃力をバトル終了まで小ダウンさせる。\\n・物理攻撃力ダウン効果の影響を受けやすい。\\n・挑発効果の影響を受けやすい。\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を中アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・カオス・ジェネレーターから受けるすべてのダ\\n\u3000メージで発生する、パーティキャラのＴＰ回復\\n\u3000量を中ダウンさせる。\\n・ユニオンバーストは、飛行状態のキャラを含む\\n\u3000敵全体に物理大ダメージを与え、混乱状態、麻\\n\u3000痺状態、物理防御力中ダウンのいずれかを付与\\n\u3000する。このスキルの状態異常はダメージを無効\\n\u3000化しても付与される。\\n・ランダムな敵１キャラを中心にした小範囲に、\\n\u3000物理大ダメージを与え、スタン状態を付与する。\\n\u3000このスキルの状態異常はダメージを無効化して\\n\u3000も付与される。\\n・ランダムな敵１キャラを中心にした小範囲に、\\n\u3000物理中ダメージを与える。\\n・ランダムな敵１キャラを中心にした小範囲に、\\n\u3000物理大ダメージを与える。\\n・向かって左側のターゲットのブレイク時、\\n\u3000自身の物理防御力と魔法防御力が小ダウンする。\\n・中央左部のターゲットのブレイク時、\\n\u3000自身の物理防御力と魔法防御力が小ダウンする。\\n・中央右部のターゲットのブレイク時、\\n\u3000自身の物理防御力と魔法防御力が中ダウンする。\\n・向かって右側のターゲットのブレイク時、\\n\u3000自身の物理防御力と魔法防御力が大ダウンする。', 321407, 0, 1, 321404, 270, 0, 0, 16, 0, 1.6, 3000, 'カオス・ジェネレーター');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】環境システムの暴走により誕生した嵐の\\n化身。非情な暴風は周囲一帯を遍く飲み込み、\\n万物を無に帰すことで世界に混沌をもたらす。\\n\\n・環境効果【雷雲】を発動する。このスキルの効\\n\u3000果は敵すべてに適用される。一定時間が経過す\\n\u3000るごとに、敵全体に最大ＨＰに応じた魔法割合\\n\u3000ダメージを与える。さらに、キャラのＨＰが\\n\u300050％未満の場合、麻痺状態を付与する。この\\n\u3000効果によるダメージでは、ＴＰが回復しない。\\n\u3000この効果の状態異常はダメージを無効化しても\\n\u3000付与される。\\n・物理攻撃力ダウン効果の影響を受けやすい。\\n・挑発効果の影響を受けやすい。\\n・バトル開始時、自身の物理防御力と魔法防御力\\n\u3000を中アップさせる。この防御力アップ効果で上\\n\u3000昇した防御力は、バトル中に受ける防御力ダウ\\n\u3000ンスキルの影響を受けない。\\n・バトル開始時、敵全体のＨＰ吸収を特大ダウン\\n\u3000させる。\\n・カオス・ジェネレーターから受けるすべてのダ\\n\u3000メージで発生する、パーティキャラのＴＰ回復\\n\u3000量を中ダウンさせる。\\n・ユニオンバーストは、飛行状態のキャラを含む\\n\u3000敵全体に物理大ダメージを与え、混乱状態、麻\\n\u3000痺状態、物理防御力中ダウンのいずれかを付与\\n\u3000する。このスキルの状態異常はダメージを無効\\n\u3000化しても付与される。\\n・ランダムな敵１キャラを中心にした小範囲に、\\n\u3000物理大ダメージを与え、スタン状態を付与する。\\n\u3000このスキルの状態異常はダメージを無効化して\\n\u3000も付与される。\\n・ランダムな敵１キャラを中心にした小範囲に、\\n\u3000物理中ダメージを与える。\\n・ランダムな敵１キャラを中心にした小範囲に、\\n\u3000物理大ダメージを与える。\\n・向かって左側のターゲットのブレイク時、\\n\u3000自身の物理攻撃力が中ダウンする。\\n・中央左部のターゲットのブレイク時、\\n\u3000自身の物理攻撃力が中ダウンする。\\n・中央右部のターゲットのブレイク時、\\n\u3000自身の物理攻撃力が中ダウンする。\\n・向かって右側のターゲットのブレイク時、\\n\u3000自身の物理攻撃力が中ダウンする。', 321408, 0, 1, 321403, 270, 0, 0, 16, 0, 1.6, 3000, 'カオス・ジェネレーター');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【魔法】巨大に変異したバジリスクの亜種。異相\\nの巨体を羽ばたかせ、獲物を絶望に突き落とす。\\n\\n・バジリスク・アロス、スノウゴート、アイス\\n\u3000チック、アイスフィッシュ、アイスモールから\\n\u3000受けるすべてのダメージで発生する、パーティ\\n\u3000キャラのＴＰ回復量を中ダウンさせる。\\n・最も近い敵１キャラに魔法中ダメージを与える。', 321900, 0, 2, 321900, 270, 0, 0, 16, 0, 1.6, 3000, 'バジリスク・アロス');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【魔法】巨大に変異したバジリスクの亜種。異相\\nの巨体を羽ばたかせ、獲物を絶望に突き落とす。\\n\\n・一定時間力を溜め、上空に飛び上がる。\\n\u3000空を飛んでいる間、自身に無敵状態を付与する。\\n\u3000その後急降下し、最も近い敵１キャラに最大\\n\u3000ＨＰに応じた物理割合ダメージを与える。\\n\u3000さらに、自身にこのスキルで与えたダメージ量\\n\u3000に応じた物理特大ダメージを与え、自身の物理\\n\u3000防御力と魔法防御力を特大ダウンさせる。', 321901, 0, 2, 321901, 270, 0, 0, 16, 0, 1.6, 3000, 'バジリスク・アロス');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【魔法】巨大に変異したバジリスクの亜種。異相\\nの巨体を羽ばたかせ、獲物を絶望に突き落とす。\\n\\n・バジリスク・アロスから受けるすべてのダメー\\n\u3000ジで発生する、パーティキャラのＴＰ回復量を\\n\u3000中ダウンさせる。\\n・ユニオンバーストは、最も近い敵１キャラに魔\\n\u3000法特大ダメージを与える。さらに敵全体に魔法\\n\u3000中ダメージを与え、石化状態を付与する。この\\n\u3000スキルの状態異常はダメージを無効化しても付\\n\u3000与される。\\n・敵全体に魔法中ダメージを与え、石化状態を付\\n\u3000与する。このスキルの状態異常はダメージを無\\n\u3000効化しても付与される。\\n・最も近い敵１キャラに魔法特大ダメージを与え\\n\u3000る。\\n・自身のＨＰが35％を切ると、行動パターンが\\n\u3000変化する。さらに自身の魔法攻撃力を中アップ\\n\u3000させる。\\n・最も近い敵１キャラに魔法中ダメージを与える。', 321902, 0, 2, 321902, 270, 0, 0, 16, 0, 1.6, 3000, 'バジリスク・アロス');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】稲妻を角に纏う剛力無双の一角獣。\\n筋骨隆々の怪腕が大地を割り、雷角が天空を貫く。\\n\\n・剛雷獣・ライガホーンから受けるすべてのダ\\n\u3000メージで発生する、パーティキャラのＴＰ回復\\n\u3000量を中ダウンさせる。\\n・ユニオンバーストは、敵全体に物理特大ダメー\\n\u3000ジと魔法特大ダメージを与える。\\n\u3000さらに【滅却の蛮雷】使用までのカウントダウ\\n\u3000ンが進む。\\n\u3000【滅却の蛮雷】使用までのカウントダウンが\\n\u3000０回になった時、【滅却の蛮雷】を使用する。\\n・最も近い敵３キャラに物理大ダメージを与える。\\n・最も近い敵１キャラに物理特大ダメージを与え、\\n\u3000スタン状態を付与する。このスキルの状態異常\\n\u3000はダメージを無効化しても付与される。\\n\\n【滅却の蛮雷】\\n・飛行状態のキャラを含む敵全体に999999\\n\u3000×５ヒットの魔法固定ダメージを与える。この\\n\u3000スキルで受けるダメージでは、敵のＴＰが回復\\n\u3000しない。', 322000, 0, 1, 322000, 270, 0, 0, 16, 0, 1.6, 3000, '剛雷獣・ライガホーン');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】稲妻を角に纏う剛力無双の一角獣。\\n筋骨隆々の怪腕が大地を割り、雷角が天空を貫く。\\n\\n・剛雷獣・ライガホーンから受けるすべてのダ\\n\u3000メージで発生する、パーティキャラのＴＰ回復\\n\u3000量を中ダウンさせる。\\n・剛雷獣・ライガホーンは環境効果によるダメー\\n\u3000ジを受けない。\\n・最も近い敵１キャラに物理特大ダメージを与え、\\n\u3000スタン状態を付与する。このスキルの状態異常\\n\u3000はダメージを無効化しても付与される。', 322001, 0, 1, 322001, 270, 0, 0, 16, 0, 1.6, 3000, '剛雷獣・ライガホーン');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('【物理】稲妻を角に纏う剛力無双の一角獣。\\n筋骨隆々の怪腕が大地を割り、雷角が天空を貫く。\\n\\n・剛雷獣・ライガホーンから受けるすべてのダ\\n\u3000メージで発生する、パーティキャラのＴＰ回復\\n\u3000量を中ダウンさせる。\\n・ユニオンバーストは、敵全体に自身の物理防御\\n\u3000力に応じた物理大ダメージと、自身の魔法防御\\n\u3000力に応じた魔法大ダメージを与える。\\n・最も近い敵３キャラに物理大ダメージを与える。\\n・最も近い敵１キャラに物理特大ダメージを与え、\\n\u3000スタン状態を付与する。このスキルの状態異常\\n\u3000はダメージを無効化しても付与される。\\n・自身のＨＰが38％を切ると、自身の物理防御\\n\u3000力と魔法防御力が大アップする。さらに自身の\\n\u3000行動速度が大アップする。', 322002, 0, 1, 322002, 270, 0, 0, 16, 0, 1.6, 3000, '剛雷獣・ライガホーン');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('七冠の一人', 390100, 0, 2, 390100, 600, 0, 0, 0, 0, 15.0, 3000, '覇瞳皇帝');
