insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('クローチェの姿をした特殊な魔物\\n\\n・【フルチャージ】中は、ユニオンバーストを使\\n\u3000用してから一定回数行動後に発動し、前方範囲\\n\u3000内の敵すべてに物理大ダメージを与え、自分の\\n\u3000ＴＰを-1000し、【フルチャージ】状態を\\n\u3000解除する。さらに、【システムダウン】状態に\\n\u3000なり、自分のステータスアップ効果をすべて解\\n\u3000除し、行動速度を特大ダウンさせる。（他の行\\n\u3000動速度変化スキルと重複する）【バッテリー】\\n\u3000をすべて消費する。\\n\u3000最も後ろの敵１キャラに物理大ダメージを与え、\\n\u3000クリティカルを受けた際のダメージを小アップ\\n\u3000させる。このスキルは１ヒットは必ずクリティ\\n\u3000カルし、クリティカルした場合のダメージは、\\n\u3000２倍ではなく３倍になる。【バッテリー】を１\\n\u3000つ消費する。\\n\u3000自分の物理攻撃力と物理クリティカルを中アッ\\n\u3000プさせ、前方範囲内の敵すべてに物理大ダメー\\n\u3000ジを与える。このスキルは１ヒットは必ずクリ\\n\u3000ティカルし、クリティカルした場合のダメージ\\n\u3000は、２倍ではなく３倍になる。【バッテリー】\\n\u3000を１つ消費する。', 626401, 1, 1, 126401, 450, 0, 1, 1, 0, 2.09, 373, 'クローチェのシャドウ');
insert into v1_83e7b4bb74df9c448153a3d87f5bcbc5302e0de80b3048aa5a22699d4422b9bf values ('ライラエルの姿をした特殊な魔物\\n\\n・特殊スキルは、環境効果【界雷】を発動する。\\n\u3000このスキルの効果は敵、味方すべてに適用され\\n\u3000る。魔法攻撃のダメージが小アップし、物理攻\\n\u3000撃を行うキャラが行動する度にそのキャラの最\\n\u3000大ＨＰに応じて最大99999の割合ダメージ\\n\u3000を与える。', 626501, 0, 2, 126501, 450, 0, 1, 7, 0, 1.965, 740, 'ライラエルのシャドウ');
